INSERT INTO bible_verses (book_name, chapter, verse, text) VALUES
  ('Deuteronomy', 3, 25, 'Please let me go over and see the good land that is beyond the Jordan, that fine mountain, and Lebanon.”'),
  ('Deuteronomy', 3, 26, 'But the LORD was angry with me because of you, and didn’t listen to me. The LORD said to me, “That is enough! Speak no more to me of this matter.'),
  ('Deuteronomy', 3, 27, 'Go up to the top of Pisgah, and lift up your eyes westward, and northward, and southward, and eastward, and see with your eyes; for you shall not go over this Jordan.'),
  ('Deuteronomy', 3, 28, 'But commission Joshua, and encourage him, and strengthen him; for he shall go over before this people, and he shall cause them to inherit the land which you shall see.”'),
  ('Deuteronomy', 3, 29, 'So we stayed in the valley near Beth Peor.'),
  ('Deuteronomy', 4, 1, 'Now, Israel, listen to the statutes and to the ordinances which I teach you, to do them, that you may live and go in and possess the land which the LORD, the God of your fathers, gives you.'),
  ('Deuteronomy', 4, 2, 'You shall not add to the word which I command you, neither shall you take away from it, that you may keep the commandments of the LORD your God which I command you.'),
  ('Deuteronomy', 4, 3, 'Your eyes have seen what the LORD did because of Baal Peor; for the LORD your God has destroyed all the men who followed Baal Peor from among you.'),
  ('Deuteronomy', 4, 4, 'But you who were faithful to the LORD your God are all alive today.'),
  ('Deuteronomy', 4, 5, 'Behold, I have taught you statutes and ordinances, even as the LORD my God commanded me, that you should do so in the middle of the land where you go in to possess it.'),
  ('Deuteronomy', 4, 6, 'Keep therefore and do them; for this is your wisdom and your understanding in the sight of the peoples who shall hear all these statutes and say, “Surely this great nation is a wise and understanding people.”'),
  ('Deuteronomy', 4, 7, 'For what great nation is there that has a god so near to them as the LORD our God is whenever we call on him?'),
  ('Deuteronomy', 4, 8, 'What great nation is there that has statutes and ordinances so righteous as all this law which I set before you today?'),
  ('Deuteronomy', 4, 9, 'Only be careful, and keep your soul diligently, lest you forget the things which your eyes saw, and lest they depart from your heart all the days of your life; but make them known to your children and your children’s children—'),
  ('Deuteronomy', 4, 10, 'the day that you stood before the LORD your God in Horeb, when the LORD said to me, “Assemble the people to me, and I will make them hear my words, that they may learn to fear me all the days that they live on the earth, and that they may teach their children.”'),
  ('Deuteronomy', 4, 11, 'You came near and stood under the mountain. The mountain burned with fire to the heart of the sky, with darkness, cloud, and thick darkness.'),
  ('Deuteronomy', 4, 12, 'The LORD spoke to you out of the middle of the fire: you heard the voice of words, but you saw no form; you only heard a voice.'),
  ('Deuteronomy', 4, 13, 'He declared to you his covenant, which he commanded you to perform, even the ten commandments. He wrote them on two stone tablets.'),
  ('Deuteronomy', 4, 14, 'The LORD commanded me at that time to teach you statutes and ordinances, that you might do them in the land where you go over to possess it.'),
  ('Deuteronomy', 4, 15, 'Be very careful, for you saw no kind of form on the day that the LORD spoke to you in Horeb out of the middle of the fire,'),
  ('Deuteronomy', 4, 16, 'lest you corrupt yourselves, and make yourself a carved image in the form of any figure, the likeness of male or female,'),
  ('Deuteronomy', 4, 17, 'the likeness of any animal that is on the earth, the likeness of any winged bird that flies in the sky,'),
  ('Deuteronomy', 4, 18, 'the likeness of anything that creeps on the ground, the likeness of any fish that is in the water under the earth;'),
  ('Deuteronomy', 4, 19, 'and lest you lift up your eyes to the sky, and when you see the sun and the moon and the stars, even all the army of the sky, you are drawn away and worship them, and serve them, which the LORD your God has allotted to all the peoples under the whole sky.'),
  ('Deuteronomy', 4, 20, 'But the LORD has taken you, and brought you out of the iron furnace, out of Egypt, to be to him a people of inheritance, as it is today.'),
  ('Deuteronomy', 4, 21, 'Furthermore the LORD was angry with me for your sakes, and swore that I should not go over the Jordan, and that I should not go in to that good land which the LORD your God gives you for an inheritance;'),
  ('Deuteronomy', 4, 22, 'but I must die in this land. I must not go over the Jordan, but you shall go over and possess that good land.'),
  ('Deuteronomy', 4, 23, 'Be careful, lest you forget the covenant of the LORD your God, which he made with you, and make yourselves a carved image in the form of anything which the LORD your God has forbidden you.'),
  ('Deuteronomy', 4, 24, 'For the LORD your God is a devouring fire, a jealous God.'),
  ('Deuteronomy', 4, 25, 'When you father children and children’s children, and you have been long in the land, and then corrupt yourselves, and make a carved image in the form of anything, and do that which is evil in the LORD your God’s sight to provoke him to anger,'),
  ('Deuteronomy', 4, 26, 'I call heaven and earth to witness against you today, that you will soon utterly perish from off the land which you go over the Jordan to possess it. You will not prolong your days on it, but will utterly be destroyed.'),
  ('Deuteronomy', 4, 27, 'The LORD will scatter you among the peoples, and you will be left few in number among the nations where the LORD will lead you away.'),
  ('Deuteronomy', 4, 28, 'There you will serve gods, the work of men’s hands, wood and stone, which neither see, nor hear, nor eat, nor smell.'),
  ('Deuteronomy', 4, 29, 'But from there you shall seek the LORD your God, and you will find him when you search after him with all your heart and with all your soul.'),
  ('Deuteronomy', 4, 30, 'When you are in oppression, and all these things have come on you, in the latter days you shall return to the LORD your God and listen to his voice.'),
  ('Deuteronomy', 4, 31, 'For the LORD your God is a merciful God. He will not fail you nor destroy you, nor forget the covenant of your fathers which he swore to them.'),
  ('Deuteronomy', 4, 32, 'For ask now of the days that are past, which were before you, since the day that God created man on the earth, and from the one end of the sky to the other, whether there has been anything as great as this thing is, or has been heard like it?'),
  ('Deuteronomy', 4, 33, 'Did a people ever hear the voice of God speaking out of the middle of the fire, as you have heard, and live?'),
  ('Deuteronomy', 4, 34, 'Or has God tried to go and take a nation for himself from among another nation, by trials, by signs, by wonders, by war, by a mighty hand, by an outstretched arm, and by great terrors, according to all that the LORD your God did for you in Egypt before your eyes?'),
  ('Deuteronomy', 4, 35, 'It was shown to you so that you might know that the LORD is God. There is no one else besides him.'),
  ('Deuteronomy', 4, 36, 'Out of heaven he made you to hear his voice, that he might instruct you. On earth he made you to see his great fire; and you heard his words out of the middle of the fire.'),
  ('Deuteronomy', 4, 37, 'Because he loved your fathers, therefore he chose their offspring after them, and brought you out with his presence, with his great power, out of Egypt;'),
  ('Deuteronomy', 4, 38, 'to drive out nations from before you greater and mightier than you, to bring you in, to give you their land for an inheritance, as it is today.'),
  ('Deuteronomy', 4, 39, 'Know therefore today, and take it to heart, that the LORD himself is God in heaven above and on the earth beneath. There is no one else.'),
  ('Deuteronomy', 4, 40, 'You shall keep his statutes and his commandments which I command you today, that it may go well with you and with your children after you, and that you may prolong your days in the land which the LORD your God gives you for all time.'),
  ('Deuteronomy', 4, 41, 'Then Moses set apart three cities beyond the Jordan toward the sunrise,'),
  ('Deuteronomy', 4, 42, 'that the man slayer might flee there, who kills his neighbor unintentionally and didn’t hate him in time past, and that fleeing to one of these cities he might live:'),
  ('Deuteronomy', 4, 43, 'Bezer in the wilderness, in the plain country, for the Reubenites; and Ramoth in Gilead for the Gadites; and Golan in Bashan for the Manassites.'),
  ('Deuteronomy', 4, 44, 'This is the law which Moses set before the children of Israel.'),
  ('Deuteronomy', 4, 45, 'These are the testimonies, and the statutes, and the ordinances which Moses spoke to the children of Israel when they came out of Egypt,'),
  ('Deuteronomy', 4, 46, 'beyond the Jordan, in the valley opposite Beth Peor, in the land of Sihon king of the Amorites, who lived at Heshbon, whom Moses and the children of Israel struck when they came out of Egypt.'),
  ('Deuteronomy', 4, 47, 'They took possession of his land and the land of Og king of Bashan, the two kings of the Amorites, who were beyond the Jordan toward the sunrise;'),
  ('Deuteronomy', 4, 48, 'from Aroer, which is on the edge of the valley of the Arnon, even to Mount Siyon (also called Hermon),'),
  ('Deuteronomy', 4, 49, 'and all the Arabah beyond the Jordan eastward, even to the sea of the Arabah, under the slopes of Pisgah.'),
  ('Deuteronomy', 5, 1, 'Moses called to all Israel, and said to them, “Hear, Israel, the statutes and the ordinances which I speak in your ears today, that you may learn them, and observe to do them.”'),
  ('Deuteronomy', 5, 2, 'The LORD our God made a covenant with us in Horeb.'),
  ('Deuteronomy', 5, 3, 'The LORD didn’t make this covenant with our fathers, but with us, even us, who are all of us here alive today.'),
  ('Deuteronomy', 5, 4, 'The LORD spoke with you face to face on the mountain out of the middle of the fire,'),
  ('Deuteronomy', 5, 5, '(I stood between the LORD and you at that time, to show you the LORD’s word; for you were afraid because of the fire, and didn’t go up onto the mountain) saying,'),
  ('Deuteronomy', 5, 6, '“I am the LORD your God, who brought you out of the land of Egypt, out of the house of bondage.'),
  ('Deuteronomy', 5, 7, '“You shall have no other gods before me.'),
  ('Deuteronomy', 5, 8, '“You shall not make a carved image for yourself—any likeness of what is in heaven above, or what is in the earth beneath, or that is in the water under the earth.'),
  ('Deuteronomy', 5, 9, 'You shall not bow yourself down to them, nor serve them, for I, the LORD your God, am a jealous God, visiting the iniquity of the fathers on the children and on the third and on the fourth generation of those who hate me'),
  ('Deuteronomy', 5, 10, 'and showing loving kindness to thousands of those who love me and keep my commandments.'),
  ('Deuteronomy', 5, 11, '“You shall not misuse the name of the LORD your God; for the LORD will not hold him guiltless who misuses his name.'),
  ('Deuteronomy', 5, 12, '“Observe the Sabbath day, to keep it holy, as the LORD your God commanded you.'),
  ('Deuteronomy', 5, 13, 'You shall labor six days, and do all your work;'),
  ('Deuteronomy', 5, 14, 'but the seventh day is a Sabbath to the LORD your God, in which you shall not do any work—neither you, nor your son, nor your daughter, nor your male servant, nor your female servant, nor your ox, nor your donkey, nor any of your livestock, nor your stranger who is within your gates; that your male servant and your female servant may rest as well as you.'),
  ('Deuteronomy', 5, 15, 'You shall remember that you were a servant in the land of Egypt, and the LORD your God brought you out of there by a mighty hand and by an outstretched arm. Therefore the LORD your God commanded you to keep the Sabbath day.'),
  ('Deuteronomy', 5, 16, '“Honor your father and your mother, as the LORD your God commanded you, that your days may be long and that it may go well with you in the land which the LORD your God gives you.'),
  ('Deuteronomy', 5, 17, '“You shall not murder.'),
  ('Deuteronomy', 5, 18, '“You shall not commit adultery.'),
  ('Deuteronomy', 5, 19, '“You shall not steal.'),
  ('Deuteronomy', 5, 20, '“You shall not give false testimony against your neighbor.'),
  ('Deuteronomy', 5, 21, '“You shall not covet your neighbor’s wife. Neither shall you desire your neighbor’s house, his field, or his male servant, or his female servant, his ox, or his donkey, or anything that is your neighbor’s.”'),
  ('Deuteronomy', 5, 22, 'The LORD spoke these words to all your assembly on the mountain out of the middle of the fire, of the cloud, and of the thick darkness, with a great voice. He added no more. He wrote them on two stone tablets, and gave them to me.'),
  ('Deuteronomy', 5, 23, 'When you heard the voice out of the middle of the darkness, while the mountain was burning with fire, you came near to me, even all the heads of your tribes, and your elders;'),
  ('Deuteronomy', 5, 24, 'and you said, “Behold, the LORD our God has shown us his glory and his greatness, and we have heard his voice out of the middle of the fire. We have seen today that God does speak with man, and he lives.'),
  ('Deuteronomy', 5, 25, 'Now therefore, why should we die? For this great fire will consume us. If we hear the LORD our God’s voice any more, then we shall die.'),
  ('Deuteronomy', 5, 26, 'For who is there of all flesh who has heard the voice of the living God speaking out of the middle of the fire, as we have, and lived?'),
  ('Deuteronomy', 5, 27, 'Go near, and hear all that the LORD our God shall say, and tell us all that the LORD our God tells you; and we will hear it, and do it.”'),
  ('Deuteronomy', 5, 28, 'The LORD heard the voice of your words when you spoke to me; and the LORD said to me, “I have heard the voice of the words of this people which they have spoken to you. They have well said all that they have spoken.'),
  ('Deuteronomy', 5, 29, 'Oh that there were such a heart in them that they would fear me and keep all my commandments always, that it might be well with them and with their children forever!'),
  ('Deuteronomy', 5, 30, '“Go tell them, ‘Return to your tents.’'),
  ('Deuteronomy', 5, 31, 'But as for you, stand here by me, and I will tell you all the commandments, and the statutes, and the ordinances, which you shall teach them, that they may do them in the land which I give them to possess.”'),
  ('Deuteronomy', 5, 32, 'You shall observe to do therefore as the LORD your God has commanded you. You shall not turn away to the right hand or to the left.'),
  ('Deuteronomy', 5, 33, 'You shall walk in all the way which the LORD your God has commanded you, that you may live and that it may be well with you, and that you may prolong your days in the land which you shall possess.'),
  ('Deuteronomy', 6, 1, 'Now these are the commandments, the statutes, and the ordinances, which the LORD your God commanded to teach you, that you might do them in the land that you go over to possess;'),
  ('Deuteronomy', 6, 2, 'that you might fear the LORD your God, to keep all his statutes and his commandments, which I command you—you, your son, and your son’s son, all the days of your life; and that your days may be prolonged.'),
  ('Deuteronomy', 6, 3, 'Hear therefore, Israel, and observe to do it, that it may be well with you, and that you may increase mightily, as the LORD, the God of your fathers, has promised to you, in a land flowing with milk and honey.'),
  ('Deuteronomy', 6, 4, 'Hear, Israel: The LORD is our God. The LORD is one.'),
  ('Deuteronomy', 6, 5, 'You shall love the LORD your God with all your heart, with all your soul, and with all your might.'),
  ('Deuteronomy', 6, 6, 'These words, which I command you today, shall be on your heart;'),
  ('Deuteronomy', 6, 7, 'and you shall teach them diligently to your children, and shall talk of them when you sit in your house, and when you walk by the way, and when you lie down, and when you rise up.'),
  ('Deuteronomy', 6, 8, 'You shall bind them for a sign on your hand, and they shall be for frontlets between your eyes.'),
  ('Deuteronomy', 6, 9, 'You shall write them on the door posts of your house and on your gates.'),
  ('Deuteronomy', 6, 10, 'It shall be, when the LORD your God brings you into the land which he swore to your fathers, to Abraham, to Isaac, and to Jacob, to give you, great and goodly cities which you didn’t build,'),
  ('Deuteronomy', 6, 11, 'and houses full of all good things which you didn’t fill, and cisterns dug out which you didn’t dig, vineyards and olive trees which you didn’t plant, and you shall eat and be full;'),
  ('Deuteronomy', 6, 12, 'then beware lest you forget the LORD, who brought you out of the land of Egypt, out of the house of bondage.'),
  ('Deuteronomy', 6, 13, 'You shall fear the LORD your God; and you shall serve him, and shall swear by his name.');
INSERT INTO bible_verses (book_name, chapter, verse, text) VALUES
  ('Deuteronomy', 6, 14, 'You shall not go after other gods, of the gods of the peoples who are around you,'),
  ('Deuteronomy', 6, 15, 'for the LORD your God among you is a jealous God, lest the anger of the LORD your God be kindled against you, and he destroy you from off the face of the earth.'),
  ('Deuteronomy', 6, 16, 'You shall not tempt the LORD your God, as you tempted him in Massah.'),
  ('Deuteronomy', 6, 17, 'You shall diligently keep the commandments of the LORD your God, and his testimonies, and his statutes, which he has commanded you.'),
  ('Deuteronomy', 6, 18, 'You shall do that which is right and good in the LORD’s sight, that it may be well with you and that you may go in and possess the good land which the LORD swore to your fathers,'),
  ('Deuteronomy', 6, 19, 'to thrust out all your enemies from before you, as the LORD has spoken.'),
  ('Deuteronomy', 6, 20, 'When your son asks you in time to come, saying, “What do the testimonies, the statutes, and the ordinances, which the LORD our God has commanded you mean?”'),
  ('Deuteronomy', 6, 21, 'then you shall tell your son, “We were Pharaoh’s slaves in Egypt. The LORD brought us out of Egypt with a mighty hand;'),
  ('Deuteronomy', 6, 22, 'and the LORD showed great and awesome signs and wonders on Egypt, on Pharaoh, and on all his house, before our eyes;'),
  ('Deuteronomy', 6, 23, 'and he brought us out from there, that he might bring us in, to give us the land which he swore to our fathers.'),
  ('Deuteronomy', 6, 24, 'The LORD commanded us to do all these statutes, to fear the LORD our God, for our good always, that he might preserve us alive, as we are today.'),
  ('Deuteronomy', 6, 25, 'It shall be righteousness to us, if we observe to do all these commandments before the LORD our God, as he has commanded us.”'),
  ('Deuteronomy', 7, 1, 'When the LORD your God brings you into the land where you go to possess it, and casts out many nations before you—the Hittite, the Girgashite, the Amorite, the Canaanite, the Perizzite, the Hivite, and the Jebusite—seven nations greater and mightier than you;'),
  ('Deuteronomy', 7, 2, 'and when the LORD your God delivers them up before you, and you strike them, then you shall utterly destroy them. You shall make no covenant with them, nor show mercy to them.'),
  ('Deuteronomy', 7, 3, 'You shall not make marriages with them. You shall not give your daughter to his son, nor shall you take his daughter for your son.'),
  ('Deuteronomy', 7, 4, 'For that would turn away your sons from following me, that they may serve other gods. So the LORD’s anger would be kindled against you, and he would destroy you quickly.'),
  ('Deuteronomy', 7, 5, 'But you shall deal with them like this: you shall break down their altars, dash their pillars in pieces, cut down their Asherah poles, and burn their engraved images with fire.'),
  ('Deuteronomy', 7, 6, 'For you are a holy people to the LORD your God. The LORD your God has chosen you to be a people for his own possession, above all peoples who are on the face of the earth.'),
  ('Deuteronomy', 7, 7, 'The LORD didn’t set his love on you nor choose you, because you were more in number than any people; for you were the fewest of all peoples;'),
  ('Deuteronomy', 7, 8, 'but because the LORD loves you, and because he desires to keep the oath which he swore to your fathers, the LORD has brought you out with a mighty hand and redeemed you out of the house of bondage, from the hand of Pharaoh king of Egypt.'),
  ('Deuteronomy', 7, 9, 'Know therefore that the LORD your God himself is God, the faithful God, who keeps covenant and loving kindness to a thousand generations with those who love him and keep his commandments,'),
  ('Deuteronomy', 7, 10, 'and repays those who hate him to their face, to destroy them. He will not be slack to him who hates him. He will repay him to his face.'),
  ('Deuteronomy', 7, 11, 'You shall therefore keep the commandments, the statutes, and the ordinances which I command you today, to do them.'),
  ('Deuteronomy', 7, 12, 'It shall happen, because you listen to these ordinances and keep and do them, that the LORD your God will keep with you the covenant and the loving kindness which he swore to your fathers.'),
  ('Deuteronomy', 7, 13, 'He will love you, bless you, and multiply you. He will also bless the fruit of your body and the fruit of your ground, your grain and your new wine and your oil, the increase of your livestock and the young of your flock, in the land which he swore to your fathers to give you.'),
  ('Deuteronomy', 7, 14, 'You will be blessed above all peoples. There won’t be male or female barren among you, or among your livestock.'),
  ('Deuteronomy', 7, 15, 'The LORD will take away from you all sickness; and he will put none of the evil diseases of Egypt, which you know, on you, but will lay them on all those who hate you.'),
  ('Deuteronomy', 7, 16, 'You shall consume all the peoples whom the LORD your God shall deliver to you. Your eye shall not pity them. You shall not serve their gods; for that would be a snare to you.'),
  ('Deuteronomy', 7, 17, 'If you shall say in your heart, “These nations are more than I; how can I dispossess them?”'),
  ('Deuteronomy', 7, 18, 'you shall not be afraid of them. You shall remember well what the LORD your God did to Pharaoh and to all Egypt:'),
  ('Deuteronomy', 7, 19, 'the great trials which your eyes saw, the signs, the wonders, the mighty hand, and the outstretched arm, by which the LORD your God brought you out. So shall the LORD your God do to all the peoples of whom you are afraid.'),
  ('Deuteronomy', 7, 20, 'Moreover the LORD your God will send the hornet among them, until those who are left, and hide themselves, perish from before you.'),
  ('Deuteronomy', 7, 21, 'You shall not be scared of them; for the LORD your God is among you, a great and awesome God.'),
  ('Deuteronomy', 7, 22, 'The LORD your God will cast out those nations before you little by little. You may not consume them at once, lest the animals of the field increase on you.'),
  ('Deuteronomy', 7, 23, 'But the LORD your God will deliver them up before you, and will confuse them with a great confusion, until they are destroyed.'),
  ('Deuteronomy', 7, 24, 'He will deliver their kings into your hand, and you shall make their name perish from under the sky. No one will be able to stand before you until you have destroyed them.'),
  ('Deuteronomy', 7, 25, 'You shall burn the engraved images of their gods with fire. You shall not covet the silver or the gold that is on them, nor take it for yourself, lest you be snared in it; for it is an abomination to the LORD your God.'),
  ('Deuteronomy', 7, 26, 'You shall not bring an abomination into your house and become a devoted thing like it. You shall utterly detest it. You shall utterly abhor it; for it is a devoted thing.'),
  ('Deuteronomy', 8, 1, 'You shall observe to do all the commandments which I command you today, that you may live, and multiply, and go in and possess the land which the LORD swore to your fathers.'),
  ('Deuteronomy', 8, 2, 'You shall remember all the way which the LORD your God has led you these forty years in the wilderness, that he might humble you, to test you, to know what was in your heart, whether you would keep his commandments or not.'),
  ('Deuteronomy', 8, 3, 'He humbled you, allowed you to be hungry, and fed you with manna, which you didn’t know, neither did your fathers know, that he might teach you that man does not live by bread only, but man lives by every word that proceeds out of the LORD’s mouth.'),
  ('Deuteronomy', 8, 4, 'Your clothing didn’t grow old on you, neither did your foot swell, these forty years.'),
  ('Deuteronomy', 8, 5, 'You shall consider in your heart that as a man disciplines his son, so the LORD your God disciplines you.'),
  ('Deuteronomy', 8, 6, 'You shall keep the commandments of the LORD your God, to walk in his ways, and to fear him.'),
  ('Deuteronomy', 8, 7, 'For the LORD your God brings you into a good land, a land of brooks of water, of springs, and underground water flowing into valleys and hills;'),
  ('Deuteronomy', 8, 8, 'a land of wheat, barley, vines, fig trees, and pomegranates; a land of olive trees and honey;'),
  ('Deuteronomy', 8, 9, 'a land in which you shall eat bread without scarcity, you shall not lack anything in it; a land whose stones are iron, and out of whose hills you may dig copper.'),
  ('Deuteronomy', 8, 10, 'You shall eat and be full, and you shall bless the LORD your God for the good land which he has given you.'),
  ('Deuteronomy', 8, 11, 'Beware lest you forget the LORD your God, in not keeping his commandments, his ordinances, and his statutes, which I command you today;'),
  ('Deuteronomy', 8, 12, 'lest, when you have eaten and are full, and have built fine houses and lived in them;'),
  ('Deuteronomy', 8, 13, 'and when your herds and your flocks multiply, and your silver and your gold is multiplied, and all that you have is multiplied;'),
  ('Deuteronomy', 8, 14, 'then your heart might be lifted up, and you forget the LORD your God, who brought you out of the land of Egypt, out of the house of bondage;'),
  ('Deuteronomy', 8, 15, 'who led you through the great and terrible wilderness, with venomous snakes and scorpions, and thirsty ground where there was no water; who poured water for you out of the rock of flint;'),
  ('Deuteronomy', 8, 16, 'who fed you in the wilderness with manna, which your fathers didn’t know, that he might humble you, and that he might prove you, to do you good at your latter end;'),
  ('Deuteronomy', 8, 17, 'and lest you say in your heart, “My power and the might of my hand has gotten me this wealth.”'),
  ('Deuteronomy', 8, 18, 'But you shall remember the LORD your God, for it is he who gives you power to get wealth, that he may establish his covenant which he swore to your fathers, as it is today.'),
  ('Deuteronomy', 8, 19, 'It shall be, if you shall forget the LORD your God, and walk after other gods, and serve them and worship them, I testify against you today that you shall surely perish.'),
  ('Deuteronomy', 8, 20, 'As the nations that the LORD makes to perish before you, so you shall perish, because you wouldn’t listen to the LORD your God’s voice.'),
  ('Deuteronomy', 9, 1, 'Hear, Israel! You are to pass over the Jordan today, to go in to dispossess nations greater and mightier than yourself, cities great and fortified up to the sky,'),
  ('Deuteronomy', 9, 2, 'a people great and tall, the sons of the Anakim, whom you know, and of whom you have heard say, “Who can stand before the sons of Anak?”'),
  ('Deuteronomy', 9, 3, 'Know therefore today that the LORD your God is he who goes over before you as a devouring fire. He will destroy them and he will bring them down before you. So you shall drive them out and make them perish quickly, as the LORD has spoken to you.'),
  ('Deuteronomy', 9, 4, 'Don’t say in your heart, after the LORD your God has thrust them out from before you, “For my righteousness the LORD has brought me in to possess this land;” because the LORD drives them out before you because of the wickedness of these nations.'),
  ('Deuteronomy', 9, 5, 'Not for your righteousness or for the uprightness of your heart do you go in to possess their land; but for the wickedness of these nations the LORD your God does drive them out from before you, and that he may establish the word which the LORD swore to your fathers, to Abraham, to Isaac, and to Jacob.'),
  ('Deuteronomy', 9, 6, 'Know therefore that the LORD your God doesn’t give you this good land to possess for your righteousness, for you are a stiff-necked people.'),
  ('Deuteronomy', 9, 7, 'Remember, and don’t forget, how you provoked the LORD your God to wrath in the wilderness. From the day that you left the land of Egypt until you came to this place, you have been rebellious against the LORD.'),
  ('Deuteronomy', 9, 8, 'Also in Horeb you provoked the LORD to wrath, and the LORD was angry with you to destroy you.'),
  ('Deuteronomy', 9, 9, 'When I had gone up onto the mountain to receive the stone tablets, even the tablets of the covenant which the LORD made with you, then I stayed on the mountain forty days and forty nights. I neither ate bread nor drank water.'),
  ('Deuteronomy', 9, 10, 'The LORD delivered to me the two stone tablets written with God’s finger. On them were all the words which the LORD spoke with you on the mountain out of the middle of the fire in the day of the assembly.'),
  ('Deuteronomy', 9, 11, 'It came to pass at the end of forty days and forty nights that the LORD gave me the two stone tablets, even the tablets of the covenant.'),
  ('Deuteronomy', 9, 12, 'The LORD said to me, “Arise, get down quickly from here; for your people whom you have brought out of Egypt have corrupted themselves. They have quickly turned away from the way which I commanded them. They have made a molten image for themselves!”'),
  ('Deuteronomy', 9, 13, 'Furthermore the LORD spoke to me, saying, “I have seen these people, and behold, they are a stiff-necked people.'),
  ('Deuteronomy', 9, 14, 'Leave me alone, that I may destroy them, and blot out their name from under the sky; and I will make of you a nation mightier and greater than they.”'),
  ('Deuteronomy', 9, 15, 'So I turned and came down from the mountain, and the mountain was burning with fire. The two tablets of the covenant were in my two hands.'),
  ('Deuteronomy', 9, 16, 'I looked, and behold, you had sinned against the LORD your God. You had made yourselves a molded calf. You had quickly turned away from the way which the LORD had commanded you.'),
  ('Deuteronomy', 9, 17, 'I took hold of the two tablets, and threw them out of my two hands, and broke them before your eyes.'),
  ('Deuteronomy', 9, 18, 'I fell down before the LORD, as at the first, forty days and forty nights. I neither ate bread nor drank water, because of all your sin which you sinned, in doing that which was evil in the LORD’s sight, to provoke him to anger.'),
  ('Deuteronomy', 9, 19, 'For I was afraid of the anger and hot displeasure with which the LORD was angry against you to destroy you. But the LORD listened to me that time also.'),
  ('Deuteronomy', 9, 20, 'The LORD was angry enough with Aaron to destroy him. I prayed for Aaron also at the same time.'),
  ('Deuteronomy', 9, 21, 'I took your sin, the calf which you had made, and burned it with fire, and crushed it, grinding it very small, until it was as fine as dust. I threw its dust into the brook that descended out of the mountain.'),
  ('Deuteronomy', 9, 22, 'At Taberah, at Massah, and at Kibroth Hattaavah you provoked the LORD to wrath.'),
  ('Deuteronomy', 9, 23, 'When the LORD sent you from Kadesh Barnea, saying, “Go up and possess the land which I have given you,” you rebelled against the commandment of the LORD your God, and you didn’t believe him or listen to his voice.'),
  ('Deuteronomy', 9, 24, 'You have been rebellious against the LORD from the day that I knew you.'),
  ('Deuteronomy', 9, 25, 'So I fell down before the LORD the forty days and forty nights that I fell down, because the LORD had said he would destroy you.'),
  ('Deuteronomy', 9, 26, 'I prayed to the LORD, and said, “Lord GOD, don’t destroy your people and your inheritance that you have redeemed through your greatness, that you have brought out of Egypt with a mighty hand.'),
  ('Deuteronomy', 9, 27, 'Remember your servants, Abraham, Isaac, and Jacob. Don’t look at the stubbornness of this people, nor at their wickedness, nor at their sin,'),
  ('Deuteronomy', 9, 28, 'lest the land you brought us out from say, ‘Because the LORD was not able to bring them into the land which he promised to them, and because he hated them, he has brought them out to kill them in the wilderness.’'),
  ('Deuteronomy', 9, 29, 'Yet they are your people and your inheritance, which you brought out by your great power and by your outstretched arm.”'),
  ('Deuteronomy', 10, 1, 'At that time the LORD said to me, “Cut two stone tablets like the first, and come up to me onto the mountain, and make an ark of wood.'),
  ('Deuteronomy', 10, 2, 'I will write on the tablets the words that were on the first tablets which you broke, and you shall put them in the ark.”'),
  ('Deuteronomy', 10, 3, 'So I made an ark of acacia wood, and cut two stone tablets like the first, and went up onto the mountain, having the two tablets in my hand.'),
  ('Deuteronomy', 10, 4, 'He wrote on the tablets, according to the first writing, the ten commandments, which the LORD spoke to you on the mountain out of the middle of the fire in the day of the assembly; and the LORD gave them to me.'),
  ('Deuteronomy', 10, 5, 'I turned and came down from the mountain, and put the tablets in the ark which I had made; and there they are as the LORD commanded me.'),
  ('Deuteronomy', 10, 6, '(The children of Israel traveled from Beeroth Bene Jaakan to Moserah. There Aaron died, and there he was buried; and Eleazar his son ministered in the priest’s office in his place.'),
  ('Deuteronomy', 10, 7, 'From there they traveled to Gudgodah; and from Gudgodah to Jotbathah, a land of brooks of water.'),
  ('Deuteronomy', 10, 8, 'At that time the LORD set apart the tribe of Levi to bear the ark of the LORD’s covenant, to stand before the LORD to minister to him, and to bless in his name, to this day.'),
  ('Deuteronomy', 10, 9, 'Therefore Levi has no portion nor inheritance with his brothers; the LORD is his inheritance, according as the LORD your God spoke to him.)'),
  ('Deuteronomy', 10, 10, 'I stayed on the mountain, as at the first time, forty days and forty nights; and the LORD listened to me that time also. The LORD would not destroy you.'),
  ('Deuteronomy', 10, 11, 'The LORD said to me, “Arise, take your journey before the people; and they shall go in and possess the land which I swore to their fathers to give to them.”'),
  ('Deuteronomy', 10, 12, 'Now, Israel, what does the LORD your God require of you, but to fear the LORD your God, to walk in all his ways, to love him, and to serve the LORD your God with all your heart and with all your soul,'),
  ('Deuteronomy', 10, 13, 'to keep the LORD’s commandments and statutes, which I command you today for your good?');
INSERT INTO bible_verses (book_name, chapter, verse, text) VALUES
  ('Deuteronomy', 10, 14, 'Behold, to the LORD your God belongs heaven, the heaven of heavens, and the earth, with all that is therein.'),
  ('Deuteronomy', 10, 15, 'Only the LORD had a delight in your fathers to love them, and he chose their offspring after them, even you above all peoples, as it is today.'),
  ('Deuteronomy', 10, 16, 'Circumcise therefore the foreskin of your heart, and be no more stiff-necked.'),
  ('Deuteronomy', 10, 17, 'For the LORD your God, he is God of gods and Lord of lords, the great God, the mighty, and the awesome, who doesn’t respect persons or take bribes.'),
  ('Deuteronomy', 10, 18, 'He executes justice for the fatherless and widow and loves the foreigner in giving him food and clothing.'),
  ('Deuteronomy', 10, 19, 'Therefore love the foreigner, for you were foreigners in the land of Egypt.'),
  ('Deuteronomy', 10, 20, 'You shall fear the LORD your God. You shall serve him. You shall cling to him, and you shall swear by his name.'),
  ('Deuteronomy', 10, 21, 'He is your praise, and he is your God, who has done for you these great and awesome things which your eyes have seen.'),
  ('Deuteronomy', 10, 22, 'Your fathers went down into Egypt with seventy persons; and now the LORD your God has made you as the stars of the sky for multitude.'),
  ('Deuteronomy', 11, 1, 'Therefore you shall love the LORD your God, and keep his instructions, his statutes, his ordinances, and his commandments, always.'),
  ('Deuteronomy', 11, 2, 'Know this day—for I don’t speak with your children who have not known, and who have not seen the chastisement of the LORD your God, his greatness, his mighty hand, his outstretched arm,'),
  ('Deuteronomy', 11, 3, 'his signs, and his works, which he did in the middle of Egypt to Pharaoh the king of Egypt, and to all his land;'),
  ('Deuteronomy', 11, 4, 'and what he did to the army of Egypt, to their horses, and to their chariots; how he made the water of the Red Sea to overflow them as they pursued you, and how the LORD has destroyed them to this day;'),
  ('Deuteronomy', 11, 5, 'and what he did to you in the wilderness until you came to this place;'),
  ('Deuteronomy', 11, 6, 'and what he did to Dathan and Abiram, the sons of Eliab, the son of Reuben—how the earth opened its mouth and swallowed them up, with their households, their tents, and every living thing that followed them, in the middle of all Israel;'),
  ('Deuteronomy', 11, 7, 'but your eyes have seen all of the LORD’s great work which he did.'),
  ('Deuteronomy', 11, 8, 'Therefore you shall keep the entire commandment which I command you today, that you may be strong, and go in and possess the land that you go over to possess;'),
  ('Deuteronomy', 11, 9, 'and that you may prolong your days in the land which the LORD swore to your fathers to give to them and to their offspring, a land flowing with milk and honey.'),
  ('Deuteronomy', 11, 10, 'For the land, where you go in to possess isn’t like the land of Egypt that you came out of, where you sowed your seed and watered it with your foot, as a garden of herbs;'),
  ('Deuteronomy', 11, 11, 'but the land that you go over to possess is a land of hills and valleys which drinks water from the rain of the sky,'),
  ('Deuteronomy', 11, 12, 'a land which the LORD your God cares for. The LORD your God’s eyes are always on it, from the beginning of the year even to the end of the year.'),
  ('Deuteronomy', 11, 13, 'It shall happen, if you shall listen diligently to my commandments which I command you today, to love the LORD your God, and to serve him with all your heart and with all your soul,'),
  ('Deuteronomy', 11, 14, 'that I will give the rain for your land in its season, the early rain and the latter rain, that you may gather in your grain, your new wine, and your oil.'),
  ('Deuteronomy', 11, 15, 'I will give grass in your fields for your livestock, and you shall eat and be full.'),
  ('Deuteronomy', 11, 16, 'Be careful, lest your heart be deceived, and you turn away to serve other gods and worship them;'),
  ('Deuteronomy', 11, 17, 'and the LORD’s anger be kindled against you, and he shut up the sky so that there is no rain, and the land doesn’t yield its fruit; and you perish quickly from off the good land which the LORD gives you.'),
  ('Deuteronomy', 11, 18, 'Therefore you shall lay up these words of mine in your heart and in your soul. You shall bind them for a sign on your hand, and they shall be for frontlets between your eyes.'),
  ('Deuteronomy', 11, 19, 'You shall teach them to your children, talking of them when you sit in your house, when you walk by the way, when you lie down, and when you rise up.'),
  ('Deuteronomy', 11, 20, 'You shall write them on the door posts of your house and on your gates;'),
  ('Deuteronomy', 11, 21, 'that your days and your children’s days may be multiplied in the land which the LORD swore to your fathers to give them, as the days of the heavens above the earth.'),
  ('Deuteronomy', 11, 22, 'For if you shall diligently keep all these commandments which I command you—to do them, to love the LORD your God, to walk in all his ways, and to cling to him—'),
  ('Deuteronomy', 11, 23, 'then the LORD will drive out all these nations from before you, and you shall dispossess nations greater and mightier than yourselves.'),
  ('Deuteronomy', 11, 24, 'Every place on which the sole of your foot treads shall be yours: from the wilderness and Lebanon, from the river, the river Euphrates, even to the western sea shall be your border.'),
  ('Deuteronomy', 11, 25, 'No man will be able to stand before you. The LORD your God will lay the fear of you and the dread of you on all the land that you tread on, as he has spoken to you.'),
  ('Deuteronomy', 11, 26, 'Behold, I set before you today a blessing and a curse:'),
  ('Deuteronomy', 11, 27, 'the blessing, if you listen to the commandments of the LORD your God, which I command you today;'),
  ('Deuteronomy', 11, 28, 'and the curse, if you do not listen to the commandments of the LORD your God, but turn away out of the way which I command you today, to go after other gods which you have not known.'),
  ('Deuteronomy', 11, 29, 'It shall happen, when the LORD your God brings you into the land that you go to possess, that you shall set the blessing on Mount Gerizim, and the curse on Mount Ebal.'),
  ('Deuteronomy', 11, 30, 'Aren’t they beyond the Jordan, behind the way of the going down of the sun, in the land of the Canaanites who dwell in the Arabah near Gilgal, beside the oaks of Moreh?'),
  ('Deuteronomy', 11, 31, 'For you are to pass over the Jordan to go in to possess the land which the LORD your God gives you, and you shall possess it and dwell in it.'),
  ('Deuteronomy', 11, 32, 'You shall observe to do all the statutes and the ordinances which I set before you today.'),
  ('Deuteronomy', 12, 1, 'These are the statutes and the ordinances which you shall observe to do in the land which the LORD, the God of your fathers, has given you to possess all the days that you live on the earth.'),
  ('Deuteronomy', 12, 2, 'You shall surely destroy all the places in which the nations that you shall dispossess served their gods: on the high mountains, and on the hills, and under every green tree.'),
  ('Deuteronomy', 12, 3, 'You shall break down their altars, dash their pillars in pieces, and burn their Asherah poles with fire. You shall cut down the engraved images of their gods. You shall destroy their name out of that place.'),
  ('Deuteronomy', 12, 4, 'You shall not do so to the LORD your God.'),
  ('Deuteronomy', 12, 5, 'But to the place which the LORD your God shall choose out of all your tribes, to put his name there, you shall seek his habitation, and you shall come there.'),
  ('Deuteronomy', 12, 6, 'You shall bring your burnt offerings, your sacrifices, your tithes, the wave offering of your hand, your vows, your free will offerings, and the firstborn of your herd and of your flock there.'),
  ('Deuteronomy', 12, 7, 'There you shall eat before the LORD your God, and you shall rejoice in all that you put your hand to, you and your households, in which the LORD your God has blessed you.'),
  ('Deuteronomy', 12, 8, 'You shall not do all the things that we do here today, every man whatever is right in his own eyes;'),
  ('Deuteronomy', 12, 9, 'for you haven’t yet come to the rest and to the inheritance which the LORD your God gives you.'),
  ('Deuteronomy', 12, 10, 'But when you go over the Jordan and dwell in the land which the LORD your God causes you to inherit, and he gives you rest from all your enemies around you, so that you dwell in safety,'),
  ('Deuteronomy', 12, 11, 'then it shall happen that to the place which the LORD your God shall choose, to cause his name to dwell there, there you shall bring all that I command you: your burnt offerings, your sacrifices, your tithes, the wave offering of your hand, and all your choice vows which you vow to the LORD.'),
  ('Deuteronomy', 12, 12, 'You shall rejoice before the LORD your God—you, and your sons, your daughters, your male servants, your female servants, and the Levite who is within your gates, because he has no portion nor inheritance with you.'),
  ('Deuteronomy', 12, 13, 'Be careful that you don’t offer your burnt offerings in every place that you see;'),
  ('Deuteronomy', 12, 14, 'but in the place which the LORD chooses in one of your tribes, there you shall offer your burnt offerings, and there you shall do all that I command you.'),
  ('Deuteronomy', 12, 15, 'Yet you may kill and eat meat within all your gates, after all the desire of your soul, according to the LORD your God’s blessing which he has given you. The unclean and the clean may eat of it, as of the gazelle and the deer.'),
  ('Deuteronomy', 12, 16, 'Only you shall not eat the blood. You shall pour it out on the earth like water.'),
  ('Deuteronomy', 12, 17, 'You may not eat within your gates the tithe of your grain, or of your new wine, or of your oil, or the firstborn of your herd or of your flock, nor any of your vows which you vow, nor your free will offerings, nor the wave offering of your hand;'),
  ('Deuteronomy', 12, 18, 'but you shall eat them before the LORD your God in the place which the LORD your God shall choose: you, your son, your daughter, your male servant, your female servant, and the Levite who is within your gates. You shall rejoice before the LORD your God in all that you put your hand to.'),
  ('Deuteronomy', 12, 19, 'Be careful that you don’t forsake the Levite as long as you live in your land.'),
  ('Deuteronomy', 12, 20, 'When the LORD your God enlarges your border, as he has promised you, and you say, “I want to eat meat,” because your soul desires to eat meat, you may eat meat, after all the desire of your soul.'),
  ('Deuteronomy', 12, 21, 'If the place which the LORD your God shall choose to put his name is too far from you, then you shall kill of your herd and of your flock, which the LORD has given you, as I have commanded you; and you may eat within your gates, after all the desire of your soul.'),
  ('Deuteronomy', 12, 22, 'Even as the gazelle and as the deer is eaten, so you shall eat of it. The unclean and the clean may eat of it alike.'),
  ('Deuteronomy', 12, 23, 'Only be sure that you don’t eat the blood; for the blood is the life. You shall not eat the life with the meat.'),
  ('Deuteronomy', 12, 24, 'You shall not eat it. You shall pour it out on the earth like water.'),
  ('Deuteronomy', 12, 25, 'You shall not eat it, that it may go well with you and with your children after you, when you do that which is right in the LORD’s eyes.'),
  ('Deuteronomy', 12, 26, 'Only your holy things which you have, and your vows, you shall take and go to the place which the LORD shall choose.'),
  ('Deuteronomy', 12, 27, 'You shall offer your burnt offerings, the meat and the blood, on the LORD your God’s altar. The blood of your sacrifices shall be poured out on the LORD your God’s altar, and you shall eat the meat.'),
  ('Deuteronomy', 12, 28, 'Observe and hear all these words which I command you, that it may go well with you and with your children after you forever, when you do that which is good and right in the LORD your God’s eyes.'),
  ('Deuteronomy', 12, 29, 'When the LORD your God cuts off the nations from before you where you go in to dispossess them, and you dispossess them and dwell in their land,'),
  ('Deuteronomy', 12, 30, 'be careful that you are not ensnared to follow them after they are destroyed from before you, and that you not inquire after their gods, saying, “How do these nations serve their gods? I will do likewise.”'),
  ('Deuteronomy', 12, 31, 'You shall not do so to the LORD your God; for every abomination to the LORD, which he hates, they have done to their gods; for they even burn their sons and their daughters in the fire to their gods.'),
  ('Deuteronomy', 12, 32, 'Whatever thing I command you, that you shall observe to do. You shall not add to it, nor take away from it.'),
  ('Deuteronomy', 13, 1, 'If a prophet or a dreamer of dreams arises among you, and he gives you a sign or a wonder,'),
  ('Deuteronomy', 13, 2, 'and the sign or the wonder comes to pass, of which he spoke to you, saying, “Let’s go after other gods” (which you have not known) “and let’s serve them,”'),
  ('Deuteronomy', 13, 3, 'you shall not listen to the words of that prophet, or to that dreamer of dreams; for the LORD your God is testing you, to know whether you love the LORD your God with all your heart and with all your soul.'),
  ('Deuteronomy', 13, 4, 'You shall walk after the LORD your God, fear him, keep his commandments, and obey his voice. You shall serve him, and cling to him.'),
  ('Deuteronomy', 13, 5, 'That prophet, or that dreamer of dreams, shall be put to death, because he has spoken rebellion against the LORD your God, who brought you out of the land of Egypt and redeemed you out of the house of bondage, to draw you aside out of the way which the LORD your God commanded you to walk in. So you shall remove the evil from among you.'),
  ('Deuteronomy', 13, 6, 'If your brother, the son of your mother, or your son, or your daughter, or the wife of your bosom, or your friend who is as your own soul, entices you secretly, saying, “Let’s go and serve other gods”—which you have not known, you, nor your fathers;'),
  ('Deuteronomy', 13, 7, 'of the gods of the peoples who are around you, near to you, or far off from you, from the one end of the earth even to the other end of the earth—'),
  ('Deuteronomy', 13, 8, 'you shall not consent to him nor listen to him; neither shall your eye pity him, neither shall you spare, neither shall you conceal him;'),
  ('Deuteronomy', 13, 9, 'but you shall surely kill him. Your hand shall be first on him to put him to death, and afterwards the hands of all the people.'),
  ('Deuteronomy', 13, 10, 'You shall stone him to death with stones, because he has sought to draw you away from the LORD your God, who brought you out of the land of Egypt, out of the house of bondage.'),
  ('Deuteronomy', 13, 11, 'All Israel shall hear, and fear, and shall not do any more wickedness like this among you.'),
  ('Deuteronomy', 13, 12, 'If you hear about one of your cities, which the LORD your God gives you to dwell there, that'),
  ('Deuteronomy', 13, 13, 'certain wicked fellows have gone out from among you and have drawn away the inhabitants of their city, saying, “Let’s go and serve other gods,” which you have not known,'),
  ('Deuteronomy', 13, 14, 'then you shall inquire, investigate, and ask diligently. Behold, if it is true, and the thing certain, that such abomination was done among you,'),
  ('Deuteronomy', 13, 15, 'you shall surely strike the inhabitants of that city with the edge of the sword, destroying it utterly, with all that is therein and its livestock, with the edge of the sword.'),
  ('Deuteronomy', 13, 16, 'You shall gather all its plunder into the middle of its street, and shall burn with fire the city, with all of its plunder, to the LORD your God. It shall be a heap forever. It shall not be built again.'),
  ('Deuteronomy', 13, 17, 'Nothing of the devoted thing shall cling to your hand, that the LORD may turn from the fierceness of his anger and show you mercy, and have compassion on you and multiply you, as he has sworn to your fathers,'),
  ('Deuteronomy', 13, 18, 'when you listen to the LORD your God’s voice, to keep all his commandments which I command you today, to do that which is right in the LORD your God’s eyes.'),
  ('Deuteronomy', 14, 1, 'You are the children of the LORD your God. You shall not cut yourselves, nor make any baldness between your eyes for the dead.'),
  ('Deuteronomy', 14, 2, 'For you are a holy people to the LORD your God, and the LORD has chosen you to be a people for his own possession, above all peoples who are on the face of the earth.'),
  ('Deuteronomy', 14, 3, 'You shall not eat any abominable thing.'),
  ('Deuteronomy', 14, 4, 'These are the animals which you may eat: the ox, the sheep, the goat,'),
  ('Deuteronomy', 14, 5, 'the deer, the gazelle, the roebuck, the wild goat, the ibex, the antelope, and the chamois.'),
  ('Deuteronomy', 14, 6, 'Every animal that parts the hoof, and has the hoof split in two and chews the cud, among the animals, you may eat.'),
  ('Deuteronomy', 14, 7, 'Nevertheless these you shall not eat of them that chew the cud, or of those who have the hoof split: the camel, the hare, and the rabbit. Because they chew the cud but don’t part the hoof, they are unclean to you.'),
  ('Deuteronomy', 14, 8, 'The pig, because it has a split hoof but doesn’t chew the cud, is unclean to you. You shall not eat their meat. You shall not touch their carcasses.'),
  ('Deuteronomy', 14, 9, 'These you may eat of all that are in the waters: you may eat whatever has fins and scales.');
INSERT INTO bible_verses (book_name, chapter, verse, text) VALUES
  ('Deuteronomy', 14, 10, 'You shall not eat whatever doesn’t have fins and scales. It is unclean to you.'),
  ('Deuteronomy', 14, 11, 'Of all clean birds you may eat.'),
  ('Deuteronomy', 14, 12, 'But these are they of which you shall not eat: the eagle, the vulture, the osprey,'),
  ('Deuteronomy', 14, 13, 'the red kite, the falcon, the kite of any kind,'),
  ('Deuteronomy', 14, 14, 'every raven of any kind,'),
  ('Deuteronomy', 14, 15, 'the ostrich, the owl, the seagull, the hawk of any kind,'),
  ('Deuteronomy', 14, 16, 'the little owl, the great owl, the horned owl,'),
  ('Deuteronomy', 14, 17, 'the pelican, the vulture, the cormorant,'),
  ('Deuteronomy', 14, 18, 'the stork, the heron after its kind, the hoopoe, and the bat.'),
  ('Deuteronomy', 14, 19, 'All winged creeping things are unclean to you. They shall not be eaten.'),
  ('Deuteronomy', 14, 20, 'Of all clean birds you may eat.'),
  ('Deuteronomy', 14, 21, 'You shall not eat of anything that dies of itself. You may give it to the foreigner living among you who is within your gates, that he may eat it; or you may sell it to a foreigner; for you are a holy people to the LORD your God. You shall not boil a young goat in its mother’s milk.'),
  ('Deuteronomy', 14, 22, 'You shall surely tithe all the increase of your seed, that which comes out of the field year by year.'),
  ('Deuteronomy', 14, 23, 'You shall eat before the LORD your God, in the place which he chooses to cause his name to dwell, the tithe of your grain, of your new wine, and of your oil, and the firstborn of your herd and of your flock; that you may learn to fear the LORD your God always.'),
  ('Deuteronomy', 14, 24, 'If the way is too long for you, so that you are not able to carry it because the place which the LORD your God shall choose to set his name there is too far from you, when the LORD your God blesses you,'),
  ('Deuteronomy', 14, 25, 'then you shall turn it into money, bind up the money in your hand, and shall go to the place which the LORD your God shall choose.'),
  ('Deuteronomy', 14, 26, 'You shall trade the money for whatever your soul desires: for cattle, or for sheep, or for wine, or for strong drink, or for whatever your soul asks of you. You shall eat there before the LORD your God, and you shall rejoice, you and your household.'),
  ('Deuteronomy', 14, 27, 'You shall not forsake the Levite who is within your gates, for he has no portion nor inheritance with you.'),
  ('Deuteronomy', 14, 28, 'At the end of every three years you shall bring all the tithe of your increase in the same year, and shall store it within your gates.'),
  ('Deuteronomy', 14, 29, 'The Levite, because he has no portion nor inheritance with you, as well as the foreigner living among you, the fatherless, and the widow who are within your gates shall come, and shall eat and be satisfied; that the LORD your God may bless you in all the work of your hand which you do.'),
  ('Deuteronomy', 15, 1, 'At the end of every seven years, you shall cancel debts.'),
  ('Deuteronomy', 15, 2, 'This is the way it shall be done: every creditor shall release that which he has lent to his neighbor. He shall not require payment from his neighbor and his brother, because the LORD’s release has been proclaimed.'),
  ('Deuteronomy', 15, 3, 'Of a foreigner you may require it; but whatever of yours is with your brother, your hand shall release.'),
  ('Deuteronomy', 15, 4, 'However there will be no poor with you (for the LORD will surely bless you in the land which the LORD your God gives you for an inheritance to possess)'),
  ('Deuteronomy', 15, 5, 'if only you diligently listen to the LORD your God’s voice, to observe to do all this commandment which I command you today.'),
  ('Deuteronomy', 15, 6, 'For the LORD your God will bless you, as he promised you. You will lend to many nations, but you will not borrow. You will rule over many nations, but they will not rule over you.'),
  ('Deuteronomy', 15, 7, 'If a poor man, one of your brothers, is with you within any of your gates in your land which the LORD your God gives you, you shall not harden your heart, nor shut your hand from your poor brother;'),
  ('Deuteronomy', 15, 8, 'but you shall surely open your hand to him, and shall surely lend him sufficient for his need, which he lacks.'),
  ('Deuteronomy', 15, 9, 'Beware that there not be a wicked thought in your heart, saying, “The seventh year, the year of release, is at hand,” and your eye be evil against your poor brother and you give him nothing; and he cry to the LORD against you, and it be sin to you.'),
  ('Deuteronomy', 15, 10, 'You shall surely give, and your heart shall not be grieved when you give to him, because it is for this thing the LORD your God will bless you in all your work and in all that you put your hand to.'),
  ('Deuteronomy', 15, 11, 'For the poor will never cease out of the land. Therefore I command you to surely open your hand to your brother, to your needy, and to your poor, in your land.'),
  ('Deuteronomy', 15, 12, 'If your brother, a Hebrew man, or a Hebrew woman, is sold to you and serves you six years, then in the seventh year you shall let him go free from you.'),
  ('Deuteronomy', 15, 13, 'When you let him go free from you, you shall not let him go empty.'),
  ('Deuteronomy', 15, 14, 'You shall furnish him liberally out of your flock, out of your threshing floor, and out of your wine press. As the LORD your God has blessed you, you shall give to him.'),
  ('Deuteronomy', 15, 15, 'You shall remember that you were a slave in the land of Egypt, and the LORD your God redeemed you. Therefore I command you this thing today.'),
  ('Deuteronomy', 15, 16, 'It shall be, if he tells you, “I will not go out from you,” because he loves you and your house, because he is well with you,'),
  ('Deuteronomy', 15, 17, 'then you shall take an awl, and thrust it through his ear to the door, and he shall be your servant forever. Also to your female servant you shall do likewise.'),
  ('Deuteronomy', 15, 18, 'It shall not seem hard to you when you let him go free from you, for he has been double the value of a hired hand as he served you six years. The LORD your God will bless you in all that you do.'),
  ('Deuteronomy', 15, 19, 'You shall dedicate all the firstborn males that are born of your herd and of your flock to the LORD your God. You shall do no work with the firstborn of your herd, nor shear the firstborn of your flock.'),
  ('Deuteronomy', 15, 20, 'You shall eat it before the LORD your God year by year in the place which the LORD shall choose, you and your household.'),
  ('Deuteronomy', 15, 21, 'If it has any defect—is lame or blind, or has any defect whatever, you shall not sacrifice it to the LORD your God.'),
  ('Deuteronomy', 15, 22, 'You shall eat it within your gates. The unclean and the clean shall eat it alike, as the gazelle and as the deer.'),
  ('Deuteronomy', 15, 23, 'Only you shall not eat its blood. You shall pour it out on the ground like water.'),
  ('Deuteronomy', 16, 1, 'Observe the month of Abib, and keep the Passover to the LORD your God; for in the month of Abib the LORD your God brought you out of Egypt by night.'),
  ('Deuteronomy', 16, 2, 'You shall sacrifice the Passover to the LORD your God, of the flock and the herd, in the place which the LORD shall choose to cause his name to dwell there.'),
  ('Deuteronomy', 16, 3, 'You shall eat no leavened bread with it. You shall eat unleavened bread with it seven days, even the bread of affliction (for you came out of the land of Egypt in haste) that you may remember the day when you came out of the land of Egypt all the days of your life.'),
  ('Deuteronomy', 16, 4, 'No yeast shall be seen with you in all your borders seven days; neither shall any of the meat, which you sacrifice the first day at evening, remain all night until the morning.'),
  ('Deuteronomy', 16, 5, 'You may not sacrifice the Passover within any of your gates which the LORD your God gives you;'),
  ('Deuteronomy', 16, 6, 'but at the place which the LORD your God shall choose to cause his name to dwell in, there you shall sacrifice the Passover at evening, at the going down of the sun, at the season that you came out of Egypt.'),
  ('Deuteronomy', 16, 7, 'You shall roast and eat it in the place which the LORD your God chooses. In the morning you shall return to your tents.'),
  ('Deuteronomy', 16, 8, 'Six days you shall eat unleavened bread. On the seventh day shall be a solemn assembly to the LORD your God. You shall do no work.'),
  ('Deuteronomy', 16, 9, 'You shall count for yourselves seven weeks. From the time you begin to put the sickle to the standing grain you shall begin to count seven weeks.'),
  ('Deuteronomy', 16, 10, 'You shall keep the feast of weeks to the LORD your God with a tribute of a free will offering of your hand, which you shall give according to how the LORD your God blesses you.'),
  ('Deuteronomy', 16, 11, 'You shall rejoice before the LORD your God: you, your son, your daughter, your male servant, your female servant, the Levite who is within your gates, the foreigner, the fatherless, and the widow who are among you, in the place which the LORD your God shall choose to cause his name to dwell there.'),
  ('Deuteronomy', 16, 12, 'You shall remember that you were a slave in Egypt. You shall observe and do these statutes.'),
  ('Deuteronomy', 16, 13, 'You shall keep the feast of booths seven days, after you have gathered in from your threshing floor and from your wine press.'),
  ('Deuteronomy', 16, 14, 'You shall rejoice in your feast, you, your son, your daughter, your male servant, your female servant, the Levite, the foreigner, the fatherless, and the widow who are within your gates.'),
  ('Deuteronomy', 16, 15, 'You shall keep a feast to the LORD your God seven days in the place which the LORD chooses, because the LORD your God will bless you in all your increase and in all the work of your hands, and you shall be altogether joyful.'),
  ('Deuteronomy', 16, 16, 'Three times in a year all of your males shall appear before the LORD your God in the place which he chooses: in the feast of unleavened bread, in the feast of weeks, and in the feast of booths. They shall not appear before the LORD empty.'),
  ('Deuteronomy', 16, 17, 'Every man shall give as he is able, according to the LORD your God’s blessing which he has given you.'),
  ('Deuteronomy', 16, 18, 'You shall make judges and officers in all your gates, which the LORD your God gives you, according to your tribes; and they shall judge the people with righteous judgment.'),
  ('Deuteronomy', 16, 19, 'You shall not pervert justice. You shall not show partiality. You shall not take a bribe, for a bribe blinds the eyes of the wise and perverts the words of the righteous.'),
  ('Deuteronomy', 16, 20, 'You shall follow that which is altogether just, that you may live and inherit the land which the LORD your God gives you.'),
  ('Deuteronomy', 16, 21, 'You shall not plant for yourselves an Asherah of any kind of tree beside the LORD your God’s altar, which you shall make for yourselves.'),
  ('Deuteronomy', 16, 22, 'Neither shall you set yourself up a sacred stone which the LORD your God hates.'),
  ('Deuteronomy', 17, 1, 'You shall not sacrifice to the LORD your God an ox or a sheep in which is a defect or anything evil; for that is an abomination to the LORD your God.'),
  ('Deuteronomy', 17, 2, 'If there is found among you, within any of your gates which the LORD your God gives you, a man or woman who does that which is evil in the LORD your God’s sight in transgressing his covenant,'),
  ('Deuteronomy', 17, 3, 'and has gone and served other gods and worshiped them, or the sun, or the moon, or any of the stars of the sky, which I have not commanded,'),
  ('Deuteronomy', 17, 4, 'and you are told, and you have heard of it, then you shall inquire diligently. Behold, if it is true, and the thing certain, that such abomination is done in Israel,'),
  ('Deuteronomy', 17, 5, 'then you shall bring out that man or that woman who has done this evil thing to your gates, even that same man or woman; and you shall stone them to death with stones.'),
  ('Deuteronomy', 17, 6, 'At the mouth of two witnesses, or three witnesses, he who is to die shall be put to death. At the mouth of one witness he shall not be put to death.'),
  ('Deuteronomy', 17, 7, 'The hands of the witnesses shall be first on him to put him to death, and afterward the hands of all the people. So you shall remove the evil from among you.'),
  ('Deuteronomy', 17, 8, 'If there arises a matter too hard for you in judgment, between blood and blood, between plea and plea, and between stroke and stroke, being matters of controversy within your gates, then you shall arise, and go up to the place which the LORD your God chooses.'),
  ('Deuteronomy', 17, 9, 'You shall come to the priests who are Levites and to the judge who shall be in those days. You shall inquire, and they shall give you the verdict.'),
  ('Deuteronomy', 17, 10, 'You shall do according to the decisions of the verdict which they shall give you from that place which the LORD chooses. You shall observe to do according to all that they shall teach you.'),
  ('Deuteronomy', 17, 11, 'According to the decisions of the law which they shall teach you, and according to the judgment which they shall tell you, you shall do. You shall not turn away from the sentence which they announce to you, to the right hand, nor to the left.'),
  ('Deuteronomy', 17, 12, 'The man who does presumptuously in not listening to the priest who stands to minister there before the LORD your God, or to the judge, even that man shall die. You shall put away the evil from Israel.'),
  ('Deuteronomy', 17, 13, 'All the people shall hear and fear, and do no more presumptuously.'),
  ('Deuteronomy', 17, 14, 'When you have come to the land which the LORD your God gives you, and possess it and dwell in it, and say, “I will set a king over me, like all the nations that are around me,”'),
  ('Deuteronomy', 17, 15, 'you shall surely set him whom the LORD your God chooses as king over yourselves. You shall set as king over you one from among your brothers. You may not put a foreigner over you, who is not your brother.'),
  ('Deuteronomy', 17, 16, 'Only he shall not multiply horses to himself, nor cause the people to return to Egypt, to the end that he may multiply horses; because the LORD has said to you, “You shall not go back that way again.”'),
  ('Deuteronomy', 17, 17, 'He shall not multiply wives to himself, that his heart not turn away. He shall not greatly multiply to himself silver and gold.'),
  ('Deuteronomy', 17, 18, 'It shall be, when he sits on the throne of his kingdom, that he shall write himself a copy of this law in a book, out of that which is before the Levitical priests.'),
  ('Deuteronomy', 17, 19, 'It shall be with him, and he shall read from it all the days of his life, that he may learn to fear the LORD his God, to keep all the words of this law and these statutes, to do them;'),
  ('Deuteronomy', 17, 20, 'that his heart not be lifted up above his brothers, and that he not turn away from the commandment to the right hand, or to the left, to the end that he may prolong his days in his kingdom, he and his children, in the middle of Israel.'),
  ('Deuteronomy', 18, 1, 'The priests and the Levites—all the tribe of Levi—shall have no portion nor inheritance with Israel. They shall eat the offerings of the LORD made by fire and his portion.'),
  ('Deuteronomy', 18, 2, 'They shall have no inheritance among their brothers. The LORD is their inheritance, as he has spoken to them.'),
  ('Deuteronomy', 18, 3, 'This shall be the priests’ due from the people, from those who offer a sacrifice, whether it be ox or sheep, that they shall give to the priest: the shoulder, the two cheeks, and the inner parts.'),
  ('Deuteronomy', 18, 4, 'You shall give him the first fruits of your grain, of your new wine, and of your oil, and the first of the fleece of your sheep.'),
  ('Deuteronomy', 18, 5, 'For the LORD your God has chosen him out of all your tribes to stand to minister in the LORD’s name, him and his sons forever.'),
  ('Deuteronomy', 18, 6, 'If a Levite comes from any of your gates out of all Israel where he lives, and comes with all the desire of his soul to the place which the LORD shall choose,'),
  ('Deuteronomy', 18, 7, 'then he shall minister in the name of the LORD his God, as all his brothers the Levites do, who stand there before the LORD.'),
  ('Deuteronomy', 18, 8, 'They shall have like portions to eat, in addition to that which comes from the sale of his family possessions.'),
  ('Deuteronomy', 18, 9, 'When you have come into the land which the LORD your God gives you, you shall not learn to imitate the abominations of those nations.'),
  ('Deuteronomy', 18, 10, 'There shall not be found with you anyone who makes his son or his daughter to pass through the fire, one who uses divination, one who tells fortunes, or an enchanter, or a sorcerer,'),
  ('Deuteronomy', 18, 11, 'or a charmer, or someone who consults with a familiar spirit, or a wizard, or a necromancer.'),
  ('Deuteronomy', 18, 12, 'For whoever does these things is an abomination to the LORD. Because of these abominations, the LORD your God drives them out from before you.'),
  ('Deuteronomy', 18, 13, 'You shall be blameless with the LORD your God.'),
  ('Deuteronomy', 18, 14, 'For these nations that you shall dispossess listen to those who practice sorcery and to diviners; but as for you, the LORD your God has not allowed you so to do.'),
  ('Deuteronomy', 18, 15, 'The LORD your God will raise up to you a prophet from among you, of your brothers, like me. You shall listen to him.');
INSERT INTO bible_verses (book_name, chapter, verse, text) VALUES
  ('Deuteronomy', 18, 16, 'This is according to all that you desired of the LORD your God in Horeb in the day of the assembly, saying, “Let me not hear again the LORD my God’s voice, neither let me see this great fire any more, that I not die.”'),
  ('Deuteronomy', 18, 17, 'The LORD said to me, “They have well said that which they have spoken.'),
  ('Deuteronomy', 18, 18, 'I will raise them up a prophet from among their brothers, like you. I will put my words in his mouth, and he shall speak to them all that I shall command him.'),
  ('Deuteronomy', 18, 19, 'It shall happen, that whoever will not listen to my words which he shall speak in my name, I will require it of him.'),
  ('Deuteronomy', 18, 20, 'But the prophet who speaks a word presumptuously in my name, which I have not commanded him to speak, or who speaks in the name of other gods, that same prophet shall die.”'),
  ('Deuteronomy', 18, 21, 'You may say in your heart, “How shall we know the word which the LORD has not spoken?”'),
  ('Deuteronomy', 18, 22, 'When a prophet speaks in the LORD’s name, if the thing doesn’t follow, nor happen, that is the thing which the LORD has not spoken. The prophet has spoken it presumptuously. You shall not be afraid of him.'),
  ('Deuteronomy', 19, 1, 'When the LORD your God cuts off the nations whose land the LORD your God gives you, and you succeed them and dwell in their cities and in their houses,'),
  ('Deuteronomy', 19, 2, 'you shall set apart three cities for yourselves in the middle of your land, which the LORD your God gives you to possess.'),
  ('Deuteronomy', 19, 3, 'You shall prepare the way, and divide the borders of your land which the LORD your God causes you to inherit into three parts, that every man slayer may flee there.'),
  ('Deuteronomy', 19, 4, 'This is the case of the man slayer who shall flee there and live: Whoever kills his neighbor unintentionally, and didn’t hate him in time past—'),
  ('Deuteronomy', 19, 5, 'as when a man goes into the forest with his neighbor to chop wood and his hand swings the ax to cut down the tree, and the head slips from the handle and hits his neighbor so that he dies—he shall flee to one of these cities and live.'),
  ('Deuteronomy', 19, 6, 'Otherwise, the avenger of blood might pursue the man slayer while hot anger is in his heart and overtake him, because the way is long, and strike him mortally, even though he was not worthy of death, because he didn’t hate him in time past.'),
  ('Deuteronomy', 19, 7, 'Therefore I command you to set apart three cities for yourselves.'),
  ('Deuteronomy', 19, 8, 'If the LORD your God enlarges your border, as he has sworn to your fathers, and gives you all the land which he promised to give to your fathers;'),
  ('Deuteronomy', 19, 9, 'and if you keep all this commandment to do it, which I command you today, to love the LORD your God, and to walk ever in his ways, then you shall add three cities more for yourselves, in addition to these three.'),
  ('Deuteronomy', 19, 10, 'This is so that innocent blood will not be shed in the middle of your land which the LORD your God gives you for an inheritance, leaving blood guilt on you.'),
  ('Deuteronomy', 19, 11, 'But if any man hates his neighbor, lies in wait for him, rises up against him, strikes him mortally so that he dies, and he flees into one of these cities;'),
  ('Deuteronomy', 19, 12, 'then the elders of his city shall send and bring him there, and deliver him into the hand of the avenger of blood, that he may die.'),
  ('Deuteronomy', 19, 13, 'Your eye shall not pity him, but you shall purge the innocent blood from Israel that it may go well with you.'),
  ('Deuteronomy', 19, 14, 'You shall not remove your neighbor’s landmark, which they of old time have set, in your inheritance which you shall inherit, in the land that the LORD your God gives you to possess.'),
  ('Deuteronomy', 19, 15, 'One witness shall not rise up against a man for any iniquity, or for any sin that he sins. At the mouth of two witnesses, or at the mouth of three witnesses, shall a matter be established.'),
  ('Deuteronomy', 19, 16, 'If an unrighteous witness rises up against any man to testify against him of wrongdoing,'),
  ('Deuteronomy', 19, 17, 'then both the men, between whom the controversy is, shall stand before the LORD, before the priests and the judges who shall be in those days;'),
  ('Deuteronomy', 19, 18, 'and the judges shall make diligent inquisition; and behold, if the witness is a false witness, and has testified falsely against his brother,'),
  ('Deuteronomy', 19, 19, 'then you shall do to him as he had thought to do to his brother. So you shall remove the evil from among you.'),
  ('Deuteronomy', 19, 20, 'Those who remain shall hear, and fear, and will never again commit any such evil among you.'),
  ('Deuteronomy', 19, 21, 'Your eyes shall not pity: life for life, eye for eye, tooth for tooth, hand for hand, foot for foot.'),
  ('Deuteronomy', 20, 1, 'When you go out to battle against your enemies, and see horses, chariots, and a people more numerous than you, you shall not be afraid of them; for the LORD your God, who brought you up out of the land of Egypt, is with you.'),
  ('Deuteronomy', 20, 2, 'It shall be, when you draw near to the battle, that the priest shall approach and speak to the people,'),
  ('Deuteronomy', 20, 3, 'and shall tell them, “Hear, Israel, you draw near today to battle against your enemies. Don’t let your heart faint! Don’t be afraid, nor tremble, neither be scared of them;'),
  ('Deuteronomy', 20, 4, 'for the LORD your God is he who goes with you, to fight for you against your enemies, to save you.”'),
  ('Deuteronomy', 20, 5, 'The officers shall speak to the people, saying, “What man is there who has built a new house, and has not dedicated it? Let him go and return to his house, lest he die in the battle, and another man dedicate it.'),
  ('Deuteronomy', 20, 6, 'What man is there who has planted a vineyard, and has not used its fruit? Let him go and return to his house, lest he die in the battle, and another man use its fruit.'),
  ('Deuteronomy', 20, 7, 'What man is there who has pledged to be married to a wife, and has not taken her? Let him go and return to his house, lest he die in the battle, and another man take her.”'),
  ('Deuteronomy', 20, 8, 'The officers shall speak further to the people, and they shall say, “What man is there who is fearful and faint-hearted? Let him go and return to his house, lest his brother’s heart melt as his heart.”'),
  ('Deuteronomy', 20, 9, 'It shall be, when the officers have finished speaking to the people, that they shall appoint captains of armies at the head of the people.'),
  ('Deuteronomy', 20, 10, 'When you draw near to a city to fight against it, then proclaim peace to it.'),
  ('Deuteronomy', 20, 11, 'It shall be, if it gives you answer of peace and opens to you, then it shall be that all the people who are found therein shall become forced laborers to you, and shall serve you.'),
  ('Deuteronomy', 20, 12, 'If it will make no peace with you, but will make war against you, then you shall besiege it.'),
  ('Deuteronomy', 20, 13, 'When the LORD your God delivers it into your hand, you shall strike every male of it with the edge of the sword;'),
  ('Deuteronomy', 20, 14, 'but the women, the little ones, the livestock, and all that is in the city, even all its plunder, you shall take for plunder for yourself. You may use the plunder of your enemies, which the LORD your God has given you.'),
  ('Deuteronomy', 20, 15, 'Thus you shall do to all the cities which are very far off from you, which are not of the cities of these nations.'),
  ('Deuteronomy', 20, 16, 'But of the cities of these peoples that the LORD your God gives you for an inheritance, you shall save alive nothing that breathes;'),
  ('Deuteronomy', 20, 17, 'but you shall utterly destroy them: the Hittite, the Amorite, the Canaanite, the Perizzite, the Hivite, and the Jebusite, as the LORD your God has commanded you;'),
  ('Deuteronomy', 20, 18, 'that they not teach you to follow all their abominations, which they have done for their gods; so would you sin against the LORD your God.'),
  ('Deuteronomy', 20, 19, 'When you shall besiege a city a long time, in making war against it to take it, you shall not destroy its trees by wielding an ax against them; for you may eat of them. You shall not cut them down, for is the tree of the field man, that it should be besieged by you?'),
  ('Deuteronomy', 20, 20, 'Only the trees that you know are not trees for food, you shall destroy and cut them down. You shall build bulwarks against the city that makes war with you, until it falls.'),
  ('Deuteronomy', 21, 1, 'If someone is found slain in the land which the LORD your God gives you to possess, lying in the field, and it isn’t known who has struck him,'),
  ('Deuteronomy', 21, 2, 'then your elders and your judges shall come out, and they shall measure to the cities which are around him who is slain.'),
  ('Deuteronomy', 21, 3, 'It shall be that the elders of the city which is nearest to the slain man shall take a heifer of the herd, which hasn’t been worked with and which has not drawn in the yoke.'),
  ('Deuteronomy', 21, 4, 'The elders of that city shall bring the heifer down to a valley with running water, which is neither plowed nor sown, and shall break the heifer’s neck there in the valley.'),
  ('Deuteronomy', 21, 5, 'The priests the sons of Levi shall come near, for them the LORD your God has chosen to minister to him, and to bless in the LORD’s name; and according to their word shall every controversy and every assault be decided.'),
  ('Deuteronomy', 21, 6, 'All the elders of that city which is nearest to the slain man shall wash their hands over the heifer whose neck was broken in the valley.'),
  ('Deuteronomy', 21, 7, 'They shall answer and say, “Our hands have not shed this blood, neither have our eyes seen it.'),
  ('Deuteronomy', 21, 8, 'Forgive, LORD, your people Israel, whom you have redeemed, and don’t allow innocent blood among your people Israel.” The blood shall be forgiven them.'),
  ('Deuteronomy', 21, 9, 'So you shall put away the innocent blood from among you, when you shall do that which is right in the LORD’s eyes.'),
  ('Deuteronomy', 21, 10, 'When you go out to battle against your enemies, and the LORD your God delivers them into your hands and you carry them away captive,'),
  ('Deuteronomy', 21, 11, 'and see among the captives a beautiful woman, and you are attracted to her, and desire to take her as your wife,'),
  ('Deuteronomy', 21, 12, 'then you shall bring her home to your house. She shall shave her head and trim her nails.'),
  ('Deuteronomy', 21, 13, 'She shall take off the clothing of her captivity, and shall remain in your house, and bewail her father and her mother a full month. After that you shall go in to her and be her husband, and she shall be your wife.'),
  ('Deuteronomy', 21, 14, 'It shall be, if you have no delight in her, then you shall let her go where she desires; but you shall not sell her at all for money. You shall not deal with her as a slave, because you have humbled her.'),
  ('Deuteronomy', 21, 15, 'If a man has two wives, the one beloved and the other hated, and they have borne him children, both the beloved and the hated, and if the firstborn son is hers who was hated,'),
  ('Deuteronomy', 21, 16, 'then it shall be, in the day that he causes his sons to inherit that which he has, that he may not give the son of the beloved the rights of the firstborn before the son of the hated, who is the firstborn;'),
  ('Deuteronomy', 21, 17, 'but he shall acknowledge the firstborn, the son of the hated, by giving him a double portion of all that he has; for he is the beginning of his strength. The right of the firstborn is his.'),
  ('Deuteronomy', 21, 18, 'If a man has a stubborn and rebellious son who will not obey the voice of his father or the voice of his mother, and though they chasten him, will not listen to them,'),
  ('Deuteronomy', 21, 19, 'then his father and his mother shall take hold of him and bring him out to the elders of his city and to the gate of his place.'),
  ('Deuteronomy', 21, 20, 'They shall tell the elders of his city, “This our son is stubborn and rebellious. He will not obey our voice. He is a glutton and a drunkard.”'),
  ('Deuteronomy', 21, 21, 'All the men of his city shall stone him to death with stones. So you shall remove the evil from among you. All Israel shall hear, and fear.'),
  ('Deuteronomy', 21, 22, 'If a man has committed a sin worthy of death, and he is put to death, and you hang him on a tree,'),
  ('Deuteronomy', 21, 23, 'his body shall not remain all night on the tree, but you shall surely bury him the same day; for he who is hanged is accursed of God. Don’t defile your land which the LORD your God gives you for an inheritance.'),
  ('Deuteronomy', 22, 1, 'You shall not see your brother’s ox or his sheep go astray and hide yourself from them. You shall surely bring them again to your brother.'),
  ('Deuteronomy', 22, 2, 'If your brother isn’t near to you, or if you don’t know him, then you shall bring it home to your house, and it shall be with you until your brother comes looking for it, and you shall restore it to him.'),
  ('Deuteronomy', 22, 3, 'So you shall do with his donkey. So you shall do with his garment. So you shall do with every lost thing of your brother’s, which he has lost and you have found. You may not hide yourself.'),
  ('Deuteronomy', 22, 4, 'You shall not see your brother’s donkey or his ox fallen down by the way, and hide yourself from them. You shall surely help him to lift them up again.'),
  ('Deuteronomy', 22, 5, 'A woman shall not wear men’s clothing, neither shall a man put on women’s clothing; for whoever does these things is an abomination to the LORD your God.'),
  ('Deuteronomy', 22, 6, 'If you come across a bird’s nest on the way, in any tree or on the ground, with young ones or eggs, and the hen sitting on the young, or on the eggs, you shall not take the hen with the young.'),
  ('Deuteronomy', 22, 7, 'You shall surely let the hen go, but the young you may take for yourself, that it may be well with you, and that you may prolong your days.'),
  ('Deuteronomy', 22, 8, 'When you build a new house, then you shall make a railing around your roof, so that you don’t bring blood on your house if anyone falls from there.'),
  ('Deuteronomy', 22, 9, 'You shall not sow your vineyard with two kinds of seed, lest all the fruit be defiled, the seed which you have sown, and the increase of the vineyard.'),
  ('Deuteronomy', 22, 10, 'You shall not plow with an ox and a donkey together.'),
  ('Deuteronomy', 22, 11, 'You shall not wear clothes of wool and linen woven together.'),
  ('Deuteronomy', 22, 12, 'You shall make yourselves fringes on the four corners of your cloak with which you cover yourself.'),
  ('Deuteronomy', 22, 13, 'If any man takes a wife, and goes in to her, hates her,'),
  ('Deuteronomy', 22, 14, 'accuses her of shameful things, gives her a bad name, and says, “I took this woman, and when I came near to her, I didn’t find in her the tokens of virginity;”'),
  ('Deuteronomy', 22, 15, 'then the young lady’s father and mother shall take and bring the tokens of the young lady’s virginity to the elders of the city in the gate.'),
  ('Deuteronomy', 22, 16, 'The young lady’s father shall tell the elders, “I gave my daughter to this man as his wife, and he hates her.'),
  ('Deuteronomy', 22, 17, 'Behold, he has accused her of shameful things, saying, ‘I didn’t find in your daughter the tokens of virginity;’ and yet these are the tokens of my daughter’s virginity.” They shall spread the cloth before the elders of the city.'),
  ('Deuteronomy', 22, 18, 'The elders of that city shall take the man and chastise him.'),
  ('Deuteronomy', 22, 19, 'They shall fine him one hundred shekels of silver, and give them to the father of the young lady, because he has given a bad name to a virgin of Israel. She shall be his wife. He may not put her away all his days.'),
  ('Deuteronomy', 22, 20, 'But if this thing is true, that the tokens of virginity were not found in the young lady,'),
  ('Deuteronomy', 22, 21, 'then they shall bring out the young lady to the door of her father’s house, and the men of her city shall stone her to death with stones, because she has done folly in Israel, to play the prostitute in her father’s house. So you shall remove the evil from among you.'),
  ('Deuteronomy', 22, 22, 'If a man is found lying with a woman married to a husband, then they shall both die, the man who lay with the woman and the woman. So you shall remove the evil from Israel.'),
  ('Deuteronomy', 22, 23, 'If there is a young lady who is a virgin pledged to be married to a husband, and a man finds her in the city, and lies with her,'),
  ('Deuteronomy', 22, 24, 'then you shall bring them both out to the gate of that city, and you shall stone them to death with stones; the lady, because she didn’t cry, being in the city; and the man, because he has humbled his neighbor’s wife. So you shall remove the evil from among you.'),
  ('Deuteronomy', 22, 25, 'But if the man finds the lady who is pledged to be married in the field, and the man forces her and lies with her, then only the man who lay with her shall die;'),
  ('Deuteronomy', 22, 26, 'but to the lady you shall do nothing. There is in the lady no sin worthy of death; for as when a man rises against his neighbor and kills him, even so is this matter;'),
  ('Deuteronomy', 22, 27, 'for he found her in the field, the pledged to be married lady cried, and there was no one to save her.'),
  ('Deuteronomy', 22, 28, 'If a man finds a lady who is a virgin, who is not pledged to be married, grabs her and lies with her, and they are found,'),
  ('Deuteronomy', 22, 29, 'then the man who lay with her shall give to the lady’s father fifty shekels of silver. She shall be his wife, because he has humbled her. He may not put her away all his days.');
INSERT INTO bible_verses (book_name, chapter, verse, text) VALUES
  ('Deuteronomy', 22, 30, 'A man shall not take his father’s wife, and shall not uncover his father’s skirt.'),
  ('Deuteronomy', 23, 1, 'He who is emasculated by crushing or cutting shall not enter into the LORD’s assembly.'),
  ('Deuteronomy', 23, 2, 'A person born of a forbidden union shall not enter into the LORD’s assembly; even to the tenth generation shall no one of his enter into the LORD’s assembly.'),
  ('Deuteronomy', 23, 3, 'An Ammonite or a Moabite shall not enter into the LORD’s assembly; even to the tenth generation shall no one belonging to them enter into the LORD’s assembly forever,'),
  ('Deuteronomy', 23, 4, 'because they didn’t meet you with bread and with water on the way when you came out of Egypt, and because they hired against you Balaam the son of Beor from Pethor of Mesopotamia, to curse you.'),
  ('Deuteronomy', 23, 5, 'Nevertheless the LORD your God wouldn’t listen to Balaam, but the LORD your God turned the curse into a blessing to you, because the LORD your God loved you.'),
  ('Deuteronomy', 23, 6, 'You shall not seek their peace nor their prosperity all your days forever.'),
  ('Deuteronomy', 23, 7, 'You shall not abhor an Edomite, for he is your brother. You shall not abhor an Egyptian, because you lived as a foreigner in his land.'),
  ('Deuteronomy', 23, 8, 'The children of the third generation who are born to them may enter into the LORD’s assembly.'),
  ('Deuteronomy', 23, 9, 'When you go out and camp against your enemies, then you shall keep yourselves from every evil thing.'),
  ('Deuteronomy', 23, 10, 'If there is among you any man who is not clean by reason of that which happens to him by night, then shall he go outside of the camp. He shall not come within the camp;'),
  ('Deuteronomy', 23, 11, 'but it shall be, when evening comes, he shall bathe himself in water. When the sun is down, he shall come within the camp.'),
  ('Deuteronomy', 23, 12, 'You shall have a place also outside of the camp where you go relieve yourself.'),
  ('Deuteronomy', 23, 13, 'You shall have a trowel among your weapons. It shall be, when you relieve yourself, you shall dig with it, and shall turn back and cover your excrement;'),
  ('Deuteronomy', 23, 14, 'for the LORD your God walks in the middle of your camp, to deliver you, and to give up your enemies before you. Therefore your camp shall be holy, that he may not see an unclean thing in you, and turn away from you.'),
  ('Deuteronomy', 23, 15, 'You shall not deliver to his master a servant who has escaped from his master to you.'),
  ('Deuteronomy', 23, 16, 'He shall dwell with you, among you, in the place which he shall choose within one of your gates, where it pleases him best. You shall not oppress him.'),
  ('Deuteronomy', 23, 17, 'There shall be no prostitute of the daughters of Israel, neither shall there be a sodomite of the sons of Israel.'),
  ('Deuteronomy', 23, 18, 'You shall not bring the hire of a prostitute, or the wages of a male prostitute, into the house of the LORD your God for any vow; for both of these are an abomination to the LORD your God.'),
  ('Deuteronomy', 23, 19, 'You shall not lend on interest to your brother: interest of money, interest of food, interest of anything that is lent on interest.'),
  ('Deuteronomy', 23, 20, 'You may charge a foreigner interest; but you shall not charge your brother interest, that the LORD your God may bless you in all that you put your hand to, in the land where you go in to possess it.'),
  ('Deuteronomy', 23, 21, 'When you vow a vow to the LORD your God, you shall not be slack to pay it, for the LORD your God will surely require it of you; and it would be sin in you.'),
  ('Deuteronomy', 23, 22, 'But if you refrain from making a vow, it shall be no sin in you.'),
  ('Deuteronomy', 23, 23, 'You shall observe and do that which has gone out of your lips. Whatever you have vowed to the LORD your God as a free will offering, which you have promised with your mouth, you must do.'),
  ('Deuteronomy', 23, 24, 'When you come into your neighbor’s vineyard, then you may eat your fill of grapes at your own pleasure; but you shall not put any in your container.'),
  ('Deuteronomy', 23, 25, 'When you come into your neighbor’s standing grain, then you may pluck the ears with your hand; but you shall not use a sickle on your neighbor’s standing grain.'),
  ('Deuteronomy', 24, 1, 'When a man takes a wife and marries her, then it shall be, if she finds no favor in his eyes because he has found some unseemly thing in her, that he shall write her a certificate of divorce, put it in her hand, and send her out of his house.'),
  ('Deuteronomy', 24, 2, 'When she has departed out of his house, she may go and be another man’s wife.'),
  ('Deuteronomy', 24, 3, 'If the latter husband hates her, and writes her a certificate of divorce, puts it in her hand, and sends her out of his house; or if the latter husband dies, who took her to be his wife;'),
  ('Deuteronomy', 24, 4, 'her former husband, who sent her away, may not take her again to be his wife after she is defiled; for that would be an abomination to the LORD. You shall not cause the land to sin, which the LORD your God gives you for an inheritance.'),
  ('Deuteronomy', 24, 5, 'When a man takes a new wife, he shall not go out in the army, neither shall he be assigned any business. He shall be free at home one year, and shall cheer his wife whom he has taken.'),
  ('Deuteronomy', 24, 6, 'No man shall take the mill or the upper millstone as a pledge, for he takes a life in pledge.'),
  ('Deuteronomy', 24, 7, 'If a man is found stealing any of his brothers of the children of Israel, and he deals with him as a slave, or sells him, then that thief shall die. So you shall remove the evil from among you.'),
  ('Deuteronomy', 24, 8, 'Be careful in the plague of leprosy, that you observe diligently and do according to all that the Levitical priests teach you. As I commanded them, so you shall observe to do.'),
  ('Deuteronomy', 24, 9, 'Remember what the LORD your God did to Miriam, by the way as you came out of Egypt.'),
  ('Deuteronomy', 24, 10, 'When you lend your neighbor any kind of loan, you shall not go into his house to get his pledge.'),
  ('Deuteronomy', 24, 11, 'You shall stand outside, and the man to whom you lend shall bring the pledge outside to you.'),
  ('Deuteronomy', 24, 12, 'If he is a poor man, you shall not sleep with his pledge.'),
  ('Deuteronomy', 24, 13, 'You shall surely restore to him the pledge when the sun goes down, that he may sleep in his garment and bless you. It shall be righteousness to you before the LORD your God.'),
  ('Deuteronomy', 24, 14, 'You shall not oppress a hired servant who is poor and needy, whether he is one of your brothers or one of the foreigners who are in your land within your gates.'),
  ('Deuteronomy', 24, 15, 'In his day you shall give him his wages, neither shall the sun go down on it, for he is poor and sets his heart on it, lest he cry against you to the LORD, and it be sin to you.'),
  ('Deuteronomy', 24, 16, 'The fathers shall not be put to death for the children, neither shall the children be put to death for the fathers. Every man shall be put to death for his own sin.'),
  ('Deuteronomy', 24, 17, 'You shall not deprive the foreigner or the fatherless of justice, nor take a widow’s clothing in pledge;'),
  ('Deuteronomy', 24, 18, 'but you shall remember that you were a slave in Egypt, and the LORD your God redeemed you there. Therefore I command you to do this thing.'),
  ('Deuteronomy', 24, 19, 'When you reap your harvest in your field, and have forgotten a sheaf in the field, you shall not go again to get it. It shall be for the foreigner, for the fatherless, and for the widow, that the LORD your God may bless you in all the work of your hands.'),
  ('Deuteronomy', 24, 20, 'When you beat your olive tree, you shall not go over the boughs again. It shall be for the foreigner, for the fatherless, and for the widow.'),
  ('Deuteronomy', 24, 21, 'When you harvest your vineyard, you shall not glean it after yourselves. It shall be for the foreigner, for the fatherless, and for the widow.'),
  ('Deuteronomy', 24, 22, 'You shall remember that you were a slave in the land of Egypt. Therefore I command you to do this thing.'),
  ('Deuteronomy', 25, 1, 'If there is a controversy between men, and they come to judgment and the judges judge them, then they shall justify the righteous and condemn the wicked.'),
  ('Deuteronomy', 25, 2, 'It shall be, if the wicked man is worthy to be beaten, that the judge shall cause him to lie down and to be beaten before his face, according to his wickedness, by number.'),
  ('Deuteronomy', 25, 3, 'He may sentence him to no more than forty stripes. He shall not give more, lest if he should give more and beat him more than that many stripes, then your brother will be degraded in your sight.'),
  ('Deuteronomy', 25, 4, 'You shall not muzzle the ox when he treads out the grain.'),
  ('Deuteronomy', 25, 5, 'If brothers dwell together, and one of them dies and has no son, the wife of the dead shall not be married outside to a stranger. Her husband’s brother shall go in to her, and take her as his wife, and perform the duty of a husband’s brother to her.'),
  ('Deuteronomy', 25, 6, 'It shall be that the firstborn whom she bears shall succeed in the name of his brother who is dead, that his name not be blotted out of Israel.'),
  ('Deuteronomy', 25, 7, 'If the man doesn’t want to take his brother’s wife, then his brother’s wife shall go up to the gate to the elders, and say, “My husband’s brother refuses to raise up to his brother a name in Israel. He will not perform the duty of a husband’s brother to me.”'),
  ('Deuteronomy', 25, 8, 'Then the elders of his city shall call him, and speak to him. If he stands and says, “I don’t want to take her,”'),
  ('Deuteronomy', 25, 9, 'then his brother’s wife shall come to him in the presence of the elders, and loose his sandal from off his foot, and spit in his face. She shall answer and say, “So shall it be done to the man who does not build up his brother’s house.”'),
  ('Deuteronomy', 25, 10, 'His name shall be called in Israel, “The house of him who had his sandal removed.”'),
  ('Deuteronomy', 25, 11, 'When men strive against each other, and the wife of one draws near to deliver her husband out of the hand of him who strikes him, and puts out her hand, and grabs him by his private parts,'),
  ('Deuteronomy', 25, 12, 'then you shall cut off her hand. Your eye shall have no pity.'),
  ('Deuteronomy', 25, 13, 'You shall not have in your bag diverse weights, one heavy and one light.'),
  ('Deuteronomy', 25, 14, 'You shall not have in your house diverse measures, one large and one small.'),
  ('Deuteronomy', 25, 15, 'You shall have a perfect and just weight. You shall have a perfect and just measure, that your days may be long in the land which the LORD your God gives you.'),
  ('Deuteronomy', 25, 16, 'For all who do such things, all who do unrighteously, are an abomination to the LORD your God.'),
  ('Deuteronomy', 25, 17, 'Remember what Amalek did to you by the way as you came out of Egypt,'),
  ('Deuteronomy', 25, 18, 'how he met you by the way, and struck the rearmost of you, all who were feeble behind you, when you were faint and weary; and he didn’t fear God.'),
  ('Deuteronomy', 25, 19, 'Therefore it shall be, when the LORD your God has given you rest from all your enemies all around, in the land which the LORD your God gives you for an inheritance to possess it, that you shall blot out the memory of Amalek from under the sky. You shall not forget.'),
  ('Deuteronomy', 26, 1, 'It shall be, when you have come in to the land which the LORD your God gives you for an inheritance, possess it, and dwell in it,'),
  ('Deuteronomy', 26, 2, 'that you shall take some of the first of all the fruit of the ground, which you shall bring in from your land that the LORD your God gives you. You shall put it in a basket, and shall go to the place which the LORD your God shall choose to cause his name to dwell there.'),
  ('Deuteronomy', 26, 3, 'You shall come to the priest who shall be in those days, and tell him, “I profess today to the LORD your God, that I have come to the land which the LORD swore to our fathers to give us.”'),
  ('Deuteronomy', 26, 4, 'The priest shall take the basket out of your hand, and set it down before the LORD your God’s altar.'),
  ('Deuteronomy', 26, 5, 'You shall answer and say before the LORD your God, “My father was a Syrian ready to perish. He went down into Egypt, and lived there, few in number. There he became a great, mighty, and populous nation.'),
  ('Deuteronomy', 26, 6, 'The Egyptians mistreated us, afflicted us, and imposed hard labor on us.'),
  ('Deuteronomy', 26, 7, 'Then we cried to the LORD, the God of our fathers. The LORD heard our voice, and saw our affliction, our toil, and our oppression.'),
  ('Deuteronomy', 26, 8, 'The LORD brought us out of Egypt with a mighty hand, with an outstretched arm, with great terror, with signs, and with wonders;'),
  ('Deuteronomy', 26, 9, 'and he has brought us into this place, and has given us this land, a land flowing with milk and honey.'),
  ('Deuteronomy', 26, 10, 'Now, behold, I have brought the first of the fruit of the ground, which you, the LORD, have given me.” You shall set it down before the LORD your God, and worship before the LORD your God.'),
  ('Deuteronomy', 26, 11, 'You shall rejoice in all the good which the LORD your God has given to you, and to your house, you, and the Levite, and the foreigner who is among you.'),
  ('Deuteronomy', 26, 12, 'When you have finished tithing all the tithe of your increase in the third year, which is the year of tithing, then you shall give it to the Levite, to the foreigner, to the fatherless, and to the widow, that they may eat within your gates and be filled.'),
  ('Deuteronomy', 26, 13, 'You shall say before the LORD your God, “I have put away the holy things out of my house, and also have given them to the Levite, to the foreigner, to the fatherless, and to the widow, according to all your commandment which you have commanded me. I have not transgressed any of your commandments, neither have I forgotten them.'),
  ('Deuteronomy', 26, 14, 'I have not eaten of it in my mourning, neither have I removed any of it while I was unclean, nor given of it for the dead. I have listened to the LORD my God’s voice. I have done according to all that you have commanded me.'),
  ('Deuteronomy', 26, 15, 'Look down from your holy habitation, from heaven, and bless your people Israel, and the ground which you have given us, as you swore to our fathers, a land flowing with milk and honey.”'),
  ('Deuteronomy', 26, 16, 'Today the LORD your God commands you to do these statutes and ordinances. You shall therefore keep and do them with all your heart and with all your soul.'),
  ('Deuteronomy', 26, 17, 'You have declared today that the LORD is your God, and that you would walk in his ways, keep his statutes, his commandments, and his ordinances, and listen to his voice.'),
  ('Deuteronomy', 26, 18, 'The LORD has declared today that you are a people for his own possession, as he has promised you, and that you should keep all his commandments.'),
  ('Deuteronomy', 26, 19, 'He will make you high above all nations that he has made, in praise, in name, and in honor, and that you may be a holy people to the LORD your God, as he has spoken.'),
  ('Deuteronomy', 27, 1, 'Moses and the elders of Israel commanded the people, saying, “Keep all the commandment which I command you today.'),
  ('Deuteronomy', 27, 2, 'It shall be on the day when you shall pass over the Jordan to the land which the LORD your God gives you, that you shall set yourself up great stones, and coat them with plaster.'),
  ('Deuteronomy', 27, 3, 'You shall write on them all the words of this law, when you have passed over, that you may go in to the land which the LORD your God gives you, a land flowing with milk and honey, as the LORD, the God of your fathers, has promised you.'),
  ('Deuteronomy', 27, 4, 'It shall be, when you have crossed over the Jordan, that you shall set up these stones, which I command you today, on Mount Ebal, and you shall coat them with plaster.'),
  ('Deuteronomy', 27, 5, 'There you shall build an altar to the LORD your God, an altar of stones. You shall not use any iron tool on them.'),
  ('Deuteronomy', 27, 6, 'You shall build the LORD your God’s altar of uncut stones. You shall offer burnt offerings on it to the LORD your God.'),
  ('Deuteronomy', 27, 7, 'You shall sacrifice peace offerings, and shall eat there. You shall rejoice before the LORD your God.'),
  ('Deuteronomy', 27, 8, 'You shall write on the stones all the words of this law very plainly.”'),
  ('Deuteronomy', 27, 9, 'Moses and the Levitical priests spoke to all Israel, saying, “Be silent and listen, Israel! Today you have become the people of the LORD your God.'),
  ('Deuteronomy', 27, 10, 'You shall therefore obey the LORD your God’s voice, and do his commandments and his statutes, which I command you today.”'),
  ('Deuteronomy', 27, 11, 'Moses commanded the people the same day, saying,'),
  ('Deuteronomy', 27, 12, '“These shall stand on Mount Gerizim to bless the people, when you have crossed over the Jordan: Simeon, Levi, Judah, Issachar, Joseph, and Benjamin.'),
  ('Deuteronomy', 27, 13, 'These shall stand on Mount Ebal for the curse: Reuben, Gad, Asher, Zebulun, Dan, and Naphtali.'),
  ('Deuteronomy', 27, 14, 'With a loud voice, the Levites shall say to all the men of Israel,');
INSERT INTO bible_verses (book_name, chapter, verse, text) VALUES
  ('Deuteronomy', 27, 15, '‘Cursed is the man who makes an engraved or molten image, an abomination to the LORD, the work of the hands of the craftsman, and sets it up in secret.’ All the people shall answer and say, ‘Amen.’'),
  ('Deuteronomy', 27, 16, '‘Cursed is he who dishonors his father or his mother.’ All the people shall say, ‘Amen.’'),
  ('Deuteronomy', 27, 17, '‘Cursed is he who removes his neighbor’s landmark.’ All the people shall say, ‘Amen.’'),
  ('Deuteronomy', 27, 18, '‘Cursed is he who leads the blind astray on the road.’ All the people shall say, ‘Amen.’'),
  ('Deuteronomy', 27, 19, '‘Cursed is he who withholds justice from the foreigner, fatherless, and widow.’ All the people shall say, ‘Amen.’'),
  ('Deuteronomy', 27, 20, '‘Cursed is he who lies with his father’s wife, because he dishonors his father’s bed.’ All the people shall say, ‘Amen.’'),
  ('Deuteronomy', 27, 21, '‘Cursed is he who lies with any kind of animal.’ All the people shall say, ‘Amen.’'),
  ('Deuteronomy', 27, 22, '‘Cursed is he who lies with his sister, his father’s daughter or his mother’s daughter.’ All the people shall say, ‘Amen.’'),
  ('Deuteronomy', 27, 23, '‘Cursed is he who lies with his mother-in-law.’ All the people shall say, ‘Amen.’'),
  ('Deuteronomy', 27, 24, '‘Cursed is he who secretly kills his neighbor.’ All the people shall say, ‘Amen.’'),
  ('Deuteronomy', 27, 25, '‘Cursed is he who takes a bribe to kill an innocent person.’ All the people shall say, ‘Amen.’'),
  ('Deuteronomy', 27, 26, '‘Cursed is he who doesn’t uphold the words of this law by doing them.’ All the people shall say, ‘Amen.’”'),
  ('Deuteronomy', 28, 1, 'It shall happen, if you shall listen diligently to the LORD your God’s voice, to observe to do all his commandments which I command you today, that the LORD your God will set you high above all the nations of the earth.'),
  ('Deuteronomy', 28, 2, 'All these blessings will come upon you, and overtake you, if you listen to the LORD your God’s voice.'),
  ('Deuteronomy', 28, 3, 'You shall be blessed in the city, and you shall be blessed in the field.'),
  ('Deuteronomy', 28, 4, 'You shall be blessed in the fruit of your body, the fruit of your ground, the fruit of your animals, the increase of your livestock, and the young of your flock.'),
  ('Deuteronomy', 28, 5, 'Your basket and your kneading trough shall be blessed.'),
  ('Deuteronomy', 28, 6, 'You shall be blessed when you come in, and you shall be blessed when you go out.'),
  ('Deuteronomy', 28, 7, 'The LORD will cause your enemies who rise up against you to be struck before you. They will come out against you one way, and will flee before you seven ways.'),
  ('Deuteronomy', 28, 8, 'The LORD will command the blessing on you in your barns, and in all that you put your hand to. He will bless you in the land which the LORD your God gives you.'),
  ('Deuteronomy', 28, 9, 'The LORD will establish you for a holy people to himself, as he has sworn to you, if you shall keep the commandments of the LORD your God, and walk in his ways.'),
  ('Deuteronomy', 28, 10, 'All the peoples of the earth shall see that you are called by the LORD’s name, and they will be afraid of you.'),
  ('Deuteronomy', 28, 11, 'The LORD will grant you abundant prosperity in the fruit of your body, in the fruit of your livestock, and in the fruit of your ground, in the land which the LORD swore to your fathers to give you.'),
  ('Deuteronomy', 28, 12, 'The LORD will open to you his good treasure in the sky, to give the rain of your land in its season, and to bless all the work of your hand. You will lend to many nations, and you will not borrow.'),
  ('Deuteronomy', 28, 13, 'The LORD will make you the head, and not the tail. You will be above only, and you will not be beneath, if you listen to the commandments of the LORD your God which I command you today, to observe and to do,'),
  ('Deuteronomy', 28, 14, 'and shall not turn away from any of the words which I command you today, to the right hand or to the left, to go after other gods to serve them.'),
  ('Deuteronomy', 28, 15, 'But it shall come to pass, if you will not listen to the LORD your God’s voice, to observe to do all his commandments and his statutes which I command you today, that all these curses will come on you and overtake you.'),
  ('Deuteronomy', 28, 16, 'You will be cursed in the city, and you will be cursed in the field.'),
  ('Deuteronomy', 28, 17, 'Your basket and your kneading trough will be cursed.'),
  ('Deuteronomy', 28, 18, 'The fruit of your body, the fruit of your ground, the increase of your livestock, and the young of your flock will be cursed.'),
  ('Deuteronomy', 28, 19, 'You will be cursed when you come in, and you will be cursed when you go out.'),
  ('Deuteronomy', 28, 20, 'The LORD will send on you cursing, confusion, and rebuke in all that you put your hand to do, until you are destroyed and until you perish quickly, because of the evil of your doings, by which you have forsaken me.'),
  ('Deuteronomy', 28, 21, 'The LORD will make the pestilence cling to you, until he has consumed you from off the land where you go in to possess it.'),
  ('Deuteronomy', 28, 22, 'The LORD will strike you with consumption, with fever, with inflammation, with fiery heat, with the sword, with blight, and with mildew. They will pursue you until you perish.'),
  ('Deuteronomy', 28, 23, 'Your sky that is over your head will be bronze, and the earth that is under you will be iron.'),
  ('Deuteronomy', 28, 24, 'The LORD will make the rain of your land powder and dust. It will come down on you from the sky, until you are destroyed.'),
  ('Deuteronomy', 28, 25, 'The LORD will cause you to be struck before your enemies. You will go out one way against them, and will flee seven ways before them. You will be tossed back and forth among all the kingdoms of the earth.'),
  ('Deuteronomy', 28, 26, 'Your dead bodies will be food to all birds of the sky, and to the animals of the earth; and there will be no one to frighten them away.'),
  ('Deuteronomy', 28, 27, 'The LORD will strike you with the boils of Egypt, with the tumors, with the scurvy, and with the itch, of which you can not be healed.'),
  ('Deuteronomy', 28, 28, 'The LORD will strike you with madness, with blindness, and with astonishment of heart.'),
  ('Deuteronomy', 28, 29, 'You will grope at noonday, as the blind gropes in darkness, and you shall not prosper in your ways. You will only be oppressed and robbed always, and there will be no one to save you.'),
  ('Deuteronomy', 28, 30, 'You will betroth a wife, and another man shall lie with her. You will build a house, and you won’t dwell in it. You will plant a vineyard, and not use its fruit.'),
  ('Deuteronomy', 28, 31, 'Your ox will be slain before your eyes, and you will not eat any of it. Your donkey will be violently taken away from before your face, and will not be restored to you. Your sheep will be given to your enemies, and you will have no one to save you.'),
  ('Deuteronomy', 28, 32, 'Your sons and your daughters will be given to another people. Your eyes will look and fail with longing for them all day long. There will be no power in your hand.'),
  ('Deuteronomy', 28, 33, 'A nation which you don’t know will eat the fruit of your ground and all of your work. You will only be oppressed and crushed always,'),
  ('Deuteronomy', 28, 34, 'so that the sights that you see with your eyes will drive you mad.'),
  ('Deuteronomy', 28, 35, 'The LORD will strike you in the knees and in the legs with a sore boil, of which you cannot be healed, from the sole of your foot to the crown of your head.'),
  ('Deuteronomy', 28, 36, 'The LORD will bring you, and your king whom you will set over yourselves, to a nation that you have not known, you nor your fathers. There you will serve other gods of wood and stone.'),
  ('Deuteronomy', 28, 37, 'You will become an astonishment, a proverb, and a byword among all the peoples where the LORD will lead you away.'),
  ('Deuteronomy', 28, 38, 'You will carry much seed out into the field, and will gather little in, for the locust will consume it.'),
  ('Deuteronomy', 28, 39, 'You will plant vineyards and dress them, but you will neither drink of the wine, nor harvest, because worms will eat them.'),
  ('Deuteronomy', 28, 40, 'You will have olive trees throughout all your borders, but you won’t anoint yourself with the oil, for your olives will drop off.'),
  ('Deuteronomy', 28, 41, 'You will father sons and daughters, but they will not be yours, for they will go into captivity.'),
  ('Deuteronomy', 28, 42, 'Locusts will consume all of your trees and the fruit of your ground.'),
  ('Deuteronomy', 28, 43, 'The foreigner who is among you will mount up above you higher and higher, and you will come down lower and lower.'),
  ('Deuteronomy', 28, 44, 'He will lend to you, and you won’t lend to him. He will be the head, and you will be the tail.'),
  ('Deuteronomy', 28, 45, 'All these curses will come on you, and will pursue you and overtake you, until you are destroyed, because you didn’t listen to the LORD your God’s voice, to keep his commandments and his statutes which he commanded you.'),
  ('Deuteronomy', 28, 46, 'They will be for a sign and for a wonder to you and to your offspring forever.'),
  ('Deuteronomy', 28, 47, 'Because you didn’t serve the LORD your God with joyfulness and with gladness of heart, by reason of the abundance of all things;'),
  ('Deuteronomy', 28, 48, 'therefore you will serve your enemies whom the LORD sends against you, in hunger, in thirst, in nakedness, and in lack of all things. He will put an iron yoke on your neck until he has destroyed you.'),
  ('Deuteronomy', 28, 49, 'The LORD will bring a nation against you from far away, from the end of the earth, as the eagle flies: a nation whose language you will not understand,'),
  ('Deuteronomy', 28, 50, 'a nation of fierce facial expressions, that doesn’t respect the elderly, nor show favor to the young.'),
  ('Deuteronomy', 28, 51, 'They will eat the fruit of your livestock and the fruit of your ground, until you are destroyed. They also won’t leave you grain, new wine, oil, the increase of your livestock, or the young of your flock, until they have caused you to perish.'),
  ('Deuteronomy', 28, 52, 'They will besiege you in all your gates until your high and fortified walls in which you trusted come down throughout all your land. They will besiege you in all your gates throughout all your land which the LORD your God has given you.'),
  ('Deuteronomy', 28, 53, 'You will eat the fruit of your own body, the flesh of your sons and of your daughters, whom the LORD your God has given you, in the siege and in the distress with which your enemies will distress you.'),
  ('Deuteronomy', 28, 54, 'The man who is tender among you, and very delicate, his eye will be evil toward his brother, toward the wife whom he loves, and toward the remnant of his children whom he has remaining,'),
  ('Deuteronomy', 28, 55, 'so that he will not give to any of them of the flesh of his children whom he will eat, because he has nothing left to him, in the siege and in the distress with which your enemy will distress you in all your gates.'),
  ('Deuteronomy', 28, 56, 'The tender and delicate woman among you, who would not venture to set the sole of her foot on the ground for delicateness and tenderness, her eye will be evil toward the husband that she loves, toward her son, toward her daughter,'),
  ('Deuteronomy', 28, 57, 'toward her young one who comes out from between her feet, and toward her children whom she bears; for she will eat them secretly for lack of all things in the siege and in the distress with which your enemy will distress you in your gates.'),
  ('Deuteronomy', 28, 58, 'If you will not observe to do all the words of this law that are written in this book, that you may fear this glorious and fearful name, THE LORD your God,'),
  ('Deuteronomy', 28, 59, 'then the LORD will make your plagues and the plagues of your offspring fearful, even great plagues, and of long duration, and severe sicknesses, and of long duration.'),
  ('Deuteronomy', 28, 60, 'He will bring on you again all the diseases of Egypt, which you were afraid of; and they will cling to you.'),
  ('Deuteronomy', 28, 61, 'Also every sickness and every plague which is not written in the book of this law, the LORD will bring them on you until you are destroyed.'),
  ('Deuteronomy', 28, 62, 'You will be left few in number, even though you were as the stars of the sky for multitude, because you didn’t listen to the LORD your God’s voice.'),
  ('Deuteronomy', 28, 63, 'It will happen that as the LORD rejoiced over you to do you good, and to multiply you, so the LORD will rejoice over you to cause you to perish and to destroy you. You will be plucked from the land that you are going in to possess.'),
  ('Deuteronomy', 28, 64, 'The LORD will scatter you among all peoples, from one end of the earth to the other end of the earth. There you will serve other gods which you have not known, you nor your fathers, even wood and stone.'),
  ('Deuteronomy', 28, 65, 'Among these nations you will find no ease, and there will be no rest for the sole of your foot; but the LORD will give you there a trembling heart, failing of eyes, and pining of soul.'),
  ('Deuteronomy', 28, 66, 'Your life will hang in doubt before you. You will be afraid night and day, and will have no assurance of your life.'),
  ('Deuteronomy', 28, 67, 'In the morning you will say, “I wish it were evening!” and at evening you will say, “I wish it were morning!” for the fear of your heart which you will fear, and for the sights which your eyes will see.'),
  ('Deuteronomy', 28, 68, 'The LORD will bring you into Egypt again with ships, by the way of which I told you that you would never see it again. There you will offer yourselves to your enemies for male and female slaves, and nobody will buy you.'),
  ('Deuteronomy', 29, 1, 'These are the words of the covenant which the LORD commanded Moses to make with the children of Israel in the land of Moab, in addition to the covenant which he made with them in Horeb.'),
  ('Deuteronomy', 29, 2, 'Moses called to all Israel, and said to them: Your eyes have seen all that the LORD did in the land of Egypt to Pharaoh, and to all his servants, and to all his land;'),
  ('Deuteronomy', 29, 3, 'the great trials which your eyes saw, the signs, and those great wonders.'),
  ('Deuteronomy', 29, 4, 'But the LORD has not given you a heart to know, eyes to see, and ears to hear, to this day.'),
  ('Deuteronomy', 29, 5, 'I have led you forty years in the wilderness. Your clothes have not grown old on you, and your sandals have not grown old on your feet.'),
  ('Deuteronomy', 29, 6, 'You have not eaten bread, neither have you drunk wine or strong drink, that you may know that I am the LORD your God.'),
  ('Deuteronomy', 29, 7, 'When you came to this place, Sihon the king of Heshbon and Og the king of Bashan came out against us to battle, and we struck them.'),
  ('Deuteronomy', 29, 8, 'We took their land, and gave it for an inheritance to the Reubenites, and to the Gadites, and to the half-tribe of the Manassites.'),
  ('Deuteronomy', 29, 9, 'Therefore keep the words of this covenant and do them, that you may prosper in all that you do.'),
  ('Deuteronomy', 29, 10, 'All of you stand today in the presence of the LORD your God: your heads, your tribes, your elders, and your officers, even all the men of Israel,'),
  ('Deuteronomy', 29, 11, 'your little ones, your wives, and the foreigners who are in the middle of your camps, from the one who cuts your wood to the one who draws your water,'),
  ('Deuteronomy', 29, 12, 'that you may enter into the covenant of the LORD your God, and into his oath, which the LORD your God makes with you today,'),
  ('Deuteronomy', 29, 13, 'that he may establish you today as his people, and that he may be your God, as he spoke to you and as he swore to your fathers, to Abraham, to Isaac, and to Jacob.'),
  ('Deuteronomy', 29, 14, 'Neither do I make this covenant and this oath with you only,'),
  ('Deuteronomy', 29, 15, 'but with those who stand here with us today before the LORD our God, and also with those who are not here with us today'),
  ('Deuteronomy', 29, 16, '(for you know how we lived in the land of Egypt, and how we came through the middle of the nations through which you passed;'),
  ('Deuteronomy', 29, 17, 'and you have seen their abominations and their idols of wood, stone, silver, and gold, which were among them);'),
  ('Deuteronomy', 29, 18, 'lest there should be among you man, woman, family, or tribe whose heart turns away today from the LORD our God, to go to serve the gods of those nations; lest there should be among you a root that produces bitter poison;'),
  ('Deuteronomy', 29, 19, 'and it happen, when he hears the words of this curse, that he bless himself in his heart, saying, “I shall have peace, though I walk in the stubbornness of my heart,” to destroy the moist with the dry.'),
  ('Deuteronomy', 29, 20, 'The LORD will not pardon him, but then the LORD’s anger and his jealousy will smoke against that man, and all the curse that is written in this book will fall on him, and the LORD will blot out his name from under the sky.');
INSERT INTO bible_verses (book_name, chapter, verse, text) VALUES
  ('Deuteronomy', 29, 21, 'The LORD will set him apart for evil out of all the tribes of Israel, according to all the curses of the covenant written in this book of the law.'),
  ('Deuteronomy', 29, 22, 'The generation to come—your children who will rise up after you, and the foreigner who will come from a far land—will say, when they see the plagues of that land, and the sicknesses with which the LORD has made it sick,'),
  ('Deuteronomy', 29, 23, 'that all of its land is sulfur, salt, and burning, that it is not sown, doesn’t produce, nor does any grass grow in it, like the overthrow of Sodom, Gomorrah, Admah, and Zeboiim, which the LORD overthrew in his anger, and in his wrath.'),
  ('Deuteronomy', 29, 24, 'Even all the nations will say, “Why has the LORD done this to this land? What does the heat of this great anger mean?”'),
  ('Deuteronomy', 29, 25, 'Then men will say, “Because they abandoned the covenant of the LORD, the God of their fathers, which he made with them when he brought them out of the land of Egypt,'),
  ('Deuteronomy', 29, 26, 'and went and served other gods and worshiped them, gods that they didn’t know and that he had not given to them.'),
  ('Deuteronomy', 29, 27, 'Therefore the LORD’s anger burned against this land, to bring on it all the curses that are written in this book.'),
  ('Deuteronomy', 29, 28, 'The LORD rooted them out of their land in anger, in wrath, and in great indignation, and thrust them into another land, as it is today.”'),
  ('Deuteronomy', 29, 29, 'The secret things belong to the LORD our God; but the things that are revealed belong to us and to our children forever, that we may do all the words of this law.'),
  ('Deuteronomy', 30, 1, 'It shall happen, when all these things have come on you, the blessing and the curse, which I have set before you, and you shall call them to mind among all the nations where the LORD your God has driven you,'),
  ('Deuteronomy', 30, 2, 'and return to the LORD your God and obey his voice according to all that I command you today, you and your children, with all your heart and with all your soul,'),
  ('Deuteronomy', 30, 3, 'that then the LORD your God will release you from captivity, have compassion on you, and will return and gather you from all the peoples where the LORD your God has scattered you.'),
  ('Deuteronomy', 30, 4, 'If your outcasts are in the uttermost parts of the heavens, from there the LORD your God will gather you, and from there he will bring you back.'),
  ('Deuteronomy', 30, 5, 'The LORD your God will bring you into the land which your fathers possessed, and you will possess it. He will do you good, and increase your numbers more than your fathers.'),
  ('Deuteronomy', 30, 6, 'The LORD your God will circumcise your heart, and the heart of your offspring, to love the LORD your God with all your heart and with all your soul, that you may live.'),
  ('Deuteronomy', 30, 7, 'The LORD your God will put all these curses on your enemies and on those who hate you, who persecuted you.'),
  ('Deuteronomy', 30, 8, 'You shall return and obey the LORD’s voice, and do all his commandments which I command you today.'),
  ('Deuteronomy', 30, 9, 'The LORD your God will make you prosperous in all the work of your hand, in the fruit of your body, in the fruit of your livestock, and in the fruit of your ground, for good; for the LORD will again rejoice over you for good, as he rejoiced over your fathers,'),
  ('Deuteronomy', 30, 10, 'if you will obey the LORD your God’s voice, to keep his commandments and his statutes which are written in this book of the law, if you turn to the LORD your God with all your heart and with all your soul.'),
  ('Deuteronomy', 30, 11, 'For this commandment which I command you today is not too hard for you or too distant.'),
  ('Deuteronomy', 30, 12, 'It is not in heaven, that you should say, “Who will go up for us to heaven, bring it to us, and proclaim it to us, that we may do it?”'),
  ('Deuteronomy', 30, 13, 'Neither is it beyond the sea, that you should say, “Who will go over the sea for us, bring it to us, and proclaim it to us, that we may do it?”'),
  ('Deuteronomy', 30, 14, 'But the word is very near to you, in your mouth and in your heart, that you may do it.'),
  ('Deuteronomy', 30, 15, 'Behold, I have set before you today life and prosperity, and death and evil.'),
  ('Deuteronomy', 30, 16, 'For I command you today to love the LORD your God, to walk in his ways and to keep his commandments, his statutes, and his ordinances, that you may live and multiply, and that the LORD your God may bless you in the land where you go in to possess it.'),
  ('Deuteronomy', 30, 17, 'But if your heart turns away, and you will not hear, but are drawn away and worship other gods, and serve them,'),
  ('Deuteronomy', 30, 18, 'I declare to you today that you will surely perish. You will not prolong your days in the land where you pass over the Jordan to go in to possess it.'),
  ('Deuteronomy', 30, 19, 'I call heaven and earth to witness against you today that I have set before you life and death, the blessing and the curse. Therefore choose life, that you may live, you and your descendants,'),
  ('Deuteronomy', 30, 20, 'to love the LORD your God, to obey his voice, and to cling to him; for he is your life, and the length of your days, that you may dwell in the land which the LORD swore to your fathers, to Abraham, to Isaac, and to Jacob, to give them.'),
  ('Deuteronomy', 31, 1, 'Moses went and spoke these words to all Israel.'),
  ('Deuteronomy', 31, 2, 'He said to them, “I am one hundred twenty years old today. I can no more go out and come in. The LORD has said to me, ‘You shall not go over this Jordan.’'),
  ('Deuteronomy', 31, 3, 'The LORD your God himself will go over before you. He will destroy these nations from before you, and you shall dispossess them. Joshua will go over before you, as the LORD has spoken.'),
  ('Deuteronomy', 31, 4, 'The LORD will do to them as he did to Sihon and to Og, the kings of the Amorites, and to their land, when he destroyed them.'),
  ('Deuteronomy', 31, 5, 'The LORD will deliver them up before you, and you shall do to them according to all the commandment which I have commanded you.'),
  ('Deuteronomy', 31, 6, 'Be strong and courageous. Don’t be afraid or scared of them, for the LORD your God himself is who goes with you. He will not fail you nor forsake you.”'),
  ('Deuteronomy', 31, 7, 'Moses called to Joshua, and said to him in the sight of all Israel, “Be strong and courageous, for you shall go with this people into the land which the LORD has sworn to their fathers to give them; and you shall cause them to inherit it.'),
  ('Deuteronomy', 31, 8, 'The LORD himself is who goes before you. He will be with you. He will not fail you nor forsake you. Don’t be afraid. Don’t be discouraged.”'),
  ('Deuteronomy', 31, 9, 'Moses wrote this law and delivered it to the priests the sons of Levi, who bore the ark of the LORD’s covenant, and to all the elders of Israel.'),
  ('Deuteronomy', 31, 10, 'Moses commanded them, saying, “At the end of every seven years, in the set time of the year of release, in the feast of booths,'),
  ('Deuteronomy', 31, 11, 'when all Israel has come to appear before the LORD your God in the place which he will choose, you shall read this law before all Israel in their hearing.'),
  ('Deuteronomy', 31, 12, 'Assemble the people, the men and the women and the little ones, and the foreigners who are within your gates, that they may hear, learn, fear the LORD your God, and observe to do all the words of this law,'),
  ('Deuteronomy', 31, 13, 'and that their children, who have not known, may hear and learn to fear the LORD your God, as long as you live in the land where you go over the Jordan to possess it.”'),
  ('Deuteronomy', 31, 14, 'The LORD said to Moses, “Behold, your days approach that you must die. Call Joshua, and present yourselves in the Tent of Meeting, that I may commission him.” Moses and Joshua went, and presented themselves in the Tent of Meeting.'),
  ('Deuteronomy', 31, 15, 'The LORD appeared in the Tent in a pillar of cloud, and the pillar of cloud stood over the Tent’s door.'),
  ('Deuteronomy', 31, 16, 'The LORD said to Moses, “Behold, you shall sleep with your fathers. This people will rise up and play the prostitute after the strange gods of the land where they go to be among them, and will forsake me and break my covenant which I have made with them.'),
  ('Deuteronomy', 31, 17, 'Then my anger shall be kindled against them in that day, and I will forsake them, and I will hide my face from them, and they shall be devoured, and many evils and troubles shall come on them; so that they will say in that day, ‘Haven’t these evils come on us because our God is not among us?’'),
  ('Deuteronomy', 31, 18, 'I will surely hide my face in that day for all the evil which they have done, in that they have turned to other gods.'),
  ('Deuteronomy', 31, 19, '“Now therefore write this song for yourselves, and teach it to the children of Israel. Put it in their mouths, that this song may be a witness for me against the children of Israel.'),
  ('Deuteronomy', 31, 20, 'For when I have brought them into the land which I swore to their fathers, flowing with milk and honey, and they have eaten and filled themselves, and grown fat, then they will turn to other gods, and serve them, and despise me, and break my covenant.'),
  ('Deuteronomy', 31, 21, 'It will happen, when many evils and troubles have come on them, that this song will testify before them as a witness; for it will not be forgotten out of the mouths of their descendants; for I know their ways and what they are doing today, before I have brought them into the land which I promised them.”'),
  ('Deuteronomy', 31, 22, 'So Moses wrote this song the same day, and taught it to the children of Israel.'),
  ('Deuteronomy', 31, 23, 'He commissioned Joshua the son of Nun, and said, “Be strong and courageous; for you shall bring the children of Israel into the land which I swore to them. I will be with you.”'),
  ('Deuteronomy', 31, 24, 'When Moses had finished writing the words of this law in a book, until they were finished,'),
  ('Deuteronomy', 31, 25, 'Moses commanded the Levites, who bore the ark of the LORD’s covenant, saying,'),
  ('Deuteronomy', 31, 26, '“Take this book of the law, and put it by the side of the ark of the LORD your God’s covenant, that it may be there for a witness against you.'),
  ('Deuteronomy', 31, 27, 'For I know your rebellion and your stiff neck. Behold, while I am yet alive with you today, you have been rebellious against the LORD. How much more after my death?'),
  ('Deuteronomy', 31, 28, 'Assemble to me all the elders of your tribes and your officers, that I may speak these words in their ears, and call heaven and earth to witness against them.'),
  ('Deuteronomy', 31, 29, 'For I know that after my death you will utterly corrupt yourselves, and turn away from the way which I have commanded you; and evil will happen to you in the latter days, because you will do that which is evil in the LORD’s sight, to provoke him to anger through the work of your hands.”'),
  ('Deuteronomy', 31, 30, 'Moses spoke in the ears of all the assembly of Israel the words of this song, until they were finished.'),
  ('Deuteronomy', 32, 1, 'Give ear, you heavens, and I will speak. Let the earth hear the words of my mouth.'),
  ('Deuteronomy', 32, 2, 'My doctrine will drop as the rain. My speech will condense as the dew, as the misty rain on the tender grass, as the showers on the herb.'),
  ('Deuteronomy', 32, 3, 'For I will proclaim the LORD’s name. Ascribe greatness to our God!'),
  ('Deuteronomy', 32, 4, 'The Rock: his work is perfect, for all his ways are just. A God of faithfulness who does no wrong, just and right is he.'),
  ('Deuteronomy', 32, 5, 'They have dealt corruptly with him. They are not his children, because of their defect. They are a perverse and crooked generation.'),
  ('Deuteronomy', 32, 6, 'Is this the way you repay the LORD, foolish and unwise people? Isn’t he your father who has bought you? He has made you and established you.'),
  ('Deuteronomy', 32, 7, 'Remember the days of old. Consider the years of many generations. Ask your father, and he will show you; your elders, and they will tell you.'),
  ('Deuteronomy', 32, 8, 'When the Most High gave to the nations their inheritance, when he separated the children of men, he set the bounds of the peoples according to the number of the children of Israel.'),
  ('Deuteronomy', 32, 9, 'For the LORD’s portion is his people. Jacob is the lot of his inheritance.'),
  ('Deuteronomy', 32, 10, 'He found him in a desert land, in the waste howling wilderness. He surrounded him. He cared for him. He kept him as the apple of his eye.'),
  ('Deuteronomy', 32, 11, 'As an eagle that stirs up her nest, that flutters over her young, he spread abroad his wings, he took them, he bore them on his feathers.'),
  ('Deuteronomy', 32, 12, 'The LORD alone led him. There was no foreign god with him.'),
  ('Deuteronomy', 32, 13, 'He made him ride on the high places of the earth. He ate the increase of the field. He caused him to suck honey out of the rock, oil out of the flinty rock;'),
  ('Deuteronomy', 32, 14, 'butter from the herd, and milk from the flock, with fat of lambs, rams of the breed of Bashan, and goats, with the finest of the wheat. From the blood of the grape, you drank wine.'),
  ('Deuteronomy', 32, 15, 'But Jeshurun grew fat, and kicked. You have grown fat. You have grown thick. You have become sleek. Then he abandoned God who made him, and rejected the Rock of his salvation.'),
  ('Deuteronomy', 32, 16, 'They moved him to jealousy with strange gods. They provoked him to anger with abominations.'),
  ('Deuteronomy', 32, 17, 'They sacrificed to demons, not God, to gods that they didn’t know, to new gods that came up recently, which your fathers didn’t dread.'),
  ('Deuteronomy', 32, 18, 'Of the Rock who became your father, you are unmindful, and have forgotten God who gave you birth.'),
  ('Deuteronomy', 32, 19, 'The LORD saw and abhorred, because of the provocation of his sons and his daughters.'),
  ('Deuteronomy', 32, 20, 'He said, “I will hide my face from them. I will see what their end will be; for they are a very perverse generation, children in whom is no faithfulness.'),
  ('Deuteronomy', 32, 21, 'They have moved me to jealousy with that which is not God. They have provoked me to anger with their vanities. I will move them to jealousy with those who are not a people. I will provoke them to anger with a foolish nation.'),
  ('Deuteronomy', 32, 22, 'For a fire is kindled in my anger, that burns to the lowest Sheol, devours the earth with its increase, and sets the foundations of the mountains on fire.'),
  ('Deuteronomy', 32, 23, '“I will heap evils on them. I will spend my arrows on them.'),
  ('Deuteronomy', 32, 24, 'They shall be wasted with hunger, and devoured with burning heat and bitter destruction. I will send the teeth of animals on them, with the venom of vipers that glide in the dust.'),
  ('Deuteronomy', 32, 25, 'Outside the sword will bereave, and in the rooms, terror on both young man and virgin, the nursing infant with the gray-haired man.'),
  ('Deuteronomy', 32, 26, 'I said that I would scatter them afar. I would make their memory to cease from among men;'),
  ('Deuteronomy', 32, 27, 'were it not that I feared the provocation of the enemy, lest their adversaries should judge wrongly, lest they should say, ‘Our hand is exalted; the LORD has not done all this.’”'),
  ('Deuteronomy', 32, 28, 'For they are a nation void of counsel. There is no understanding in them.'),
  ('Deuteronomy', 32, 29, 'Oh that they were wise, that they understood this, that they would consider their latter end!'),
  ('Deuteronomy', 32, 30, 'How could one chase a thousand, and two put ten thousand to flight, unless their Rock had sold them, and the LORD had delivered them up?'),
  ('Deuteronomy', 32, 31, 'For their rock is not as our Rock, even our enemies themselves concede.'),
  ('Deuteronomy', 32, 32, 'For their vine is of the vine of Sodom, of the fields of Gomorrah. Their grapes are poison grapes. Their clusters are bitter.'),
  ('Deuteronomy', 32, 33, 'Their wine is the poison of serpents, the cruel venom of asps.'),
  ('Deuteronomy', 32, 34, '“Isn’t this laid up in store with me, sealed up among my treasures?'),
  ('Deuteronomy', 32, 35, 'Vengeance is mine, and recompense, at the time when their foot slides, for the day of their calamity is at hand. Their doom rushes at them.”'),
  ('Deuteronomy', 32, 36, 'For the LORD will judge his people, and have compassion on his servants, when he sees that their power is gone, that there is no one remaining, shut up or left at large.'),
  ('Deuteronomy', 32, 37, 'He will say, “Where are their gods, the rock in which they took refuge,'),
  ('Deuteronomy', 32, 38, 'which ate the fat of their sacrifices, and drank the wine of their drink offering? Let them rise up and help you! Let them be your protection.'),
  ('Deuteronomy', 32, 39, '“See now that I myself am he. There is no god with me. I kill and I make alive. I wound and I heal. There is no one who can deliver out of my hand.'),
  ('Deuteronomy', 32, 40, 'For I lift up my hand to heaven and declare, as I live forever,'),
  ('Deuteronomy', 32, 41, 'if I sharpen my glittering sword, my hand grasps it in judgment; I will take vengeance on my adversaries, and will repay those who hate me.');
INSERT INTO bible_verses (book_name, chapter, verse, text) VALUES
  ('Deuteronomy', 32, 42, 'I will make my arrows drunk with blood. My sword shall devour flesh with the blood of the slain and the captives, from the head of the leaders of the enemy.”'),
  ('Deuteronomy', 32, 43, 'Rejoice, you nations, with his people, for he will avenge the blood of his servants. He will take vengeance on his adversaries, and will make atonement for his land and for his people.'),
  ('Deuteronomy', 32, 44, 'Moses came and spoke all the words of this song in the ears of the people, he and Joshua the son of Nun.'),
  ('Deuteronomy', 32, 45, 'Moses finished reciting all these words to all Israel.'),
  ('Deuteronomy', 32, 46, 'He said to them, “Set your heart to all the words which I testify to you today, which you shall command your children to observe to do, all the words of this law.'),
  ('Deuteronomy', 32, 47, 'For it is no vain thing for you, because it is your life, and through this thing you shall prolong your days in the land, where you go over the Jordan to possess it.”'),
  ('Deuteronomy', 32, 48, 'The LORD spoke to Moses that same day, saying,'),
  ('Deuteronomy', 32, 49, '“Go up into this mountain of Abarim, to Mount Nebo, which is in the land of Moab, that is across from Jericho; and see the land of Canaan, which I give to the children of Israel for a possession.'),
  ('Deuteronomy', 32, 50, 'Die on the mountain where you go up, and be gathered to your people, as Aaron your brother died on Mount Hor, and was gathered to his people;'),
  ('Deuteronomy', 32, 51, 'because you trespassed against me among the children of Israel at the waters of Meribah of Kadesh, in the wilderness of Zin; because you didn’t uphold my holiness among the children of Israel.'),
  ('Deuteronomy', 32, 52, 'For you shall see the land from a distance; but you shall not go there into the land which I give the children of Israel.”'),
  ('Deuteronomy', 33, 1, 'This is the blessing with which Moses the man of God blessed the children of Israel before his death.'),
  ('Deuteronomy', 33, 2, 'He said, “The LORD came from Sinai, and rose from Seir to them. He shone from Mount Paran. He came from the ten thousands of holy ones. At his right hand was a fiery law for them.'),
  ('Deuteronomy', 33, 3, 'Yes, he loves the people. All his saints are in your hand. They sat down at your feet. Each receives your words.'),
  ('Deuteronomy', 33, 4, 'Moses commanded us a law, an inheritance for the assembly of Jacob.'),
  ('Deuteronomy', 33, 5, 'He was king in Jeshurun, when the heads of the people were gathered, all the tribes of Israel together.'),
  ('Deuteronomy', 33, 6, '“Let Reuben live, and not die; Nor let his men be few.”'),
  ('Deuteronomy', 33, 7, 'This is for Judah. He said, “Hear, LORD, the voice of Judah. Bring him in to his people. With his hands he contended for himself. You shall be a help against his adversaries.”'),
  ('Deuteronomy', 33, 8, 'About Levi he said, “Your Thummim and your Urim are with your godly one, whom you proved at Massah, with whom you contended at the waters of Meribah.'),
  ('Deuteronomy', 33, 9, 'He said of his father, and of his mother, ‘I have not seen him.’ He didn’t acknowledge his brothers, nor did he know his own children; for they have observed your word, and keep your covenant.'),
  ('Deuteronomy', 33, 10, 'They shall teach Jacob your ordinances, and Israel your law. They shall put incense before you, and whole burnt offering on your altar.'),
  ('Deuteronomy', 33, 11, 'LORD, bless his skills. Accept the work of his hands. Strike through the hips of those who rise up against him, of those who hate him, that they not rise again.”'),
  ('Deuteronomy', 33, 12, 'About Benjamin he said, “The beloved of the LORD will dwell in safety by him. He covers him all day long. He dwells between his shoulders.”'),
  ('Deuteronomy', 33, 13, 'About Joseph he said, “His land is blessed by the LORD, for the precious things of the heavens, for the dew, for the deep that couches beneath,'),
  ('Deuteronomy', 33, 14, 'for the precious things of the fruits of the sun, for the precious things that the moon can yield,'),
  ('Deuteronomy', 33, 15, 'for the best things of the ancient mountains, for the precious things of the everlasting hills,'),
  ('Deuteronomy', 33, 16, 'for the precious things of the earth and its fullness, the good will of him who lived in the bush. Let this come on the head of Joseph, on the crown of the head of him who was separated from his brothers.'),
  ('Deuteronomy', 33, 17, 'Majesty belongs to the firstborn of his herd. His horns are the horns of the wild ox. With them he will push all the peoples to the ends of the earth. They are the ten thousands of Ephraim. They are the thousands of Manasseh.”'),
  ('Deuteronomy', 33, 18, 'About Zebulun he said, “Rejoice, Zebulun, in your going out; and Issachar, in your tents.'),
  ('Deuteronomy', 33, 19, 'They will call the peoples to the mountain. There they will offer sacrifices of righteousness, for they will draw out the abundance of the seas, the hidden treasures of the sand.”'),
  ('Deuteronomy', 33, 20, 'About Gad he said, “He who enlarges Gad is blessed. He dwells as a lioness, and tears the arm and the crown of the head.'),
  ('Deuteronomy', 33, 21, 'He provided the first part for himself, for the lawgiver’s portion was reserved for him. He came with the heads of the people. He executed the righteousness of the LORD, His ordinances with Israel.”'),
  ('Deuteronomy', 33, 22, 'About Dan he said, “Dan is a lion’s cub that leaps out of Bashan.”'),
  ('Deuteronomy', 33, 23, 'About Naphtali he said, “Naphtali, satisfied with favor, full of the LORD’s blessing, Possess the west and the south.”'),
  ('Deuteronomy', 33, 24, 'About Asher he said, “Asher is blessed with children. Let him be acceptable to his brothers. Let him dip his foot in oil.'),
  ('Deuteronomy', 33, 25, 'Your bars will be iron and bronze. As your days, so your strength will be.'),
  ('Deuteronomy', 33, 26, '“There is no one like God, Jeshurun, who rides on the heavens for your help, in his excellency on the skies.'),
  ('Deuteronomy', 33, 27, 'The eternal God is your dwelling place. Underneath are the everlasting arms. He thrust out the enemy from before you, and said, ‘Destroy!’'),
  ('Deuteronomy', 33, 28, 'Israel dwells in safety, the fountain of Jacob alone, In a land of grain and new wine. Yes, his heavens drop down dew.'),
  ('Deuteronomy', 33, 29, 'You are happy, Israel! Who is like you, a people saved by the LORD, the shield of your help, the sword of your excellency? Your enemies will submit themselves to you. You will tread on their high places.”'),
  ('Deuteronomy', 34, 1, 'Moses went up from the plains of Moab to Mount Nebo, to the top of Pisgah, that is opposite Jericho. The LORD showed him all the land of Gilead to Dan,'),
  ('Deuteronomy', 34, 2, 'and all Naphtali, and the land of Ephraim and Manasseh, and all the land of Judah, to the Western Sea,'),
  ('Deuteronomy', 34, 3, 'and the south, and the Plain of the valley of Jericho the city of palm trees, to Zoar.'),
  ('Deuteronomy', 34, 4, 'The LORD said to him, “This is the land which I swore to Abraham, to Isaac, and to Jacob, saying, ‘I will give it to your offspring.’ I have caused you to see it with your eyes, but you shall not go over there.”'),
  ('Deuteronomy', 34, 5, 'So Moses the servant of the LORD died there in the land of Moab, according to the LORD’s word.'),
  ('Deuteronomy', 34, 6, 'He buried him in the valley in the land of Moab opposite Beth Peor, but no man knows where his tomb is to this day.'),
  ('Deuteronomy', 34, 7, 'Moses was one hundred twenty years old when he died. His eye was not dim, nor his strength gone.'),
  ('Deuteronomy', 34, 8, 'The children of Israel wept for Moses in the plains of Moab thirty days, until the days of weeping in the mourning for Moses were ended.'),
  ('Deuteronomy', 34, 9, 'Joshua the son of Nun was full of the spirit of wisdom, for Moses had laid his hands on him. The children of Israel listened to him, and did as the LORD commanded Moses.'),
  ('Deuteronomy', 34, 10, 'Since then, there has not arisen a prophet in Israel like Moses, whom the LORD knew face to face,'),
  ('Deuteronomy', 34, 11, 'in all the signs and the wonders which the LORD sent him to do in the land of Egypt, to Pharaoh, and to all his servants, and to all his land,'),
  ('Deuteronomy', 34, 12, 'and in all the mighty hand, and in all the awesome deeds, which Moses did in the sight of all Israel.'),
  ('Joshua', 1, 1, 'Now after the death of Moses the servant of the LORD, the LORD spoke to Joshua the son of Nun, Moses’ servant, saying,'),
  ('Joshua', 1, 2, '“Moses my servant is dead. Now therefore arise, go across this Jordan, you and all these people, to the land which I am giving to them, even to the children of Israel.'),
  ('Joshua', 1, 3, 'I have given you every place that the sole of your foot will tread on, as I told Moses.'),
  ('Joshua', 1, 4, 'From the wilderness and this Lebanon even to the great river, the river Euphrates, all the land of the Hittites, and to the great sea toward the going down of the sun, shall be your border.'),
  ('Joshua', 1, 5, 'No man will be able to stand before you all the days of your life. As I was with Moses, so I will be with you. I will not fail you nor forsake you.'),
  ('Joshua', 1, 6, '“Be strong and courageous; for you shall cause this people to inherit the land which I swore to their fathers to give them.'),
  ('Joshua', 1, 7, 'Only be strong and very courageous. Be careful to observe to do according to all the law which Moses my servant commanded you. Don’t turn from it to the right hand or to the left, that you may have good success wherever you go.'),
  ('Joshua', 1, 8, 'This book of the law shall not depart from your mouth, but you shall meditate on it day and night, that you may observe to do according to all that is written in it; for then you shall make your way prosperous, and then you shall have good success.'),
  ('Joshua', 1, 9, 'Haven’t I commanded you? Be strong and courageous. Don’t be afraid. Don’t be dismayed, for the LORD your God is with you wherever you go.”'),
  ('Joshua', 1, 10, 'Then Joshua commanded the officers of the people, saying,'),
  ('Joshua', 1, 11, '“Pass through the middle of the camp, and command the people, saying, ‘Prepare food; for within three days you are to pass over this Jordan, to go in to possess the land which the LORD your God gives you to possess.’”'),
  ('Joshua', 1, 12, 'Joshua spoke to the Reubenites, and to the Gadites, and to the half-tribe of Manasseh, saying,'),
  ('Joshua', 1, 13, '“Remember the word which Moses the servant of the LORD commanded you, saying, ‘The LORD your God gives you rest, and will give you this land.'),
  ('Joshua', 1, 14, 'Your wives, your little ones, and your livestock shall live in the land which Moses gave you beyond the Jordan; but you shall pass over before your brothers armed, all the mighty men of valor, and shall help them'),
  ('Joshua', 1, 15, 'until the LORD has given your brothers rest, as he has given you, and they have also possessed the land which the LORD your God gives them. Then you shall return to the land of your possession and possess it, which Moses the servant of the LORD gave you beyond the Jordan toward the sunrise.’”'),
  ('Joshua', 1, 16, 'They answered Joshua, saying, “All that you have commanded us we will do, and wherever you send us we will go.'),
  ('Joshua', 1, 17, 'Just as we listened to Moses in all things, so will we listen to you. Only may the LORD your God be with you, as he was with Moses.'),
  ('Joshua', 1, 18, 'Whoever rebels against your commandment, and doesn’t listen to your words in all that you command him shall himself be put to death. Only be strong and courageous.”'),
  ('Joshua', 2, 1, 'Joshua the son of Nun secretly sent two men out of Shittim as spies, saying, “Go, view the land, including Jericho.” They went and came into the house of a prostitute whose name was Rahab, and slept there.'),
  ('Joshua', 2, 2, 'The king of Jericho was told, “Behold, men of the children of Israel came in here tonight to spy out the land.”'),
  ('Joshua', 2, 3, 'Jericho’s king sent to Rahab, saying, “Bring out the men who have come to you, who have entered into your house; for they have come to spy out all the land.”'),
  ('Joshua', 2, 4, 'The woman took the two men and hid them. Then she said, “Yes, the men came to me, but I didn’t know where they came from.'),
  ('Joshua', 2, 5, 'About the time of the shutting of the gate, when it was dark, the men went out. Where the men went, I don’t know. Pursue them quickly. You may catch up with them.”'),
  ('Joshua', 2, 6, 'But she had brought them up to the roof, and hidden them under the stalks of flax which she had laid in order on the roof.'),
  ('Joshua', 2, 7, 'The men pursued them along the way to the fords of the Jordan River. As soon as those who pursued them had gone out, they shut the gate.'),
  ('Joshua', 2, 8, 'Before they had lain down, she came up to them on the roof.'),
  ('Joshua', 2, 9, 'She said to the men, “I know that the LORD has given you the land, and that the fear of you has fallen upon us, and that all the inhabitants of the land melt away before you.'),
  ('Joshua', 2, 10, 'For we have heard how the LORD dried up the water of the Red Sea before you, when you came out of Egypt; and what you did to the two kings of the Amorites, who were beyond the Jordan, to Sihon and to Og, whom you utterly destroyed.'),
  ('Joshua', 2, 11, 'As soon as we had heard it, our hearts melted, and there wasn’t any more spirit in any man, because of you: for the LORD your God, he is God in heaven above, and on earth beneath.'),
  ('Joshua', 2, 12, 'Now therefore, please swear to me by the LORD, since I have dealt kindly with you, that you also will deal kindly with my father’s house, and give me a true sign;'),
  ('Joshua', 2, 13, 'and that you will save alive my father, my mother, my brothers, and my sisters, and all that they have, and will deliver our lives from death.”'),
  ('Joshua', 2, 14, 'The men said to her, “Our life for yours, if you don’t talk about this business of ours; and it shall be, when the LORD gives us the land, that we will deal kindly and truly with you.”'),
  ('Joshua', 2, 15, 'Then she let them down by a cord through the window; for her house was on the side of the wall, and she lived on the wall.'),
  ('Joshua', 2, 16, 'She said to them, “Go to the mountain, lest the pursuers find you. Hide yourselves there three days, until the pursuers have returned. Afterward, you may go your way.”'),
  ('Joshua', 2, 17, 'The men said to her, “We will be guiltless of this your oath which you’ve made us to swear.'),
  ('Joshua', 2, 18, 'Behold, when we come into the land, tie this line of scarlet thread in the window which you used to let us down. Gather to yourself into the house your father, your mother, your brothers, and all your father’s household.'),
  ('Joshua', 2, 19, 'It shall be that whoever goes out of the doors of your house into the street, his blood will be on his head, and we will be guiltless. Whoever is with you in the house, his blood shall be on our head, if any hand is on him.'),
  ('Joshua', 2, 20, 'But if you talk about this business of ours, then we shall be guiltless of your oath which you’ve made us to swear.”'),
  ('Joshua', 2, 21, 'She said, “Let it be as you have said.” She sent them away, and they departed. Then she tied the scarlet line in the window.'),
  ('Joshua', 2, 22, 'They went and came to the mountain, and stayed there three days, until the pursuers had returned. The pursuers sought them all along the way, but didn’t find them.'),
  ('Joshua', 2, 23, 'Then the two men returned, descended from the mountain, crossed the river, and came to Joshua the son of Nun. They told him all that had happened to them.'),
  ('Joshua', 2, 24, 'They said to Joshua, “Truly the LORD has delivered all the land into our hands. Moreover, all the inhabitants of the land melt away before us.”'),
  ('Joshua', 3, 1, 'Joshua got up early in the morning; and they moved from Shittim and came to the Jordan, he and all the children of Israel. They camped there before they crossed over.'),
  ('Joshua', 3, 2, 'After three days, the officers went through the middle of the camp;'),
  ('Joshua', 3, 3, 'and they commanded the people, saying, “When you see the ark of the LORD your God’s covenant, and the Levitical priests bearing it, then leave your place and follow it.'),
  ('Joshua', 3, 4, 'Yet there shall be a space between you and it of about two thousand cubits by measure—don’t come closer to it—that you may know the way by which you must go; for you have not passed this way before.”'),
  ('Joshua', 3, 5, 'Joshua said to the people, “Sanctify yourselves; for tomorrow the LORD will do wonders among you.”'),
  ('Joshua', 3, 6, 'Joshua spoke to the priests, saying, “Take up the ark of the covenant, and cross over before the people.” They took up the ark of the covenant, and went before the people.');
INSERT INTO bible_verses (book_name, chapter, verse, text) VALUES
  ('Joshua', 3, 7, 'The LORD said to Joshua, “Today I will begin to magnify you in the sight of all Israel, that they may know that as I was with Moses, so I will be with you.'),
  ('Joshua', 3, 8, 'You shall command the priests who bear the ark of the covenant, saying, ‘When you come to the brink of the waters of the Jordan, you shall stand still in the Jordan.’”'),
  ('Joshua', 3, 9, 'Joshua said to the children of Israel, “Come here, and hear the words of the LORD your God.”'),
  ('Joshua', 3, 10, 'Joshua said, “By this you shall know that the living God is among you, and that he will without fail drive the Canaanite, the Hittite, the Hivite, the Perizzite, the Girgashite, the Amorite, and the Jebusite out from before you.'),
  ('Joshua', 3, 11, 'Behold, the ark of the covenant of the Lord of all the earth passes over before you into the Jordan.'),
  ('Joshua', 3, 12, 'Now therefore take twelve men out of the tribes of Israel, for every tribe a man.'),
  ('Joshua', 3, 13, 'It shall be that when the soles of the feet of the priests who bear the ark of GOD, the Lord of all the earth, rest in the waters of the Jordan, that the waters of the Jordan will be cut off. The waters that come down from above shall stand in one heap.”'),
  ('Joshua', 3, 14, 'When the people moved from their tents to pass over the Jordan, the priests who bore the ark of the covenant being before the people,'),
  ('Joshua', 3, 15, 'and when those who bore the ark had come to the Jordan, and the feet of the priests who bore the ark had dipped in the edge of the water (for the Jordan overflows all its banks all the time of harvest),'),
  ('Joshua', 3, 16, 'the waters which came down from above stood, and rose up in one heap a great way off, at Adam, the city that is beside Zarethan; and those that went down toward the sea of the Arabah, even the Salt Sea, were wholly cut off. Then the people passed over near Jericho.'),
  ('Joshua', 3, 17, 'The priests who bore the ark of the LORD’s covenant stood firm on dry ground in the middle of the Jordan; and all Israel crossed over on dry ground, until all the nation had passed completely over the Jordan.'),
  ('Joshua', 4, 1, 'When all the nation had completely crossed over the Jordan, the LORD spoke to Joshua, saying,'),
  ('Joshua', 4, 2, '“Take twelve men out of the people, a man out of every tribe,'),
  ('Joshua', 4, 3, 'and command them, saying, ‘Take from out of the middle of the Jordan, out of the place where the priests’ feet stood firm, twelve stones, carry them over with you, and lay them down in the place where you’ll camp tonight.’”'),
  ('Joshua', 4, 4, 'Then Joshua called the twelve men whom he had prepared of the children of Israel, a man out of every tribe.'),
  ('Joshua', 4, 5, 'Joshua said to them, “Cross before the ark of the LORD your God into the middle of the Jordan, and each of you pick up a stone and put it on your shoulder, according to the number of the tribes of the children of Israel;'),
  ('Joshua', 4, 6, 'that this may be a sign among you, that when your children ask in the future, saying, ‘What do you mean by these stones?’'),
  ('Joshua', 4, 7, 'then you shall tell them, ‘Because the waters of the Jordan were cut off before the ark of the LORD’s covenant. When it crossed over the Jordan, the waters of the Jordan were cut off. These stones shall be for a memorial to the children of Israel forever.’”'),
  ('Joshua', 4, 8, 'The children of Israel did as Joshua commanded, and took up twelve stones out of the middle of the Jordan, as the LORD spoke to Joshua, according to the number of the tribes of the children of Israel. They carried them over with them to the place where they camped, and laid them down there.'),
  ('Joshua', 4, 9, 'Joshua set up twelve stones in the middle of the Jordan, in the place where the feet of the priests who bore the ark of the covenant stood; and they are there to this day.'),
  ('Joshua', 4, 10, 'For the priests who bore the ark stood in the middle of the Jordan until everything was finished that the LORD commanded Joshua to speak to the people, according to all that Moses commanded Joshua; and the people hurried and passed over.'),
  ('Joshua', 4, 11, 'When all the people had completely crossed over, the LORD’s ark crossed over with the priests in the presence of the people.'),
  ('Joshua', 4, 12, 'The children of Reuben, and the children of Gad, and the half-tribe of Manasseh crossed over armed before the children of Israel, as Moses spoke to them.'),
  ('Joshua', 4, 13, 'About forty thousand men, ready and armed for war, passed over before the LORD to battle, to the plains of Jericho.'),
  ('Joshua', 4, 14, 'On that day, the LORD magnified Joshua in the sight of all Israel; and they feared him, as they feared Moses, all the days of his life.'),
  ('Joshua', 4, 15, 'The LORD spoke to Joshua, saying,'),
  ('Joshua', 4, 16, '“Command the priests who bear the ark of the covenant, that they come up out of the Jordan.”'),
  ('Joshua', 4, 17, 'Joshua therefore commanded the priests, saying, “Come up out of the Jordan!”'),
  ('Joshua', 4, 18, 'When the priests who bore the ark of the LORD’s covenant had come up out of the middle of the Jordan, and the soles of the priests’ feet had been lifted up to the dry ground, the waters of the Jordan returned to their place, and went over all its banks, as before.'),
  ('Joshua', 4, 19, 'The people came up out of the Jordan on the tenth day of the first month, and encamped in Gilgal, on the east border of Jericho.'),
  ('Joshua', 4, 20, 'Joshua set up those twelve stones, which they took out of the Jordan, in Gilgal.'),
  ('Joshua', 4, 21, 'He spoke to the children of Israel, saying, “When your children ask their fathers in time to come, saying, ‘What do these stones mean?’'),
  ('Joshua', 4, 22, 'Then you shall let your children know, saying, ‘Israel came over this Jordan on dry land.'),
  ('Joshua', 4, 23, 'For the LORD your God dried up the waters of the Jordan from before you until you had crossed over, as the LORD your God did to the Red Sea, which he dried up from before us, until we had crossed over,'),
  ('Joshua', 4, 24, 'that all the peoples of the earth may know that the LORD’s hand is mighty, and that you may fear the LORD your God forever.’”'),
  ('Joshua', 5, 1, 'When all the kings of the Amorites, who were beyond the Jordan westward, and all the kings of the Canaanites, who were by the sea, heard how the LORD had dried up the waters of the Jordan from before the children of Israel until we had crossed over, their heart melted, and there was no more spirit in them, because of the children of Israel.'),
  ('Joshua', 5, 2, 'At that time, the LORD said to Joshua, “Make flint knives, and circumcise again the sons of Israel the second time.”'),
  ('Joshua', 5, 3, 'Joshua made himself flint knives, and circumcised the sons of Israel at the hill of the foreskins.'),
  ('Joshua', 5, 4, 'This is the reason Joshua circumcised them: all the people who came out of Egypt, who were males, even all the men of war, died in the wilderness along the way, after they came out of Egypt.'),
  ('Joshua', 5, 5, 'For all the people who came out were circumcised; but all the people who were born in the wilderness along the way as they came out of Egypt had not been circumcised.'),
  ('Joshua', 5, 6, 'For the children of Israel walked forty years in the wilderness until all the nation, even the men of war who came out of Egypt, were consumed, because they didn’t listen to the LORD’s voice. The LORD swore to them that he wouldn’t let them see the land which the LORD swore to their fathers that he would give us, a land flowing with milk and honey.'),
  ('Joshua', 5, 7, 'Their children, whom he raised up in their place, were circumcised by Joshua, for they were uncircumcised, because they had not circumcised them on the way.'),
  ('Joshua', 5, 8, 'When they were done circumcising the whole nation, they stayed in their places in the camp until they were healed.'),
  ('Joshua', 5, 9, 'The LORD said to Joshua, “Today I have rolled away the reproach of Egypt from you.” Therefore the name of that place was called Gilgal to this day.'),
  ('Joshua', 5, 10, 'The children of Israel encamped in Gilgal. They kept the Passover on the fourteenth day of the month at evening in the plains of Jericho.'),
  ('Joshua', 5, 11, 'They ate unleavened cakes and parched grain of the produce of the land on the next day after the Passover, in the same day.'),
  ('Joshua', 5, 12, 'The manna ceased on the next day, after they had eaten of the produce of the land. The children of Israel didn’t have manna any more, but they ate of the fruit of the land of Canaan that year.'),
  ('Joshua', 5, 13, 'When Joshua was by Jericho, he lifted up his eyes and looked, and behold, a man stood in front of him with his sword drawn in his hand. Joshua went to him and said to him, “Are you for us, or for our enemies?”'),
  ('Joshua', 5, 14, 'He said, “No; but I have come now as commander of the LORD’s army.” Joshua fell on his face to the earth, and worshiped, and asked him, “What does my lord say to his servant?”'),
  ('Joshua', 5, 15, 'The prince of the LORD’s army said to Joshua, “Take off your sandals, for the place on which you stand is holy.” Joshua did so.'),
  ('Joshua', 6, 1, 'Now Jericho was tightly shut up because of the children of Israel. No one went out, and no one came in.'),
  ('Joshua', 6, 2, 'The LORD said to Joshua, “Behold, I have given Jericho into your hand, with its king and the mighty men of valor.'),
  ('Joshua', 6, 3, 'All of your men of war shall march around the city, going around the city once. You shall do this six days.'),
  ('Joshua', 6, 4, 'Seven priests shall bear seven trumpets of rams’ horns before the ark. On the seventh day, you shall march around the city seven times, and the priests shall blow the trumpets.'),
  ('Joshua', 6, 5, 'It shall be that when they make a long blast with the ram’s horn, and when you hear the sound of the trumpet, all the people shall shout with a great shout; then the city wall will fall down flat, and the people shall go up, every man straight in front of him.”'),
  ('Joshua', 6, 6, 'Joshua the son of Nun called the priests, and said to them, “Take up the ark of the covenant, and let seven priests bear seven trumpets of rams’ horns before the LORD’s ark.”'),
  ('Joshua', 6, 7, 'They said to the people, “Advance! March around the city, and let the armed men pass on before the LORD’s ark.”'),
  ('Joshua', 6, 8, 'It was so, that when Joshua had spoken to the people, the seven priests bearing the seven trumpets of rams’ horns before the LORD advanced and blew the trumpets, and the ark of the LORD’s covenant followed them.'),
  ('Joshua', 6, 9, 'The armed men went before the priests who blew the trumpets, and the ark went after them. The trumpets sounded as they went.'),
  ('Joshua', 6, 10, 'Joshua commanded the people, saying, “You shall not shout nor let your voice be heard, neither shall any word proceed out of your mouth until the day I tell you to shout. Then you shall shout.”'),
  ('Joshua', 6, 11, 'So he caused the LORD’s ark to go around the city, circling it once. Then they came into the camp, and stayed in the camp.'),
  ('Joshua', 6, 12, 'Joshua rose early in the morning, and the priests took up the LORD’s ark.'),
  ('Joshua', 6, 13, 'The seven priests bearing the seven trumpets of rams’ horns in front of the LORD’s ark went on continually, and blew the trumpets. The armed men went in front of them. The rear guard came after the LORD’s ark. The trumpets sounded as they went.'),
  ('Joshua', 6, 14, 'The second day they marched around the city once, and returned into the camp. They did this six days.'),
  ('Joshua', 6, 15, 'On the seventh day, they rose early at the dawning of the day, and marched around the city in the same way seven times. On this day only they marched around the city seven times.'),
  ('Joshua', 6, 16, 'At the seventh time, when the priests blew the trumpets, Joshua said to the people, “Shout, for the LORD has given you the city!'),
  ('Joshua', 6, 17, 'The city shall be devoted, even it and all that is in it, to the LORD. Only Rahab the prostitute shall live, she and all who are with her in the house, because she hid the messengers that we sent.'),
  ('Joshua', 6, 18, 'But as for you, only keep yourselves from what is devoted to destruction, lest when you have devoted it, you take of the devoted thing; so you would make the camp of Israel accursed and trouble it.'),
  ('Joshua', 6, 19, 'But all the silver, gold, and vessels of bronze and iron are holy to the LORD. They shall come into the LORD’s treasury.”'),
  ('Joshua', 6, 20, 'So the people shouted and the priests blew the trumpets. When the people heard the sound of the trumpet, the people shouted with a great shout, and the wall fell down flat, so that the people went up into the city, every man straight in front of him, and they took the city.'),
  ('Joshua', 6, 21, 'They utterly destroyed all that was in the city, both man and woman, both young and old, and ox, sheep, and donkey, with the edge of the sword.'),
  ('Joshua', 6, 22, 'Joshua said to the two men who had spied out the land, “Go into the prostitute’s house, and bring the woman and all that she has out from there, as you swore to her.”'),
  ('Joshua', 6, 23, 'The young men who were spies went in, and brought out Rahab with her father, her mother, her brothers, and all that she had. They also brought out all of her relatives, and they set them outside of the camp of Israel.'),
  ('Joshua', 6, 24, 'They burned the city with fire, and all that was in it. Only they put the silver, the gold, and the vessels of bronze and of iron into the treasury of the LORD’s house.'),
  ('Joshua', 6, 25, 'But Rahab the prostitute, her father’s household, and all that she had, Joshua saved alive. She lives in the middle of Israel to this day, because she hid the messengers whom Joshua sent to spy out Jericho.'),
  ('Joshua', 6, 26, 'Joshua commanded them with an oath at that time, saying, “Cursed is the man before the LORD who rises up and builds this city Jericho. With the loss of his firstborn he will lay its foundation, and with the loss of his youngest son he will set up its gates.”'),
  ('Joshua', 6, 27, 'So the LORD was with Joshua; and his fame was in all the land.'),
  ('Joshua', 7, 1, 'But the children of Israel committed a trespass in the devoted things; for Achan, the son of Carmi, the son of Zabdi, the son of Zerah, of the tribe of Judah, took some of the devoted things. Therefore the LORD’s anger burned against the children of Israel.'),
  ('Joshua', 7, 2, 'Joshua sent men from Jericho to Ai, which is beside Beth Aven, on the east side of Bethel, and spoke to them, saying, “Go up and spy out the land.” The men went up and spied out Ai.'),
  ('Joshua', 7, 3, 'They returned to Joshua, and said to him, “Don’t let all the people go up, but let about two or three thousand men go up and strike Ai. Don’t make all the people to toil there, for there are only a few of them.”'),
  ('Joshua', 7, 4, 'So about three thousand men of the people went up there, and they fled before the men of Ai.'),
  ('Joshua', 7, 5, 'The men of Ai struck about thirty-six men of them. They chased them from before the gate even to Shebarim, and struck them at the descent. The hearts of the people melted, and became like water.'),
  ('Joshua', 7, 6, 'Joshua tore his clothes, and fell to the earth on his face before the LORD’s ark until the evening, he and the elders of Israel; and they put dust on their heads.'),
  ('Joshua', 7, 7, 'Joshua said, “Alas, Lord GOD, why have you brought this people over the Jordan at all, to deliver us into the hand of the Amorites, to cause us to perish? I wish that we had been content and lived beyond the Jordan!'),
  ('Joshua', 7, 8, 'Oh, Lord, what shall I say, after Israel has turned their backs before their enemies?'),
  ('Joshua', 7, 9, 'For the Canaanites and all the inhabitants of the land will hear of it, and will surround us, and cut off our name from the earth. What will you do for your great name?”'),
  ('Joshua', 7, 10, 'The LORD said to Joshua, “Get up! Why have you fallen on your face like that?'),
  ('Joshua', 7, 11, 'Israel has sinned. Yes, they have even transgressed my covenant which I commanded them. Yes, they have even taken some of the devoted things, and have also stolen, and also deceived. They have even put it among their own stuff.'),
  ('Joshua', 7, 12, 'Therefore the children of Israel can’t stand before their enemies. They turn their backs before their enemies, because they have become devoted for destruction. I will not be with you any more, unless you destroy the devoted things from among you.'),
  ('Joshua', 7, 13, 'Get up! Sanctify the people, and say, ‘Sanctify yourselves for tomorrow, for the LORD, the God of Israel, says, “There is a devoted thing among you, Israel. You cannot stand before your enemies until you take away the devoted thing from among you.”'),
  ('Joshua', 7, 14, 'In the morning therefore you shall be brought near by your tribes. It shall be that the tribe which the LORD selects shall come near by families. The family which the LORD selects shall come near by households. The household which the LORD selects shall come near man by man.'),
  ('Joshua', 7, 15, 'It shall be, that he who is taken with the devoted thing shall be burned with fire, he and all that he has, because he has transgressed the LORD’s covenant, and because he has done a disgraceful thing in Israel.’”'),
  ('Joshua', 7, 16, 'So Joshua rose up early in the morning and brought Israel near by their tribes. The tribe of Judah was selected.'),
  ('Joshua', 7, 17, 'He brought near the family of Judah, and he selected the family of the Zerahites. He brought near the family of the Zerahites man by man, and Zabdi was selected.'),
  ('Joshua', 7, 18, 'He brought near his household man by man, and Achan, the son of Carmi, the son of Zabdi, the son of Zerah, of the tribe of Judah, was selected.'),
  ('Joshua', 7, 19, 'Joshua said to Achan, “My son, please give glory to the LORD, the God of Israel, and make confession to him. Tell me now what you have done! Don’t hide it from me!”'),
  ('Joshua', 7, 20, 'Achan answered Joshua, and said, “I have truly sinned against the LORD, the God of Israel, and this is what I have done.'),
  ('Joshua', 7, 21, 'When I saw among the plunder a beautiful Babylonian robe, two hundred shekels of silver, and a wedge of gold weighing fifty shekels, then I coveted them and took them. Behold, they are hidden in the ground in the middle of my tent, with the silver under it.”'),
  ('Joshua', 7, 22, 'So Joshua sent messengers, and they ran to the tent. Behold, it was hidden in his tent, with the silver under it.'),
  ('Joshua', 7, 23, 'They took them from the middle of the tent, and brought them to Joshua and to all the children of Israel. They laid them down before the LORD.');
INSERT INTO bible_verses (book_name, chapter, verse, text) VALUES
  ('Joshua', 7, 24, 'Joshua, and all Israel with him, took Achan the son of Zerah, the silver, the robe, the wedge of gold, his sons, his daughters, his cattle, his donkeys, his sheep, his tent, and all that he had; and they brought them up to the valley of Achor.'),
  ('Joshua', 7, 25, 'Joshua said, “Why have you troubled us? The LORD will trouble you today.” All Israel stoned him with stones, and they burned them with fire and stoned them with stones.'),
  ('Joshua', 7, 26, 'They raised over him a great heap of stones that remains to this day. The LORD turned from the fierceness of his anger. Therefore the name of that place was called “The valley of Achor” to this day.'),
  ('Joshua', 8, 1, 'The LORD said to Joshua, “Don’t be afraid, and don’t be dismayed. Take all the warriors with you, and arise, go up to Ai. Behold, I have given into your hand the king of Ai, with his people, his city, and his land.'),
  ('Joshua', 8, 2, 'You shall do to Ai and her king as you did to Jericho and her king, except you shall take its goods and its livestock for yourselves. Set an ambush for the city behind it.”'),
  ('Joshua', 8, 3, 'So Joshua arose, with all the warriors, to go up to Ai. Joshua chose thirty thousand men, the mighty men of valor, and sent them out by night.'),
  ('Joshua', 8, 4, 'He commanded them, saying, “Behold, you shall lie in ambush against the city, behind the city. Don’t go very far from the city, but all of you be ready.'),
  ('Joshua', 8, 5, 'I and all the people who are with me will approach the city. It shall happen, when they come out against us, as at the first, that we will flee before them.'),
  ('Joshua', 8, 6, 'They will come out after us until we have drawn them away from the city; for they will say, ‘They flee before us, like the first time.’ So we will flee before them,'),
  ('Joshua', 8, 7, 'and you shall rise up from the ambush, and take possession of the city; for the LORD your God will deliver it into your hand.'),
  ('Joshua', 8, 8, 'It shall be, when you have seized the city, that you shall set the city on fire. You shall do this according to the LORD’s word. Behold, I have commanded you.”'),
  ('Joshua', 8, 9, 'Joshua sent them out; and they went to set up the ambush, and stayed between Bethel and Ai on the west side of Ai; but Joshua stayed among the people that night.'),
  ('Joshua', 8, 10, 'Joshua rose up early in the morning, mustered the people, and went up, he and the elders of Israel, before the people to Ai.'),
  ('Joshua', 8, 11, 'All the people, even the men of war who were with him, went up and came near, and came before the city and encamped on the north side of Ai. Now there was a valley between him and Ai.'),
  ('Joshua', 8, 12, 'He took about five thousand men, and set them in ambush between Bethel and Ai, on the west side of the city.'),
  ('Joshua', 8, 13, 'So they set the people, even all the army who was on the north of the city, and their ambush on the west of the city; and Joshua went that night into the middle of the valley.'),
  ('Joshua', 8, 14, 'When the king of Ai saw it, they hurried and rose up early, and the men of the city went out against Israel to battle, he and all his people, at the time appointed, before the Arabah; but he didn’t know that there was an ambush against him behind the city.'),
  ('Joshua', 8, 15, 'Joshua and all Israel made as if they were beaten before them, and fled by the way of the wilderness.'),
  ('Joshua', 8, 16, 'All the people who were in the city were called together to pursue after them. They pursued Joshua, and were drawn away from the city.'),
  ('Joshua', 8, 17, 'There was not a man left in Ai or Bethel who didn’t go out after Israel. They left the city open, and pursued Israel.'),
  ('Joshua', 8, 18, 'The LORD said to Joshua, “Stretch out the javelin that is in your hand toward Ai, for I will give it into your hand.” Joshua stretched out the javelin that was in his hand toward the city.'),
  ('Joshua', 8, 19, 'The ambush arose quickly out of their place, and they ran as soon as he had stretched out his hand and entered into the city and took it. They hurried and set the city on fire.'),
  ('Joshua', 8, 20, 'When the men of Ai looked behind them, they saw, and behold, the smoke of the city ascended up to heaven, and they had no power to flee this way or that way. The people who fled to the wilderness turned back on the pursuers.'),
  ('Joshua', 8, 21, 'When Joshua and all Israel saw that the ambush had taken the city, and that the smoke of the city ascended, then they turned back and killed the men of Ai.'),
  ('Joshua', 8, 22, 'The others came out of the city against them, so they were in the middle of Israel, some on this side, and some on that side. They struck them, so that they let none of them remain or escape.'),
  ('Joshua', 8, 23, 'They captured the king of Ai alive, and brought him to Joshua.'),
  ('Joshua', 8, 24, 'When Israel had finished killing all the inhabitants of Ai in the field, in the wilderness in which they pursued them, and they had all fallen by the edge of the sword until they were consumed, all Israel returned to Ai and struck it with the edge of the sword.'),
  ('Joshua', 8, 25, 'All that fell that day, both of men and women, were twelve thousand, even all the people of Ai.'),
  ('Joshua', 8, 26, 'For Joshua didn’t draw back his hand, with which he stretched out the javelin, until he had utterly destroyed all the inhabitants of Ai.'),
  ('Joshua', 8, 27, 'Israel took for themselves only the livestock and the goods of that city, according to the LORD’s word which he commanded Joshua.'),
  ('Joshua', 8, 28, 'So Joshua burned Ai and made it a heap forever, even a desolation, to this day.'),
  ('Joshua', 8, 29, 'He hanged the king of Ai on a tree until the evening. At sundown, Joshua commanded, and they took his body down from the tree and threw it at the entrance of the gate of the city, and raised a great heap of stones on it that remains to this day.'),
  ('Joshua', 8, 30, 'Then Joshua built an altar to the LORD, the God of Israel, on Mount Ebal,'),
  ('Joshua', 8, 31, 'as Moses the servant of the LORD commanded the children of Israel, as it is written in the book of the law of Moses: an altar of uncut stones, on which no one had lifted up any iron. They offered burnt offerings on it to the LORD and sacrificed peace offerings.'),
  ('Joshua', 8, 32, 'He wrote there on the stones a copy of Moses’ law, which he wrote in the presence of the children of Israel.'),
  ('Joshua', 8, 33, 'All Israel, with their elders, officers, and judges, stood on both sides of the ark before the Levitical priests, who carried the ark of the LORD’s covenant, the foreigner as well as the native; half of them in front of Mount Gerizim, and half of them in front of Mount Ebal, as Moses the servant of the LORD had commanded at the first, that they should bless the people of Israel.'),
  ('Joshua', 8, 34, 'Afterward he read all the words of the law, the blessing and the curse, according to all that is written in the book of the law.'),
  ('Joshua', 8, 35, 'There was not a word of all that Moses commanded which Joshua didn’t read before all the assembly of Israel, with the women, the little ones, and the foreigners who were among them.'),
  ('Joshua', 9, 1, 'When all the kings who were beyond the Jordan, in the hill country, and in the lowland, and on all the shore of the great sea in front of Lebanon, the Hittite, the Amorite, the Canaanite, the Perizzite, the Hivite, and the Jebusite, heard of it'),
  ('Joshua', 9, 2, 'they gathered themselves together to fight with Joshua and with Israel, with one accord.'),
  ('Joshua', 9, 3, 'But when the inhabitants of Gibeon heard what Joshua had done to Jericho and to Ai,'),
  ('Joshua', 9, 4, 'they also resorted to a ruse, and went and made as if they had been ambassadors, and took old sacks on their donkeys, and old, torn-up and bound up wineskins,'),
  ('Joshua', 9, 5, 'and old and patched sandals on their feet, and wore old garments. All the bread of their food supply was dry and moldy.'),
  ('Joshua', 9, 6, 'They went to Joshua at the camp at Gilgal, and said to him and to the men of Israel, “We have come from a far country. Now therefore make a covenant with us.”'),
  ('Joshua', 9, 7, 'The men of Israel said to the Hivites, “What if you live among us? How could we make a covenant with you?”'),
  ('Joshua', 9, 8, 'They said to Joshua, “We are your servants.” Joshua said to them, “Who are you? Where do you come from?”'),
  ('Joshua', 9, 9, 'They said to him, “Your servants have come from a very far country because of the name of the LORD your God; for we have heard of his fame, all that he did in Egypt,'),
  ('Joshua', 9, 10, 'and all that he did to the two kings of the Amorites who were beyond the Jordan, to Sihon king of Heshbon and to Og king of Bashan, who was at Ashtaroth.'),
  ('Joshua', 9, 11, 'Our elders and all the inhabitants of our country spoke to us, saying, ‘Take supplies in your hand for the journey, and go to meet them. Tell them, “We are your servants. Now make a covenant with us.”’'),
  ('Joshua', 9, 12, 'This our bread we took hot for our supplies out of our houses on the day we went out to go to you; but now, behold, it is dry, and has become moldy.'),
  ('Joshua', 9, 13, 'These wineskins, which we filled, were new; and behold, they are torn. These our garments and our sandals have become old because of the very long journey.”'),
  ('Joshua', 9, 14, 'The men sampled their provisions, and didn’t ask counsel from the LORD’s mouth.'),
  ('Joshua', 9, 15, 'Joshua made peace with them, and made a covenant with them, to let them live. The princes of the congregation swore to them.'),
  ('Joshua', 9, 16, 'At the end of three days after they had made a covenant with them, they heard that they were their neighbors, and that they lived among them.'),
  ('Joshua', 9, 17, 'The children of Israel traveled and came to their cities on the third day. Now their cities were Gibeon, Chephirah, Beeroth, and Kiriath Jearim.'),
  ('Joshua', 9, 18, 'The children of Israel didn’t strike them, because the princes of the congregation had sworn to them by the LORD, the God of Israel. All the congregation murmured against the princes.'),
  ('Joshua', 9, 19, 'But all the princes said to all the congregation, “We have sworn to them by the LORD, the God of Israel. Now therefore we may not touch them.'),
  ('Joshua', 9, 20, 'We will do this to them, and let them live; lest wrath be on us, because of the oath which we swore to them.”'),
  ('Joshua', 9, 21, 'The princes said to them, “Let them live.” So they became wood cutters and drawers of water for all the congregation, as the princes had spoken to them.'),
  ('Joshua', 9, 22, 'Joshua called for them, and he spoke to them, saying, “Why have you deceived us, saying, ‘We are very far from you,’ when you live among us?'),
  ('Joshua', 9, 23, 'Now therefore you are cursed, and some of you will never fail to be slaves, both wood cutters and drawers of water for the house of my God.”'),
  ('Joshua', 9, 24, 'They answered Joshua, and said, “Because your servants were certainly told how the LORD your God commanded his servant Moses to give you all the land, and to destroy all the inhabitants of the land from before you. Therefore we were very afraid for our lives because of you, and have done this thing.'),
  ('Joshua', 9, 25, 'Now, behold, we are in your hand. Do to us as it seems good and right to you to do.”'),
  ('Joshua', 9, 26, 'He did so to them, and delivered them out of the hand of the children of Israel, so that they didn’t kill them.'),
  ('Joshua', 9, 27, 'That day Joshua made them wood cutters and drawers of water for the congregation and for the LORD’s altar to this day, in the place which he should choose.'),
  ('Joshua', 10, 1, 'Now when Adoni-Zedek king of Jerusalem heard how Joshua had taken Ai, and had utterly destroyed it; as he had done to Jericho and her king, so he had done to Ai and her king; and how the inhabitants of Gibeon had made peace with Israel, and were among them,'),
  ('Joshua', 10, 2, 'they were very afraid, because Gibeon was a great city, as one of the royal cities, and because it was greater than Ai, and all its men were mighty.'),
  ('Joshua', 10, 3, 'Therefore Adoni-Zedek king of Jerusalem sent to Hoham king of Hebron, Piram king of Jarmuth, Japhia king of Lachish, and Debir king of Eglon, saying,'),
  ('Joshua', 10, 4, '“Come up to me and help me. Let’s strike Gibeon; for they have made peace with Joshua and with the children of Israel.”'),
  ('Joshua', 10, 5, 'Therefore the five kings of the Amorites, the king of Jerusalem, the king of Hebron, the king of Jarmuth, the king of Lachish, and the king of Eglon, gathered themselves together and went up, they and all their armies, and encamped against Gibeon, and made war against it.'),
  ('Joshua', 10, 6, 'The men of Gibeon sent to Joshua at the camp at Gilgal, saying, “Don’t abandon your servants! Come up to us quickly and save us! Help us; for all the kings of the Amorites that dwell in the hill country have gathered together against us.”'),
  ('Joshua', 10, 7, 'So Joshua went up from Gilgal, he and the whole army with him, including all the mighty men of valor.'),
  ('Joshua', 10, 8, 'The LORD said to Joshua, “Don’t fear them, for I have delivered them into your hands. Not a man of them will stand before you.”'),
  ('Joshua', 10, 9, 'Joshua therefore came to them suddenly. He marched from Gilgal all night.'),
  ('Joshua', 10, 10, 'The LORD confused them before Israel. He killed them with a great slaughter at Gibeon, and chased them by the way of the ascent of Beth Horon, and struck them to Azekah and to Makkedah.'),
  ('Joshua', 10, 11, 'As they fled from before Israel, while they were at the descent of Beth Horon, the LORD hurled down great stones from the sky on them to Azekah, and they died. There were more who died from the hailstones than those whom the children of Israel killed with the sword.'),
  ('Joshua', 10, 12, 'Then Joshua spoke to the LORD in the day when the LORD delivered up the Amorites before the children of Israel. He said in the sight of Israel, “Sun, stand still on Gibeon! You, moon, stop in the valley of Aijalon!”'),
  ('Joshua', 10, 13, 'The sun stood still, and the moon stayed, until the nation had avenged themselves of their enemies. Isn’t this written in the book of Jashar? The sun stayed in the middle of the sky, and didn’t hurry to go down about a whole day.'),
  ('Joshua', 10, 14, 'There was no day like that before it or after it, that the LORD listened to the voice of a man; for the LORD fought for Israel.'),
  ('Joshua', 10, 15, 'Joshua returned, and all Israel with him, to the camp to Gilgal.'),
  ('Joshua', 10, 16, 'These five kings fled, and hid themselves in the cave at Makkedah.'),
  ('Joshua', 10, 17, 'Joshua was told, saying, “The five kings have been found, hidden in the cave at Makkedah.”'),
  ('Joshua', 10, 18, 'Joshua said, “Roll large stones to cover the cave’s entrance, and set men by it to guard them;'),
  ('Joshua', 10, 19, 'but don’t stay there. Pursue your enemies, and attack them from the rear. Don’t allow them to enter into their cities; for the LORD your God has delivered them into your hand.”'),
  ('Joshua', 10, 20, 'When Joshua and the children of Israel had finished killing them with a very great slaughter until they were consumed, and the remnant which remained of them had entered into the fortified cities,'),
  ('Joshua', 10, 21, 'all the people returned to the camp to Joshua at Makkedah in peace. None moved his tongue against any of the children of Israel.'),
  ('Joshua', 10, 22, 'Then Joshua said, “Open the cave entrance, and bring those five kings out of the cave to me.”'),
  ('Joshua', 10, 23, 'They did so, and brought those five kings out of the cave to him: the king of Jerusalem, the king of Hebron, the king of Jarmuth, the king of Lachish, and the king of Eglon.'),
  ('Joshua', 10, 24, 'When they brought those kings out to Joshua, Joshua called for all the men of Israel, and said to the chiefs of the men of war who went with him, “Come near. Put your feet on the necks of these kings.” They came near, and put their feet on their necks.'),
  ('Joshua', 10, 25, 'Joshua said to them, “Don’t be afraid, nor be dismayed. Be strong and courageous, for the LORD will do this to all your enemies against whom you fight.”'),
  ('Joshua', 10, 26, 'Afterward Joshua struck them, put them to death, and hanged them on five trees. They were hanging on the trees until the evening.'),
  ('Joshua', 10, 27, 'At the time of the going down of the sun, Joshua commanded, and they took them down off the trees, and threw them into the cave in which they had hidden themselves, and laid great stones on the mouth of the cave, which remain to this very day.'),
  ('Joshua', 10, 28, 'Joshua took Makkedah on that day, and struck it with the edge of the sword, with its king. He utterly destroyed it and all the souls who were in it. He left no one remaining. He did to the king of Makkedah as he had done to the king of Jericho.'),
  ('Joshua', 10, 29, 'Joshua passed from Makkedah, and all Israel with him, to Libnah, and fought against Libnah.'),
  ('Joshua', 10, 30, 'The LORD delivered it also, with its king, into the hand of Israel. He struck it with the edge of the sword, and all the souls who were in it. He left no one remaining in it. He did to its king as he had done to the king of Jericho.'),
  ('Joshua', 10, 31, 'Joshua passed from Libnah, and all Israel with him, to Lachish, and encamped against it, and fought against it.'),
  ('Joshua', 10, 32, 'The LORD delivered Lachish into the hand of Israel. He took it on the second day, and struck it with the edge of the sword, with all the souls who were in it, according to all that he had done to Libnah.'),
  ('Joshua', 10, 33, 'Then Horam king of Gezer came up to help Lachish; and Joshua struck him and his people, until he had left him no one remaining.'),
  ('Joshua', 10, 34, 'Joshua passed from Lachish, and all Israel with him, to Eglon; and they encamped against it and fought against it.'),
  ('Joshua', 10, 35, 'They took it on that day, and struck it with the edge of the sword. He utterly destroyed all the souls who were in it that day, according to all that he had done to Lachish.');
INSERT INTO bible_verses (book_name, chapter, verse, text) VALUES
  ('Joshua', 10, 36, 'Joshua went up from Eglon, and all Israel with him, to Hebron; and they fought against it.'),
  ('Joshua', 10, 37, 'They took it, and struck it with the edge of the sword, with its king and all its cities, and all the souls who were in it. He left no one remaining, according to all that he had done to Eglon; but he utterly destroyed it, and all the souls who were in it.'),
  ('Joshua', 10, 38, 'Joshua returned, and all Israel with him, to Debir, and fought against it.'),
  ('Joshua', 10, 39, 'He took it, with its king and all its cities. They struck them with the edge of the sword, and utterly destroyed all the souls who were in it. He left no one remaining. As he had done to Hebron, so he did to Debir, and to its king; as he had done also to Libnah, and to its king.'),
  ('Joshua', 10, 40, 'So Joshua struck all the land, the hill country, the South, the lowland, the slopes, and all their kings. He left no one remaining, but he utterly destroyed all that breathed, as the LORD, the God of Israel, commanded.'),
  ('Joshua', 10, 41, 'Joshua struck them from Kadesh Barnea even to Gaza, and all the country of Goshen, even to Gibeon.'),
  ('Joshua', 10, 42, 'Joshua took all these kings and their land at one time because the LORD, the God of Israel, fought for Israel.'),
  ('Joshua', 10, 43, 'Joshua returned, and all Israel with him, to the camp to Gilgal.'),
  ('Joshua', 11, 1, 'When Jabin king of Hazor heard of it, he sent to Jobab king of Madon, to the king of Shimron, to the king of Achshaph,'),
  ('Joshua', 11, 2, 'and to the kings who were on the north, in the hill country, in the Arabah south of Chinneroth, in the lowland, and in the heights of Dor on the west,'),
  ('Joshua', 11, 3, 'to the Canaanite on the east and on the west, the Amorite, the Hittite, the Perizzite, the Jebusite in the hill country, and the Hivite under Hermon in the land of Mizpah.'),
  ('Joshua', 11, 4, 'They went out, they and all their armies with them, many people, even as the sand that is on the seashore in multitude, with very many horses and chariots.'),
  ('Joshua', 11, 5, 'All these kings met together; and they came and encamped together at the waters of Merom, to fight with Israel.'),
  ('Joshua', 11, 6, 'The LORD said to Joshua, “Don’t be afraid because of them; for tomorrow at this time, I will deliver them up all slain before Israel. You shall hamstring their horses and burn their chariots with fire.”'),
  ('Joshua', 11, 7, 'So Joshua came suddenly, with all the warriors, against them by the waters of Merom, and attacked them.'),
  ('Joshua', 11, 8, 'The LORD delivered them into the hand of Israel, and they struck them, and chased them to great Sidon, and to Misrephoth Maim, and to the valley of Mizpah eastward. They struck them until they left them no one remaining.'),
  ('Joshua', 11, 9, 'Joshua did to them as the LORD told him. He hamstrung their horses and burned their chariots with fire.'),
  ('Joshua', 11, 10, 'Joshua turned back at that time, and took Hazor, and struck its king with the sword; for Hazor used to be the head of all those kingdoms.'),
  ('Joshua', 11, 11, 'They struck all the souls who were in it with the edge of the sword, utterly destroying them. There was no one left who breathed. He burned Hazor with fire.'),
  ('Joshua', 11, 12, 'Joshua captured all the cities of those kings, with their kings, and he struck them with the edge of the sword, and utterly destroyed them, as Moses the servant of the LORD commanded.'),
  ('Joshua', 11, 13, 'But as for the cities that stood on their mounds, Israel burned none of them, except Hazor only. Joshua burned that.'),
  ('Joshua', 11, 14, 'The children of Israel took all the plunder of these cities, with the livestock, as plunder for themselves; but every man they struck with the edge of the sword, until they had destroyed them. They didn’t leave any who breathed.'),
  ('Joshua', 11, 15, 'As the LORD commanded Moses his servant, so Moses commanded Joshua. Joshua did so. He left nothing undone of all that the LORD commanded Moses.'),
  ('Joshua', 11, 16, 'So Joshua captured all that land, the hill country, all the South, all the land of Goshen, the lowland, the Arabah, the hill country of Israel, and the lowland of the same,'),
  ('Joshua', 11, 17, 'from Mount Halak, that goes up to Seir, even to Baal Gad in the valley of Lebanon under Mount Hermon. He took all their kings, struck them, and put them to death.'),
  ('Joshua', 11, 18, 'Joshua made war a long time with all those kings.'),
  ('Joshua', 11, 19, 'There was not a city that made peace with the children of Israel, except the Hivites, the inhabitants of Gibeon. They took all in battle.'),
  ('Joshua', 11, 20, 'For it was of the LORD to harden their hearts, to come against Israel in battle, that he might utterly destroy them, that they might have no favor, but that he might destroy them, as the LORD commanded Moses.'),
  ('Joshua', 11, 21, 'Joshua came at that time, and cut off the Anakim from the hill country, from Hebron, from Debir, from Anab, and from all the hill country of Judah, and from all the hill country of Israel. Joshua utterly destroyed them with their cities.'),
  ('Joshua', 11, 22, 'There were none of the Anakim left in the land of the children of Israel. Only in Gaza, in Gath, and in Ashdod, did some remain.'),
  ('Joshua', 11, 23, 'So Joshua took the whole land, according to all that the LORD spoke to Moses; and Joshua gave it for an inheritance to Israel according to their divisions by their tribes. Then the land had rest from war.'),
  ('Joshua', 12, 1, 'Now these are the kings of the land, whom the children of Israel struck, and possessed their land beyond the Jordan toward the sunrise, from the valley of the Arnon to Mount Hermon, and all the Arabah eastward:'),
  ('Joshua', 12, 2, 'Sihon king of the Amorites, who lived in Heshbon, and ruled from Aroer, which is on the edge of the valley of the Arnon, and the middle of the valley, and half Gilead, even to the river Jabbok, the border of the children of Ammon;'),
  ('Joshua', 12, 3, 'and the Arabah to the sea of Chinneroth, eastward, and to the sea of the Arabah, even the Salt Sea, eastward, the way to Beth Jeshimoth; and on the south, under the slopes of Pisgah:'),
  ('Joshua', 12, 4, 'and the border of Og king of Bashan, of the remnant of the Rephaim, who lived at Ashtaroth and at Edrei,'),
  ('Joshua', 12, 5, 'and ruled in Mount Hermon, and in Salecah, and in all Bashan, to the border of the Geshurites and the Maacathites, and half Gilead, the border of Sihon king of Heshbon.'),
  ('Joshua', 12, 6, 'Moses the servant of the LORD and the children of Israel struck them. Moses the servant of the LORD gave it for a possession to the Reubenites, and the Gadites, and the half-tribe of Manasseh.'),
  ('Joshua', 12, 7, 'These are the kings of the land whom Joshua and the children of Israel struck beyond the Jordan westward, from Baal Gad in the valley of Lebanon even to Mount Halak, that goes up to Seir. Joshua gave it to the tribes of Israel for a possession according to their divisions;'),
  ('Joshua', 12, 8, 'in the hill country, and in the lowland, and in the Arabah, and in the slopes, and in the wilderness, and in the South; the Hittite, the Amorite, and the Canaanite, the Perizzite, the Hivite, and the Jebusite:'),
  ('Joshua', 12, 9, 'the king of Jericho, one; the king of Ai, which is beside Bethel, one;'),
  ('Joshua', 12, 10, 'the king of Jerusalem, one; the king of Hebron, one;'),
  ('Joshua', 12, 11, 'the king of Jarmuth, one; the king of Lachish, one;'),
  ('Joshua', 12, 12, 'the king of Eglon, one; the king of Gezer, one;'),
  ('Joshua', 12, 13, 'the king of Debir, one; the king of Geder, one;'),
  ('Joshua', 12, 14, 'the king of Hormah, one; the king of Arad, one;'),
  ('Joshua', 12, 15, 'the king of Libnah, one; the king of Adullam, one;'),
  ('Joshua', 12, 16, 'the king of Makkedah, one; the king of Bethel, one;'),
  ('Joshua', 12, 17, 'the king of Tappuah, one; the king of Hepher, one;'),
  ('Joshua', 12, 18, 'the king of Aphek, one; the king of Lassharon, one;'),
  ('Joshua', 12, 19, 'the king of Madon, one; the king of Hazor, one;'),
  ('Joshua', 12, 20, 'the king of Shimron Meron, one; the king of Achshaph, one;'),
  ('Joshua', 12, 21, 'the king of Taanach, one; the king of Megiddo, one;'),
  ('Joshua', 12, 22, 'the king of Kedesh, one; the king of Jokneam in Carmel, one;'),
  ('Joshua', 12, 23, 'the king of Dor in the height of Dor, one; the king of Goiim in Gilgal, one;'),
  ('Joshua', 12, 24, 'the king of Tirzah, one: all the kings thirty-one.'),
  ('Joshua', 13, 1, 'Now Joshua was old and well advanced in years. The LORD said to him, “You are old and advanced in years, and there remains yet very much land to be possessed.'),
  ('Joshua', 13, 2, '“This is the land that still remains: all the regions of the Philistines, and all the Geshurites;'),
  ('Joshua', 13, 3, 'from the Shihor, which is before Egypt, even to the border of Ekron northward, which is counted as Canaanite; the five lords of the Philistines; the Gazites, and the Ashdodites, the Ashkelonites, the Gittites, and the Ekronites; also the Avvim,'),
  ('Joshua', 13, 4, 'on the south; all the land of the Canaanites, and Mearah that belongs to the Sidonians, to Aphek, to the border of the Amorites;'),
  ('Joshua', 13, 5, 'and the land of the Gebalites, and all Lebanon, toward the sunrise, from Baal Gad under Mount Hermon to the entrance of Hamath;'),
  ('Joshua', 13, 6, 'all the inhabitants of the hill country from Lebanon to Misrephoth Maim, even all the Sidonians. I will drive them out from before the children of Israel. Just allocate it to Israel for an inheritance, as I have commanded you.'),
  ('Joshua', 13, 7, 'Now therefore divide this land for an inheritance to the nine tribes and the half-tribe of Manasseh.”'),
  ('Joshua', 13, 8, 'With him the Reubenites and the Gadites received their inheritance, which Moses gave them, beyond the Jordan eastward, even as Moses the servant of the LORD gave them:'),
  ('Joshua', 13, 9, 'from Aroer, that is on the edge of the valley of the Arnon, and the city that is in the middle of the valley, and all the plain of Medeba to Dibon;'),
  ('Joshua', 13, 10, 'and all the cities of Sihon king of the Amorites, who reigned in Heshbon, to the border of the children of Ammon;'),
  ('Joshua', 13, 11, 'and Gilead, and the border of the Geshurites and Maacathites, and all Mount Hermon, and all Bashan to Salecah;'),
  ('Joshua', 13, 12, 'all the kingdom of Og in Bashan, who reigned in Ashtaroth and in Edrei (who was left of the remnant of the Rephaim); for Moses attacked these, and drove them out.'),
  ('Joshua', 13, 13, 'Nevertheless the children of Israel didn’t drive out the Geshurites, nor the Maacathites: but Geshur and Maacath live within Israel to this day.'),
  ('Joshua', 13, 14, 'Only he gave no inheritance to the tribe of Levi. The offerings of the LORD, the God of Israel, made by fire are his inheritance, as he spoke to him.'),
  ('Joshua', 13, 15, 'Moses gave to the tribe of the children of Reuben according to their families.'),
  ('Joshua', 13, 16, 'Their border was from Aroer, that is on the edge of the valley of the Arnon, and the city that is in the middle of the valley, and all the plain by Medeba;'),
  ('Joshua', 13, 17, 'Heshbon, and all its cities that are in the plain; Dibon, Bamoth Baal, Beth Baal Meon,'),
  ('Joshua', 13, 18, 'Jahaz, Kedemoth, Mephaath,'),
  ('Joshua', 13, 19, 'Kiriathaim, Sibmah, Zereth Shahar in the mount of the valley,'),
  ('Joshua', 13, 20, 'Beth Peor, the slopes of Pisgah, Beth Jeshimoth,'),
  ('Joshua', 13, 21, 'all the cities of the plain, and all the kingdom of Sihon king of the Amorites, who reigned in Heshbon, whom Moses struck with the chiefs of Midian, Evi, Rekem, Zur, Hur, and Reba, the princes of Sihon, who lived in the land.'),
  ('Joshua', 13, 22, 'The children of Israel also killed Balaam the son of Beor, the soothsayer, with the sword, among the rest of their slain.'),
  ('Joshua', 13, 23, 'The border of the children of Reuben was the bank of the Jordan. This was the inheritance of the children of Reuben according to their families, the cities and its villages.'),
  ('Joshua', 13, 24, 'Moses gave to the tribe of Gad, to the children of Gad, according to their families.'),
  ('Joshua', 13, 25, 'Their border was Jazer, and all the cities of Gilead, and half the land of the children of Ammon, to Aroer that is near Rabbah;'),
  ('Joshua', 13, 26, 'and from Heshbon to Ramath Mizpeh, and Betonim; and from Mahanaim to the border of Debir;'),
  ('Joshua', 13, 27, 'and in the valley, Beth Haram, Beth Nimrah, Succoth, and Zaphon, the rest of the kingdom of Sihon king of Heshbon, the Jordan’s bank, to the uttermost part of the sea of Chinnereth beyond the Jordan eastward.'),
  ('Joshua', 13, 28, 'This is the inheritance of the children of Gad according to their families, the cities and its villages.'),
  ('Joshua', 13, 29, 'Moses gave an inheritance to the half-tribe of Manasseh. It was for the half-tribe of the children of Manasseh according to their families.'),
  ('Joshua', 13, 30, 'Their border was from Mahanaim, all Bashan, all the kingdom of Og king of Bashan, and all the villages of Jair, which are in Bashan, sixty cities.'),
  ('Joshua', 13, 31, 'Half Gilead, Ashtaroth, and Edrei, the cities of the kingdom of Og in Bashan, were for the children of Machir the son of Manasseh, even for the half of the children of Machir according to their families.'),
  ('Joshua', 13, 32, 'These are the inheritances which Moses distributed in the plains of Moab, beyond the Jordan at Jericho, eastward.'),
  ('Joshua', 13, 33, 'But Moses gave no inheritance to the tribe of Levi. The LORD, the God of Israel, is their inheritance, as he spoke to them.'),
  ('Joshua', 14, 1, 'These are the inheritances which the children of Israel took in the land of Canaan, which Eleazar the priest, Joshua the son of Nun, and the heads of the fathers’ houses of the tribes of the children of Israel, distributed to them,'),
  ('Joshua', 14, 2, 'by the lot of their inheritance, as the LORD commanded by Moses, for the nine tribes, and for the half-tribe.'),
  ('Joshua', 14, 3, 'For Moses had given the inheritance of the two tribes and the half-tribe beyond the Jordan; but to the Levites he gave no inheritance among them.'),
  ('Joshua', 14, 4, 'For the children of Joseph were two tribes, Manasseh and Ephraim. They gave no portion to the Levites in the land, except cities to dwell in, with their pasture lands for their livestock and for their property.'),
  ('Joshua', 14, 5, 'The children of Israel did as the LORD commanded Moses, and they divided the land.'),
  ('Joshua', 14, 6, 'Then the children of Judah came near to Joshua in Gilgal. Caleb the son of Jephunneh the Kenizzite said to him, “You know the thing that the LORD spoke to Moses the man of God concerning me and concerning you in Kadesh Barnea.'),
  ('Joshua', 14, 7, 'I was forty years old when Moses the servant of the LORD sent me from Kadesh Barnea to spy out the land. I brought him word again as it was in my heart.'),
  ('Joshua', 14, 8, 'Nevertheless, my brothers who went up with me made the heart of the people melt; but I wholly followed the LORD my God.'),
  ('Joshua', 14, 9, 'Moses swore on that day, saying, ‘Surely the land where you walked shall be an inheritance to you and to your children forever, because you have wholly followed the LORD my God.’'),
  ('Joshua', 14, 10, '“Now, behold, the LORD has kept me alive, as he spoke, these forty-five years, from the time that the LORD spoke this word to Moses, while Israel walked in the wilderness. Now, behold, I am eighty-five years old, today.'),
  ('Joshua', 14, 11, 'As yet I am as strong today as I was in the day that Moses sent me. As my strength was then, even so is my strength now for war, to go out and to come in.'),
  ('Joshua', 14, 12, 'Now therefore give me this hill country, of which the LORD spoke in that day; for you heard in that day how the Anakim were there, and great and fortified cities. It may be that the LORD will be with me, and I shall drive them out, as the LORD said.”');
INSERT INTO bible_verses (book_name, chapter, verse, text) VALUES
  ('Joshua', 14, 13, 'Joshua blessed him; and he gave Hebron to Caleb the son of Jephunneh for an inheritance.'),
  ('Joshua', 14, 14, 'Therefore Hebron became the inheritance of Caleb the son of Jephunneh the Kenizzite to this day, because he followed the LORD, the God of Israel wholeheartedly.'),
  ('Joshua', 14, 15, 'Now the name of Hebron before was Kiriath Arba, after the greatest man among the Anakim. Then the land had rest from war.'),
  ('Joshua', 15, 1, 'The lot for the tribe of the children of Judah according to their families was to the border of Edom, even to the wilderness of Zin southward, at the uttermost part of the south.'),
  ('Joshua', 15, 2, 'Their south border was from the uttermost part of the Salt Sea, from the bay that looks southward;'),
  ('Joshua', 15, 3, 'and it went out southward of the ascent of Akrabbim, and passed along to Zin, and went up by the south of Kadesh Barnea, and passed along by Hezron, went up to Addar, and turned toward Karka;'),
  ('Joshua', 15, 4, 'and it passed along to Azmon, went out at the brook of Egypt; and the border ended at the sea. This shall be your south border.'),
  ('Joshua', 15, 5, 'The east border was the Salt Sea, even to the end of the Jordan. The border of the north quarter was from the bay of the sea at the end of the Jordan.'),
  ('Joshua', 15, 6, 'The border went up to Beth Hoglah, and passed along by the north of Beth Arabah; and the border went up to the stone of Bohan the son of Reuben.'),
  ('Joshua', 15, 7, 'The border went up to Debir from the valley of Achor, and so northward, looking toward Gilgal, that faces the ascent of Adummim, which is on the south side of the river. The border passed along to the waters of En Shemesh, and ended at En Rogel.'),
  ('Joshua', 15, 8, 'The border went up by the valley of the son of Hinnom to the side of the Jebusite (also called Jerusalem) southward; and the border went up to the top of the mountain that lies before the valley of Hinnom westward, which is at the farthest part of the valley of Rephaim northward.'),
  ('Joshua', 15, 9, 'The border extended from the top of the mountain to the spring of the waters of Nephtoah, and went out to the cities of Mount Ephron; and the border extended to Baalah (also called Kiriath Jearim);'),
  ('Joshua', 15, 10, 'and the border turned about from Baalah westward to Mount Seir, and passed along to the side of Mount Jearim (also called Chesalon) on the north, and went down to Beth Shemesh, and passed along by Timnah;'),
  ('Joshua', 15, 11, 'and the border went out to the side of Ekron northward; and the border extended to Shikkeron, and passed along to Mount Baalah, and went out at Jabneel; and the goings out of the border were at the sea.'),
  ('Joshua', 15, 12, 'The west border was to the shore of the great sea. This is the border of the children of Judah according to their families.'),
  ('Joshua', 15, 13, 'He gave to Caleb the son of Jephunneh a portion among the children of Judah, according to the commandment of the LORD to Joshua, even Kiriath Arba, named after the father of Anak (also called Hebron).'),
  ('Joshua', 15, 14, 'Caleb drove out the three sons of Anak: Sheshai, and Ahiman, and Talmai, the children of Anak.'),
  ('Joshua', 15, 15, 'He went up against the inhabitants of Debir: now the name of Debir before was Kiriath Sepher.'),
  ('Joshua', 15, 16, 'Caleb said, “He who strikes Kiriath Sepher, and takes it, to him I will give Achsah my daughter as wife.”'),
  ('Joshua', 15, 17, 'Othniel the son of Kenaz, the brother of Caleb, took it: and he gave him Achsah his daughter as wife.'),
  ('Joshua', 15, 18, 'When she came, she had him ask her father for a field. She got off her donkey, and Caleb said, “What do you want?”'),
  ('Joshua', 15, 19, 'She said, “Give me a blessing. Because you have set me in the land of the South, give me also springs of water.” So he gave her the upper springs and the lower springs.'),
  ('Joshua', 15, 20, 'This is the inheritance of the tribe of the children of Judah according to their families.'),
  ('Joshua', 15, 21, 'The farthest cities of the tribe of the children of Judah toward the border of Edom in the South were Kabzeel, Eder, Jagur,'),
  ('Joshua', 15, 22, 'Kinah, Dimonah, Adadah,'),
  ('Joshua', 15, 23, 'Kedesh, Hazor, Ithnan,'),
  ('Joshua', 15, 24, 'Ziph, Telem, Bealoth,'),
  ('Joshua', 15, 25, 'Hazor Hadattah, Kerioth Hezron (also called Hazor),'),
  ('Joshua', 15, 26, 'Amam, Shema, Moladah,'),
  ('Joshua', 15, 27, 'Hazar Gaddah, Heshmon, Beth Pelet,'),
  ('Joshua', 15, 28, 'Hazar Shual, Beersheba, Biziothiah,'),
  ('Joshua', 15, 29, 'Baalah, Iim, Ezem,'),
  ('Joshua', 15, 30, 'Eltolad, Chesil, Hormah,'),
  ('Joshua', 15, 31, 'Ziklag, Madmannah, Sansannah,'),
  ('Joshua', 15, 32, 'Lebaoth, Shilhim, Ain, and Rimmon. All the cities are twenty-nine, with their villages.'),
  ('Joshua', 15, 33, 'In the lowland, Eshtaol, Zorah, Ashnah,'),
  ('Joshua', 15, 34, 'Zanoah, En Gannim, Tappuah, Enam,'),
  ('Joshua', 15, 35, 'Jarmuth, Adullam, Socoh, Azekah,'),
  ('Joshua', 15, 36, 'Shaaraim, Adithaim and Gederah (or Gederothaim); fourteen cities with their villages.'),
  ('Joshua', 15, 37, 'Zenan, Hadashah, Migdal Gad,'),
  ('Joshua', 15, 38, 'Dilean, Mizpah, Joktheel,'),
  ('Joshua', 15, 39, 'Lachish, Bozkath, Eglon,'),
  ('Joshua', 15, 40, 'Cabbon, Lahmam, Chitlish,'),
  ('Joshua', 15, 41, 'Gederoth, Beth Dagon, Naamah, and Makkedah; sixteen cities with their villages.'),
  ('Joshua', 15, 42, 'Libnah, Ether, Ashan,'),
  ('Joshua', 15, 43, 'Iphtah, Ashnah, Nezib,'),
  ('Joshua', 15, 44, 'Keilah, Achzib, and Mareshah; nine cities with their villages.'),
  ('Joshua', 15, 45, 'Ekron, with its towns and its villages;'),
  ('Joshua', 15, 46, 'from Ekron even to the sea, all that were by the side of Ashdod, with their villages.'),
  ('Joshua', 15, 47, 'Ashdod, its towns and its villages; Gaza, its towns and its villages; to the brook of Egypt, and the great sea with its coastline.'),
  ('Joshua', 15, 48, 'In the hill country, Shamir, Jattir, Socoh,'),
  ('Joshua', 15, 49, 'Dannah, Kiriath Sannah (which is Debir),'),
  ('Joshua', 15, 50, 'Anab, Eshtemoh, Anim,'),
  ('Joshua', 15, 51, 'Goshen, Holon, and Giloh; eleven cities with their villages.'),
  ('Joshua', 15, 52, 'Arab, Dumah, Eshan,'),
  ('Joshua', 15, 53, 'Janim, Beth Tappuah, Aphekah,'),
  ('Joshua', 15, 54, 'Humtah, Kiriath Arba (also called Hebron), and Zior; nine cities with their villages.'),
  ('Joshua', 15, 55, 'Maon, Carmel, Ziph, Jutah,'),
  ('Joshua', 15, 56, 'Jezreel, Jokdeam, Zanoah,'),
  ('Joshua', 15, 57, 'Kain, Gibeah, and Timnah; ten cities with their villages.'),
  ('Joshua', 15, 58, 'Halhul, Beth Zur, Gedor,'),
  ('Joshua', 15, 59, 'Maarath, Beth Anoth, and Eltekon; six cities with their villages.'),
  ('Joshua', 15, 60, 'Kiriath Baal (also called Kiriath Jearim), and Rabbah; two cities with their villages.'),
  ('Joshua', 15, 61, 'In the wilderness, Beth Arabah, Middin, Secacah,'),
  ('Joshua', 15, 62, 'Nibshan, the City of Salt, and En Gedi; six cities with their villages.'),
  ('Joshua', 15, 63, 'As for the Jebusites, the inhabitants of Jerusalem, the children of Judah couldn’t drive them out; but the Jebusites live with the children of Judah at Jerusalem to this day.'),
  ('Joshua', 16, 1, 'The lot came out for the children of Joseph from the Jordan at Jericho, at the waters of Jericho on the east, even the wilderness, going up from Jericho through the hill country to Bethel.'),
  ('Joshua', 16, 2, 'It went out from Bethel to Luz, and passed along to the border of the Archites to Ataroth;'),
  ('Joshua', 16, 3, 'and it went down westward to the border of the Japhletites, to the border of Beth Horon the lower, and on to Gezer; and ended at the sea.'),
  ('Joshua', 16, 4, 'The children of Joseph, Manasseh and Ephraim, took their inheritance.'),
  ('Joshua', 16, 5, 'This was the border of the children of Ephraim according to their families. The border of their inheritance eastward was Ataroth Addar, to Beth Horon the upper.'),
  ('Joshua', 16, 6, 'The border went out westward at Michmethath on the north. The border turned about eastward to Taanath Shiloh, and passed along it on the east of Janoah.'),
  ('Joshua', 16, 7, 'It went down from Janoah to Ataroth, to Naarah, reached to Jericho, and went out at the Jordan.'),
  ('Joshua', 16, 8, 'From Tappuah the border went along westward to the brook of Kanah; and ended at the sea. This is the inheritance of the tribe of the children of Ephraim according to their families;'),
  ('Joshua', 16, 9, 'together with the cities which were set apart for the children of Ephraim in the middle of the inheritance of the children of Manasseh, all the cities with their villages.'),
  ('Joshua', 16, 10, 'They didn’t drive out the Canaanites who lived in Gezer; but the Canaanites dwell in the territory of Ephraim to this day, and have become servants to do forced labor.'),
  ('Joshua', 17, 1, 'This was the lot for the tribe of Manasseh, for he was the firstborn of Joseph. As for Machir the firstborn of Manasseh, the father of Gilead, because he was a man of war, therefore he had Gilead and Bashan.'),
  ('Joshua', 17, 2, 'So this was for the rest of the children of Manasseh according to their families: for the children of Abiezer, for the children of Helek, for the children of Asriel, for the children of Shechem, for the children of Hepher, and for the children of Shemida. These were the male children of Manasseh the son of Joseph according to their families.'),
  ('Joshua', 17, 3, 'But Zelophehad, the son of Hepher, the son of Gilead, the son of Machir, the son of Manasseh, had no sons, but daughters. These are the names of his daughters: Mahlah, Noah, Hoglah, Milcah, and Tirzah.'),
  ('Joshua', 17, 4, 'They came to Eleazar the priest, and to Joshua the son of Nun, and to the princes, saying, “The LORD commanded Moses to give us an inheritance among our brothers.” Therefore according to the commandment of the LORD he gave them an inheritance among the brothers of their father.'),
  ('Joshua', 17, 5, 'Ten parts fell to Manasseh, in addition to the land of Gilead and Bashan, which is beyond the Jordan;'),
  ('Joshua', 17, 6, 'because the daughters of Manasseh had an inheritance among his sons. The land of Gilead belonged to the rest of the sons of Manasseh.'),
  ('Joshua', 17, 7, 'The border of Manasseh was from Asher to Michmethath, which is before Shechem. The border went along to the right hand, to the inhabitants of En Tappuah.'),
  ('Joshua', 17, 8, 'The land of Tappuah belonged to Manasseh; but Tappuah on the border of Manasseh belonged to the children of Ephraim.'),
  ('Joshua', 17, 9, 'The border went down to the brook of Kanah, southward of the brook. These cities belonged to Ephraim among the cities of Manasseh. The border of Manasseh was on the north side of the brook, and ended at the sea.'),
  ('Joshua', 17, 10, 'Southward it was Ephraim’s, and northward it was Manasseh’s, and the sea was his border. They reached to Asher on the north, and to Issachar on the east.'),
  ('Joshua', 17, 11, 'Manasseh had three heights in Issachar, in Asher Beth Shean and its towns, and Ibleam and its towns, and the inhabitants of Dor and its towns, and the inhabitants of Endor and its towns, and the inhabitants of Taanach and its towns, and the inhabitants of Megiddo and its towns.'),
  ('Joshua', 17, 12, 'Yet the children of Manasseh couldn’t drive out the inhabitants of those cities; but the Canaanites would dwell in that land.'),
  ('Joshua', 17, 13, 'When the children of Israel had grown strong, they put the Canaanites to forced labor, and didn’t utterly drive them out.'),
  ('Joshua', 17, 14, 'The children of Joseph spoke to Joshua, saying, “Why have you given me just one lot and one part for an inheritance, since we are a numerous people, because the LORD has blessed us so far?”'),
  ('Joshua', 17, 15, 'Joshua said to them, “If you are a numerous people, go up to the forest, and clear land for yourself there in the land of the Perizzites and of the Rephaim, since the hill country of Ephraim is too narrow for you.”'),
  ('Joshua', 17, 16, 'The children of Joseph said, “The hill country is not enough for us. All the Canaanites who dwell in the land of the valley have chariots of iron, both those who are in Beth Shean and its towns, and those who are in the valley of Jezreel.”'),
  ('Joshua', 17, 17, 'Joshua spoke to the house of Joseph, that is, to Ephraim and to Manasseh, saying, “You are a numerous people, and have great power. You shall not have one lot only;'),
  ('Joshua', 17, 18, 'but the hill country shall be yours. Although it is a forest, you shall cut it down, and it’s farthest extent shall be yours; for you shall drive out the Canaanites, though they have chariots of iron, and though they are strong.”'),
  ('Joshua', 18, 1, 'The whole congregation of the children of Israel assembled themselves together at Shiloh, and set up the Tent of Meeting there. The land was subdued before them.'),
  ('Joshua', 18, 2, 'Seven tribes remained among the children of Israel, which had not yet divided their inheritance.'),
  ('Joshua', 18, 3, 'Joshua said to the children of Israel, “How long will you neglect to go in to possess the land, which the LORD, the God of your fathers, has given you?'),
  ('Joshua', 18, 4, 'Appoint for yourselves three men from each tribe. I will send them, and they shall arise, walk through the land, and describe it according to their inheritance; then they shall come to me.'),
  ('Joshua', 18, 5, 'They shall divide it into seven portions. Judah shall live in his borders on the south, and the house of Joseph shall live in their borders on the north.'),
  ('Joshua', 18, 6, 'You shall survey the land into seven parts, and bring the description here to me; and I will cast lots for you here before the LORD our God.');
INSERT INTO bible_verses (book_name, chapter, verse, text) VALUES
  ('Joshua', 18, 7, 'However, the Levites have no portion among you; for the priesthood of the LORD is their inheritance. Gad, Reuben, and the half-tribe of Manasseh have received their inheritance east of the Jordan, which Moses the servant of the LORD gave them.”'),
  ('Joshua', 18, 8, 'The men arose and went. Joshua commanded those who went to survey the land, saying, “Go walk through the land, survey it, and come again to me. I will cast lots for you here before the LORD in Shiloh.”'),
  ('Joshua', 18, 9, 'The men went and passed through the land, and surveyed it by cities into seven portions in a book. They came to Joshua to the camp at Shiloh.'),
  ('Joshua', 18, 10, 'Joshua cast lots for them in Shiloh before the LORD. There Joshua divided the land to the children of Israel according to their divisions.'),
  ('Joshua', 18, 11, 'The lot of the tribe of the children of Benjamin came up according to their families. The border of their lot went out between the children of Judah and the children of Joseph.'),
  ('Joshua', 18, 12, 'Their border on the north quarter was from the Jordan. The border went up to the side of Jericho on the north, and went up through the hill country westward. It ended at the wilderness of Beth Aven.'),
  ('Joshua', 18, 13, 'The border passed along from there to Luz, to the side of Luz (also called Bethel), southward. The border went down to Ataroth Addar, by the mountain that lies on the south of Beth Horon the lower.'),
  ('Joshua', 18, 14, 'The border extended, and turned around on the west quarter southward, from the mountain that lies before Beth Horon southward; and ended at Kiriath Baal (also called Kiriath Jearim), a city of the children of Judah. This was the west quarter.'),
  ('Joshua', 18, 15, 'The south quarter was from the farthest part of Kiriath Jearim. The border went out westward, and went out to the spring of the waters of Nephtoah.'),
  ('Joshua', 18, 16, 'The border went down to the farthest part of the mountain that lies before the valley of the son of Hinnom, which is in the valley of Rephaim northward. It went down to the valley of Hinnom, to the side of the Jebusite southward, and went down to En Rogel.'),
  ('Joshua', 18, 17, 'It extended northward, went out at En Shemesh, and went out to Geliloth, which is opposite the ascent of Adummim. It went down to the stone of Bohan the son of Reuben.'),
  ('Joshua', 18, 18, 'It passed along to the side opposite the Arabah northward, and went down to the Arabah.'),
  ('Joshua', 18, 19, 'The border passed along to the side of Beth Hoglah northward; and the border ended at the north bay of the Salt Sea, at the south end of the Jordan. This was the south border.'),
  ('Joshua', 18, 20, 'The Jordan was its border on the east quarter. This was the inheritance of the children of Benjamin, by the borders around it, according to their families.'),
  ('Joshua', 18, 21, 'Now the cities of the tribe of the children of Benjamin according to their families were Jericho, Beth Hoglah, Emek Keziz,'),
  ('Joshua', 18, 22, 'Beth Arabah, Zemaraim, Bethel,'),
  ('Joshua', 18, 23, 'Avvim, Parah, Ophrah,'),
  ('Joshua', 18, 24, 'Chephar Ammoni, Ophni, and Geba; twelve cities with their villages.'),
  ('Joshua', 18, 25, 'Gibeon, Ramah, Beeroth,'),
  ('Joshua', 18, 26, 'Mizpeh, Chephirah, Mozah,'),
  ('Joshua', 18, 27, 'Rekem, Irpeel, Taralah,'),
  ('Joshua', 18, 28, 'Zelah, Eleph, the Jebusite (also called Jerusalem), Gibeath, and Kiriath; fourteen cities with their villages. This is the inheritance of the children of Benjamin according to their families.'),
  ('Joshua', 19, 1, 'The second lot came out for Simeon, even for the tribe of the children of Simeon according to their families. Their inheritance was in the middle of the inheritance of the children of Judah.'),
  ('Joshua', 19, 2, 'They had for their inheritance Beersheba (or Sheba), Moladah,'),
  ('Joshua', 19, 3, 'Hazar Shual, Balah, Ezem,'),
  ('Joshua', 19, 4, 'Eltolad, Bethul, Hormah,'),
  ('Joshua', 19, 5, 'Ziklag, Beth Marcaboth, Hazar Susah,'),
  ('Joshua', 19, 6, 'Beth Lebaoth, and Sharuhen; thirteen cities with their villages;'),
  ('Joshua', 19, 7, 'Ain, Rimmon, Ether, and Ashan; four cities with their villages;'),
  ('Joshua', 19, 8, 'and all the villages that were around these cities to Baalath Beer, Ramah of the South. This is the inheritance of the tribe of the children of Simeon according to their families.'),
  ('Joshua', 19, 9, 'Out of the part of the children of Judah was the inheritance of the children of Simeon; for the portion of the children of Judah was too much for them. Therefore the children of Simeon had inheritance in the middle of their inheritance.'),
  ('Joshua', 19, 10, 'The third lot came up for the children of Zebulun according to their families. The border of their inheritance was to Sarid.'),
  ('Joshua', 19, 11, 'Their border went up westward, even to Maralah, and reached to Dabbesheth. It reached to the brook that is before Jokneam.'),
  ('Joshua', 19, 12, 'It turned from Sarid eastward toward the sunrise to the border of Chisloth Tabor. It went out to Daberath, and went up to Japhia.'),
  ('Joshua', 19, 13, 'From there it passed along eastward to Gath Hepher, to Ethkazin; and it went out at Rimmon which stretches to Neah.'),
  ('Joshua', 19, 14, 'The border turned around it on the north to Hannathon; and it ended at the valley of Iphtah El;'),
  ('Joshua', 19, 15, 'Kattath, Nahalal, Shimron, Idalah, and Bethlehem: twelve cities with their villages.'),
  ('Joshua', 19, 16, 'This is the inheritance of the children of Zebulun according to their families, these cities with their villages.'),
  ('Joshua', 19, 17, 'The fourth lot came out for Issachar, even for the children of Issachar according to their families.'),
  ('Joshua', 19, 18, 'Their border was to Jezreel, Chesulloth, Shunem,'),
  ('Joshua', 19, 19, 'Hapharaim, Shion, Anaharath,'),
  ('Joshua', 19, 20, 'Rabbith, Kishion, Ebez,'),
  ('Joshua', 19, 21, 'Remeth, Engannim, En Haddah, and Beth Pazzez.'),
  ('Joshua', 19, 22, 'The border reached to Tabor, Shahazumah, and Beth Shemesh. Their border ended at the Jordan: sixteen cities with their villages.'),
  ('Joshua', 19, 23, 'This is the inheritance of the tribe of the children of Issachar according to their families, the cities with their villages.'),
  ('Joshua', 19, 24, 'The fifth lot came out for the tribe of the children of Asher according to their families.'),
  ('Joshua', 19, 25, 'Their border was Helkath, Hali, Beten, Achshaph,'),
  ('Joshua', 19, 26, 'Allammelech, Amad, Mishal. It reached to Carmel westward, and to Shihorlibnath.'),
  ('Joshua', 19, 27, 'It turned toward the sunrise to Beth Dagon, and reached to Zebulun, and to the valley of Iphtah El northward to Beth Emek and Neiel. It went out to Cabul on the left hand,'),
  ('Joshua', 19, 28, 'and Ebron, Rehob, Hammon, and Kanah, even to great Sidon.'),
  ('Joshua', 19, 29, 'The border turned to Ramah, to the fortified city of Tyre; and the border turned to Hosah. It ended at the sea by the region of Achzib;'),
  ('Joshua', 19, 30, 'Ummah also, and Aphek, and Rehob: twenty-two cities with their villages.'),
  ('Joshua', 19, 31, 'This is the inheritance of the tribe of the children of Asher according to their families, these cities with their villages.'),
  ('Joshua', 19, 32, 'The sixth lot came out for the children of Naphtali, even for the children of Naphtali according to their families.'),
  ('Joshua', 19, 33, 'Their border was from Heleph, from the oak in Zaanannim, Adami-nekeb, and Jabneel, to Lakkum. It ended at the Jordan.'),
  ('Joshua', 19, 34, 'The border turned westward to Aznoth Tabor, and went out from there to Hukkok. It reached to Zebulun on the south, and reached to Asher on the west, and to Judah at the Jordan toward the sunrise.'),
  ('Joshua', 19, 35, 'The fortified cities were Ziddim, Zer, Hammath, Rakkath, Chinnereth,'),
  ('Joshua', 19, 36, 'Adamah, Ramah, Hazor,'),
  ('Joshua', 19, 37, 'Kedesh, Edrei, En Hazor,'),
  ('Joshua', 19, 38, 'Iron, Migdal El, Horem, Beth Anath, and Beth Shemesh; nineteen cities with their villages.'),
  ('Joshua', 19, 39, 'This is the inheritance of the tribe of the children of Naphtali according to their families, the cities with their villages.'),
  ('Joshua', 19, 40, 'The seventh lot came out for the tribe of the children of Dan according to their families.'),
  ('Joshua', 19, 41, 'The border of their inheritance was Zorah, Eshtaol, Irshemesh,'),
  ('Joshua', 19, 42, 'Shaalabbin, Aijalon, Ithlah,'),
  ('Joshua', 19, 43, 'Elon, Timnah, Ekron,'),
  ('Joshua', 19, 44, 'Eltekeh, Gibbethon, Baalath,'),
  ('Joshua', 19, 45, 'Jehud, Bene Berak, Gath Rimmon,'),
  ('Joshua', 19, 46, 'Me Jarkon, and Rakkon, with the border opposite Joppa.'),
  ('Joshua', 19, 47, 'The border of the children of Dan went out beyond them; for the children of Dan went up and fought against Leshem, and took it, and struck it with the edge of the sword, and possessed it, and lived therein, and called Leshem, Dan, after the name of Dan their forefather.'),
  ('Joshua', 19, 48, 'This is the inheritance of the tribe of the children of Dan according to their families, these cities with their villages.'),
  ('Joshua', 19, 49, 'So they finished distributing the land for inheritance by its borders. The children of Israel gave an inheritance to Joshua the son of Nun among them.'),
  ('Joshua', 19, 50, 'According to the LORD’s commandment, they gave him the city which he asked, even Timnathserah in the hill country of Ephraim; and he built the city, and lived there.'),
  ('Joshua', 19, 51, 'These are the inheritances, which Eleazar the priest, Joshua the son of Nun, and the heads of the fathers’ houses of the tribes of the children of Israel, distributed for inheritance by lot in Shiloh before the LORD, at the door of the Tent of Meeting. So they finished dividing the land.'),
  ('Joshua', 20, 1, 'The LORD spoke to Joshua, saying,'),
  ('Joshua', 20, 2, '“Speak to the children of Israel, saying, ‘Assign the cities of refuge, of which I spoke to you by Moses,'),
  ('Joshua', 20, 3, 'that the man slayer who kills any person accidentally or unintentionally may flee there. They shall be to you for a refuge from the avenger of blood.'),
  ('Joshua', 20, 4, 'He shall flee to one of those cities, and shall stand at the entrance of the gate of the city, and declare his case in the ears of the elders of that city. They shall take him into the city with them, and give him a place, that he may live among them.'),
  ('Joshua', 20, 5, 'If the avenger of blood pursues him, then they shall not deliver up the man slayer into his hand; because he struck his neighbor unintentionally, and didn’t hate him before.'),
  ('Joshua', 20, 6, 'He shall dwell in that city until he stands before the congregation for judgment, until the death of the high priest that shall be in those days. Then the man slayer shall return, and come to his own city, and to his own house, to the city he fled from.’”'),
  ('Joshua', 20, 7, 'They set apart Kedesh in Galilee in the hill country of Naphtali, Shechem in the hill country of Ephraim, and Kiriath Arba (also called Hebron) in the hill country of Judah.'),
  ('Joshua', 20, 8, 'Beyond the Jordan at Jericho eastward, they assigned Bezer in the wilderness in the plain out of the tribe of Reuben, Ramoth in Gilead out of the tribe of Gad, and Golan in Bashan out of the tribe of Manasseh.'),
  ('Joshua', 20, 9, 'These were the appointed cities for all the children of Israel, and for the alien who lives among them, that whoever kills any person unintentionally might flee there, and not die by the hand of the avenger of blood, until he stands trial before the congregation.'),
  ('Joshua', 21, 1, 'Then the heads of fathers’ houses of the Levites came near to Eleazar the priest, and to Joshua the son of Nun, and to the heads of fathers’ houses of the tribes of the children of Israel.'),
  ('Joshua', 21, 2, 'They spoke to them at Shiloh in the land of Canaan, saying, “The LORD commanded through Moses to give us cities to dwell in, with their pasture lands for our livestock.”'),
  ('Joshua', 21, 3, 'The children of Israel gave to the Levites out of their inheritance, according to the commandment of the LORD, these cities with their pasture lands.'),
  ('Joshua', 21, 4, 'The lot came out for the families of the Kohathites. The children of Aaron the priest, who were of the Levites, had thirteen cities by lot out of the tribe of Judah, out of the tribe of the Simeonites, and out of the tribe of Benjamin.'),
  ('Joshua', 21, 5, 'The rest of the children of Kohath had ten cities by lot out of the families of the tribe of Ephraim, out of the tribe of Dan, and out of the half-tribe of Manasseh.'),
  ('Joshua', 21, 6, 'The children of Gershon had thirteen cities by lot out of the families of the tribe of Issachar, out of the tribe of Asher, out of the tribe of Naphtali, and out of the half-tribe of Manasseh in Bashan.'),
  ('Joshua', 21, 7, 'The children of Merari according to their families had twelve cities out of the tribe of Reuben, out of the tribe of Gad, and out of the tribe of Zebulun.'),
  ('Joshua', 21, 8, 'The children of Israel gave these cities with their pasture lands by lot to the Levites, as the LORD commanded by Moses.'),
  ('Joshua', 21, 9, 'They gave out of the tribe of the children of Judah, and out of the tribe of the children of Simeon, these cities which are mentioned by name:'),
  ('Joshua', 21, 10, 'and they were for the children of Aaron, of the families of the Kohathites, who were of the children of Levi; for theirs was the first lot.'),
  ('Joshua', 21, 11, 'They gave them Kiriath Arba, named after the father of Anak (also called Hebron), in the hill country of Judah, with its pasture lands around it.'),
  ('Joshua', 21, 12, 'But they gave the fields of the city and its villages to Caleb the son of Jephunneh for his possession.'),
  ('Joshua', 21, 13, 'To the children of Aaron the priest they gave Hebron with its pasture lands, the city of refuge for the man slayer, Libnah with its pasture lands,'),
  ('Joshua', 21, 14, 'Jattir with its pasture lands, Eshtemoa with its pasture lands,'),
  ('Joshua', 21, 15, 'Holon with its pasture lands, Debir with its pasture lands,'),
  ('Joshua', 21, 16, 'Ain with its pasture lands, Juttah with its pasture lands, and Beth Shemesh with its pasture lands: nine cities out of those two tribes.'),
  ('Joshua', 21, 17, 'Out of the tribe of Benjamin, Gibeon with its pasture lands, Geba with its pasture lands,'),
  ('Joshua', 21, 18, 'Anathoth with its pasture lands, and Almon with its pasture lands: four cities.');
INSERT INTO bible_verses (book_name, chapter, verse, text) VALUES
  ('Joshua', 21, 19, 'All the cities of the children of Aaron, the priests, were thirteen cities with their pasture lands.'),
  ('Joshua', 21, 20, 'The families of the children of Kohath, the Levites, even the rest of the children of Kohath, had the cities of their lot out of the tribe of Ephraim.'),
  ('Joshua', 21, 21, 'They gave them Shechem with its pasture lands in the hill country of Ephraim, the city of refuge for the man slayer, and Gezer with its pasture lands,'),
  ('Joshua', 21, 22, 'Kibzaim with its pasture lands, and Beth Horon with its pasture lands: four cities.'),
  ('Joshua', 21, 23, 'Out of the tribe of Dan, Elteke with its pasture lands, Gibbethon with its pasture lands,'),
  ('Joshua', 21, 24, 'Aijalon with its pasture lands, Gath Rimmon with its pasture lands: four cities.'),
  ('Joshua', 21, 25, 'Out of the half-tribe of Manasseh, Taanach with its pasture lands, and Gath Rimmon with its pasture lands: two cities.'),
  ('Joshua', 21, 26, 'All the cities of the families of the rest of the children of Kohath were ten with their pasture lands.'),
  ('Joshua', 21, 27, 'They gave to the children of Gershon, of the families of the Levites, out of the half-tribe of Manasseh Golan in Bashan with its pasture lands, the city of refuge for the man slayer, and Be Eshterah with its pasture lands: two cities.'),
  ('Joshua', 21, 28, 'Out of the tribe of Issachar, Kishion with its pasture lands, Daberath with its pasture lands,'),
  ('Joshua', 21, 29, 'Jarmuth with its pasture lands, En Gannim with its pasture lands: four cities.'),
  ('Joshua', 21, 30, 'Out of the tribe of Asher, Mishal with its pasture lands, Abdon with its pasture lands,'),
  ('Joshua', 21, 31, 'Helkath with its pasture lands, and Rehob with its pasture lands: four cities.'),
  ('Joshua', 21, 32, 'Out of the tribe of Naphtali, Kedesh in Galilee with its pasture lands, the city of refuge for the man slayer, Hammothdor with its pasture lands, and Kartan with its pasture lands: three cities.'),
  ('Joshua', 21, 33, 'All the cities of the Gershonites according to their families were thirteen cities with their pasture lands.'),
  ('Joshua', 21, 34, 'To the families of the children of Merari, the rest of the Levites, out of the tribe of Zebulun, Jokneam with its pasture lands, Kartah with its pasture lands,'),
  ('Joshua', 21, 35, 'Dimnah with its pasture lands, and Nahalal with its pasture lands: four cities.'),
  ('Joshua', 21, 36, 'Out of the tribe of Reuben, Bezer with its pasture lands, Jahaz with its pasture lands,'),
  ('Joshua', 21, 37, 'Kedemoth with its pasture lands, and Mephaath with its pasture lands: four cities.'),
  ('Joshua', 21, 38, 'Out of the tribe of Gad, Ramoth in Gilead with its pasture lands, the city of refuge for the man slayer, and Mahanaim with its pasture lands,'),
  ('Joshua', 21, 39, 'Heshbon with its pasture lands, Jazer with its pasture lands: four cities in all.'),
  ('Joshua', 21, 40, 'All these were the cities of the children of Merari according to their families, even the rest of the families of the Levites. Their lot was twelve cities.'),
  ('Joshua', 21, 41, 'All the cities of the Levites among the possessions of the children of Israel were forty-eight cities with their pasture lands.'),
  ('Joshua', 21, 42, 'Each of these cities included their pasture lands around them. It was this way with all these cities.'),
  ('Joshua', 21, 43, 'So the LORD gave to Israel all the land which he swore to give to their fathers. They possessed it, and lived in it.'),
  ('Joshua', 21, 44, 'The LORD gave them rest all around, according to all that he swore to their fathers. Not a man of all their enemies stood before them. The LORD delivered all their enemies into their hand.'),
  ('Joshua', 21, 45, 'Nothing failed of any good thing which the LORD had spoken to the house of Israel. All came to pass.'),
  ('Joshua', 22, 1, 'Then Joshua called the Reubenites, the Gadites, and the half-tribe of Manasseh,'),
  ('Joshua', 22, 2, 'and said to them, “You have kept all that Moses the servant of the LORD commanded you, and have listened to my voice in all that I commanded you.'),
  ('Joshua', 22, 3, 'You have not left your brothers these many days to this day, but have performed the duty of the commandment of the LORD your God.'),
  ('Joshua', 22, 4, 'Now the LORD your God has given rest to your brothers, as he spoke to them. Therefore now return and go to your tents, to the land of your possession, which Moses the servant of the LORD gave you beyond the Jordan.'),
  ('Joshua', 22, 5, 'Only take diligent heed to do the commandment and the law which Moses the servant of the LORD commanded you, to love the LORD your God, to walk in all his ways, to keep his commandments, to hold fast to him, and to serve him with all your heart and with all your soul.”'),
  ('Joshua', 22, 6, 'So Joshua blessed them, and sent them away; and they went to their tents.'),
  ('Joshua', 22, 7, 'Now to the one half-tribe of Manasseh Moses had given inheritance in Bashan; but Joshua gave to the other half among their brothers beyond the Jordan westward. Moreover when Joshua sent them away to their tents, he blessed them,'),
  ('Joshua', 22, 8, 'and spoke to them, saying, “Return with much wealth to your tents, with very much livestock, with silver, with gold, with bronze, with iron, and with very much clothing. Divide the plunder of your enemies with your brothers.”'),
  ('Joshua', 22, 9, 'The children of Reuben and the children of Gad and the half-tribe of Manasseh returned, and departed from the children of Israel out of Shiloh, which is in the land of Canaan, to go to the land of Gilead, to the land of their possession, which they owned, according to the commandment of the LORD by Moses.'),
  ('Joshua', 22, 10, 'When they came to the region near the Jordan, that is in the land of Canaan, the children of Reuben and the children of Gad and the half-tribe of Manasseh built an altar there by the Jordan, a great altar to look at.'),
  ('Joshua', 22, 11, 'The children of Israel heard this, “Behold, the children of Reuben and the children of Gad and the half-tribe of Manasseh have built an altar along the border of the land of Canaan, in the region around the Jordan, on the side that belongs to the children of Israel.”'),
  ('Joshua', 22, 12, 'When the children of Israel heard of it, the whole congregation of the children of Israel gathered themselves together at Shiloh, to go up against them to war.'),
  ('Joshua', 22, 13, 'The children of Israel sent to the children of Reuben, and to the children of Gad, and to the half-tribe of Manasseh, into the land of Gilead, Phinehas the son of Eleazar the priest.'),
  ('Joshua', 22, 14, 'With him were ten princes, one prince of a fathers’ house for each of the tribes of Israel; and they were each head of their fathers’ houses among the thousands of Israel.'),
  ('Joshua', 22, 15, 'They came to the children of Reuben, and to the children of Gad, and to the half-tribe of Manasseh, to the land of Gilead, and they spoke with them, saying,'),
  ('Joshua', 22, 16, '“The whole congregation of the LORD says, ‘What trespass is this that you have committed against the God of Israel, to turn away today from following the LORD, in that you have built yourselves an altar, to rebel today against the LORD?'),
  ('Joshua', 22, 17, 'Is the iniquity of Peor too little for us, from which we have not cleansed ourselves to this day, although there came a plague on the congregation of the LORD,'),
  ('Joshua', 22, 18, 'that you must turn away today from following the LORD? It will be, since you rebel today against the LORD, that tomorrow he will be angry with the whole congregation of Israel.'),
  ('Joshua', 22, 19, 'However, if the land of your possession is unclean, then pass over to the land of the possession of the LORD, in which the LORD’s tabernacle dwells, and take possession among us; but don’t rebel against the LORD, nor rebel against us, in building an altar other than the LORD our God’s altar.'),
  ('Joshua', 22, 20, 'Didn’t Achan the son of Zerah commit a trespass in the devoted thing, and wrath fell on all the congregation of Israel? That man didn’t perish alone in his iniquity.’”'),
  ('Joshua', 22, 21, 'Then the children of Reuben and the children of Gad and the half-tribe of Manasseh answered, and spoke to the heads of the thousands of Israel,'),
  ('Joshua', 22, 22, '“The Mighty One, God, the LORD, the Mighty One, God, the LORD, he knows; and Israel shall know: if it was in rebellion, or if in trespass against the LORD (don’t save us today),'),
  ('Joshua', 22, 23, 'that we have built us an altar to turn away from following the LORD; or if to offer burnt offering or meal offering, or if to offer sacrifices of peace offerings, let the LORD himself require it.'),
  ('Joshua', 22, 24, '“If we have not out of concern done this, and for a reason, saying, ‘In time to come your children might speak to our children, saying, “What have you to do with the LORD, the God of Israel?'),
  ('Joshua', 22, 25, 'For the LORD has made the Jordan a border between us and you, you children of Reuben and children of Gad. You have no portion in the LORD.”’ So your children might make our children cease from fearing the LORD.'),
  ('Joshua', 22, 26, '“Therefore we said, ‘Let’s now prepare to build ourselves an altar, not for burnt offering, nor for sacrifice;'),
  ('Joshua', 22, 27, 'but it will be a witness between us and you, and between our generations after us, that we may perform the service of the LORD before him with our burnt offerings, with our sacrifices, and with our peace offerings;’ that your children may not tell our children in time to come, ‘You have no portion in the LORD.’'),
  ('Joshua', 22, 28, '“Therefore we said, ‘It shall be, when they tell us or our generations this in time to come, that we shall say, “Behold the pattern of the LORD’s altar, which our fathers made, not for burnt offering, nor for sacrifice; but it is a witness between us and you.”’'),
  ('Joshua', 22, 29, '“Far be it from us that we should rebel against the LORD, and turn away today from following the LORD, to build an altar for burnt offering, for meal offering, or for sacrifice, besides the LORD our God’s altar that is before his tabernacle!”'),
  ('Joshua', 22, 30, 'When Phinehas the priest, and the princes of the congregation, even the heads of the thousands of Israel that were with him, heard the words that the children of Reuben and the children of Gad and the children of Manasseh spoke, it pleased them well.'),
  ('Joshua', 22, 31, 'Phinehas the son of Eleazar the priest said to the children of Reuben, to the children of Gad, and to the children of Manasseh, “Today we know that the LORD is among us, because you have not committed this trespass against the LORD. Now you have delivered the children of Israel out of the LORD’s hand.”'),
  ('Joshua', 22, 32, 'Phinehas the son of Eleazar the priest, and the princes, returned from the children of Reuben, and from the children of Gad, out of the land of Gilead, to the land of Canaan, to the children of Israel, and brought them word again.'),
  ('Joshua', 22, 33, 'The thing pleased the children of Israel; and the children of Israel blessed God, and spoke no more of going up against them to war, to destroy the land in which the children of Reuben and the children of Gad lived.'),
  ('Joshua', 22, 34, 'The children of Reuben and the children of Gad named the altar “A Witness Between Us that the LORD is God.”'),
  ('Joshua', 23, 1, 'After many days, when the LORD had given rest to Israel from their enemies all around, and Joshua was old and well advanced in years,'),
  ('Joshua', 23, 2, 'Joshua called for all Israel, for their elders and for their heads, and for their judges and for their officers, and said to them, “I am old and well advanced in years.'),
  ('Joshua', 23, 3, 'You have seen all that the LORD your God has done to all these nations because of you; for it is the LORD your God who has fought for you.'),
  ('Joshua', 23, 4, 'Behold, I have allotted to you these nations that remain, to be an inheritance for your tribes, from the Jordan, with all the nations that I have cut off, even to the great sea toward the going down of the sun.'),
  ('Joshua', 23, 5, 'The LORD your God will thrust them out from before you, and drive them from out of your sight. You shall possess their land, as the LORD your God spoke to you.'),
  ('Joshua', 23, 6, '“Therefore be very courageous to keep and to do all that is written in the book of the law of Moses, that you not turn away from it to the right hand or to the left;'),
  ('Joshua', 23, 7, 'that you not come among these nations, these that remain among you; neither make mention of the name of their gods, nor cause to swear by them, neither serve them, nor bow down yourselves to them;'),
  ('Joshua', 23, 8, 'but hold fast to the LORD your God, as you have done to this day.'),
  ('Joshua', 23, 9, '“For the LORD has driven great and strong nations out from before you. But as for you, no man has stood before you to this day.'),
  ('Joshua', 23, 10, 'One man of you shall chase a thousand; for it is the LORD your God who fights for you, as he spoke to you.'),
  ('Joshua', 23, 11, 'Take good heed therefore to yourselves, that you love the LORD your God.'),
  ('Joshua', 23, 12, '“But if you do at all go back, and hold fast to the remnant of these nations, even these who remain among you, and make marriages with them, and go in to them, and they to you;'),
  ('Joshua', 23, 13, 'know for a certainty that the LORD your God will no longer drive these nations from out of your sight; but they shall be a snare and a trap to you, a scourge in your sides, and thorns in your eyes, until you perish from off this good land which the LORD your God has given you.'),
  ('Joshua', 23, 14, '“Behold, today I am going the way of all the earth. You know in all your hearts and in all your souls that not one thing has failed of all the good things which the LORD your God spoke concerning you. All have happened to you. Not one thing has failed of it.'),
  ('Joshua', 23, 15, 'It shall happen that as all the good things have come on you of which the LORD your God spoke to you, so the LORD will bring on you all the evil things, until he has destroyed you from off this good land which the LORD your God has given you,'),
  ('Joshua', 23, 16, 'when you disobey the covenant of the LORD your God, which he commanded you, and go and serve other gods, and bow down yourselves to them. Then the LORD’s anger will be kindled against you, and you will perish quickly from off the good land which he has given to you.”'),
  ('Joshua', 24, 1, 'Joshua gathered all the tribes of Israel to Shechem, and called for the elders of Israel, for their heads, for their judges, and for their officers; and they presented themselves before God.'),
  ('Joshua', 24, 2, 'Joshua said to all the people, “The LORD, the God of Israel, says, ‘Your fathers lived of old time beyond the River, even Terah, the father of Abraham, and the father of Nahor. They served other gods.'),
  ('Joshua', 24, 3, 'I took your father Abraham from beyond the River, and led him throughout all the land of Canaan, and multiplied his offspring, and gave him Isaac.'),
  ('Joshua', 24, 4, 'I gave to Isaac Jacob and Esau: and I gave to Esau Mount Seir, to possess it. Jacob and his children went down into Egypt.'),
  ('Joshua', 24, 5, '“‘I sent Moses and Aaron, and I plagued Egypt, according to that which I did among them: and afterward I brought you out.'),
  ('Joshua', 24, 6, 'I brought your fathers out of Egypt: and you came to the sea. The Egyptians pursued your fathers with chariots and with horsemen to the Red Sea.'),
  ('Joshua', 24, 7, 'When they cried out to the LORD, he put darkness between you and the Egyptians, and brought the sea on them, and covered them; and your eyes saw what I did in Egypt. You lived in the wilderness many days.'),
  ('Joshua', 24, 8, '“‘I brought you into the land of the Amorites, that lived beyond the Jordan. They fought with you, and I gave them into your hand. You possessed their land, and I destroyed them from before you.'),
  ('Joshua', 24, 9, 'Then Balak the son of Zippor, king of Moab, arose and fought against Israel. He sent and called Balaam the son of Beor to curse you,'),
  ('Joshua', 24, 10, 'but I would not listen to Balaam; therefore he blessed you still. So I delivered you out of his hand.'),
  ('Joshua', 24, 11, '“‘You went over the Jordan, and came to Jericho. The men of Jericho fought against you, the Amorite, the Perizzite, the Canaanite, the Hittite, the Girgashite, the Hivite, and the Jebusite; and I delivered them into your hand.'),
  ('Joshua', 24, 12, 'I sent the hornet before you, which drove them out from before you, even the two kings of the Amorites; not with your sword, nor with your bow.'),
  ('Joshua', 24, 13, 'I gave you a land on which you had not labored, and cities which you didn’t build, and you live in them. You eat of vineyards and olive groves which you didn’t plant.’'),
  ('Joshua', 24, 14, '“Now therefore fear the LORD, and serve him in sincerity and in truth. Put away the gods which your fathers served beyond the River, in Egypt; and serve the LORD.'),
  ('Joshua', 24, 15, 'If it seems evil to you to serve the LORD, choose today whom you will serve; whether the gods which your fathers served that were beyond the River, or the gods of the Amorites, in whose land you dwell; but as for me and my house, we will serve the LORD.”'),
  ('Joshua', 24, 16, 'The people answered, “Far be it from us that we should forsake the LORD, to serve other gods;'),
  ('Joshua', 24, 17, 'for it is the LORD our God who brought us and our fathers up out of the land of Egypt, from the house of bondage, and who did those great signs in our sight, and preserved us in all the way in which we went, and among all the peoples through the middle of whom we passed.'),
  ('Joshua', 24, 18, 'The LORD drove out from before us all the peoples, even the Amorites who lived in the land. Therefore we also will serve the LORD; for he is our God.”'),
  ('Joshua', 24, 19, 'Joshua said to the people, “You can’t serve the LORD, for he is a holy God. He is a jealous God. He will not forgive your disobedience nor your sins.'),
  ('Joshua', 24, 20, 'If you forsake the LORD, and serve foreign gods, then he will turn and do you evil, and consume you, after he has done you good.”'),
  ('Joshua', 24, 21, 'The people said to Joshua, “No, but we will serve the LORD.”'),
  ('Joshua', 24, 22, 'Joshua said to the people, “You are witnesses against yourselves that you have chosen the LORD yourselves, to serve him.” They said, “We are witnesses.”'),
  ('Joshua', 24, 23, '“Now therefore put away the foreign gods which are among you, and incline your heart to the LORD, the God of Israel.”');
INSERT INTO bible_verses (book_name, chapter, verse, text) VALUES
  ('Joshua', 24, 24, 'The people said to Joshua, “We will serve the LORD our God, and we will listen to his voice.”'),
  ('Joshua', 24, 25, 'So Joshua made a covenant with the people that day, and made for them a statute and an ordinance in Shechem.'),
  ('Joshua', 24, 26, 'Joshua wrote these words in the book of the law of God; and he took a great stone, and set it up there under the oak that was by the sanctuary of the LORD.'),
  ('Joshua', 24, 27, 'Joshua said to all the people, “Behold, this stone shall be a witness against us, for it has heard all the LORD’s words which he spoke to us. It shall be therefore a witness against you, lest you deny your God.”'),
  ('Joshua', 24, 28, 'So Joshua sent the people away, each to his own inheritance.'),
  ('Joshua', 24, 29, 'After these things, Joshua the son of Nun, the servant of the LORD, died, being one hundred ten years old.'),
  ('Joshua', 24, 30, 'They buried him in the border of his inheritance in Timnathserah, which is in the hill country of Ephraim, on the north of the mountain of Gaash.'),
  ('Joshua', 24, 31, 'Israel served the LORD all the days of Joshua, and all the days of the elders who outlived Joshua, and had known all the work of the LORD, that he had worked for Israel.'),
  ('Joshua', 24, 32, 'They buried the bones of Joseph, which the children of Israel brought up out of Egypt, in Shechem, in the parcel of ground which Jacob bought from the sons of Hamor the father of Shechem for a hundred pieces of silver. They became the inheritance of the children of Joseph.'),
  ('Joshua', 24, 33, 'Eleazar the son of Aaron died. They buried him in the hill of Phinehas his son, which was given him in the hill country of Ephraim.'),
  ('Judges', 1, 1, 'After the death of Joshua, the children of Israel asked of the LORD, saying, “Who should go up for us first against the Canaanites, to fight against them?”'),
  ('Judges', 1, 2, 'The LORD said, “Judah shall go up. Behold, I have delivered the land into his hand.”'),
  ('Judges', 1, 3, 'Judah said to Simeon his brother, “Come up with me into my lot, that we may fight against the Canaanites; and I likewise will go with you into your lot.” So Simeon went with him.'),
  ('Judges', 1, 4, 'Judah went up, and the LORD delivered the Canaanites and the Perizzites into their hand. They struck ten thousand men in Bezek.'),
  ('Judges', 1, 5, 'They found Adoni-Bezek in Bezek, and they fought against him. They struck the Canaanites and the Perizzites.'),
  ('Judges', 1, 6, 'But Adoni-Bezek fled. They pursued him, caught him, and cut off his thumbs and his big toes.'),
  ('Judges', 1, 7, 'Adoni-Bezek said, “Seventy kings, having their thumbs and their big toes cut off, scavenged under my table. As I have done, so God has done to me.” They brought him to Jerusalem, and he died there.'),
  ('Judges', 1, 8, 'The children of Judah fought against Jerusalem, took it, struck it with the edge of the sword, and set the city on fire.'),
  ('Judges', 1, 9, 'After that, the children of Judah went down to fight against the Canaanites who lived in the hill country, and in the South, and in the lowland.'),
  ('Judges', 1, 10, 'Judah went against the Canaanites who lived in Hebron. (The name of Hebron before that was Kiriath Arba.) They struck Sheshai, Ahiman, and Talmai.'),
  ('Judges', 1, 11, 'From there he went against the inhabitants of Debir. (The name of Debir before that was Kiriath Sepher.)'),
  ('Judges', 1, 12, 'Caleb said, “I will give Achsah my daughter as wife to the man who strikes Kiriath Sepher, and takes it.”'),
  ('Judges', 1, 13, 'Othniel the son of Kenaz, Caleb’s younger brother, took it, so he gave him Achsah his daughter as his wife.'),
  ('Judges', 1, 14, 'When she came, she got him to ask her father for a field. She got off her donkey; and Caleb said to her, “What would you like?”'),
  ('Judges', 1, 15, 'She said to him, “Give me a blessing; because you have set me in the land of the South, give me also springs of water.” Then Caleb gave her the upper springs and the lower springs.'),
  ('Judges', 1, 16, 'The children of the Kenite, Moses’ brother-in-law, went up out of the city of palm trees with the children of Judah into the wilderness of Judah, which is in the south of Arad; and they went and lived with the people.'),
  ('Judges', 1, 17, 'Judah went with Simeon his brother, and they struck the Canaanites who inhabited Zephath, and utterly destroyed it. The name of the city was called Hormah.'),
  ('Judges', 1, 18, 'Also Judah took Gaza with its border, and Ashkelon with its border, and Ekron with its border.'),
  ('Judges', 1, 19, 'The LORD was with Judah, and drove out the inhabitants of the hill country; for he could not drive out the inhabitants of the valley, because they had chariots of iron.'),
  ('Judges', 1, 20, 'They gave Hebron to Caleb, as Moses had said, and he drove the three sons of Anak out of there.'),
  ('Judges', 1, 21, 'The children of Benjamin didn’t drive out the Jebusites who inhabited Jerusalem, but the Jebusites dwell with the children of Benjamin in Jerusalem to this day.'),
  ('Judges', 1, 22, 'The house of Joseph also went up against Bethel, and the LORD was with them.'),
  ('Judges', 1, 23, 'The house of Joseph sent to spy out Bethel. (The name of the city before that was Luz.)'),
  ('Judges', 1, 24, 'The watchers saw a man come out of the city, and they said to him, “Please show us the entrance into the city, and we will deal kindly with you.”'),
  ('Judges', 1, 25, 'He showed them the entrance into the city, and they struck the city with the edge of the sword; but they let the man and all his family go.'),
  ('Judges', 1, 26, 'The man went into the land of the Hittites, built a city, and called its name Luz, which is its name to this day.'),
  ('Judges', 1, 27, 'Manasseh didn’t drive out the inhabitants of Beth Shean and its towns, nor Taanach and its towns, nor the inhabitants of Dor and its towns, nor the inhabitants of Ibleam and its towns, nor the inhabitants of Megiddo and its towns; but the Canaanites would dwell in that land.'),
  ('Judges', 1, 28, 'When Israel had grown strong, they put the Canaanites to forced labor, and didn’t utterly drive them out.'),
  ('Judges', 1, 29, 'Ephraim didn’t drive out the Canaanites who lived in Gezer, but the Canaanites lived in Gezer among them.'),
  ('Judges', 1, 30, 'Zebulun didn’t drive out the inhabitants of Kitron, nor the inhabitants of Nahalol; but the Canaanites lived among them, and became subject to forced labor.'),
  ('Judges', 1, 31, 'Asher didn’t drive out the inhabitants of Acco, nor the inhabitants of Sidon, nor of Ahlab, nor of Achzib, nor of Helbah, nor of Aphik, nor of Rehob;'),
  ('Judges', 1, 32, 'but the Asherites lived among the Canaanites, the inhabitants of the land, for they didn’t drive them out.'),
  ('Judges', 1, 33, 'Naphtali didn’t drive out the inhabitants of Beth Shemesh, nor the inhabitants of Beth Anath; but he lived among the Canaanites, the inhabitants of the land. Nevertheless the inhabitants of Beth Shemesh and of Beth Anath became subject to forced labor.'),
  ('Judges', 1, 34, 'The Amorites forced the children of Dan into the hill country, for they would not allow them to come down to the valley;'),
  ('Judges', 1, 35, 'but the Amorites would dwell in Mount Heres, in Aijalon, and in Shaalbim. Yet the hand of the house of Joseph prevailed, so that they became subject to forced labor.'),
  ('Judges', 1, 36, 'The border of the Amorites was from the ascent of Akrabbim, from the rock, and upward.'),
  ('Judges', 2, 1, 'The LORD’s angel came up from Gilgal to Bochim. He said, “I brought you out of Egypt, and have brought you to the land which I swore to give your fathers. I said, ‘I will never break my covenant with you.'),
  ('Judges', 2, 2, 'You shall make no covenant with the inhabitants of this land. You shall break down their altars.’ But you have not listened to my voice. Why have you done this?'),
  ('Judges', 2, 3, 'Therefore I also said, ‘I will not drive them out from before you; but they shall be in your sides, and their gods will be a snare to you.’”'),
  ('Judges', 2, 4, 'When the LORD’s angel spoke these words to all the children of Israel, the people lifted up their voice and wept.'),
  ('Judges', 2, 5, 'They called the name of that place Bochim, and they sacrificed there to the LORD.'),
  ('Judges', 2, 6, 'Now when Joshua had sent the people away, the children of Israel each went to his inheritance to possess the land.'),
  ('Judges', 2, 7, 'The people served the LORD all the days of Joshua, and all the days of the elders who outlived Joshua, who had seen all the great work of the LORD that he had worked for Israel.'),
  ('Judges', 2, 8, 'Joshua the son of Nun, the servant of the LORD, died, being one hundred ten years old.'),
  ('Judges', 2, 9, 'They buried him in the border of his inheritance in Timnath Heres, in the hill country of Ephraim, on the north of the mountain of Gaash.'),
  ('Judges', 2, 10, 'After all that generation were gathered to their fathers, another generation arose after them who didn’t know the LORD, nor the work which he had done for Israel.'),
  ('Judges', 2, 11, 'The children of Israel did that which was evil in the LORD’s sight, and served the Baals.'),
  ('Judges', 2, 12, 'They abandoned the LORD, the God of their fathers, who brought them out of the land of Egypt, and followed other gods, of the gods of the peoples who were around them, and bowed themselves down to them; and they provoked the LORD to anger.'),
  ('Judges', 2, 13, 'They abandoned the LORD, and served Baal and the Ashtaroth.'),
  ('Judges', 2, 14, 'The LORD’s anger burned against Israel, and he delivered them into the hands of raiders who plundered them. He sold them into the hands of their enemies all around, so that they could no longer stand before their enemies.'),
  ('Judges', 2, 15, 'Wherever they went out, the LORD’s hand was against them for evil, as the LORD had spoken, and as the LORD had sworn to them; and they were very distressed.'),
  ('Judges', 2, 16, 'The LORD raised up judges, who saved them out of the hand of those who plundered them.'),
  ('Judges', 2, 17, 'Yet they didn’t listen to their judges; for they prostituted themselves to other gods, and bowed themselves down to them. They quickly turned away from the way in which their fathers walked, obeying the LORD’s commandments. They didn’t do so.'),
  ('Judges', 2, 18, 'When the LORD raised up judges for them, then the LORD was with the judge, and saved them out of the hand of their enemies all the days of the judge; for it grieved the LORD because of their groaning by reason of those who oppressed them and troubled them.'),
  ('Judges', 2, 19, 'But when the judge was dead, they turned back, and dealt more corruptly than their fathers in following other gods to serve them and to bow down to them. They didn’t cease what they were doing, or give up their stubborn ways.'),
  ('Judges', 2, 20, 'The LORD’s anger burned against Israel; and he said, “Because this nation transgressed my covenant which I commanded their fathers, and has not listened to my voice,'),
  ('Judges', 2, 21, 'I also will no longer drive out any of the nations that Joshua left when he died from before them;'),
  ('Judges', 2, 22, 'that by them I may test Israel, to see if they will keep the LORD’s way to walk therein, as their fathers kept it, or not.”'),
  ('Judges', 2, 23, 'So the LORD left those nations, without driving them out hastily. He didn’t deliver them into Joshua’s hand.'),
  ('Judges', 3, 1, 'Now these are the nations which the LORD left, to test Israel by them, even as many as had not known all the wars of Canaan;'),
  ('Judges', 3, 2, 'only that the generations of the children of Israel might know, to teach them war, at least those who knew nothing of it before:'),
  ('Judges', 3, 3, 'the five lords of the Philistines, all the Canaanites, the Sidonians, and the Hivites who lived on Mount Lebanon, from Mount Baal Hermon to the entrance of Hamath.'),
  ('Judges', 3, 4, 'They were left to test Israel by them, to know whether they would listen to the LORD’s commandments, which he commanded their fathers by Moses.'),
  ('Judges', 3, 5, 'The children of Israel lived among the Canaanites, the Hittites, the Amorites, the Perizzites, the Hivites, and the Jebusites.'),
  ('Judges', 3, 6, 'They took their daughters to be their wives, and gave their own daughters to their sons and served their gods.'),
  ('Judges', 3, 7, 'The children of Israel did that which was evil in the LORD’s sight, and forgot the LORD their God, and served the Baals and the Asheroth.'),
  ('Judges', 3, 8, 'Therefore the LORD’s anger burned against Israel, and he sold them into the hand of Cushan Rishathaim king of Mesopotamia; and the children of Israel served Cushan Rishathaim eight years.'),
  ('Judges', 3, 9, 'When the children of Israel cried to the LORD, the LORD raised up a savior to the children of Israel, who saved them, even Othniel the son of Kenaz, Caleb’s younger brother.'),
  ('Judges', 3, 10, 'The LORD’s Spirit came on him, and he judged Israel; and he went out to war, and the LORD delivered Cushan Rishathaim king of Mesopotamia into his hand. His hand prevailed against Cushan Rishathaim.'),
  ('Judges', 3, 11, 'The land had rest forty years, then Othniel the son of Kenaz died.'),
  ('Judges', 3, 12, 'The children of Israel again did that which was evil in the LORD’s sight, and the LORD strengthened Eglon the king of Moab against Israel, because they had done that which was evil in the LORD’s sight.'),
  ('Judges', 3, 13, 'He gathered the children of Ammon and Amalek to himself; and he went and struck Israel, and they possessed the city of palm trees.'),
  ('Judges', 3, 14, 'The children of Israel served Eglon the king of Moab eighteen years.'),
  ('Judges', 3, 15, 'But when the children of Israel cried to the LORD, the LORD raised up a savior for them: Ehud the son of Gera, the Benjamite, a left-handed man. The children of Israel sent tribute by him to Eglon the king of Moab.'),
  ('Judges', 3, 16, 'Ehud made himself a sword which had two edges, a cubit in length; and he wore it under his clothing on his right thigh.'),
  ('Judges', 3, 17, 'He offered the tribute to Eglon king of Moab. Now Eglon was a very fat man.'),
  ('Judges', 3, 18, 'When Ehud had finished offering the tribute, he sent away the people who carried the tribute.'),
  ('Judges', 3, 19, 'But he himself turned back from the stone idols that were by Gilgal, and said, “I have a secret message for you, O king.” The king said, “Keep silence!” All who stood by him left him.'),
  ('Judges', 3, 20, 'Ehud came to him; and he was sitting by himself alone in the cool upper room. Ehud said, “I have a message from God to you.” He arose out of his seat.'),
  ('Judges', 3, 21, 'Ehud put out his left hand, and took the sword from his right thigh, and thrust it into his body.'),
  ('Judges', 3, 22, 'The handle also went in after the blade; and the fat closed on the blade, for he didn’t draw the sword out of his body; and it came out behind.'),
  ('Judges', 3, 23, 'Then Ehud went out onto the porch, and shut the doors of the upper room on him, and locked them.'),
  ('Judges', 3, 24, 'After he had gone, his servants came and saw that the doors of the upper room were locked. They said, “Surely he is covering his feet in the upper room.”'),
  ('Judges', 3, 25, 'They waited until they were ashamed; and behold, he didn’t open the doors of the upper room. Therefore they took the key and opened them, and behold, their lord had fallen down dead on the floor.'),
  ('Judges', 3, 26, 'Ehud escaped while they waited, passed beyond the stone idols, and escaped to Seirah.'),
  ('Judges', 3, 27, 'When he had come, he blew a trumpet in the hill country of Ephraim; and the children of Israel went down with him from the hill country, and he led them.'),
  ('Judges', 3, 28, 'He said to them, “Follow me; for the LORD has delivered your enemies the Moabites into your hand.” They followed him, and took the fords of the Jordan against the Moabites, and didn’t allow any man to pass over.'),
  ('Judges', 3, 29, 'They struck at that time about ten thousand men of Moab, every strong man and every man of valor. No man escaped.'),
  ('Judges', 3, 30, 'So Moab was subdued that day under the hand of Israel. Then the land had rest eighty years.'),
  ('Judges', 3, 31, 'After him was Shamgar the son of Anath, who struck six hundred men of the Philistines with an ox goad. He also saved Israel.');
INSERT INTO bible_verses (book_name, chapter, verse, text) VALUES
  ('Judges', 4, 1, 'The children of Israel again did that which was evil in the LORD’s sight, when Ehud was dead.'),
  ('Judges', 4, 2, 'The LORD sold them into the hand of Jabin king of Canaan, who reigned in Hazor; the captain of whose army was Sisera, who lived in Harosheth of the Gentiles.'),
  ('Judges', 4, 3, 'The children of Israel cried to the LORD, for he had nine hundred chariots of iron; and he mightily oppressed the children of Israel for twenty years.'),
  ('Judges', 4, 4, 'Now Deborah, a prophetess, the wife of Lappidoth, judged Israel at that time.'),
  ('Judges', 4, 5, 'She lived under Deborah’s palm tree between Ramah and Bethel in the hill country of Ephraim; and the children of Israel came up to her for judgment.'),
  ('Judges', 4, 6, 'She sent and called Barak the son of Abinoam out of Kedesh Naphtali, and said to him, “Hasn’t the LORD, the God of Israel, commanded, ‘Go and lead the way to Mount Tabor, and take with you ten thousand men of the children of Naphtali and of the children of Zebulun?'),
  ('Judges', 4, 7, 'I will draw to you, to the river Kishon, Sisera, the captain of Jabin’s army, with his chariots and his multitude; and I will deliver him into your hand.’”'),
  ('Judges', 4, 8, 'Barak said to her, “If you will go with me, then I will go; but if you will not go with me, I will not go.”'),
  ('Judges', 4, 9, 'She said, “I will surely go with you. Nevertheless, the journey that you take won’t be for your honor; for the LORD will sell Sisera into a woman’s hand.” Deborah arose, and went with Barak to Kedesh.'),
  ('Judges', 4, 10, 'Barak called Zebulun and Naphtali together to Kedesh. Ten thousand men followed him; and Deborah went up with him.'),
  ('Judges', 4, 11, 'Now Heber the Kenite had separated himself from the Kenites, even from the children of Hobab, Moses’ brother-in-law, and had pitched his tent as far as the oak in Zaanannim, which is by Kedesh.'),
  ('Judges', 4, 12, 'They told Sisera that Barak the son of Abinoam had gone up to Mount Tabor.'),
  ('Judges', 4, 13, 'Sisera gathered together all his chariots, even nine hundred chariots of iron, and all the people who were with him, from Harosheth of the Gentiles, to the river Kishon.'),
  ('Judges', 4, 14, 'Deborah said to Barak, “Go; for this is the day in which the LORD has delivered Sisera into your hand. Hasn’t the LORD gone out before you?” So Barak went down from Mount Tabor, and ten thousand men after him.'),
  ('Judges', 4, 15, 'The LORD confused Sisera, all his chariots, and all his army, with the edge of the sword before Barak. Sisera abandoned his chariot and fled away on his feet.'),
  ('Judges', 4, 16, 'But Barak pursued the chariots and the army to Harosheth of the Gentiles; and all the army of Sisera fell by the edge of the sword. There was not a man left.'),
  ('Judges', 4, 17, 'However Sisera fled away on his feet to the tent of Jael the wife of Heber the Kenite; for there was peace between Jabin the king of Hazor and the house of Heber the Kenite.'),
  ('Judges', 4, 18, 'Jael went out to meet Sisera, and said to him, “Turn in, my lord, turn in to me; don’t be afraid.” He came in to her into the tent, and she covered him with a rug.'),
  ('Judges', 4, 19, 'He said to her, “Please give me a little water to drink; for I am thirsty.” She opened a container of milk, and gave him a drink, and covered him.'),
  ('Judges', 4, 20, 'He said to her, “Stand in the door of the tent, and if any man comes and inquires of you, and says, ‘Is there any man here?’ you shall say, ‘No.’”'),
  ('Judges', 4, 21, 'Then Jael, Heber’s wife, took a tent peg, and took a hammer in her hand, and went softly to him, and struck the pin into his temples, and it pierced through into the ground, for he was in a deep sleep; so he fainted and died.'),
  ('Judges', 4, 22, 'Behold, as Barak pursued Sisera, Jael came out to meet him, and said to him, “Come, and I will show you the man whom you seek.” He came to her; and behold, Sisera lay dead, and the tent peg was in his temples.'),
  ('Judges', 4, 23, 'So God subdued Jabin the king of Canaan before the children of Israel on that day.'),
  ('Judges', 4, 24, 'The hand of the children of Israel prevailed more and more against Jabin the king of Canaan, until they had destroyed Jabin king of Canaan.'),
  ('Judges', 5, 1, 'Then Deborah and Barak the son of Abinoam sang on that day, saying,'),
  ('Judges', 5, 2, '“Because the leaders took the lead in Israel, because the people offered themselves willingly, be blessed, LORD!'),
  ('Judges', 5, 3, '“Hear, you kings! Give ear, you princes! I, even I, will sing to the LORD. I will sing praise to the LORD, the God of Israel.'),
  ('Judges', 5, 4, '“LORD, when you went out of Seir, when you marched out of the field of Edom, the earth trembled, the sky also dropped. Yes, the clouds dropped water.'),
  ('Judges', 5, 5, 'The mountains quaked at the LORD’s presence, even Sinai at the presence of the LORD, the God of Israel.'),
  ('Judges', 5, 6, '“In the days of Shamgar the son of Anath, in the days of Jael, the highways were unoccupied. The travelers walked through byways.'),
  ('Judges', 5, 7, 'The rulers ceased in Israel. They ceased until I, Deborah, arose; Until I arose a mother in Israel.'),
  ('Judges', 5, 8, 'They chose new gods. Then war was in the gates. Was there a shield or spear seen among forty thousand in Israel?'),
  ('Judges', 5, 9, 'My heart is toward the governors of Israel, who offered themselves willingly among the people. Bless the LORD!'),
  ('Judges', 5, 10, '“Speak, you who ride on white donkeys, you who sit on rich carpets, and you who walk by the way.'),
  ('Judges', 5, 11, 'Far from the noise of archers, in the places of drawing water, there they will rehearse the LORD’s righteous acts, the righteous acts of his rule in Israel. “Then the LORD’s people went down to the gates.'),
  ('Judges', 5, 12, '‘Awake, awake, Deborah! Awake, awake, utter a song! Arise, Barak, and lead away your captives, you son of Abinoam.’'),
  ('Judges', 5, 13, '“Then a remnant of the nobles and the people came down. The LORD came down for me against the mighty.'),
  ('Judges', 5, 14, 'Those whose root is in Amalek came out of Ephraim, after you, Benjamin, among your peoples. Governors come down out of Machir. Those who handle the marshal’s staff came out of Zebulun.'),
  ('Judges', 5, 15, 'The princes of Issachar were with Deborah. As was Issachar, so was Barak. They rushed into the valley at his feet. By the watercourses of Reuben, there were great resolves of heart.'),
  ('Judges', 5, 16, 'Why did you sit among the sheepfolds? To hear the whistling for the flocks? At the watercourses of Reuben, there were great searchings of heart.'),
  ('Judges', 5, 17, 'Gilead lived beyond the Jordan. Why did Dan remain in ships? Asher sat still at the haven of the sea, and lived by his creeks.'),
  ('Judges', 5, 18, 'Zebulun was a people that jeopardized their lives to the death; Naphtali also, on the high places of the field.'),
  ('Judges', 5, 19, '“The kings came and fought, then the kings of Canaan fought at Taanach by the waters of Megiddo. They took no plunder of silver.'),
  ('Judges', 5, 20, 'From the sky the stars fought. From their courses, they fought against Sisera.'),
  ('Judges', 5, 21, 'The river Kishon swept them away, that ancient river, the river Kishon. My soul, march on with strength.'),
  ('Judges', 5, 22, 'Then the horse hoofs stamped because of the prancing, the prancing of their strong ones.'),
  ('Judges', 5, 23, '‘Curse Meroz,’ said the LORD’s angel. ‘Curse bitterly its inhabitants, because they didn’t come to help the LORD, to help the LORD against the mighty.’'),
  ('Judges', 5, 24, '“Jael shall be blessed above women, the wife of Heber the Kenite; blessed shall she be above women in the tent.'),
  ('Judges', 5, 25, 'He asked for water. She gave him milk. She brought him butter in a lordly dish.'),
  ('Judges', 5, 26, 'She put her hand to the tent peg, and her right hand to the workmen’s hammer. With the hammer she struck Sisera. She struck through his head. Yes, she pierced and struck through his temples.'),
  ('Judges', 5, 27, 'At her feet he bowed, he fell, he lay. At her feet he bowed, he fell. Where he bowed, there he fell down dead.'),
  ('Judges', 5, 28, '“Through the window she looked out, and cried: Sisera’s mother looked through the lattice. ‘Why is his chariot so long in coming? Why do the wheels of his chariots wait?’'),
  ('Judges', 5, 29, 'Her wise ladies answered her, Yes, she returned answer to herself,'),
  ('Judges', 5, 30, '‘Have they not found, have they not divided the plunder? A lady, two ladies to every man; to Sisera a plunder of dyed garments, a plunder of dyed garments embroidered, of dyed garments embroidered on both sides, on the necks of the plunder?’'),
  ('Judges', 5, 31, '“So let all your enemies perish, LORD, but let those who love him be as the sun when it rises in its strength.” Then the land had rest forty years.'),
  ('Judges', 6, 1, 'The children of Israel did that which was evil in the LORD’s sight, so the LORD delivered them into the hand of Midian seven years.'),
  ('Judges', 6, 2, 'The hand of Midian prevailed against Israel; and because of Midian the children of Israel made themselves the dens which are in the mountains, the caves, and the strongholds.'),
  ('Judges', 6, 3, 'So it was, when Israel had sown, that the Midianites, the Amalekites, and the children of the east came up against them.'),
  ('Judges', 6, 4, 'They encamped against them, and destroyed the increase of the earth, until you come to Gaza. They left no sustenance in Israel, and no sheep, ox, or donkey.'),
  ('Judges', 6, 5, 'For they came up with their livestock and their tents. They came in as locusts for multitude. Both they and their camels were without number; and they came into the land to destroy it.'),
  ('Judges', 6, 6, 'Israel was brought very low because of Midian; and the children of Israel cried to the LORD.'),
  ('Judges', 6, 7, 'When the children of Israel cried to the LORD because of Midian,'),
  ('Judges', 6, 8, 'The LORD sent a prophet to the children of Israel; and he said to them, “The LORD, the God of Israel, says, ‘I brought you up from Egypt, and brought you out of the house of bondage.'),
  ('Judges', 6, 9, 'I delivered you out of the hand of the Egyptians and out of the hand of all who oppressed you, and drove them out from before you, and gave you their land.'),
  ('Judges', 6, 10, 'I said to you, “I am the LORD your God. You shall not fear the gods of the Amorites, in whose land you dwell.” But you have not listened to my voice.’”'),
  ('Judges', 6, 11, 'The LORD’s angel came and sat under the oak which was in Ophrah, that belonged to Joash the Abiezrite. His son Gideon was beating out wheat in the wine press, to hide it from the Midianites.'),
  ('Judges', 6, 12, 'The LORD’s angel appeared to him, and said to him, “The LORD is with you, you mighty man of valor!”'),
  ('Judges', 6, 13, 'Gideon said to him, “Oh, my lord, if the LORD is with us, why then has all this happened to us? Where are all his wondrous works which our fathers told us of, saying, ‘Didn’t the LORD bring us up from Egypt?’ But now the LORD has cast us off, and delivered us into the hand of Midian.”'),
  ('Judges', 6, 14, 'The LORD looked at him, and said, “Go in this your might, and save Israel from the hand of Midian. Haven’t I sent you?”'),
  ('Judges', 6, 15, 'He said to him, “O Lord, how shall I save Israel? Behold, my family is the poorest in Manasseh, and I am the least in my father’s house.”'),
  ('Judges', 6, 16, 'The LORD said to him, “Surely I will be with you, and you shall strike the Midianites as one man.”'),
  ('Judges', 6, 17, 'He said to him, “If now I have found favor in your sight, then show me a sign that it is you who talk with me.'),
  ('Judges', 6, 18, 'Please don’t go away until I come to you, and bring out my present, and lay it before you.” He said, “I will wait until you come back.”'),
  ('Judges', 6, 19, 'Gideon went in and prepared a young goat and unleavened cakes of an ephah of meal. He put the meat in a basket and he put the broth in a pot, and brought it out to him under the oak, and presented it.'),
  ('Judges', 6, 20, 'The angel of God said to him, “Take the meat and the unleavened cakes, and lay them on this rock, and pour out the broth.” He did so.'),
  ('Judges', 6, 21, 'Then the LORD’s angel stretched out the end of the staff that was in his hand, and touched the meat and the unleavened cakes; and fire went up out of the rock and consumed the meat and the unleavened cakes. Then the LORD’s angel departed out of his sight.'),
  ('Judges', 6, 22, 'Gideon saw that he was the LORD’s angel; and Gideon said, “Alas, Lord GOD! Because I have seen the LORD’s angel face to face!”'),
  ('Judges', 6, 23, 'The LORD said to him, “Peace be to you! Don’t be afraid. You shall not die.”'),
  ('Judges', 6, 24, 'Then Gideon built an altar there to the LORD, and called it “The LORD is Peace.” To this day it is still in Ophrah of the Abiezrites.'),
  ('Judges', 6, 25, 'That same night, the LORD said to him, “Take your father’s bull, even the second bull seven years old, and throw down the altar of Baal that your father has, and cut down the Asherah that is by it.'),
  ('Judges', 6, 26, 'Then build an altar to the LORD your God on the top of this stronghold, in an orderly way, and take the second bull, and offer a burnt offering with the wood of the Asherah which you shall cut down.”'),
  ('Judges', 6, 27, 'Then Gideon took ten men of his servants, and did as the LORD had spoken to him. Because he feared his father’s household and the men of the city, he could not do it by day, but he did it by night.'),
  ('Judges', 6, 28, 'When the men of the city arose early in the morning, behold, the altar of Baal was broken down, and the Asherah was cut down that was by it, and the second bull was offered on the altar that was built.'),
  ('Judges', 6, 29, 'They said to one another, “Who has done this thing?” When they inquired and asked, they said, “Gideon the son of Joash has done this thing.”'),
  ('Judges', 6, 30, 'Then the men of the city said to Joash, “Bring out your son, that he may die, because he has broken down the altar of Baal, and because he has cut down the Asherah that was by it.”'),
  ('Judges', 6, 31, 'Joash said to all who stood against him, “Will you contend for Baal? Or will you save him? He who will contend for him, let him be put to death by morning! If he is a god, let him contend for himself, because someone has broken down his altar!”'),
  ('Judges', 6, 32, 'Therefore on that day he named him Jerub-Baal, saying, “Let Baal contend against him, because he has broken down his altar.”'),
  ('Judges', 6, 33, 'Then all the Midianites and the Amalekites and the children of the east assembled themselves together; and they passed over, and encamped in the valley of Jezreel.'),
  ('Judges', 6, 34, 'But the LORD’s Spirit came on Gideon, and he blew a trumpet; and Abiezer was gathered together to follow him.'),
  ('Judges', 6, 35, 'He sent messengers throughout all Manasseh, and they also were gathered together to follow him. He sent messengers to Asher, to Zebulun, and to Naphtali; and they came up to meet them.'),
  ('Judges', 6, 36, 'Gideon said to God, “If you will save Israel by my hand, as you have spoken,'),
  ('Judges', 6, 37, 'behold, I will put a fleece of wool on the threshing floor. If there is dew on the fleece only, and it is dry on all the ground, then I’ll know that you will save Israel by my hand, as you have spoken.”'),
  ('Judges', 6, 38, 'It was so; for he rose up early on the next day, and pressed the fleece together, and wrung the dew out of the fleece, a bowl full of water.'),
  ('Judges', 6, 39, 'Gideon said to God, “Don’t let your anger be kindled against me, and I will speak but this once. Please let me make a trial just this once with the fleece. Let it now be dry only on the fleece, and on all the ground let there be dew.”'),
  ('Judges', 6, 40, 'God did so that night; for it was dry on the fleece only, and there was dew on all the ground.'),
  ('Judges', 7, 1, 'Then Jerubbaal, who is Gideon, and all the people who were with him, rose up early and encamped beside the spring of Harod. Midian’s camp was on the north side of them, by the hill of Moreh, in the valley.'),
  ('Judges', 7, 2, 'The LORD said to Gideon, “The people who are with you are too many for me to give the Midianites into their hand, lest Israel brag against me, saying, ‘My own hand has saved me.’'),
  ('Judges', 7, 3, 'Now therefore proclaim in the ears of the people, saying, ‘Whoever is fearful and trembling, let him return and depart from Mount Gilead.’” So twenty-two thousand of the people returned, and ten thousand remained.'),
  ('Judges', 7, 4, 'The LORD said to Gideon, “There are still too many people. Bring them down to the water, and I will test them for you there. It shall be, that those whom I tell you, ‘This shall go with you,’ shall go with you; and whoever I tell you, ‘This shall not go with you,’ shall not go.”'),
  ('Judges', 7, 5, 'So he brought down the people to the water; and the LORD said to Gideon, “Everyone who laps of the water with his tongue, like a dog laps, you shall set him by himself; likewise everyone who bows down on his knees to drink.”');
INSERT INTO bible_verses (book_name, chapter, verse, text) VALUES
  ('Judges', 7, 6, 'The number of those who lapped, putting their hand to their mouth, was three hundred men; but all the rest of the people bowed down on their knees to drink water.'),
  ('Judges', 7, 7, 'The LORD said to Gideon, “I will save you by the three hundred men who lapped, and deliver the Midianites into your hand. Let all the other people go, each to his own place.”'),
  ('Judges', 7, 8, 'So the people took food in their hand, and their trumpets; and he sent all the rest of the men of Israel to their own tents, but retained the three hundred men; and the camp of Midian was beneath him in the valley.'),
  ('Judges', 7, 9, 'That same night, the LORD said to him, “Arise, go down into the camp, for I have delivered it into your hand.'),
  ('Judges', 7, 10, 'But if you are afraid to go down, go with Purah your servant down to the camp.'),
  ('Judges', 7, 11, 'You will hear what they say; and afterward your hands will be strengthened to go down into the camp.” Then went he down with Purah his servant to the outermost part of the armed men who were in the camp.'),
  ('Judges', 7, 12, 'The Midianites and the Amalekites and all the children of the east lay along in the valley like locusts for multitude; and their camels were without number, as the sand which is on the seashore for multitude.'),
  ('Judges', 7, 13, 'When Gideon had come, behold, there was a man telling a dream to his fellow. He said, “Behold, I dreamed a dream; and behold, a cake of barley bread tumbled into the camp of Midian, came to the tent, and struck it so that it fell, and turned it upside down, so that the tent lay flat.”'),
  ('Judges', 7, 14, 'His fellow answered, “This is nothing other than the sword of Gideon the son of Joash, a man of Israel. God has delivered Midian into his hand, with all the army.”'),
  ('Judges', 7, 15, 'It was so, when Gideon heard the telling of the dream and its interpretation, that he worshiped. Then he returned into the camp of Israel and said, “Arise, for the LORD has delivered the army of Midian into your hand!”'),
  ('Judges', 7, 16, 'He divided the three hundred men into three companies, and he put into the hands of all of them trumpets and empty pitchers, with torches within the pitchers.'),
  ('Judges', 7, 17, 'He said to them, “Watch me, and do likewise. Behold, when I come to the outermost part of the camp, it shall be that, as I do, so you shall do.'),
  ('Judges', 7, 18, 'When I blow the trumpet, I and all who are with me, then blow the trumpets also on every side of all the camp, and shout, ‘For the LORD and for Gideon!’”'),
  ('Judges', 7, 19, 'So Gideon and the hundred men who were with him came to the outermost part of the camp in the beginning of the middle watch, when they had but newly set the watch. Then they blew the trumpets and broke in pieces the pitchers that were in their hands.'),
  ('Judges', 7, 20, 'The three companies blew the trumpets, broke the pitchers, and held the torches in their left hands and the trumpets in their right hands with which to blow; and they shouted, “The sword of the LORD and of Gideon!”'),
  ('Judges', 7, 21, 'They each stood in his place around the camp, and all the army ran; and they shouted, and put them to flight.'),
  ('Judges', 7, 22, 'They blew the three hundred trumpets, and the LORD set every man’s sword against his fellow and against all the army; and the army fled as far as Beth Shittah toward Zererah, as far as the border of Abel Meholah, by Tabbath.'),
  ('Judges', 7, 23, 'The men of Israel were gathered together out of Naphtali, out of Asher, and out of all Manasseh, and pursued Midian.'),
  ('Judges', 7, 24, 'Gideon sent messengers throughout all the hill country of Ephraim, saying, “Come down against Midian and take the waters before them as far as Beth Barah, even the Jordan!” So all the men of Ephraim were gathered together and took the waters as far as Beth Barah, even the Jordan.'),
  ('Judges', 7, 25, 'They took the two princes of Midian, Oreb and Zeeb. They killed Oreb at Oreb’s rock, and Zeeb they killed at Zeeb’s wine press, as they pursued Midian. Then they brought the heads of Oreb and Zeeb to Gideon beyond the Jordan.'),
  ('Judges', 8, 1, 'The men of Ephraim said to him, “Why have you treated us this way, that you didn’t call us when you went to fight with Midian?” They rebuked him sharply.'),
  ('Judges', 8, 2, 'He said to them, “What have I now done in comparison with you? Isn’t the gleaning of the grapes of Ephraim better than the vintage of Abiezer?'),
  ('Judges', 8, 3, 'God has delivered into your hand the princes of Midian, Oreb and Zeeb! What was I able to do in comparison with you?” Then their anger was abated toward him when he had said that.'),
  ('Judges', 8, 4, 'Gideon came to the Jordan and passed over, he and the three hundred men who were with him, faint, yet pursuing.'),
  ('Judges', 8, 5, 'He said to the men of Succoth, “Please give loaves of bread to the people who follow me; for they are faint, and I am pursuing after Zebah and Zalmunna, the kings of Midian.”'),
  ('Judges', 8, 6, 'The princes of Succoth said, “Are the hands of Zebah and Zalmunna now in your hand, that we should give bread to your army?”'),
  ('Judges', 8, 7, 'Gideon said, “Therefore when the LORD has delivered Zebah and Zalmunna into my hand, then I will tear your flesh with the thorns of the wilderness and with briers.”'),
  ('Judges', 8, 8, 'He went up there to Penuel, and spoke to them in the same way; and the men of Penuel answered him as the men of Succoth had answered.'),
  ('Judges', 8, 9, 'He spoke also to the men of Penuel, saying, “When I come again in peace, I will break down this tower.”'),
  ('Judges', 8, 10, 'Now Zebah and Zalmunna were in Karkor, and their armies with them, about fifteen thousand men, all who were left of all the army of the children of the east; for there fell one hundred twenty thousand men who drew sword.'),
  ('Judges', 8, 11, 'Gideon went up by the way of those who lived in tents on the east of Nobah and Jogbehah, and struck the army; for the army felt secure.'),
  ('Judges', 8, 12, 'Zebah and Zalmunna fled and he pursued them. He took the two kings of Midian, Zebah and Zalmunna, and confused all the army.'),
  ('Judges', 8, 13, 'Gideon the son of Joash returned from the battle from the ascent of Heres.'),
  ('Judges', 8, 14, 'He caught a young man of the men of Succoth, and inquired of him; and he described for him the princes of Succoth, and its elders, seventy-seven men.'),
  ('Judges', 8, 15, 'He came to the men of Succoth, and said, “See Zebah and Zalmunna, concerning whom you taunted me, saying, ‘Are the hands of Zebah and Zalmunna now in your hand, that we should give bread to your men who are weary?’”'),
  ('Judges', 8, 16, 'He took the elders of the city, and thorns of the wilderness and briers, and with them he taught the men of Succoth.'),
  ('Judges', 8, 17, 'He broke down the tower of Penuel, and killed the men of the city.'),
  ('Judges', 8, 18, 'Then he said to Zebah and Zalmunna, “What kind of men were they whom you killed at Tabor?” They answered, “They were like you. They all resembled the children of a king.”'),
  ('Judges', 8, 19, 'He said, “They were my brothers, the sons of my mother. As the LORD lives, if you had saved them alive, I would not kill you.”'),
  ('Judges', 8, 20, 'He said to Jether his firstborn, “Get up and kill them!” But the youth didn’t draw his sword; for he was afraid, because he was yet a youth.'),
  ('Judges', 8, 21, 'Then Zebah and Zalmunna said, “You rise and fall on us; for as the man is, so is his strength.” Gideon arose, and killed Zebah and Zalmunna, and took the crescents that were on their camels’ necks.'),
  ('Judges', 8, 22, 'Then the men of Israel said to Gideon, “Rule over us, both you, your son, and your son’s son also; for you have saved us out of the hand of Midian.”'),
  ('Judges', 8, 23, 'Gideon said to them, “I will not rule over you, neither shall my son rule over you. The LORD shall rule over you.”'),
  ('Judges', 8, 24, 'Gideon said to them, “I do have a request: that you would each give me the earrings of his plunder.” (For they had golden earrings, because they were Ishmaelites.)'),
  ('Judges', 8, 25, 'They answered, “We will willingly give them.” They spread a garment, and every man threw the earrings of his plunder into it.'),
  ('Judges', 8, 26, 'The weight of the golden earrings that he requested was one thousand and seven hundred shekels of gold, in addition to the crescents, and the pendants, and the purple clothing that was on the kings of Midian, and in addition to the chains that were about their camels’ necks.'),
  ('Judges', 8, 27, 'Gideon made an ephod out of it, and put it in Ophrah, his city. Then all Israel played the prostitute with it there; and it became a snare to Gideon and to his house.'),
  ('Judges', 8, 28, 'So Midian was subdued before the children of Israel, and they lifted up their heads no more. The land had rest forty years in the days of Gideon.'),
  ('Judges', 8, 29, 'Jerubbaal the son of Joash went and lived in his own house.'),
  ('Judges', 8, 30, 'Gideon had seventy sons conceived from his body, for he had many wives.'),
  ('Judges', 8, 31, 'His concubine who was in Shechem also bore him a son, and he named him Abimelech.'),
  ('Judges', 8, 32, 'Gideon the son of Joash died in a good old age, and was buried in the tomb of Joash his father, in Ophrah of the Abiezrites.'),
  ('Judges', 8, 33, 'As soon as Gideon was dead, the children of Israel turned again and played the prostitute following the Baals, and made Baal Berith their god.'),
  ('Judges', 8, 34, 'The children of Israel didn’t remember the LORD their God, who had delivered them out of the hand of all their enemies on every side;'),
  ('Judges', 8, 35, 'neither did they show kindness to the house of Jerubbaal, that is, Gideon, according to all the goodness which he had shown to Israel.'),
  ('Judges', 9, 1, 'Abimelech the son of Jerubbaal went to Shechem to his mother’s brothers, and spoke with them and with all the family of the house of his mother’s father, saying,'),
  ('Judges', 9, 2, '“Please speak in the ears of all the men of Shechem, ‘Is it better for you that all the sons of Jerubbaal, who are seventy persons, rule over you, or that one rule over you?’ Remember also that I am your bone and your flesh.”'),
  ('Judges', 9, 3, 'His mother’s brothers spoke of him in the ears of all the men of Shechem all these words. Their hearts inclined to follow Abimelech; for they said, “He is our brother.”'),
  ('Judges', 9, 4, 'They gave him seventy pieces of silver out of the house of Baal Berith, with which Abimelech hired vain and reckless fellows who followed him.'),
  ('Judges', 9, 5, 'He went to his father’s house at Ophrah, and killed his brothers the sons of Jerubbaal, being seventy persons, on one stone; but Jotham the youngest son of Jerubbaal was left, for he hid himself.'),
  ('Judges', 9, 6, 'All the men of Shechem assembled themselves together with all the house of Millo, and went and made Abimelech king by the oak of the pillar that was in Shechem.'),
  ('Judges', 9, 7, 'When they told it to Jotham, he went and stood on the top of Mount Gerizim and lifted up his voice, cried out, and said to them, “Listen to me, you men of Shechem, that God may listen to you.'),
  ('Judges', 9, 8, 'The trees set out to anoint a king over themselves. They said to the olive tree, ‘Reign over us.’'),
  ('Judges', 9, 9, '“But the olive tree said to them, ‘Should I stop producing my oil, with which they honor God and man by me, and go to wave back and forth over the trees?’'),
  ('Judges', 9, 10, '“The trees said to the fig tree, ‘Come and reign over us.’'),
  ('Judges', 9, 11, '“But the fig tree said to them, ‘Should I leave my sweetness, and my good fruit, and go to wave back and forth over the trees?’'),
  ('Judges', 9, 12, '“The trees said to the vine, ‘Come and reign over us.’'),
  ('Judges', 9, 13, '“The vine said to them, ‘Should I leave my new wine, which cheers God and man, and go to wave back and forth over the trees?’'),
  ('Judges', 9, 14, '“Then all the trees said to the bramble, ‘Come and reign over us.’'),
  ('Judges', 9, 15, '“The bramble said to the trees, ‘If in truth you anoint me king over you, then come and take refuge in my shade; and if not, let fire come out of the bramble, and devour the cedars of Lebanon.’'),
  ('Judges', 9, 16, '“Now therefore, if you have dealt truly and righteously, in that you have made Abimelech king, and if you have dealt well with Jerubbaal and his house, and have done to him according to the deserving of his hands'),
  ('Judges', 9, 17, '(for my father fought for you, risked his life, and delivered you out of the hand of Midian;'),
  ('Judges', 9, 18, 'and you have risen up against my father’s house today and have slain his sons, seventy persons, on one stone, and have made Abimelech, the son of his female servant, king over the men of Shechem, because he is your brother);'),
  ('Judges', 9, 19, 'if you then have dealt truly and righteously with Jerubbaal and with his house today, then rejoice in Abimelech, and let him also rejoice in you;'),
  ('Judges', 9, 20, 'but if not, let fire come out from Abimelech and devour the men of Shechem and the house of Millo; and let fire come out from the men of Shechem and from the house of Millo and devour Abimelech.”'),
  ('Judges', 9, 21, 'Jotham ran away and fled, and went to Beer and lived there, for fear of Abimelech his brother.'),
  ('Judges', 9, 22, 'Abimelech was prince over Israel three years.'),
  ('Judges', 9, 23, 'Then God sent an evil spirit between Abimelech and the men of Shechem; and the men of Shechem dealt treacherously with Abimelech,'),
  ('Judges', 9, 24, 'that the violence done to the seventy sons of Jerubbaal might come, and that their blood might be laid on Abimelech their brother who killed them, and on the men of Shechem who strengthened his hands to kill his brothers.'),
  ('Judges', 9, 25, 'The men of Shechem set an ambush for him on the tops of the mountains, and they robbed all who came along that way by them; and Abimelech was told about it.'),
  ('Judges', 9, 26, 'Gaal the son of Ebed came with his brothers and went over to Shechem; and the men of Shechem put their trust in him.'),
  ('Judges', 9, 27, 'They went out into the field, harvested their vineyards, trod the grapes, celebrated, and went into the house of their god and ate and drank, and cursed Abimelech.'),
  ('Judges', 9, 28, 'Gaal the son of Ebed said, “Who is Abimelech, and who is Shechem, that we should serve him? Isn’t he the son of Jerubbaal? Isn’t Zebul his officer? Serve the men of Hamor the father of Shechem, but why should we serve him?'),
  ('Judges', 9, 29, 'I wish that this people were under my hand! Then I would remove Abimelech.” He said to Abimelech, “Increase your army and come out!”'),
  ('Judges', 9, 30, 'When Zebul the ruler of the city heard the words of Gaal the son of Ebed, his anger burned.'),
  ('Judges', 9, 31, 'He sent messengers to Abimelech craftily, saying, “Behold, Gaal the son of Ebed and his brothers have come to Shechem; and behold, they incite the city against you.'),
  ('Judges', 9, 32, 'Now therefore, go up by night, you and the people who are with you, and lie in wait in the field.'),
  ('Judges', 9, 33, 'It shall be that in the morning, as soon as the sun is up, you shall rise early and rush on the city. Behold, when he and the people who are with him come out against you, then may you do to them as you shall find occasion.”'),
  ('Judges', 9, 34, 'Abimelech rose up, and all the people who were with him, by night, and they laid wait against Shechem in four companies.'),
  ('Judges', 9, 35, 'Gaal the son of Ebed went out, and stood in the entrance of the gate of the city. Abimelech rose up, and the people who were with him, from the ambush.'),
  ('Judges', 9, 36, 'When Gaal saw the people, he said to Zebul, “Behold, people are coming down from the tops of the mountains.” Zebul said to him, “You see the shadows of the mountains as if they were men.”'),
  ('Judges', 9, 37, 'Gaal spoke again and said, “Behold, people are coming down by the middle of the land, and one company comes by the way of the oak of Meonenim.”'),
  ('Judges', 9, 38, 'Then Zebul said to him, “Now where is your mouth, that you said, ‘Who is Abimelech, that we should serve him?’ Isn’t this the people that you have despised? Please go out now and fight with them.”'),
  ('Judges', 9, 39, 'Gaal went out before the men of Shechem, and fought with Abimelech.'),
  ('Judges', 9, 40, 'Abimelech chased him, and he fled before him, and many fell wounded, even to the entrance of the gate.'),
  ('Judges', 9, 41, 'Abimelech lived at Arumah; and Zebul drove out Gaal and his brothers, that they should not dwell in Shechem.'),
  ('Judges', 9, 42, 'On the next day, the people went out into the field; and they told Abimelech.'),
  ('Judges', 9, 43, 'He took the people and divided them into three companies, and laid wait in the field; and he looked, and behold, the people came out of the city. So, he rose up against them and struck them.'),
  ('Judges', 9, 44, 'Abimelech and the companies that were with him rushed forward and stood in the entrance of the gate of the city; and the two companies rushed on all who were in the field and struck them.'),
  ('Judges', 9, 45, 'Abimelech fought against the city all that day; and he took the city and killed the people in it. He beat down the city and sowed it with salt.');
INSERT INTO bible_verses (book_name, chapter, verse, text) VALUES
  ('Judges', 9, 46, 'When all the men of the tower of Shechem heard of it, they entered into the stronghold of the house of Elberith.'),
  ('Judges', 9, 47, 'Abimelech was told that all the men of the tower of Shechem were gathered together.'),
  ('Judges', 9, 48, 'Abimelech went up to Mount Zalmon, he and all the people who were with him; and Abimelech took an ax in his hand, and cut down a bough from the trees, and took it up, and laid it on his shoulder. Then he said to the people who were with him, “What you have seen me do, make haste, and do as I have done!”'),
  ('Judges', 9, 49, 'All the people likewise each cut down his bough, followed Abimelech, and put them at the base of the stronghold, and set the stronghold on fire over them, so that all the people of the tower of Shechem died also, about a thousand men and women.'),
  ('Judges', 9, 50, 'Then Abimelech went to Thebez and encamped against Thebez, and took it.'),
  ('Judges', 9, 51, 'But there was a strong tower within the city, and all the men and women of the city fled there, and shut themselves in, and went up to the roof of the tower.'),
  ('Judges', 9, 52, 'Abimelech came to the tower and fought against it, and came near to the door of the tower to burn it with fire.'),
  ('Judges', 9, 53, 'A certain woman cast an upper millstone on Abimelech’s head, and broke his skull.'),
  ('Judges', 9, 54, 'Then he called hastily to the young man, his armor bearer, and said to him, “Draw your sword and kill me, that men not say of me, ‘A woman killed him.’ His young man thrust him through, and he died.”'),
  ('Judges', 9, 55, 'When the men of Israel saw that Abimelech was dead, they each departed to his place.'),
  ('Judges', 9, 56, 'Thus God repaid the wickedness of Abimelech, which he did to his father in killing his seventy brothers;'),
  ('Judges', 9, 57, 'and God repaid all the wickedness of the men of Shechem on their heads; and the curse of Jotham the son of Jerubbaal came on them.'),
  ('Judges', 10, 1, 'After Abimelech, Tola the son of Puah, the son of Dodo, a man of Issachar, arose to save Israel. He lived in Shamir in the hill country of Ephraim.'),
  ('Judges', 10, 2, 'He judged Israel twenty-three years, and died, and was buried in Shamir.'),
  ('Judges', 10, 3, 'After him Jair, the Gileadite, arose. He judged Israel twenty-two years.'),
  ('Judges', 10, 4, 'He had thirty sons who rode on thirty donkey colts. They had thirty cities, which are called Havvoth Jair to this day, which are in the land of Gilead.'),
  ('Judges', 10, 5, 'Jair died, and was buried in Kamon.'),
  ('Judges', 10, 6, 'The children of Israel again did that which was evil in the LORD’s sight, and served the Baals, the Ashtaroth, the gods of Syria, the gods of Sidon, the gods of Moab, the gods of the children of Ammon, and the gods of the Philistines. They abandoned the LORD, and didn’t serve him.'),
  ('Judges', 10, 7, 'The LORD’s anger burned against Israel, and he sold them into the hand of the Philistines and into the hand of the children of Ammon.'),
  ('Judges', 10, 8, 'They troubled and oppressed the children of Israel that year. For eighteen years they oppressed all the children of Israel that were beyond the Jordan in the land of the Amorites, which is in Gilead.'),
  ('Judges', 10, 9, 'The children of Ammon passed over the Jordan to fight also against Judah, and against Benjamin, and against the house of Ephraim, so that Israel was very distressed.'),
  ('Judges', 10, 10, 'The children of Israel cried to the LORD, saying, “We have sinned against you, even because we have forsaken our God, and have served the Baals.”'),
  ('Judges', 10, 11, 'The LORD said to the children of Israel, “Didn’t I save you from the Egyptians, and from the Amorites, from the children of Ammon, and from the Philistines?'),
  ('Judges', 10, 12, 'The Sidonians also, and the Amalekites, and the Maonites, oppressed you; and you cried to me, and I saved you out of their hand.'),
  ('Judges', 10, 13, 'Yet you have forsaken me and served other gods. Therefore I will save you no more.'),
  ('Judges', 10, 14, 'Go and cry to the gods which you have chosen. Let them save you in the time of your distress!”'),
  ('Judges', 10, 15, 'The children of Israel said to the LORD, “We have sinned! Do to us whatever seems good to you; only deliver us, please, today.”'),
  ('Judges', 10, 16, 'They put away the foreign gods from among them and served the LORD; and his soul was grieved for the misery of Israel.'),
  ('Judges', 10, 17, 'Then the children of Ammon were gathered together and encamped in Gilead. The children of Israel assembled themselves together and encamped in Mizpah.'),
  ('Judges', 10, 18, 'The people, the princes of Gilead, said to one another, “Who is the man who will begin to fight against the children of Ammon? He shall be head over all the inhabitants of Gilead.”'),
  ('Judges', 11, 1, 'Now Jephthah the Gileadite was a mighty man of valor. He was the son of a prostitute. Gilead became the father of Jephthah.'),
  ('Judges', 11, 2, 'Gilead’s wife bore him sons. When his wife’s sons grew up, they drove Jephthah out and said to him, “You will not inherit in our father’s house, for you are the son of another woman.”'),
  ('Judges', 11, 3, 'Then Jephthah fled from his brothers and lived in the land of Tob. Outlaws joined up with Jephthah, and they went out with him.'),
  ('Judges', 11, 4, 'After a while, the children of Ammon made war against Israel.'),
  ('Judges', 11, 5, 'When the children of Ammon made war against Israel, the elders of Gilead went to get Jephthah out of the land of Tob.'),
  ('Judges', 11, 6, 'They said to Jephthah, “Come and be our chief, that we may fight with the children of Ammon.”'),
  ('Judges', 11, 7, 'Jephthah said to the elders of Gilead, “Didn’t you hate me, and drive me out of my father’s house? Why have you come to me now when you are in distress?”'),
  ('Judges', 11, 8, 'The elders of Gilead said to Jephthah, “Therefore we have turned again to you now, that you may go with us and fight with the children of Ammon. You will be our head over all the inhabitants of Gilead.”'),
  ('Judges', 11, 9, 'Jephthah said to the elders of Gilead, “If you bring me home again to fight with the children of Ammon, and the LORD delivers them before me, will I be your head?”'),
  ('Judges', 11, 10, 'The elders of Gilead said to Jephthah, “The LORD will be witness between us. Surely we will do what you say.”'),
  ('Judges', 11, 11, 'Then Jephthah went with the elders of Gilead, and the people made him head and chief over them. Jephthah spoke all his words before the LORD in Mizpah.'),
  ('Judges', 11, 12, 'Jephthah sent messengers to the king of the children of Ammon, saying, “What do you have to do with me, that you have come to me to fight against my land?”'),
  ('Judges', 11, 13, 'The king of the children of Ammon answered the messengers of Jephthah, “Because Israel took away my land when he came up out of Egypt, from the Arnon even to the Jabbok, and to the Jordan. Now therefore restore that territory again peaceably.”'),
  ('Judges', 11, 14, 'Jephthah sent messengers again to the king of the children of Ammon;'),
  ('Judges', 11, 15, 'and he said to him, “Jephthah says: Israel didn’t take away the land of Moab, nor the land of the children of Ammon;'),
  ('Judges', 11, 16, 'but when they came up from Egypt, and Israel went through the wilderness to the Red Sea, and came to Kadesh,'),
  ('Judges', 11, 17, 'then Israel sent messengers to the king of Edom, saying, ‘Please let me pass through your land;’ but the king of Edom didn’t listen. In the same way, he sent to the king of Moab, but he refused; so Israel stayed in Kadesh.'),
  ('Judges', 11, 18, 'Then they went through the wilderness, and went around the land of Edom, and the land of Moab, and came by the east side of the land of Moab, and they encamped on the other side of the Arnon; but they didn’t come within the border of Moab, for the Arnon was the border of Moab.'),
  ('Judges', 11, 19, 'Israel sent messengers to Sihon king of the Amorites, the king of Heshbon; and Israel said to him, ‘Please let us pass through your land to my place.’'),
  ('Judges', 11, 20, 'But Sihon didn’t trust Israel to pass through his border; but Sihon gathered all his people together, and encamped in Jahaz, and fought against Israel.'),
  ('Judges', 11, 21, 'The LORD, the God of Israel, delivered Sihon and all his people into the hand of Israel, and they struck them. So Israel possessed all the land of the Amorites, the inhabitants of that country.'),
  ('Judges', 11, 22, 'They possessed all the border of the Amorites, from the Arnon even to the Jabbok, and from the wilderness even to the Jordan.'),
  ('Judges', 11, 23, 'So now the LORD, the God of Israel, has dispossessed the Amorites from before his people Israel, and should you possess them?'),
  ('Judges', 11, 24, 'Won’t you possess that which Chemosh your god gives you to possess? So whoever the LORD our God has dispossessed from before us, them will we possess.'),
  ('Judges', 11, 25, 'Now are you anything better than Balak the son of Zippor, king of Moab? Did he ever strive against Israel, or did he ever fight against them?'),
  ('Judges', 11, 26, 'Israel lived in Heshbon and its towns, and in Aroer and its towns, and in all the cities that are along the side of the Arnon for three hundred years! Why didn’t you recover them within that time?'),
  ('Judges', 11, 27, 'Therefore I have not sinned against you, but you do me wrong to war against me. May the LORD the Judge be judge today between the children of Israel and the children of Ammon.”'),
  ('Judges', 11, 28, 'However, the king of the children of Ammon didn’t listen to the words of Jephthah which he sent him.'),
  ('Judges', 11, 29, 'Then the LORD’s Spirit came on Jephthah, and he passed over Gilead and Manasseh, and passed over Mizpah of Gilead, and from Mizpah of Gilead he passed over to the children of Ammon.'),
  ('Judges', 11, 30, 'Jephthah vowed a vow to the LORD, and said, “If you will indeed deliver the children of Ammon into my hand,'),
  ('Judges', 11, 31, 'then it shall be, that whatever comes out of the doors of my house to meet me when I return in peace from the children of Ammon, it shall be the LORD’s, and I will offer it up for a burnt offering.”'),
  ('Judges', 11, 32, 'So Jephthah passed over to the children of Ammon to fight against them; and the LORD delivered them into his hand.'),
  ('Judges', 11, 33, 'He struck them from Aroer until you come to Minnith, even twenty cities, and to Abelcheramim, with a very great slaughter. So the children of Ammon were subdued before the children of Israel.'),
  ('Judges', 11, 34, 'Jephthah came to Mizpah to his house; and behold, his daughter came out to meet him with tambourines and with dances. She was his only child. Besides her he had neither son nor daughter.'),
  ('Judges', 11, 35, 'When he saw her, he tore his clothes, and said, “Alas, my daughter! You have brought me very low, and you are one of those who trouble me; for I have opened my mouth to the LORD, and I can’t go back.”'),
  ('Judges', 11, 36, 'She said to him, “My father, you have opened your mouth to the LORD; do to me according to that which has proceeded out of your mouth, because the LORD has taken vengeance for you on your enemies, even on the children of Ammon.”'),
  ('Judges', 11, 37, 'Then she said to her father, “Let this thing be done for me. Leave me alone two months, that I may depart and go down on the mountains, and bewail my virginity, I and my companions.”'),
  ('Judges', 11, 38, 'He said, “Go.” He sent her away for two months; and she departed, she and her companions, and mourned her virginity on the mountains.'),
  ('Judges', 11, 39, 'At the end of two months, she returned to her father, who did with her according to his vow which he had vowed. She was a virgin. It became a custom in Israel'),
  ('Judges', 11, 40, 'that the daughters of Israel went yearly to celebrate the daughter of Jephthah the Gileadite four days in a year.'),
  ('Judges', 12, 1, 'The men of Ephraim were gathered together, and passed northward; and they said to Jephthah, “Why did you pass over to fight against the children of Ammon, and didn’t call us to go with you? We will burn your house around you with fire!”'),
  ('Judges', 12, 2, 'Jephthah said to them, “I and my people were at great strife with the children of Ammon; and when I called you, you didn’t save me out of their hand.'),
  ('Judges', 12, 3, 'When I saw that you didn’t save me, I put my life in my hand, and passed over against the children of Ammon, and the LORD delivered them into my hand. Why then have you come up to me today, to fight against me?”'),
  ('Judges', 12, 4, 'Then Jephthah gathered together all the men of Gilead, and fought with Ephraim. The men of Gilead struck Ephraim, because they said, “You are fugitives of Ephraim, you Gileadites, in the middle of Ephraim, and in the middle of Manasseh.”'),
  ('Judges', 12, 5, 'The Gileadites took the fords of the Jordan against the Ephraimites. Whenever a fugitive of Ephraim said, “Let me go over,” the men of Gilead said to him, “Are you an Ephraimite?” If he said, “No;”'),
  ('Judges', 12, 6, 'then they said to him, “Now say ‘Shibboleth;’” and he said “Sibboleth”; for he couldn’t manage to pronounce it correctly, then they seized him and killed him at the fords of the Jordan. At that time, forty-two thousand of Ephraim fell.'),
  ('Judges', 12, 7, 'Jephthah judged Israel six years. Then Jephthah the Gileadite died, and was buried in the cities of Gilead.'),
  ('Judges', 12, 8, 'After him Ibzan of Bethlehem judged Israel.'),
  ('Judges', 12, 9, 'He had thirty sons. He sent his thirty daughters outside his clan, and he brought in thirty daughters from outside his clan for his sons. He judged Israel seven years.'),
  ('Judges', 12, 10, 'Ibzan died, and was buried at Bethlehem.'),
  ('Judges', 12, 11, 'After him, Elon the Zebulunite judged Israel; and he judged Israel ten years.'),
  ('Judges', 12, 12, 'Elon the Zebulunite died, and was buried in Aijalon in the land of Zebulun.'),
  ('Judges', 12, 13, 'After him, Abdon the son of Hillel the Pirathonite judged Israel.'),
  ('Judges', 12, 14, 'He had forty sons and thirty sons’ sons who rode on seventy donkey colts. He judged Israel eight years.'),
  ('Judges', 12, 15, 'Abdon the son of Hillel the Pirathonite died, and was buried in Pirathon in the land of Ephraim, in the hill country of the Amalekites.'),
  ('Judges', 13, 1, 'The children of Israel again did that which was evil in the LORD’s sight; and the LORD delivered them into the hand of the Philistines forty years.'),
  ('Judges', 13, 2, 'There was a certain man of Zorah, of the family of the Danites, whose name was Manoah; and his wife was barren, and childless.'),
  ('Judges', 13, 3, 'The LORD’s angel appeared to the woman, and said to her, “See now, you are barren and childless; but you shall conceive and bear a son.'),
  ('Judges', 13, 4, 'Now therefore please beware and drink no wine nor strong drink, and don’t eat any unclean thing;'),
  ('Judges', 13, 5, 'for, behold, you shall conceive and give birth to a son. No razor shall come on his head, for the child shall be a Nazirite to God from the womb. He shall begin to save Israel out of the hand of the Philistines.”'),
  ('Judges', 13, 6, 'Then the woman came and told her husband, saying, “A man of God came to me, and his face was like the face of the angel of God, very awesome. I didn’t ask him where he was from, neither did he tell me his name;'),
  ('Judges', 13, 7, 'but he said to me, ‘Behold, you shall conceive and bear a son; and now drink no wine nor strong drink. Don’t eat any unclean thing, for the child shall be a Nazirite to God from the womb to the day of his death.’”'),
  ('Judges', 13, 8, 'Then Manoah entreated the LORD, and said, “Oh, Lord, please let the man of God whom you sent come again to us, and teach us what we should do to the child who shall be born.”'),
  ('Judges', 13, 9, 'God listened to the voice of Manoah, and the angel of God came again to the woman as she sat in the field; but Manoah, her husband, wasn’t with her.'),
  ('Judges', 13, 10, 'The woman hurried and ran, and told her husband, saying to him, “Behold, the man who came to me that day has appeared to me.”'),
  ('Judges', 13, 11, 'Manoah arose and followed his wife, and came to the man, and said to him, “Are you the man who spoke to my wife?” He said, “I am.”'),
  ('Judges', 13, 12, 'Manoah said, “Now let your words happen. What shall the child’s way of life and mission be?”'),
  ('Judges', 13, 13, 'The LORD’s angel said to Manoah, “Of all that I said to the woman let her beware.'),
  ('Judges', 13, 14, 'She may not eat of anything that comes of the vine, neither let her drink wine or strong drink, nor eat any unclean thing. Let her observe all that I commanded her.”'),
  ('Judges', 13, 15, 'Manoah said to the LORD’s angel, “Please stay with us, that we may make a young goat ready for you.”');
INSERT INTO bible_verses (book_name, chapter, verse, text) VALUES
  ('Judges', 13, 16, 'The LORD’s angel said to Manoah, “Though you detain me, I won’t eat your bread. If you will prepare a burnt offering, you must offer it to the LORD.” For Manoah didn’t know that he was the LORD’s angel.'),
  ('Judges', 13, 17, 'Manoah said to the LORD’s angel, “What is your name, that when your words happen, we may honor you?”'),
  ('Judges', 13, 18, 'The LORD’s angel said to him, “Why do you ask about my name, since it is incomprehensible?”'),
  ('Judges', 13, 19, 'So Manoah took the young goat with the meal offering, and offered it on the rock to the LORD. Then the angel did an amazing thing as Manoah and his wife watched.'),
  ('Judges', 13, 20, 'For when the flame went up toward the sky from off the altar, the LORD’s angel ascended in the flame of the altar. Manoah and his wife watched; and they fell on their faces to the ground.'),
  ('Judges', 13, 21, 'But the LORD’s angel didn’t appear to Manoah or to his wife any more. Then Manoah knew that he was the LORD’s angel.'),
  ('Judges', 13, 22, 'Manoah said to his wife, “We shall surely die, because we have seen God.”'),
  ('Judges', 13, 23, 'But his wife said to him, “If the LORD were pleased to kill us, he wouldn’t have received a burnt offering and a meal offering at our hand, and he wouldn’t have shown us all these things, nor would he have told us such things as these at this time.”'),
  ('Judges', 13, 24, 'The woman bore a son and named him Samson. The child grew, and the LORD blessed him.'),
  ('Judges', 13, 25, 'The LORD’s Spirit began to move him in Mahaneh Dan, between Zorah and Eshtaol.'),
  ('Judges', 14, 1, 'Samson went down to Timnah, and saw a woman in Timnah of the daughters of the Philistines.'),
  ('Judges', 14, 2, 'He came up, and told his father and his mother, saying, “I have seen a woman in Timnah of the daughters of the Philistines. Now therefore get her for me as my wife.”'),
  ('Judges', 14, 3, 'Then his father and his mother said to him, “Isn’t there a woman among your brothers’ daughters, or among all my people, that you go to take a wife of the uncircumcised Philistines?” Samson said to his father, “Get her for me, for she pleases me well.”'),
  ('Judges', 14, 4, 'But his father and his mother didn’t know that it was of the LORD; for he sought an occasion against the Philistines. Now at that time the Philistines ruled over Israel.'),
  ('Judges', 14, 5, 'Then Samson went down to Timnah with his father and his mother, and came to the vineyards of Timnah; and behold, a young lion roared at him.'),
  ('Judges', 14, 6, 'The LORD’s Spirit came mightily on him, and he tore him as he would have torn a young goat with his bare hands, but he didn’t tell his father or his mother what he had done.'),
  ('Judges', 14, 7, 'He went down and talked with the woman, and she pleased Samson well.'),
  ('Judges', 14, 8, 'After a while he returned to take her, and he went over to see the carcass of the lion; and behold, there was a swarm of bees in the body of the lion, and honey.'),
  ('Judges', 14, 9, 'He took it into his hands, and went on, eating as he went. He came to his father and mother and gave to them, and they ate, but he didn’t tell them that he had taken the honey out of the lion’s body.'),
  ('Judges', 14, 10, 'His father went down to the woman; and Samson made a feast there, for the young men used to do so.'),
  ('Judges', 14, 11, 'When they saw him, they brought thirty companions to be with him.'),
  ('Judges', 14, 12, 'Samson said to them, “Let me tell you a riddle now. If you can tell me the answer within the seven days of the feast, and find it out, then I will give you thirty linen garments and thirty changes of clothing;'),
  ('Judges', 14, 13, 'but if you can’t tell me the answer, then you shall give me thirty linen garments and thirty changes of clothing.” They said to him, “Tell us your riddle, that we may hear it.”'),
  ('Judges', 14, 14, 'He said to them, “Out of the eater came out food. Out of the strong came out sweetness.” They couldn’t in three days declare the riddle.'),
  ('Judges', 14, 15, 'On the seventh day, they said to Samson’s wife, “Entice your husband, that he may declare to us the riddle, lest we burn you and your father’s house with fire. Have you called us to impoverish us? Isn’t that so?”'),
  ('Judges', 14, 16, 'Samson’s wife wept before him, and said, “You just hate me, and don’t love me. You’ve told a riddle to the children of my people, and haven’t told it to me.” He said to her, “Behold, I haven’t told my father or my mother, so why should I tell you?”'),
  ('Judges', 14, 17, 'She wept before him the seven days, while their feast lasted; and on the seventh day, he told her, because she pressed him severely; and she told the riddle to the children of her people.'),
  ('Judges', 14, 18, 'The men of the city said to him on the seventh day before the sun went down, “What is sweeter than honey? What is stronger than a lion?” He said to them, “If you hadn’t plowed with my heifer, you wouldn’t have found out my riddle.”'),
  ('Judges', 14, 19, 'The LORD’s Spirit came mightily on him, and he went down to Ashkelon and struck thirty men of them. He took their plunder, then gave the changes of clothing to those who declared the riddle. His anger burned, and he went up to his father’s house.'),
  ('Judges', 14, 20, 'But Samson’s wife was given to his companion, who had been his friend.'),
  ('Judges', 15, 1, 'But after a while, in the time of wheat harvest, Samson visited his wife with a young goat. He said, “I will go in to my wife’s room.” But her father wouldn’t allow him to go in.'),
  ('Judges', 15, 2, 'Her father said, “I most certainly thought that you utterly hated her; therefore I gave her to your companion. Isn’t her younger sister more beautiful than she? Please, take her instead.”'),
  ('Judges', 15, 3, 'Samson said to them, “This time I will be blameless in the case of the Philistines when I harm them.”'),
  ('Judges', 15, 4, 'Samson went and caught three hundred foxes, and took torches, and turned tail to tail, and put a torch in the middle between every two tails.'),
  ('Judges', 15, 5, 'When he had set the torches on fire, he let them go into the standing grain of the Philistines, and burned up both the shocks and the standing grain, and also the olive groves.'),
  ('Judges', 15, 6, 'Then the Philistines said, “Who has done this?” They said, “Samson, the son-in-law of the Timnite, because he has taken his wife and given her to his companion.” The Philistines came up, and burned her and her father with fire.'),
  ('Judges', 15, 7, 'Samson said to them, “If you behave like this, surely I will take revenge on you, and after that I will cease.”'),
  ('Judges', 15, 8, 'He struck them hip and thigh with a great slaughter; and he went down and lived in the cave in Etam’s rock.'),
  ('Judges', 15, 9, 'Then the Philistines went up, encamped in Judah, and spread themselves in Lehi.'),
  ('Judges', 15, 10, 'The men of Judah said, “Why have you come up against us?” They said, “We have come up to bind Samson, to do to him as he has done to us.”'),
  ('Judges', 15, 11, 'Then three thousand men of Judah went down to the cave in Etam’s rock, and said to Samson, “Don’t you know that the Philistines are rulers over us? What then is this that you have done to us?” He said to them, “As they did to me, so I have done to them.”'),
  ('Judges', 15, 12, 'They said to him, “We have come down to bind you, that we may deliver you into the hand of the Philistines.” Samson said to them, “Swear to me that you will not attack me yourselves.”'),
  ('Judges', 15, 13, 'They spoke to him, saying, “No, but we will bind you securely and deliver you into their hands; but surely we will not kill you.” They bound him with two new ropes, and brought him up from the rock.'),
  ('Judges', 15, 14, 'When he came to Lehi, the Philistines shouted as they met him. Then the LORD’s Spirit came mightily on him, and the ropes that were on his arms became as flax that was burned with fire; and his bands dropped from off his hands.'),
  ('Judges', 15, 15, 'He found a fresh jawbone of a donkey, put out his hand, took it, and struck a thousand men with it.'),
  ('Judges', 15, 16, 'Samson said, “With the jawbone of a donkey, heaps on heaps; with the jawbone of a donkey I have struck a thousand men.”'),
  ('Judges', 15, 17, 'When he had finished speaking, he threw the jawbone out of his hand; and that place was called Ramath Lehi.'),
  ('Judges', 15, 18, 'He was very thirsty, and called on the LORD and said, “You have given this great deliverance by the hand of your servant; and now shall I die of thirst, and fall into the hands of the uncircumcised?”'),
  ('Judges', 15, 19, 'But God split the hollow place that is in Lehi, and water came out of it. When he had drunk, his spirit came again, and he revived. Therefore its name was called En Hakkore, which is in Lehi, to this day.'),
  ('Judges', 15, 20, 'He judged Israel twenty years in the days of the Philistines.'),
  ('Judges', 16, 1, 'Samson went to Gaza, and saw there a prostitute, and went in to her.'),
  ('Judges', 16, 2, 'The Gazites were told, “Samson is here!” They surrounded him and laid wait for him all night in the gate of the city, and were quiet all the night, saying, “Wait until morning light; then we will kill him.”'),
  ('Judges', 16, 3, 'Samson lay until midnight, then arose at midnight and took hold of the doors of the gate of the city, with the two posts, and plucked them up, bar and all, and put them on his shoulders and carried them up to the top of the mountain that is before Hebron.'),
  ('Judges', 16, 4, 'It came to pass afterward that he loved a woman in the valley of Sorek, whose name was Delilah.'),
  ('Judges', 16, 5, 'The lords of the Philistines came up to her and said to her, “Entice him, and see in which his great strength lies, and by what means we may prevail against him, that we may bind him to afflict him; and we will each give you eleven hundred pieces of silver.”'),
  ('Judges', 16, 6, 'Delilah said to Samson, “Please tell me where your great strength lies, and what you might be bound to afflict you.”'),
  ('Judges', 16, 7, 'Samson said to her, “If they bind me with seven green cords that were never dried, then shall I become weak, and be as another man.”'),
  ('Judges', 16, 8, 'Then the lords of the Philistines brought up to her seven green cords which had not been dried, and she bound him with them.'),
  ('Judges', 16, 9, 'Now she had an ambush waiting in the inner room. She said to him, “The Philistines are on you, Samson!” He broke the cords as a flax thread is broken when it touches the fire. So his strength was not known.'),
  ('Judges', 16, 10, 'Delilah said to Samson, “Behold, you have mocked me, and told me lies. Now please tell me how you might be bound.”'),
  ('Judges', 16, 11, 'He said to her, “If they only bind me with new ropes with which no work has been done, then I will become weak, and be as another man.”'),
  ('Judges', 16, 12, 'So Delilah took new ropes and bound him with them, then said to him, “The Philistines are on you, Samson!” The ambush was waiting in the inner room. He broke them off his arms like a thread.'),
  ('Judges', 16, 13, 'Delilah said to Samson, “Until now, you have mocked me and told me lies. Tell me with what you might be bound.” He said to her, “If you weave the seven locks of my head with the fabric on the loom.”'),
  ('Judges', 16, 14, 'She fastened it with the pin, and said to him, “The Philistines are on you, Samson!” He awakened out of his sleep, and plucked away the pin of the beam and the fabric.'),
  ('Judges', 16, 15, 'She said to him, “How can you say, ‘I love you,’ when your heart is not with me? You have mocked me these three times, and have not told me where your great strength lies.”'),
  ('Judges', 16, 16, 'When she pressed him daily with her words and urged him, his soul was troubled to death.'),
  ('Judges', 16, 17, 'He told her all his heart and said to her, “No razor has ever come on my head; for I have been a Nazirite to God from my mother’s womb. If I am shaved, then my strength will go from me and I will become weak, and be like any other man.”'),
  ('Judges', 16, 18, 'When Delilah saw that he had told her all his heart, she sent and called for the lords of the Philistines, saying, “Come up this once, for he has told me all his heart.” Then the lords of the Philistines came up to her and brought the money in their hand.'),
  ('Judges', 16, 19, 'She made him sleep on her knees; and she called for a man and shaved off the seven locks of his head; and she began to afflict him, and his strength went from him.'),
  ('Judges', 16, 20, 'She said, “The Philistines are upon you, Samson!” He awoke out of his sleep, and said, “I will go out as at other times, and shake myself free.” But he didn’t know that the LORD had departed from him.'),
  ('Judges', 16, 21, 'The Philistines laid hold on him and put out his eyes; and they brought him down to Gaza and bound him with fetters of bronze; and he ground at the mill in the prison.'),
  ('Judges', 16, 22, 'However, the hair of his head began to grow again after he was shaved.'),
  ('Judges', 16, 23, 'The lords of the Philistines gathered together to offer a great sacrifice to Dagon their god, and to rejoice; for they said, “Our god has delivered Samson our enemy into our hand.”'),
  ('Judges', 16, 24, 'When the people saw him, they praised their god; for they said, “Our god has delivered our enemy and the destroyer of our country, who has slain many of us, into our hand.”'),
  ('Judges', 16, 25, 'When their hearts were merry, they said, “Call for Samson, that he may entertain us.” They called for Samson out of the prison; and he performed before them. They set him between the pillars;'),
  ('Judges', 16, 26, 'and Samson said to the boy who held him by the hand, “Allow me to feel the pillars on which the house rests, that I may lean on them.”'),
  ('Judges', 16, 27, 'Now the house was full of men and women; and all the lords of the Philistines were there; and there were on the roof about three thousand men and women, who saw while Samson performed.'),
  ('Judges', 16, 28, 'Samson called to the LORD, and said, “Lord GOD, remember me, please, and strengthen me, please, only this once, God, that I may be at once avenged of the Philistines for my two eyes.”'),
  ('Judges', 16, 29, 'Samson took hold of the two middle pillars on which the house rested and leaned on them, the one with his right hand and the other with his left.'),
  ('Judges', 16, 30, 'Samson said, “Let me die with the Philistines!” He bowed himself with all his might; and the house fell on the lords, and on all the people who were in it. So the dead that he killed at his death were more than those who he killed in his life.'),
  ('Judges', 16, 31, 'Then his brothers and all the house of his father came down and took him, and brought him up and buried him between Zorah and Eshtaol in the burial site of Manoah his father. He judged Israel twenty years.'),
  ('Judges', 17, 1, 'There was a man of the hill country of Ephraim, whose name was Micah.'),
  ('Judges', 17, 2, 'He said to his mother, “The eleven hundred pieces of silver that were taken from you, about which you uttered a curse, and also spoke it in my ears—behold, the silver is with me. I took it.” His mother said, “May the LORD bless my son!”'),
  ('Judges', 17, 3, 'He restored the eleven hundred pieces of silver to his mother, then his mother said, “I most certainly dedicate the silver to the LORD from my hand for my son, to make a carved image and a molten image. Now therefore I will restore it to you.”'),
  ('Judges', 17, 4, 'When he restored the money to his mother, his mother took two hundred pieces of silver, and gave them to a silversmith, who made a carved image and a molten image out of it. It was in the house of Micah.'),
  ('Judges', 17, 5, 'The man Micah had a house of gods, and he made an ephod, and teraphim, and consecrated one of his sons, who became his priest.'),
  ('Judges', 17, 6, 'In those days there was no king in Israel. Everyone did that which was right in his own eyes.'),
  ('Judges', 17, 7, 'There was a young man out of Bethlehem Judah, of the family of Judah, who was a Levite; and he lived there.'),
  ('Judges', 17, 8, 'The man departed out of the city, out of Bethlehem Judah, to live where he could find a place, and he came to the hill country of Ephraim, to the house of Micah, as he traveled.'),
  ('Judges', 17, 9, 'Micah said to him, “Where did you come from?” He said to him, “I am a Levite of Bethlehem Judah, and I am looking for a place to live.”'),
  ('Judges', 17, 10, 'Micah said to him, “Dwell with me, and be to me a father and a priest, and I will give you ten pieces of silver per year, a suit of clothing, and your food.” So the Levite went in.'),
  ('Judges', 17, 11, 'The Levite was content to dwell with the man; and the young man was to him as one of his sons.'),
  ('Judges', 17, 12, 'Micah consecrated the Levite, and the young man became his priest, and was in the house of Micah.'),
  ('Judges', 17, 13, 'Then Micah said, “Now I know that the LORD will do good to me, since I have a Levite as my priest.”'),
  ('Judges', 18, 1, 'In those days there was no king in Israel. In those days the tribe of the Danites sought an inheritance to dwell in; for to that day, their inheritance had not fallen to them among the tribes of Israel.'),
  ('Judges', 18, 2, 'The children of Dan sent five men of their family from their whole number, men of valor, from Zorah and from Eshtaol, to spy out the land and to search it. They said to them, “Go, explore the land!” They came to the hill country of Ephraim, to the house of Micah, and lodged there.'),
  ('Judges', 18, 3, 'When they were by the house of Micah, they knew the voice of the young man the Levite; so they went over there and said to him, “Who brought you here? What do you do in this place? What do you have here?”'),
  ('Judges', 18, 4, 'He said to them, “Thus and thus has Micah dealt with me, and he has hired me, and I have become his priest.”'),
  ('Judges', 18, 5, 'They said to him, “Please ask counsel of God, that we may know whether our way which we go shall be prosperous.”'),
  ('Judges', 18, 6, 'The priest said to them, “Go in peace. Your way in which you go is before the LORD.”');
INSERT INTO bible_verses (book_name, chapter, verse, text) VALUES
  ('Judges', 18, 7, 'Then the five men departed and came to Laish and saw the people who were there, how they lived in safety, in the way of the Sidonians, quiet and secure; for there was no one in the land possessing authority, that might put them to shame in anything, and they were far from the Sidonians, and had no dealings with anyone else.'),
  ('Judges', 18, 8, 'They came to their brothers at Zorah and Eshtaol; and their brothers asked them, “What do you say?”'),
  ('Judges', 18, 9, 'They said, “Arise, and let’s go up against them; for we have seen the land, and behold, it is very good. Do you stand still? Don’t be slothful to go and to enter in to possess the land.'),
  ('Judges', 18, 10, 'When you go, you will come to an unsuspecting people, and the land is large; for God has given it into your hand, a place where there is no lack of anything that is in the earth.”'),
  ('Judges', 18, 11, 'The family of the Danites set out from Zorah and Eshtaol with six hundred men armed with weapons of war.'),
  ('Judges', 18, 12, 'They went up and encamped in Kiriath Jearim in Judah. Therefore they call that place Mahaneh Dan to this day. Behold, it is behind Kiriath Jearim.'),
  ('Judges', 18, 13, 'They passed from there to the hill country of Ephraim, and came to the house of Micah.'),
  ('Judges', 18, 14, 'Then the five men who went to spy out the country of Laish answered and said to their brothers, “Do you know that there is in these houses an ephod, and teraphim, and a carved image, and a molten image? Now therefore consider what you have to do.”'),
  ('Judges', 18, 15, 'They went over there and came to the house of the young Levite man, even to the house of Micah, and asked him how he was doing.'),
  ('Judges', 18, 16, 'The six hundred men armed with their weapons of war, who were of the children of Dan, stood by the entrance of the gate.'),
  ('Judges', 18, 17, 'The five men who went to spy out the land went up, and came in there, and took the engraved image, the ephod, the teraphim, and the molten image; and the priest stood by the entrance of the gate with the six hundred men armed with weapons of war.'),
  ('Judges', 18, 18, 'When these went into Micah’s house, and took the engraved image, the ephod, the teraphim, and the molten image, the priest said to them, “What are you doing?”'),
  ('Judges', 18, 19, 'They said to him, “Hold your peace, put your hand on your mouth, and go with us. Be a father and a priest to us. Is it better for you to be priest to the house of one man, or to be priest to a tribe and a family in Israel?”'),
  ('Judges', 18, 20, 'The priest’s heart was glad, and he took the ephod, the teraphim, and the engraved image, and went with the people.'),
  ('Judges', 18, 21, 'So they turned and departed, and put the little ones, the livestock, and the goods before them.'),
  ('Judges', 18, 22, 'When they were a good way from the house of Micah, the men who were in the houses near Micah’s house gathered together and overtook the children of Dan.'),
  ('Judges', 18, 23, 'As they called to the children of Dan, they turned their faces, and said to Micah, “What ails you, that you come with such a company?”'),
  ('Judges', 18, 24, 'He said, “You have taken away my gods which I made, and the priest, and have gone away! What more do I have? How can you ask me, ‘What ails you?’”'),
  ('Judges', 18, 25, 'The children of Dan said to him, “Don’t let your voice be heard among us, lest angry fellows fall on you, and you lose your life, with the lives of your household.”'),
  ('Judges', 18, 26, 'The children of Dan went their way; and when Micah saw that they were too strong for him, he turned and went back to his house.'),
  ('Judges', 18, 27, 'They took that which Micah had made, and the priest whom he had, and came to Laish, to a people quiet and unsuspecting, and struck them with the edge of the sword; then they burned the city with fire.'),
  ('Judges', 18, 28, 'There was no deliverer, because it was far from Sidon, and they had no dealings with anyone else; and it was in the valley that lies by Beth Rehob. They built the city and lived in it.'),
  ('Judges', 18, 29, 'They called the name of the city Dan, after the name of Dan their father, who was born to Israel; however the name of the city used to be Laish.'),
  ('Judges', 18, 30, 'The children of Dan set up for themselves the engraved image; and Jonathan, the son of Gershom, the son of Moses, and his sons were priests to the tribe of the Danites until the day of the captivity of the land.'),
  ('Judges', 18, 31, 'So they set up for themselves Micah’s engraved image which he made, and it remained all the time that God’s house was in Shiloh.'),
  ('Judges', 19, 1, 'In those days, when there was no king in Israel, there was a certain Levite living on the farther side of the hill country of Ephraim, who took for himself a concubine out of Bethlehem Judah.'),
  ('Judges', 19, 2, 'His concubine played the prostitute against him, and went away from him to her father’s house to Bethlehem Judah, and was there for four months.'),
  ('Judges', 19, 3, 'Her husband arose and went after her to speak kindly to her, to bring her again, having his servant with him and a couple of donkeys. She brought him into her father’s house; and when the father of the young lady saw him, he rejoiced to meet him.'),
  ('Judges', 19, 4, 'His father-in-law, the young lady’s father, kept him there; and he stayed with him three days. So they ate and drank, and stayed there.'),
  ('Judges', 19, 5, 'On the fourth day, they got up early in the morning, and he rose up to depart. The young lady’s father said to his son-in-law, “Strengthen your heart with a morsel of bread, and afterward you shall go your way.”'),
  ('Judges', 19, 6, 'So they sat down, ate, and drank, both of them together. Then the young lady’s father said to the man, “Please be pleased to stay all night, and let your heart be merry.”'),
  ('Judges', 19, 7, 'The man rose up to depart; but his father-in-law urged him, and he stayed there again.'),
  ('Judges', 19, 8, 'He arose early in the morning on the fifth day to depart; and the young lady’s father said, “Please strengthen your heart and stay until the day declines;” and they both ate.'),
  ('Judges', 19, 9, 'When the man rose up to depart, he, and his concubine, and his servant, his father-in-law, the young lady’s father, said to him, “Behold, now the day draws toward evening, please stay all night. Behold, the day is ending. Stay here, that your heart may be merry; and tomorrow go on your way early, that you may go home.”'),
  ('Judges', 19, 10, 'But the man wouldn’t stay that night, but he rose up and went near Jebus (also called Jerusalem). With him were a couple of saddled donkeys. His concubine also was with him.'),
  ('Judges', 19, 11, 'When they were by Jebus, the day was far spent; and the servant said to his master, “Please come and let’s enter into this city of the Jebusites, and stay in it.”'),
  ('Judges', 19, 12, 'His master said to him, “We won’t enter into the city of a foreigner that is not of the children of Israel; but we will pass over to Gibeah.”'),
  ('Judges', 19, 13, 'He said to his servant, “Come and let’s draw near to one of these places; and we will lodge in Gibeah, or in Ramah.”'),
  ('Judges', 19, 14, 'So they passed on and went their way; and the sun went down on them near Gibeah, which belongs to Benjamin.'),
  ('Judges', 19, 15, 'They went over there, to go in to stay in Gibeah. He went in, and sat down in the street of the city; for there was no one who took them into his house to stay.'),
  ('Judges', 19, 16, 'Behold, an old man came from his work out of the field at evening. Now the man was from the hill country of Ephraim, and he lived in Gibeah; but the men of the place were Benjamites.'),
  ('Judges', 19, 17, 'He lifted up his eyes, and saw the wayfaring man in the street of the city; and the old man said, “Where are you going? Where did you come from?”'),
  ('Judges', 19, 18, 'He said to him, “We are passing from Bethlehem Judah to the farther side of the hill country of Ephraim. I am from there, and I went to Bethlehem Judah. I am going to the LORD’s house; and there is no one who has taken me into his house.'),
  ('Judges', 19, 19, 'Yet there is both straw and feed for our donkeys; and there is bread and wine also for me, and for your servant, and for the young man who is with your servants. There is no lack of anything.”'),
  ('Judges', 19, 20, 'The old man said, “Peace be to you! Just let me supply all your needs, but don’t sleep in the street.”'),
  ('Judges', 19, 21, 'So he brought him into his house, and gave the donkeys fodder. Then they washed their feet, and ate and drank.'),
  ('Judges', 19, 22, 'As they were making their hearts merry, behold, the men of the city, certain wicked fellows, surrounded the house, beating at the door; and they spoke to the master of the house, the old man, saying, “Bring out the man who came into your house, that we can have sex with him!”'),
  ('Judges', 19, 23, 'The man, the master of the house, went out to them, and said to them, “No, my brothers, please don’t act so wickedly; since this man has come into my house, don’t do this folly.'),
  ('Judges', 19, 24, 'Behold, here is my virgin daughter and his concubine. I will bring them out now. Humble them, and do with them what seems good to you; but to this man don’t do any such folly.”'),
  ('Judges', 19, 25, 'But the men wouldn’t listen to him; so the man grabbed his concubine, and brought her out to them; and they had sex with her, and abused her all night until the morning. When the day began to dawn, they let her go.'),
  ('Judges', 19, 26, 'Then the woman came in the dawning of the day, and fell down at the door of the man’s house where her lord was, until it was light.'),
  ('Judges', 19, 27, 'Her lord rose up in the morning and opened the doors of the house, and went out to go his way; and behold, the woman his concubine had fallen down at the door of the house, with her hands on the threshold.'),
  ('Judges', 19, 28, 'He said to her, “Get up, and let’s get going!” but no one answered. Then he took her up on the donkey; and the man rose up, and went to his place.'),
  ('Judges', 19, 29, 'When he had come into his house, he took a knife and cut up his concubine, and divided her, limb by limb, into twelve pieces, and sent her throughout all the borders of Israel.'),
  ('Judges', 19, 30, 'It was so, that all who saw it said, “Such a deed has not been done or seen from the day that the children of Israel came up out of the land of Egypt to this day! Consider it, take counsel, and speak.”'),
  ('Judges', 20, 1, 'Then all the children of Israel went out, and the congregation was assembled as one man, from Dan even to Beersheba, with the land of Gilead, to the LORD at Mizpah.'),
  ('Judges', 20, 2, 'The chiefs of all the people, even of all the tribes of Israel, presented themselves in the assembly of the people of God, four hundred thousand footmen who drew sword.'),
  ('Judges', 20, 3, '(Now the children of Benjamin heard that the children of Israel had gone up to Mizpah.) The children of Israel said, “Tell us, how did this wickedness happen?”'),
  ('Judges', 20, 4, 'The Levite, the husband of the woman who was murdered, answered, “I came into Gibeah that belongs to Benjamin, I and my concubine, to spend the night.'),
  ('Judges', 20, 5, 'The men of Gibeah rose against me, and surrounded the house by night. They intended to kill me and they raped my concubine, and she is dead.'),
  ('Judges', 20, 6, 'I took my concubine and cut her in pieces, and sent her throughout all the country of the inheritance of Israel; for they have committed lewdness and folly in Israel.'),
  ('Judges', 20, 7, 'Behold, you children of Israel, all of you, give here your advice and counsel.”'),
  ('Judges', 20, 8, 'All the people arose as one man, saying, “None of us will go to his tent, neither will any of us turn to his house.'),
  ('Judges', 20, 9, 'But now this is the thing which we will do to Gibeah: we will go up against it by lot;'),
  ('Judges', 20, 10, 'and we will take ten men of one hundred throughout all the tribes of Israel, and one hundred of one thousand, and a thousand out of ten thousand to get food for the people, that they may do, when they come to Gibeah of Benjamin, according to all the folly that the men of Gibeah have done in Israel.”'),
  ('Judges', 20, 11, 'So all the men of Israel were gathered against the city, knit together as one man.'),
  ('Judges', 20, 12, 'The tribes of Israel sent men through all the tribe of Benjamin, saying, “What wickedness is this that has happened among you?'),
  ('Judges', 20, 13, 'Now therefore deliver up the men, the wicked fellows who are in Gibeah, that we may put them to death and put away evil from Israel.” But Benjamin would not listen to the voice of their brothers, the children of Israel.'),
  ('Judges', 20, 14, 'The children of Benjamin gathered themselves together out of the cities to Gibeah, to go out to battle against the children of Israel.'),
  ('Judges', 20, 15, 'The children of Benjamin were counted on that day out of the cities twenty-six thousand men who drew the sword, in addition to the inhabitants of Gibeah, who were counted seven hundred chosen men.'),
  ('Judges', 20, 16, 'Among all these soldiers there were seven hundred chosen men who were left-handed. Every one of them could sling a stone at a hair and not miss.'),
  ('Judges', 20, 17, 'The men of Israel, besides Benjamin, were counted four hundred thousand men who drew sword. All these were men of war.'),
  ('Judges', 20, 18, 'The children of Israel arose, went up to Bethel, and asked counsel of God. They asked, “Who shall go up for us first to battle against the children of Benjamin?” The LORD said, “Judah first.”'),
  ('Judges', 20, 19, 'The children of Israel rose up in the morning and encamped against Gibeah.'),
  ('Judges', 20, 20, 'The men of Israel went out to battle against Benjamin; and the men of Israel set the battle in array against them at Gibeah.'),
  ('Judges', 20, 21, 'The children of Benjamin came out of Gibeah, and on that day destroyed twenty-two thousand of the Israelite men down to the ground.'),
  ('Judges', 20, 22, 'The people, the men of Israel, encouraged themselves, and set the battle again in array in the place where they set themselves in array the first day.'),
  ('Judges', 20, 23, 'The children of Israel went up and wept before the LORD until evening; and they asked of the LORD, saying, “Shall I again draw near to battle against the children of Benjamin my brother?” The LORD said, “Go up against him.”'),
  ('Judges', 20, 24, 'The children of Israel came near against the children of Benjamin the second day.'),
  ('Judges', 20, 25, 'Benjamin went out against them out of Gibeah the second day, and destroyed down to the ground of the children of Israel again eighteen thousand men. All these drew the sword.'),
  ('Judges', 20, 26, 'Then all the children of Israel and all the people went up, and came to Bethel, and wept, and sat there before the LORD, and fasted that day until evening; then they offered burnt offerings and peace offerings before the LORD.'),
  ('Judges', 20, 27, 'The children of Israel asked the LORD (for the ark of the covenant of God was there in those days,'),
  ('Judges', 20, 28, 'and Phinehas, the son of Eleazar, the son of Aaron, stood before it in those days), saying, “Shall I yet again go out to battle against the children of Benjamin my brother, or shall I cease?” The LORD said, “Go up; for tomorrow I will deliver him into your hand.”'),
  ('Judges', 20, 29, 'Israel set ambushes all around Gibeah.'),
  ('Judges', 20, 30, 'The children of Israel went up against the children of Benjamin on the third day, and set themselves in array against Gibeah, as at other times.'),
  ('Judges', 20, 31, 'The children of Benjamin went out against the people, and were drawn away from the city; and they began to strike and kill of the people as at other times, in the highways, of which one goes up to Bethel and the other to Gibeah, in the field, about thirty men of Israel.'),
  ('Judges', 20, 32, 'The children of Benjamin said, “They are struck down before us, as at the first.” But the children of Israel said, “Let’s flee, and draw them away from the city to the highways.”'),
  ('Judges', 20, 33, 'All the men of Israel rose up out of their place and set themselves in array at Baal Tamar. Then the ambushers of Israel broke out of their place, even out of Maareh Geba.'),
  ('Judges', 20, 34, 'Ten thousand chosen men out of all Israel came over against Gibeah, and the battle was severe; but they didn’t know that disaster was close to them.'),
  ('Judges', 20, 35, 'The LORD struck Benjamin before Israel; and the children of Israel destroyed of Benjamin that day twenty-five thousand one hundred men. All these drew the sword.'),
  ('Judges', 20, 36, 'So the children of Benjamin saw that they were struck, for the men of Israel yielded to Benjamin because they trusted the ambushers whom they had set against Gibeah.'),
  ('Judges', 20, 37, 'The ambushers hurried, and rushed on Gibeah; then the ambushers spread out, and struck all the city with the edge of the sword.'),
  ('Judges', 20, 38, 'Now the appointed sign between the men of Israel and the ambushers was that they should make a great cloud of smoke rise up out of the city.'),
  ('Judges', 20, 39, 'The men of Israel turned in the battle, and Benjamin began to strike and kill of the men of Israel about thirty persons; for they said, “Surely they are struck down before us, as in the first battle.”'),
  ('Judges', 20, 40, 'But when the cloud began to arise up out of the city in a pillar of smoke, the Benjamites looked behind them; and behold, the whole city went up in smoke to the sky.'),
  ('Judges', 20, 41, 'The men of Israel turned, and the men of Benjamin were dismayed; for they saw that disaster had come on them.'),
  ('Judges', 20, 42, 'Therefore they turned their backs before the men of Israel to the way of the wilderness, but the battle followed hard after them; and those who came out of the cities destroyed them in the middle of it.'),
  ('Judges', 20, 43, 'They surrounded the Benjamites, chased them, and trod them down at their resting place, as far as near Gibeah toward the sunrise.'),
  ('Judges', 20, 44, 'Eighteen thousand men of Benjamin fell; all these were men of valor.'),
  ('Judges', 20, 45, 'They turned and fled toward the wilderness to the rock of Rimmon. They gleaned five thousand men of them in the highways, and followed hard after them to Gidom, and struck two thousand men of them.');
INSERT INTO bible_verses (book_name, chapter, verse, text) VALUES
  ('Judges', 20, 46, 'So that all who fell that day of Benjamin were twenty-five thousand men who drew the sword. All these were men of valor.'),
  ('Judges', 20, 47, 'But six hundred men turned and fled toward the wilderness to the rock of Rimmon, and stayed in the rock of Rimmon four months.'),
  ('Judges', 20, 48, 'The men of Israel turned again on the children of Benjamin, and struck them with the edge of the sword—including the entire city, the livestock, and all that they found. Moreover they set all the cities which they found on fire.'),
  ('Judges', 21, 1, 'Now the men of Israel had sworn in Mizpah, saying, “None of us will give his daughter to Benjamin as a wife.”'),
  ('Judges', 21, 2, 'The people came to Bethel and sat there until evening before God, and lifted up their voices, and wept severely.'),
  ('Judges', 21, 3, 'They said, “The LORD, the God of Israel, why has this happened in Israel, that there should be one tribe lacking in Israel today?”'),
  ('Judges', 21, 4, 'On the next day, the people rose early and built an altar there, and offered burnt offerings and peace offerings.'),
  ('Judges', 21, 5, 'The children of Israel said, “Who is there among all the tribes of Israel who didn’t come up in the assembly to the LORD?” For they had made a great oath concerning him who didn’t come up to the LORD to Mizpah, saying, “He shall surely be put to death.”'),
  ('Judges', 21, 6, 'The children of Israel grieved for Benjamin their brother, and said, “There is one tribe cut off from Israel today.'),
  ('Judges', 21, 7, 'How shall we provide wives for those who remain, since we have sworn by the LORD that we will not give them of our daughters to wives?”'),
  ('Judges', 21, 8, 'They said, “What one is there of the tribes of Israel who didn’t come up to the LORD to Mizpah?” Behold, no one came from Jabesh Gilead to the camp to the assembly.'),
  ('Judges', 21, 9, 'For when the people were counted, behold, there were none of the inhabitants of Jabesh Gilead there.'),
  ('Judges', 21, 10, 'The congregation sent twelve thousand of the most valiant men there, and commanded them, saying, “Go and strike the inhabitants of Jabesh Gilead with the edge of the sword, with the women and the little ones.'),
  ('Judges', 21, 11, 'This is the thing that you shall do: you shall utterly destroy every male, and every woman who has lain with a man.”'),
  ('Judges', 21, 12, 'They found among the inhabitants of Jabesh Gilead four hundred young virgins who had not known man by lying with him; and they brought them to the camp to Shiloh, which is in the land of Canaan.'),
  ('Judges', 21, 13, 'The whole congregation sent and spoke to the children of Benjamin who were in the rock of Rimmon, and proclaimed peace to them.'),
  ('Judges', 21, 14, 'Benjamin returned at that time; and they gave them the women whom they had saved alive of the women of Jabesh Gilead. There still weren’t enough for them.'),
  ('Judges', 21, 15, 'The people grieved for Benjamin, because the LORD had made a breach in the tribes of Israel.'),
  ('Judges', 21, 16, 'Then the elders of the congregation said, “How shall we provide wives for those who remain, since the women are destroyed out of Benjamin?”'),
  ('Judges', 21, 17, 'They said, “There must be an inheritance for those who are escaped of Benjamin, that a tribe not be blotted out from Israel.'),
  ('Judges', 21, 18, 'However, we may not give them wives of our daughters, for the children of Israel had sworn, saying, ‘Cursed is he who gives a wife to Benjamin.’”'),
  ('Judges', 21, 19, 'They said, “Behold, there is a feast of the LORD from year to year in Shiloh, which is on the north of Bethel, on the east side of the highway that goes up from Bethel to Shechem, and on the south of Lebonah.”'),
  ('Judges', 21, 20, 'They commanded the children of Benjamin, saying, “Go and lie in wait in the vineyards,'),
  ('Judges', 21, 21, 'and see, and behold, if the daughters of Shiloh come out to dance in the dances, then come out of the vineyards, and each man catch his wife of the daughters of Shiloh, and go to the land of Benjamin.'),
  ('Judges', 21, 22, 'It shall be, when their fathers or their brothers come to complain to us, that we will say to them, ‘Grant them graciously to us, because we didn’t take for each man his wife in battle, neither did you give them to them; otherwise you would now be guilty.’”'),
  ('Judges', 21, 23, 'The children of Benjamin did so, and took wives for themselves according to their number, of those who danced, whom they carried off. They went and returned to their inheritance, built the cities, and lived in them.'),
  ('Judges', 21, 24, 'The children of Israel departed from there at that time, every man to his tribe and to his family, and they each went out from there to his own inheritance.'),
  ('Judges', 21, 25, 'In those days there was no king in Israel. Everyone did that which was right in his own eyes.'),
  ('Ruth', 1, 1, 'In the days when the judges judged, there was a famine in the land. A certain man of Bethlehem Judah went to live in the country of Moab with his wife and his two sons.'),
  ('Ruth', 1, 2, 'The name of the man was Elimelech, and the name of his wife Naomi. The names of his two sons were Mahlon and Chilion, Ephrathites of Bethlehem Judah. They came into the country of Moab and lived there.'),
  ('Ruth', 1, 3, 'Elimelech, Naomi’s husband, died; and she was left with her two sons.'),
  ('Ruth', 1, 4, 'They took for themselves wives of the women of Moab. The name of the one was Orpah, and the name of the other was Ruth. They lived there about ten years.'),
  ('Ruth', 1, 5, 'Mahlon and Chilion both died, and the woman was bereaved of her two children and of her husband.'),
  ('Ruth', 1, 6, 'Then she arose with her daughters-in-law, that she might return from the country of Moab; for she had heard in the country of Moab how the LORD had visited his people in giving them bread.'),
  ('Ruth', 1, 7, 'She went out of the place where she was, and her two daughters-in-law with her. They went on the way to return to the land of Judah.'),
  ('Ruth', 1, 8, 'Naomi said to her two daughters-in-law, “Go, return each of you to her mother’s house. May the LORD deal kindly with you, as you have dealt with the dead and with me.'),
  ('Ruth', 1, 9, 'May the LORD grant you that you may find rest, each of you in the house of her husband.” Then she kissed them, and they lifted up their voices, and wept.'),
  ('Ruth', 1, 10, 'They said to her, “No, but we will return with you to your people.”'),
  ('Ruth', 1, 11, 'Naomi said, “Go back, my daughters. Why do you want to go with me? Do I still have sons in my womb, that they may be your husbands?'),
  ('Ruth', 1, 12, 'Go back, my daughters, go your way; for I am too old to have a husband. If I should say, ‘I have hope,’ if I should even have a husband tonight, and should also bear sons,'),
  ('Ruth', 1, 13, 'would you then wait until they were grown? Would you then refrain from having husbands? No, my daughters, for it grieves me seriously for your sakes, for the LORD’s hand has gone out against me.”'),
  ('Ruth', 1, 14, 'They lifted up their voices and wept again; then Orpah kissed her mother-in-law, but Ruth stayed with her.'),
  ('Ruth', 1, 15, 'She said, “Behold, your sister-in-law has gone back to her people and to her god. Follow your sister-in-law.”'),
  ('Ruth', 1, 16, 'Ruth said, “Don’t urge me to leave you, and to return from following you, for where you go, I will go; and where you stay, I will stay. Your people will be my people, and your God my God.'),
  ('Ruth', 1, 17, 'Where you die, I will die, and there I will be buried. May the LORD do so to me, and more also, if anything but death parts you and me.”'),
  ('Ruth', 1, 18, 'When Naomi saw that she was determined to go with her, she stopped urging her.'),
  ('Ruth', 1, 19, 'So they both went until they came to Bethlehem. When they had come to Bethlehem, all the city was excited about them, and they asked, “Is this Naomi?”'),
  ('Ruth', 1, 20, 'She said to them, “Don’t call me Naomi. Call me Mara, for the Almighty has dealt very bitterly with me.'),
  ('Ruth', 1, 21, 'I went out full, and the LORD has brought me home again empty. Why do you call me Naomi, since the LORD has testified against me, and the Almighty has afflicted me?”'),
  ('Ruth', 1, 22, 'So Naomi returned, and Ruth the Moabitess, her daughter-in-law, with her, who returned out of the country of Moab. They came to Bethlehem in the beginning of barley harvest.'),
  ('Ruth', 2, 1, 'Naomi had a relative of her husband’s, a mighty man of wealth, of the family of Elimelech, and his name was Boaz.'),
  ('Ruth', 2, 2, 'Ruth the Moabitess said to Naomi, “Let me now go to the field, and glean among the ears of grain after him in whose sight I find favor.” She said to her, “Go, my daughter.”'),
  ('Ruth', 2, 3, 'She went, and came and gleaned in the field after the reapers; and she happened to come to the portion of the field belonging to Boaz, who was of the family of Elimelech.'),
  ('Ruth', 2, 4, 'Behold, Boaz came from Bethlehem, and said to the reapers, “May the LORD be with you.” They answered him, “May the LORD bless you.”'),
  ('Ruth', 2, 5, 'Then Boaz said to his servant who was set over the reapers, “Whose young lady is this?”'),
  ('Ruth', 2, 6, 'The servant who was set over the reapers answered, “It is the Moabite lady who came back with Naomi out of the country of Moab.'),
  ('Ruth', 2, 7, 'She said, ‘Please let me glean and gather after the reapers among the sheaves.’ So she came, and has continued even from the morning until now, except that she rested a little in the house.”'),
  ('Ruth', 2, 8, 'Then Boaz said to Ruth, “Listen, my daughter. Don’t go to glean in another field, and don’t go from here, but stay here close to my maidens.'),
  ('Ruth', 2, 9, 'Let your eyes be on the field that they reap, and go after them. Haven’t I commanded the young men not to touch you? When you are thirsty, go to the vessels, and drink from that which the young men have drawn.”'),
  ('Ruth', 2, 10, 'Then she fell on her face and bowed herself to the ground, and said to him, “Why have I found favor in your sight, that you should take knowledge of me, since I am a foreigner?”'),
  ('Ruth', 2, 11, 'Boaz answered her, “I have been told all about what you have done for your mother-in-law since the death of your husband, and how you have left your father, your mother, and the land of your birth, and have come to a people that you didn’t know before.'),
  ('Ruth', 2, 12, 'May the LORD repay your work, and a full reward be given to you from the LORD, the God of Israel, under whose wings you have come to take refuge.”'),
  ('Ruth', 2, 13, 'Then she said, “Let me find favor in your sight, my lord, because you have comforted me, and because you have spoken kindly to your servant, though I am not as one of your servants.”'),
  ('Ruth', 2, 14, 'At meal time Boaz said to her, “Come here, and eat some bread, and dip your morsel in the vinegar.” She sat beside the reapers, and they passed her parched grain. She ate, was satisfied, and left some of it.'),
  ('Ruth', 2, 15, 'When she had risen up to glean, Boaz commanded his young men, saying, “Let her glean even among the sheaves, and don’t reproach her.'),
  ('Ruth', 2, 16, 'Also pull out some for her from the bundles, and leave it. Let her glean, and don’t rebuke her.”'),
  ('Ruth', 2, 17, 'So she gleaned in the field until evening; and she beat out that which she had gleaned, and it was about an ephah of barley.'),
  ('Ruth', 2, 18, 'She took it up, and went into the city. Then her mother-in-law saw what she had gleaned; and she brought out and gave to her that which she had left after she had enough.'),
  ('Ruth', 2, 19, 'Her mother-in-law said to her, “Where have you gleaned today? Where have you worked? Blessed be he who noticed you.” She told her mother-in-law with whom she had worked, “The man’s name with whom I worked today is Boaz.”'),
  ('Ruth', 2, 20, 'Naomi said to her daughter-in-law, “May he be blessed by the LORD, who has not abandoned his kindness to the living and to the dead.” Naomi said to her, “The man is a close relative to us, one of our near kinsmen.”'),
  ('Ruth', 2, 21, 'Ruth the Moabitess said, “Yes, he said to me, ‘You shall stay close to my young men until they have finished all my harvest.’”'),
  ('Ruth', 2, 22, 'Naomi said to Ruth her daughter-in-law, “It is good, my daughter, that you go out with his maidens, and that they not harm you in any other field.”'),
  ('Ruth', 2, 23, 'So she stayed close to the maidens of Boaz, to glean to the end of barley harvest and of wheat harvest; and she lived with her mother-in-law.'),
  ('Ruth', 3, 1, 'Naomi her mother-in-law said to her, “My daughter, shall I not seek rest for you, that it may be well with you?'),
  ('Ruth', 3, 2, 'Now isn’t Boaz our kinsman, with whose maidens you were? Behold, he will be winnowing barley tonight on the threshing floor.'),
  ('Ruth', 3, 3, 'Therefore wash yourself, anoint yourself, get dressed, and go down to the threshing floor; but don’t make yourself known to the man until he has finished eating and drinking.'),
  ('Ruth', 3, 4, 'It shall be, when he lies down, that you shall note the place where he is lying. Then you shall go in, uncover his feet, and lie down. Then he will tell you what to do.”'),
  ('Ruth', 3, 5, 'She said to her, “All that you say, I will do.”'),
  ('Ruth', 3, 6, 'She went down to the threshing floor, and did everything that her mother-in-law told her.'),
  ('Ruth', 3, 7, 'When Boaz had eaten and drunk, and his heart was merry, he went to lie down at the end of the heap of grain. She came softly, uncovered his feet, and lay down.'),
  ('Ruth', 3, 8, 'At midnight, the man was startled and turned himself; and behold, a woman lay at his feet.'),
  ('Ruth', 3, 9, 'He said, “Who are you?” She answered, “I am Ruth your servant. Therefore spread the corner of your garment over your servant; for you are a near kinsman.”'),
  ('Ruth', 3, 10, 'He said, “You are blessed by the LORD, my daughter. You have shown more kindness in the latter end than at the beginning, because you didn’t follow young men, whether poor or rich.'),
  ('Ruth', 3, 11, 'Now, my daughter, don’t be afraid. I will do to you all that you say; for all the city of my people knows that you are a worthy woman.'),
  ('Ruth', 3, 12, 'Now it is true that I am a near kinsman. However, there is a kinsman nearer than I.'),
  ('Ruth', 3, 13, 'Stay this night, and in the morning, if he will perform for you the part of a kinsman, good. Let him do the kinsman’s duty. But if he will not do the duty of a kinsman for you, then I will do the duty of a kinsman for you, as the LORD lives. Lie down until the morning.”'),
  ('Ruth', 3, 14, 'She lay at his feet until the morning, then she rose up before one could discern another. For he said, “Let it not be known that the woman came to the threshing floor.”'),
  ('Ruth', 3, 15, 'He said, “Bring the mantle that is on you, and hold it.” She held it; and he measured six measures of barley, and laid it on her; then he went into the city.'),
  ('Ruth', 3, 16, 'When she came to her mother-in-law, she said, “How did it go, my daughter?” She told her all that the man had done for her.'),
  ('Ruth', 3, 17, 'She said, “He gave me these six measures of barley; for he said, ‘Don’t go empty to your mother-in-law.’”'),
  ('Ruth', 3, 18, 'Then she said, “Wait, my daughter, until you know what will happen; for the man will not rest until he has settled this today.”'),
  ('Ruth', 4, 1, 'Now Boaz went up to the gate and sat down there. Behold, the near kinsman of whom Boaz spoke came by. Boaz said to him, “Come over here, friend, and sit down!” He came over, and sat down.'),
  ('Ruth', 4, 2, 'Boaz took ten men of the elders of the city, and said, “Sit down here,” and they sat down.'),
  ('Ruth', 4, 3, 'He said to the near kinsman, “Naomi, who has come back out of the country of Moab, is selling the parcel of land, which was our brother Elimelech’s.'),
  ('Ruth', 4, 4, 'I thought I should tell you, saying, ‘Buy it before those who sit here, and before the elders of my people.’ If you will redeem it, redeem it; but if you will not redeem it, then tell me, that I may know. For there is no one to redeem it besides you; and I am after you.” He said, “I will redeem it.”'),
  ('Ruth', 4, 5, 'Then Boaz said, “On the day you buy the field from the hand of Naomi, you must buy it also from Ruth the Moabitess, the wife of the dead, to raise up the name of the dead on his inheritance.”'),
  ('Ruth', 4, 6, 'The near kinsman said, “I can’t redeem it for myself, lest I endanger my own inheritance. Take my right of redemption for yourself; for I can’t redeem it.”'),
  ('Ruth', 4, 7, 'Now this was the custom in former time in Israel concerning redeeming and concerning exchanging, to confirm all things: a man took off his sandal, and gave it to his neighbor; and this was the way of formalizing transactions in Israel.'),
  ('Ruth', 4, 8, 'So the near kinsman said to Boaz, “Buy it for yourself,” then he took off his sandal.'),
  ('Ruth', 4, 9, 'Boaz said to the elders and to all the people, “You are witnesses today, that I have bought all that was Elimelech’s, and all that was Chilion’s and Mahlon’s, from the hand of Naomi.');
INSERT INTO bible_verses (book_name, chapter, verse, text) VALUES
  ('Ruth', 4, 10, 'Moreover, Ruth the Moabitess, the wife of Mahlon, I have purchased to be my wife, to raise up the name of the dead on his inheritance, that the name of the dead may not be cut off from among his brothers and from the gate of his place. You are witnesses today.”'),
  ('Ruth', 4, 11, 'All the people who were in the gate, and the elders, said, “We are witnesses. May the LORD make the woman who has come into your house like Rachel and like Leah, which both built the house of Israel; and treat you worthily in Ephrathah, and be famous in Bethlehem.'),
  ('Ruth', 4, 12, 'Let your house be like the house of Perez, whom Tamar bore to Judah, of the offspring which the LORD will give you by this young woman.”'),
  ('Ruth', 4, 13, 'So Boaz took Ruth and she became his wife; and he went in to her, and the LORD enabled her to conceive, and she bore a son.'),
  ('Ruth', 4, 14, 'The women said to Naomi, “Blessed be the LORD, who has not left you today without a near kinsman. Let his name be famous in Israel.'),
  ('Ruth', 4, 15, 'He shall be to you a restorer of life and sustain you in your old age; for your daughter-in-law, who loves you, who is better to you than seven sons, has given birth to him.”'),
  ('Ruth', 4, 16, 'Naomi took the child, laid him in her bosom, and became nurse to him.'),
  ('Ruth', 4, 17, 'The women, her neighbors, gave him a name, saying, “A son is born to Naomi”. They named him Obed. He is the father of Jesse, the father of David.'),
  ('Ruth', 4, 18, 'Now this is the history of the generations of Perez: Perez became the father of Hezron,'),
  ('Ruth', 4, 19, 'and Hezron became the father of Ram, and Ram became the father of Amminadab,'),
  ('Ruth', 4, 20, 'and Amminadab became the father of Nahshon, and Nahshon became the father of Salmon,'),
  ('Ruth', 4, 21, 'and Salmon became the father of Boaz, and Boaz became the father of Obed,'),
  ('Ruth', 4, 22, 'and Obed became the father of Jesse, and Jesse became the father of David.'),
  ('1 Samuel', 1, 1, 'Now there was a certain man of Ramathaim Zophim, of the hill country of Ephraim, and his name was Elkanah, the son of Jeroham, the son of Elihu, the son of Tohu, the son of Zuph, an Ephraimite.'),
  ('1 Samuel', 1, 2, 'He had two wives. The name of one was Hannah, and the name of the other Peninnah. Peninnah had children, but Hannah had no children.'),
  ('1 Samuel', 1, 3, 'This man went up out of his city from year to year to worship and to sacrifice to the LORD of Armies in Shiloh. The two sons of Eli, Hophni and Phinehas, priests to the LORD, were there.'),
  ('1 Samuel', 1, 4, 'When the day came that Elkanah sacrificed, he gave portions to Peninnah his wife and to all her sons and her daughters;'),
  ('1 Samuel', 1, 5, 'but he gave a double portion to Hannah, for he loved Hannah, but the LORD had shut up her womb.'),
  ('1 Samuel', 1, 6, 'Her rival provoked her severely, to irritate her, because the LORD had shut up her womb.'),
  ('1 Samuel', 1, 7, 'So year by year, when she went up to the LORD’s house, her rival provoked her. Therefore she wept, and didn’t eat.'),
  ('1 Samuel', 1, 8, 'Elkanah her husband said to her, “Hannah, why do you weep? Why don’t you eat? Why is your heart grieved? Am I not better to you than ten sons?”'),
  ('1 Samuel', 1, 9, 'So Hannah rose up after they had finished eating and drinking in Shiloh. Now Eli the priest was sitting on his seat by the doorpost of the LORD’s temple.'),
  ('1 Samuel', 1, 10, 'She was in bitterness of soul, and prayed to the LORD, weeping bitterly.'),
  ('1 Samuel', 1, 11, 'She vowed a vow, and said, “LORD of Armies, if you will indeed look at the affliction of your servant and remember me, and not forget your servant, but will give to your servant a boy, then I will give him to the LORD all the days of his life, and no razor shall come on his head.”'),
  ('1 Samuel', 1, 12, 'As she continued praying before the LORD, Eli saw her mouth.'),
  ('1 Samuel', 1, 13, 'Now Hannah spoke in her heart. Only her lips moved, but her voice was not heard. Therefore Eli thought she was drunk.'),
  ('1 Samuel', 1, 14, 'Eli said to her, “How long will you be drunk? Get rid of your wine!”'),
  ('1 Samuel', 1, 15, 'Hannah answered, “No, my lord, I am a woman of a sorrowful spirit. I have not been drinking wine or strong drink, but I poured out my soul before the LORD.'),
  ('1 Samuel', 1, 16, 'Don’t consider your servant a wicked woman; for I have been speaking out of the abundance of my complaint and my provocation.”'),
  ('1 Samuel', 1, 17, 'Then Eli answered, “Go in peace; and may the God of Israel grant your petition that you have asked of him.”'),
  ('1 Samuel', 1, 18, 'She said, “Let your servant find favor in your sight.” So the woman went her way and ate; and her facial expression wasn’t sad any more.'),
  ('1 Samuel', 1, 19, 'They rose up in the morning early and worshiped the LORD, then returned and came to their house to Ramah. Then Elkanah knew Hannah his wife; and the LORD remembered her.'),
  ('1 Samuel', 1, 20, 'When the time had come, Hannah conceived, and bore a son; and she named him Samuel, saying, “Because I have asked him of the LORD.”'),
  ('1 Samuel', 1, 21, 'The man Elkanah, and all his house, went up to offer to the LORD the yearly sacrifice and his vow.'),
  ('1 Samuel', 1, 22, 'But Hannah didn’t go up, for she said to her husband, “Not until the child is weaned; then I will bring him, that he may appear before the LORD, and stay there forever.”'),
  ('1 Samuel', 1, 23, 'Elkanah her husband said to her, “Do what seems good to you. Wait until you have weaned him; only may the LORD establish his word.” So the woman waited and nursed her son until she weaned him.'),
  ('1 Samuel', 1, 24, 'When she had weaned him, she took him up with her, with three bulls, and one ephah of meal, and a container of wine, and brought him to the LORD’s house in Shiloh. The child was young.'),
  ('1 Samuel', 1, 25, 'They killed the bull, and brought the child to Eli.'),
  ('1 Samuel', 1, 26, 'She said, “Oh, my lord, as your soul lives, my lord, I am the woman who stood by you here, praying to the LORD.'),
  ('1 Samuel', 1, 27, 'I prayed for this child, and the LORD has given me my petition which I asked of him.'),
  ('1 Samuel', 1, 28, 'Therefore I have also given him to the LORD. As long as he lives he is given to the LORD.” He worshiped the LORD there.'),
  ('1 Samuel', 2, 1, 'Hannah prayed, and said, “My heart exults in the LORD! My horn is exalted in the LORD. My mouth is enlarged over my enemies, because I rejoice in your salvation.'),
  ('1 Samuel', 2, 2, 'There is no one as holy as the LORD, for there is no one besides you, nor is there any rock like our God.'),
  ('1 Samuel', 2, 3, '“Don’t keep talking so exceedingly proudly. Don’t let arrogance come out of your mouth, for the LORD is a God of knowledge. By him actions are weighed.'),
  ('1 Samuel', 2, 4, '“The bows of the mighty men are broken. Those who stumbled are armed with strength.'),
  ('1 Samuel', 2, 5, 'Those who were full have hired themselves out for bread. Those who were hungry are satisfied. Yes, the barren has borne seven. She who has many children languishes.'),
  ('1 Samuel', 2, 6, '“The LORD kills and makes alive. He brings down to Sheol and brings up.'),
  ('1 Samuel', 2, 7, 'The LORD makes poor and makes rich. He brings low, he also lifts up.'),
  ('1 Samuel', 2, 8, 'He raises up the poor out of the dust. He lifts up the needy from the dunghill to make them sit with princes and inherit the throne of glory. For the pillars of the earth are the LORD’s. He has set the world on them.'),
  ('1 Samuel', 2, 9, 'He will keep the feet of his holy ones, but the wicked will be put to silence in darkness; for no man will prevail by strength.'),
  ('1 Samuel', 2, 10, 'Those who strive with the LORD shall be broken to pieces. He will thunder against them in the sky. “The LORD will judge the ends of the earth. He will give strength to his king, and exalt the horn of his anointed.”'),
  ('1 Samuel', 2, 11, 'Elkanah went to Ramah to his house. The child served the LORD before Eli the priest.'),
  ('1 Samuel', 2, 12, 'Now the sons of Eli were wicked men. They didn’t know the LORD.'),
  ('1 Samuel', 2, 13, 'The custom of the priests with the people was that when anyone offered a sacrifice, the priest’s servant came while the meat was boiling, with a fork of three teeth in his hand;'),
  ('1 Samuel', 2, 14, 'and he stabbed it into the pan, or kettle, or cauldron, or pot. The priest took all that the fork brought up for himself. They did this to all the Israelites who came there to Shiloh.'),
  ('1 Samuel', 2, 15, 'Yes, before they burned the fat, the priest’s servant came, and said to the man who sacrificed, “Give meat to roast for the priest; for he will not accept boiled meat from you, but raw.”'),
  ('1 Samuel', 2, 16, 'If the man said to him, “Let the fat be burned first, and then take as much as your soul desires;” then he would say, “No, but you shall give it to me now; and if not, I will take it by force.”'),
  ('1 Samuel', 2, 17, 'The sin of the young men was very great before the LORD; for the men despised the LORD’s offering.'),
  ('1 Samuel', 2, 18, 'But Samuel ministered before the LORD, being a child, clothed with a linen ephod.'),
  ('1 Samuel', 2, 19, 'Moreover his mother made him a little robe, and brought it to him from year to year when she came up with her husband to offer the yearly sacrifice.'),
  ('1 Samuel', 2, 20, 'Eli blessed Elkanah and his wife, and said, “May the LORD give you offspring from this woman for the petition which was asked of the LORD.” Then they went to their own home.'),
  ('1 Samuel', 2, 21, 'The LORD visited Hannah, and she conceived and bore three sons and two daughters. The child Samuel grew before the LORD.'),
  ('1 Samuel', 2, 22, 'Now Eli was very old; and he heard all that his sons did to all Israel, and how that they slept with the women who served at the door of the Tent of Meeting.'),
  ('1 Samuel', 2, 23, 'He said to them, “Why do you do such things? For I hear of your evil dealings from all these people.'),
  ('1 Samuel', 2, 24, 'No, my sons; for it is not a good report that I hear! You make the LORD’s people disobey.'),
  ('1 Samuel', 2, 25, 'If one man sins against another, God will judge him; but if a man sins against the LORD, who will intercede for him?” Notwithstanding, they didn’t listen to the voice of their father, because the LORD intended to kill them.'),
  ('1 Samuel', 2, 26, 'The child Samuel grew on, and increased in favor both with the LORD and also with men.'),
  ('1 Samuel', 2, 27, 'A man of God came to Eli and said to him, “The LORD says, ‘Did I reveal myself to the house of your father when they were in Egypt in bondage to Pharaoh’s house?'),
  ('1 Samuel', 2, 28, 'Didn’t I choose him out of all the tribes of Israel to be my priest, to go up to my altar, to burn incense, to wear an ephod before me? Didn’t I give to the house of your father all the offerings of the children of Israel made by fire?'),
  ('1 Samuel', 2, 29, 'Why do you kick at my sacrifice and at my offering, which I have commanded in my habitation, and honor your sons above me, to make yourselves fat with the best of all the offerings of Israel my people?’'),
  ('1 Samuel', 2, 30, '“Therefore the LORD, the God of Israel, says, ‘I said indeed that your house and the house of your father should walk before me forever.’ But now the LORD says, ‘Far be it from me; for those who honor me I will honor, and those who despise me will be cursed.'),
  ('1 Samuel', 2, 31, 'Behold, the days come that I will cut off your arm and the arm of your father’s house, that there will not be an old man in your house.'),
  ('1 Samuel', 2, 32, 'You will see the affliction of my habitation, in all the wealth which I will give Israel. There shall not be an old man in your house forever.'),
  ('1 Samuel', 2, 33, 'The man of yours whom I don’t cut off from my altar will consume your eyes and grieve your heart. All the increase of your house will die in the flower of their age.'),
  ('1 Samuel', 2, 34, 'This will be the sign to you that will come on your two sons, on Hophni and Phinehas: in one day they will both die.'),
  ('1 Samuel', 2, 35, 'I will raise up a faithful priest for myself who will do according to that which is in my heart and in my mind. I will build him a sure house. He will walk before my anointed forever.'),
  ('1 Samuel', 2, 36, 'It will happen that everyone who is left in your house will come and bow down to him for a piece of silver and a loaf of bread, and will say, “Please put me into one of the priests’ offices, that I may eat a morsel of bread.”’”'),
  ('1 Samuel', 3, 1, 'The child Samuel ministered to the LORD before Eli. The LORD’s word was rare in those days. There were not many visions, then.'),
  ('1 Samuel', 3, 2, 'At that time, when Eli was laid down in his place (now his eyes had begun to grow dim, so that he could not see),'),
  ('1 Samuel', 3, 3, 'and God’s lamp hadn’t yet gone out, and Samuel had laid down in the LORD’s temple where God’s ark was,'),
  ('1 Samuel', 3, 4, 'The LORD called Samuel. He said, “Here I am.”'),
  ('1 Samuel', 3, 5, 'He ran to Eli and said, “Here I am; for you called me.” He said, “I didn’t call. Lie down again.” He went and lay down.'),
  ('1 Samuel', 3, 6, 'The LORD called yet again, “Samuel!” Samuel arose and went to Eli and said, “Here I am; for you called me.” He answered, “I didn’t call, my son. Lie down again.”'),
  ('1 Samuel', 3, 7, 'Now Samuel didn’t yet know the LORD, neither was the LORD’s word yet revealed to him.'),
  ('1 Samuel', 3, 8, 'The LORD called Samuel again the third time. He arose and went to Eli and said, “Here I am; for you called me.” Eli perceived that the LORD had called the child.'),
  ('1 Samuel', 3, 9, 'Therefore Eli said to Samuel, “Go, lie down. It shall be, if he calls you, that you shall say, ‘Speak, LORD; for your servant hears.’” So Samuel went and lay down in his place.'),
  ('1 Samuel', 3, 10, 'The LORD came, and stood, and called as at other times, “Samuel! Samuel!” Then Samuel said, “Speak; for your servant hears.”'),
  ('1 Samuel', 3, 11, 'The LORD said to Samuel, “Behold, I will do a thing in Israel at which both the ears of everyone who hears it will tingle.'),
  ('1 Samuel', 3, 12, 'In that day I will perform against Eli all that I have spoken concerning his house, from the beginning even to the end.'),
  ('1 Samuel', 3, 13, 'For I have told him that I will judge his house forever for the iniquity which he knew, because his sons brought a curse on themselves, and he didn’t restrain them.'),
  ('1 Samuel', 3, 14, 'Therefore I have sworn to the house of Eli that the iniquity of Eli’s house shall not be removed with sacrifice or offering forever.”'),
  ('1 Samuel', 3, 15, 'Samuel lay until the morning, and opened the doors of the LORD’s house. Samuel was afraid to show Eli the vision.'),
  ('1 Samuel', 3, 16, 'Then Eli called Samuel and said, “Samuel, my son!” He said, “Here I am.”'),
  ('1 Samuel', 3, 17, 'He said, “What is the thing that he has spoken to you? Please don’t hide it from me. God do so to you, and more also, if you hide anything from me of all the things that he spoke to you.”'),
  ('1 Samuel', 3, 18, 'Samuel told him every bit, and hid nothing from him. He said, “It is the LORD. Let him do what seems good to him.”'),
  ('1 Samuel', 3, 19, 'Samuel grew, and the LORD was with him and let none of his words fall to the ground.'),
  ('1 Samuel', 3, 20, 'All Israel from Dan even to Beersheba knew that Samuel was established to be a prophet of the LORD.'),
  ('1 Samuel', 3, 21, 'The LORD appeared again in Shiloh; for the LORD revealed himself to Samuel in Shiloh by the LORD’s word.'),
  ('1 Samuel', 4, 1, 'The word of Samuel came to all Israel. Now Israel went out against the Philistines to battle, and encamped beside Ebenezer; and the Philistines encamped in Aphek.'),
  ('1 Samuel', 4, 2, 'The Philistines put themselves in array against Israel. When they joined battle, Israel was defeated by the Philistines, who killed about four thousand men of the army in the field.');
INSERT INTO bible_verses (book_name, chapter, verse, text) VALUES
  ('1 Samuel', 4, 3, 'When the people had come into the camp, the elders of Israel said, “Why has the LORD defeated us today before the Philistines? Let’s get the ark of the LORD’s covenant out of Shiloh and bring it to us, that it may come among us and save us out of the hand of our enemies.”'),
  ('1 Samuel', 4, 4, 'So the people sent to Shiloh, and they brought from there the ark of the covenant of the LORD of Armies, who sits above the cherubim; and the two sons of Eli, Hophni and Phinehas, were there with the ark of the covenant of God.'),
  ('1 Samuel', 4, 5, 'When the ark of the LORD’s covenant came into the camp, all Israel shouted with a great shout, so that the earth resounded.'),
  ('1 Samuel', 4, 6, 'When the Philistines heard the noise of the shout, they said, “What does the noise of this great shout in the camp of the Hebrews mean?” They understood that the LORD’s ark had come into the camp.'),
  ('1 Samuel', 4, 7, 'The Philistines were afraid, for they said, “God has come into the camp.” They said, “Woe to us! For there has not been such a thing before.'),
  ('1 Samuel', 4, 8, 'Woe to us! Who shall deliver us out of the hand of these mighty gods? These are the gods that struck the Egyptians with all kinds of plagues in the wilderness.'),
  ('1 Samuel', 4, 9, 'Be strong and behave like men, O you Philistines, that you not be servants to the Hebrews, as they have been to you. Strengthen yourselves like men, and fight!”'),
  ('1 Samuel', 4, 10, 'The Philistines fought, and Israel was defeated, and each man fled to his tent. There was a very great slaughter; for thirty thousand footmen of Israel fell.'),
  ('1 Samuel', 4, 11, 'God’s ark was taken; and the two sons of Eli, Hophni and Phinehas, were slain.'),
  ('1 Samuel', 4, 12, 'A man of Benjamin ran out of the army and came to Shiloh the same day, with his clothes torn and with dirt on his head.'),
  ('1 Samuel', 4, 13, 'When he came, behold, Eli was sitting on his seat by the road watching, for his heart trembled for God’s ark. When the man came into the city and told about it, all the city cried out.'),
  ('1 Samuel', 4, 14, 'When Eli heard the noise of the crying, he said, “What does the noise of this tumult mean?” The man hurried, and came and told Eli.'),
  ('1 Samuel', 4, 15, 'Now Eli was ninety-eight years old. His eyes were set, so that he could not see.'),
  ('1 Samuel', 4, 16, 'The man said to Eli, “I am he who came out of the army, and I fled today out of the army.” He said, “How did the matter go, my son?”'),
  ('1 Samuel', 4, 17, 'He who brought the news answered, “Israel has fled before the Philistines, and there has been also a great slaughter among the people. Your two sons also, Hophni and Phinehas, are dead, and God’s ark has been captured.”'),
  ('1 Samuel', 4, 18, 'When he made mention of God’s ark, Eli fell from off his seat backward by the side of the gate; and his neck broke, and he died, for he was an old man and heavy. He had judged Israel forty years.'),
  ('1 Samuel', 4, 19, 'His daughter-in-law, Phinehas’ wife, was with child, near to giving birth. When she heard the news that God’s ark was taken and that her father-in-law and her husband were dead, she bowed herself and gave birth; for her pains came on her.'),
  ('1 Samuel', 4, 20, 'About the time of her death the women who stood by her said to her, “Don’t be afraid, for you have given birth to a son.” But she didn’t answer, neither did she regard it.'),
  ('1 Samuel', 4, 21, 'She named the child Ichabod, saying, “The glory has departed from Israel!” because God’s ark was taken, and because of her father-in-law and her husband.'),
  ('1 Samuel', 4, 22, 'She said, “The glory has departed from Israel; for God’s ark has been taken.”'),
  ('1 Samuel', 5, 1, 'Now the Philistines had taken God’s ark, and they brought it from Ebenezer to Ashdod.'),
  ('1 Samuel', 5, 2, 'The Philistines took God’s ark, and brought it into the house of Dagon and set it by Dagon.'),
  ('1 Samuel', 5, 3, 'When the people of Ashdod arose early on the next day, behold, Dagon had fallen on his face to the ground before the LORD’s ark. They took Dagon and set him in his place again.'),
  ('1 Samuel', 5, 4, 'When they arose early on the following morning, behold, Dagon had fallen on his face to the ground before the LORD’s ark; and the head of Dagon and both the palms of his hands were cut off on the threshold. Only Dagon’s torso was intact.'),
  ('1 Samuel', 5, 5, 'Therefore neither the priests of Dagon nor any who come into Dagon’s house step on the threshold of Dagon in Ashdod to this day.'),
  ('1 Samuel', 5, 6, 'But the LORD’s hand was heavy on the people of Ashdod, and he destroyed them and struck them with tumors, even Ashdod and its borders.'),
  ('1 Samuel', 5, 7, 'When the men of Ashdod saw that it was so, they said, “The ark of the God of Israel shall not stay with us, for his hand is severe on us and on Dagon our god.”'),
  ('1 Samuel', 5, 8, 'They sent therefore and gathered together all the lords of the Philistines, and said, “What shall we do with the ark of the God of Israel?” They answered, “Let the ark of the God of Israel be carried over to Gath.” They carried the ark of the God of Israel there.'),
  ('1 Samuel', 5, 9, 'It was so, that after they had carried it there, the LORD’s hand was against the city with a very great confusion; and he struck the men of the city, both small and great, so that tumors broke out on them.'),
  ('1 Samuel', 5, 10, 'So they sent God’s ark to Ekron. As God’s ark came to Ekron, the Ekronites cried out, saying, “They have brought the ark of the God of Israel here to us, to kill us and our people.”'),
  ('1 Samuel', 5, 11, 'They sent therefore and gathered together all the lords of the Philistines, and they said, “Send the ark of the God of Israel away, and let it go again to its own place, that it not kill us and our people.” For there was a deadly panic throughout all the city. The hand of God was very heavy there.'),
  ('1 Samuel', 5, 12, 'The men who didn’t die were struck with the tumors; and the cry of the city went up to heaven.'),
  ('1 Samuel', 6, 1, 'The LORD’s ark was in the country of the Philistines seven months.'),
  ('1 Samuel', 6, 2, 'The Philistines called for the priests and the diviners, saying, “What shall we do with the LORD’s ark? Show us how we should send it to its place.”'),
  ('1 Samuel', 6, 3, 'They said, “If you send away the ark of the God of Israel, don’t send it empty; but by all means return a trespass offering to him. Then you will be healed, and it will be known to you why his hand is not removed from you.”'),
  ('1 Samuel', 6, 4, 'Then they said, “What should the trespass offering be which we shall return to him?” They said, “Five golden tumors and five golden mice, for the number of the lords of the Philistines; for one plague was on you all, and on your lords.'),
  ('1 Samuel', 6, 5, 'Therefore you shall make images of your tumors and images of your mice that mar the land; and you shall give glory to the God of Israel. Perhaps he will release his hand from you, from your gods, and from your land.'),
  ('1 Samuel', 6, 6, 'Why then do you harden your hearts as the Egyptians and Pharaoh hardened their hearts? When he had worked wonderfully among them, didn’t they let the people go, and they departed?'),
  ('1 Samuel', 6, 7, '“Now therefore take and prepare yourselves a new cart and two milk cows on which there has come no yoke; and tie the cows to the cart, and bring their calves home from them;'),
  ('1 Samuel', 6, 8, 'and take the LORD’s ark and lay it on the cart. Put the jewels of gold, which you return him for a trespass offering, in a box by its side; and send it away, that it may go.'),
  ('1 Samuel', 6, 9, 'Behold, if it goes up by the way of its own border to Beth Shemesh, then he has done us this great evil; but if not, then we shall know that it is not his hand that struck us. It was a chance that happened to us.”'),
  ('1 Samuel', 6, 10, 'The men did so, and took two milk cows and tied them to the cart, and shut up their calves at home.'),
  ('1 Samuel', 6, 11, 'They put the LORD’s ark on the cart, and the box with the golden mice and the images of their tumors.'),
  ('1 Samuel', 6, 12, 'The cows took the straight way by the way to Beth Shemesh. They went along the highway, lowing as they went, and didn’t turn away to the right hand or to the left; and the lords of the Philistines went after them to the border of Beth Shemesh.'),
  ('1 Samuel', 6, 13, 'The people of Beth Shemesh were reaping their wheat harvest in the valley; and they lifted up their eyes and saw the ark, and rejoiced to see it.'),
  ('1 Samuel', 6, 14, 'The cart came into the field of Joshua of Beth Shemesh, and stood there, where there was a great stone. Then they split the wood of the cart and offered up the cows for a burnt offering to the LORD.'),
  ('1 Samuel', 6, 15, 'The Levites took down the LORD’s ark and the box that was with it, in which the jewels of gold were, and put them on the great stone; and the men of Beth Shemesh offered burnt offerings and sacrificed sacrifices the same day to the LORD.'),
  ('1 Samuel', 6, 16, 'When the five lords of the Philistines had seen it, they returned to Ekron the same day.'),
  ('1 Samuel', 6, 17, 'These are the golden tumors which the Philistines returned for a trespass offering to the LORD: for Ashdod one, for Gaza one, for Ashkelon one, for Gath one, for Ekron one;'),
  ('1 Samuel', 6, 18, 'and the golden mice, according to the number of all the cities of the Philistines belonging to the five lords, both of fortified cities and of country villages, even to the great stone on which they set down the LORD’s ark. That stone remains to this day in the field of Joshua of Beth Shemesh.'),
  ('1 Samuel', 6, 19, 'He struck of the men of Beth Shemesh, because they had looked into the LORD’s ark, he struck fifty thousand seventy of the men. Then the people mourned, because the LORD had struck the people with a great slaughter.'),
  ('1 Samuel', 6, 20, 'The men of Beth Shemesh said, “Who is able to stand before the LORD, this holy God? To whom shall he go up from us?”'),
  ('1 Samuel', 6, 21, 'They sent messengers to the inhabitants of Kiriath Jearim, saying, “The Philistines have brought back the LORD’s ark. Come down and bring it up to yourselves.”'),
  ('1 Samuel', 7, 1, 'The men of Kiriath Jearim came and took the LORD’s ark, and brought it into Abinadab’s house on the hill, and consecrated Eleazar his son to keep the LORD’s ark.'),
  ('1 Samuel', 7, 2, 'From the day that the ark stayed in Kiriath Jearim, the time was long—for it was twenty years; and all the house of Israel lamented after the LORD.'),
  ('1 Samuel', 7, 3, 'Samuel spoke to all the house of Israel, saying, “If you are returning to the LORD with all your heart, then put away the foreign gods and the Ashtaroth from among you, and direct your hearts to the LORD, and serve him only; and he will deliver you out of the hand of the Philistines.”'),
  ('1 Samuel', 7, 4, 'Then the children of Israel removed the Baals and the Ashtaroth, and served the LORD only.'),
  ('1 Samuel', 7, 5, 'Samuel said, “Gather all Israel to Mizpah, and I will pray to the LORD for you.”'),
  ('1 Samuel', 7, 6, 'They gathered together to Mizpah, and drew water, and poured it out before the LORD, and fasted on that day, and said there, “We have sinned against the LORD.” Samuel judged the children of Israel in Mizpah.'),
  ('1 Samuel', 7, 7, 'When the Philistines heard that the children of Israel were gathered together at Mizpah, the lords of the Philistines went up against Israel. When the children of Israel heard it, they were afraid of the Philistines.'),
  ('1 Samuel', 7, 8, 'The children of Israel said to Samuel, “Don’t stop crying to the LORD our God for us, that he will save us out of the hand of the Philistines.”'),
  ('1 Samuel', 7, 9, 'Samuel took a suckling lamb, and offered it for a whole burnt offering to the LORD. Samuel cried to the LORD for Israel, and the LORD answered him.'),
  ('1 Samuel', 7, 10, 'As Samuel was offering up the burnt offering, the Philistines came near to battle against Israel; but the LORD thundered with a great thunder on that day on the Philistines and confused them; and they were struck down before Israel.'),
  ('1 Samuel', 7, 11, 'The men of Israel went out of Mizpah and pursued the Philistines, and struck them until they came under Beth Kar.'),
  ('1 Samuel', 7, 12, 'Then Samuel took a stone and set it between Mizpah and Shen, and called its name Ebenezer, saying, “The LORD helped us until now.”'),
  ('1 Samuel', 7, 13, 'So the Philistines were subdued, and they stopped coming within the border of Israel. The LORD’s hand was against the Philistines all the days of Samuel.'),
  ('1 Samuel', 7, 14, 'The cities which the Philistines had taken from Israel were restored to Israel, from Ekron even to Gath; and Israel recovered its border out of the hand of the Philistines. There was peace between Israel and the Amorites.'),
  ('1 Samuel', 7, 15, 'Samuel judged Israel all the days of his life.'),
  ('1 Samuel', 7, 16, 'He went from year to year in a circuit to Bethel, Gilgal, and Mizpah; and he judged Israel in all those places.'),
  ('1 Samuel', 7, 17, 'His return was to Ramah, for his house was there, and he judged Israel there; and he built an altar to the LORD there.'),
  ('1 Samuel', 8, 1, 'When Samuel was old, he made his sons judges over Israel.'),
  ('1 Samuel', 8, 2, 'Now the name of his firstborn was Joel, and the name of his second, Abijah. They were judges in Beersheba.'),
  ('1 Samuel', 8, 3, 'His sons didn’t walk in his ways, but turned away after dishonest gain, took bribes, and perverted justice.'),
  ('1 Samuel', 8, 4, 'Then all the elders of Israel gathered themselves together and came to Samuel to Ramah.'),
  ('1 Samuel', 8, 5, 'They said to him, “Behold, you are old, and your sons don’t walk in your ways. Now make us a king to judge us like all the nations.”'),
  ('1 Samuel', 8, 6, 'But the thing displeased Samuel when they said, “Give us a king to judge us.” Samuel prayed to the LORD.'),
  ('1 Samuel', 8, 7, 'The LORD said to Samuel, “Listen to the voice of the people in all that they tell you; for they have not rejected you, but they have rejected me as the king over them.'),
  ('1 Samuel', 8, 8, 'According to all the works which they have done since the day that I brought them up out of Egypt even to this day, in that they have forsaken me and served other gods, so they also do to you.'),
  ('1 Samuel', 8, 9, 'Now therefore, listen to their voice. However, you shall protest solemnly to them, and shall show them the way of the king who will reign over them.”'),
  ('1 Samuel', 8, 10, 'Samuel told all the LORD’s words to the people who asked him for a king.'),
  ('1 Samuel', 8, 11, 'He said, “This will be the way of the king who shall reign over you: he will take your sons and appoint them as his servants, for his chariots and to be his horsemen; and they will run before his chariots.'),
  ('1 Samuel', 8, 12, 'He will appoint them to him for captains of thousands and captains of fifties; and he will assign some to plow his ground and to reap his harvest; and to make his instruments of war and the instruments of his chariots.'),
  ('1 Samuel', 8, 13, 'He will take your daughters to be perfumers, to be cooks, and to be bakers.'),
  ('1 Samuel', 8, 14, 'He will take your fields, your vineyards, and your olive groves, even your best, and give them to his servants.'),
  ('1 Samuel', 8, 15, 'He will take one tenth of your seed and of your vineyards, and give it to his officers and to his servants.'),
  ('1 Samuel', 8, 16, 'He will take your male servants, your female servants, your best young men, and your donkeys, and assign them to his own work.'),
  ('1 Samuel', 8, 17, 'He will take one tenth of your flocks; and you will be his servants.'),
  ('1 Samuel', 8, 18, 'You will cry out in that day because of your king whom you will have chosen for yourselves; and the LORD will not answer you in that day.”'),
  ('1 Samuel', 8, 19, 'But the people refused to listen to the voice of Samuel; and they said, “No, but we will have a king over us,'),
  ('1 Samuel', 8, 20, 'that we also may be like all the nations; and that our king may judge us, and go out before us, and fight our battles.”'),
  ('1 Samuel', 8, 21, 'Samuel heard all the words of the people, and he rehearsed them in the ears of the LORD.'),
  ('1 Samuel', 8, 22, 'The LORD said to Samuel, “Listen to their voice, and make them a king.” Samuel said to the men of Israel, “Everyone go to your own city.”'),
  ('1 Samuel', 9, 1, 'Now there was a man of Benjamin, whose name was Kish the son of Abiel, the son of Zeror, the son of Becorath, the son of Aphiah, the son of a Benjamite, a mighty man of valor.'),
  ('1 Samuel', 9, 2, 'He had a son whose name was Saul, an impressive young man; and there was not among the children of Israel a more handsome person than he. From his shoulders and upward he was taller than any of the people.'),
  ('1 Samuel', 9, 3, 'The donkeys of Kish, Saul’s father, were lost. Kish said to Saul his son, “Now take one of the servants with you, and arise, go look for the donkeys.”'),
  ('1 Samuel', 9, 4, 'He passed through the hill country of Ephraim, and passed through the land of Shalishah, but they didn’t find them. Then they passed through the land of Shaalim, and they weren’t there. Then he passed through the land of the Benjamites, but they didn’t find them.'),
  ('1 Samuel', 9, 5, 'When they had come to the land of Zuph, Saul said to his servant who was with him, “Come! Let’s return, lest my father stop caring about the donkeys and be anxious for us.”'),
  ('1 Samuel', 9, 6, 'The servant said to him, “Behold now, there is a man of God in this city, and he is a man who is held in honor. All that he says surely happens. Now let’s go there. Perhaps he can tell us which way to go.”'),
  ('1 Samuel', 9, 7, 'Then Saul said to his servant, “But behold, if we go, what should we bring the man? For the bread is spent in our sacks, and there is not a present to bring to the man of God. What do we have?”'),
  ('1 Samuel', 9, 8, 'The servant answered Saul again and said, “Behold, I have in my hand the fourth part of a shekel of silver. I will give that to the man of God, to tell us our way.”');
INSERT INTO bible_verses (book_name, chapter, verse, text) VALUES
  ('1 Samuel', 9, 9, '(In earlier times in Israel, when a man went to inquire of God, he said, “Come! Let’s go to the seer;” for he who is now called a prophet was before called a seer.)'),
  ('1 Samuel', 9, 10, 'Then Saul said to his servant, “Well said. Come! Let’s go.” So they went to the city where the man of God was.'),
  ('1 Samuel', 9, 11, 'As they went up the ascent to the city, they found young maidens going out to draw water, and said to them, “Is the seer here?”'),
  ('1 Samuel', 9, 12, 'They answered them and said, “He is. Behold, he is before you. Hurry now, for he has come today into the city; for the people have a sacrifice today in the high place.'),
  ('1 Samuel', 9, 13, 'As soon as you have come into the city, you will immediately find him before he goes up to the high place to eat; for the people will not eat until he comes, because he blesses the sacrifice. Afterwards those who are invited eat. Now therefore go up; for at this time you will find him.”'),
  ('1 Samuel', 9, 14, 'They went up to the city. As they came within the city, behold, Samuel came out toward them to go up to the high place.'),
  ('1 Samuel', 9, 15, 'Now the LORD had revealed to Samuel a day before Saul came, saying,'),
  ('1 Samuel', 9, 16, '“Tomorrow about this time I will send you a man out of the land of Benjamin, and you shall anoint him to be prince over my people Israel. He will save my people out of the hand of the Philistines; for I have looked upon my people, because their cry has come to me.”'),
  ('1 Samuel', 9, 17, 'When Samuel saw Saul, the LORD said to him, “Behold, the man of whom I spoke to you! He will have authority over my people.”'),
  ('1 Samuel', 9, 18, 'Then Saul approached Samuel in the gateway, and said, “Please tell me where the seer’s house is.”'),
  ('1 Samuel', 9, 19, 'Samuel answered Saul and said, “I am the seer. Go up before me to the high place, for you are to eat with me today. In the morning I will let you go and will tell you all that is in your heart.'),
  ('1 Samuel', 9, 20, 'As for your donkeys who were lost three days ago, don’t set your mind on them, for they have been found. For whom does all Israel desire? Is it not you and all your father’s house?”'),
  ('1 Samuel', 9, 21, 'Saul answered, “Am I not a Benjamite, of the smallest of the tribes of Israel? And my family the least of all the families of the tribe of Benjamin? Why then do you speak to me like this?”'),
  ('1 Samuel', 9, 22, 'Samuel took Saul and his servant and brought them into the guest room, and made them sit in the best place among those who were invited, who were about thirty persons.'),
  ('1 Samuel', 9, 23, 'Samuel said to the cook, “Bring the portion which I gave you, of which I said to you, ‘Set it aside.’”'),
  ('1 Samuel', 9, 24, 'The cook took up the thigh, and that which was on it, and set it before Saul. Samuel said, “Behold, that which has been reserved! Set it before yourself and eat; because it has been kept for you for the appointed time, for I said, ‘I have invited the people.’” So Saul ate with Samuel that day.'),
  ('1 Samuel', 9, 25, 'When they had come down from the high place into the city, he talked with Saul on the housetop.'),
  ('1 Samuel', 9, 26, 'They arose early; and about daybreak, Samuel called to Saul on the housetop, saying, “Get up, that I may send you away.” Saul arose, and they both went outside, he and Samuel, together.'),
  ('1 Samuel', 9, 27, 'As they were going down at the end of the city, Samuel said to Saul, “Tell the servant to go on ahead of us.” He went ahead, then Samuel said, “But stand still first, that I may cause you to hear God’s message.”'),
  ('1 Samuel', 10, 1, 'Then Samuel took the vial of oil and poured it on his head, then kissed him and said, “Hasn’t the LORD anointed you to be prince over his inheritance?'),
  ('1 Samuel', 10, 2, 'When you have departed from me today, then you will find two men by Rachel’s tomb, on the border of Benjamin at Zelzah. They will tell you, ‘The donkeys which you went to look for have been found; and behold, your father has stopped caring about the donkeys and is anxious for you, saying, “What shall I do for my son?”’'),
  ('1 Samuel', 10, 3, '“Then you will go on forward from there, and you will come to the oak of Tabor. Three men will meet you there going up to God to Bethel: one carrying three young goats, and another carrying three loaves of bread, and another carrying a container of wine.'),
  ('1 Samuel', 10, 4, 'They will greet you and give you two loaves of bread, which you shall receive from their hand.'),
  ('1 Samuel', 10, 5, '“After that you will come to the hill of God, where the garrison of the Philistines is; and it will happen, when you have come there to the city, that you will meet a band of prophets coming down from the high place with a lute, a tambourine, a pipe, and a harp before them; and they will be prophesying.'),
  ('1 Samuel', 10, 6, 'Then the LORD’s Spirit will come mightily on you, then you will prophesy with them and will be turned into another man.'),
  ('1 Samuel', 10, 7, 'Let it be, when these signs have come to you, that you do what is appropriate for the occasion; for God is with you.'),
  ('1 Samuel', 10, 8, '“Go down ahead of me to Gilgal; and behold, I will come down to you to offer burnt offerings and to sacrifice sacrifices of peace offerings. Wait seven days, until I come to you and show you what you are to do.”'),
  ('1 Samuel', 10, 9, 'It was so, that when he had turned his back to go from Samuel, God gave him another heart; and all those signs happened that day.'),
  ('1 Samuel', 10, 10, 'When they came there to the hill, behold, a band of prophets met him; and the Spirit of God came mightily on him, and he prophesied among them.'),
  ('1 Samuel', 10, 11, 'When all who knew him before saw that, behold, he prophesied with the prophets, then the people said to one another, “What is this that has come to the son of Kish? Is Saul also among the prophets?”'),
  ('1 Samuel', 10, 12, 'One from the same place answered, “Who is their father?” Therefore it became a proverb, “Is Saul also among the prophets?”'),
  ('1 Samuel', 10, 13, 'When he had finished prophesying, he came to the high place.'),
  ('1 Samuel', 10, 14, 'Saul’s uncle said to him and to his servant, “Where did you go?” He said, “To seek the donkeys. When we saw that they were not found, we came to Samuel.”'),
  ('1 Samuel', 10, 15, 'Saul’s uncle said, “Please tell me what Samuel said to you.”'),
  ('1 Samuel', 10, 16, 'Saul said to his uncle, “He told us plainly that the donkeys were found.” But concerning the matter of the kingdom, of which Samuel spoke, he didn’t tell him.'),
  ('1 Samuel', 10, 17, 'Samuel called the people together to the LORD to Mizpah;'),
  ('1 Samuel', 10, 18, 'and he said to the children of Israel, “The LORD, the God of Israel, says ‘I brought Israel up out of Egypt and I delivered you out of the hand of the Egyptians, and out of the hand of all the kingdoms that oppressed you.’'),
  ('1 Samuel', 10, 19, 'But you have today rejected your God, who himself saves you out of all your calamities and your distresses; and you have said to him, ‘No! Set a king over us!’ Now therefore present yourselves before the LORD by your tribes and by your thousands.”'),
  ('1 Samuel', 10, 20, 'So Samuel brought all the tribes of Israel near, and the tribe of Benjamin was chosen.'),
  ('1 Samuel', 10, 21, 'He brought the tribe of Benjamin near by their families and the family of the Matrites was chosen. Then Saul the son of Kish was chosen; but when they looked for him, he could not be found.'),
  ('1 Samuel', 10, 22, 'Therefore they asked of the LORD further, “Is there yet a man to come here?” The LORD answered, “Behold, he has hidden himself among the baggage.”'),
  ('1 Samuel', 10, 23, 'They ran and got him there. When he stood among the people, he was higher than any of the people from his shoulders and upward.'),
  ('1 Samuel', 10, 24, 'Samuel said to all the people, “Do you see him whom the LORD has chosen, that there is no one like him among all the people?” All the people shouted and said, “Long live the king!”'),
  ('1 Samuel', 10, 25, 'Then Samuel told the people the regulations of the kingdom, and wrote it in a book and laid it up before the LORD. Samuel sent all the people away, every man to his house.'),
  ('1 Samuel', 10, 26, 'Saul also went to his house in Gibeah; and the army went with him, whose hearts God had touched.'),
  ('1 Samuel', 10, 27, 'But certain worthless fellows said, “How could this man save us?” They despised him, and brought him no tribute. But he held his peace.'),
  ('1 Samuel', 11, 1, 'Then Nahash the Ammonite came up and encamped against Jabesh Gilead; and all the men of Jabesh said to Nahash, “Make a covenant with us, and we will serve you.”'),
  ('1 Samuel', 11, 2, 'Nahash the Ammonite said to them, “On this condition I will make it with you, that all your right eyes be gouged out. I will make this dishonor all Israel.”'),
  ('1 Samuel', 11, 3, 'The elders of Jabesh said to him, “Give us seven days, that we may send messengers to all the borders of Israel; and then, if there is no one to save us, we will come out to you.”'),
  ('1 Samuel', 11, 4, 'Then the messengers came to Gibeah of Saul, and spoke these words in the ears of the people, then all the people lifted up their voice and wept.'),
  ('1 Samuel', 11, 5, 'Behold, Saul came following the oxen out of the field; and Saul said, “What ails the people that they weep?” They told him the words of the men of Jabesh.'),
  ('1 Samuel', 11, 6, 'God’s Spirit came mightily on Saul when he heard those words, and his anger burned hot.'),
  ('1 Samuel', 11, 7, 'He took a yoke of oxen and cut them in pieces, then sent them throughout all the borders of Israel by the hand of messengers, saying, “Whoever doesn’t come out after Saul and after Samuel, so shall it be done to his oxen.” The dread of the LORD fell on the people, and they came out as one man.'),
  ('1 Samuel', 11, 8, 'He counted them in Bezek; and the children of Israel were three hundred thousand, and the men of Judah thirty thousand.'),
  ('1 Samuel', 11, 9, 'They said to the messengers who came, “Tell the men of Jabesh Gilead, ‘Tomorrow, by the time the sun is hot, you will be rescued.’” The messengers came and told the men of Jabesh; and they were glad.'),
  ('1 Samuel', 11, 10, 'Therefore the men of Jabesh said, “Tomorrow we will come out to you, and you shall do with us all that seems good to you.”'),
  ('1 Samuel', 11, 11, 'On the next day, Saul put the people in three companies; and they came into the middle of the camp in the morning watch, and struck the Ammonites until the heat of the day. Those who remained were scattered, so that no two of them were left together.'),
  ('1 Samuel', 11, 12, 'The people said to Samuel, “Who is he who said, ‘Shall Saul reign over us?’ Bring those men, that we may put them to death!”'),
  ('1 Samuel', 11, 13, 'Saul said, “No man shall be put to death today; for today the LORD has rescued Israel.”'),
  ('1 Samuel', 11, 14, 'Then Samuel said to the people, “Come! Let’s go to Gilgal, and renew the kingdom there.”'),
  ('1 Samuel', 11, 15, 'All the people went to Gilgal; and there they made Saul king before the LORD in Gilgal. There they offered sacrifices of peace offerings before the LORD; and there Saul and all the men of Israel rejoiced greatly.'),
  ('1 Samuel', 12, 1, 'Samuel said to all Israel, “Behold, I have listened to your voice in all that you said to me, and have made a king over you.'),
  ('1 Samuel', 12, 2, 'Now, behold, the king walks before you. I am old and gray-headed. Behold, my sons are with you. I have walked before you from my youth to this day.'),
  ('1 Samuel', 12, 3, 'Here I am. Witness against me before the LORD and before his anointed. Whose ox have I taken? Whose donkey have I taken? Whom have I defrauded? Whom have I oppressed? Of whose hand have I taken a bribe to make me blind my eyes? I will restore it to you.”'),
  ('1 Samuel', 12, 4, 'They said, “You have not defrauded us, nor oppressed us, neither have you taken anything from anyone’s hand.”'),
  ('1 Samuel', 12, 5, 'He said to them, “The LORD is witness against you, and his anointed is witness today, that you have not found anything in my hand.” They said, “He is witness.”'),
  ('1 Samuel', 12, 6, 'Samuel said to the people, “It is the LORD who appointed Moses and Aaron, and that brought your fathers up out of the land of Egypt.'),
  ('1 Samuel', 12, 7, 'Now therefore stand still, that I may plead with you before the LORD concerning all the righteous acts of the LORD, which he did to you and to your fathers.'),
  ('1 Samuel', 12, 8, '“When Jacob had come into Egypt, and your fathers cried to the LORD, then the LORD sent Moses and Aaron, who brought your fathers out of Egypt, and made them to dwell in this place.'),
  ('1 Samuel', 12, 9, 'But they forgot the LORD their God; and he sold them into the hand of Sisera, captain of the army of Hazor, and into the hand of the Philistines, and into the hand of the king of Moab; and they fought against them.'),
  ('1 Samuel', 12, 10, 'They cried to the LORD, and said, ‘We have sinned, because we have forsaken the LORD and have served the Baals and the Ashtaroth; but now deliver us out of the hand of our enemies, and we will serve you.’'),
  ('1 Samuel', 12, 11, 'The LORD sent Jerubbaal, Bedan, Jephthah, and Samuel, and delivered you out of the hand of your enemies on every side; and you lived in safety.'),
  ('1 Samuel', 12, 12, '“When you saw that Nahash the king of the children of Ammon came against you, you said to me, ‘No, but a king shall reign over us,’ when the LORD your God was your king.'),
  ('1 Samuel', 12, 13, 'Now therefore see the king whom you have chosen and whom you have asked for. Behold, the LORD has set a king over you.'),
  ('1 Samuel', 12, 14, 'If you will fear the LORD, and serve him, and listen to his voice, and not rebel against the commandment of the LORD, then both you and also the king who reigns over you are followers of the LORD your God.'),
  ('1 Samuel', 12, 15, 'But if you will not listen to the LORD’s voice, but rebel against the commandment of the LORD, then the LORD’s hand will be against you, as it was against your fathers.'),
  ('1 Samuel', 12, 16, '“Now therefore stand still and see this great thing, which the LORD will do before your eyes.'),
  ('1 Samuel', 12, 17, 'Isn’t it wheat harvest today? I will call to the LORD, that he may send thunder and rain; and you will know and see that your wickedness is great, which you have done in the LORD’s sight, in asking for a king.”'),
  ('1 Samuel', 12, 18, 'So Samuel called to the LORD, and the LORD sent thunder and rain that day. Then all the people greatly feared the LORD and Samuel.'),
  ('1 Samuel', 12, 19, 'All the people said to Samuel, “Pray for your servants to the LORD your God, that we not die; for we have added to all our sins this evil, to ask for a king.”'),
  ('1 Samuel', 12, 20, 'Samuel said to the people, “Don’t be afraid. You have indeed done all this evil; yet don’t turn away from following the LORD, but serve the LORD with all your heart.'),
  ('1 Samuel', 12, 21, 'Don’t turn away to go after vain things which can’t profit or deliver, for they are vain.'),
  ('1 Samuel', 12, 22, 'For the LORD will not forsake his people for his great name’s sake, because it has pleased the LORD to make you a people for himself.'),
  ('1 Samuel', 12, 23, 'Moreover, as for me, far be it from me that I should sin against the LORD in ceasing to pray for you; but I will instruct you in the good and the right way.'),
  ('1 Samuel', 12, 24, 'Only fear the LORD, and serve him in truth with all your heart; for consider what great things he has done for you.'),
  ('1 Samuel', 12, 25, 'But if you keep doing evil, you will be consumed, both you and your king.”'),
  ('1 Samuel', 13, 1, 'Saul was thirty years old when he became king, and he reigned over Israel forty-two years.'),
  ('1 Samuel', 13, 2, 'Saul chose for himself three thousand men of Israel, of which two thousand were with Saul in Michmash and in the Mount of Bethel, and one thousand were with Jonathan in Gibeah of Benjamin. He sent the rest of the people to their own tents.'),
  ('1 Samuel', 13, 3, 'Jonathan struck the garrison of the Philistines that was in Geba, and the Philistines heard of it. Saul blew the trumpet throughout all the land, saying, “Let the Hebrews hear!”'),
  ('1 Samuel', 13, 4, 'All Israel heard that Saul had struck the garrison of the Philistines, and also that Israel was considered an abomination to the Philistines. The people were gathered together after Saul to Gilgal.'),
  ('1 Samuel', 13, 5, 'The Philistines assembled themselves together to fight with Israel: thirty thousand chariots, six thousand horsemen, and people as the sand which is on the seashore in multitude. They came up and encamped in Michmash, eastward of Beth Aven.'),
  ('1 Samuel', 13, 6, 'When the men of Israel saw that they were in trouble (for the people were distressed), then the people hid themselves in caves, in thickets, in rocks, in tombs, and in pits.'),
  ('1 Samuel', 13, 7, 'Now some of the Hebrews had gone over the Jordan to the land of Gad and Gilead; but as for Saul, he was yet in Gilgal, and all the people followed him trembling.'),
  ('1 Samuel', 13, 8, 'He stayed seven days, according to the time set by Samuel; but Samuel didn’t come to Gilgal, and the people were scattering from him.'),
  ('1 Samuel', 13, 9, 'Saul said, “Bring the burnt offering to me here, and the peace offerings.” He offered the burnt offering.'),
  ('1 Samuel', 13, 10, 'It came to pass that as soon as he had finished offering the burnt offering, behold, Samuel came; and Saul went out to meet him, that he might greet him.'),
  ('1 Samuel', 13, 11, 'Samuel said, “What have you done?” Saul said, “Because I saw that the people were scattered from me, and that you didn’t come within the days appointed, and that the Philistines assembled themselves together at Michmash,'),
  ('1 Samuel', 13, 12, 'therefore I said, ‘Now the Philistines will come down on me to Gilgal, and I haven’t entreated the favor of the LORD.’ I forced myself therefore, and offered the burnt offering.”'),
  ('1 Samuel', 13, 13, 'Samuel said to Saul, “You have done foolishly. You have not kept the commandment of the LORD your God, which he commanded you; for now the LORD would have established your kingdom on Israel forever.'),
  ('1 Samuel', 13, 14, 'But now your kingdom will not continue. The LORD has sought for himself a man after his own heart, and the LORD has appointed him to be prince over his people, because you have not kept that which the LORD commanded you.”');
INSERT INTO bible_verses (book_name, chapter, verse, text) VALUES
  ('1 Samuel', 13, 15, 'Samuel arose, and went from Gilgal to Gibeah of Benjamin. Saul counted the people who were present with him, about six hundred men.'),
  ('1 Samuel', 13, 16, 'Saul, and Jonathan his son, and the people who were present with them, stayed in Geba of Benjamin; but the Philistines encamped in Michmash.'),
  ('1 Samuel', 13, 17, 'The raiders came out of the camp of the Philistines in three companies: one company turned to the way that leads to Ophrah, to the land of Shual;'),
  ('1 Samuel', 13, 18, 'another company turned the way to Beth Horon; and another company turned the way of the border that looks down on the valley of Zeboim toward the wilderness.'),
  ('1 Samuel', 13, 19, 'Now there was no blacksmith found throughout all the land of Israel, for the Philistines said, “Lest the Hebrews make themselves swords or spears”;'),
  ('1 Samuel', 13, 20, 'but all the Israelites went down to the Philistines, each man to sharpen his own plowshare, mattock, ax, and sickle.'),
  ('1 Samuel', 13, 21, 'The price was one payim each to sharpen mattocks, plowshares, pitchforks, axes, and goads.'),
  ('1 Samuel', 13, 22, 'So it came to pass in the day of battle that neither sword nor spear was found in the hand of any of the people who were with Saul and Jonathan; but Saul and Jonathan his son had them.'),
  ('1 Samuel', 13, 23, 'The garrison of the Philistines went out to the pass of Michmash.'),
  ('1 Samuel', 14, 1, 'Now it happened on a day that Jonathan the son of Saul said to the young man who bore his armor, “Come! Let’s go over to the Philistines’ garrison that is on the other side.” But he didn’t tell his father.'),
  ('1 Samuel', 14, 2, 'Saul stayed in the uttermost part of Gibeah under the pomegranate tree which is in Migron; and the people who were with him were about six hundred men,'),
  ('1 Samuel', 14, 3, 'including Ahijah the son of Ahitub, Ichabod’s brother, the son of Phinehas, the son of Eli the priest of the LORD in Shiloh, wearing an ephod. The people didn’t know that Jonathan was gone.'),
  ('1 Samuel', 14, 4, 'Between the passes, by which Jonathan sought to go over to the Philistines’ garrison, there was a rocky crag on the one side and a rocky crag on the other side; and the name of the one was Bozez, and the name of the other Seneh.'),
  ('1 Samuel', 14, 5, 'The one crag rose up on the north in front of Michmash, and the other on the south in front of Geba.'),
  ('1 Samuel', 14, 6, 'Jonathan said to the young man who bore his armor, “Come! Let’s go over to the garrison of these uncircumcised. It may be that the LORD will work for us, for there is no restraint on the LORD to save by many or by few.”'),
  ('1 Samuel', 14, 7, 'His armor bearer said to him, “Do all that is in your heart. Go, and behold, I am with you according to your heart.”'),
  ('1 Samuel', 14, 8, 'Then Jonathan said, “Behold, we will pass over to the men, and we will reveal ourselves to them.'),
  ('1 Samuel', 14, 9, 'If they say this to us, ‘Wait until we come to you!’ then we will stand still in our place and will not go up to them.'),
  ('1 Samuel', 14, 10, 'But if they say this, ‘Come up to us!’ then we will go up, for the LORD has delivered them into our hand. This shall be the sign to us.”'),
  ('1 Samuel', 14, 11, 'Both of them revealed themselves to the garrison of the Philistines; and the Philistines said, “Behold, the Hebrews are coming out of the holes where they had hidden themselves!”'),
  ('1 Samuel', 14, 12, 'The men of the garrison answered Jonathan and his armor bearer, and said, “Come up to us, and we will show you something!” Jonathan said to his armor bearer, “Come up after me, for the LORD has delivered them into the hand of Israel.”'),
  ('1 Samuel', 14, 13, 'Jonathan climbed up on his hands and on his feet, and his armor bearer after him, and they fell before Jonathan; and his armor bearer killed them after him.'),
  ('1 Samuel', 14, 14, 'That first slaughter, which Jonathan and his armor bearer made, was about twenty men, within as it were half a furrow’s length in an acre of land.'),
  ('1 Samuel', 14, 15, 'There was a trembling in the camp, in the field, and among all the people; the garrison and the raiders also trembled; and the earth quaked, so there was an exceedingly great trembling.'),
  ('1 Samuel', 14, 16, 'The watchmen of Saul in Gibeah of Benjamin looked; and behold, the multitude melted away and scattered.'),
  ('1 Samuel', 14, 17, 'Then Saul said to the people who were with him, “Count now, and see who is missing from us.” When they had counted, behold, Jonathan and his armor bearer were not there.'),
  ('1 Samuel', 14, 18, 'Saul said to Ahijah, “Bring God’s ark here.” For God’s ark was with the children of Israel at that time.'),
  ('1 Samuel', 14, 19, 'While Saul talked to the priest, the tumult that was in the camp of the Philistines went on and increased; and Saul said to the priest, “Withdraw your hand!”'),
  ('1 Samuel', 14, 20, 'Saul and all the people who were with him were gathered together, and came to the battle; and behold, they were all striking each other with their swords in very great confusion.'),
  ('1 Samuel', 14, 21, 'Now the Hebrews who were with the Philistines before and who went up with them into the camp from all around, even they also turned to be with the Israelites who were with Saul and Jonathan.'),
  ('1 Samuel', 14, 22, 'Likewise all the men of Israel who had hidden themselves in the hill country of Ephraim, when they heard that the Philistines fled, even they also followed hard after them in the battle.'),
  ('1 Samuel', 14, 23, 'So the LORD saved Israel that day; and the battle passed over by Beth Aven.'),
  ('1 Samuel', 14, 24, 'The men of Israel were distressed that day; for Saul had adjured the people, saying, “Cursed is the man who eats any food until it is evening, and I am avenged of my enemies.” So none of the people tasted food.'),
  ('1 Samuel', 14, 25, 'All the people came into the forest; and there was honey on the ground.'),
  ('1 Samuel', 14, 26, 'When the people had come to the forest, behold, honey was dripping, but no one put his hand to his mouth, for the people feared the oath.'),
  ('1 Samuel', 14, 27, 'But Jonathan didn’t hear when his father commanded the people with the oath. Therefore he put out the end of the rod that was in his hand and dipped it in the honeycomb, and put his hand to his mouth; and his eyes brightened.'),
  ('1 Samuel', 14, 28, 'Then one of the people answered, and said, “Your father directly commanded the people with an oath, saying, ‘Cursed is the man who eats food today.’” So the people were faint.'),
  ('1 Samuel', 14, 29, 'Then Jonathan said, “My father has troubled the land. Please look how my eyes have brightened because I tasted a little of this honey.'),
  ('1 Samuel', 14, 30, 'How much more, if perhaps the people had eaten freely today of the plunder of their enemies which they found? For now there has been no great slaughter among the Philistines.”'),
  ('1 Samuel', 14, 31, 'They struck the Philistines that day from Michmash to Aijalon. The people were very faint;'),
  ('1 Samuel', 14, 32, 'and the people pounced on the plunder, and took sheep, cattle, and calves, and killed them on the ground; and the people ate them with the blood.'),
  ('1 Samuel', 14, 33, 'Then they told Saul, saying, “Behold, the people are sinning against the LORD, in that they eat meat with the blood.” He said, “You have dealt treacherously. Roll a large stone to me today!”'),
  ('1 Samuel', 14, 34, 'Saul said, “Disperse yourselves among the people, and tell them, ‘Every man bring me here his ox, and every man his sheep, and kill them here, and eat; and don’t sin against the LORD in eating meat with the blood.’” All the people brought every man his ox with him that night, and killed them there.'),
  ('1 Samuel', 14, 35, 'Saul built an altar to the LORD. This was the first altar that he built to the LORD.'),
  ('1 Samuel', 14, 36, 'Saul said, “Let’s go down after the Philistines by night, and take plunder among them until the morning light. Let’s not leave a man of them.” They said, “Do whatever seems good to you.” Then the priest said, “Let’s draw near here to God.”'),
  ('1 Samuel', 14, 37, 'Saul asked counsel of God: “Shall I go down after the Philistines? Will you deliver them into the hand of Israel?” But he didn’t answer him that day.'),
  ('1 Samuel', 14, 38, 'Saul said, “Draw near here, all you chiefs of the people, and know and see in whom this sin has been today.'),
  ('1 Samuel', 14, 39, 'For as the LORD lives, who saves Israel, though it is in Jonathan my son, he shall surely die.” But there was not a man among all the people who answered him.'),
  ('1 Samuel', 14, 40, 'Then he said to all Israel, “You be on one side, and I and Jonathan my son will be on the other side.” The people said to Saul, “Do what seems good to you.”'),
  ('1 Samuel', 14, 41, 'Therefore Saul said to the LORD, the God of Israel, “Show the right.” Jonathan and Saul were chosen, but the people escaped.'),
  ('1 Samuel', 14, 42, 'Saul said, “Cast lots between me and Jonathan my son.” Jonathan was selected.'),
  ('1 Samuel', 14, 43, 'Then Saul said to Jonathan, “Tell me what you have done!” Jonathan told him, and said, “I certainly did taste a little honey with the end of the rod that was in my hand; and behold, I must die.”'),
  ('1 Samuel', 14, 44, 'Saul said, “God do so and more also; for you shall surely die, Jonathan.”'),
  ('1 Samuel', 14, 45, 'The people said to Saul, “Shall Jonathan die, who has worked this great salvation in Israel? Far from it! As the LORD lives, there shall not one hair of his head fall to the ground, for he has worked with God today!” So the people rescued Jonathan, so he didn’t die.'),
  ('1 Samuel', 14, 46, 'Then Saul went up from following the Philistines; and the Philistines went to their own place.'),
  ('1 Samuel', 14, 47, 'Now when Saul had taken the kingdom over Israel, he fought against all his enemies on every side: against Moab, and against the children of Ammon, and against Edom, and against the kings of Zobah, and against the Philistines. Wherever he turned himself, he defeated them.'),
  ('1 Samuel', 14, 48, 'He did valiantly and struck the Amalekites, and delivered Israel out of the hands of those who plundered them.'),
  ('1 Samuel', 14, 49, 'Now the sons of Saul were Jonathan, Ishvi, and Malchishua; and the names of his two daughters were these: the name of the firstborn Merab, and the name of the younger Michal.'),
  ('1 Samuel', 14, 50, 'The name of Saul’s wife was Ahinoam the daughter of Ahimaaz. The name of the captain of his army was Abner the son of Ner, Saul’s uncle.'),
  ('1 Samuel', 14, 51, 'Kish was the father of Saul, and Ner the father of Abner was the son of Abiel.'),
  ('1 Samuel', 14, 52, 'There was severe war against the Philistines all the days of Saul; and when Saul saw any mighty man or any valiant man, he took him into his service.'),
  ('1 Samuel', 15, 1, 'Samuel said to Saul, “The LORD sent me to anoint you to be king over his people, over Israel. Now therefore listen to the voice of the LORD’s words.'),
  ('1 Samuel', 15, 2, 'The LORD of Armies says, ‘I remember what Amalek did to Israel, how he set himself against him on the way when he came up out of Egypt.'),
  ('1 Samuel', 15, 3, 'Now go and strike Amalek, and utterly destroy all that they have, and don’t spare them; but kill both man and woman, infant and nursing baby, ox and sheep, camel and donkey.’”'),
  ('1 Samuel', 15, 4, 'Saul summoned the people, and counted them in Telaim, two hundred thousand footmen and ten thousand men of Judah.'),
  ('1 Samuel', 15, 5, 'Saul came to the city of Amalek, and set an ambush in the valley.'),
  ('1 Samuel', 15, 6, 'Saul said to the Kenites, “Go, depart, go down from among the Amalekites, lest I destroy you with them; for you showed kindness to all the children of Israel when they came up out of Egypt.” So the Kenites departed from among the Amalekites.'),
  ('1 Samuel', 15, 7, 'Saul struck the Amalekites, from Havilah as you go to Shur, which is before Egypt.'),
  ('1 Samuel', 15, 8, 'He took Agag the king of the Amalekites alive, and utterly destroyed all the people with the edge of the sword.'),
  ('1 Samuel', 15, 9, 'But Saul and the people spared Agag and the best of the sheep, of the cattle, of the fat calves, of the lambs, and all that was good, and were not willing to utterly destroy them; but everything that was vile and refuse, that they destroyed utterly.'),
  ('1 Samuel', 15, 10, 'Then the LORD’s word came to Samuel, saying,'),
  ('1 Samuel', 15, 11, '“It grieves me that I have set up Saul to be king, for he has turned back from following me, and has not performed my commandments.” Samuel was angry; and he cried to the LORD all night.'),
  ('1 Samuel', 15, 12, 'Samuel rose early to meet Saul in the morning; and Samuel was told, saying, “Saul came to Carmel, and behold, he set up a monument for himself, turned, passed on, and went down to Gilgal.”'),
  ('1 Samuel', 15, 13, 'Samuel came to Saul; and Saul said to him, “You are blessed by the LORD! I have performed the commandment of the LORD.”'),
  ('1 Samuel', 15, 14, 'Samuel said, “Then what does this bleating of the sheep in my ears and the lowing of the cattle which I hear mean?”'),
  ('1 Samuel', 15, 15, 'Saul said, “They have brought them from the Amalekites; for the people spared the best of the sheep and of the cattle, to sacrifice to the LORD your God. We have utterly destroyed the rest.”'),
  ('1 Samuel', 15, 16, 'Then Samuel said to Saul, “Stay, and I will tell you what the LORD said to me last night.” He said to him, “Say on.”'),
  ('1 Samuel', 15, 17, 'Samuel said, “Though you were little in your own sight, weren’t you made the head of the tribes of Israel? The LORD anointed you king over Israel;'),
  ('1 Samuel', 15, 18, 'and the LORD sent you on a journey, and said, ‘Go, and utterly destroy the sinners the Amalekites, and fight against them until they are consumed.’'),
  ('1 Samuel', 15, 19, 'Why then didn’t you obey the LORD’s voice, but took the plunder, and did that which was evil in the LORD’s sight?”'),
  ('1 Samuel', 15, 20, 'Saul said to Samuel, “But I have obeyed the LORD’s voice, and have gone the way which the LORD sent me, and have brought Agag the king of Amalek, and have utterly destroyed the Amalekites.'),
  ('1 Samuel', 15, 21, 'But the people took of the plunder, sheep and cattle, the best of the devoted things, to sacrifice to the LORD your God in Gilgal.”'),
  ('1 Samuel', 15, 22, 'Samuel said, “Has the LORD as great delight in burnt offerings and sacrifices, as in obeying the LORD’s voice? Behold, to obey is better than sacrifice, and to listen than the fat of rams.'),
  ('1 Samuel', 15, 23, 'For rebellion is as the sin of witchcraft, and stubbornness is as idolatry and teraphim. Because you have rejected the LORD’s word, he has also rejected you from being king.”'),
  ('1 Samuel', 15, 24, 'Saul said to Samuel, “I have sinned; for I have transgressed the commandment of the LORD and your words, because I feared the people and obeyed their voice.'),
  ('1 Samuel', 15, 25, 'Now therefore, please pardon my sin, and turn again with me, that I may worship the LORD.”'),
  ('1 Samuel', 15, 26, 'Samuel said to Saul, “I will not return with you; for you have rejected the LORD’s word, and the LORD has rejected you from being king over Israel.”'),
  ('1 Samuel', 15, 27, 'As Samuel turned around to go away, Saul grabbed the skirt of his robe, and it tore.'),
  ('1 Samuel', 15, 28, 'Samuel said to him, “The LORD has torn the kingdom of Israel from you today, and has given it to a neighbor of yours who is better than you.'),
  ('1 Samuel', 15, 29, 'Also the Strength of Israel will not lie nor repent; for he is not a man, that he should repent.”'),
  ('1 Samuel', 15, 30, 'Then he said, “I have sinned; yet please honor me now before the elders of my people and before Israel, and come back with me, that I may worship the LORD your God.”'),
  ('1 Samuel', 15, 31, 'So Samuel went back with Saul; and Saul worshiped the LORD.'),
  ('1 Samuel', 15, 32, 'Then Samuel said, “Bring Agag the king of the Amalekites here to me!” Agag came to him cheerfully. Agag said, “Surely the bitterness of death is past.”'),
  ('1 Samuel', 15, 33, 'Samuel said, “As your sword has made women childless, so your mother will be childless among women!” Then Samuel cut Agag in pieces before the LORD in Gilgal.'),
  ('1 Samuel', 15, 34, 'Then Samuel went to Ramah; and Saul went up to his house to Gibeah of Saul.'),
  ('1 Samuel', 15, 35, 'Samuel came no more to see Saul until the day of his death, but Samuel mourned for Saul. The LORD grieved that he had made Saul king over Israel.'),
  ('1 Samuel', 16, 1, 'The LORD said to Samuel, “How long will you mourn for Saul, since I have rejected him from being king over Israel? Fill your horn with oil, and go. I will send you to Jesse the Bethlehemite, for I have provided a king for myself among his sons.”'),
  ('1 Samuel', 16, 2, 'Samuel said, “How can I go? If Saul hears it, he will kill me.” The LORD said, “Take a heifer with you, and say, ‘I have come to sacrifice to the LORD.’'),
  ('1 Samuel', 16, 3, 'Call Jesse to the sacrifice, and I will show you what you shall do. You shall anoint to me him whom I name to you.”'),
  ('1 Samuel', 16, 4, 'Samuel did that which the LORD spoke, and came to Bethlehem. The elders of the city came to meet him trembling, and said, “Do you come peaceably?”');
INSERT INTO bible_verses (book_name, chapter, verse, text) VALUES
  ('1 Samuel', 16, 5, 'He said, “Peaceably; I have come to sacrifice to the LORD. Sanctify yourselves, and come with me to the sacrifice.” He sanctified Jesse and his sons, and called them to the sacrifice.'),
  ('1 Samuel', 16, 6, 'When they had come, he looked at Eliab, and said, “Surely the LORD’s anointed is before him.”'),
  ('1 Samuel', 16, 7, 'But the LORD said to Samuel, “Don’t look on his face, or on the height of his stature, because I have rejected him; for I don’t see as man sees. For man looks at the outward appearance, but the LORD looks at the heart.”'),
  ('1 Samuel', 16, 8, 'Then Jesse called Abinadab, and made him pass before Samuel. He said, “The LORD has not chosen this one, either.”'),
  ('1 Samuel', 16, 9, 'Then Jesse made Shammah to pass by. He said, “The LORD has not chosen this one, either.”'),
  ('1 Samuel', 16, 10, 'Jesse made seven of his sons to pass before Samuel. Samuel said to Jesse, “The LORD has not chosen these.”'),
  ('1 Samuel', 16, 11, 'Samuel said to Jesse, “Are all your children here?” He said, “There remains yet the youngest. Behold, he is keeping the sheep.” Samuel said to Jesse, “Send and get him, for we will not sit down until he comes here.”'),
  ('1 Samuel', 16, 12, 'He sent, and brought him in. Now he was ruddy, with a handsome face and good appearance. The LORD said, “Arise! Anoint him, for this is he.”'),
  ('1 Samuel', 16, 13, 'Then Samuel took the horn of oil and anointed him in the middle of his brothers. Then the LORD’s Spirit came mightily on David from that day forward. So Samuel rose up and went to Ramah.'),
  ('1 Samuel', 16, 14, 'Now the LORD’s Spirit departed from Saul, and an evil spirit from the LORD troubled him.'),
  ('1 Samuel', 16, 15, 'Saul’s servants said to him, “See now, an evil spirit from God troubles you.'),
  ('1 Samuel', 16, 16, 'Let our lord now command your servants who are in front of you to seek out a man who is a skillful player on the harp. Then when the evil spirit from God is on you, he will play with his hand, and you will be well.”'),
  ('1 Samuel', 16, 17, 'Saul said to his servants, “Provide me now a man who can play well, and bring him to me.”'),
  ('1 Samuel', 16, 18, 'Then one of the young men answered and said, “Behold, I have seen a son of Jesse the Bethlehemite who is skillful in playing, a mighty man of valor, a man of war, prudent in speech, and a handsome person; and the LORD is with him.”'),
  ('1 Samuel', 16, 19, 'Therefore Saul sent messengers to Jesse, and said, “Send me David your son, who is with the sheep.”'),
  ('1 Samuel', 16, 20, 'Jesse took a donkey loaded with bread, a container of wine, and a young goat, and sent them by David his son to Saul.'),
  ('1 Samuel', 16, 21, 'David came to Saul and stood before him. He loved him greatly; and he became his armor bearer.'),
  ('1 Samuel', 16, 22, 'Saul sent to Jesse, saying, “Please let David stand before me, for he has found favor in my sight.”'),
  ('1 Samuel', 16, 23, 'When the spirit from God was on Saul, David took the harp and played with his hand; so Saul was refreshed and was well, and the evil spirit departed from him.'),
  ('1 Samuel', 17, 1, 'Now the Philistines gathered together their armies to battle; and they were gathered together at Socoh, which belongs to Judah, and encamped between Socoh and Azekah in Ephesdammim.'),
  ('1 Samuel', 17, 2, 'Saul and the men of Israel were gathered together, and encamped in the valley of Elah, and set the battle in array against the Philistines.'),
  ('1 Samuel', 17, 3, 'The Philistines stood on the mountain on the one side, and Israel stood on the mountain on the other side: and there was a valley between them.'),
  ('1 Samuel', 17, 4, 'A champion out of the camp of the Philistines named Goliath of Gath, whose height was six cubits and a span went out.'),
  ('1 Samuel', 17, 5, 'He had a helmet of bronze on his head, and he wore a coat of mail; and the weight of the coat was five thousand shekels of bronze.'),
  ('1 Samuel', 17, 6, 'He had bronze shin armor on his legs and a bronze javelin between his shoulders.'),
  ('1 Samuel', 17, 7, 'The staff of his spear was like a weaver’s beam; and his spear’s head weighed six hundred shekels of iron. His shield bearer went before him.'),
  ('1 Samuel', 17, 8, 'He stood and cried to the armies of Israel, and said to them, “Why have you come out to set your battle in array? Am I not a Philistine, and you servants to Saul? Choose a man for yourselves, and let him come down to me.'),
  ('1 Samuel', 17, 9, 'If he is able to fight with me and kill me, then will we be your servants; but if I prevail against him and kill him, then you will be our servants and serve us.”'),
  ('1 Samuel', 17, 10, 'The Philistine said, “I defy the armies of Israel today! Give me a man, that we may fight together!”'),
  ('1 Samuel', 17, 11, 'When Saul and all Israel heard those words of the Philistine, they were dismayed and greatly afraid.'),
  ('1 Samuel', 17, 12, 'Now David was the son of that Ephrathite of Bethlehem Judah, whose name was Jesse; and he had eight sons. The man was an elderly old man in the days of Saul.'),
  ('1 Samuel', 17, 13, 'The three oldest sons of Jesse had gone after Saul to the battle; and the names of his three sons who went to the battle were Eliab the firstborn, and next to him Abinadab, and the third Shammah.'),
  ('1 Samuel', 17, 14, 'David was the youngest; and the three oldest followed Saul.'),
  ('1 Samuel', 17, 15, 'Now David went back and forth from Saul to feed his father’s sheep at Bethlehem.'),
  ('1 Samuel', 17, 16, 'The Philistine came near morning and evening, and presented himself forty days.'),
  ('1 Samuel', 17, 17, 'Jesse said to David his son, “Now take for your brothers an ephah of this parched grain and these ten loaves, and carry them quickly to the camp to your brothers;'),
  ('1 Samuel', 17, 18, 'and bring these ten cheeses to the captain of their thousand; and see how your brothers are doing, and bring back news.”'),
  ('1 Samuel', 17, 19, 'Now Saul, and they, and all the men of Israel were in the valley of Elah, fighting with the Philistines.'),
  ('1 Samuel', 17, 20, 'David rose up early in the morning and left the sheep with a keeper, and took the provisions and went, as Jesse had commanded him. He came to the place of the wagons as the army which was going out to the fight shouted for the battle.'),
  ('1 Samuel', 17, 21, 'Israel and the Philistines put the battle in array, army against army.'),
  ('1 Samuel', 17, 22, 'David left his baggage in the hand of the keeper of the baggage and ran to the army, and came and greeted his brothers.'),
  ('1 Samuel', 17, 23, 'As he talked with them, behold, the champion, the Philistine of Gath, Goliath by name, came up out of the ranks of the Philistines, and said the same words; and David heard them.'),
  ('1 Samuel', 17, 24, 'All the men of Israel, when they saw the man, fled from him and were terrified.'),
  ('1 Samuel', 17, 25, 'The men of Israel said, “Have you seen this man who has come up? He has surely come up to defy Israel. The king will give great riches to the man who kills him, and will give him his daughter, and will make his father’s house tax-free in Israel.”'),
  ('1 Samuel', 17, 26, 'David spoke to the men who stood by him, saying, “What shall be done to the man who kills this Philistine and takes away the reproach from Israel? For who is this uncircumcised Philistine, that he should defy the armies of the living God?”'),
  ('1 Samuel', 17, 27, 'The people answered him in this way, saying, “So shall it be done to the man who kills him.”'),
  ('1 Samuel', 17, 28, 'Eliab his oldest brother heard when he spoke to the men; and Eliab’s anger burned against David, and he said, “Why have you come down? With whom have you left those few sheep in the wilderness? I know your pride and the evil of your heart; for you have come down that you might see the battle.”'),
  ('1 Samuel', 17, 29, 'David said, “What have I now done? Is there not a cause?”'),
  ('1 Samuel', 17, 30, 'He turned away from him toward another, and spoke like that again; and the people answered him again the same way.'),
  ('1 Samuel', 17, 31, 'When the words were heard which David spoke, they rehearsed them before Saul; and he sent for him.'),
  ('1 Samuel', 17, 32, 'David said to Saul, “Let no man’s heart fail because of him. Your servant will go and fight with this Philistine.”'),
  ('1 Samuel', 17, 33, 'Saul said to David, “You are not able to go against this Philistine to fight with him; for you are but a youth, and he a man of war from his youth.”'),
  ('1 Samuel', 17, 34, 'David said to Saul, “Your servant was keeping his father’s sheep; and when a lion or a bear came and took a lamb out of the flock,'),
  ('1 Samuel', 17, 35, 'I went out after him, struck him, and rescued it out of his mouth. When he arose against me, I caught him by his beard, struck him, and killed him.'),
  ('1 Samuel', 17, 36, 'Your servant struck both the lion and the bear. This uncircumcised Philistine shall be as one of them, since he has defied the armies of the living God.”'),
  ('1 Samuel', 17, 37, 'David said, “The LORD, who delivered me out of the paw of the lion and out of the paw of the bear, will deliver me out of the hand of this Philistine.” Saul said to David, “Go! The LORD will be with you.”'),
  ('1 Samuel', 17, 38, 'Saul dressed David with his clothing. He put a helmet of bronze on his head, and he clad him with a coat of mail.'),
  ('1 Samuel', 17, 39, 'David strapped his sword on his clothing and he tried to move, for he had not tested it. David said to Saul, “I can’t go with these, for I have not tested them.” Then David took them off.'),
  ('1 Samuel', 17, 40, 'He took his staff in his hand, and chose for himself five smooth stones out of the brook, and put them in the pouch of his shepherd’s bag which he had. His sling was in his hand; and he came near to the Philistine.'),
  ('1 Samuel', 17, 41, 'The Philistine walked and came near to David; and the man who bore the shield went before him.'),
  ('1 Samuel', 17, 42, 'When the Philistine looked around and saw David, he disdained him; for he was but a youth, and ruddy, and had a good looking face.'),
  ('1 Samuel', 17, 43, 'The Philistine said to David, “Am I a dog, that you come to me with sticks?” The Philistine cursed David by his gods.'),
  ('1 Samuel', 17, 44, 'The Philistine said to David, “Come to me, and I will give your flesh to the birds of the sky and to the animals of the field.”'),
  ('1 Samuel', 17, 45, 'Then David said to the Philistine, “You come to me with a sword, with a spear, and with a javelin; but I come to you in the name of the LORD of Armies, the God of the armies of Israel, whom you have defied.'),
  ('1 Samuel', 17, 46, 'Today, the LORD will deliver you into my hand. I will strike you and take your head from off you. I will give the dead bodies of the army of the Philistines today to the birds of the sky and to the wild animals of the earth, that all the earth may know that there is a God in Israel,'),
  ('1 Samuel', 17, 47, 'and that all this assembly may know that the LORD doesn’t save with sword and spear; for the battle is the LORD’s, and he will give you into our hand.”'),
  ('1 Samuel', 17, 48, 'When the Philistine arose, and walked and came near to meet David, David hurried and ran toward the army to meet the Philistine.'),
  ('1 Samuel', 17, 49, 'David put his hand in his bag, took a stone and slung it, and struck the Philistine in his forehead. The stone sank into his forehead, and he fell on his face to the earth.'),
  ('1 Samuel', 17, 50, 'So David prevailed over the Philistine with a sling and with a stone, and struck the Philistine and killed him; but there was no sword in David’s hand.'),
  ('1 Samuel', 17, 51, 'Then David ran, stood over the Philistine, took his sword, drew it out of its sheath, killed him, and cut off his head with it. When the Philistines saw that their champion was dead, they fled.'),
  ('1 Samuel', 17, 52, 'The men of Israel and of Judah arose and shouted, and pursued the Philistines as far as Gai and to the gates of Ekron. The wounded of the Philistines fell down by the way to Shaaraim, even to Gath and to Ekron.'),
  ('1 Samuel', 17, 53, 'The children of Israel returned from chasing after the Philistines, and they plundered their camp.'),
  ('1 Samuel', 17, 54, 'David took the head of the Philistine and brought it to Jerusalem, but he put his armor in his tent.'),
  ('1 Samuel', 17, 55, 'When Saul saw David go out against the Philistine, he said to Abner, the captain of the army, “Abner, whose son is this youth?” Abner said, “As your soul lives, O king, I can’t tell.”'),
  ('1 Samuel', 17, 56, 'The king said, “Inquire whose son the young man is!”'),
  ('1 Samuel', 17, 57, 'As David returned from the slaughter of the Philistine, Abner took him and brought him before Saul with the head of the Philistine in his hand.'),
  ('1 Samuel', 17, 58, 'Saul said to him, “Whose son are you, you young man?” David answered, “I am the son of your servant Jesse the Bethlehemite.”'),
  ('1 Samuel', 18, 1, 'When he had finished speaking to Saul, the soul of Jonathan was knit with the soul of David, and Jonathan loved him as his own soul.'),
  ('1 Samuel', 18, 2, 'Saul took him that day, and wouldn’t let him go home to his father’s house any more.'),
  ('1 Samuel', 18, 3, 'Then Jonathan and David made a covenant, because he loved him as his own soul.'),
  ('1 Samuel', 18, 4, 'Jonathan stripped himself of the robe that was on him and gave it to David with his clothing, even including his sword, his bow, and his sash.'),
  ('1 Samuel', 18, 5, 'David went out wherever Saul sent him, and behaved himself wisely; and Saul set him over the men of war. It was good in the sight of all the people, and also in the sight of Saul’s servants.'),
  ('1 Samuel', 18, 6, 'As they came, when David returned from the slaughter of the Philistine, the women came out of all the cities of Israel, singing and dancing, to meet King Saul with tambourines, with joy, and with instruments of music.'),
  ('1 Samuel', 18, 7, 'The women sang to one another as they played, and said, “Saul has slain his thousands, and David his ten thousands.”'),
  ('1 Samuel', 18, 8, 'Saul was very angry, and this saying displeased him. He said, “They have credited David with ten thousands, and they have only credited me with thousands. What can he have more but the kingdom?”'),
  ('1 Samuel', 18, 9, 'Saul watched David from that day and forward.'),
  ('1 Samuel', 18, 10, 'On the next day, an evil spirit from God came mightily on Saul, and he prophesied in the middle of the house. David played with his hand, as he did day by day. Saul had his spear in his hand;'),
  ('1 Samuel', 18, 11, 'and Saul threw the spear, for he said, “I will pin David to the wall!” David escaped from his presence twice.'),
  ('1 Samuel', 18, 12, 'Saul was afraid of David, because the LORD was with him, and had departed from Saul.'),
  ('1 Samuel', 18, 13, 'Therefore Saul removed him from his presence, and made him his captain over a thousand; and he went out and came in before the people.'),
  ('1 Samuel', 18, 14, 'David behaved himself wisely in all his ways; and the LORD was with him.'),
  ('1 Samuel', 18, 15, 'When Saul saw that he behaved himself very wisely, he stood in awe of him.'),
  ('1 Samuel', 18, 16, 'But all Israel and Judah loved David; for he went out and came in before them.'),
  ('1 Samuel', 18, 17, 'Saul said to David, “Behold, my elder daughter Merab. I will give her to you as wife. Only be valiant for me, and fight the LORD’s battles.” For Saul said, “Don’t let my hand be on him, but let the hand of the Philistines be on him.”'),
  ('1 Samuel', 18, 18, 'David said to Saul, “Who am I, and what is my life, or my father’s family in Israel, that I should be son-in-law to the king?”'),
  ('1 Samuel', 18, 19, 'But at the time when Merab, Saul’s daughter, should have been given to David, she was given to Adriel the Meholathite as wife.'),
  ('1 Samuel', 18, 20, 'Michal, Saul’s daughter, loved David; and they told Saul, and the thing pleased him.'),
  ('1 Samuel', 18, 21, 'Saul said, I will give her to him, that she may be a snare to him and that the hand of the Philistines may be against him. Therefore Saul said to David a second time, “You shall today be my son-in-law.”'),
  ('1 Samuel', 18, 22, 'Saul commanded his servants, “Talk with David secretly, and say, ‘Behold, the king has delight in you, and all his servants love you. Now therefore be the king’s son-in-law.’”'),
  ('1 Samuel', 18, 23, 'Saul’s servants spoke those words in the ears of David. David said, “Does it seem to you a light thing to be the king’s son-in-law, since I am a poor man and little known?”');
INSERT INTO bible_verses (book_name, chapter, verse, text) VALUES
  ('1 Samuel', 18, 24, 'The servants of Saul told him, saying, “David spoke like this.”'),
  ('1 Samuel', 18, 25, 'Saul said, “Tell David, ‘The king desires no dowry except one hundred foreskins of the Philistines, to be avenged of the king’s enemies.’” Now Saul thought he would make David fall by the hand of the Philistines.'),
  ('1 Samuel', 18, 26, 'When his servants told David these words, it pleased David well to be the king’s son-in-law. Before the deadline,'),
  ('1 Samuel', 18, 27, 'David arose and went, he and his men, and killed two hundred men of the Philistines. Then David brought their foreskins, and they gave them in full number to the king, that he might be the king’s son-in-law. Then Saul gave him Michal his daughter as wife.'),
  ('1 Samuel', 18, 28, 'Saul saw and knew that the LORD was with David; and Michal, Saul’s daughter, loved him.'),
  ('1 Samuel', 18, 29, 'Saul was even more afraid of David; and Saul was David’s enemy continually.'),
  ('1 Samuel', 18, 30, 'Then the princes of the Philistines went out; and as often as they went out, David behaved himself more wisely than all the servants of Saul, so that his name was highly esteemed.'),
  ('1 Samuel', 19, 1, 'Saul spoke to Jonathan his son and to all his servants, that they should kill David. But Jonathan, Saul’s son, greatly delighted in David.'),
  ('1 Samuel', 19, 2, 'Jonathan told David, saying, “Saul my father seeks to kill you. Now therefore, please take care of yourself in the morning, live in a secret place, and hide yourself.'),
  ('1 Samuel', 19, 3, 'I will go out and stand beside my father in the field where you are, and I will talk with my father about you; and if I see anything, I will tell you.”'),
  ('1 Samuel', 19, 4, 'Jonathan spoke good of David to Saul his father, and said to him, “Don’t let the king sin against his servant, against David; because he has not sinned against you, and because his works have been very good toward you;'),
  ('1 Samuel', 19, 5, 'for he put his life in his hand and struck the Philistine, and the LORD worked a great victory for all Israel. You saw it and rejoiced. Why then will you sin against innocent blood, to kill David without a cause?”'),
  ('1 Samuel', 19, 6, 'Saul listened to the voice of Jonathan; and Saul swore, “As the LORD lives, he shall not be put to death.”'),
  ('1 Samuel', 19, 7, 'Jonathan called David, and Jonathan showed him all those things. Then Jonathan brought David to Saul, and he was in his presence as before.'),
  ('1 Samuel', 19, 8, 'There was war again. David went out and fought with the Philistines, and killed them with a great slaughter; and they fled before him.'),
  ('1 Samuel', 19, 9, 'An evil spirit from the LORD was on Saul as he sat in his house with his spear in his hand; and David was playing music with his hand.'),
  ('1 Samuel', 19, 10, 'Saul sought to pin David to the wall with the spear, but he slipped away out of Saul’s presence; and he stuck the spear into the wall. David fled and escaped that night.'),
  ('1 Samuel', 19, 11, 'Saul sent messengers to David’s house to watch him and to kill him in the morning. Michal, David’s wife, told him, saying, “If you don’t save your life tonight, tomorrow you will be killed.”'),
  ('1 Samuel', 19, 12, 'So Michal let David down through the window. He went away, fled, and escaped.'),
  ('1 Samuel', 19, 13, 'Michal took the teraphim and laid it in the bed, and put a pillow of goats’ hair at its head and covered it with clothes.'),
  ('1 Samuel', 19, 14, 'When Saul sent messengers to take David, she said, “He is sick.”'),
  ('1 Samuel', 19, 15, 'Saul sent the messengers to see David, saying, “Bring him up to me in the bed, that I may kill him.”'),
  ('1 Samuel', 19, 16, 'When the messengers came in, behold, the teraphim was in the bed, with the pillow of goats’ hair at its head.'),
  ('1 Samuel', 19, 17, 'Saul said to Michal, “Why have you deceived me like this and let my enemy go, so that he has escaped?” Michal answered Saul, “He said to me, ‘Let me go! Why should I kill you?’”'),
  ('1 Samuel', 19, 18, 'Now David fled and escaped, and came to Samuel at Ramah, and told him all that Saul had done to him. He and Samuel went and lived in Naioth.'),
  ('1 Samuel', 19, 19, 'Saul was told, saying, “Behold, David is at Naioth in Ramah.”'),
  ('1 Samuel', 19, 20, 'Saul sent messengers to seize David; and when they saw the company of the prophets prophesying, and Samuel standing as head over them, God’s Spirit came on Saul’s messengers, and they also prophesied.'),
  ('1 Samuel', 19, 21, 'When Saul was told, he sent other messengers, and they also prophesied. Saul sent messengers again the third time, and they also prophesied.'),
  ('1 Samuel', 19, 22, 'Then he also went to Ramah, and came to the great well that is in Secu: and he asked, “Where are Samuel and David?” One said, “Behold, they are at Naioth in Ramah.”'),
  ('1 Samuel', 19, 23, 'He went there to Naioth in Ramah. Then God’s Spirit came on him also, and he went on, and prophesied, until he came to Naioth in Ramah.'),
  ('1 Samuel', 19, 24, 'He also stripped off his clothes. He also prophesied before Samuel and lay down naked all that day and all that night. Therefore they say, “Is Saul also among the prophets?”'),
  ('1 Samuel', 20, 1, 'David fled from Naioth in Ramah, and came and said to Jonathan, “What have I done? What is my iniquity? What is my sin before your father, that he seeks my life?”'),
  ('1 Samuel', 20, 2, 'He said to him, “Far from it; you will not die. Behold, my father does nothing either great or small, but that he discloses it to me. Why would my father hide this thing from me? It is not so.”'),
  ('1 Samuel', 20, 3, 'David swore moreover, and said, “Your father knows well that I have found favor in your eyes; and he says, ‘Don’t let Jonathan know this, lest he be grieved;’ but truly as the LORD lives, and as your soul lives, there is but a step between me and death.”'),
  ('1 Samuel', 20, 4, 'Then Jonathan said to David, “Whatever your soul desires, I will even do it for you.”'),
  ('1 Samuel', 20, 5, 'David said to Jonathan, “Behold, tomorrow is the new moon, and I should not fail to dine with the king; but let me go, that I may hide myself in the field to the third day at evening.'),
  ('1 Samuel', 20, 6, 'If your father misses me at all, then say, ‘David earnestly asked leave of me that he might run to Bethlehem, his city; for it is the yearly sacrifice there for all the family.’'),
  ('1 Samuel', 20, 7, 'If he says, ‘It is well,’ your servant shall have peace; but if he is angry, then know that evil is determined by him.'),
  ('1 Samuel', 20, 8, 'Therefore deal kindly with your servant, for you have brought your servant into a covenant of the LORD with you; but if there is iniquity in me, kill me yourself, for why should you bring me to your father?”'),
  ('1 Samuel', 20, 9, 'Jonathan said, “Far be it from you; for if I should at all know that evil were determined by my father to come on you, then wouldn’t I tell you that?”'),
  ('1 Samuel', 20, 10, 'Then David said to Jonathan, “Who will tell me if your father answers you roughly?”'),
  ('1 Samuel', 20, 11, 'Jonathan said to David, “Come! Let’s go out into the field.” They both went out into the field.'),
  ('1 Samuel', 20, 12, 'Jonathan said to David, “By the LORD, the God of Israel, when I have sounded out my father about this time tomorrow, or the third day, behold, if there is good toward David, won’t I then send to you and disclose it to you?'),
  ('1 Samuel', 20, 13, 'The LORD do so to Jonathan and more also, should it please my father to do you evil, if I don’t disclose it to you and send you away, that you may go in peace. May the LORD be with you as he has been with my father.'),
  ('1 Samuel', 20, 14, 'You shall not only show me the loving kindness of the LORD while I still live, that I not die;'),
  ('1 Samuel', 20, 15, 'but you shall also not cut off your kindness from my house forever, no, not when the LORD has cut off every one of the enemies of David from the surface of the earth.”'),
  ('1 Samuel', 20, 16, 'So Jonathan made a covenant with David’s house, saying, “The LORD will require it at the hand of David’s enemies.”'),
  ('1 Samuel', 20, 17, 'Jonathan caused David to swear again, for the love that he had to him; for he loved him as he loved his own soul.'),
  ('1 Samuel', 20, 18, 'Then Jonathan said to him, “Tomorrow is the new moon, and you will be missed, because your seat will be empty.'),
  ('1 Samuel', 20, 19, 'When you have stayed three days, go down quickly and come to the place where you hid yourself when this started, and remain by the stone Ezel.'),
  ('1 Samuel', 20, 20, 'I will shoot three arrows on its side, as though I shot at a mark.'),
  ('1 Samuel', 20, 21, 'Behold, I will send the boy, saying, ‘Go, find the arrows!’ If I tell the boy, ‘Behold, the arrows are on this side of you. Take them;’ then come, for there is peace to you and no danger, as the LORD lives.'),
  ('1 Samuel', 20, 22, 'But if I say this to the boy, ‘Behold, the arrows are beyond you,’ then go your way, for the LORD has sent you away.'),
  ('1 Samuel', 20, 23, 'Concerning the matter which you and I have spoken of, behold, the LORD is between you and me forever.”'),
  ('1 Samuel', 20, 24, 'So David hid himself in the field. When the new moon had come, the king sat himself down to eat food.'),
  ('1 Samuel', 20, 25, 'The king sat on his seat, as at other times, even on the seat by the wall; and Jonathan stood up, and Abner sat by Saul’s side, but David’s place was empty.'),
  ('1 Samuel', 20, 26, 'Nevertheless Saul didn’t say anything that day, for he thought, “Something has happened to him. He is not clean. Surely he is not clean.”'),
  ('1 Samuel', 20, 27, 'On the next day after the new moon, the second day, David’s place was empty. Saul said to Jonathan his son, “Why didn’t the son of Jesse come to eat, either yesterday, or today?”'),
  ('1 Samuel', 20, 28, 'Jonathan answered Saul, “David earnestly asked permission of me to go to Bethlehem.'),
  ('1 Samuel', 20, 29, 'He said, ‘Please let me go, for our family has a sacrifice in the city. My brother has commanded me to be there. Now, if I have found favor in your eyes, please let me go away and see my brothers.’ Therefore he has not come to the king’s table.”'),
  ('1 Samuel', 20, 30, 'Then Saul’s anger burned against Jonathan, and he said to him, “You son of a perverse rebellious woman, don’t I know that you have chosen the son of Jesse to your own shame, and to the shame of your mother’s nakedness?'),
  ('1 Samuel', 20, 31, 'For as long as the son of Jesse lives on the earth, you will not be established, nor will your kingdom. Therefore now send and bring him to me, for he shall surely die!”'),
  ('1 Samuel', 20, 32, 'Jonathan answered Saul his father, and said to him, “Why should he be put to death? What has he done?”'),
  ('1 Samuel', 20, 33, 'Saul cast his spear at him to strike him. By this Jonathan knew that his father was determined to put David to death.'),
  ('1 Samuel', 20, 34, 'So Jonathan arose from the table in fierce anger, and ate no food the second day of the month; for he was grieved for David, because his father had treated him shamefully.'),
  ('1 Samuel', 20, 35, 'In the morning, Jonathan went out into the field at the time appointed with David, and a little boy with him.'),
  ('1 Samuel', 20, 36, 'He said to his boy, “Run, find now the arrows which I shoot.” As the boy ran, he shot an arrow beyond him.'),
  ('1 Samuel', 20, 37, 'When the boy had come to the place of the arrow which Jonathan had shot, Jonathan cried after the boy, and said, “Isn’t the arrow beyond you?”'),
  ('1 Samuel', 20, 38, 'Jonathan cried after the boy, “Go fast! Hurry! Don’t delay!” Jonathan’s boy gathered up the arrows, and came to his master.'),
  ('1 Samuel', 20, 39, 'But the boy didn’t know anything. Only Jonathan and David knew the matter.'),
  ('1 Samuel', 20, 40, 'Jonathan gave his weapons to his boy, and said to him, “Go, carry them to the city.”'),
  ('1 Samuel', 20, 41, 'As soon as the boy was gone, David arose out of the south, and fell on his face to the ground, and bowed himself three times. They kissed one another and wept with one another, and David wept the most.'),
  ('1 Samuel', 20, 42, 'Jonathan said to David, “Go in peace, because we have both sworn in the LORD’s name, saying, ‘The LORD is between me and you, and between my offspring and your offspring, forever.’” He arose and departed; and Jonathan went into the city.'),
  ('1 Samuel', 21, 1, 'Then David came to Nob to Ahimelech the priest. Ahimelech came to meet David trembling, and said to him, “Why are you alone, and no man with you?”'),
  ('1 Samuel', 21, 2, 'David said to Ahimelech the priest, “The king has commanded me to do something, and has said to me, ‘Let no one know anything about the business about which I send you, and what I have commanded you. I have sent the young men to a certain place.’'),
  ('1 Samuel', 21, 3, 'Now therefore what is under your hand? Please give me five loaves of bread in my hand, or whatever is available.”'),
  ('1 Samuel', 21, 4, 'The priest answered David, and said, “I have no common bread, but there is holy bread; if only the young men have kept themselves from women.”'),
  ('1 Samuel', 21, 5, 'David answered the priest, and said to him, “Truly, women have been kept from us as usual these three days. When I came out, the vessels of the young men were holy, though it was only a common journey. How much more then today shall their vessels be holy?”'),
  ('1 Samuel', 21, 6, 'So the priest gave him holy bread; for there was no bread there but the show bread that was taken from before the LORD, to be replaced with hot bread in the day when it was taken away.'),
  ('1 Samuel', 21, 7, 'Now a certain man of the servants of Saul was there that day, detained before the LORD; and his name was Doeg the Edomite, the best of the herdsmen who belonged to Saul.'),
  ('1 Samuel', 21, 8, 'David said to Ahimelech, “Isn’t there here under your hand spear or sword? For I haven’t brought my sword or my weapons with me, because the king’s business required haste.”'),
  ('1 Samuel', 21, 9, 'The priest said, “Behold, the sword of Goliath the Philistine, whom you killed in the valley of Elah, is here wrapped in a cloth behind the ephod. If you would like to take that, take it, for there is no other except that here.” David said, “There is none like that. Give it to me.”'),
  ('1 Samuel', 21, 10, 'David arose and fled that day for fear of Saul, and went to Achish the king of Gath.'),
  ('1 Samuel', 21, 11, 'The servants of Achish said to him, “Isn’t this David the king of the land? Didn’t they sing to one another about him in dances, saying, ‘Saul has slain his thousands, and David his ten thousands’?”'),
  ('1 Samuel', 21, 12, 'David laid up these words in his heart, and was very afraid of Achish the king of Gath.'),
  ('1 Samuel', 21, 13, 'He changed his behavior before them and pretended to be insane in their hands, and scribbled on the doors of the gate, and let his spittle fall down on his beard.'),
  ('1 Samuel', 21, 14, 'Then Achish said to his servants, “Look, you see the man is insane. Why then have you brought him to me?'),
  ('1 Samuel', 21, 15, 'Do I lack madmen, that you have brought this fellow to play the madman in my presence? Should this fellow come into my house?”'),
  ('1 Samuel', 22, 1, 'David therefore departed from there and escaped to Adullam’s cave. When his brothers and all his father’s house heard it, they went down there to him.'),
  ('1 Samuel', 22, 2, 'Everyone who was in distress, everyone who was in debt, and everyone who was discontented gathered themselves to him; and he became captain over them. There were with him about four hundred men.'),
  ('1 Samuel', 22, 3, 'David went from there to Mizpeh of Moab; and he said to the king of Moab, “Please let my father and my mother come out to you, until I know what God will do for me.”'),
  ('1 Samuel', 22, 4, 'He brought them before the king of Moab; and they lived with him all the time that David was in the stronghold.'),
  ('1 Samuel', 22, 5, 'The prophet Gad said to David, “Don’t stay in the stronghold. Depart, and go into the land of Judah.” Then David departed, and came into the forest of Hereth.'),
  ('1 Samuel', 22, 6, 'Saul heard that David was discovered, with the men who were with him. Now Saul was sitting in Gibeah, under the tamarisk tree in Ramah, with his spear in his hand, and all his servants were standing around him.'),
  ('1 Samuel', 22, 7, 'Saul said to his servants who stood around him, “Hear now, you Benjamites! Will the son of Jesse give everyone of you fields and vineyards? Will he make you all captains of thousands and captains of hundreds?'),
  ('1 Samuel', 22, 8, 'Is that why all of you have conspired against me, and there is no one who discloses to me when my son makes a treaty with the son of Jesse, and there is none of you who is sorry for me, or discloses to me that my son has stirred up my servant against me, to lie in wait, as it is today?”'),
  ('1 Samuel', 22, 9, 'Then Doeg the Edomite, who stood by the servants of Saul, answered and said, “I saw the son of Jesse coming to Nob, to Ahimelech the son of Ahitub.'),
  ('1 Samuel', 22, 10, 'He inquired of the LORD for him, gave him food, and gave him the sword of Goliath the Philistine.”'),
  ('1 Samuel', 22, 11, 'Then the king sent to call Ahimelech the priest, the son of Ahitub, and all his father’s house, the priests who were in Nob; and they all came to the king.'),
  ('1 Samuel', 22, 12, 'Saul said, “Hear now, you son of Ahitub.” He answered, “Here I am, my lord.”');
INSERT INTO bible_verses (book_name, chapter, verse, text) VALUES
  ('1 Samuel', 22, 13, 'Saul said to him, “Why have you conspired against me, you and the son of Jesse, in that you have given him bread, and a sword, and have inquired of God for him, that he should rise against me, to lie in wait, as it is today?”'),
  ('1 Samuel', 22, 14, 'Then Ahimelech answered the king, and said, “Who among all your servants is so faithful as David, who is the king’s son-in-law, captain of your body guard, and honored in your house?'),
  ('1 Samuel', 22, 15, 'Have I today begun to inquire of God for him? Be it far from me! Don’t let the king impute anything to his servant, nor to all the house of my father; for your servant knew nothing of all this, less or more.”'),
  ('1 Samuel', 22, 16, 'The king said, “You shall surely die, Ahimelech, you and all your father’s house.”'),
  ('1 Samuel', 22, 17, 'The king said to the guard who stood about him, “Turn and kill the priests of the LORD, because their hand also is with David, and because they knew that he fled and didn’t disclose it to me.” But the servants of the king wouldn’t put out their hand to fall on the priests of the LORD.'),
  ('1 Samuel', 22, 18, 'The king said to Doeg, “Turn and attack the priests!” Doeg the Edomite turned, and he attacked the priests, and he killed on that day eighty-five people who wore a linen ephod.'),
  ('1 Samuel', 22, 19, 'He struck Nob, the city of the priests, with the edge of the sword—both men and women, children and nursing babies, and cattle, donkeys, and sheep, with the edge of the sword.'),
  ('1 Samuel', 22, 20, 'One of the sons of Ahimelech the son of Ahitub, named Abiathar, escaped and fled after David.'),
  ('1 Samuel', 22, 21, 'Abiathar told David that Saul had slain the LORD’s priests.'),
  ('1 Samuel', 22, 22, 'David said to Abiathar, “I knew on that day, when Doeg the Edomite was there, that he would surely tell Saul. I am responsible for the death of all the persons of your father’s house.'),
  ('1 Samuel', 22, 23, 'Stay with me. Don’t be afraid, for he who seeks my life seeks your life. You will be safe with me.”'),
  ('1 Samuel', 23, 1, 'David was told, “Behold, the Philistines are fighting against Keilah, and are robbing the threshing floors.”'),
  ('1 Samuel', 23, 2, 'Therefore David inquired of the LORD, saying, “Shall I go and strike these Philistines?” The LORD said to David, “Go strike the Philistines, and save Keilah.”'),
  ('1 Samuel', 23, 3, 'David’s men said to him, “Behold, we are afraid here in Judah. How much more then if we go to Keilah against the armies of the Philistines?”'),
  ('1 Samuel', 23, 4, 'Then David inquired of the LORD yet again. The LORD answered him, and said, “Arise, go down to Keilah; for I will deliver the Philistines into your hand.”'),
  ('1 Samuel', 23, 5, 'David and his men went to Keilah and fought with the Philistines, and brought away their livestock, and killed them with a great slaughter. So David saved the inhabitants of Keilah.'),
  ('1 Samuel', 23, 6, 'When Abiathar the son of Ahimelech fled to David to Keilah, he came down with an ephod in his hand.'),
  ('1 Samuel', 23, 7, 'Saul was told that David had come to Keilah. Saul said, “God has delivered him into my hand, for he is shut in by entering into a town that has gates and bars.”'),
  ('1 Samuel', 23, 8, 'Saul summoned all the people to war, to go down to Keilah to besiege David and his men.'),
  ('1 Samuel', 23, 9, 'David knew that Saul was devising mischief against him. He said to Abiathar the priest, “Bring the ephod here.”'),
  ('1 Samuel', 23, 10, 'Then David said, “O LORD, the God of Israel, your servant has surely heard that Saul seeks to come to Keilah to destroy the city for my sake.'),
  ('1 Samuel', 23, 11, 'Will the men of Keilah deliver me up into his hand? Will Saul come down, as your servant has heard? LORD, the God of Israel, I beg you, tell your servant.” The LORD said, “He will come down.”'),
  ('1 Samuel', 23, 12, 'Then David said, “Will the men of Keilah deliver me and my men into the hand of Saul?” The LORD said, “They will deliver you up.”'),
  ('1 Samuel', 23, 13, 'Then David and his men, who were about six hundred, arose and departed out of Keilah and went wherever they could go. Saul was told that David had escaped from Keilah; and he gave up going there.'),
  ('1 Samuel', 23, 14, 'David stayed in the wilderness in the strongholds, and remained in the hill country in the wilderness of Ziph. Saul sought him every day, but God didn’t deliver him into his hand.'),
  ('1 Samuel', 23, 15, 'David saw that Saul had come out to seek his life. David was in the wilderness of Ziph in the woods.'),
  ('1 Samuel', 23, 16, 'Jonathan, Saul’s son, arose and went to David into the woods, and strengthened his hand in God.'),
  ('1 Samuel', 23, 17, 'He said to him, “Don’t be afraid, for the hand of Saul my father won’t find you; and you will be king over Israel, and I will be next to you; and Saul my father knows that also.”'),
  ('1 Samuel', 23, 18, 'They both made a covenant before the LORD. Then David stayed in the woods and Jonathan went to his house.'),
  ('1 Samuel', 23, 19, 'Then the Ziphites came up to Saul to Gibeah, saying, “Doesn’t David hide himself with us in the strongholds in the woods, in the hill of Hachilah, which is on the south of the desert?'),
  ('1 Samuel', 23, 20, 'Now therefore, O king, come down. According to all the desire of your soul to come down; and our part will be to deliver him up into the king’s hand.”'),
  ('1 Samuel', 23, 21, 'Saul said, “You are blessed by the LORD, for you have had compassion on me.'),
  ('1 Samuel', 23, 22, 'Please go make yet more sure, and know and see his place where his haunt is, and who has seen him there; for I have been told that he is very cunning.'),
  ('1 Samuel', 23, 23, 'See therefore, and take knowledge of all the lurking places where he hides himself; and come again to me with certainty, and I will go with you. It shall happen, if he is in the land, that I will search him out among all the thousands of Judah.”'),
  ('1 Samuel', 23, 24, 'They arose, and went to Ziph before Saul; but David and his men were in the wilderness of Maon, in the Arabah on the south of the desert.'),
  ('1 Samuel', 23, 25, 'Saul and his men went to seek him. When David was told, he went down to the rock, and stayed in the wilderness of Maon. When Saul heard that, he pursued David in the wilderness of Maon.'),
  ('1 Samuel', 23, 26, 'Saul went on this side of the mountain, and David and his men on that side of the mountain; and David hurried to get away for fear of Saul, for Saul and his men surrounded David and his men to take them.'),
  ('1 Samuel', 23, 27, 'But a messenger came to Saul, saying, “Hurry and come, for the Philistines have made a raid on the land!”'),
  ('1 Samuel', 23, 28, 'So Saul returned from pursuing David, and went against the Philistines. Therefore they called that place Sela Hammahlekoth.'),
  ('1 Samuel', 23, 29, 'David went up from there and lived in the strongholds of En Gedi.'),
  ('1 Samuel', 24, 1, 'When Saul had returned from following the Philistines, he was told, “Behold, David is in the wilderness of En Gedi.”'),
  ('1 Samuel', 24, 2, 'Then Saul took three thousand chosen men out of all Israel, and went to seek David and his men on the rocks of the wild goats.'),
  ('1 Samuel', 24, 3, 'He came to the sheep pens by the way, where there was a cave; and Saul went in to relieve himself. Now David and his men were staying in the innermost parts of the cave.'),
  ('1 Samuel', 24, 4, 'David’s men said to him, “Behold, the day of which the LORD said to you, ‘Behold, I will deliver your enemy into your hand, and you shall do to him as it shall seem good to you.’” Then David arose and cut off the skirt of Saul’s robe secretly.'),
  ('1 Samuel', 24, 5, 'Afterward, David’s heart struck him because he had cut off Saul’s skirt.'),
  ('1 Samuel', 24, 6, 'He said to his men, “The LORD forbid that I should do this thing to my lord, the LORD’s anointed, to stretch out my hand against him, since he is the LORD’s anointed.”'),
  ('1 Samuel', 24, 7, 'So David checked his men with these words, and didn’t allow them to rise against Saul. Saul rose up out of the cave, and went on his way.'),
  ('1 Samuel', 24, 8, 'David also arose afterward, and went out of the cave and cried after Saul, saying, “My lord the king!” When Saul looked behind him, David bowed with his face to the earth, and showed respect.'),
  ('1 Samuel', 24, 9, 'David said to Saul, “Why do you listen to men’s words, saying, ‘Behold, David seeks to harm you’?'),
  ('1 Samuel', 24, 10, 'Behold, today your eyes have seen how the LORD had delivered you today into my hand in the cave. Some urged me to kill you, but I spared you. I said, ‘I will not stretch out my hand against my lord, for he is the LORD’s anointed.’'),
  ('1 Samuel', 24, 11, 'Moreover, my father, behold, yes, see the skirt of your robe in my hand; for in that I cut off the skirt of your robe and didn’t kill you, know and see that there is neither evil nor disobedience in my hand. I have not sinned against you, though you hunt for my life to take it.'),
  ('1 Samuel', 24, 12, 'May the LORD judge between me and you, and may the LORD avenge me of you; but my hand will not be on you.'),
  ('1 Samuel', 24, 13, 'As the proverb of the ancients says, ‘Out of the wicked comes wickedness;’ but my hand will not be on you.'),
  ('1 Samuel', 24, 14, 'Against whom has the king of Israel come out? Whom do you pursue? A dead dog? A flea?'),
  ('1 Samuel', 24, 15, 'May the LORD therefore be judge, and give sentence between me and you, and see, and plead my cause, and deliver me out of your hand.”'),
  ('1 Samuel', 24, 16, 'It came to pass, when David had finished speaking these words to Saul, that Saul said, “Is that your voice, my son David?” Saul lifted up his voice and wept.'),
  ('1 Samuel', 24, 17, 'He said to David, “You are more righteous than I; for you have done good to me, whereas I have done evil to you.'),
  ('1 Samuel', 24, 18, 'You have declared today how you have dealt well with me, because when the LORD had delivered me up into your hand, you didn’t kill me.'),
  ('1 Samuel', 24, 19, 'For if a man finds his enemy, will he let him go away unharmed? Therefore may the LORD reward you good for that which you have done to me today.'),
  ('1 Samuel', 24, 20, 'Now, behold, I know that you will surely be king, and that the kingdom of Israel will be established in your hand.'),
  ('1 Samuel', 24, 21, 'Swear now therefore to me by the LORD that you will not cut off my offspring after me, and that you will not destroy my name out of my father’s house.”'),
  ('1 Samuel', 24, 22, 'David swore to Saul. Saul went home, but David and his men went up to the stronghold.'),
  ('1 Samuel', 25, 1, 'Samuel died; and all Israel gathered themselves together and mourned for him, and buried him at his house at Ramah. Then David arose and went down to the wilderness of Paran.'),
  ('1 Samuel', 25, 2, 'There was a man in Maon whose possessions were in Carmel; and the man was very great. He had three thousand sheep and a thousand goats; and he was shearing his sheep in Carmel.'),
  ('1 Samuel', 25, 3, 'Now the name of the man was Nabal; and the name of his wife Abigail. This woman was intelligent and had a beautiful face; but the man was surly and evil in his doings. He was of the house of Caleb.'),
  ('1 Samuel', 25, 4, 'David heard in the wilderness that Nabal was shearing his sheep.'),
  ('1 Samuel', 25, 5, 'David sent ten young men; and David said to the young men, “Go up to Carmel, and go to Nabal, and greet him in my name.'),
  ('1 Samuel', 25, 6, 'Tell him, ‘Long life to you! Peace be to you! Peace be to your house! Peace be to all that you have!'),
  ('1 Samuel', 25, 7, 'Now I have heard that you have shearers. Your shepherds have now been with us, and we didn’t harm them. Nothing was missing from them all the time they were in Carmel.'),
  ('1 Samuel', 25, 8, 'Ask your young men, and they will tell you. Therefore let the young men find favor in your eyes, for we come on a good day. Please give whatever comes to your hand to your servants and to your son David.’”'),
  ('1 Samuel', 25, 9, 'When David’s young men came, they spoke to Nabal all those words in the name of David, and waited.'),
  ('1 Samuel', 25, 10, 'Nabal answered David’s servants and said, “Who is David? Who is the son of Jesse? There are many servants who break away from their masters these days.'),
  ('1 Samuel', 25, 11, 'Shall I then take my bread, my water, and my meat that I have killed for my shearers, and give it to men who I don’t know where they come from?”'),
  ('1 Samuel', 25, 12, 'So David’s young men turned on their way and went back, and came and told him all these words.'),
  ('1 Samuel', 25, 13, 'David said to his men, “Every man put on his sword!” Every man put on his sword. David also put on his sword. About four hundred men followed David, and two hundred stayed by the baggage.'),
  ('1 Samuel', 25, 14, 'But one of the young men told Abigail, Nabal’s wife, saying, “Behold, David sent messengers out of the wilderness to greet our master; and he insulted them.'),
  ('1 Samuel', 25, 15, 'But the men were very good to us, and we were not harmed, and we didn’t miss anything as long as we went with them, when we were in the fields.'),
  ('1 Samuel', 25, 16, 'They were a wall to us both by night and by day, all the while we were with them keeping the sheep.'),
  ('1 Samuel', 25, 17, 'Now therefore know and consider what you will do; for evil is determined against our master and against all his house, for he is such a worthless fellow that one can’t speak to him.”'),
  ('1 Samuel', 25, 18, 'Then Abigail hurried and took two hundred loaves of bread, two containers of wine, five sheep ready dressed, five seahs of parched grain, one hundred clusters of raisins, and two hundred cakes of figs, and laid them on donkeys.'),
  ('1 Samuel', 25, 19, 'She said to her young men, “Go on before me. Behold, I am coming after you.” But she didn’t tell her husband, Nabal.'),
  ('1 Samuel', 25, 20, 'As she rode on her donkey, and came down hidden by the mountain, behold, David and his men came down toward her, and she met them.'),
  ('1 Samuel', 25, 21, 'Now David had said, “Surely in vain I have kept all that this fellow has in the wilderness, so that nothing was missed of all that pertained to him. He has returned me evil for good.'),
  ('1 Samuel', 25, 22, 'God do so to the enemies of David, and more also, if I leave of all that belongs to him by the morning light so much as one who urinates on a wall.”'),
  ('1 Samuel', 25, 23, 'When Abigail saw David, she hurried and got off her donkey, and fell before David on her face and bowed herself to the ground.'),
  ('1 Samuel', 25, 24, 'She fell at his feet and said, “On me, my lord, on me be the blame! Please let your servant speak in your ears. Hear the words of your servant.'),
  ('1 Samuel', 25, 25, 'Please don’t let my lord pay attention to this worthless fellow, Nabal, for as his name is, so is he. Nabal is his name, and folly is with him; but I, your servant, didn’t see my lord’s young men whom you sent.'),
  ('1 Samuel', 25, 26, 'Now therefore, my lord, as the LORD lives and as your soul lives, since the LORD has withheld you from blood guiltiness and from avenging yourself with your own hand, now therefore let your enemies and those who seek evil to my lord be as Nabal.'),
  ('1 Samuel', 25, 27, 'Now this present which your servant has brought to my lord, let it be given to the young men who follow my lord.'),
  ('1 Samuel', 25, 28, 'Please forgive the trespass of your servant. For the LORD will certainly make my lord a sure house, because my lord fights the LORD’s battles. Evil will not be found in you all your days.'),
  ('1 Samuel', 25, 29, 'Though men may rise up to pursue you and to seek your soul, yet the soul of my lord will be bound in the bundle of life with the LORD your God. He will sling out the souls of your enemies as from a sling’s pocket.'),
  ('1 Samuel', 25, 30, 'It will come to pass, when the LORD has done to my lord according to all the good that he has spoken concerning you, and has appointed you prince over Israel,'),
  ('1 Samuel', 25, 31, 'that this shall be no grief to you, nor offense of heart to my lord, either that you have shed blood without cause, or that my lord has avenged himself. When the LORD has dealt well with my lord, then remember your servant.”'),
  ('1 Samuel', 25, 32, 'David said to Abigail, “Blessed is the LORD, the God of Israel, who sent you today to meet me!'),
  ('1 Samuel', 25, 33, 'Blessed is your discretion, and blessed are you, who have kept me today from blood guiltiness, and from avenging myself with my own hand.'),
  ('1 Samuel', 25, 34, 'For indeed, as the LORD the God of Israel lives, who has withheld me from harming you, unless you had hurried and come to meet me, surely there wouldn’t have been left to Nabal by the morning light so much as one who urinates on a wall.”'),
  ('1 Samuel', 25, 35, 'So David received from her hand that which she had brought him. Then he said to her, “Go up in peace to your house. Behold, I have listened to your voice and have granted your request.”'),
  ('1 Samuel', 25, 36, 'Abigail came to Nabal; and behold, he held a feast in his house like the feast of a king. Nabal’s heart was merry within him, for he was very drunk. Therefore she told him nothing until the morning light.'),
  ('1 Samuel', 25, 37, 'In the morning, when the wine had gone out of Nabal, his wife told him these things; and his heart died within him, and he became as a stone.'),
  ('1 Samuel', 25, 38, 'About ten days later, the LORD struck Nabal, so that he died.');
INSERT INTO bible_verses (book_name, chapter, verse, text) VALUES
  ('1 Samuel', 25, 39, 'When David heard that Nabal was dead, he said, “Blessed is the LORD, who has pleaded the cause of my reproach from the hand of Nabal, and has kept back his servant from evil. The LORD has returned the evildoing of Nabal on his own head.” David sent and spoke concerning Abigail, to take her to himself as wife.'),
  ('1 Samuel', 25, 40, 'When David’s servants had come to Abigail to Carmel, they spoke to her, saying, “David has sent us to you, to take you to him as wife.”'),
  ('1 Samuel', 25, 41, 'She arose and bowed herself with her face to the earth, and said, “Behold, your servant is a servant to wash the feet of the servants of my lord.”'),
  ('1 Samuel', 25, 42, 'Abigail hurriedly arose and rode on a donkey with her five maids who followed her; and she went after the messengers of David, and became his wife.'),
  ('1 Samuel', 25, 43, 'David also took Ahinoam of Jezreel; and they both became his wives.'),
  ('1 Samuel', 25, 44, 'Now Saul had given Michal his daughter, David’s wife, to Palti the son of Laish, who was of Gallim.'),
  ('1 Samuel', 26, 1, 'The Ziphites came to Saul to Gibeah, saying, “Doesn’t David hide himself in the hill of Hachilah, which is before the desert?”'),
  ('1 Samuel', 26, 2, 'Then Saul arose and went down to the wilderness of Ziph, having three thousand chosen men of Israel with him, to seek David in the wilderness of Ziph.'),
  ('1 Samuel', 26, 3, 'Saul encamped in the hill of Hachilah, which is before the desert, by the way. But David stayed in the wilderness, and he saw that Saul came after him into the wilderness.'),
  ('1 Samuel', 26, 4, 'David therefore sent out spies, and understood that Saul had certainly come.'),
  ('1 Samuel', 26, 5, 'Then David arose and came to the place where Saul had encamped; and David saw the place where Saul lay, with Abner the son of Ner, the captain of his army. Saul lay within the place of the wagons, and the people were encamped around him.'),
  ('1 Samuel', 26, 6, 'Then David answered and said to Ahimelech the Hittite, and to Abishai the son of Zeruiah, brother of Joab, saying, “Who will go down with me to Saul to the camp?” Abishai said, “I will go down with you.”'),
  ('1 Samuel', 26, 7, 'So David and Abishai came to the people by night; and, behold, Saul lay sleeping within the place of the wagons, with his spear stuck in the ground at his head; and Abner and the people lay around him.'),
  ('1 Samuel', 26, 8, 'Then Abishai said to David, “God has delivered up your enemy into your hand today. Now therefore please let me strike him with the spear to the earth at one stroke, and I will not strike him the second time.”'),
  ('1 Samuel', 26, 9, 'David said to Abishai, “Don’t destroy him, for who can stretch out his hand against the LORD’s anointed, and be guiltless?”'),
  ('1 Samuel', 26, 10, 'David said, “As the LORD lives, the LORD will strike him; or his day shall come to die, or he shall go down into battle and perish.'),
  ('1 Samuel', 26, 11, 'The LORD forbid that I should stretch out my hand against the LORD’s anointed; but now please take the spear that is at his head and the jar of water, and let’s go.”'),
  ('1 Samuel', 26, 12, 'So David took the spear and the jar of water from Saul’s head, and they went away. No man saw it, or knew it, nor did any awake; for they were all asleep, because a deep sleep from the LORD had fallen on them.'),
  ('1 Samuel', 26, 13, 'Then David went over to the other side, and stood on the top of the mountain far away, a great space being between them;'),
  ('1 Samuel', 26, 14, 'and David cried to the people, and to Abner the son of Ner, saying, “Don’t you answer, Abner?” Then Abner answered, “Who are you who calls to the king?”'),
  ('1 Samuel', 26, 15, 'David said to Abner, “Aren’t you a man? Who is like you in Israel? Why then have you not kept watch over your lord the king? For one of the people came in to destroy your lord the king.'),
  ('1 Samuel', 26, 16, 'This thing isn’t good that you have done. As the LORD lives, you are worthy to die, because you have not kept watch over your lord, the LORD’s anointed. Now see where the king’s spear is, and the jar of water that was at his head.”'),
  ('1 Samuel', 26, 17, 'Saul recognized David’s voice, and said, “Is this your voice, my son David?” David said, “It is my voice, my lord, O king.”'),
  ('1 Samuel', 26, 18, 'He said, “Why does my lord pursue his servant? For what have I done? What evil is in my hand?'),
  ('1 Samuel', 26, 19, 'Now therefore, please let my lord the king hear the words of his servant. If it is so that the LORD has stirred you up against me, let him accept an offering. But if it is the children of men, they are cursed before the LORD; for they have driven me out today that I shouldn’t cling to the LORD’s inheritance, saying, ‘Go, serve other gods!’'),
  ('1 Samuel', 26, 20, 'Now therefore, don’t let my blood fall to the earth away from the presence of the LORD; for the king of Israel has come out to seek a flea, as when one hunts a partridge in the mountains.”'),
  ('1 Samuel', 26, 21, 'Then Saul said, “I have sinned. Return, my son David; for I will no more do you harm, because my life was precious in your eyes today. Behold, I have played the fool, and have erred exceedingly.”'),
  ('1 Samuel', 26, 22, 'David answered, “Behold the spear, O king! Let one of the young men come over and get it.'),
  ('1 Samuel', 26, 23, 'The LORD will give to every man his righteousness and his faithfulness; because the LORD delivered you into my hand today, and I wouldn’t stretch out my hand against the LORD’s anointed.'),
  ('1 Samuel', 26, 24, 'Behold, as your life was respected today in my eyes, so let my life be respected in the LORD’s eyes, and let him deliver me out of all oppression.”'),
  ('1 Samuel', 26, 25, 'Then Saul said to David, “You are blessed, my son David. You will both do mightily, and will surely prevail.” So David went his way, and Saul returned to his place.'),
  ('1 Samuel', 27, 1, 'David said in his heart, “I will now perish one day by the hand of Saul. There is nothing better for me than that I should escape into the land of the Philistines; and Saul will despair of me, to seek me any more in all the borders of Israel. So I will escape out of his hand.”'),
  ('1 Samuel', 27, 2, 'David arose and passed over, he and the six hundred men who were with him, to Achish the son of Maoch, king of Gath.'),
  ('1 Samuel', 27, 3, 'David lived with Achish at Gath, he and his men, every man with his household, even David with his two wives, Ahinoam the Jezreelitess and Abigail the Carmelitess, Nabal’s wife.'),
  ('1 Samuel', 27, 4, 'Saul was told that David had fled to Gath, so he stopped looking for him.'),
  ('1 Samuel', 27, 5, 'David said to Achish, “If now I have found favor in your eyes, let them give me a place in one of the cities in the country, that I may dwell there. For why should your servant dwell in the royal city with you?”'),
  ('1 Samuel', 27, 6, 'Then Achish gave him Ziklag that day: therefore Ziklag belongs to the kings of Judah to this day.'),
  ('1 Samuel', 27, 7, 'The number of the days that David lived in the country of the Philistines was a full year and four months.'),
  ('1 Samuel', 27, 8, 'David and his men went up and raided the Geshurites, the Girzites, and the Amalekites; for those were the inhabitants of the land who were of old, on the way to Shur, even to the land of Egypt.'),
  ('1 Samuel', 27, 9, 'David struck the land, and saved no man or woman alive, and took away the sheep, the cattle, the donkeys, the camels, and the clothing. Then he returned, and came to Achish.'),
  ('1 Samuel', 27, 10, 'Achish said, “Against whom have you made a raid today?” David said, “Against the South of Judah, against the South of the Jerahmeelites, and against the South of the Kenites.”'),
  ('1 Samuel', 27, 11, 'David saved neither man nor woman alive to bring them to Gath, saying, “Lest they should tell about us, saying, ‘David did this, and this has been his way all the time he has lived in the country of the Philistines.’”'),
  ('1 Samuel', 27, 12, 'Achish believed David, saying, “He has made his people Israel utterly to abhor him. Therefore he will be my servant forever.”'),
  ('1 Samuel', 28, 1, 'In those days, the Philistines gathered their armies together for warfare, to fight with Israel. Achish said to David, “Know assuredly that you will go out with me in the army, you and your men.”'),
  ('1 Samuel', 28, 2, 'David said to Achish, “Therefore you will know what your servant can do.” Achish said to David, “Therefore I will make you my bodyguard forever.”'),
  ('1 Samuel', 28, 3, 'Now Samuel was dead, and all Israel had mourned for him and buried him in Ramah, even in his own city. Saul had sent away those who had familiar spirits and the wizards out of the land.'),
  ('1 Samuel', 28, 4, 'The Philistines gathered themselves together, and came and encamped in Shunem; and Saul gathered all Israel together, and they encamped in Gilboa.'),
  ('1 Samuel', 28, 5, 'When Saul saw the army of the Philistines, he was afraid, and his heart trembled greatly.'),
  ('1 Samuel', 28, 6, 'When Saul inquired of the LORD, the LORD didn’t answer him by dreams, by Urim, or by prophets.'),
  ('1 Samuel', 28, 7, 'Then Saul said to his servants, “Seek for me a woman who has a familiar spirit, that I may go to her and inquire of her.” His servants said to him, “Behold, there is a woman who has a familiar spirit at Endor.”'),
  ('1 Samuel', 28, 8, 'Saul disguised himself and put on other clothing, and went, he and two men with him, and they came to the woman by night. Then he said, “Please consult for me by the familiar spirit, and bring me up whomever I shall name to you.”'),
  ('1 Samuel', 28, 9, 'The woman said to him, “Behold, you know what Saul has done, how he has cut off those who have familiar spirits and the wizards out of the land. Why then do you lay a snare for my life, to cause me to die?”'),
  ('1 Samuel', 28, 10, 'Saul swore to her by the LORD, saying, “As the LORD lives, no punishment will happen to you for this thing.”'),
  ('1 Samuel', 28, 11, 'Then the woman said, “Whom shall I bring up to you?” He said, “Bring Samuel up for me.”'),
  ('1 Samuel', 28, 12, 'When the woman saw Samuel, she cried with a loud voice; and the woman spoke to Saul, saying, “Why have you deceived me? For you are Saul!”'),
  ('1 Samuel', 28, 13, 'The king said to her, “Don’t be afraid! What do you see?” The woman said to Saul, “I see a god coming up out of the earth.”'),
  ('1 Samuel', 28, 14, 'He said to her, “What does he look like?” She said, “An old man comes up. He is covered with a robe.” Saul perceived that it was Samuel, and he bowed with his face to the ground, and showed respect.'),
  ('1 Samuel', 28, 15, 'Samuel said to Saul, “Why have you disturbed me, to bring me up?” Saul answered, “I am very distressed; for the Philistines make war against me, and God has departed from me, and answers me no more, by prophets, or by dreams. Therefore I have called you, that you may make known to me what I shall do.”'),
  ('1 Samuel', 28, 16, 'Samuel said, “Why then do you ask me, since the LORD has departed from you and has become your adversary?'),
  ('1 Samuel', 28, 17, 'The LORD has done to you as he spoke by me. The LORD has torn the kingdom out of your hand and given it to your neighbor, even to David.'),
  ('1 Samuel', 28, 18, 'Because you didn’t obey the LORD’s voice, and didn’t execute his fierce wrath on Amalek, therefore the LORD has done this thing to you today.'),
  ('1 Samuel', 28, 19, 'Moreover the LORD will deliver Israel also with you into the hand of the Philistines; and tomorrow you and your sons will be with me. The LORD will deliver the army of Israel also into the hand of the Philistines.”'),
  ('1 Samuel', 28, 20, 'Then Saul fell immediately his full length on the earth, and was terrified, because of Samuel’s words. There was no strength in him, for he had eaten no bread all day long or all night long.'),
  ('1 Samuel', 28, 21, 'The woman came to Saul and saw that he was very troubled, and said to him, “Behold, your servant has listened to your voice, and I have put my life in my hand, and have listened to your words which you spoke to me.'),
  ('1 Samuel', 28, 22, 'Now therefore, please listen also to the voice of your servant, and let me set a morsel of bread before you. Eat, that you may have strength when you go on your way.”'),
  ('1 Samuel', 28, 23, 'But he refused, and said, “I will not eat.” But his servants, together with the woman, constrained him; and he listened to their voice. So he arose from the earth and sat on the bed.'),
  ('1 Samuel', 28, 24, 'The woman had a fattened calf in the house. She hurried and killed it; and she took flour and kneaded it, and baked unleavened bread of it.'),
  ('1 Samuel', 28, 25, 'She brought it before Saul and before his servants, and they ate. Then they rose up and went away that night.'),
  ('1 Samuel', 29, 1, 'Now the Philistines gathered together all their armies to Aphek; and the Israelites encamped by the spring which is in Jezreel.'),
  ('1 Samuel', 29, 2, 'The lords of the Philistines passed on by hundreds and by thousands; and David and his men passed on in the rear with Achish.'),
  ('1 Samuel', 29, 3, 'Then the princes of the Philistines said, “What about these Hebrews?” Achish said to the princes of the Philistines, “Isn’t this David, the servant of Saul the king of Israel, who has been with me these days, or rather these years? I have found no fault in him since he fell away until today.”'),
  ('1 Samuel', 29, 4, 'But the princes of the Philistines were angry with him; and the princes of the Philistines said to him, “Make the man return, that he may go back to his place where you have appointed him, and let him not go down with us to battle, lest in the battle he become an adversary to us. For with what should this fellow reconcile himself to his lord? Should it not be with the heads of these men?'),
  ('1 Samuel', 29, 5, 'Isn’t this David, of whom people sang to one another in dances, saying, ‘Saul has slain his thousands, and David his ten thousands’?”'),
  ('1 Samuel', 29, 6, 'Then Achish called David and said to him, “As the LORD lives, you have been upright, and your going out and your coming in with me in the army is good in my sight; for I have not found evil in you since the day of your coming to me to this day. Nevertheless, the lords don’t favor you.'),
  ('1 Samuel', 29, 7, 'Therefore now return, and go in peace, that you not displease the lords of the Philistines.”'),
  ('1 Samuel', 29, 8, 'David said to Achish, “But what have I done? What have you found in your servant so long as I have been before you to this day, that I may not go and fight against the enemies of my lord the king?”'),
  ('1 Samuel', 29, 9, 'Achish answered David, “I know that you are good in my sight, as an angel of God. Notwithstanding, the princes of the Philistines have said, ‘He shall not go up with us to the battle.’'),
  ('1 Samuel', 29, 10, 'Therefore now rise up early in the morning with the servants of your lord who have come with you; and as soon as you are up early in the morning and have light, depart.”'),
  ('1 Samuel', 29, 11, 'So David rose up early, he and his men, to depart in the morning, to return into the land of the Philistines; and the Philistines went up to Jezreel.'),
  ('1 Samuel', 30, 1, 'When David and his men had come to Ziklag on the third day, the Amalekites had made a raid on the South and on Ziklag, and had struck Ziklag and burned it with fire,'),
  ('1 Samuel', 30, 2, 'and had taken captive the women and all who were in it, both small and great. They didn’t kill any, but carried them off and went their way.'),
  ('1 Samuel', 30, 3, 'When David and his men came to the city, behold, it was burned with fire; and their wives, their sons, and their daughters were taken captive.'),
  ('1 Samuel', 30, 4, 'Then David and the people who were with him lifted up their voice and wept until they had no more power to weep.'),
  ('1 Samuel', 30, 5, 'David’s two wives were taken captive, Ahinoam the Jezreelitess, and Abigail the wife of Nabal the Carmelite.'),
  ('1 Samuel', 30, 6, 'David was greatly distressed, for the people spoke of stoning him, because the souls of all the people were grieved, every man for his sons and for his daughters; but David strengthened himself in the LORD his God.'),
  ('1 Samuel', 30, 7, 'David said to Abiathar the priest, the son of Ahimelech, “Please bring the ephod here to me.” Abiathar brought the ephod to David.'),
  ('1 Samuel', 30, 8, 'David inquired of the LORD, saying, “If I pursue after this troop, will I overtake them?” He answered him, “Pursue, for you will surely overtake them, and will without fail recover all.”'),
  ('1 Samuel', 30, 9, 'So David went, he and the six hundred men who were with him, and came to the brook Besor, where those who were left behind stayed.'),
  ('1 Samuel', 30, 10, 'But David pursued, he and four hundred men; for two hundred stayed behind, who were so faint that they couldn’t go over the brook Besor.'),
  ('1 Samuel', 30, 11, 'They found an Egyptian in the field, and brought him to David, and gave him bread, and he ate; and they gave him water to drink.'),
  ('1 Samuel', 30, 12, 'They gave him a piece of a cake of figs and two clusters of raisins. When he had eaten, his spirit came again to him; for he had eaten no bread, and drank no water for three days and three nights.'),
  ('1 Samuel', 30, 13, 'David asked him, “To whom do you belong? Where are you from?” He said, “I am a young man of Egypt, servant to an Amalekite; and my master left me, because three days ago I got sick.'),
  ('1 Samuel', 30, 14, 'We made a raid on the South of the Cherethites, and on that which belongs to Judah, and on the South of Caleb; and we burned Ziklag with fire.”'),
  ('1 Samuel', 30, 15, 'David said to him, “Will you bring me down to this troop?” He said, “Swear to me by God that you will not kill me and not deliver me up into the hands of my master, and I will bring you down to this troop.”'),
  ('1 Samuel', 30, 16, 'When he had brought him down, behold, they were spread around over all the ground, eating, drinking, and dancing, because of all the great plunder that they had taken out of the land of the Philistines, and out of the land of Judah.'),
  ('1 Samuel', 30, 17, 'David struck them from the twilight even to the evening of the next day. Not a man of them escaped from there, except four hundred young men who rode on camels and fled.'),
  ('1 Samuel', 30, 18, 'David recovered all that the Amalekites had taken, and David rescued his two wives.'),
  ('1 Samuel', 30, 19, 'There was nothing lacking to them, neither small nor great, neither sons nor daughters, neither plunder, nor anything that they had taken. David brought them all back.'),
  ('1 Samuel', 30, 20, 'David took all the flocks and the herds, which they drove before those other livestock, and said, “This is David’s plunder.”'),
  ('1 Samuel', 30, 21, 'David came to the two hundred men, who were so faint that they could not follow David, whom also they had made to stay at the brook Besor; and they went out to meet David, and to meet the people who were with him. When David came near to the people, he greeted them.');
INSERT INTO bible_verses (book_name, chapter, verse, text) VALUES
  ('1 Samuel', 30, 22, 'Then all the wicked men and worthless fellows of those who went with David answered and said, “Because they didn’t go with us, we will not give them anything of the plunder that we have recovered, except to every man his wife and his children, that he may lead them away and depart.”'),
  ('1 Samuel', 30, 23, 'Then David said, “Do not do so, my brothers, with that which the LORD has given to us, who has preserved us, and delivered the troop that came against us into our hand.'),
  ('1 Samuel', 30, 24, 'Who will listen to you in this matter? For as his share is who goes down to the battle, so shall his share be who stays with the baggage. They shall share alike.”'),
  ('1 Samuel', 30, 25, 'It was so from that day forward that he made it a statute and an ordinance for Israel to this day.'),
  ('1 Samuel', 30, 26, 'When David came to Ziklag, he sent some of the plunder to the elders of Judah, even to his friends, saying, “Behold, a present for you from the plunder of the LORD’s enemies.”'),
  ('1 Samuel', 30, 27, 'He sent it to those who were in Bethel, to those who were in Ramoth of the South, to those who were in Jattir,'),
  ('1 Samuel', 30, 28, 'to those who were in Aroer, to those who were in Siphmoth, to those who were in Eshtemoa,'),
  ('1 Samuel', 30, 29, 'to those who were in Racal, to those who were in the cities of the Jerahmeelites, to those who were in the cities of the Kenites,'),
  ('1 Samuel', 30, 30, 'to those who were in Hormah, to those who were in Borashan, to those who were in Athach,'),
  ('1 Samuel', 30, 31, 'to those who were in Hebron, and to all the places where David himself and his men used to stay.'),
  ('1 Samuel', 31, 1, 'Now the Philistines fought against Israel; and the men of Israel fled from before the Philistines, and fell down slain on Mount Gilboa.'),
  ('1 Samuel', 31, 2, 'The Philistines overtook Saul and his sons; and the Philistines killed Jonathan, Abinadab, and Malchishua, the sons of Saul.'),
  ('1 Samuel', 31, 3, 'The battle went hard against Saul, and the archers overtook him; and he was greatly distressed by reason of the archers.'),
  ('1 Samuel', 31, 4, 'Then Saul said to his armor bearer, “Draw your sword, and thrust me through with it, lest these uncircumcised come and thrust me through and abuse me!” But his armor bearer would not, for he was terrified. Therefore Saul took his sword and fell on it.'),
  ('1 Samuel', 31, 5, 'When his armor bearer saw that Saul was dead, he likewise fell on his sword, and died with him.'),
  ('1 Samuel', 31, 6, 'So Saul died with his three sons, his armor bearer, and all his men that same day together.'),
  ('1 Samuel', 31, 7, 'When the men of Israel who were on the other side of the valley, and those who were beyond the Jordan, saw that the men of Israel fled and that Saul and his sons were dead, they abandoned the cities and fled; and the Philistines came and lived in them.'),
  ('1 Samuel', 31, 8, 'On the next day, when the Philistines came to strip the slain, they found Saul and his three sons fallen on Mount Gilboa.'),
  ('1 Samuel', 31, 9, 'They cut off his head, stripped off his armor, and sent into the land of the Philistines all around, to carry the news to the house of their idols and to the people.'),
  ('1 Samuel', 31, 10, 'They put his armor in the house of the Ashtaroth, and they fastened his body to the wall of Beth Shan.'),
  ('1 Samuel', 31, 11, 'When the inhabitants of Jabesh Gilead heard what the Philistines had done to Saul,'),
  ('1 Samuel', 31, 12, 'all the valiant men arose, went all night, and took the body of Saul and the bodies of his sons from the wall of Beth Shan; and they came to Jabesh and burned them there.'),
  ('1 Samuel', 31, 13, 'They took their bones and buried them under the tamarisk tree in Jabesh, and fasted seven days.'),
  ('2 Samuel', 1, 1, 'After the death of Saul, when David had returned from the slaughter of the Amalekites, and David had stayed two days in Ziklag,'),
  ('2 Samuel', 1, 2, 'on the third day, behold, a man came out of the camp from Saul, with his clothes torn and earth on his head. When he came to David, he fell to the earth and showed respect.'),
  ('2 Samuel', 1, 3, 'David said to him, “Where do you come from?” He said to him, “I have escaped out of the camp of Israel.”'),
  ('2 Samuel', 1, 4, 'David said to him, “How did it go? Please tell me.” He answered, “The people have fled from the battle, and many of the people also have fallen and are dead. Saul and Jonathan his son are dead also.”'),
  ('2 Samuel', 1, 5, 'David said to the young man who told him, “How do you know that Saul and Jonathan his son are dead?”'),
  ('2 Samuel', 1, 6, 'The young man who told him said, “As I happened by chance on Mount Gilboa, behold, Saul was leaning on his spear; and behold, the chariots and the horsemen followed close behind him.'),
  ('2 Samuel', 1, 7, 'When he looked behind him, he saw me and called to me. I answered, ‘Here I am.’'),
  ('2 Samuel', 1, 8, 'He said to me, ‘Who are you?’ I answered him, ‘I am an Amalekite.’'),
  ('2 Samuel', 1, 9, 'He said to me, ‘Please stand beside me, and kill me, for anguish has taken hold of me because my life lingers in me.’'),
  ('2 Samuel', 1, 10, 'So I stood beside him and killed him, because I was sure that he could not live after he had fallen. I took the crown that was on his head and the bracelet that was on his arm, and have brought them here to my lord.”'),
  ('2 Samuel', 1, 11, 'Then David took hold on his clothes and tore them; and all the men who were with him did likewise.'),
  ('2 Samuel', 1, 12, 'They mourned, wept, and fasted until evening for Saul and for Jonathan his son, and for the people of the LORD, and for the house of Israel, because they had fallen by the sword.'),
  ('2 Samuel', 1, 13, 'David said to the young man who told him, “Where are you from?” He answered, “I am the son of a foreigner, an Amalekite.”'),
  ('2 Samuel', 1, 14, 'David said to him, “Why were you not afraid to stretch out your hand to destroy the LORD’s anointed?”'),
  ('2 Samuel', 1, 15, 'David called one of the young men and said, “Go near, and cut him down!” He struck him so that he died.'),
  ('2 Samuel', 1, 16, 'David said to him, “Your blood be on your head, for your mouth has testified against you, saying, ‘I have slain the LORD’s anointed.’”'),
  ('2 Samuel', 1, 17, 'David lamented with this lamentation over Saul and over Jonathan his son'),
  ('2 Samuel', 1, 18, '(and he commanded them to teach the children of Judah the song of the bow; behold, it is written in the book of Jashar):'),
  ('2 Samuel', 1, 19, '“Your glory, Israel, was slain on your high places! How the mighty have fallen!'),
  ('2 Samuel', 1, 20, 'Don’t tell it in Gath. Don’t publish it in the streets of Ashkelon, lest the daughters of the Philistines rejoice, lest the daughters of the uncircumcised triumph.'),
  ('2 Samuel', 1, 21, 'You mountains of Gilboa, let there be no dew or rain on you, and no fields of offerings; for there the shield of the mighty was defiled and cast away, the shield of Saul was not anointed with oil.'),
  ('2 Samuel', 1, 22, 'From the blood of the slain, from the fat of the mighty, Jonathan’s bow didn’t turn back. Saul’s sword didn’t return empty.'),
  ('2 Samuel', 1, 23, 'Saul and Jonathan were lovely and pleasant in their lives. In their death, they were not divided. They were swifter than eagles. They were stronger than lions.'),
  ('2 Samuel', 1, 24, 'You daughters of Israel, weep over Saul, who clothed you delicately in scarlet, who put ornaments of gold on your clothing.'),
  ('2 Samuel', 1, 25, 'How the mighty have fallen in the middle of the battle! Jonathan was slain on your high places.'),
  ('2 Samuel', 1, 26, 'I am distressed for you, my brother Jonathan. You have been very pleasant to me. Your love to me was wonderful, surpassing the love of women.'),
  ('2 Samuel', 1, 27, 'How the mighty have fallen, and the weapons of war have perished!”'),
  ('2 Samuel', 2, 1, 'After this, David inquired of the LORD, saying, “Shall I go up into any of the cities of Judah?” The LORD said to him, “Go up.” David said, “Where shall I go up?” He said, “To Hebron.”'),
  ('2 Samuel', 2, 2, 'So David went up there with his two wives, Ahinoam the Jezreelitess, and Abigail the wife of Nabal the Carmelite.'),
  ('2 Samuel', 2, 3, 'David brought up his men who were with him, every man with his household. They lived in the cities of Hebron.'),
  ('2 Samuel', 2, 4, 'The men of Judah came, and there they anointed David king over the house of Judah. They told David, “The men of Jabesh Gilead were those who buried Saul.”'),
  ('2 Samuel', 2, 5, 'David sent messengers to the men of Jabesh Gilead, and said to them, “Blessed are you by the LORD, that you have shown this kindness to your lord, even to Saul, and have buried him.'),
  ('2 Samuel', 2, 6, 'Now may the LORD show loving kindness and truth to you. I also will reward you for this kindness, because you have done this thing.'),
  ('2 Samuel', 2, 7, 'Now therefore let your hands be strong, and be valiant; for Saul your lord is dead, and also the house of Judah have anointed me king over them.”'),
  ('2 Samuel', 2, 8, 'Now Abner the son of Ner, captain of Saul’s army, had taken Ishbosheth the son of Saul and brought him over to Mahanaim.'),
  ('2 Samuel', 2, 9, 'He made him king over Gilead, over the Ashurites, over Jezreel, over Ephraim, over Benjamin, and over all Israel.'),
  ('2 Samuel', 2, 10, 'Ishbosheth, Saul’s son, was forty years old when he began to reign over Israel, and he reigned two years. But the house of Judah followed David.'),
  ('2 Samuel', 2, 11, 'The time that David was king in Hebron over the house of Judah was seven years and six months.'),
  ('2 Samuel', 2, 12, 'Abner the son of Ner, and the servants of Ishbosheth the son of Saul, went out from Mahanaim to Gibeon.'),
  ('2 Samuel', 2, 13, 'Joab the son of Zeruiah and David’s servants went out, and met them by the pool of Gibeon; and they sat down, the one on the one side of the pool and the other on the other side of the pool.'),
  ('2 Samuel', 2, 14, 'Abner said to Joab, “Please let the young men arise and compete before us!” Joab said, “Let them arise!”'),
  ('2 Samuel', 2, 15, 'Then they arose and went over by number: twelve for Benjamin and for Ishbosheth the son of Saul, and twelve of David’s servants.'),
  ('2 Samuel', 2, 16, 'They each caught his opponent by the head and thrust his sword in his fellow’s side; so they fell down together. Therefore that place in Gibeon was called Helkath Hazzurim.'),
  ('2 Samuel', 2, 17, 'The battle was very severe that day; and Abner was beaten, and the men of Israel, before David’s servants.'),
  ('2 Samuel', 2, 18, 'The three sons of Zeruiah were there: Joab, Abishai, and Asahel. Asahel was as light of foot as a wild gazelle.'),
  ('2 Samuel', 2, 19, 'Asahel pursued Abner. He didn’t turn to the right hand or to the left from following Abner.'),
  ('2 Samuel', 2, 20, 'Then Abner looked behind him and said, “Is that you, Asahel?” He answered, “It is.”'),
  ('2 Samuel', 2, 21, 'Abner said to him, “Turn away to your right hand or to your left, and grab one of the young men, and take his armor.” But Asahel would not turn away from following him.'),
  ('2 Samuel', 2, 22, 'Abner said again to Asahel, “Turn away from following me. Why should I strike you to the ground? How then could I look Joab your brother in the face?”'),
  ('2 Samuel', 2, 23, 'However, he refused to turn away. Therefore Abner with the back end of the spear struck him in the body, so that the spear came out behind him; and he fell down there and died in the same place. As many as came to the place where Asahel fell down and died stood still.'),
  ('2 Samuel', 2, 24, 'But Joab and Abishai pursued Abner. The sun went down when they had come to the hill of Ammah, that lies before Giah by the way of the wilderness of Gibeon.'),
  ('2 Samuel', 2, 25, 'The children of Benjamin gathered themselves together after Abner and became one band, and stood on the top of a hill.'),
  ('2 Samuel', 2, 26, 'Then Abner called to Joab, and said, “Shall the sword devour forever? Don’t you know that it will be bitterness in the latter end? How long will it be then, before you ask the people to return from following their brothers?”'),
  ('2 Samuel', 2, 27, 'Joab said, “As God lives, if you had not spoken, surely then in the morning the people would have gone away, and not each followed his brother.”'),
  ('2 Samuel', 2, 28, 'So Joab blew the trumpet; and all the people stood still and pursued Israel no more, and they fought no more.'),
  ('2 Samuel', 2, 29, 'Abner and his men went all that night through the Arabah; and they passed over the Jordan, and went through all Bithron, and came to Mahanaim.'),
  ('2 Samuel', 2, 30, 'Joab returned from following Abner; and when he had gathered all the people together, nineteen men of David’s and Asahel were missing.'),
  ('2 Samuel', 2, 31, 'But David’s servants had struck Benjamin Abner’s men so that three hundred sixty men died.'),
  ('2 Samuel', 2, 32, 'They took up Asahel and buried him in the tomb of his father, which was in Bethlehem. Joab and his men went all night, and the day broke on them at Hebron.'),
  ('2 Samuel', 3, 1, 'Now there was long war between Saul’s house and David’s house. David grew stronger and stronger, but Saul’s house grew weaker and weaker.'),
  ('2 Samuel', 3, 2, 'Sons were born to David in Hebron. His firstborn was Amnon, of Ahinoam the Jezreelitess;'),
  ('2 Samuel', 3, 3, 'and his second, Chileab, of Abigail the wife of Nabal the Carmelite; and the third, Absalom the son of Maacah the daughter of Talmai king of Geshur;'),
  ('2 Samuel', 3, 4, 'and the fourth, Adonijah the son of Haggith; and the fifth, Shephatiah the son of Abital;'),
  ('2 Samuel', 3, 5, 'and the sixth, Ithream, of Eglah, David’s wife. These were born to David in Hebron.'),
  ('2 Samuel', 3, 6, 'While there was war between Saul’s house and David’s house, Abner made himself strong in Saul’s house.'),
  ('2 Samuel', 3, 7, 'Now Saul had a concubine, whose name was Rizpah, the daughter of Aiah; and Ishbosheth said to Abner, “Why have you gone in to my father’s concubine?”'),
  ('2 Samuel', 3, 8, 'Then Abner was very angry about Ishbosheth’s words, and said, “Am I a dog’s head that belongs to Judah? Today I show kindness to your father Saul’s house, to his brothers, and to his friends, and have not delivered you into the hand of David; and yet you charge me today with a fault concerning this woman!'),
  ('2 Samuel', 3, 9, 'God do so to Abner, and more also, if, as the LORD has sworn to David, I don’t do even so to him:'),
  ('2 Samuel', 3, 10, 'to transfer the kingdom from Saul’s house, and to set up David’s throne over Israel and over Judah, from Dan even to Beersheba.”'),
  ('2 Samuel', 3, 11, 'He could not answer Abner another word, because he was afraid of him.'),
  ('2 Samuel', 3, 12, 'Abner sent messengers to David on his behalf, saying, “Whose is the land?” and saying, “Make your alliance with me, and behold, my hand will be with you to bring all Israel around to you.”'),
  ('2 Samuel', 3, 13, 'David said, “Good. I will make a treaty with you, but one thing I require of you. That is, you will not see my face unless you first bring Michal, Saul’s daughter, when you come to see my face.”'),
  ('2 Samuel', 3, 14, 'David sent messengers to Ishbosheth, Saul’s son, saying, “Deliver me my wife Michal, whom I was given to marry for one hundred foreskins of the Philistines.”'),
  ('2 Samuel', 3, 15, 'Ishbosheth sent and took her from her husband, Paltiel the son of Laish.'),
  ('2 Samuel', 3, 16, 'Her husband went with her, weeping as he went, and followed her to Bahurim. Then Abner said to him, “Go! Return!” and he returned.'),
  ('2 Samuel', 3, 17, 'Abner had communication with the elders of Israel, saying, “In times past, you sought for David to be king over you.'),
  ('2 Samuel', 3, 18, 'Now then do it! For the LORD has spoken of David, saying, ‘By the hand of my servant David, I will save my people Israel out of the hand of the Philistines, and out of the hand of all their enemies.’”');
INSERT INTO bible_verses (book_name, chapter, verse, text) VALUES
  ('2 Samuel', 3, 19, 'Abner also spoke in the ears of Benjamin; and Abner went also to speak in the ears of David in Hebron all that seemed good to Israel and to the whole house of Benjamin.'),
  ('2 Samuel', 3, 20, 'So Abner came to David to Hebron, and twenty men with him. David made Abner and the men who were with him a feast.'),
  ('2 Samuel', 3, 21, 'Abner said to David, “I will arise and go, and will gather all Israel to my lord the king, that they may make a covenant with you, and that you may reign over all that your soul desires.” David sent Abner away; and he went in peace.'),
  ('2 Samuel', 3, 22, 'Behold, David’s servants and Joab came from a raid and brought in a great plunder with them; but Abner was not with David in Hebron, for he had sent him away, and he had gone in peace.'),
  ('2 Samuel', 3, 23, 'When Joab and all the army who was with him had come, they told Joab, “Abner the son of Ner came to the king, and he has sent him away, and he has gone in peace.”'),
  ('2 Samuel', 3, 24, 'Then Joab came to the king and said, “What have you done? Behold, Abner came to you. Why is it that you have sent him away, and he is already gone?'),
  ('2 Samuel', 3, 25, 'You know Abner the son of Ner. He came to deceive you, and to know your going out and your coming in, and to know all that you do.”'),
  ('2 Samuel', 3, 26, 'When Joab had come out from David, he sent messengers after Abner, and they brought him back from the well of Sirah; but David didn’t know it.'),
  ('2 Samuel', 3, 27, 'When Abner had returned to Hebron, Joab took him aside into the middle of the gate to speak with him quietly, and struck him there in the body, so that he died for the blood of Asahel his brother.'),
  ('2 Samuel', 3, 28, 'Afterward, when David heard it, he said, “I and my kingdom are guiltless before the LORD forever of the blood of Abner the son of Ner.'),
  ('2 Samuel', 3, 29, 'Let it fall on the head of Joab and on all his father’s house. Let there not fail from the house of Joab one who has a discharge, or who is a leper, or who leans on a staff, or who falls by the sword, or who lacks bread.”'),
  ('2 Samuel', 3, 30, 'So Joab and Abishai his brother killed Abner, because he had killed their brother Asahel at Gibeon in the battle.'),
  ('2 Samuel', 3, 31, 'David said to Joab and to all the people who were with him, “Tear your clothes, and clothe yourselves with sackcloth, and mourn in front of Abner.” King David followed the bier.'),
  ('2 Samuel', 3, 32, 'They buried Abner in Hebron; and the king lifted up his voice and wept at Abner’s grave; and all the people wept.'),
  ('2 Samuel', 3, 33, 'The king lamented for Abner, and said, “Should Abner die as a fool dies?'),
  ('2 Samuel', 3, 34, 'Your hands weren’t bound, and your feet weren’t put into fetters. As a man falls before the children of iniquity, so you fell.” All the people wept again over him.'),
  ('2 Samuel', 3, 35, 'All the people came to urge David to eat bread while it was yet day; but David swore, saying, “God do so to me, and more also, if I taste bread or anything else, until the sun goes down.”'),
  ('2 Samuel', 3, 36, 'All the people took notice of it, and it pleased them, as whatever the king did pleased all the people.'),
  ('2 Samuel', 3, 37, 'So all the people and all Israel understood that day that it was not of the king to kill Abner the son of Ner.'),
  ('2 Samuel', 3, 38, 'The king said to his servants, “Don’t you know that a prince and a great man has fallen today in Israel?'),
  ('2 Samuel', 3, 39, 'I am weak today, though anointed king. These men, the sons of Zeruiah are too hard for me. May the LORD reward the evildoer according to his wickedness.”'),
  ('2 Samuel', 4, 1, 'When Saul’s son heard that Abner was dead in Hebron, his hands became feeble, and all the Israelites were troubled.'),
  ('2 Samuel', 4, 2, 'Saul’s son had two men who were captains of raiding bands. The name of one was Baanah and the name of the other Rechab, the sons of Rimmon the Beerothite, of the children of Benjamin (for Beeroth also is considered a part of Benjamin;'),
  ('2 Samuel', 4, 3, 'and the Beerothites fled to Gittaim, and have lived as foreigners there until today).'),
  ('2 Samuel', 4, 4, 'Now Jonathan, Saul’s son, had a son who was lame in his feet. He was five years old when the news came about Saul and Jonathan out of Jezreel; and his nurse picked him up and fled. As she hurried to flee, he fell and became lame. His name was Mephibosheth.'),
  ('2 Samuel', 4, 5, 'The sons of Rimmon the Beerothite, Rechab and Baanah, went out and came at about the heat of the day to the house of Ishbosheth as he took his rest at noon.'),
  ('2 Samuel', 4, 6, 'They came there into the middle of the house as though they would have fetched wheat, and they struck him in the body; and Rechab and Baanah his brother escaped.'),
  ('2 Samuel', 4, 7, 'Now when they came into the house as he lay on his bed in his bedroom, they struck him, killed him, beheaded him, and took his head, and went by the way of the Arabah all night.'),
  ('2 Samuel', 4, 8, 'They brought the head of Ishbosheth to David to Hebron, and said to the king, “Behold, the head of Ishbosheth, the son of Saul, your enemy, who sought your life! The LORD has avenged my lord the king today of Saul and of his offspring.”'),
  ('2 Samuel', 4, 9, 'David answered Rechab and Baanah his brother, the sons of Rimmon the Beerothite, and said to them, “As the LORD lives, who has redeemed my soul out of all adversity,'),
  ('2 Samuel', 4, 10, 'when someone told me, ‘Behold, Saul is dead,’ thinking that he brought good news, I seized him and killed him in Ziklag, which was the reward I gave him for his news.'),
  ('2 Samuel', 4, 11, 'How much more, when wicked men have slain a righteous person in his own house on his bed, should I not now require his blood from your hand, and rid the earth of you?”'),
  ('2 Samuel', 4, 12, 'David commanded his young men, and they killed them, cut off their hands and their feet, and hanged them up beside the pool in Hebron. But they took the head of Ishbosheth and buried it in Abner’s grave in Hebron.'),
  ('2 Samuel', 5, 1, 'Then all the tribes of Israel came to David at Hebron and spoke, saying, “Behold, we are your bone and your flesh.'),
  ('2 Samuel', 5, 2, 'In times past, when Saul was king over us, it was you who led Israel out and in. The LORD said to you, ‘You will be shepherd of my people Israel, and you will be prince over Israel.’”'),
  ('2 Samuel', 5, 3, 'So all the elders of Israel came to the king to Hebron, and King David made a covenant with them in Hebron before the LORD; and they anointed David king over Israel.'),
  ('2 Samuel', 5, 4, 'David was thirty years old when he began to reign, and he reigned forty years.'),
  ('2 Samuel', 5, 5, 'In Hebron he reigned over Judah seven years and six months, and in Jerusalem he reigned thirty-three years over all Israel and Judah.'),
  ('2 Samuel', 5, 6, 'The king and his men went to Jerusalem against the Jebusites, the inhabitants of the land, who spoke to David, saying, “The blind and the lame will keep you out of here,” thinking, “David can’t come in here.”'),
  ('2 Samuel', 5, 7, 'Nevertheless David took the stronghold of Zion. This is David’s city.'),
  ('2 Samuel', 5, 8, 'David said on that day, “Whoever strikes the Jebusites, let him go up to the watercourse and strike those lame and blind, who are hated by David’s soul.” Therefore they say, “The blind and the lame can’t come into the house.”'),
  ('2 Samuel', 5, 9, 'David lived in the stronghold, and called it David’s city. David built around from Millo and inward.'),
  ('2 Samuel', 5, 10, 'David grew greater and greater, for the LORD, the God of Armies, was with him.'),
  ('2 Samuel', 5, 11, 'Hiram king of Tyre sent messengers to David, with cedar trees, carpenters, and masons; and they built David a house.'),
  ('2 Samuel', 5, 12, 'David perceived that the LORD had established him king over Israel, and that he had exalted his kingdom for his people Israel’s sake.'),
  ('2 Samuel', 5, 13, 'David took more concubines and wives for himself out of Jerusalem, after he had come from Hebron; and more sons and daughters were born to David.'),
  ('2 Samuel', 5, 14, 'These are the names of those who were born to him in Jerusalem: Shammua, Shobab, Nathan, Solomon,'),
  ('2 Samuel', 5, 15, 'Ibhar, Elishua, Nepheg, Japhia,'),
  ('2 Samuel', 5, 16, 'Elishama, Eliada, and Eliphelet.'),
  ('2 Samuel', 5, 17, 'When the Philistines heard that they had anointed David king over Israel, all the Philistines went up to seek David, but David heard about it and went down to the stronghold.'),
  ('2 Samuel', 5, 18, 'Now the Philistines had come and spread themselves in the valley of Rephaim.'),
  ('2 Samuel', 5, 19, 'David inquired of the LORD, saying, “Shall I go up against the Philistines? Will you deliver them into my hand?” The LORD said to David, “Go up; for I will certainly deliver the Philistines into your hand.”'),
  ('2 Samuel', 5, 20, 'David came to Baal Perazim, and David struck them there. Then he said, “The LORD has broken my enemies before me, like the breach of waters.” Therefore he called the name of that place Baal Perazim.'),
  ('2 Samuel', 5, 21, 'They left their images there, and David and his men took them away.'),
  ('2 Samuel', 5, 22, 'The Philistines came up yet again and spread themselves in the valley of Rephaim.'),
  ('2 Samuel', 5, 23, 'When David inquired of the LORD, he said, “You shall not go up. Circle around behind them, and attack them in front of the mulberry trees.'),
  ('2 Samuel', 5, 24, 'When you hear the sound of marching in the tops of the mulberry trees, then stir yourself up; for then the LORD has gone out before you to strike the army of the Philistines.”'),
  ('2 Samuel', 5, 25, 'David did so, as the LORD commanded him, and struck the Philistines all the way from Geba to Gezer.'),
  ('2 Samuel', 6, 1, 'David again gathered together all the chosen men of Israel, thirty thousand.'),
  ('2 Samuel', 6, 2, 'David arose and went with all the people who were with him from Baale Judah, to bring up from there God’s ark, which is called by the Name, even the name of the LORD of Armies who sits above the cherubim.'),
  ('2 Samuel', 6, 3, 'They set God’s ark on a new cart, and brought it out of Abinadab’s house that was on the hill; and Uzzah and Ahio, the sons of Abinadab, drove the new cart.'),
  ('2 Samuel', 6, 4, 'They brought it out of Abinadab’s house which was in the hill, with God’s ark; and Ahio went before the ark.'),
  ('2 Samuel', 6, 5, 'David and all the house of Israel played before the LORD with all kinds of instruments made of cypress wood, with harps, with stringed instruments, with tambourines, with castanets, and with cymbals.'),
  ('2 Samuel', 6, 6, 'When they came to the threshing floor of Nacon, Uzzah reached for God’s ark and took hold of it, for the cattle stumbled.'),
  ('2 Samuel', 6, 7, 'The LORD’s anger burned against Uzzah, and God struck him there for his error; and he died there by God’s ark.'),
  ('2 Samuel', 6, 8, 'David was displeased because the LORD had broken out against Uzzah; and he called that place Perez Uzzah to this day.'),
  ('2 Samuel', 6, 9, 'David was afraid of the LORD that day; and he said, “How could the LORD’s ark come to me?”'),
  ('2 Samuel', 6, 10, 'So David would not move the LORD’s ark to be with him in David’s city; but David carried it aside into Obed-Edom the Gittite’s house.'),
  ('2 Samuel', 6, 11, 'The LORD’s ark remained in Obed-Edom the Gittite’s house three months; and the LORD blessed Obed-Edom and all his house.'),
  ('2 Samuel', 6, 12, 'King David was told, “The LORD has blessed the house of Obed-Edom, and all that belongs to him, because of God’s ark.” So David went and brought up God’s ark from the house of Obed-Edom into David’s city with joy.'),
  ('2 Samuel', 6, 13, 'When those who bore the LORD’s ark had gone six paces, he sacrificed an ox and a fattened calf.'),
  ('2 Samuel', 6, 14, 'David danced before the LORD with all his might; and David was clothed in a linen ephod.'),
  ('2 Samuel', 6, 15, 'So David and all the house of Israel brought up the LORD’s ark with shouting and with the sound of the trumpet.'),
  ('2 Samuel', 6, 16, 'As the LORD’s ark came into David’s city, Michal the daughter of Saul looked out through the window and saw King David leaping and dancing before the LORD; and she despised him in her heart.'),
  ('2 Samuel', 6, 17, 'They brought in the LORD’s ark, and set it in its place in the middle of the tent that David had pitched for it; and David offered burnt offerings and peace offerings before the LORD.'),
  ('2 Samuel', 6, 18, 'When David had finished offering the burnt offering and the peace offerings, he blessed the people in the name of the LORD of Armies.'),
  ('2 Samuel', 6, 19, 'He gave to all the people, even among the whole multitude of Israel, both to men and women, to everyone a portion of bread, dates, and raisins. So all the people departed, each to his own house.'),
  ('2 Samuel', 6, 20, 'Then David returned to bless his household. Michal the daughter of Saul came out to meet David, and said, “How glorious the king of Israel was today, who uncovered himself today in the eyes of his servants’ maids, as one of the vain fellows shamelessly uncovers himself!”'),
  ('2 Samuel', 6, 21, 'David said to Michal, “It was before the LORD, who chose me above your father, and above all his house, to appoint me prince over the people of the LORD, over Israel. Therefore I will celebrate before the LORD.'),
  ('2 Samuel', 6, 22, 'I will be yet more undignified than this, and will be worthless in my own sight. But the maids of whom you have spoken will honor me.”'),
  ('2 Samuel', 6, 23, 'Michal the daughter of Saul had no child to the day of her death.'),
  ('2 Samuel', 7, 1, 'When the king lived in his house, and the LORD had given him rest from all his enemies all around,'),
  ('2 Samuel', 7, 2, 'the king said to Nathan the prophet, “See now, I dwell in a house of cedar, but God’s ark dwells within curtains.”'),
  ('2 Samuel', 7, 3, 'Nathan said to the king, “Go, do all that is in your heart, for the LORD is with you.”'),
  ('2 Samuel', 7, 4, 'That same night, the LORD’s word came to Nathan, saying,'),
  ('2 Samuel', 7, 5, '“Go and tell my servant David, ‘The LORD says, “Should you build me a house for me to dwell in?'),
  ('2 Samuel', 7, 6, 'For I have not lived in a house since the day that I brought the children of Israel up out of Egypt, even to this day, but have moved around in a tent and in a tabernacle.'),
  ('2 Samuel', 7, 7, 'In all places in which I have walked with all the children of Israel, did I say a word to anyone from the tribes of Israel whom I commanded to be shepherd of my people Israel, saying, ‘Why have you not built me a house of cedar?’”’'),
  ('2 Samuel', 7, 8, 'Now therefore tell my servant David this: ‘The LORD of Armies says, “I took you from the sheep pen, from following the sheep, to be prince over my people, over Israel.'),
  ('2 Samuel', 7, 9, 'I have been with you wherever you went, and have cut off all your enemies from before you. I will make you a great name, like the name of the great ones who are in the earth.'),
  ('2 Samuel', 7, 10, 'I will appoint a place for my people Israel, and will plant them, that they may dwell in their own place and be moved no more. The children of wickedness will not afflict them any more, as at the first,'),
  ('2 Samuel', 7, 11, 'and as from the day that I commanded judges to be over my people Israel. I will cause you to rest from all your enemies. Moreover the LORD tells you that the LORD will make you a house.'),
  ('2 Samuel', 7, 12, 'When your days are fulfilled and you sleep with your fathers, I will set up your offspring after you, who will proceed out of your body, and I will establish his kingdom.'),
  ('2 Samuel', 7, 13, 'He will build a house for my name, and I will establish the throne of his kingdom forever.'),
  ('2 Samuel', 7, 14, 'I will be his father, and he will be my son. If he commits iniquity, I will chasten him with the rod of men and with the stripes of the children of men;'),
  ('2 Samuel', 7, 15, 'but my loving kindness will not depart from him, as I took it from Saul, whom I put away before you.'),
  ('2 Samuel', 7, 16, 'Your house and your kingdom will be made sure forever before you. Your throne will be established forever.”’”'),
  ('2 Samuel', 7, 17, 'Nathan spoke to David all these words, and according to all this vision.'),
  ('2 Samuel', 7, 18, 'Then David the king went in and sat before the LORD; and he said, “Who am I, Lord GOD, and what is my house, that you have brought me this far?'),
  ('2 Samuel', 7, 19, 'This was yet a small thing in your eyes, Lord GOD, but you have spoken also of your servant’s house for a great while to come; and this among men, Lord GOD!');
INSERT INTO bible_verses (book_name, chapter, verse, text) VALUES
  ('2 Samuel', 7, 20, 'What more can David say to you? For you know your servant, Lord GOD.'),
  ('2 Samuel', 7, 21, 'For your word’s sake, and according to your own heart, you have worked all this greatness, to make your servant know it.'),
  ('2 Samuel', 7, 22, 'Therefore you are great, LORD God. For there is no one like you, neither is there any God besides you, according to all that we have heard with our ears.'),
  ('2 Samuel', 7, 23, 'What one nation in the earth is like your people, even like Israel, whom God went to redeem to himself for a people, and to make himself a name, and to do great things for you, and awesome things for your land, before your people, whom you redeemed to yourself out of Egypt, from the nations and their gods?'),
  ('2 Samuel', 7, 24, 'You established for yourself your people Israel to be your people forever; and you, LORD, became their God.'),
  ('2 Samuel', 7, 25, '“Now, LORD God, the word that you have spoken concerning your servant, and concerning his house, confirm it forever, and do as you have spoken.'),
  ('2 Samuel', 7, 26, 'Let your name be magnified forever, saying, ‘The LORD of Armies is God over Israel; and the house of your servant David will be established before you.’'),
  ('2 Samuel', 7, 27, 'For you, LORD of Armies, the God of Israel, have revealed to your servant, saying, ‘I will build you a house.’ Therefore your servant has found in his heart to pray this prayer to you.'),
  ('2 Samuel', 7, 28, '“Now, O Lord GOD, you are God, and your words are truth, and you have promised this good thing to your servant.'),
  ('2 Samuel', 7, 29, 'Now therefore, let it please you to bless the house of your servant, that it may continue forever before you; for you, Lord GOD, have spoken it. Let the house of your servant be blessed forever with your blessing.”'),
  ('2 Samuel', 8, 1, 'After this, David struck the Philistines and subdued them; and David took the bridle of the mother city out of the hand of the Philistines.'),
  ('2 Samuel', 8, 2, 'He defeated Moab, and measured them with the line, making them to lie down on the ground; and he measured two lines to put to death, and one full line to keep alive. The Moabites became servants to David, and brought tribute.'),
  ('2 Samuel', 8, 3, 'David also struck Hadadezer the son of Rehob, king of Zobah, as he went to recover his dominion at the River.'),
  ('2 Samuel', 8, 4, 'David took from him one thousand seven hundred horsemen and twenty thousand footmen. David hamstrung the chariot horses, but reserved enough of them for one hundred chariots.'),
  ('2 Samuel', 8, 5, 'When the Syrians of Damascus came to help Hadadezer king of Zobah, David struck twenty two thousand men of the Syrians.'),
  ('2 Samuel', 8, 6, 'Then David put garrisons in Syria of Damascus; and the Syrians became servants to David, and brought tribute. The LORD gave victory to David wherever he went.'),
  ('2 Samuel', 8, 7, 'David took the shields of gold that were on the servants of Hadadezer, and brought them to Jerusalem.'),
  ('2 Samuel', 8, 8, 'From Betah and from Berothai, cities of Hadadezer, King David took a great quantity of bronze.'),
  ('2 Samuel', 8, 9, 'When Toi king of Hamath heard that David had struck all the army of Hadadezer,'),
  ('2 Samuel', 8, 10, 'then Toi sent Joram his son to King David to greet him and to bless him, because he had fought against Hadadezer and struck him; for Hadadezer had wars with Toi. Joram brought with him vessels of silver, vessels of gold, and vessels of bronze.'),
  ('2 Samuel', 8, 11, 'King David also dedicated these to the LORD, with the silver and gold that he dedicated of all the nations which he subdued—'),
  ('2 Samuel', 8, 12, 'of Syria, of Moab, of the children of Ammon, of the Philistines, of Amalek, and of the plunder of Hadadezer, son of Rehob, king of Zobah.'),
  ('2 Samuel', 8, 13, 'David earned a reputation when he returned from striking down eighteen thousand men of the Syrians in the Valley of Salt.'),
  ('2 Samuel', 8, 14, 'He put garrisons in Edom. Throughout all Edom, he put garrisons, and all the Edomites became servants to David. The LORD gave victory to David wherever he went.'),
  ('2 Samuel', 8, 15, 'David reigned over all Israel; and David executed justice and righteousness for all his people.'),
  ('2 Samuel', 8, 16, 'Joab the son of Zeruiah was over the army, Jehoshaphat the son of Ahilud was recorder,'),
  ('2 Samuel', 8, 17, 'Zadok the son of Ahitub and Ahimelech the son of Abiathar were priests, Seraiah was scribe,'),
  ('2 Samuel', 8, 18, 'Benaiah the son of Jehoiada was over the Cherethites and the Pelethites; and David’s sons were chief ministers.'),
  ('2 Samuel', 9, 1, 'David said, “Is there yet any who is left of Saul’s house, that I may show him kindness for Jonathan’s sake?”'),
  ('2 Samuel', 9, 2, 'There was of Saul’s house a servant whose name was Ziba, and they called him to David; and the king said to him, “Are you Ziba?” He said, “I am your servant.”'),
  ('2 Samuel', 9, 3, 'The king said, “Is there not yet any of Saul’s house, that I may show the kindness of God to him?” Ziba said to the king, “Jonathan still has a son, who is lame in his feet.”'),
  ('2 Samuel', 9, 4, 'The king said to him, “Where is he?” Ziba said to the king, “Behold, he is in the house of Machir the son of Ammiel, in Lo Debar.”'),
  ('2 Samuel', 9, 5, 'Then King David sent and brought him out of the house of Machir the son of Ammiel, from Lo Debar.'),
  ('2 Samuel', 9, 6, 'Mephibosheth, the son of Jonathan, the son of Saul, came to David, fell on his face, and showed respect. David said, “Mephibosheth?” He answered, “Behold, your servant!”'),
  ('2 Samuel', 9, 7, 'David said to him, “Don’t be afraid, for I will surely show you kindness for Jonathan your father’s sake, and will restore to you all the land of Saul your father. You will eat bread at my table continually.”'),
  ('2 Samuel', 9, 8, 'He bowed down, and said, “What is your servant, that you should look at such a dead dog as I am?”'),
  ('2 Samuel', 9, 9, 'Then the king called to Ziba, Saul’s servant, and said to him, “All that belonged to Saul and to all his house I have given to your master’s son.'),
  ('2 Samuel', 9, 10, 'Till the land for him—you, your sons, and your servants. Bring in the harvest, that your master’s son may have bread to eat; but Mephibosheth your master’s son will always eat bread at my table.” Now Ziba had fifteen sons and twenty servants.'),
  ('2 Samuel', 9, 11, 'Then Ziba said to the king, “According to all that my lord the king commands his servant, so your servant will do.” So Mephibosheth ate at the king’s table like one of the king’s sons.'),
  ('2 Samuel', 9, 12, 'Mephibosheth had a young son, whose name was Mica. All who lived in Ziba’s house were servants to Mephibosheth.'),
  ('2 Samuel', 9, 13, 'So Mephibosheth lived in Jerusalem, for he ate continually at the king’s table. He was lame in both his feet.'),
  ('2 Samuel', 10, 1, 'After this, the king of the children of Ammon died, and Hanun his son reigned in his place.'),
  ('2 Samuel', 10, 2, 'David said, “I will show kindness to Hanun the son of Nahash, as his father showed kindness to me.” So David sent by his servants to comfort him concerning his father. David’s servants came into the land of the children of Ammon.'),
  ('2 Samuel', 10, 3, 'But the princes of the children of Ammon said to Hanun their lord, “Do you think that David honors your father, in that he has sent comforters to you? Hasn’t David sent his servants to you to search the city, to spy it out, and to overthrow it?”'),
  ('2 Samuel', 10, 4, 'So Hanun took David’s servants, shaved off one half of their beards, and cut off their garments in the middle, even to their buttocks, and sent them away.'),
  ('2 Samuel', 10, 5, 'When they told David this, he sent to meet them, for the men were greatly ashamed. The king said, “Wait at Jericho until your beards have grown, and then return.”'),
  ('2 Samuel', 10, 6, 'When the children of Ammon saw that they had become odious to David, the children of Ammon sent and hired the Syrians of Beth Rehob and the Syrians of Zobah, twenty thousand footmen, and the king of Maacah with one thousand men, and the men of Tob twelve thousand men.'),
  ('2 Samuel', 10, 7, 'When David heard of it, he sent Joab and all the army of the mighty men.'),
  ('2 Samuel', 10, 8, 'The children of Ammon came out, and put the battle in array at the entrance of the gate. The Syrians of Zobah and of Rehob and the men of Tob and Maacah were by themselves in the field.'),
  ('2 Samuel', 10, 9, 'Now when Joab saw that the battle was set against him before and behind, he chose of all the choice men of Israel and put them in array against the Syrians.'),
  ('2 Samuel', 10, 10, 'The rest of the people he committed into the hand of Abishai his brother; and he put them in array against the children of Ammon.'),
  ('2 Samuel', 10, 11, 'He said, “If the Syrians are too strong for me, then you shall help me; but if the children of Ammon are too strong for you, then I will come and help you.'),
  ('2 Samuel', 10, 12, 'Be courageous, and let’s be strong for our people and for the cities of our God; and may the LORD do what seems good to him.”'),
  ('2 Samuel', 10, 13, 'So Joab and the people who were with him came near to the battle against the Syrians, and they fled before him.'),
  ('2 Samuel', 10, 14, 'When the children of Ammon saw that the Syrians had fled, they likewise fled before Abishai, and entered into the city. Then Joab returned from the children of Ammon and came to Jerusalem.'),
  ('2 Samuel', 10, 15, 'When the Syrians saw that they were defeated by Israel, they gathered themselves together.'),
  ('2 Samuel', 10, 16, 'Hadadezer sent and brought out the Syrians who were beyond the River; and they came to Helam, with Shobach the captain of the army of Hadadezer at their head.'),
  ('2 Samuel', 10, 17, 'David was told that; and he gathered all Israel together, passed over the Jordan, and came to Helam. The Syrians set themselves in array against David and fought with him.'),
  ('2 Samuel', 10, 18, 'The Syrians fled before Israel; and David killed seven hundred charioteers of the Syrians and forty thousand horsemen, and struck Shobach the captain of their army, so that he died there.'),
  ('2 Samuel', 10, 19, 'When all the kings who were servants to Hadadezer saw that they were defeated before Israel, they made peace with Israel and served them. So the Syrians were afraid to help the children of Ammon any more.'),
  ('2 Samuel', 11, 1, 'At the return of the year, at the time when kings go out, David sent Joab and his servants with him, and all Israel; and they destroyed the children of Ammon and besieged Rabbah. But David stayed at Jerusalem.'),
  ('2 Samuel', 11, 2, 'At evening, David arose from his bed and walked on the roof of the king’s house. From the roof, he saw a woman bathing, and the woman was very beautiful to look at.'),
  ('2 Samuel', 11, 3, 'David sent and inquired after the woman. One said, “Isn’t this Bathsheba, the daughter of Eliam, Uriah the Hittite’s wife?”'),
  ('2 Samuel', 11, 4, 'David sent messengers, and took her; and she came in to him, and he lay with her (for she was purified from her uncleanness); and she returned to her house.'),
  ('2 Samuel', 11, 5, 'The woman conceived; and she sent and told David, and said, “I am with child.”'),
  ('2 Samuel', 11, 6, 'David sent to Joab, “Send me Uriah the Hittite.” Joab sent Uriah to David.'),
  ('2 Samuel', 11, 7, 'When Uriah had come to him, David asked him how Joab did, and how the people fared, and how the war prospered.'),
  ('2 Samuel', 11, 8, 'David said to Uriah, “Go down to your house and wash your feet.” Uriah departed out of the king’s house, and a gift from the king was sent after him.'),
  ('2 Samuel', 11, 9, 'But Uriah slept at the door of the king’s house with all the servants of his lord, and didn’t go down to his house.'),
  ('2 Samuel', 11, 10, 'When they had told David, saying, “Uriah didn’t go down to his house,” David said to Uriah, “Haven’t you come from a journey? Why didn’t you go down to your house?”'),
  ('2 Samuel', 11, 11, 'Uriah said to David, “The ark, Israel, and Judah, are staying in tents; and my lord Joab and the servants of my lord are encamped in the open field. Shall I then go into my house to eat and to drink, and to lie with my wife? As you live, and as your soul lives, I will not do this thing!”'),
  ('2 Samuel', 11, 12, 'David said to Uriah, “Stay here today also, and tomorrow I will let you depart.” So Uriah stayed in Jerusalem that day and the next day.'),
  ('2 Samuel', 11, 13, 'When David had called him, he ate and drank before him; and he made him drunk. At evening, he went out to lie on his bed with the servants of his lord, but didn’t go down to his house.'),
  ('2 Samuel', 11, 14, 'In the morning, David wrote a letter to Joab and sent it by the hand of Uriah.'),
  ('2 Samuel', 11, 15, 'He wrote in the letter, saying, “Send Uriah to the forefront of the hottest battle, and retreat from him, that he may be struck and die.”'),
  ('2 Samuel', 11, 16, 'When Joab kept watch on the city, he assigned Uriah to the place where he knew that valiant men were.'),
  ('2 Samuel', 11, 17, 'The men of the city went out and fought with Joab. Some of the people fell, even of David’s servants; and Uriah the Hittite died also.'),
  ('2 Samuel', 11, 18, 'Then Joab sent and told David all the things concerning the war;'),
  ('2 Samuel', 11, 19, 'and he commanded the messenger, saying, “When you have finished telling all the things concerning the war to the king,'),
  ('2 Samuel', 11, 20, 'it shall be that, if the king’s wrath arise, and he asks you, ‘Why did you go so near to the city to fight? Didn’t you know that they would shoot from the wall?'),
  ('2 Samuel', 11, 21, 'Who struck Abimelech the son of Jerubbesheth? Didn’t a woman cast an upper millstone on him from the wall, so that he died at Thebez? Why did you go so near the wall?’ then you shall say, ‘Your servant Uriah the Hittite is also dead.’”'),
  ('2 Samuel', 11, 22, 'So the messenger went, and came and showed David all that Joab had sent him for.'),
  ('2 Samuel', 11, 23, 'The messenger said to David, “The men prevailed against us, and came out to us into the field; and we were on them even to the entrance of the gate.'),
  ('2 Samuel', 11, 24, 'The shooters shot at your servants from off the wall; and some of the king’s servants are dead, and your servant Uriah the Hittite is also dead.”'),
  ('2 Samuel', 11, 25, 'Then David said to the messenger, “Tell Joab, ‘Don’t let this thing displease you, for the sword devours one as well as another. Make your battle stronger against the city, and overthrow it.’ Encourage him.”'),
  ('2 Samuel', 11, 26, 'When Uriah’s wife heard that Uriah her husband was dead, she mourned for her husband.'),
  ('2 Samuel', 11, 27, 'When the mourning was past, David sent and took her home to his house, and she became his wife and bore him a son. But the thing that David had done displeased the LORD.'),
  ('2 Samuel', 12, 1, 'The LORD sent Nathan to David. He came to him, and said to him, “There were two men in one city: the one rich, and the other poor.'),
  ('2 Samuel', 12, 2, 'The rich man had very many flocks and herds,'),
  ('2 Samuel', 12, 3, 'but the poor man had nothing, except one little ewe lamb, which he had bought and raised. It grew up together with him and with his children. It ate of his own food, drank of his own cup, and lay in his bosom, and was like a daughter to him.'),
  ('2 Samuel', 12, 4, 'A traveler came to the rich man, and he didn’t want to take of his own flock and of his own herd to prepare for the wayfaring man who had come to him, but took the poor man’s lamb and prepared it for the man who had come to him.”'),
  ('2 Samuel', 12, 5, 'David’s anger burned hot against the man, and he said to Nathan, “As the LORD lives, the man who has done this deserves to die!'),
  ('2 Samuel', 12, 6, 'He must restore the lamb fourfold, because he did this thing and because he had no pity!”'),
  ('2 Samuel', 12, 7, 'Nathan said to David, “You are the man! This is what the LORD, the God of Israel, says: ‘I anointed you king over Israel, and I delivered you out of the hand of Saul.'),
  ('2 Samuel', 12, 8, 'I gave you your master’s house and your master’s wives into your bosom, and gave you the house of Israel and of Judah; and if that would have been too little, I would have added to you many more such things.'),
  ('2 Samuel', 12, 9, 'Why have you despised the LORD’s word, to do that which is evil in his sight? You have struck Uriah the Hittite with the sword, have taken his wife to be your wife, and have slain him with the sword of the children of Ammon.'),
  ('2 Samuel', 12, 10, 'Now therefore the sword will never depart from your house, because you have despised me and have taken Uriah the Hittite’s wife to be your wife.’'),
  ('2 Samuel', 12, 11, '“This is what the LORD says: ‘Behold, I will raise up evil against you out of your own house; and I will take your wives before your eyes and give them to your neighbor, and he will lie with your wives in the sight of this sun.'),
  ('2 Samuel', 12, 12, 'For you did this secretly, but I will do this thing before all Israel, and before the sun.’”'),
  ('2 Samuel', 12, 13, 'David said to Nathan, “I have sinned against the LORD.” Nathan said to David, “The LORD also has put away your sin. You will not die.');
INSERT INTO bible_verses (book_name, chapter, verse, text) VALUES
  ('2 Samuel', 12, 14, 'However, because by this deed you have given great occasion to the LORD’s enemies to blaspheme, the child also who is born to you will surely die.”'),
  ('2 Samuel', 12, 15, 'Then Nathan departed to his house. The LORD struck the child that Uriah’s wife bore to David, and he was very sick.'),
  ('2 Samuel', 12, 16, 'David therefore begged God for the child; and David fasted, and went in and lay all night on the ground.'),
  ('2 Samuel', 12, 17, 'The elders of his house arose beside him, to raise him up from the earth; but he would not, and he didn’t eat bread with them.'),
  ('2 Samuel', 12, 18, 'On the seventh day, the child died. David’s servants were afraid to tell him that the child was dead, for they said, “Behold, while the child was yet alive, we spoke to him and he didn’t listen to our voice. How will he then harm himself if we tell him that the child is dead?”'),
  ('2 Samuel', 12, 19, 'But when David saw that his servants were whispering together, David perceived that the child was dead; and David said to his servants, “Is the child dead?” They said, “He is dead.”'),
  ('2 Samuel', 12, 20, 'Then David arose from the earth, and washed and anointed himself, and changed his clothing; and he came into the LORD’s house, and worshiped. Then he came to his own house; and when he requested, they set bread before him and he ate.'),
  ('2 Samuel', 12, 21, 'Then his servants said to him, “What is this that you have done? You fasted and wept for the child while he was alive, but when the child was dead, you rose up and ate bread.”'),
  ('2 Samuel', 12, 22, 'He said, “While the child was yet alive, I fasted and wept; for I said, ‘Who knows whether the LORD will not be gracious to me, that the child may live?’'),
  ('2 Samuel', 12, 23, 'But now he is dead. Why should I fast? Can I bring him back again? I will go to him, but he will not return to me.”'),
  ('2 Samuel', 12, 24, 'David comforted Bathsheba his wife, and went in to her, and lay with her. She bore a son, and he called his name Solomon. The LORD loved him;'),
  ('2 Samuel', 12, 25, 'and he sent by the hand of Nathan the prophet, and he named him Jedidiah, for the LORD’s sake.'),
  ('2 Samuel', 12, 26, 'Now Joab fought against Rabbah of the children of Ammon, and took the royal city.'),
  ('2 Samuel', 12, 27, 'Joab sent messengers to David, and said, “I have fought against Rabbah. Yes, I have taken the city of waters.'),
  ('2 Samuel', 12, 28, 'Now therefore gather the rest of the people together, and encamp against the city and take it; lest I take the city, and it be called by my name.”'),
  ('2 Samuel', 12, 29, 'David gathered all the people together and went to Rabbah, and fought against it and took it.'),
  ('2 Samuel', 12, 30, 'He took the crown of their king from off his head; and its weight was a talent of gold, and in it were precious stones; and it was set on David’s head. He brought a great quantity of plunder out of the city.'),
  ('2 Samuel', 12, 31, 'He brought out the people who were in it, and put them to work under saws, under iron picks, under axes of iron, and made them go to the brick kiln; and he did so to all the cities of the children of Ammon. Then David and all the people returned to Jerusalem.'),
  ('2 Samuel', 13, 1, 'After this, Absalom the son of David had a beautiful sister, whose name was Tamar; and Amnon the son of David loved her.'),
  ('2 Samuel', 13, 2, 'Amnon was so troubled that he became sick because of his sister Tamar, for she was a virgin, and it seemed hard to Amnon to do anything to her.'),
  ('2 Samuel', 13, 3, 'But Amnon had a friend whose name was Jonadab the son of Shimeah, David’s brother; and Jonadab was a very subtle man.'),
  ('2 Samuel', 13, 4, 'He said to him, “Why, son of the king, are you so sad from day to day? Won’t you tell me?” Amnon said to him, “I love Tamar, my brother Absalom’s sister.”'),
  ('2 Samuel', 13, 5, 'Jonadab said to him, “Lay down on your bed and pretend to be sick. When your father comes to see you, tell him, ‘Please let my sister Tamar come and give me bread to eat, and prepare the food in my sight, that I may see it and eat it from her hand.’”'),
  ('2 Samuel', 13, 6, 'So Amnon lay down and faked being sick. When the king came to see him, Amnon said to the king, “Please let my sister Tamar come and make me a couple of cakes in my sight, that I may eat from her hand.”'),
  ('2 Samuel', 13, 7, 'Then David sent home to Tamar, saying, “Go now to your brother Amnon’s house, and prepare food for him.”'),
  ('2 Samuel', 13, 8, 'So Tamar went to her brother Amnon’s house; and he was lying down. She took dough, kneaded it, made cakes in his sight, and baked the cakes.'),
  ('2 Samuel', 13, 9, 'She took the pan and poured them out before him, but he refused to eat. Amnon said, “Have all men leave me.” Then every man went out from him.'),
  ('2 Samuel', 13, 10, 'Amnon said to Tamar, “Bring the food into the room, that I may eat from your hand.” Tamar took the cakes which she had made, and brought them into the room to Amnon her brother.'),
  ('2 Samuel', 13, 11, 'When she had brought them near to him to eat, he took hold of her and said to her, “Come, lie with me, my sister!”'),
  ('2 Samuel', 13, 12, 'She answered him, “No, my brother, do not force me! For no such thing ought to be done in Israel. Don’t you do this folly!'),
  ('2 Samuel', 13, 13, 'As for me, where would I carry my shame? And as for you, you will be as one of the fools in Israel. Now therefore, please speak to the king; for he will not withhold me from you.”'),
  ('2 Samuel', 13, 14, 'However, he would not listen to her voice; but being stronger than she, he forced her and lay with her.'),
  ('2 Samuel', 13, 15, 'Then Amnon hated her with exceedingly great hatred; for the hatred with which he hated her was greater than the love with which he had loved her. Amnon said to her, “Arise, be gone!”'),
  ('2 Samuel', 13, 16, 'She said to him, “Not so, because this great wrong in sending me away is worse than the other that you did to me!” But he would not listen to her.'),
  ('2 Samuel', 13, 17, 'Then he called his servant who ministered to him, and said, “Now put this woman out from me, and bolt the door after her.”'),
  ('2 Samuel', 13, 18, 'She had a garment of various colors on her, for the king’s daughters who were virgins dressed in such robes. Then his servant brought her out and bolted the door after her.'),
  ('2 Samuel', 13, 19, 'Tamar put ashes on her head, and tore her garment of various colors that was on her; and she laid her hand on her head and went her way, crying aloud as she went.'),
  ('2 Samuel', 13, 20, 'Absalom her brother said to her, “Has Amnon your brother been with you? But now hold your peace, my sister. He is your brother. Don’t take this thing to heart.” So Tamar remained desolate in her brother Absalom’s house.'),
  ('2 Samuel', 13, 21, 'But when King David heard of all these things, he was very angry.'),
  ('2 Samuel', 13, 22, 'Absalom spoke to Amnon neither good nor bad; for Absalom hated Amnon, because he had forced his sister Tamar.'),
  ('2 Samuel', 13, 23, 'After two full years, Absalom had sheep shearers in Baal Hazor, which is beside Ephraim; and Absalom invited all the king’s sons.'),
  ('2 Samuel', 13, 24, 'Absalom came to the king and said, “See now, your servant has sheep shearers. Please let the king and his servants go with your servant.”'),
  ('2 Samuel', 13, 25, 'The king said to Absalom, “No, my son, let’s not all go, lest we be burdensome to you.” He pressed him; however he would not go, but blessed him.'),
  ('2 Samuel', 13, 26, 'Then Absalom said, “If not, please let my brother Amnon go with us.” The king said to him, “Why should he go with you?”'),
  ('2 Samuel', 13, 27, 'But Absalom pressed him, and he let Amnon and all the king’s sons go with him.'),
  ('2 Samuel', 13, 28, 'Absalom commanded his servants, saying, “Mark now, when Amnon’s heart is merry with wine; and when I tell you, ‘Strike Amnon,’ then kill him. Don’t be afraid. Haven’t I commanded you? Be courageous, and be valiant!”'),
  ('2 Samuel', 13, 29, 'The servants of Absalom did to Amnon as Absalom had commanded. Then all the king’s sons arose, and every man got up on his mule and fled.'),
  ('2 Samuel', 13, 30, 'While they were on the way, the news came to David, saying, “Absalom has slain all the king’s sons, and there is not one of them left!”'),
  ('2 Samuel', 13, 31, 'Then the king arose, and tore his garments, and lay on the earth; and all his servants stood by with their clothes torn.'),
  ('2 Samuel', 13, 32, 'Jonadab the son of Shimeah, David’s brother, answered, “Don’t let my lord suppose that they have killed all the young men, the king’s sons, for Amnon only is dead; for by the appointment of Absalom this has been determined from the day that he forced his sister Tamar.'),
  ('2 Samuel', 13, 33, 'Now therefore don’t let my lord the king take the thing to his heart, to think that all the king’s sons are dead; for only Amnon is dead.”'),
  ('2 Samuel', 13, 34, 'But Absalom fled. The young man who kept the watch lifted up his eyes and looked, and behold, many people were coming by way of the hillside behind him.'),
  ('2 Samuel', 13, 35, 'Jonadab said to the king, “Behold, the king’s sons are coming! It is as your servant said.”'),
  ('2 Samuel', 13, 36, 'As soon as he had finished speaking, behold, the king’s sons came, and lifted up their voices and wept. The king also and all his servants wept bitterly.'),
  ('2 Samuel', 13, 37, 'But Absalom fled and went to Talmai the son of Ammihur, king of Geshur. David mourned for his son every day.'),
  ('2 Samuel', 13, 38, 'So Absalom fled and went to Geshur, and was there three years.'),
  ('2 Samuel', 13, 39, 'King David longed to go out to Absalom, for he was comforted concerning Amnon, since he was dead.'),
  ('2 Samuel', 14, 1, 'Now Joab the son of Zeruiah perceived that the king’s heart was toward Absalom.'),
  ('2 Samuel', 14, 2, 'Joab sent to Tekoa and brought a wise woman from there, and said to her, “Please act like a mourner, and put on mourning clothing, please, and don’t anoint yourself with oil; but be as a woman who has mourned a long time for the dead.'),
  ('2 Samuel', 14, 3, 'Go in to the king and speak like this to him.” So Joab put the words in her mouth.'),
  ('2 Samuel', 14, 4, 'When the woman of Tekoa spoke to the king, she fell on her face to the ground, showed respect, and said, “Help, O king!”'),
  ('2 Samuel', 14, 5, 'The king said to her, “What ails you?” She answered, “Truly I am a widow, and my husband is dead.'),
  ('2 Samuel', 14, 6, 'Your servant had two sons; and they both fought together in the field, and there was no one to part them, but the one struck the other and killed him.'),
  ('2 Samuel', 14, 7, 'Behold, the whole family has risen against your servant, and they say, ‘Deliver him who struck his brother, that we may kill him for the life of his brother whom he killed, and so destroy the heir also.’ Thus they would quench my coal which is left, and would leave to my husband neither name nor remainder on the surface of the earth.”'),
  ('2 Samuel', 14, 8, 'The king said to the woman, “Go to your house, and I will give a command concerning you.”'),
  ('2 Samuel', 14, 9, 'The woman of Tekoa said to the king, “My lord, O king, may the iniquity be on me, and on my father’s house; and may the king and his throne be guiltless.”'),
  ('2 Samuel', 14, 10, 'The king said, “Whoever says anything to you, bring him to me, and he will not bother you any more.”'),
  ('2 Samuel', 14, 11, 'Then she said, “Please let the king remember the LORD your God, that the avenger of blood destroy not any more, lest they destroy my son.” He said, “As the LORD lives, not one hair of your son shall fall to the earth.”'),
  ('2 Samuel', 14, 12, 'Then the woman said, “Please let your servant speak a word to my lord the king.” He said, “Say on.”'),
  ('2 Samuel', 14, 13, 'The woman said, “Why then have you devised such a thing against the people of God? For in speaking this word the king is as one who is guilty, in that the king does not bring home again his banished one.'),
  ('2 Samuel', 14, 14, 'For we must die, and are like water spilled on the ground, which can’t be gathered up again; neither does God take away life, but devises means, that he who is banished not be an outcast from him.'),
  ('2 Samuel', 14, 15, 'Now therefore, seeing that I have come to speak this word to my lord the king, it is because the people have made me afraid. Your servant said, ‘I will now speak to the king; it may be that the king will perform the request of his servant.’'),
  ('2 Samuel', 14, 16, 'For the king will hear, to deliver his servant out of the hand of the man who would destroy me and my son together out of the inheritance of God.'),
  ('2 Samuel', 14, 17, 'Then your servant said, ‘Please let the word of my lord the king bring rest; for as an angel of God, so is my lord the king to discern good and bad. May the LORD, your God, be with you.’”'),
  ('2 Samuel', 14, 18, 'Then the king answered the woman, “Please don’t hide anything from me that I ask you.” The woman said, “Let my lord the king now speak.”'),
  ('2 Samuel', 14, 19, 'The king said, “Is the hand of Joab with you in all this?” The woman answered, “As your soul lives, my lord the king, no one can turn to the right hand or to the left from anything that my lord the king has spoken; for your servant Joab urged me, and he put all these words in the mouth of your servant.'),
  ('2 Samuel', 14, 20, 'Your servant Joab has done this thing to change the face of the matter. My lord is wise, according to the wisdom of an angel of God, to know all things that are in the earth.”'),
  ('2 Samuel', 14, 21, 'The king said to Joab, “Behold now, I have granted this thing. Go therefore, and bring the young man Absalom back.”'),
  ('2 Samuel', 14, 22, 'Joab fell to the ground on his face, showed respect, and blessed the king. Joab said, “Today your servant knows that I have found favor in your sight, my lord, O king, in that the king has performed the request of his servant.”'),
  ('2 Samuel', 14, 23, 'So Joab arose and went to Geshur, and brought Absalom to Jerusalem.'),
  ('2 Samuel', 14, 24, 'The king said, “Let him return to his own house, but let him not see my face.” So Absalom returned to his own house, and didn’t see the king’s face.'),
  ('2 Samuel', 14, 25, 'Now in all Israel there was no one to be so much praised as Absalom for his beauty. From the sole of his foot even to the crown of his head there was no defect in him.'),
  ('2 Samuel', 14, 26, 'When he cut the hair of his head (now it was at every year’s end that he cut it; because it was heavy on him, therefore he cut it), he weighed the hair of his head at two hundred shekels, after the king’s weight.'),
  ('2 Samuel', 14, 27, 'Three sons were born to Absalom, and one daughter, whose name was Tamar. She was a woman with a beautiful face.'),
  ('2 Samuel', 14, 28, 'Absalom lived two full years in Jerusalem, and he didn’t see the king’s face.'),
  ('2 Samuel', 14, 29, 'Then Absalom sent for Joab, to send him to the king, but he would not come to him. Then he sent again a second time, but he would not come.'),
  ('2 Samuel', 14, 30, 'Therefore he said to his servants, “Behold, Joab’s field is near mine, and he has barley there. Go and set it on fire.” So Absalom’s servants set the field on fire.'),
  ('2 Samuel', 14, 31, 'Then Joab arose and came to Absalom to his house, and said to him, “Why have your servants set my field on fire?”'),
  ('2 Samuel', 14, 32, 'Absalom answered Joab, “Behold, I sent to you, saying, ‘Come here, that I may send you to the king, to say, “Why have I come from Geshur? It would be better for me to be there still. Now therefore, let me see the king’s face; and if there is iniquity in me, let him kill me.”’”'),
  ('2 Samuel', 14, 33, 'So Joab came to the king and told him; and when he had called for Absalom, he came to the king and bowed himself on his face to the ground before the king; and the king kissed Absalom.'),
  ('2 Samuel', 15, 1, 'After this, Absalom prepared a chariot and horses for himself, and fifty men to run before him.'),
  ('2 Samuel', 15, 2, 'Absalom rose up early, and stood beside the way of the gate. When any man had a suit which should come to the king for judgment, then Absalom called to him, and said, “What city are you from?” He said, “Your servant is of one of the tribes of Israel.”'),
  ('2 Samuel', 15, 3, 'Absalom said to him, “Behold, your matters are good and right; but there is no man deputized by the king to hear you.”'),
  ('2 Samuel', 15, 4, 'Absalom said moreover, “Oh that I were made judge in the land, that every man who has any suit or cause might come to me, and I would do him justice!”'),
  ('2 Samuel', 15, 5, 'It was so, that when any man came near to bow down to him, he stretched out his hand, took hold of him, and kissed him.'),
  ('2 Samuel', 15, 6, 'Absalom did this sort of thing to all Israel who came to the king for judgment. So Absalom stole the hearts of the men of Israel.'),
  ('2 Samuel', 15, 7, 'At the end of forty years, Absalom said to the king, “Please let me go and pay my vow, which I have vowed to the LORD, in Hebron.'),
  ('2 Samuel', 15, 8, 'For your servant vowed a vow while I stayed at Geshur in Syria, saying, ‘If the LORD shall indeed bring me again to Jerusalem, then I will serve the LORD.’”'),
  ('2 Samuel', 15, 9, 'The king said to him, “Go in peace.” So he arose and went to Hebron.'),
  ('2 Samuel', 15, 10, 'But Absalom sent spies throughout all the tribes of Israel, saying, “As soon as you hear the sound of the trumpet, then you shall say, ‘Absalom is king in Hebron!’”');
INSERT INTO bible_verses (book_name, chapter, verse, text) VALUES
  ('2 Samuel', 15, 11, 'Two hundred men went with Absalom out of Jerusalem, who were invited, and went in their simplicity; and they didn’t know anything.'),
  ('2 Samuel', 15, 12, 'Absalom sent for Ahithophel the Gilonite, David’s counselor, from his city, even from Giloh, while he was offering the sacrifices. The conspiracy was strong, for the people increased continually with Absalom.'),
  ('2 Samuel', 15, 13, 'A messenger came to David, saying, “The hearts of the men of Israel are after Absalom.”'),
  ('2 Samuel', 15, 14, 'David said to all his servants who were with him at Jerusalem, “Arise! Let’s flee, or else none of us will escape from Absalom. Hurry to depart, lest he overtake us quickly and bring down evil on us, and strike the city with the edge of the sword.”'),
  ('2 Samuel', 15, 15, 'The king’s servants said to the king, “Behold, your servants are ready to do whatever my lord the king chooses.”'),
  ('2 Samuel', 15, 16, 'The king went out, and all his household after him. The king left ten women, who were concubines, to keep the house.'),
  ('2 Samuel', 15, 17, 'The king went out, and all the people after him; and they stayed in Beth Merhak.'),
  ('2 Samuel', 15, 18, 'All his servants passed on beside him; and all the Cherethites, and all the Pelethites, and all the Gittites, six hundred men who came after him from Gath, passed on before the king.'),
  ('2 Samuel', 15, 19, 'Then the king said to Ittai the Gittite, “Why do you also go with us? Return, and stay with the king; for you are a foreigner and also an exile. Return to your own place.'),
  ('2 Samuel', 15, 20, 'Whereas you came but yesterday, should I today make you go up and down with us, since I go where I may? Return, and take back your brothers. Mercy and truth be with you.”'),
  ('2 Samuel', 15, 21, 'Ittai answered the king and said, “As the LORD lives, and as my lord the king lives, surely in what place my lord the king is, whether for death or for life, your servant will be there also.”'),
  ('2 Samuel', 15, 22, 'David said to Ittai, “Go and pass over.” Ittai the Gittite passed over, and all his men, and all the little ones who were with him.'),
  ('2 Samuel', 15, 23, 'All the country wept with a loud voice, and all the people passed over. The king also himself passed over the brook Kidron, and all the people passed over toward the way of the wilderness.'),
  ('2 Samuel', 15, 24, 'Behold, Zadok also came, and all the Levites with him, bearing the ark of the covenant of God; and they set down God’s ark; and Abiathar went up until all the people finished passing out of the city.'),
  ('2 Samuel', 15, 25, 'The king said to Zadok, “Carry God’s ark back into the city. If I find favor in the LORD’s eyes, he will bring me again, and show me both it and his habitation;'),
  ('2 Samuel', 15, 26, 'but if he says, ‘I have no delight in you,’ behold, here I am. Let him do to me as seems good to him.”'),
  ('2 Samuel', 15, 27, 'The king said also to Zadok the priest, “Aren’t you a seer? Return into the city in peace, and your two sons with you, Ahimaaz your son and Jonathan the son of Abiathar.'),
  ('2 Samuel', 15, 28, 'Behold, I will stay at the fords of the wilderness until word comes from you to inform me.”'),
  ('2 Samuel', 15, 29, 'Zadok therefore and Abiathar carried God’s ark to Jerusalem again; and they stayed there.'),
  ('2 Samuel', 15, 30, 'David went up by the ascent of the Mount of Olives, and wept as he went up; and he had his head covered and went barefoot. All the people who were with him each covered his head, and they went up, weeping as they went up.'),
  ('2 Samuel', 15, 31, 'Someone told David, saying, “Ahithophel is among the conspirators with Absalom.” David said, “LORD, please turn the counsel of Ahithophel into foolishness.”'),
  ('2 Samuel', 15, 32, 'When David had come to the top, where God was worshiped, behold, Hushai the Archite came to meet him with his tunic torn and earth on his head.'),
  ('2 Samuel', 15, 33, 'David said to him, “If you pass on with me, then you will be a burden to me;'),
  ('2 Samuel', 15, 34, 'but if you return to the city, and tell Absalom, ‘I will be your servant, O king. As I have been your father’s servant in time past, so I will now be your servant; then you will defeat for me the counsel of Ahithophel.’'),
  ('2 Samuel', 15, 35, 'Don’t you have Zadok and Abiathar the priests there with you? Therefore whatever you hear out of the king’s house, tell it to Zadok and Abiathar the priests.'),
  ('2 Samuel', 15, 36, 'Behold, they have there with them their two sons, Ahimaaz, Zadok’s son, and Jonathan, Abiathar’s son. Send to me everything that you shall hear by them.”'),
  ('2 Samuel', 15, 37, 'So Hushai, David’s friend, came into the city; and Absalom came into Jerusalem.'),
  ('2 Samuel', 16, 1, 'When David was a little past the top, behold, Ziba the servant of Mephibosheth met him with a couple of donkeys saddled, and on them two hundred loaves of bread, and one hundred clusters of raisins, and one hundred summer fruits, and a container of wine.'),
  ('2 Samuel', 16, 2, 'The king said to Ziba, “What do you mean by these?” Ziba said, “The donkeys are for the king’s household to ride on; and the bread and summer fruit for the young men to eat; and the wine, that those who are faint in the wilderness may drink.”'),
  ('2 Samuel', 16, 3, 'The king said, “Where is your master’s son?” Ziba said to the king, “Behold, he is staying in Jerusalem; for he said, ‘Today the house of Israel will restore me the kingdom of my father.’”'),
  ('2 Samuel', 16, 4, 'Then the king said to Ziba, “Behold, all that belongs to Mephibosheth is yours.” Ziba said, “I bow down. Let me find favor in your sight, my lord, O king.”'),
  ('2 Samuel', 16, 5, 'When King David came to Bahurim, behold, a man of the family of Saul’s house came out, whose name was Shimei, the son of Gera. He came out and cursed as he came.'),
  ('2 Samuel', 16, 6, 'He cast stones at David and at all the servants of King David, and all the people and all the mighty men were on his right hand and on his left.'),
  ('2 Samuel', 16, 7, 'Shimei said when he cursed, “Be gone, be gone, you man of blood, and wicked fellow!'),
  ('2 Samuel', 16, 8, 'The LORD has returned on you all the blood of Saul’s house, in whose place you have reigned! The LORD has delivered the kingdom into the hand of Absalom your son! Behold, you are caught by your own mischief, because you are a man of blood!”'),
  ('2 Samuel', 16, 9, 'Then Abishai the son of Zeruiah said to the king, “Why should this dead dog curse my lord the king? Please let me go over and take off his head.”'),
  ('2 Samuel', 16, 10, 'The king said, “What have I to do with you, you sons of Zeruiah? Because he curses, and because the LORD has said to him, ‘Curse David,’ who then shall say, ‘Why have you done so?’”'),
  ('2 Samuel', 16, 11, 'David said to Abishai and to all his servants, “Behold, my son, who came out of my bowels, seeks my life. How much more this Benjamite, now? Leave him alone, and let him curse; for the LORD has invited him.'),
  ('2 Samuel', 16, 12, 'It may be that the LORD will look on the wrong done to me, and that the LORD will repay me good for the cursing of me today.”'),
  ('2 Samuel', 16, 13, 'So David and his men went by the way; and Shimei went along on the hillside opposite him and cursed as he went, threw stones at him, and threw dust.'),
  ('2 Samuel', 16, 14, 'The king and all the people who were with him arrived weary; and he refreshed himself there.'),
  ('2 Samuel', 16, 15, 'Absalom and all the people, the men of Israel, came to Jerusalem, and Ahithophel with him.'),
  ('2 Samuel', 16, 16, 'When Hushai the Archite, David’s friend, had come to Absalom, Hushai said to Absalom, “Long live the king! Long live the king!”'),
  ('2 Samuel', 16, 17, 'Absalom said to Hushai, “Is this your kindness to your friend? Why didn’t you go with your friend?”'),
  ('2 Samuel', 16, 18, 'Hushai said to Absalom, “No; but whomever the LORD and this people and all the men of Israel have chosen, I will be his, and I will stay with him.'),
  ('2 Samuel', 16, 19, 'Again, whom should I serve? Shouldn’t I serve in the presence of his son? As I have served in your father’s presence, so I will be in your presence.”'),
  ('2 Samuel', 16, 20, 'Then Absalom said to Ahithophel, “Give your counsel what we shall do.”'),
  ('2 Samuel', 16, 21, 'Ahithophel said to Absalom, “Go in to your father’s concubines that he has left to keep the house. Then all Israel will hear that you are abhorred by your father. Then the hands of all who are with you will be strong.”'),
  ('2 Samuel', 16, 22, 'So they spread a tent for Absalom on the top of the house, and Absalom went in to his father’s concubines in the sight of all Israel.'),
  ('2 Samuel', 16, 23, 'The counsel of Ahithophel, which he gave in those days, was as if a man inquired at the inner sanctuary of God. All the counsel of Ahithophel was like this both with David and with Absalom.'),
  ('2 Samuel', 17, 1, 'Moreover Ahithophel said to Absalom, “Let me now choose twelve thousand men, and I will arise and pursue after David tonight.'),
  ('2 Samuel', 17, 2, 'I will come on him while he is weary and exhausted, and will make him afraid. All the people who are with him will flee. I will strike the king only,'),
  ('2 Samuel', 17, 3, 'and I will bring back all the people to you. The man whom you seek is as if all returned. All the people shall be in peace.”'),
  ('2 Samuel', 17, 4, 'The saying pleased Absalom well, and all the elders of Israel.'),
  ('2 Samuel', 17, 5, 'Then Absalom said, “Now call Hushai the Archite also, and let’s hear likewise what he says.”'),
  ('2 Samuel', 17, 6, 'When Hushai had come to Absalom, Absalom spoke to him, saying, “Ahithophel has spoken like this. Shall we do what he says? If not, speak up.”'),
  ('2 Samuel', 17, 7, 'Hushai said to Absalom, “The counsel that Ahithophel has given this time is not good.”'),
  ('2 Samuel', 17, 8, 'Hushai said moreover, “You know your father and his men, that they are mighty men, and they are fierce in their minds, like a bear robbed of her cubs in the field. Your father is a man of war, and will not lodge with the people.'),
  ('2 Samuel', 17, 9, 'Behold, he is now hidden in some pit, or in some other place. It will happen, when some of them have fallen at the first, that whoever hears it will say, ‘There is a slaughter among the people who follow Absalom!’'),
  ('2 Samuel', 17, 10, 'Even he who is valiant, whose heart is as the heart of a lion, will utterly melt; for all Israel knows that your father is a mighty man, and those who are with him are valiant men.'),
  ('2 Samuel', 17, 11, 'But I counsel that all Israel be gathered together to you, from Dan even to Beersheba, as the sand that is by the sea for multitude; and that you go to battle in your own person.'),
  ('2 Samuel', 17, 12, 'So we will come on him in some place where he will be found, and we will light on him as the dew falls on the ground, then we will not leave so much as one of him and of all the men who are with him.'),
  ('2 Samuel', 17, 13, 'Moreover, if he has gone into a city, then all Israel will bring ropes to that city, and we will draw it into the river, until there isn’t one small stone found there.”'),
  ('2 Samuel', 17, 14, 'Absalom and all the men of Israel said, “The counsel of Hushai the Archite is better than the counsel of Ahithophel.” For the LORD had ordained to defeat the good counsel of Ahithophel, to the intent that the LORD might bring evil on Absalom.'),
  ('2 Samuel', 17, 15, 'Then Hushai said to Zadok and to Abiathar the priests, “Ahithophel counseled Absalom and the elders of Israel that way; and I have counseled this way.'),
  ('2 Samuel', 17, 16, 'Now therefore send quickly, and tell David, saying, ‘Don’t lodge tonight at the fords of the wilderness, but by all means pass over, lest the king be swallowed up, and all the people who are with him.’”'),
  ('2 Samuel', 17, 17, 'Now Jonathan and Ahimaaz were staying by En Rogel; and a female servant used to go and report to them, and they went and told King David; for they couldn’t risk being seen coming into the city.'),
  ('2 Samuel', 17, 18, 'But a boy saw them, and told Absalom. Then they both went away quickly and came to the house of a man in Bahurim, who had a well in his court; and they went down there.'),
  ('2 Samuel', 17, 19, 'The woman took and spread the covering over the well’s mouth, and spread out crushed grain on it; and nothing was known.'),
  ('2 Samuel', 17, 20, 'Absalom’s servants came to the woman to the house; and they said, “Where are Ahimaaz and Jonathan?” The woman said to them, “They have gone over the brook of water.” When they had sought and could not find them, they returned to Jerusalem.'),
  ('2 Samuel', 17, 21, 'After they had departed, they came up out of the well and went and told King David; and they said to David, “Arise and pass quickly over the water; for thus has Ahithophel counseled against you.”'),
  ('2 Samuel', 17, 22, 'Then David arose, and all the people who were with him, and they passed over the Jordan. By the morning light there lacked not one of them who had not gone over the Jordan.'),
  ('2 Samuel', 17, 23, 'When Ahithophel saw that his counsel was not followed, he saddled his donkey, arose, and went home to his city, set his house in order, and hanged himself; and he died, and was buried in the tomb of his father.'),
  ('2 Samuel', 17, 24, 'Then David came to Mahanaim. Absalom passed over the Jordan, he and all the men of Israel with him.'),
  ('2 Samuel', 17, 25, 'Absalom set Amasa over the army instead of Joab. Now Amasa was the son of a man whose name was Ithra the Israelite, who went in to Abigail the daughter of Nahash, sister to Zeruiah, Joab’s mother.'),
  ('2 Samuel', 17, 26, 'Israel and Absalom encamped in the land of Gilead.'),
  ('2 Samuel', 17, 27, 'When David had come to Mahanaim, Shobi the son of Nahash of Rabbah of the children of Ammon, and Machir the son of Ammiel of Lodebar, and Barzillai the Gileadite of Rogelim,'),
  ('2 Samuel', 17, 28, 'brought beds, basins, earthen vessels, wheat, barley, meal, parched grain, beans, lentils, roasted grain,'),
  ('2 Samuel', 17, 29, 'honey, butter, sheep, and cheese of the herd, for David and for the people who were with him to eat; for they said, “The people are hungry, weary, and thirsty in the wilderness.”'),
  ('2 Samuel', 18, 1, 'David counted the people who were with him, and set captains of thousands and captains of hundreds over them.'),
  ('2 Samuel', 18, 2, 'David sent the people out, a third part under the hand of Joab, and a third part under the hand of Abishai the son of Zeruiah, Joab’s brother, and a third part under the hand of Ittai the Gittite. The king said to the people, “I will also surely go out with you myself.”'),
  ('2 Samuel', 18, 3, 'But the people said, “You shall not go out, for if we flee away, they will not care for us, neither if half of us die, will they care for us. But you are worth ten thousand of us. Therefore now it is better that you are ready to help us out of the city.”'),
  ('2 Samuel', 18, 4, 'The king said to them, “I will do what seems best to you.” The king stood beside the gate, and all the people went out by hundreds and by thousands.'),
  ('2 Samuel', 18, 5, 'The king commanded Joab and Abishai and Ittai, saying, “Deal gently for my sake with the young man Absalom.” All the people heard when the king commanded all the captains concerning Absalom.'),
  ('2 Samuel', 18, 6, 'So the people went out into the field against Israel; and the battle was in the forest of Ephraim.'),
  ('2 Samuel', 18, 7, 'The people of Israel were struck there before David’s servants, and there was a great slaughter there that day of twenty thousand men.'),
  ('2 Samuel', 18, 8, 'For the battle was there spread over the surface of all the country, and the forest devoured more people that day than the sword devoured.'),
  ('2 Samuel', 18, 9, 'Absalom happened to meet David’s servants. Absalom was riding on his mule, and the mule went under the thick boughs of a great oak; and his head caught hold of the oak, and he was hanging between the sky and earth; and the mule that was under him went on.'),
  ('2 Samuel', 18, 10, 'A certain man saw it, and told Joab, and said, “Behold, I saw Absalom hanging in an oak.”'),
  ('2 Samuel', 18, 11, 'Joab said to the man who told him, “Behold, you saw it, and why didn’t you strike him there to the ground? I would have given you ten pieces of silver and a sash.”'),
  ('2 Samuel', 18, 12, 'The man said to Joab, “Though I should receive a thousand pieces of silver in my hand, I still wouldn’t stretch out my hand against the king’s son; for in our hearing the king commanded you and Abishai and Ittai, saying, ‘Beware that no one touch the young man Absalom.’'),
  ('2 Samuel', 18, 13, 'Otherwise, if I had dealt falsely against his life (and there is no matter hidden from the king), then you yourself would have set yourself against me.”'),
  ('2 Samuel', 18, 14, 'Then Joab said, “I’m not going to wait like this with you.” He took three darts in his hand and thrust them through Absalom’s heart while he was still alive in the middle of the oak.'),
  ('2 Samuel', 18, 15, 'Ten young men who bore Joab’s armor surrounded and struck Absalom, and killed him.'),
  ('2 Samuel', 18, 16, 'Joab blew the trumpet, and the people returned from pursuing after Israel; for Joab held the people back.'),
  ('2 Samuel', 18, 17, 'They took Absalom and cast him into a great pit in the forest, and raised over him a very great heap of stones. Then all Israel fled, each to his own tent.'),
  ('2 Samuel', 18, 18, 'Now Absalom in his lifetime had taken and reared up for himself the pillar which is in the king’s valley, for he said, “I have no son to keep my name in memory.” He called the pillar after his own name. It is called Absalom’s monument, to this day.'),
  ('2 Samuel', 18, 19, 'Then Ahimaaz the son of Zadok said, “Let me now run and carry the king news, how the LORD has avenged him of his enemies.”'),
  ('2 Samuel', 18, 20, 'Joab said to him, “You must not be the bearer of news today, but you must carry news another day. But today you must carry no news, because the king’s son is dead.”'),
  ('2 Samuel', 18, 21, 'Then Joab said to the Cushite, “Go, tell the king what you have seen!” The Cushite bowed himself to Joab, and ran.');
INSERT INTO bible_verses (book_name, chapter, verse, text) VALUES
  ('2 Samuel', 18, 22, 'Then Ahimaaz the son of Zadok said yet again to Joab, “But come what may, please let me also run after the Cushite.” Joab said, “Why do you want to run, my son, since you will have no reward for the news?”'),
  ('2 Samuel', 18, 23, '“But come what may,” he said, “I will run.” He said to him, “Run!” Then Ahimaaz ran by the way of the Plain, and outran the Cushite.'),
  ('2 Samuel', 18, 24, 'Now David was sitting between the two gates; and the watchman went up to the roof of the gate to the wall, and lifted up his eyes and looked, and, behold, a man running alone.'),
  ('2 Samuel', 18, 25, 'The watchman shouted and told the king. The king said, “If he is alone, there is news in his mouth.” He came closer and closer.'),
  ('2 Samuel', 18, 26, 'The watchman saw another man running; and the watchman called to the gatekeeper and said, “Behold, a man running alone!” The king said, “He also brings news.”'),
  ('2 Samuel', 18, 27, 'The watchman said, “I think the running of the first one is like the running of Ahimaaz the son of Zadok.” The king said, “He is a good man, and comes with good news.”'),
  ('2 Samuel', 18, 28, 'Ahimaaz called, and said to the king, “All is well.” He bowed himself before the king with his face to the earth, and said, “Blessed is the LORD your God, who has delivered up the men who lifted up their hand against my lord the king!”'),
  ('2 Samuel', 18, 29, 'The king said, “Is it well with the young man Absalom?” Ahimaaz answered, “When Joab sent the king’s servant, even me your servant, I saw a great tumult, but I don’t know what it was.”'),
  ('2 Samuel', 18, 30, 'The king said, “Come and stand here.” He came and stood still.'),
  ('2 Samuel', 18, 31, 'Behold, the Cushite came. The Cushite said, “Good news for my lord the king, for the LORD has avenged you today of all those who rose up against you.”'),
  ('2 Samuel', 18, 32, 'The king said to the Cushite, “Is it well with the young man Absalom?” The Cushite answered, “May the enemies of my lord the king, and all who rise up against you to do you harm, be as that young man is.”'),
  ('2 Samuel', 18, 33, 'The king was much moved, and went up to the room over the gate and wept. As he went, he said, “My son Absalom! My son, my son Absalom! I wish I had died instead of you, Absalom, my son, my son!”'),
  ('2 Samuel', 19, 1, 'Joab was told, “Behold, the king weeps and mourns for Absalom.”'),
  ('2 Samuel', 19, 2, 'The victory that day was turned into mourning among all the people, for the people heard it said that day, “The king grieves for his son.”'),
  ('2 Samuel', 19, 3, 'The people sneaked into the city that day, as people who are ashamed steal away when they flee in battle.'),
  ('2 Samuel', 19, 4, 'The king covered his face, and the king cried with a loud voice, “My son Absalom, Absalom, my son, my son!”'),
  ('2 Samuel', 19, 5, 'Joab came into the house to the king, and said, “Today you have shamed the faces of all your servants who today have saved your life, and the lives of your sons and of your daughters, and the lives of your wives, and the lives of your concubines;'),
  ('2 Samuel', 19, 6, 'in that you love those who hate you and hate those who love you. For you have declared today that princes and servants are nothing to you. For today I perceive that if Absalom had lived and we had all died today, then it would have pleased you well.'),
  ('2 Samuel', 19, 7, 'Now therefore arise, go out and speak to comfort your servants; for I swear by the LORD, if you don’t go out, not a man will stay with you this night. That would be worse to you than all the evil that has happened to you from your youth until now.”'),
  ('2 Samuel', 19, 8, 'Then the king arose and sat in the gate. The people were all told, “Behold, the king is sitting in the gate.” All the people came before the king. Now Israel had fled every man to his tent.'),
  ('2 Samuel', 19, 9, 'All the people were at strife throughout all the tribes of Israel, saying, “The king delivered us out of the hand of our enemies, and he saved us out of the hand of the Philistines; and now he has fled out of the land from Absalom.'),
  ('2 Samuel', 19, 10, 'Absalom, whom we anointed over us, is dead in battle. Now therefore why don’t you speak a word of bringing the king back?”'),
  ('2 Samuel', 19, 11, 'King David sent to Zadok and to Abiathar the priests, saying, “Speak to the elders of Judah, saying, ‘Why are you the last to bring the king back to his house, since the speech of all Israel has come to the king, to return him to his house?'),
  ('2 Samuel', 19, 12, 'You are my brothers. You are my bone and my flesh. Why then are you the last to bring back the king?’'),
  ('2 Samuel', 19, 13, 'Say to Amasa, ‘Aren’t you my bone and my flesh? God do so to me, and more also, if you aren’t captain of the army before me continually instead of Joab.’”'),
  ('2 Samuel', 19, 14, 'He bowed the heart of all the men of Judah, even as one man, so that they sent to the king, saying, “Return, you and all your servants.”'),
  ('2 Samuel', 19, 15, 'So the king returned, and came to the Jordan. Judah came to Gilgal, to go to meet the king, to bring the king over the Jordan.'),
  ('2 Samuel', 19, 16, 'Shimei the son of Gera, the Benjamite, who was of Bahurim, hurried and came down with the men of Judah to meet King David.'),
  ('2 Samuel', 19, 17, 'There were a thousand men of Benjamin with him, and Ziba the servant of Saul’s house, and his fifteen sons and his twenty servants with him; and they went through the Jordan in the presence of the king.'),
  ('2 Samuel', 19, 18, 'A ferry boat went to bring over the king’s household, and to do what he thought good. Shimei the son of Gera fell down before the king when he had come over the Jordan.'),
  ('2 Samuel', 19, 19, 'He said to the king, “Don’t let my lord impute iniquity to me, or remember that which your servant did perversely the day that my lord the king went out of Jerusalem, that the king should take it to his heart.'),
  ('2 Samuel', 19, 20, 'For your servant knows that I have sinned. Therefore behold, I have come today as the first of all the house of Joseph to go down to meet my lord the king.”'),
  ('2 Samuel', 19, 21, 'But Abishai the son of Zeruiah answered, “Shouldn’t Shimei be put to death for this, because he cursed the LORD’s anointed?”'),
  ('2 Samuel', 19, 22, 'David said, “What have I to do with you, you sons of Zeruiah, that you should be adversaries to me today? Shall any man be put to death today in Israel? For don’t I know that I am king over Israel today?”'),
  ('2 Samuel', 19, 23, 'The king said to Shimei, “You will not die.” The king swore to him.'),
  ('2 Samuel', 19, 24, 'Mephibosheth the son of Saul came down to meet the king; and he had neither groomed his feet, nor trimmed his beard, nor washed his clothes, from the day the king departed until the day he came home in peace.'),
  ('2 Samuel', 19, 25, 'When he had come to Jerusalem to meet the king, the king said to him, “Why didn’t you go with me, Mephibosheth?”'),
  ('2 Samuel', 19, 26, 'He answered, “My lord, O king, my servant deceived me. For your servant said, ‘I will saddle a donkey for myself, that I may ride on it and go with the king,’ because your servant is lame.'),
  ('2 Samuel', 19, 27, 'He has slandered your servant to my lord the king, but my lord the king is as an angel of God. Therefore do what is good in your eyes.'),
  ('2 Samuel', 19, 28, 'For all my father’s house were but dead men before my lord the king; yet you set your servant among those who ate at your own table. What right therefore have I yet that I should appeal any more to the king?”'),
  ('2 Samuel', 19, 29, 'The king said to him, “Why do you speak any more of your matters? I say, you and Ziba divide the land.”'),
  ('2 Samuel', 19, 30, 'Mephibosheth said to the king, “Yes, let him take all, because my lord the king has come in peace to his own house.”'),
  ('2 Samuel', 19, 31, 'Barzillai the Gileadite came down from Rogelim; and he went over the Jordan with the king to conduct him over the Jordan.'),
  ('2 Samuel', 19, 32, 'Now Barzillai was a very aged man, even eighty years old. He had provided the king with sustenance while he stayed at Mahanaim, for he was a very great man.'),
  ('2 Samuel', 19, 33, 'The king said to Barzillai, “Come over with me, and I will sustain you with me in Jerusalem.”'),
  ('2 Samuel', 19, 34, 'Barzillai said to the king, “How many are the days of the years of my life, that I should go up with the king to Jerusalem?'),
  ('2 Samuel', 19, 35, 'I am eighty years old, today. Can I discern between good and bad? Can your servant taste what I eat or what I drink? Can I hear the voice of singing men and singing women any more? Why then should your servant be a burden to my lord the king?'),
  ('2 Samuel', 19, 36, 'Your servant will just go over the Jordan with the king. Why should the king repay me with such a reward?'),
  ('2 Samuel', 19, 37, 'Please let your servant turn back again, that I may die in my own city, by the grave of my father and my mother. But behold, your servant Chimham; let him go over with my lord the king; and do to him what shall seem good to you.”'),
  ('2 Samuel', 19, 38, 'The king answered, “Chimham shall go over with me, and I will do to him that which shall seem good to you. Whatever you request of me, that I will do for you.”'),
  ('2 Samuel', 19, 39, 'All the people went over the Jordan, and the king went over. Then the king kissed Barzillai and blessed him; and he returned to his own place.'),
  ('2 Samuel', 19, 40, 'So the king went over to Gilgal, and Chimham went over with him. All the people of Judah brought the king over, and also half the people of Israel.'),
  ('2 Samuel', 19, 41, 'Behold, all the men of Israel came to the king, and said to the king, “Why have our brothers the men of Judah stolen you away, and brought the king and his household, over the Jordan, and all David’s men with him?”'),
  ('2 Samuel', 19, 42, 'All the men of Judah answered the men of Israel, “Because the king is a close relative to us. Why then are you angry about this matter? Have we eaten at all at the king’s cost? Or has he given us any gift?”'),
  ('2 Samuel', 19, 43, 'The men of Israel answered the men of Judah, and said, “We have ten parts in the king, and we have also more claim to David than you. Why then did you despise us, that our advice should not be first had in bringing back our king?” The words of the men of Judah were fiercer than the words of the men of Israel.'),
  ('2 Samuel', 20, 1, 'There happened to be there a wicked fellow, whose name was Sheba the son of Bichri, a Benjamite; and he blew the trumpet, and said, “We have no portion in David, neither have we inheritance in the son of Jesse. Every man to his tents, Israel!”'),
  ('2 Samuel', 20, 2, 'So all the men of Israel went up from following David, and followed Sheba the son of Bichri; but the men of Judah joined with their king, from the Jordan even to Jerusalem.'),
  ('2 Samuel', 20, 3, 'David came to his house at Jerusalem; and the king took the ten women his concubines, whom he had left to keep the house, and put them in custody and provided them with sustenance, but didn’t go in to them. So they were shut up to the day of their death, living in widowhood.'),
  ('2 Samuel', 20, 4, 'Then the king said to Amasa, “Call me the men of Judah together within three days, and be here present.”'),
  ('2 Samuel', 20, 5, 'So Amasa went to call the men of Judah together, but he stayed longer than the set time which had been appointed to him.'),
  ('2 Samuel', 20, 6, 'David said to Abishai, “Now Sheba the son of Bichri will do us more harm than Absalom did. Take your lord’s servants and pursue after him, lest he get himself fortified cities, and escape out of our sight.”'),
  ('2 Samuel', 20, 7, 'Joab’s men went out after him with the Cherethites, the Pelethites, and all the mighty men; and they went out of Jerusalem to pursue Sheba the son of Bichri.'),
  ('2 Samuel', 20, 8, 'When they were at the great stone which is in Gibeon, Amasa came to meet them. Joab was clothed in his apparel of war that he had put on, and on it was a sash with a sword fastened on his waist in its sheath; and as he went along it fell out.'),
  ('2 Samuel', 20, 9, 'Joab said to Amasa, “Is it well with you, my brother?” Joab took Amasa by the beard with his right hand to kiss him.'),
  ('2 Samuel', 20, 10, 'But Amasa took no heed to the sword that was in Joab’s hand. So he struck him with it in the body and shed out his bowels to the ground, and didn’t strike him again; and he died. Joab and Abishai his brother pursued Sheba the son of Bichri.'),
  ('2 Samuel', 20, 11, 'One of Joab’s young men stood by him, and said, “He who favors Joab, and he who is for David, let him follow Joab!”'),
  ('2 Samuel', 20, 12, 'Amasa lay wallowing in his blood in the middle of the highway. When the man saw that all the people stood still, he carried Amasa out of the highway into the field, and cast a garment over him when he saw that everyone who came by him stood still.'),
  ('2 Samuel', 20, 13, 'When he was removed out of the highway, all the people went on after Joab to pursue Sheba the son of Bichri.'),
  ('2 Samuel', 20, 14, 'He went through all the tribes of Israel to Abel, to Beth Maacah, and all the Berites. They were gathered together, and went also after him.'),
  ('2 Samuel', 20, 15, 'They came and besieged him in Abel of Beth Maacah, and they cast up a mound against the city, and it stood against the rampart; and all the people who were with Joab battered the wall to throw it down.'),
  ('2 Samuel', 20, 16, 'Then a wise woman cried out of the city, “Hear, hear! Please say to Joab, ‘Come near here, that I may speak with you.’”'),
  ('2 Samuel', 20, 17, 'He came near to her; and the woman said, “Are you Joab?” He answered, “I am.” Then she said to him, “Hear the words of your servant.” He answered, “I’m listening.”'),
  ('2 Samuel', 20, 18, 'Then she spoke, saying, “They used to say in old times, ‘They shall surely ask counsel at Abel,’ and so they settled a matter.'),
  ('2 Samuel', 20, 19, 'I am among those who are peaceable and faithful in Israel. You seek to destroy a city and a mother in Israel. Why will you swallow up the LORD’s inheritance?”'),
  ('2 Samuel', 20, 20, 'Joab answered, “Far be it, far be it from me, that I should swallow up or destroy.'),
  ('2 Samuel', 20, 21, 'The matter is not so. But a man of the hill country of Ephraim, Sheba the son of Bichri by name, has lifted up his hand against the king, even against David. Just deliver him, and I will depart from the city.” The woman said to Joab, “Behold, his head will be thrown to you over the wall.”'),
  ('2 Samuel', 20, 22, 'Then the woman went to all the people in her wisdom. They cut off the head of Sheba the son of Bichri, and threw it out to Joab. He blew the trumpet, and they were dispersed from the city, every man to his tent. Then Joab returned to Jerusalem to the king.'),
  ('2 Samuel', 20, 23, 'Now Joab was over all the army of Israel, Benaiah the son of Jehoiada was over the Cherethites and over the Pelethites,'),
  ('2 Samuel', 20, 24, 'Adoram was over the men subject to forced labor, Jehoshaphat the son of Ahilud was the recorder,'),
  ('2 Samuel', 20, 25, 'Sheva was scribe, Zadok and Abiathar were priests,'),
  ('2 Samuel', 20, 26, 'and Ira the Jairite was chief minister to David.'),
  ('2 Samuel', 21, 1, 'There was a famine in the days of David for three years, year after year; and David sought the face of the LORD. The LORD said, “It is for Saul, and for his bloody house, because he put the Gibeonites to death.”'),
  ('2 Samuel', 21, 2, 'The king called the Gibeonites and said to them (now the Gibeonites were not of the children of Israel, but of the remnant of the Amorites, and the children of Israel had sworn to them; and Saul sought to kill them in his zeal for the children of Israel and Judah);'),
  ('2 Samuel', 21, 3, 'and David said to the Gibeonites, “What should I do for you? And with what should I make atonement, that you may bless the LORD’s inheritance?”'),
  ('2 Samuel', 21, 4, 'The Gibeonites said to him, “It is no matter of silver or gold between us and Saul or his house; neither is it for us to put any man to death in Israel.” He said, “I will do for you whatever you say.”'),
  ('2 Samuel', 21, 5, 'They said to the king, “The man who consumed us and who plotted against us, that we should be destroyed from remaining in any of the borders of Israel,'),
  ('2 Samuel', 21, 6, 'let seven men of his sons be delivered to us, and we will hang them up to the LORD in Gibeah of Saul, the chosen of the LORD.” The king said, “I will give them.”'),
  ('2 Samuel', 21, 7, 'But the king spared Mephibosheth the son of Jonathan the son of Saul, because of the LORD’s oath that was between them, between David and Jonathan the son of Saul.'),
  ('2 Samuel', 21, 8, 'But the king took the two sons of Rizpah the daughter of Aiah, whom she bore to Saul, Armoni and Mephibosheth; and the five sons of Merab the daughter of Saul, whom she bore to Adriel the son of Barzillai the Meholathite.'),
  ('2 Samuel', 21, 9, 'He delivered them into the hands of the Gibeonites; and they hanged them on the mountain before the LORD, and all seven of them fell together. They were put to death in the days of harvest, in the first days, at the beginning of barley harvest.'),
  ('2 Samuel', 21, 10, 'Rizpah the daughter of Aiah took sackcloth and spread it for herself on the rock, from the beginning of harvest until water poured on them from the sky. She allowed neither the birds of the sky to rest on them by day, nor the animals of the field by night.'),
  ('2 Samuel', 21, 11, 'David was told what Rizpah the daughter of Aiah, the concubine of Saul, had done.'),
  ('2 Samuel', 21, 12, 'So David went and took the bones of Saul and the bones of Jonathan his son from the men of Jabesh Gilead, who had stolen them from the street of Beth Shan, where the Philistines had hanged them in the day that the Philistines killed Saul in Gilboa;'),
  ('2 Samuel', 21, 13, 'and he brought up from there the bones of Saul and the bones of Jonathan his son. They also gathered the bones of those who were hanged.'),
  ('2 Samuel', 21, 14, 'They buried the bones of Saul and Jonathan his son in the country of Benjamin in Zela, in the tomb of Kish his father; and they performed all that the king commanded. After that, God answered prayer for the land.'),
  ('2 Samuel', 21, 15, 'The Philistines had war again with Israel; and David went down, and his servants with him, and fought against the Philistines. David grew faint;'),
  ('2 Samuel', 21, 16, 'and Ishbibenob, who was of the sons of the giant, the weight of whose spear was three hundred shekels of bronze in weight, he being armed with a new sword, thought he would kill David.'),
  ('2 Samuel', 21, 17, 'But Abishai the son of Zeruiah helped him, and struck the Philistine and killed him. Then the men of David swore to him, saying, “Don’t go out with us to battle any more, so that you don’t quench the lamp of Israel.”'),
  ('2 Samuel', 21, 18, 'After this, there was again war with the Philistines at Gob. Then Sibbecai the Hushathite killed Saph, who was of the sons of the giant.'),
  ('2 Samuel', 21, 19, 'There was again war with the Philistines at Gob, and Elhanan the son of Jaare-Oregim the Bethlehemite killed Goliath the Gittite’s brother, the staff of whose spear was like a weaver’s beam.');
INSERT INTO bible_verses (book_name, chapter, verse, text) VALUES
  ('2 Samuel', 21, 20, 'There was again war at Gath, where there was a man of great stature, who had six fingers on every hand and six toes on every foot, twenty-four in number, and he also was born to the giant.'),
  ('2 Samuel', 21, 21, 'When he defied Israel, Jonathan the son of Shimei, David’s brother, killed him.'),
  ('2 Samuel', 21, 22, 'These four were born to the giant in Gath; and they fell by the hand of David and by the hand of his servants.'),
  ('2 Samuel', 22, 1, 'David spoke to the LORD the words of this song in the day that the LORD delivered him out of the hand of all his enemies, and out of the hand of Saul,'),
  ('2 Samuel', 22, 2, 'and he said: “The LORD is my rock, my fortress, and my deliverer, even mine;'),
  ('2 Samuel', 22, 3, 'God is my rock in whom I take refuge; my shield, and the horn of my salvation, my high tower, and my refuge. My savior, you save me from violence.'),
  ('2 Samuel', 22, 4, 'I call on the LORD, who is worthy to be praised; So shall I be saved from my enemies.'),
  ('2 Samuel', 22, 5, 'For the waves of death surrounded me. The floods of ungodliness made me afraid.'),
  ('2 Samuel', 22, 6, 'The cords of Sheol were around me. The snares of death caught me.'),
  ('2 Samuel', 22, 7, 'In my distress, I called on the LORD. Yes, I called to my God. He heard my voice out of his temple. My cry came into his ears.'),
  ('2 Samuel', 22, 8, 'Then the earth shook and trembled. The foundations of heaven quaked and were shaken, because he was angry.'),
  ('2 Samuel', 22, 9, 'Smoke went up out of his nostrils. Consuming fire came out of his mouth. Coals were kindled by it.'),
  ('2 Samuel', 22, 10, 'He bowed the heavens also, and came down. Thick darkness was under his feet.'),
  ('2 Samuel', 22, 11, 'He rode on a cherub, and flew. Yes, he was seen on the wings of the wind.'),
  ('2 Samuel', 22, 12, 'He made darkness a shelter around himself, gathering of waters, and thick clouds of the skies.'),
  ('2 Samuel', 22, 13, 'At the brightness before him, coals of fire were kindled.'),
  ('2 Samuel', 22, 14, 'The LORD thundered from heaven. The Most High uttered his voice.'),
  ('2 Samuel', 22, 15, 'He sent out arrows and scattered them, lightning and confused them.'),
  ('2 Samuel', 22, 16, 'Then the channels of the sea appeared. The foundations of the world were laid bare by the LORD’s rebuke, at the blast of the breath of his nostrils.'),
  ('2 Samuel', 22, 17, 'He sent from on high and he took me. He drew me out of many waters.'),
  ('2 Samuel', 22, 18, 'He delivered me from my strong enemy, from those who hated me, for they were too mighty for me.'),
  ('2 Samuel', 22, 19, 'They came on me in the day of my calamity, but the LORD was my support.'),
  ('2 Samuel', 22, 20, 'He also brought me out into a large place. He delivered me, because he delighted in me.'),
  ('2 Samuel', 22, 21, 'The LORD rewarded me according to my righteousness. He rewarded me according to the cleanness of my hands.'),
  ('2 Samuel', 22, 22, 'For I have kept the LORD’s ways, and have not wickedly departed from my God.'),
  ('2 Samuel', 22, 23, 'For all his ordinances were before me. As for his statutes, I didn’t depart from them.'),
  ('2 Samuel', 22, 24, 'I was also perfect toward him. I kept myself from my iniquity.'),
  ('2 Samuel', 22, 25, 'Therefore the LORD has rewarded me according to my righteousness, According to my cleanness in his eyesight.'),
  ('2 Samuel', 22, 26, 'With the merciful you will show yourself merciful. With the perfect man you will show yourself perfect.'),
  ('2 Samuel', 22, 27, 'With the pure you will show yourself pure. With the crooked you will show yourself shrewd.'),
  ('2 Samuel', 22, 28, 'You will save the afflicted people, but your eyes are on the arrogant, that you may bring them down.'),
  ('2 Samuel', 22, 29, 'For you are my lamp, LORD. The LORD will light up my darkness.'),
  ('2 Samuel', 22, 30, 'For by you, I run against a troop. By my God, I leap over a wall.'),
  ('2 Samuel', 22, 31, 'As for God, his way is perfect. The LORD’s word is tested. He is a shield to all those who take refuge in him.'),
  ('2 Samuel', 22, 32, 'For who is God, besides the LORD? Who is a rock, besides our God?'),
  ('2 Samuel', 22, 33, 'God is my strong fortress. He makes my way perfect.'),
  ('2 Samuel', 22, 34, 'He makes his feet like hinds’ feet, and sets me on my high places.'),
  ('2 Samuel', 22, 35, 'He teaches my hands to war, so that my arms bend a bow of bronze.'),
  ('2 Samuel', 22, 36, 'You have also given me the shield of your salvation. Your gentleness has made me great.'),
  ('2 Samuel', 22, 37, 'You have enlarged my steps under me. My feet have not slipped.'),
  ('2 Samuel', 22, 38, 'I have pursued my enemies and destroyed them. I didn’t turn again until they were consumed.'),
  ('2 Samuel', 22, 39, 'I have consumed them, and struck them through, so that they can’t arise. Yes, they have fallen under my feet.'),
  ('2 Samuel', 22, 40, 'For you have armed me with strength for the battle. You have subdued under me those who rose up against me.'),
  ('2 Samuel', 22, 41, 'You have also made my enemies turn their backs to me, that I might cut off those who hate me.'),
  ('2 Samuel', 22, 42, 'They looked, but there was no one to save; even to the LORD, but he didn’t answer them.'),
  ('2 Samuel', 22, 43, 'Then I beat them as small as the dust of the earth. I crushed them as the mire of the streets, and spread them abroad.'),
  ('2 Samuel', 22, 44, 'You also have delivered me from the strivings of my people. You have kept me to be the head of the nations. A people whom I have not known will serve me.'),
  ('2 Samuel', 22, 45, 'The foreigners will submit themselves to me. As soon as they hear of me, they will obey me.'),
  ('2 Samuel', 22, 46, 'The foreigners will fade away, and will come trembling out of their close places.'),
  ('2 Samuel', 22, 47, 'The LORD lives! Blessed be my rock! Exalted be God, the rock of my salvation,'),
  ('2 Samuel', 22, 48, 'even the God who executes vengeance for me, who brings down peoples under me,'),
  ('2 Samuel', 22, 49, 'who brings me away from my enemies. Yes, you lift me up above those who rise up against me. You deliver me from the violent man.'),
  ('2 Samuel', 22, 50, 'Therefore I will give thanks to you, LORD, among the nations, and will sing praises to your name.'),
  ('2 Samuel', 22, 51, 'He gives great deliverance to his king, and shows loving kindness to his anointed, to David and to his offspring, forever more.”'),
  ('2 Samuel', 23, 1, 'Now these are the last words of David. David the son of Jesse says, the man who was raised on high says, the anointed of the God of Jacob, the sweet psalmist of Israel:'),
  ('2 Samuel', 23, 2, '“The LORD’s Spirit spoke by me. His word was on my tongue.'),
  ('2 Samuel', 23, 3, 'The God of Israel said, the Rock of Israel spoke to me, ‘One who rules over men righteously, who rules in the fear of God,'),
  ('2 Samuel', 23, 4, 'shall be as the light of the morning when the sun rises, a morning without clouds, when the tender grass springs out of the earth, through clear shining after rain.’'),
  ('2 Samuel', 23, 5, 'Isn’t my house so with God? Yet he has made with me an everlasting covenant, ordered in all things, and sure, for it is all my salvation and all my desire. Won’t he make it grow?'),
  ('2 Samuel', 23, 6, 'But all the ungodly will be as thorns to be thrust away, because they can’t be taken with the hand.'),
  ('2 Samuel', 23, 7, 'The man who touches them must be armed with iron and the staff of a spear. They will be utterly burned with fire in their place.”'),
  ('2 Samuel', 23, 8, 'These are the names of the mighty men whom David had: Josheb Basshebeth a Tahchemonite, chief of the captains; he was called Adino the Eznite, who killed eight hundred at one time.'),
  ('2 Samuel', 23, 9, 'After him was Eleazar the son of Dodai the son of an Ahohite, one of the three mighty men with David when they defied the Philistines who were there gathered together to battle, and the men of Israel had gone away.'),
  ('2 Samuel', 23, 10, 'He arose and struck the Philistines until his hand was weary, and his hand froze to the sword; and the LORD worked a great victory that day; and the people returned after him only to take plunder.'),
  ('2 Samuel', 23, 11, 'After him was Shammah the son of Agee a Hararite. The Philistines had gathered together into a troop where there was a plot of ground full of lentils; and the people fled from the Philistines.'),
  ('2 Samuel', 23, 12, 'But he stood in the middle of the plot and defended it, and killed the Philistines; and the LORD worked a great victory.'),
  ('2 Samuel', 23, 13, 'Three of the thirty chief men went down, and came to David in the harvest time to the cave of Adullam; and the troop of the Philistines was encamped in the valley of Rephaim.'),
  ('2 Samuel', 23, 14, 'David was then in the stronghold; and the garrison of the Philistines was then in Bethlehem.'),
  ('2 Samuel', 23, 15, 'David said longingly, “Oh that someone would give me water to drink from the well of Bethlehem, which is by the gate!”'),
  ('2 Samuel', 23, 16, 'The three mighty men broke through the army of the Philistines, and drew water out of the well of Bethlehem that was by the gate and took it and brought it to David; but he would not drink of it, but poured it out to the LORD.'),
  ('2 Samuel', 23, 17, 'He said, “Be it far from me, LORD, that I should do this! Isn’t this the blood of the men who risked their lives to go?” Therefore he would not drink it. The three mighty men did these things.'),
  ('2 Samuel', 23, 18, 'Abishai, the brother of Joab, the son of Zeruiah, was chief of the three. He lifted up his spear against three hundred and killed them, and had a name among the three.'),
  ('2 Samuel', 23, 19, 'Wasn’t he most honorable of the three? Therefore he was made their captain. However he wasn’t included as one of the three.'),
  ('2 Samuel', 23, 20, 'Benaiah the son of Jehoiada, the son of a valiant man of Kabzeel, who had done mighty deeds, killed the two sons of Ariel of Moab. He also went down and killed a lion in the middle of a pit in a time of snow.'),
  ('2 Samuel', 23, 21, 'He killed a huge Egyptian, and the Egyptian had a spear in his hand; but he went down to him with a staff and plucked the spear out of the Egyptian’s hand, and killed him with his own spear.'),
  ('2 Samuel', 23, 22, 'Benaiah the son of Jehoiada did these things, and had a name among the three mighty men.'),
  ('2 Samuel', 23, 23, 'He was more honorable than the thirty, but he didn’t attain to the three. David set him over his guard.'),
  ('2 Samuel', 23, 24, 'Asahel the brother of Joab was one of the thirty: Elhanan the son of Dodo of Bethlehem,'),
  ('2 Samuel', 23, 25, 'Shammah the Harodite, Elika the Harodite,'),
  ('2 Samuel', 23, 26, 'Helez the Paltite, Ira the son of Ikkesh the Tekoite,'),
  ('2 Samuel', 23, 27, 'Abiezer the Anathothite, Mebunnai the Hushathite,'),
  ('2 Samuel', 23, 28, 'Zalmon the Ahohite, Maharai the Netophathite,'),
  ('2 Samuel', 23, 29, 'Heleb the son of Baanah the Netophathite, Ittai the son of Ribai of Gibeah of the children of Benjamin,'),
  ('2 Samuel', 23, 30, 'Benaiah a Pirathonite, Hiddai of the brooks of Gaash.'),
  ('2 Samuel', 23, 31, 'Abialbon the Arbathite, Azmaveth the Barhumite,'),
  ('2 Samuel', 23, 32, 'Eliahba the Shaalbonite, the sons of Jashen, Jonathan,'),
  ('2 Samuel', 23, 33, 'Shammah the Hararite, Ahiam the son of Sharar the Ararite,'),
  ('2 Samuel', 23, 34, 'Eliphelet the son of Ahasbai, the son of the Maacathite, Eliam the son of Ahithophel the Gilonite,'),
  ('2 Samuel', 23, 35, 'Hezro the Carmelite, Paarai the Arbite,'),
  ('2 Samuel', 23, 36, 'Igal the son of Nathan of Zobah, Bani the Gadite,'),
  ('2 Samuel', 23, 37, 'Zelek the Ammonite, Naharai the Beerothite, armor bearers to Joab the son of Zeruiah,'),
  ('2 Samuel', 23, 38, 'Ira the Ithrite, Gareb the Ithrite,'),
  ('2 Samuel', 23, 39, 'and Uriah the Hittite: thirty-seven in all.'),
  ('2 Samuel', 24, 1, 'Again the LORD’s anger burned against Israel, and he moved David against them, saying, “Go, count Israel and Judah.”'),
  ('2 Samuel', 24, 2, 'The king said to Joab the captain of the army, who was with him, “Now go back and forth through all the tribes of Israel, from Dan even to Beersheba, and count the people, that I may know the sum of the people.”'),
  ('2 Samuel', 24, 3, 'Joab said to the king, “Now may the LORD your God add to the people, however many they may be, one hundred times; and may the eyes of my lord the king see it. But why does my lord the king delight in this thing?”'),
  ('2 Samuel', 24, 4, 'Notwithstanding, the king’s word prevailed against Joab and against the captains of the army. Joab and the captains of the army went out from the presence of the king to count the people of Israel.'),
  ('2 Samuel', 24, 5, 'They passed over the Jordan and encamped in Aroer, on the right side of the city that is in the middle of the valley of Gad, and to Jazer;'),
  ('2 Samuel', 24, 6, 'then they came to Gilead and to the land of Tahtim Hodshi; and they came to Dan Jaan and around to Sidon,'),
  ('2 Samuel', 24, 7, 'and came to the stronghold of Tyre, and to all the cities of the Hivites and of the Canaanites; and they went out to the south of Judah, at Beersheba.');
INSERT INTO bible_verses (book_name, chapter, verse, text) VALUES
  ('2 Samuel', 24, 8, 'So when they had gone back and forth through all the land, they came to Jerusalem at the end of nine months and twenty days.'),
  ('2 Samuel', 24, 9, 'Joab gave up the sum of the counting of the people to the king; and there were in Israel eight hundred thousand valiant men who drew the sword, and the men of Judah were five hundred thousand men.'),
  ('2 Samuel', 24, 10, 'David’s heart struck him after he had counted the people. David said to the LORD, “I have sinned greatly in that which I have done. But now, the LORD, put away, I beg you, the iniquity of your servant; for I have done very foolishly.”'),
  ('2 Samuel', 24, 11, 'When David rose up in the morning, the LORD’s word came to the prophet Gad, David’s seer, saying,'),
  ('2 Samuel', 24, 12, '“Go and speak to David, ‘The LORD says, “I offer you three things. Choose one of them, that I may do it to you.”’”'),
  ('2 Samuel', 24, 13, 'So Gad came to David, and told him, saying, “Shall seven years of famine come to you in your land? Or will you flee three months before your foes while they pursue you? Or shall there be three days’ pestilence in your land? Now answer, and consider what answer I shall return to him who sent me.”'),
  ('2 Samuel', 24, 14, 'David said to Gad, “I am in distress. Let us fall now into the LORD’s hand, for his mercies are great. Let me not fall into man’s hand.”'),
  ('2 Samuel', 24, 15, 'So the LORD sent a pestilence on Israel from the morning even to the appointed time; and seventy thousand men died of the people from Dan even to Beersheba.'),
  ('2 Samuel', 24, 16, 'When the angel stretched out his hand toward Jerusalem to destroy it, the LORD relented of the disaster, and said to the angel who destroyed the people, “It is enough. Now withdraw your hand.” The LORD’s angel was by the threshing floor of Araunah the Jebusite.'),
  ('2 Samuel', 24, 17, 'David spoke to the LORD when he saw the angel who struck the people, and said, “Behold, I have sinned, and I have done perversely; but these sheep, what have they done? Please let your hand be against me, and against my father’s house.”'),
  ('2 Samuel', 24, 18, 'Gad came that day to David and said to him, “Go up, build an altar to the LORD on the threshing floor of Araunah the Jebusite.”'),
  ('2 Samuel', 24, 19, 'David went up according to the saying of Gad, as the LORD commanded.'),
  ('2 Samuel', 24, 20, 'Araunah looked out, and saw the king and his servants coming on toward him. Then Araunah went out and bowed himself before the king with his face to the ground.'),
  ('2 Samuel', 24, 21, 'Araunah said, “Why has my lord the king come to his servant?” David said, “To buy your threshing floor, to build an altar to the LORD, that the plague may be stopped from afflicting the people.”'),
  ('2 Samuel', 24, 22, 'Araunah said to David, “Let my lord the king take and offer up what seems good to him. Behold, the cattle for the burnt offering, and the threshing sledges and the yokes of the oxen for the wood.'),
  ('2 Samuel', 24, 23, 'All this, O king, does Araunah give to the king.” Araunah said to the king, “May the LORD your God accept you.”'),
  ('2 Samuel', 24, 24, 'The king said to Araunah, “No, but I will most certainly buy it from you for a price. I will not offer burnt offerings to the LORD my God which cost me nothing.” So David bought the threshing floor and the oxen for fifty shekels of silver.'),
  ('2 Samuel', 24, 25, 'David built an altar to the LORD there, and offered burnt offerings and peace offerings. So the LORD was entreated for the land, and the plague was removed from Israel.'),
  ('1 Kings', 1, 1, 'Now King David was old and advanced in years; and they covered him with clothes, but he couldn’t keep warm.'),
  ('1 Kings', 1, 2, 'Therefore his servants said to him, “Let a young virgin be sought for my lord the king. Let her stand before the king, and cherish him; and let her lie in your bosom, that my lord the king may keep warm.”'),
  ('1 Kings', 1, 3, 'So they sought for a beautiful young lady throughout all the borders of Israel, and found Abishag the Shunammite, and brought her to the king.'),
  ('1 Kings', 1, 4, 'The young lady was very beautiful; and she cherished the king, and served him; but the king didn’t know her intimately.'),
  ('1 Kings', 1, 5, 'Then Adonijah the son of Haggith exalted himself, saying, “I will be king.” Then he prepared him chariots and horsemen, and fifty men to run before him.'),
  ('1 Kings', 1, 6, 'His father had not displeased him at any time in saying, “Why have you done so?” and he was also a very handsome man; and he was born after Absalom.'),
  ('1 Kings', 1, 7, 'He conferred with Joab the son of Zeruiah and with Abiathar the priest; and they followed Adonijah and helped him.'),
  ('1 Kings', 1, 8, 'But Zadok the priest, Benaiah the son of Jehoiada, Nathan the prophet, Shimei, Rei, and the mighty men who belonged to David, were not with Adonijah.'),
  ('1 Kings', 1, 9, 'Adonijah killed sheep, cattle, and fatlings by the stone of Zoheleth, which is beside En Rogel; and he called all his brothers, the king’s sons, and all the men of Judah, the king’s servants;'),
  ('1 Kings', 1, 10, 'but he didn’t call Nathan the prophet, and Benaiah, and the mighty men, and Solomon his brother.'),
  ('1 Kings', 1, 11, 'Then Nathan spoke to Bathsheba the mother of Solomon, saying, “Haven’t you heard that Adonijah the son of Haggith reigns, and David our lord doesn’t know it?'),
  ('1 Kings', 1, 12, 'Now therefore come, please let me give you counsel, that you may save your own life and your son Solomon’s life.'),
  ('1 Kings', 1, 13, 'Go in to King David, and tell him, ‘Didn’t you, my lord the king, swear to your servant, saying, “Assuredly Solomon your son shall reign after me, and he shall sit on my throne”? Why then does Adonijah reign?’'),
  ('1 Kings', 1, 14, 'Behold, while you are still talking there with the king, I will also come in after you and confirm your words.”'),
  ('1 Kings', 1, 15, 'Bathsheba went in to the king in his room. The king was very old; and Abishag the Shunammite was serving the king.'),
  ('1 Kings', 1, 16, 'Bathsheba bowed and showed respect to the king. The king said, “What would you like?”'),
  ('1 Kings', 1, 17, 'She said to him, “My lord, you swore by the LORD your God to your servant, ‘Assuredly Solomon your son shall reign after me, and he shall sit on my throne.’'),
  ('1 Kings', 1, 18, 'Now, behold, Adonijah reigns; and you, my lord the king, don’t know it.'),
  ('1 Kings', 1, 19, 'He has slain cattle and fatlings and sheep in abundance, and has called all the sons of the king, Abiathar the priest, and Joab the captain of the army; but he hasn’t called Solomon your servant.'),
  ('1 Kings', 1, 20, 'You, my lord the king, the eyes of all Israel are on you, that you should tell them who will sit on the throne of my lord the king after him.'),
  ('1 Kings', 1, 21, 'Otherwise it will happen, when my lord the king sleeps with his fathers, that I and my son Solomon will be considered criminals.”'),
  ('1 Kings', 1, 22, 'Behold, while she was still talking with the king, Nathan the prophet came in.'),
  ('1 Kings', 1, 23, 'They told the king, saying, “Behold, Nathan the prophet!” When he had come in before the king, he bowed himself before the king with his face to the ground.'),
  ('1 Kings', 1, 24, 'Nathan said, “My lord, King, have you said, ‘Adonijah shall reign after me, and he shall sit on my throne’?'),
  ('1 Kings', 1, 25, 'For he has gone down today, and has slain cattle, fatlings, and sheep in abundance, and has called all the king’s sons, the captains of the army, and Abiathar the priest. Behold, they are eating and drinking before him, and saying, ‘Long live King Adonijah!’'),
  ('1 Kings', 1, 26, 'But he hasn’t called me, even me your servant, Zadok the priest, Benaiah the son of Jehoiada, and your servant Solomon.'),
  ('1 Kings', 1, 27, 'Was this thing done by my lord the king, and you haven’t shown to your servants who should sit on the throne of my lord the king after him?”'),
  ('1 Kings', 1, 28, 'Then King David answered, “Call Bathsheba in to me.” She came into the king’s presence and stood before the king.'),
  ('1 Kings', 1, 29, 'The king vowed and said, “As the LORD lives, who has redeemed my soul out of all adversity,'),
  ('1 Kings', 1, 30, 'most certainly as I swore to you by the LORD, the God of Israel, saying, ‘Assuredly Solomon your son shall reign after me, and he shall sit on my throne in my place;’ I will most certainly do this today.”'),
  ('1 Kings', 1, 31, 'Then Bathsheba bowed with her face to the earth and showed respect to the king, and said, “Let my lord King David live forever!”'),
  ('1 Kings', 1, 32, 'King David said, “Call to me Zadok the priest, Nathan the prophet, and Benaiah the son of Jehoiada.” They came before the king.'),
  ('1 Kings', 1, 33, 'The king said to them, “Take with you the servants of your lord, and cause Solomon my son to ride on my own mule, and bring him down to Gihon.'),
  ('1 Kings', 1, 34, 'Let Zadok the priest and Nathan the prophet anoint him there king over Israel. Blow the trumpet, and say, ‘Long live King Solomon!’'),
  ('1 Kings', 1, 35, 'Then come up after him, and he shall come and sit on my throne; for he shall be king in my place. I have appointed him to be prince over Israel and over Judah.”'),
  ('1 Kings', 1, 36, 'Benaiah the son of Jehoiada answered the king, and said, “Amen. May the LORD, the God of my lord the king, say so.'),
  ('1 Kings', 1, 37, 'As the LORD has been with my lord the king, even so may he be with Solomon, and make his throne greater than the throne of my lord King David.”'),
  ('1 Kings', 1, 38, 'So Zadok the priest, Nathan the prophet, Benaiah the son of Jehoiada, and the Cherethites and the Pelethites went down and had Solomon ride on King David’s mule, and brought him to Gihon.'),
  ('1 Kings', 1, 39, 'Zadok the priest took the horn of oil from the Tent, and anointed Solomon. They blew the trumpet; and all the people said, “Long live King Solomon!”'),
  ('1 Kings', 1, 40, 'All the people came up after him, and the people piped with pipes, and rejoiced with great joy, so that the earth shook with their sound.'),
  ('1 Kings', 1, 41, 'Adonijah and all the guests who were with him heard it as they had finished eating. When Joab heard the sound of the trumpet, he said, “Why is this noise of the city being in an uproar?”'),
  ('1 Kings', 1, 42, 'While he yet spoke, behold, Jonathan the son of Abiathar the priest came; and Adonijah said, “Come in; for you are a worthy man, and bring good news.”'),
  ('1 Kings', 1, 43, 'Jonathan answered Adonijah, “Most certainly our lord King David has made Solomon king.'),
  ('1 Kings', 1, 44, 'The king has sent with him Zadok the priest, Nathan the prophet, Benaiah the son of Jehoiada, and the Cherethites and the Pelethites; and they have caused him to ride on the king’s mule.'),
  ('1 Kings', 1, 45, 'Zadok the priest and Nathan the prophet have anointed him king in Gihon. They have come up from there rejoicing, so that the city rang again. This is the noise that you have heard.'),
  ('1 Kings', 1, 46, 'Also, Solomon sits on the throne of the kingdom.'),
  ('1 Kings', 1, 47, 'Moreover the king’s servants came to bless our lord King David, saying, ‘May your God make the name of Solomon better than your name, and make his throne greater than your throne;’ and the king bowed himself on the bed.'),
  ('1 Kings', 1, 48, 'Also thus said the king, ‘Blessed be the LORD, the God of Israel, who has given one to sit on my throne today, my eyes even seeing it.’”'),
  ('1 Kings', 1, 49, 'All the guests of Adonijah were afraid, and rose up, and each man went his way.'),
  ('1 Kings', 1, 50, 'Adonijah was afraid because of Solomon; and he arose, and went, and hung onto the horns of the altar.'),
  ('1 Kings', 1, 51, 'Solomon was told, “Behold, Adonijah fears King Solomon; for, behold, he is hanging onto the horns of the altar, saying, ‘Let King Solomon swear to me first that he will not kill his servant with the sword.’”'),
  ('1 Kings', 1, 52, 'Solomon said, “If he shows himself a worthy man, not a hair of his shall fall to the earth; but if wickedness is found in him, he shall die.”'),
  ('1 Kings', 1, 53, 'So King Solomon sent, and they brought him down from the altar. He came and bowed down to King Solomon; and Solomon said to him, “Go to your house.”'),
  ('1 Kings', 2, 1, 'Now the days of David came near that he should die; and he commanded Solomon his son, saying,'),
  ('1 Kings', 2, 2, '“I am going the way of all the earth. You be strong therefore, and show yourself a man;'),
  ('1 Kings', 2, 3, 'and keep the instruction of the LORD your God, to walk in his ways, to keep his statutes, his commandments, his ordinances, and his testimonies, according to that which is written in the law of Moses, that you may prosper in all that you do and wherever you turn yourself.'),
  ('1 Kings', 2, 4, 'Then the LORD may establish his word which he spoke concerning me, saying, ‘If your children are careful of their way, to walk before me in truth with all their heart and with all their soul, there shall not fail you,’ he said, ‘a man on the throne of Israel.’'),
  ('1 Kings', 2, 5, '“Moreover you know also what Joab the son of Zeruiah did to me, even what he did to the two captains of the armies of Israel, to Abner the son of Ner and to Amasa the son of Jether, whom he killed, and shed the blood of war in peace, and put the blood of war on his sash that was around his waist and in his sandals that were on his feet.'),
  ('1 Kings', 2, 6, 'Do therefore according to your wisdom, and don’t let his gray head go down to Sheol in peace.'),
  ('1 Kings', 2, 7, 'But show kindness to the sons of Barzillai the Gileadite, and let them be among those who eat at your table; for so they came to me when I fled from Absalom your brother.'),
  ('1 Kings', 2, 8, '“Behold, there is with you Shimei the son of Gera, the Benjamite of Bahurim, who cursed me with a grievous curse in the day when I went to Mahanaim; but he came down to meet me at the Jordan, and I swore to him by the LORD, saying, ‘I will not put you to death with the sword.’'),
  ('1 Kings', 2, 9, 'Now therefore don’t hold him guiltless, for you are a wise man; and you will know what you ought to do to him, and you shall bring his gray head down to Sheol with blood.”'),
  ('1 Kings', 2, 10, 'David slept with his fathers, and was buried in David’s city.'),
  ('1 Kings', 2, 11, 'The days that David reigned over Israel were forty years; he reigned seven years in Hebron, and he reigned thirty-three years in Jerusalem.'),
  ('1 Kings', 2, 12, 'Solomon sat on David his father’s throne; and his kingdom was firmly established.'),
  ('1 Kings', 2, 13, 'Then Adonijah the son of Haggith came to Bathsheba the mother of Solomon. She said, “Do you come peaceably?” He said, “Peaceably.'),
  ('1 Kings', 2, 14, 'He said moreover, I have something to tell you.” She said, “Say on.”'),
  ('1 Kings', 2, 15, 'He said, “You know that the kingdom was mine, and that all Israel set their faces on me, that I should reign. However, the kingdom is turned around, and has become my brother’s; for it was his from the LORD.'),
  ('1 Kings', 2, 16, 'Now I ask one petition of you. Don’t deny me.” She said to him, “Say on.”'),
  ('1 Kings', 2, 17, 'He said, “Please speak to Solomon the king (for he will not tell you ‘no’), that he give me Abishag the Shunammite as wife.”'),
  ('1 Kings', 2, 18, 'Bathsheba said, “All right. I will speak for you to the king.”'),
  ('1 Kings', 2, 19, 'Bathsheba therefore went to King Solomon, to speak to him for Adonijah. The king rose up to meet her and bowed himself to her, and sat down on his throne and caused a throne to be set for the king’s mother; and she sat on his right hand.'),
  ('1 Kings', 2, 20, 'Then she said, “I ask one small petition of you; don’t deny me.” The king said to her, “Ask on, my mother, for I will not deny you.”'),
  ('1 Kings', 2, 21, 'She said, “Let Abishag the Shunammite be given to Adonijah your brother as wife.”'),
  ('1 Kings', 2, 22, 'King Solomon answered his mother, “Why do you ask Abishag the Shunammite for Adonijah? Ask for him the kingdom also, for he is my elder brother; even for him, and for Abiathar the priest, and for Joab the son of Zeruiah.”'),
  ('1 Kings', 2, 23, 'Then King Solomon swore by the LORD, saying, “God do so to me, and more also, if Adonijah has not spoken this word against his own life.'),
  ('1 Kings', 2, 24, 'Now therefore as the LORD lives, who has established me and set me on my father David’s throne, and who has made me a house as he promised, surely Adonijah shall be put to death today.”'),
  ('1 Kings', 2, 25, 'King Solomon sent Benaiah the son of Jehoiada; and he fell on him, so that he died.'),
  ('1 Kings', 2, 26, 'To Abiathar the priest the king said, “Go to Anathoth, to your own fields, for you are worthy of death. But I will not at this time put you to death, because you bore the Lord GOD’s ark before David my father, and because you were afflicted in all in which my father was afflicted.”'),
  ('1 Kings', 2, 27, 'So Solomon thrust Abiathar out from being priest to the LORD, that he might fulfill the LORD’s word which he spoke concerning the house of Eli in Shiloh.'),
  ('1 Kings', 2, 28, 'This news came to Joab; for Joab had followed Adonijah, although he didn’t follow Absalom. Joab fled to the LORD’s Tent, and held onto the horns of the altar.'),
  ('1 Kings', 2, 29, 'King Solomon was told, “Joab has fled to the LORD’s Tent; and behold, he is by the altar.” Then Solomon sent Benaiah the son of Jehoiada, saying, “Go, fall on him.”');
INSERT INTO bible_verses (book_name, chapter, verse, text) VALUES
  ('1 Kings', 2, 30, 'Benaiah came to the LORD’s Tent, and said to him, “The king says, ‘Come out!’” He said, “No; but I will die here.” Benaiah brought the king word again, saying, “This is what Joab said, and this is how he answered me.”'),
  ('1 Kings', 2, 31, 'The king said to him, “Do as he has said, and fall on him, and bury him, that you may take away the blood, which Joab shed without cause, from me and from my father’s house.'),
  ('1 Kings', 2, 32, 'The LORD will return his blood on his own head, because he fell on two men more righteous and better than he, and killed them with the sword, and my father David didn’t know it: Abner the son of Ner, captain of the army of Israel, and Amasa the son of Jether, captain of the army of Judah.'),
  ('1 Kings', 2, 33, 'So their blood will return on the head of Joab and on the head of his offspring forever. But for David, for his offspring, for his house, and for his throne, there will be peace forever from the LORD.”'),
  ('1 Kings', 2, 34, 'Then Benaiah the son of Jehoiada went up and fell on him, and killed him; and he was buried in his own house in the wilderness.'),
  ('1 Kings', 2, 35, 'The king put Benaiah the son of Jehoiada in his place over the army; and the king put Zadok the priest in the place of Abiathar.'),
  ('1 Kings', 2, 36, 'The king sent and called for Shimei, and said to him, “Build yourself a house in Jerusalem, and live there, and don’t go anywhere else.'),
  ('1 Kings', 2, 37, 'For on the day you go out and pass over the brook Kidron, know for certain that you will surely die. Your blood will be on your own head.”'),
  ('1 Kings', 2, 38, 'Shimei said to the king, “What you say is good. As my lord the king has said, so will your servant do.” Shimei lived in Jerusalem many days.'),
  ('1 Kings', 2, 39, 'At the end of three years, two of Shimei’s slaves ran away to Achish, son of Maacah, king of Gath. They told Shimei, saying, “Behold, your slaves are in Gath.”'),
  ('1 Kings', 2, 40, 'Shimei arose, saddled his donkey, and went to Gath to Achish to seek his slaves; and Shimei went and brought his slaves from Gath.'),
  ('1 Kings', 2, 41, 'Solomon was told that Shimei had gone from Jerusalem to Gath, and had come again.'),
  ('1 Kings', 2, 42, 'The king sent and called for Shimei, and said to him, “Didn’t I adjure you by the LORD and warn you, saying, ‘Know for certain that on the day you go out and walk anywhere else, you shall surely die’? You said to me, ‘The saying that I have heard is good.’'),
  ('1 Kings', 2, 43, 'Why then have you not kept the oath of the LORD and the commandment that I have instructed you with?”'),
  ('1 Kings', 2, 44, 'The king said moreover to Shimei, “You know in your heart all the wickedness that you did to David my father. Therefore the LORD will return your wickedness on your own head.'),
  ('1 Kings', 2, 45, 'But King Solomon will be blessed, and David’s throne will be established before the LORD forever.”'),
  ('1 Kings', 2, 46, 'So the king commanded Benaiah the son of Jehoiada; and he went out, and fell on him, so that he died. The kingdom was established in the hand of Solomon.'),
  ('1 Kings', 3, 1, 'Solomon made a marriage alliance with Pharaoh king of Egypt. He took Pharaoh’s daughter and brought her into David’s city until he had finished building his own house, the LORD’s house, and the wall around Jerusalem.'),
  ('1 Kings', 3, 2, 'However, the people sacrificed in the high places, because there was not yet a house built for the LORD’s name.'),
  ('1 Kings', 3, 3, 'Solomon loved the LORD, walking in the statutes of David his father, except that he sacrificed and burned incense in the high places.'),
  ('1 Kings', 3, 4, 'The king went to Gibeon to sacrifice there, for that was the great high place. Solomon offered a thousand burnt offerings on that altar.'),
  ('1 Kings', 3, 5, 'In Gibeon, the LORD appeared to Solomon in a dream by night; and God said, “Ask for what I should give you.”'),
  ('1 Kings', 3, 6, 'Solomon said, “You have shown to your servant David my father great loving kindness, because he walked before you in truth, in righteousness, and in uprightness of heart with you. You have kept for him this great loving kindness, that you have given him a son to sit on his throne, as it is today.'),
  ('1 Kings', 3, 7, 'Now, LORD my God, you have made your servant king instead of David my father. I am just a little child. I don’t know how to go out or come in.'),
  ('1 Kings', 3, 8, 'Your servant is among your people which you have chosen, a great people, that can’t be numbered or counted for multitude.'),
  ('1 Kings', 3, 9, 'Give your servant therefore an understanding heart to judge your people, that I may discern between good and evil; for who is able to judge this great people of yours?”'),
  ('1 Kings', 3, 10, 'This request pleased the Lord, that Solomon had asked this thing.'),
  ('1 Kings', 3, 11, 'God said to him, “Because you have asked this thing, and have not asked for yourself long life, nor have you asked for riches for yourself, nor have you asked for the life of your enemies, but have asked for yourself understanding to discern justice,'),
  ('1 Kings', 3, 12, 'behold, I have done according to your word. Behold, I have given you a wise and understanding heart, so that there has been no one like you before you, and after you none will arise like you.'),
  ('1 Kings', 3, 13, 'I have also given you that which you have not asked, both riches and honor, so that there will not be any among the kings like you for all your days.'),
  ('1 Kings', 3, 14, 'If you will walk in my ways, to keep my statutes and my commandments, as your father David walked, then I will lengthen your days.”'),
  ('1 Kings', 3, 15, 'Solomon awoke; and behold, it was a dream. Then he came to Jerusalem and stood before the ark of the LORD’s covenant, and offered up burnt offerings, offered peace offerings, and made a feast for all his servants.'),
  ('1 Kings', 3, 16, 'Then two women who were prostitutes came to the king, and stood before him.'),
  ('1 Kings', 3, 17, 'The one woman said, “Oh, my lord, I and this woman dwell in one house. I delivered a child with her in the house.'),
  ('1 Kings', 3, 18, 'The third day after I delivered, this woman delivered also. We were together. There was no stranger with us in the house, just us two in the house.'),
  ('1 Kings', 3, 19, 'This woman’s child died in the night, because she lay on it.'),
  ('1 Kings', 3, 20, 'She arose at midnight, and took my son from beside me while your servant slept, and laid it in her bosom, and laid her dead child in my bosom.'),
  ('1 Kings', 3, 21, 'When I rose in the morning to nurse my child, behold, he was dead; but when I had looked at him in the morning, behold, it was not my son whom I bore.”'),
  ('1 Kings', 3, 22, 'The other woman said, “No! But the living one is my son, and the dead one is your son.” The first one said, “No! But the dead one is your son, and the living one is my son.” They argued like this before the king.'),
  ('1 Kings', 3, 23, 'Then the king said, “One says, ‘This is my son who lives, and your son is the dead one;’ and the other says, ‘No! But your son is the dead one, and my son is the living one.’”'),
  ('1 Kings', 3, 24, 'The king said, “Get me a sword.” So they brought a sword before the king.'),
  ('1 Kings', 3, 25, 'The king said, “Divide the living child in two, and give half to the one, and half to the other.”'),
  ('1 Kings', 3, 26, 'Then the woman whose the living child was spoke to the king, for her heart yearned over her son, and she said, “Oh, my lord, give her the living child, and in no way kill him!” But the other said, “He shall be neither mine nor yours. Divide him.”'),
  ('1 Kings', 3, 27, 'Then the king answered, “Give the first woman the living child, and definitely do not kill him. She is his mother.”'),
  ('1 Kings', 3, 28, 'All Israel heard of the judgment which the king had judged; and they feared the king, for they saw that the wisdom of God was in him to do justice.'),
  ('1 Kings', 4, 1, 'King Solomon was king over all Israel.'),
  ('1 Kings', 4, 2, 'These were the princes whom he had: Azariah the son of Zadok, the priest;'),
  ('1 Kings', 4, 3, 'Elihoreph and Ahijah, the sons of Shisha, scribes; Jehoshaphat the son of Ahilud, the recorder;'),
  ('1 Kings', 4, 4, 'Benaiah the son of Jehoiada was over the army; Zadok and Abiathar were priests;'),
  ('1 Kings', 4, 5, 'Azariah the son of Nathan was over the officers; Zabud the son of Nathan was chief minister, the king’s friend;'),
  ('1 Kings', 4, 6, 'Ahishar was over the household; and Adoniram the son of Abda was over the men subject to forced labor.'),
  ('1 Kings', 4, 7, 'Solomon had twelve officers over all Israel, who provided food for the king and his household. Each man had to make provision for a month in the year.'),
  ('1 Kings', 4, 8, 'These are their names: Ben Hur, in the hill country of Ephraim;'),
  ('1 Kings', 4, 9, 'Ben Deker, in Makaz, in Shaalbim, Beth Shemesh, and Elon Beth Hanan;'),
  ('1 Kings', 4, 10, 'Ben Hesed, in Arubboth (Socoh and all the land of Hepher belonged to him);'),
  ('1 Kings', 4, 11, 'Ben Abinadab, in all the height of Dor (he had Taphath, Solomon’s daughter, as wife);'),
  ('1 Kings', 4, 12, 'Baana the son of Ahilud, in Taanach and Megiddo, and all Beth Shean which is beside Zarethan, beneath Jezreel, from Beth Shean to Abel Meholah, as far as beyond Jokmeam;'),
  ('1 Kings', 4, 13, 'Ben Geber, in Ramoth Gilead (the towns of Jair the son of Manasseh, which are in Gilead, belonged to him; and the region of Argob, which is in Bashan, sixty great cities with walls and bronze bars, belonged to him);'),
  ('1 Kings', 4, 14, 'Ahinadab the son of Iddo, in Mahanaim;'),
  ('1 Kings', 4, 15, 'Ahimaaz, in Naphtali (he also took Basemath the daughter of Solomon as wife);'),
  ('1 Kings', 4, 16, 'Baana the son of Hushai, in Asher and Bealoth;'),
  ('1 Kings', 4, 17, 'Jehoshaphat the son of Paruah, in Issachar;'),
  ('1 Kings', 4, 18, 'Shimei the son of Ela, in Benjamin;'),
  ('1 Kings', 4, 19, 'Geber the son of Uri, in the land of Gilead, the country of Sihon king of the Amorites and of Og king of Bashan; and he was the only officer who was in the land.'),
  ('1 Kings', 4, 20, 'Judah and Israel were numerous as the sand which is by the sea in multitude, eating and drinking and making merry.'),
  ('1 Kings', 4, 21, 'Solomon ruled over all the kingdoms from the River to the land of the Philistines, and to the border of Egypt. They brought tribute and served Solomon all the days of his life.'),
  ('1 Kings', 4, 22, 'Solomon’s provision for one day was thirty cors of fine flour, sixty measures of meal,'),
  ('1 Kings', 4, 23, 'ten head of fat cattle, twenty head of cattle out of the pastures, and one hundred sheep, in addition to deer, gazelles, roebucks, and fattened fowl.'),
  ('1 Kings', 4, 24, 'For he had dominion over all on this side of the River, from Tiphsah even to Gaza, over all the kings on this side of the River; and he had peace on all sides around him.'),
  ('1 Kings', 4, 25, 'Judah and Israel lived safely, every man under his vine and under his fig tree, from Dan even to Beersheba, all the days of Solomon.'),
  ('1 Kings', 4, 26, 'Solomon had forty thousand stalls of horses for his chariots, and twelve thousand horsemen.'),
  ('1 Kings', 4, 27, 'Those officers provided food for King Solomon, and for all who came to King Solomon’s table, every man in his month. They let nothing be lacking.'),
  ('1 Kings', 4, 28, 'They also brought barley and straw for the horses and swift steeds to the place where the officers were, each man according to his duty.'),
  ('1 Kings', 4, 29, 'God gave Solomon abundant wisdom, understanding, and breadth of mind like the sand that is on the seashore.'),
  ('1 Kings', 4, 30, 'Solomon’s wisdom excelled the wisdom of all the children of the east and all the wisdom of Egypt.'),
  ('1 Kings', 4, 31, 'For he was wiser than all men—wiser than Ethan the Ezrahite, Heman, Calcol, and Darda, the sons of Mahol; and his fame was in all the nations all around.'),
  ('1 Kings', 4, 32, 'He spoke three thousand proverbs, and his songs numbered one thousand five.'),
  ('1 Kings', 4, 33, 'He spoke of trees, from the cedar that is in Lebanon even to the hyssop that grows out of the wall; he also spoke of animals, of birds, of creeping things, and of fish.'),
  ('1 Kings', 4, 34, 'People of all nations came to hear the wisdom of Solomon, sent by all kings of the earth who had heard of his wisdom.'),
  ('1 Kings', 5, 1, 'Hiram king of Tyre sent his servants to Solomon, for he had heard that they had anointed him king in the place of his father, and Hiram had always loved David.'),
  ('1 Kings', 5, 2, 'Solomon sent to Hiram, saying,'),
  ('1 Kings', 5, 3, '“You know that David my father could not build a house for the name of the LORD his God because of the wars which were around him on every side, until the LORD put his enemies under the soles of his feet.'),
  ('1 Kings', 5, 4, 'But now the LORD my God has given me rest on every side. There is no enemy and no evil occurrence.'),
  ('1 Kings', 5, 5, 'Behold, I intend to build a house for the name of the LORD my God, as the LORD spoke to David my father, saying, ‘Your son, whom I will set on your throne in your place shall build the house for my name.’'),
  ('1 Kings', 5, 6, 'Now therefore command that cedar trees be cut for me out of Lebanon. My servants will be with your servants; and I will give you wages for your servants according to all that you say. For you know that there is nobody among us who knows how to cut timber like the Sidonians.”'),
  ('1 Kings', 5, 7, 'When Hiram heard the words of Solomon, he rejoiced greatly, and said, “Blessed is the LORD today, who has given to David a wise son to rule over this great people.”'),
  ('1 Kings', 5, 8, 'Hiram sent to Solomon, saying, “I have heard the message which you have sent to me. I will do all your desire concerning timber of cedar, and concerning cypress timber.'),
  ('1 Kings', 5, 9, 'My servants will bring them down from Lebanon to the sea. I will make them into rafts to go by sea to the place that you specify to me, and will cause them to be broken up there, and you will receive them. You will accomplish my desire, in giving food for my household.”'),
  ('1 Kings', 5, 10, 'So Hiram gave Solomon cedar timber and cypress timber according to all his desire.'),
  ('1 Kings', 5, 11, 'Solomon gave Hiram twenty thousand cors of wheat for food to his household, and twenty cors of pure oil. Solomon gave this to Hiram year by year.'),
  ('1 Kings', 5, 12, 'The LORD gave Solomon wisdom, as he promised him. There was peace between Hiram and Solomon, and the two of them made a treaty together.'),
  ('1 Kings', 5, 13, 'King Solomon raised a levy out of all Israel; and the levy was thirty thousand men.'),
  ('1 Kings', 5, 14, 'He sent them to Lebanon, ten thousand a month by courses: for a month they were in Lebanon, and two months at home; and Adoniram was over the men subject to forced labor.'),
  ('1 Kings', 5, 15, 'Solomon had seventy thousand who bore burdens, and eighty thousand who were stone cutters in the mountains,'),
  ('1 Kings', 5, 16, 'besides Solomon’s chief officers who were over the work: three thousand three hundred who ruled over the people who labored in the work.'),
  ('1 Kings', 5, 17, 'The king commanded, and they cut out large stones, costly stones, to lay the foundation of the house with worked stone.'),
  ('1 Kings', 5, 18, 'Solomon’s builders and Hiram’s builders and the Gebalites cut them, and prepared the timber and the stones to build the house.'),
  ('1 Kings', 6, 1, 'In the four hundred and eightieth year after the children of Israel had come out of the land of Egypt, in the fourth year of Solomon’s reign over Israel, in the month Ziv, which is the second month, he began to build the LORD’s house.'),
  ('1 Kings', 6, 2, 'The house which King Solomon built for the LORD had a length of sixty cubits, and its width twenty, and its height thirty cubits.'),
  ('1 Kings', 6, 3, 'The porch in front of the temple of the house had a length of twenty cubits, which was along the width of the house. Ten cubits was its width in front of the house.');
INSERT INTO bible_verses (book_name, chapter, verse, text) VALUES
  ('1 Kings', 6, 4, 'He made windows of fixed lattice work for the house.'),
  ('1 Kings', 6, 5, 'Against the wall of the house, he built floors all around, against the walls of the house all around, both of the temple and of the inner sanctuary; and he made side rooms all around.'),
  ('1 Kings', 6, 6, 'The lowest floor was five cubits wide, and the middle was six cubits wide, and the third was seven cubits wide; for on the outside he made offsets in the wall of the house all around, that the beams should not be inserted into the walls of the house.'),
  ('1 Kings', 6, 7, 'The house, when it was under construction, was built of stone prepared at the quarry; and no hammer or ax or any tool of iron was heard in the house while it was under construction.'),
  ('1 Kings', 6, 8, 'The door for the middle side rooms was in the right side of the house. They went up by winding stairs into the middle floor, and out of the middle into the third.'),
  ('1 Kings', 6, 9, 'So he built the house and finished it; and he covered the house with beams and planks of cedar.'),
  ('1 Kings', 6, 10, 'He built the floors all along the house, each five cubits high; and they rested on the house with timbers of cedar.'),
  ('1 Kings', 6, 11, 'The LORD’s word came to Solomon, saying,'),
  ('1 Kings', 6, 12, '“Concerning this house which you are building, if you will walk in my statutes, and execute my ordinances, and keep all my commandments to walk in them, then I will establish my word with you, which I spoke to David your father.'),
  ('1 Kings', 6, 13, 'I will dwell among the children of Israel, and will not forsake my people Israel.”'),
  ('1 Kings', 6, 14, 'So Solomon built the house and finished it.'),
  ('1 Kings', 6, 15, 'He built the walls of the house within with boards of cedar; from the floor of the house to the walls of the ceiling, he covered them on the inside with wood. He covered the floor of the house with cypress boards.'),
  ('1 Kings', 6, 16, 'He built twenty cubits of the back part of the house with boards of cedar from the floor to the ceiling. He built this within, for an inner sanctuary, even for the most holy place.'),
  ('1 Kings', 6, 17, 'In front of the temple sanctuary was forty cubits long.'),
  ('1 Kings', 6, 18, 'There was cedar on the house within, carved with buds and open flowers. All was cedar. No stone was visible.'),
  ('1 Kings', 6, 19, 'He prepared an inner sanctuary in the middle of the house within, to set the ark of the LORD’s covenant there.'),
  ('1 Kings', 6, 20, 'Within the inner sanctuary was twenty cubits in length, and twenty cubits in width, and twenty cubits in its height. He overlaid it with pure gold. He covered the altar with cedar.'),
  ('1 Kings', 6, 21, 'So Solomon overlaid the house within with pure gold. He drew chains of gold across before the inner sanctuary, and he overlaid it with gold.'),
  ('1 Kings', 6, 22, 'He overlaid the whole house with gold, until all the house was finished. He also overlaid the whole altar that belonged to the inner sanctuary with gold.'),
  ('1 Kings', 6, 23, 'In the inner sanctuary he made two cherubim of olive wood, each ten cubits high.'),
  ('1 Kings', 6, 24, 'Five cubits was the length of one wing of the cherub, and five cubits was the length of the other wing of the cherub. From the tip of one wing to the tip of the other was ten cubits.'),
  ('1 Kings', 6, 25, 'The other cherub was ten cubits. Both the cherubim were of one measure and one form.'),
  ('1 Kings', 6, 26, 'One cherub was ten cubits high, and so was the other cherub.'),
  ('1 Kings', 6, 27, 'He set the cherubim within the inner house. The wings of the cherubim were stretched out, so that the wing of the one touched the one wall and the wing of the other cherub touched the other wall; and their wings touched one another in the middle of the house.'),
  ('1 Kings', 6, 28, 'He overlaid the cherubim with gold.'),
  ('1 Kings', 6, 29, 'He carved all the walls of the house around with carved figures of cherubim, palm trees, and open flowers, inside and outside.'),
  ('1 Kings', 6, 30, 'He overlaid the floor of the house with gold, inside and outside.'),
  ('1 Kings', 6, 31, 'For the entrance of the inner sanctuary, he made doors of olive wood. The lintel and door posts were a fifth part of the wall.'),
  ('1 Kings', 6, 32, 'So he made two doors of olive wood; and he carved on them carvings of cherubim, palm trees, and open flowers, and overlaid them with gold. He spread the gold on the cherubim and on the palm trees.'),
  ('1 Kings', 6, 33, 'He also made the entrance of the temple door posts of olive wood, out of a fourth part of the wall,'),
  ('1 Kings', 6, 34, 'and two doors of cypress wood. The two leaves of the one door were folding, and the two leaves of the other door were folding.'),
  ('1 Kings', 6, 35, 'He carved cherubim, palm trees, and open flowers; and he overlaid them with gold fitted on the engraved work.'),
  ('1 Kings', 6, 36, 'He built the inner court with three courses of cut stone and a course of cedar beams.'),
  ('1 Kings', 6, 37, 'The foundation of the LORD’s house was laid in the fourth year, in the month Ziv.'),
  ('1 Kings', 6, 38, 'In the eleventh year, in the month Bul, which is the eighth month, the house was finished throughout all its parts and according to all its specifications. So he spent seven years building it.'),
  ('1 Kings', 7, 1, 'Solomon was building his own house thirteen years, and he finished all his house.'),
  ('1 Kings', 7, 2, 'For he built the House of the Forest of Lebanon. Its length was one hundred cubits, its width fifty cubits, and its height thirty cubits, on four rows of cedar pillars, with cedar beams on the pillars.'),
  ('1 Kings', 7, 3, 'It was covered with cedar above over the forty-five beams that were on the pillars, fifteen in a row.'),
  ('1 Kings', 7, 4, 'There were beams in three rows, and window was facing window in three ranks.'),
  ('1 Kings', 7, 5, 'All the doors and posts were made square with beams; and window was facing window in three ranks.'),
  ('1 Kings', 7, 6, 'He made the hall of pillars. Its length was fifty cubits and its width thirty cubits, with a porch before them, and pillars and a threshold before them.'),
  ('1 Kings', 7, 7, 'He made the porch of the throne where he was to judge, even the porch of judgment; and it was covered with cedar from floor to floor.'),
  ('1 Kings', 7, 8, 'His house where he was to dwell, the other court within the porch, was of the same construction. He made also a house for Pharaoh’s daughter (whom Solomon had taken as wife), like this porch.'),
  ('1 Kings', 7, 9, 'All these were of costly stones, even of stone cut according to measure, sawed with saws, inside and outside, even from the foundation to the coping, and so on the outside to the great court.'),
  ('1 Kings', 7, 10, 'The foundation was of costly stones, even great stones, stones of ten cubits and stones of eight cubits.'),
  ('1 Kings', 7, 11, 'Above were costly stones, even cut stone, according to measure, and cedar wood.'),
  ('1 Kings', 7, 12, 'The great court around had three courses of cut stone with a course of cedar beams, like the inner court of the LORD’s house and the porch of the house.'),
  ('1 Kings', 7, 13, 'King Solomon sent and brought Hiram out of Tyre.'),
  ('1 Kings', 7, 14, 'He was the son of a widow of the tribe of Naphtali, and his father was a man of Tyre, a worker in bronze; and he was filled with wisdom and understanding and skill to work all works in bronze. He came to King Solomon and performed all his work.'),
  ('1 Kings', 7, 15, 'For he fashioned the two pillars of bronze, eighteen cubits high apiece; and a line of twelve cubits encircled either of them.'),
  ('1 Kings', 7, 16, 'He made two capitals of molten bronze to set on the tops of the pillars. The height of the one capital was five cubits, and the height of the other capital was five cubits.'),
  ('1 Kings', 7, 17, 'There were nets of checker work and wreaths of chain work for the capitals which were on the top of the pillars: seven for the one capital, and seven for the other capital.'),
  ('1 Kings', 7, 18, 'So he made the pillars; and there were two rows of pomegranates around the one network, to cover the capitals that were on the top of the pillars; and he did so for the other capital.'),
  ('1 Kings', 7, 19, 'The capitals that were on the top of the pillars in the porch were of lily work, four cubits.'),
  ('1 Kings', 7, 20, 'There were capitals above also on the two pillars, close by the belly which was beside the network. There were two hundred pomegranates in rows around the other capital.'),
  ('1 Kings', 7, 21, 'He set up the pillars at the porch of the temple. He set up the right pillar and called its name Jachin; and he set up the left pillar and called its name Boaz.'),
  ('1 Kings', 7, 22, 'On the tops of the pillars was lily work. So the work of the pillars was finished.'),
  ('1 Kings', 7, 23, 'He made the molten sea ten cubits from brim to brim, round in shape. Its height was five cubits; and a line of thirty cubits encircled it.'),
  ('1 Kings', 7, 24, 'Under its brim around there were buds which encircled it for ten cubits, encircling the sea. The buds were in two rows, cast when it was cast.'),
  ('1 Kings', 7, 25, 'It stood on twelve oxen, three looking toward the north, and three looking toward the west, and three looking toward the south, and three looking toward the east; and the sea was set on them above, and all their hindquarters were inward.'),
  ('1 Kings', 7, 26, 'It was a hand width thick. Its brim was worked like the brim of a cup, like the flower of a lily. It held two thousand baths.'),
  ('1 Kings', 7, 27, 'He made the ten bases of bronze. The length of one base was four cubits, four cubits its width, and three cubits its height.'),
  ('1 Kings', 7, 28, 'The work of the bases was like this: they had panels; and there were panels between the ledges;'),
  ('1 Kings', 7, 29, 'and on the panels that were between the ledges were lions, oxen, and cherubim; and on the ledges there was a pedestal above; and beneath the lions and oxen were wreaths of hanging work.'),
  ('1 Kings', 7, 30, 'Every base had four bronze wheels and axles of bronze; and its four feet had supports. The supports were cast beneath the basin, with wreaths at the side of each.'),
  ('1 Kings', 7, 31, 'Its opening within the capital and above was a cubit. Its opening was round like the work of a pedestal, a cubit and a half; and also on its opening were engravings, and their panels were square, not round.'),
  ('1 Kings', 7, 32, 'The four wheels were underneath the panels; and the axles of the wheels were in the base. The height of a wheel was a cubit and half a cubit.'),
  ('1 Kings', 7, 33, 'The work of the wheels was like the work of a chariot wheel. Their axles, their rims, their spokes, and their hubs were all of cast metal.'),
  ('1 Kings', 7, 34, 'There were four supports at the four corners of each base. Its supports were of the base itself.'),
  ('1 Kings', 7, 35, 'In the top of the base there was a round band half a cubit high; and on the top of the base its supports and its panels were the same.'),
  ('1 Kings', 7, 36, 'On the plates of its supports and on its panels, he engraved cherubim, lions, and palm trees, each in its space, with wreaths all around.'),
  ('1 Kings', 7, 37, 'He made the ten bases in this way: all of them had one casting, one measure, and one form.'),
  ('1 Kings', 7, 38, 'He made ten basins of bronze. One basin contained forty baths. Every basin measured four cubits. One basin was on every one of the ten bases.'),
  ('1 Kings', 7, 39, 'He set the bases, five on the right side of the house and five on the left side of the house. He set the sea on the right side of the house eastward and toward the south.'),
  ('1 Kings', 7, 40, 'Hiram made the pots, the shovels, and the basins. So Hiram finished doing all the work that he worked for King Solomon in the LORD’s house:'),
  ('1 Kings', 7, 41, 'the two pillars; the two bowls of the capitals that were on the top of the pillars; the two networks to cover the two bowls of the capitals that were on the top of the pillars;'),
  ('1 Kings', 7, 42, 'the four hundred pomegranates for the two networks; two rows of pomegranates for each network, to cover the two bowls of the capitals that were on the pillars;'),
  ('1 Kings', 7, 43, 'the ten bases; the ten basins on the bases;'),
  ('1 Kings', 7, 44, 'the one sea; the twelve oxen under the sea;'),
  ('1 Kings', 7, 45, 'the pots; the shovels; and the basins. All of these vessels, which Hiram made for King Solomon for the LORD’s house, were of burnished bronze.'),
  ('1 Kings', 7, 46, 'The king cast them in the plain of the Jordan, in the clay ground between Succoth and Zarethan.'),
  ('1 Kings', 7, 47, 'Solomon left all the vessels unweighed, because there were so many of them. The weight of the bronze could not be determined.'),
  ('1 Kings', 7, 48, 'Solomon made all the vessels that were in the LORD’s house: the golden altar and the table that the show bread was on, of gold;'),
  ('1 Kings', 7, 49, 'and the lamp stands, five on the right side and five on the left, in front of the inner sanctuary, of pure gold; and the flowers, the lamps, and the tongs, of gold;'),
  ('1 Kings', 7, 50, 'the cups, the snuffers, the basins, the spoons, and the fire pans, of pure gold; and the hinges, both for the doors of the inner house, the most holy place, and for the doors of the house, of the temple, of gold.'),
  ('1 Kings', 7, 51, 'Thus all the work that King Solomon did in the LORD’s house was finished. Solomon brought in the things which David his father had dedicated—the silver, the gold, and the vessels—and put them in the treasuries of the LORD’s house.'),
  ('1 Kings', 8, 1, 'Then Solomon assembled the elders of Israel with all the heads of the tribes, the princes of the fathers’ households of the children of Israel, to King Solomon in Jerusalem, to bring up the ark of the LORD’s covenant out of David’s city, which is Zion.'),
  ('1 Kings', 8, 2, 'All the men of Israel assembled themselves to King Solomon at the feast in the month Ethanim, which is the seventh month.'),
  ('1 Kings', 8, 3, 'All the elders of Israel came, and the priests picked up the ark.'),
  ('1 Kings', 8, 4, 'They brought up the LORD’s ark, the Tent of Meeting, and all the holy vessels that were in the Tent. The priests and the Levites brought these up.'),
  ('1 Kings', 8, 5, 'King Solomon and all the congregation of Israel, who were assembled to him, were with him before the ark, sacrificing sheep and cattle that could not be counted or numbered for multitude.'),
  ('1 Kings', 8, 6, 'The priests brought in the ark of the LORD’s covenant to its place, into the inner sanctuary of the house, to the most holy place, even under the cherubim’s wings.'),
  ('1 Kings', 8, 7, 'For the cherubim spread their wings out over the place of the ark, and the cherubim covered the ark and its poles above.'),
  ('1 Kings', 8, 8, 'The poles were so long that the ends of the poles were seen from the holy place before the inner sanctuary, but they were not seen outside. They are there to this day.'),
  ('1 Kings', 8, 9, 'There was nothing in the ark except the two stone tablets which Moses put there at Horeb, when the LORD made a covenant with the children of Israel, when they came out of the land of Egypt.'),
  ('1 Kings', 8, 10, 'It came to pass, when the priests had come out of the holy place, that the cloud filled the LORD’s house,'),
  ('1 Kings', 8, 11, 'so that the priests could not stand to minister by reason of the cloud; for the LORD’s glory filled the LORD’s house.'),
  ('1 Kings', 8, 12, 'Then Solomon said, “The LORD has said that he would dwell in the thick darkness.'),
  ('1 Kings', 8, 13, 'I have surely built you a house of habitation, a place for you to dwell in forever.”'),
  ('1 Kings', 8, 14, 'The king turned his face around and blessed all the assembly of Israel; and all the assembly of Israel stood.');
INSERT INTO bible_verses (book_name, chapter, verse, text) VALUES
  ('1 Kings', 8, 15, 'He said, “Blessed is the LORD, the God of Israel, who spoke with his mouth to David your father, and has with his hand fulfilled it, saying,'),
  ('1 Kings', 8, 16, '‘Since the day that I brought my people Israel out of Egypt, I chose no city out of all the tribes of Israel to build a house, that my name might be there; but I chose David to be over my people Israel.’'),
  ('1 Kings', 8, 17, '“Now it was in the heart of David my father to build a house for the name of the LORD, the God of Israel.'),
  ('1 Kings', 8, 18, 'But the LORD said to David my father, ‘Whereas it was in your heart to build a house for my name, you did well that it was in your heart.'),
  ('1 Kings', 8, 19, 'Nevertheless, you shall not build the house; but your son who shall come out of your body, he shall build the house for my name.’'),
  ('1 Kings', 8, 20, 'The LORD has established his word that he spoke; for I have risen up in the place of David my father, and I sit on the throne of Israel, as the LORD promised, and have built the house for the name of the LORD, the God of Israel.'),
  ('1 Kings', 8, 21, 'There I have set a place for the ark, in which is the LORD’s covenant, which he made with our fathers when he brought them out of the land of Egypt.”'),
  ('1 Kings', 8, 22, 'Solomon stood before the LORD’s altar in the presence of all the assembly of Israel, and spread out his hands toward heaven;'),
  ('1 Kings', 8, 23, 'and he said, “LORD, the God of Israel, there is no God like you, in heaven above, or on earth beneath; who keeps covenant and loving kindness with your servants who walk before you with all their heart;'),
  ('1 Kings', 8, 24, 'who has kept with your servant David my father that which you promised him. Yes, you spoke with your mouth, and have fulfilled it with your hand, as it is today.'),
  ('1 Kings', 8, 25, 'Now therefore, may LORD, the God of Israel, keep with your servant David my father that which you have promised him, saying, ‘There shall not fail from you a man in my sight to sit on the throne of Israel, if only your children take heed to their way, to walk before me as you have walked before me.’'),
  ('1 Kings', 8, 26, '“Now therefore, God of Israel, please let your word be verified, which you spoke to your servant David my father.'),
  ('1 Kings', 8, 27, 'But will God in very deed dwell on the earth? Behold, heaven and the heaven of heavens can’t contain you; how much less this house that I have built!'),
  ('1 Kings', 8, 28, 'Yet have respect for the prayer of your servant and for his supplication, LORD my God, to listen to the cry and to the prayer which your servant prays before you today;'),
  ('1 Kings', 8, 29, 'that your eyes may be open toward this house night and day, even toward the place of which you have said, ‘My name shall be there;’ to listen to the prayer which your servant prays toward this place.'),
  ('1 Kings', 8, 30, 'Listen to the supplication of your servant, and of your people Israel, when they pray toward this place. Yes, hear in heaven, your dwelling place; and when you hear, forgive.'),
  ('1 Kings', 8, 31, '“If a man sins against his neighbor, and an oath is laid on him to cause him to swear, and he comes and swears before your altar in this house,'),
  ('1 Kings', 8, 32, 'then hear in heaven, and act, and judge your servants, condemning the wicked, to bring his way on his own head, and justifying the righteous, to give him according to his righteousness.'),
  ('1 Kings', 8, 33, '“When your people Israel are struck down before the enemy because they have sinned against you, if they turn again to you and confess your name, and pray and make supplication to you in this house,'),
  ('1 Kings', 8, 34, 'then hear in heaven, and forgive the sin of your people Israel, and bring them again to the land which you gave to their fathers.'),
  ('1 Kings', 8, 35, '“When the sky is shut up and there is no rain because they have sinned against you, if they pray toward this place and confess your name, and turn from their sin when you afflict them,'),
  ('1 Kings', 8, 36, 'then hear in heaven, and forgive the sin of your servants, and of your people Israel, when you teach them the good way in which they should walk; and send rain on your land which you have given to your people for an inheritance.'),
  ('1 Kings', 8, 37, '“If there is famine in the land, if there is pestilence, if there is blight, mildew, locust or caterpillar; if their enemy besieges them in the land of their cities, whatever plague, whatever sickness there is,'),
  ('1 Kings', 8, 38, 'whatever prayer and supplication is made by any man, or by all your people Israel, who shall each know the plague of his own heart, and spread out his hands toward this house,'),
  ('1 Kings', 8, 39, 'then hear in heaven, your dwelling place, and forgive, and act, and give to every man according to all his ways, whose heart you know (for you, even you only, know the hearts of all the children of men);'),
  ('1 Kings', 8, 40, 'that they may fear you all the days that they live in the land which you gave to our fathers.'),
  ('1 Kings', 8, 41, '“Moreover, concerning the foreigner, who is not of your people Israel, when he comes out of a far country for your name’s sake'),
  ('1 Kings', 8, 42, '(for they shall hear of your great name and of your mighty hand and of your outstretched arm), when he comes and prays toward this house,'),
  ('1 Kings', 8, 43, 'hear in heaven, your dwelling place, and do according to all that the foreigner calls to you for; that all the peoples of the earth may know your name, to fear you, as do your people Israel, and that they may know that this house which I have built is called by your name.'),
  ('1 Kings', 8, 44, '“If your people go out to battle against their enemy, by whatever way you shall send them, and they pray to the LORD toward the city which you have chosen, and toward the house which I have built for your name,'),
  ('1 Kings', 8, 45, 'then hear in heaven their prayer and their supplication, and maintain their cause.'),
  ('1 Kings', 8, 46, 'If they sin against you (for there is no man who doesn’t sin), and you are angry with them and deliver them to the enemy, so that they carry them away captive to the land of the enemy, far off or near;'),
  ('1 Kings', 8, 47, 'yet if they repent in the land where they are carried captive, and turn again, and make supplication to you in the land of those who carried them captive, saying, ‘We have sinned and have done perversely; we have dealt wickedly,’'),
  ('1 Kings', 8, 48, 'if they return to you with all their heart and with all their soul in the land of their enemies who carried them captive, and pray to you toward their land which you gave to their fathers, the city which you have chosen and the house which I have built for your name,'),
  ('1 Kings', 8, 49, 'then hear their prayer and their supplication in heaven, your dwelling place, and maintain their cause;'),
  ('1 Kings', 8, 50, 'and forgive your people who have sinned against you, and all their transgressions in which they have transgressed against you; and give them compassion before those who carried them captive, that they may have compassion on them'),
  ('1 Kings', 8, 51, '(for they are your people and your inheritance, which you brought out of Egypt, from the middle of the iron furnace);'),
  ('1 Kings', 8, 52, 'that your eyes may be open to the supplication of your servant and to the supplication of your people Israel, to listen to them whenever they cry to you.'),
  ('1 Kings', 8, 53, 'For you separated them from among all the peoples of the earth to be your inheritance, as you spoke by Moses your servant, when you brought our fathers out of Egypt, Lord GOD.”'),
  ('1 Kings', 8, 54, 'It was so, that when Solomon had finished praying all this prayer and supplication to the LORD, he arose from before the LORD’s altar, from kneeling on his knees with his hands spread out toward heaven.'),
  ('1 Kings', 8, 55, 'He stood and blessed all the assembly of Israel with a loud voice, saying,'),
  ('1 Kings', 8, 56, '“Blessed be the LORD, who has given rest to his people Israel, according to all that he promised. There has not failed one word of all his good promise, which he promised by Moses his servant.'),
  ('1 Kings', 8, 57, 'May the LORD our God be with us as he was with our fathers. Let him not leave us or forsake us,'),
  ('1 Kings', 8, 58, 'that he may incline our hearts to him, to walk in all his ways, and to keep his commandments, his statutes, and his ordinances, which he commanded our fathers.'),
  ('1 Kings', 8, 59, 'Let these my words, with which I have made supplication before the LORD, be near to the LORD our God day and night, that he may maintain the cause of his servant and the cause of his people Israel, as every day requires;'),
  ('1 Kings', 8, 60, 'that all the peoples of the earth may know that the LORD himself is God. There is no one else.'),
  ('1 Kings', 8, 61, '“Let your heart therefore be perfect with the LORD our God, to walk in his statutes, and to keep his commandments, as it is today.”'),
  ('1 Kings', 8, 62, 'The king, and all Israel with him, offered sacrifice before the LORD.'),
  ('1 Kings', 8, 63, 'Solomon offered for the sacrifice of peace offerings, which he offered to the LORD, twenty two thousand head of cattle and one hundred twenty thousand sheep. So the king and all the children of Israel dedicated the LORD’s house.'),
  ('1 Kings', 8, 64, 'The same day the king made the middle of the court holy that was before the LORD’s house; for there he offered the burnt offering, the meal offering, and the fat of the peace offerings, because the bronze altar that was before the LORD was too little to receive the burnt offering, the meal offering, and the fat of the peace offerings.'),
  ('1 Kings', 8, 65, 'So Solomon held the feast at that time, and all Israel with him, a great assembly, from the entrance of Hamath to the brook of Egypt, before the LORD our God, seven days and seven more days, even fourteen days.'),
  ('1 Kings', 8, 66, 'On the eighth day he sent the people away; and they blessed the king, and went to their tents joyful and glad in their hearts for all the goodness that the LORD had shown to David his servant, and to Israel his people.'),
  ('1 Kings', 9, 1, 'When Solomon had finished the building of the LORD’s house, the king’s house, and all Solomon’s desire which he was pleased to do,'),
  ('1 Kings', 9, 2, 'The LORD appeared to Solomon the second time, as he had appeared to him at Gibeon.'),
  ('1 Kings', 9, 3, 'The LORD said to him, “I have heard your prayer and your supplication that you have made before me. I have made this house holy, which you have built, to put my name there forever; and my eyes and my heart shall be there perpetually.'),
  ('1 Kings', 9, 4, 'As for you, if you will walk before me as David your father walked, in integrity of heart and in uprightness, to do according to all that I have commanded you, and will keep my statutes and my ordinances,'),
  ('1 Kings', 9, 5, 'then I will establish the throne of your kingdom over Israel forever, as I promised to David your father, saying, ‘There shall not fail from you a man on the throne of Israel.’'),
  ('1 Kings', 9, 6, 'But if you turn away from following me, you or your children, and not keep my commandments and my statutes which I have set before you, but go and serve other gods and worship them,'),
  ('1 Kings', 9, 7, 'then I will cut off Israel out of the land which I have given them; and I will cast this house, which I have made holy for my name, out of my sight; and Israel will be a proverb and a byword among all peoples.'),
  ('1 Kings', 9, 8, 'Though this house is so high, yet everyone who passes by it will be astonished and hiss; and they will say, ‘Why has the LORD done this to this land and to this house?’'),
  ('1 Kings', 9, 9, 'and they will answer, ‘Because they abandoned the LORD their God, who brought their fathers out of the land of Egypt, and embraced other gods, and worshiped them, and served them. Therefore the LORD has brought all this evil on them.’”'),
  ('1 Kings', 9, 10, 'At the end of twenty years, in which Solomon had built the two houses, the LORD’s house and the king’s house'),
  ('1 Kings', 9, 11, '(now Hiram the king of Tyre had furnished Solomon with cedar trees and cypress trees, and with gold, according to all his desire), King Solomon gave Hiram twenty cities in the land of Galilee.'),
  ('1 Kings', 9, 12, 'Hiram came out of Tyre to see the cities which Solomon had given him; and they didn’t please him.'),
  ('1 Kings', 9, 13, 'He said, “What cities are these which you have given me, my brother?” He called them the land of Cabul to this day.'),
  ('1 Kings', 9, 14, 'Hiram sent to the king one hundred twenty talents of gold.'),
  ('1 Kings', 9, 15, 'This is the reason of the forced labor which King Solomon conscripted: to build the LORD’s house, his own house, Millo, Jerusalem’s wall, Hazor, Megiddo, and Gezer.'),
  ('1 Kings', 9, 16, 'Pharaoh king of Egypt had gone up, taken Gezer, burned it with fire, killed the Canaanites who lived in the city, and given it for a wedding gift to his daughter, Solomon’s wife.'),
  ('1 Kings', 9, 17, 'Solomon built in the land Gezer, Beth Horon the lower,'),
  ('1 Kings', 9, 18, 'Baalath, Tamar in the wilderness,'),
  ('1 Kings', 9, 19, 'all the storage cities that Solomon had, the cities for his chariots, the cities for his horsemen, and that which Solomon desired to build for his pleasure in Jerusalem, and in Lebanon, and in all the land of his dominion.'),
  ('1 Kings', 9, 20, 'As for all the people who were left of the Amorites, the Hittites, the Perizzites, the Hivites, and the Jebusites, who were not of the children of Israel—'),
  ('1 Kings', 9, 21, 'their children who were left after them in the land, whom the children of Israel were not able utterly to destroy—of them Solomon raised a levy of bondservants to this day.'),
  ('1 Kings', 9, 22, 'But of the children of Israel Solomon made no bondservants; but they were the men of war, his servants, his princes, his captains, and rulers of his chariots and of his horsemen.'),
  ('1 Kings', 9, 23, 'These were the five hundred fifty chief officers who were over Solomon’s work, who ruled over the people who labored in the work.'),
  ('1 Kings', 9, 24, 'But Pharaoh’s daughter came up out of David’s city to her house which Solomon had built for her. Then he built Millo.'),
  ('1 Kings', 9, 25, 'Solomon offered burnt offerings and peace offerings on the altar which he built to the LORD three times per year, burning incense with them on the altar that was before the LORD. So he finished the house.'),
  ('1 Kings', 9, 26, 'King Solomon made a fleet of ships in Ezion Geber, which is beside Eloth, on the shore of the Red Sea, in the land of Edom.'),
  ('1 Kings', 9, 27, 'Hiram sent in the fleet his servants, sailors who had knowledge of the sea, with the servants of Solomon.'),
  ('1 Kings', 9, 28, 'They came to Ophir, and fetched from there gold, four hundred and twenty talents, and brought it to King Solomon.'),
  ('1 Kings', 10, 1, 'When the queen of Sheba heard of the fame of Solomon concerning the LORD’s name, she came to test him with hard questions.'),
  ('1 Kings', 10, 2, 'She came to Jerusalem with a very great caravan, with camels that bore spices, very much gold, and precious stones; and when she had come to Solomon, she talked with him about all that was in her heart.'),
  ('1 Kings', 10, 3, 'Solomon answered all her questions. There wasn’t anything hidden from the king which he didn’t tell her.'),
  ('1 Kings', 10, 4, 'When the queen of Sheba had seen all the wisdom of Solomon, the house that he had built,'),
  ('1 Kings', 10, 5, 'the food of his table, the sitting of his servants, the attendance of his officials, their clothing, his cup bearers, and his ascent by which he went up to the LORD’s house, there was no more spirit in her.'),
  ('1 Kings', 10, 6, 'She said to the king, “It was a true report that I heard in my own land of your acts and of your wisdom.'),
  ('1 Kings', 10, 7, 'However, I didn’t believe the words until I came and my eyes had seen it. Behold, not even half was told me! Your wisdom and prosperity exceed the fame which I heard.'),
  ('1 Kings', 10, 8, 'Happy are your men, happy are these your servants who stand continually before you, who hear your wisdom.'),
  ('1 Kings', 10, 9, 'Blessed is the LORD your God, who delighted in you, to set you on the throne of Israel. Because the LORD loved Israel forever, therefore he made you king, to do justice and righteousness.”'),
  ('1 Kings', 10, 10, 'She gave the king one hundred twenty talents of gold, and a very great quantity of spices, and precious stones. Never again was there such an abundance of spices as these which the queen of Sheba gave to King Solomon.'),
  ('1 Kings', 10, 11, 'The fleet of Hiram that brought gold from Ophir also brought in from Ophir great quantities of almug trees and precious stones.'),
  ('1 Kings', 10, 12, 'The king made of the almug trees pillars for the LORD’s house and for the king’s house, harps also and stringed instruments for the singers; no such almug trees came or were seen to this day.'),
  ('1 Kings', 10, 13, 'King Solomon gave to the queen of Sheba all her desire, whatever she asked, in addition to that which Solomon gave her of his royal bounty. So she turned and went to her own land, she and her servants.'),
  ('1 Kings', 10, 14, 'Now the weight of gold that came to Solomon in one year was six hundred sixty-six talents of gold,'),
  ('1 Kings', 10, 15, 'in addition to that which the traders brought, and the traffic of the merchants, and of all the kings of the mixed people, and of the governors of the country.'),
  ('1 Kings', 10, 16, 'King Solomon made two hundred bucklers of beaten gold; six hundred shekels of gold went to one buckler.'),
  ('1 Kings', 10, 17, 'He made three hundred shields of beaten gold; three minas of gold went to one shield; and the king put them in the House of the Forest of Lebanon.'),
  ('1 Kings', 10, 18, 'Moreover the king made a great throne of ivory, and overlaid it with the finest gold.'),
  ('1 Kings', 10, 19, 'There were six steps to the throne, and the top of the throne was round behind; and there were armrests on either side by the place of the seat, and two lions standing beside the armrests.'),
  ('1 Kings', 10, 20, 'Twelve lions stood there on the one side and on the other on the six steps. Nothing like it was made in any kingdom.');
INSERT INTO bible_verses (book_name, chapter, verse, text) VALUES
  ('1 Kings', 10, 21, 'All King Solomon’s drinking vessels were of gold, and all the vessels of the House of the Forest of Lebanon were of pure gold. None were of silver, because it was considered of little value in the days of Solomon.'),
  ('1 Kings', 10, 22, 'For the king had a fleet of ships of Tarshish at sea with Hiram’s fleet. Once every three years the fleet of Tarshish came bringing gold, silver, ivory, apes, and peacocks.'),
  ('1 Kings', 10, 23, 'So King Solomon exceeded all the kings of the earth in riches and in wisdom.'),
  ('1 Kings', 10, 24, 'All the earth sought the presence of Solomon to hear his wisdom which God had put in his heart.'),
  ('1 Kings', 10, 25, 'Year after year, every man brought his tribute, vessels of silver, vessels of gold, clothing, armor, spices, horses, and mules.'),
  ('1 Kings', 10, 26, 'Solomon gathered together chariots and horsemen. He had one thousand four hundred chariots and twelve thousand horsemen. He kept them in the chariot cities and with the king at Jerusalem.'),
  ('1 Kings', 10, 27, 'The king made silver as common as stones in Jerusalem, and cedars as common as the sycamore trees that are in the lowland.'),
  ('1 Kings', 10, 28, 'The horses which Solomon had were brought out of Egypt. The king’s merchants received them in droves, each drove at a price.'),
  ('1 Kings', 10, 29, 'A chariot was imported from Egypt for six hundred shekels of silver, and a horse for one hundred fifty shekels; and so they exported them to all the kings of the Hittites and to the kings of Syria.'),
  ('1 Kings', 11, 1, 'Now King Solomon loved many foreign women, together with the daughter of Pharaoh: women of the Moabites, Ammonites, Edomites, Sidonians, and Hittites,'),
  ('1 Kings', 11, 2, 'of the nations concerning which the LORD said to the children of Israel, “You shall not go among them, neither shall they come among you, for surely they will turn away your heart after their gods.” Solomon joined to these in love.'),
  ('1 Kings', 11, 3, 'He had seven hundred wives, princesses, and three hundred concubines. His wives turned his heart away.'),
  ('1 Kings', 11, 4, 'When Solomon was old, his wives turned away his heart after other gods; and his heart was not perfect with the LORD his God, as the heart of David his father was.'),
  ('1 Kings', 11, 5, 'For Solomon went after Ashtoreth the goddess of the Sidonians, and after Milcom the abomination of the Ammonites.'),
  ('1 Kings', 11, 6, 'Solomon did that which was evil in the LORD’s sight, and didn’t go fully after the LORD, as David his father did.'),
  ('1 Kings', 11, 7, 'Then Solomon built a high place for Chemosh the abomination of Moab, on the mountain that is before Jerusalem, and for Molech the abomination of the children of Ammon.'),
  ('1 Kings', 11, 8, 'So he did for all his foreign wives, who burned incense and sacrificed to their gods.'),
  ('1 Kings', 11, 9, 'The LORD was angry with Solomon, because his heart was turned away from the LORD, the God of Israel, who had appeared to him twice,'),
  ('1 Kings', 11, 10, 'and had commanded him concerning this thing, that he should not go after other gods; but he didn’t keep that which the LORD commanded.'),
  ('1 Kings', 11, 11, 'Therefore the LORD said to Solomon, “Because this is done by you, and you have not kept my covenant and my statutes, which I have commanded you, I will surely tear the kingdom from you, and will give it to your servant.'),
  ('1 Kings', 11, 12, 'Nevertheless, I will not do it in your days, for David your father’s sake; but I will tear it out of your son’s hand.'),
  ('1 Kings', 11, 13, 'However, I will not tear away all the kingdom; but I will give one tribe to your son, for David my servant’s sake, and for Jerusalem’s sake which I have chosen.”'),
  ('1 Kings', 11, 14, 'The LORD raised up an adversary to Solomon: Hadad the Edomite. He was one of the king’s offspring in Edom.'),
  ('1 Kings', 11, 15, 'For when David was in Edom, and Joab the captain of the army had gone up to bury the slain, and had struck every male in Edom'),
  ('1 Kings', 11, 16, '(for Joab and all Israel remained there six months, until he had cut off every male in Edom),'),
  ('1 Kings', 11, 17, 'Hadad fled, he and certain Edomites of his father’s servants with him, to go into Egypt, when Hadad was still a little child.'),
  ('1 Kings', 11, 18, 'They arose out of Midian and came to Paran; and they took men with them out of Paran, and they came to Egypt, to Pharaoh king of Egypt, who gave him a house, and appointed him food, and gave him land.'),
  ('1 Kings', 11, 19, 'Hadad found great favor in the sight of Pharaoh, so that he gave him as wife the sister of his own wife, the sister of Tahpenes the queen.'),
  ('1 Kings', 11, 20, 'The sister of Tahpenes bore him Genubath his son, whom Tahpenes weaned in Pharaoh’s house; and Genubath was in Pharaoh’s house among the sons of Pharaoh.'),
  ('1 Kings', 11, 21, 'When Hadad heard in Egypt that David slept with his fathers, and that Joab the captain of the army was dead, Hadad said to Pharaoh, “Let me depart, that I may go to my own country.”'),
  ('1 Kings', 11, 22, 'Then Pharaoh said to him, “But what have you lacked with me, that behold, you seek to go to your own country?” He answered, “Nothing, however only let me depart.”'),
  ('1 Kings', 11, 23, 'God raised up an adversary to him, Rezon the son of Eliada, who had fled from his lord, Hadadezer king of Zobah.'),
  ('1 Kings', 11, 24, 'He gathered men to himself, and became captain over a troop, when David killed them of Zobah. They went to Damascus and lived there, and reigned in Damascus.'),
  ('1 Kings', 11, 25, 'He was an adversary to Israel all the days of Solomon, in addition to the mischief of Hadad. He abhorred Israel, and reigned over Syria.'),
  ('1 Kings', 11, 26, 'Jeroboam the son of Nebat, an Ephraimite of Zeredah, a servant of Solomon, whose mother’s name was Zeruah, a widow, also lifted up his hand against the king.'),
  ('1 Kings', 11, 27, 'This was the reason why he lifted up his hand against the king: Solomon built Millo, and repaired the breach of his father David’s city.'),
  ('1 Kings', 11, 28, 'The man Jeroboam was a mighty man of valor; and Solomon saw that the young man was industrious, and he put him in charge of all the labor of the house of Joseph.'),
  ('1 Kings', 11, 29, 'At that time, when Jeroboam went out of Jerusalem, the prophet Ahijah the Shilonite found him on the way. Now Ahijah had clad himself with a new garment; and the two of them were alone in the field.'),
  ('1 Kings', 11, 30, 'Ahijah took the new garment that was on him, and tore it in twelve pieces.'),
  ('1 Kings', 11, 31, 'He said to Jeroboam, “Take ten pieces; for the LORD, the God of Israel, says, ‘Behold, I will tear the kingdom out of the hand of Solomon and will give ten tribes to you'),
  ('1 Kings', 11, 32, '(but he shall have one tribe, for my servant David’s sake and for Jerusalem’s sake, the city which I have chosen out of all the tribes of Israel),'),
  ('1 Kings', 11, 33, 'because they have forsaken me, and have worshiped Ashtoreth the goddess of the Sidonians, Chemosh the god of Moab, and Milcom the god of the children of Ammon. They have not walked in my ways, to do that which is right in my eyes, and to keep my statutes and my ordinances, as David his father did.'),
  ('1 Kings', 11, 34, '“‘However, I will not take the whole kingdom out of his hand, but I will make him prince all the days of his life for David my servant’s sake whom I chose, who kept my commandments and my statutes,'),
  ('1 Kings', 11, 35, 'but I will take the kingdom out of his son’s hand and will give it to you, even ten tribes.'),
  ('1 Kings', 11, 36, 'I will give one tribe to his son, that David my servant may have a lamp always before me in Jerusalem, the city which I have chosen for myself to put my name there.'),
  ('1 Kings', 11, 37, 'I will take you, and you shall reign according to all that your soul desires, and shall be king over Israel.'),
  ('1 Kings', 11, 38, 'It shall be, if you will listen to all that I command you, and will walk in my ways, and do that which is right in my eyes, to keep my statutes and my commandments, as David my servant did, that I will be with you, and will build you a sure house, as I built for David, and will give Israel to you.'),
  ('1 Kings', 11, 39, 'I will afflict the offspring of David for this, but not forever.’”'),
  ('1 Kings', 11, 40, 'Therefore Solomon sought to kill Jeroboam, but Jeroboam arose and fled into Egypt, to Shishak king of Egypt, and was in Egypt until the death of Solomon.'),
  ('1 Kings', 11, 41, 'Now the rest of the acts of Solomon, and all that he did, and his wisdom, aren’t they written in the book of the acts of Solomon?'),
  ('1 Kings', 11, 42, 'The time that Solomon reigned in Jerusalem over all Israel was forty years.'),
  ('1 Kings', 11, 43, 'Solomon slept with his fathers, and was buried in his father David’s city; and Rehoboam his son reigned in his place.'),
  ('1 Kings', 12, 1, 'Rehoboam went to Shechem, for all Israel had come to Shechem to make him king.'),
  ('1 Kings', 12, 2, 'When Jeroboam the son of Nebat heard of it (for he was yet in Egypt, where he had fled from the presence of King Solomon, and Jeroboam lived in Egypt;'),
  ('1 Kings', 12, 3, 'and they sent and called him), Jeroboam and all the assembly of Israel came, and spoke to Rehoboam, saying,'),
  ('1 Kings', 12, 4, '“Your father made our yoke difficult. Now therefore make the hard service of your father, and his heavy yoke which he put on us, lighter, and we will serve you.”'),
  ('1 Kings', 12, 5, 'He said to them, “Depart for three days, then come back to me.” So the people departed.'),
  ('1 Kings', 12, 6, 'King Rehoboam took counsel with the old men who had stood before Solomon his father while he yet lived, saying, “What counsel do you give me to answer these people?”'),
  ('1 Kings', 12, 7, 'They replied, “If you will be a servant to this people today, and will serve them, and answer them with good words, then they will be your servants forever.”'),
  ('1 Kings', 12, 8, 'But he abandoned the counsel of the old men which they had given him, and took counsel with the young men who had grown up with him, who stood before him.'),
  ('1 Kings', 12, 9, 'He said to them, “What counsel do you give, that we may answer these people who have spoken to me, saying, ‘Make the yoke that your father put on us lighter’?”'),
  ('1 Kings', 12, 10, 'The young men who had grown up with him said to him, “Tell these people who spoke to you, saying, ‘Your father made our yoke heavy, but make it lighter to us’—tell them, ‘My little finger is thicker than my father’s waist.'),
  ('1 Kings', 12, 11, 'Now my father burdened you with a heavy yoke, but I will add to your yoke. My father chastised you with whips, but I will chastise you with scorpions.’”'),
  ('1 Kings', 12, 12, 'So Jeroboam and all the people came to Rehoboam the third day, as the king asked, saying, “Come to me again the third day.”'),
  ('1 Kings', 12, 13, 'The king answered the people roughly, and abandoned the counsel of the old men which they had given him,'),
  ('1 Kings', 12, 14, 'and spoke to them according to the counsel of the young men, saying, “My father made your yoke heavy, but I will add to your yoke. My father chastised you with whips, but I will chastise you with scorpions.”'),
  ('1 Kings', 12, 15, 'So the king didn’t listen to the people; for it was a thing brought about from the LORD, that he might establish his word, which the LORD spoke by Ahijah the Shilonite to Jeroboam the son of Nebat.'),
  ('1 Kings', 12, 16, 'When all Israel saw that the king didn’t listen to them, the people answered the king, saying, “What portion have we in David? We don’t have an inheritance in the son of Jesse. To your tents, Israel! Now see to your own house, David.” So Israel departed to their tents.'),
  ('1 Kings', 12, 17, 'But as for the children of Israel who lived in the cities of Judah, Rehoboam reigned over them.'),
  ('1 Kings', 12, 18, 'Then King Rehoboam sent Adoram, who was over the men subject to forced labor; and all Israel stoned him to death with stones. King Rehoboam hurried to get himself up to his chariot, to flee to Jerusalem.'),
  ('1 Kings', 12, 19, 'So Israel rebelled against David’s house to this day.'),
  ('1 Kings', 12, 20, 'When all Israel heard that Jeroboam had returned, they sent and called him to the congregation, and made him king over all Israel. There was no one who followed David’s house, except for the tribe of Judah only.'),
  ('1 Kings', 12, 21, 'When Rehoboam had come to Jerusalem, he assembled all the house of Judah and the tribe of Benjamin, a hundred and eighty thousand chosen men who were warriors, to fight against the house of Israel, to bring the kingdom again to Rehoboam the son of Solomon.'),
  ('1 Kings', 12, 22, 'But the word of God came to Shemaiah the man of God, saying,'),
  ('1 Kings', 12, 23, '“Speak to Rehoboam the son of Solomon, king of Judah, and to all the house of Judah and Benjamin, and to the rest of the people, saying,'),
  ('1 Kings', 12, 24, '‘The LORD says, “You shall not go up or fight against your brothers, the children of Israel. Everyone return to his house; for this thing is from me.”’” So they listened to the LORD’s word, and returned and went their way, according to the LORD’s word.'),
  ('1 Kings', 12, 25, 'Then Jeroboam built Shechem in the hill country of Ephraim, and lived in it; and he went out from there and built Penuel.'),
  ('1 Kings', 12, 26, 'Jeroboam said in his heart, “Now the kingdom will return to David’s house.'),
  ('1 Kings', 12, 27, 'If this people goes up to offer sacrifices in the LORD’s house at Jerusalem, then the heart of this people will turn again to their lord, even to Rehoboam king of Judah; and they will kill me, and return to Rehoboam king of Judah.”'),
  ('1 Kings', 12, 28, 'So the king took counsel, and made two calves of gold; and he said to them, “It is too much for you to go up to Jerusalem. Look and behold your gods, Israel, which brought you up out of the land of Egypt!”'),
  ('1 Kings', 12, 29, 'He set the one in Bethel, and the other he put in Dan.'),
  ('1 Kings', 12, 30, 'This thing became a sin, for the people went even as far as Dan to worship before the one there.'),
  ('1 Kings', 12, 31, 'He made houses of high places, and made priests from among all the people, who were not of the sons of Levi.'),
  ('1 Kings', 12, 32, 'Jeroboam ordained a feast in the eighth month, on the fifteenth day of the month, like the feast that is in Judah, and he went up to the altar. He did so in Bethel, sacrificing to the calves that he had made, and he placed in Bethel the priests of the high places that he had made.'),
  ('1 Kings', 12, 33, 'He went up to the altar which he had made in Bethel on the fifteenth day in the eighth month, even in the month which he had devised of his own heart; and he ordained a feast for the children of Israel, and went up to the altar to burn incense.'),
  ('1 Kings', 13, 1, 'Behold, a man of God came out of Judah by the LORD’s word to Bethel; and Jeroboam was standing by the altar to burn incense.'),
  ('1 Kings', 13, 2, 'He cried against the altar by the LORD’s word, and said, “Altar! Altar! The LORD says: ‘Behold, a son will be born to David’s house, Josiah by name. On you he will sacrifice the priests of the high places who burn incense on you, and they will burn men’s bones on you.’”'),
  ('1 Kings', 13, 3, 'He gave a sign the same day, saying, “This is the sign which the LORD has spoken: Behold, the altar will be split apart, and the ashes that are on it will be poured out.”'),
  ('1 Kings', 13, 4, 'When the king heard the saying of the man of God, which he cried against the altar in Bethel, Jeroboam put out his hand from the altar, saying, “Seize him!” His hand, which he put out against him, dried up, so that he could not draw it back again to himself.'),
  ('1 Kings', 13, 5, 'The altar was also split apart, and the ashes poured out from the altar, according to the sign which the man of God had given by the LORD’s word.'),
  ('1 Kings', 13, 6, 'The king answered the man of God, “Now intercede for the favor of the LORD your God, and pray for me, that my hand may be restored to me.” The man of God interceded with the LORD, and the king’s hand was restored to him, and became as it was before.'),
  ('1 Kings', 13, 7, 'The king said to the man of God, “Come home with me and refresh yourself, and I will give you a reward.”'),
  ('1 Kings', 13, 8, 'The man of God said to the king, “Even if you gave me half of your house, I would not go in with you, neither would I eat bread nor drink water in this place;'),
  ('1 Kings', 13, 9, 'for so was it commanded me by the LORD’s word, saying, ‘You shall eat no bread, drink no water, and don’t return by the way that you came.’”'),
  ('1 Kings', 13, 10, 'So he went another way, and didn’t return by the way that he came to Bethel.'),
  ('1 Kings', 13, 11, 'Now an old prophet lived in Bethel, and one of his sons came and told him all the works that the man of God had done that day in Bethel. They also told their father the words which he had spoken to the king.'),
  ('1 Kings', 13, 12, 'Their father said to them, “Which way did he go?” Now his sons had seen which way the man of God went, who came from Judah.'),
  ('1 Kings', 13, 13, 'He said to his sons, “Saddle the donkey for me.” So they saddled the donkey for him; and he rode on it.'),
  ('1 Kings', 13, 14, 'He went after the man of God, and found him sitting under an oak. He said to him, “Are you the man of God who came from Judah?” He said, “I am.”'),
  ('1 Kings', 13, 15, 'Then he said to him, “Come home with me and eat bread.”');
INSERT INTO bible_verses (book_name, chapter, verse, text) VALUES
  ('1 Kings', 13, 16, 'He said, “I may not return with you, nor go in with you. I will not eat bread or drink water with you in this place.'),
  ('1 Kings', 13, 17, 'For it was said to me by the LORD’s word, ‘You shall eat no bread or drink water there, and don’t turn again to go by the way that you came.’”'),
  ('1 Kings', 13, 18, 'He said to him, “I also am a prophet as you are; and an angel spoke to me by the LORD’s word, saying, ‘Bring him back with you into your house, that he may eat bread and drink water.’” He lied to him.'),
  ('1 Kings', 13, 19, 'So he went back with him, ate bread in his house, and drank water.'),
  ('1 Kings', 13, 20, 'As they sat at the table, the LORD’s word came to the prophet who brought him back;'),
  ('1 Kings', 13, 21, 'and he cried out to the man of God who came from Judah, saying, “The LORD says, ‘Because you have been disobedient to the LORD’s word, and have not kept the commandment which the LORD your God commanded you,'),
  ('1 Kings', 13, 22, 'but came back, and have eaten bread and drank water in the place of which he said to you, “Eat no bread, and drink no water,” your body will not come to the tomb of your fathers.’”'),
  ('1 Kings', 13, 23, 'After he had eaten bread and after he drank, he saddled the donkey for the prophet whom he had brought back.'),
  ('1 Kings', 13, 24, 'When he had gone, a lion met him by the way and killed him. His body was thrown on the path, and the donkey stood by it. The lion also stood by the body.'),
  ('1 Kings', 13, 25, 'Behold, men passed by and saw the body thrown on the path, and the lion standing by the body; and they came and told it in the city where the old prophet lived.'),
  ('1 Kings', 13, 26, 'When the prophet who brought him back from the way heard of it, he said, “It is the man of God who was disobedient to the LORD’s word. Therefore the LORD has delivered him to the lion, which has mauled him and slain him, according to the LORD’s word which he spoke to him.”'),
  ('1 Kings', 13, 27, 'He said to his sons, saying, “Saddle the donkey for me,” and they saddled it.'),
  ('1 Kings', 13, 28, 'He went and found his body thrown on the path, and the donkey and the lion standing by the body. The lion had not eaten the body nor mauled the donkey.'),
  ('1 Kings', 13, 29, 'The prophet took up the body of the man of God, and laid it on the donkey, and brought it back. He came to the city of the old prophet to mourn, and to bury him.'),
  ('1 Kings', 13, 30, 'He laid his body in his own grave; and they mourned over him, saying, “Alas, my brother!”'),
  ('1 Kings', 13, 31, 'After he had buried him, he spoke to his sons, saying, “When I am dead, bury me in the tomb in which the man of God is buried. Lay my bones beside his bones.'),
  ('1 Kings', 13, 32, 'For the saying which he cried by the LORD’s word against the altar in Bethel, and against all the houses of the high places which are in the cities of Samaria, will surely happen.”'),
  ('1 Kings', 13, 33, 'After this thing, Jeroboam didn’t turn from his evil way, but again made priests of the high places from among all the people. Whoever wanted to, he consecrated him, that there might be priests of the high places.'),
  ('1 Kings', 13, 34, 'This thing became sin to the house of Jeroboam, even to cut it off and to destroy it from off the surface of the earth.'),
  ('1 Kings', 14, 1, 'At that time Abijah the son of Jeroboam became sick.'),
  ('1 Kings', 14, 2, 'Jeroboam said to his wife, “Please get up and disguise yourself, so that you won’t be recognized as Jeroboam’s wife. Go to Shiloh. Behold, Ahijah the prophet is there, who said that I would be king over this people.'),
  ('1 Kings', 14, 3, 'Take with you ten loaves of bread, some cakes, and a jar of honey, and go to him. He will tell you what will become of the child.”'),
  ('1 Kings', 14, 4, 'Jeroboam’s wife did so, and arose and went to Shiloh, and came to Ahijah’s house. Now Ahijah could not see, for his eyes were set by reason of his age.'),
  ('1 Kings', 14, 5, 'The LORD said to Ahijah, “Behold, Jeroboam’s wife is coming to inquire of you concerning her son, for he is sick. Tell her such and such; for it will be, when she comes in, that she will pretend to be another woman.”'),
  ('1 Kings', 14, 6, 'So when Ahijah heard the sound of her feet as she came in at the door, he said, “Come in, Jeroboam’s wife! Why do you pretend to be another? For I am sent to you with heavy news.'),
  ('1 Kings', 14, 7, 'Go, tell Jeroboam, ‘The LORD, the God of Israel, says: “Because I exalted you from among the people, and made you prince over my people Israel,'),
  ('1 Kings', 14, 8, 'and tore the kingdom away from David’s house, and gave it to you; and yet you have not been as my servant David, who kept my commandments, and who followed me with all his heart, to do that only which was right in my eyes,'),
  ('1 Kings', 14, 9, 'but have done evil above all who were before you, and have gone and made for yourself other gods, molten images, to provoke me to anger, and have cast me behind your back,'),
  ('1 Kings', 14, 10, 'therefore, behold, I will bring evil on the house of Jeroboam, and will cut off from Jeroboam everyone who urinates on a wall, he who is shut up and he who is left at large in Israel, and will utterly sweep away the house of Jeroboam, as a man sweeps away dung until it is all gone.'),
  ('1 Kings', 14, 11, 'The dogs will eat whoever belongs to Jeroboam who dies in the city; and the birds of the sky will eat whoever dies in the field, for the LORD has spoken it.”’'),
  ('1 Kings', 14, 12, 'Arise therefore, and go to your house. When your feet enter into the city, the child will die.'),
  ('1 Kings', 14, 13, 'All Israel will mourn for him and bury him; for he only of Jeroboam will come to the grave, because in him there is found some good thing toward the LORD, the God of Israel, in the house of Jeroboam.'),
  ('1 Kings', 14, 14, 'Moreover the LORD will raise up a king for himself over Israel who will cut off the house of Jeroboam. This is the day! What? Even now.'),
  ('1 Kings', 14, 15, 'For the LORD will strike Israel, as a reed is shaken in the water; and he will root up Israel out of this good land which he gave to their fathers, and will scatter them beyond the River, because they have made their Asherah poles, provoking the LORD to anger.'),
  ('1 Kings', 14, 16, 'He will give Israel up because of the sins of Jeroboam, which he has sinned, and with which he has made Israel to sin.”'),
  ('1 Kings', 14, 17, 'Jeroboam’s wife arose and departed, and came to Tirzah. As she came to the threshold of the house, the child died.'),
  ('1 Kings', 14, 18, 'All Israel buried him and mourned for him, according to the LORD’s word, which he spoke by his servant Ahijah the prophet.'),
  ('1 Kings', 14, 19, 'The rest of the acts of Jeroboam, how he fought and how he reigned, behold, they are written in the book of the chronicles of the kings of Israel.'),
  ('1 Kings', 14, 20, 'The days which Jeroboam reigned were twenty two years; then he slept with his fathers, and Nadab his son reigned in his place.'),
  ('1 Kings', 14, 21, 'Rehoboam the son of Solomon reigned in Judah. Rehoboam was forty-one years old when he began to reign, and he reigned seventeen years in Jerusalem, the city which the LORD had chosen out of all the tribes of Israel, to put his name there. His mother’s name was Naamah the Ammonitess.'),
  ('1 Kings', 14, 22, 'Judah did that which was evil in the LORD’s sight, and they provoked him to jealousy with their sins which they committed, above all that their fathers had done.'),
  ('1 Kings', 14, 23, 'For they also built for themselves high places, sacred pillars, and Asherah poles on every high hill and under every green tree.'),
  ('1 Kings', 14, 24, 'There were also sodomites in the land. They did according to all the abominations of the nations which the LORD drove out before the children of Israel.'),
  ('1 Kings', 14, 25, 'In the fifth year of King Rehoboam, Shishak king of Egypt came up against Jerusalem;'),
  ('1 Kings', 14, 26, 'and he took away the treasures of the LORD’s house and the treasures of the king’s house. He even took away all of it, including all the gold shields which Solomon had made.'),
  ('1 Kings', 14, 27, 'King Rehoboam made shields of bronze in their place, and committed them to the hands of the captains of the guard, who guarded the door of the king’s house.'),
  ('1 Kings', 14, 28, 'It was so, that as often as the king went into the LORD’s house, the guard bore them, and brought them back into the guard room.'),
  ('1 Kings', 14, 29, 'Now the rest of the acts of Rehoboam, and all that he did, aren’t they written in the book of the chronicles of the kings of Judah?'),
  ('1 Kings', 14, 30, 'There was war between Rehoboam and Jeroboam continually.'),
  ('1 Kings', 14, 31, 'Rehoboam slept with his fathers, and was buried with his fathers in David’s city. His mother’s name was Naamah the Ammonitess. Abijam his son reigned in his place.'),
  ('1 Kings', 15, 1, 'Now in the eighteenth year of King Jeroboam the son of Nebat, Abijam began to reign over Judah.'),
  ('1 Kings', 15, 2, 'He reigned three years in Jerusalem. His mother’s name was Maacah the daughter of Abishalom.'),
  ('1 Kings', 15, 3, 'He walked in all the sins of his father, which he had done before him; and his heart was not perfect with the LORD his God, as the heart of David his father.'),
  ('1 Kings', 15, 4, 'Nevertheless for David’s sake, the LORD his God gave him a lamp in Jerusalem, to set up his son after him and to establish Jerusalem;'),
  ('1 Kings', 15, 5, 'because David did that which was right in the LORD’s eyes, and didn’t turn away from anything that he commanded him all the days of his life, except only in the matter of Uriah the Hittite.'),
  ('1 Kings', 15, 6, 'Now there was war between Rehoboam and Jeroboam all the days of his life.'),
  ('1 Kings', 15, 7, 'The rest of the acts of Abijam, and all that he did, aren’t they written in the book of the chronicles of the kings of Judah? There was war between Abijam and Jeroboam.'),
  ('1 Kings', 15, 8, 'Abijam slept with his fathers, and they buried him in David’s city; and Asa his son reigned in his place.'),
  ('1 Kings', 15, 9, 'In the twentieth year of Jeroboam king of Israel, Asa began to reign over Judah.'),
  ('1 Kings', 15, 10, 'He reigned forty-one years in Jerusalem. His mother’s name was Maacah the daughter of Abishalom.'),
  ('1 Kings', 15, 11, 'Asa did that which was right in the LORD’s eyes, as David his father did.'),
  ('1 Kings', 15, 12, 'He put away the sodomites out of the land, and removed all the idols that his fathers had made.'),
  ('1 Kings', 15, 13, 'He also removed Maacah his mother from being queen, because she had made an abominable image for an Asherah. Asa cut down her image and burned it at the brook Kidron.'),
  ('1 Kings', 15, 14, 'But the high places were not taken away. Nevertheless the heart of Asa was perfect with the LORD all his days.'),
  ('1 Kings', 15, 15, 'He brought into the LORD’s house the things that his father had dedicated, and the things that he himself had dedicated: silver, gold, and utensils.'),
  ('1 Kings', 15, 16, 'There was war between Asa and Baasha king of Israel all their days.'),
  ('1 Kings', 15, 17, 'Baasha king of Israel went up against Judah, and built Ramah, that he might not allow anyone to go out or come in to Asa king of Judah.'),
  ('1 Kings', 15, 18, 'Then Asa took all the silver and the gold that was left in the treasures of the LORD’s house, and the treasures of the king’s house, and delivered it into the hand of his servants. Then King Asa sent them to Ben Hadad, the son of Tabrimmon, the son of Hezion, king of Syria, who lived at Damascus, saying,'),
  ('1 Kings', 15, 19, '“Let there be a treaty between me and you, like that between my father and your father. Behold, I have sent to you a present of silver and gold. Go, break your treaty with Baasha king of Israel, that he may depart from me.”'),
  ('1 Kings', 15, 20, 'Ben Hadad listened to King Asa, and sent the captains of his armies against the cities of Israel, and struck Ijon, and Dan, and Abel Beth Maacah, and all Chinneroth, with all the land of Naphtali.'),
  ('1 Kings', 15, 21, 'When Baasha heard of it, he stopped building Ramah, and lived in Tirzah.'),
  ('1 Kings', 15, 22, 'Then King Asa made a proclamation to all Judah. No one was exempted. They carried away the stones of Ramah, and its timber, with which Baasha had built; and King Asa used it to build Geba of Benjamin, and Mizpah.'),
  ('1 Kings', 15, 23, 'Now the rest of all the acts of Asa, and all his might, and all that he did, and the cities which he built, aren’t they written in the book of the chronicles of the kings of Judah? But in the time of his old age he was diseased in his feet.'),
  ('1 Kings', 15, 24, 'Asa slept with his fathers, and was buried with his fathers in his father David’s city; and Jehoshaphat his son reigned in his place.'),
  ('1 Kings', 15, 25, 'Nadab the son of Jeroboam began to reign over Israel in the second year of Asa king of Judah; and he reigned over Israel two years.'),
  ('1 Kings', 15, 26, 'He did that which was evil in the LORD’s sight, and walked in the way of his father, and in his sin with which he made Israel to sin.'),
  ('1 Kings', 15, 27, 'Baasha the son of Ahijah, of the house of Issachar, conspired against him; and Baasha struck him at Gibbethon, which belonged to the Philistines; for Nadab and all Israel were besieging Gibbethon.'),
  ('1 Kings', 15, 28, 'Even in the third year of Asa king of Judah, Baasha killed him and reigned in his place.'),
  ('1 Kings', 15, 29, 'As soon as he was king, he struck all the house of Jeroboam. He didn’t leave to Jeroboam any who breathed, until he had destroyed him, according to the saying of the LORD, which he spoke by his servant Ahijah the Shilonite;'),
  ('1 Kings', 15, 30, 'for the sins of Jeroboam which he sinned, and with which he made Israel to sin, because of his provocation with which he provoked the LORD, the God of Israel, to anger.'),
  ('1 Kings', 15, 31, 'Now the rest of the acts of Nadab, and all that he did, aren’t they written in the book of the chronicles of the kings of Israel?'),
  ('1 Kings', 15, 32, 'There was war between Asa and Baasha king of Israel all their days.'),
  ('1 Kings', 15, 33, 'In the third year of Asa king of Judah, Baasha the son of Ahijah began to reign over all Israel in Tirzah for twenty-four years.'),
  ('1 Kings', 15, 34, 'He did that which was evil in the LORD’s sight, and walked in the way of Jeroboam, and in his sin with which he made Israel to sin.'),
  ('1 Kings', 16, 1, 'The LORD’s word came to Jehu the son of Hanani against Baasha, saying,'),
  ('1 Kings', 16, 2, '“Because I exalted you out of the dust and made you prince over my people Israel, and you have walked in the way of Jeroboam and have made my people Israel to sin, to provoke me to anger with their sins,'),
  ('1 Kings', 16, 3, 'behold, I will utterly sweep away Baasha and his house; and I will make your house like the house of Jeroboam the son of Nebat.'),
  ('1 Kings', 16, 4, 'The dogs will eat Baasha’s descendants who die in the city; and he who dies of his in the field, the birds of the sky will eat.”'),
  ('1 Kings', 16, 5, 'Now the rest of the acts of Baasha, and what he did, and his might, aren’t they written in the book of the chronicles of the kings of Israel?'),
  ('1 Kings', 16, 6, 'Baasha slept with his fathers, and was buried in Tirzah; and Elah his son reigned in his place.'),
  ('1 Kings', 16, 7, 'Moreover the LORD’s word came by the prophet Jehu the son of Hanani against Baasha and against his house, both because of all the evil that he did in the LORD’s sight, to provoke him to anger with the work of his hands, in being like the house of Jeroboam, and because he struck him.'),
  ('1 Kings', 16, 8, 'In the twenty-sixth year of Asa king of Judah, Elah the son of Baasha began to reign over Israel in Tirzah for two years.'),
  ('1 Kings', 16, 9, 'His servant Zimri, captain of half his chariots, conspired against him. Now he was in Tirzah, drinking himself drunk in the house of Arza, who was over the household in Tirzah;'),
  ('1 Kings', 16, 10, 'and Zimri went in and struck him and killed him in the twenty-seventh year of Asa king of Judah, and reigned in his place.'),
  ('1 Kings', 16, 11, 'When he began to reign, as soon as he sat on his throne, he attacked all the house of Baasha. He didn’t leave him a single one who urinates on a wall among his relatives or his friends.'),
  ('1 Kings', 16, 12, 'Thus Zimri destroyed all the house of Baasha, according to the LORD’s word which he spoke against Baasha by Jehu the prophet,'),
  ('1 Kings', 16, 13, 'for all the sins of Baasha, and the sins of Elah his son, which they sinned and with which they made Israel to sin, to provoke the LORD, the God of Israel, to anger with their vanities.'),
  ('1 Kings', 16, 14, 'Now the rest of the acts of Elah, and all that he did, aren’t they written in the book of the chronicles of the kings of Israel?'),
  ('1 Kings', 16, 15, 'In the twenty-seventh year of Asa king of Judah, Zimri reigned seven days in Tirzah. Now the people were encamped against Gibbethon, which belonged to the Philistines.'),
  ('1 Kings', 16, 16, 'The people who were encamped heard that Zimri had conspired, and had also killed the king. Therefore all Israel made Omri, the captain of the army, king over Israel that day in the camp.');
INSERT INTO bible_verses (book_name, chapter, verse, text) VALUES
  ('1 Kings', 16, 17, 'Omri went up from Gibbethon, and all Israel with him, and they besieged Tirzah.'),
  ('1 Kings', 16, 18, 'When Zimri saw that the city was taken, he went into the fortified part of the king’s house and burned the king’s house over him with fire, and died,'),
  ('1 Kings', 16, 19, 'for his sins which he sinned in doing that which was evil in the LORD’s sight, in walking in the way of Jeroboam, and in his sin which he did to make Israel to sin.'),
  ('1 Kings', 16, 20, 'Now the rest of the acts of Zimri, and his treason that he committed, aren’t they written in the book of the chronicles of the kings of Israel?'),
  ('1 Kings', 16, 21, 'Then the people of Israel were divided into two parts: half of the people followed Tibni the son of Ginath, to make him king, and half followed Omri.'),
  ('1 Kings', 16, 22, 'But the people who followed Omri prevailed against the people who followed Tibni the son of Ginath; so Tibni died, and Omri reigned.'),
  ('1 Kings', 16, 23, 'In the thirty-first year of Asa king of Judah, Omri began to reign over Israel for twelve years. He reigned six years in Tirzah.'),
  ('1 Kings', 16, 24, 'He bought the hill Samaria of Shemer for two talents of silver; and he built on the hill, and called the name of the city which he built, Samaria, after the name of Shemer, the owner of the hill.'),
  ('1 Kings', 16, 25, 'Omri did that which was evil in the LORD’s sight, and dealt wickedly above all who were before him.'),
  ('1 Kings', 16, 26, 'For he walked in all the way of Jeroboam the son of Nebat, and in his sins with which he made Israel to sin, to provoke the LORD, the God of Israel, to anger with their vanities.'),
  ('1 Kings', 16, 27, 'Now the rest of the acts of Omri which he did, and his might that he showed, aren’t they written in the book of the chronicles of the kings of Israel?'),
  ('1 Kings', 16, 28, 'So Omri slept with his fathers, and was buried in Samaria; and Ahab his son reigned in his place.'),
  ('1 Kings', 16, 29, 'In the thirty-eighth year of Asa king of Judah, Ahab the son of Omri began to reign over Israel. Ahab the son of Omri reigned over Israel in Samaria twenty-two years.'),
  ('1 Kings', 16, 30, 'Ahab the son of Omri did that which was evil in the LORD’s sight above all that were before him.'),
  ('1 Kings', 16, 31, 'As if it had been a light thing for him to walk in the sins of Jeroboam the son of Nebat, he took as wife Jezebel the daughter of Ethbaal king of the Sidonians, and went and served Baal and worshiped him.'),
  ('1 Kings', 16, 32, 'He raised up an altar for Baal in the house of Baal, which he had built in Samaria.'),
  ('1 Kings', 16, 33, 'Ahab made the Asherah; and Ahab did more yet to provoke the LORD, the God of Israel, to anger than all the kings of Israel who were before him.'),
  ('1 Kings', 16, 34, 'In his days Hiel the Bethelite built Jericho. He laid its foundation with the loss of Abiram his firstborn, and set up its gates with the loss of his youngest son Segub, according to the LORD’s word, which he spoke by Joshua the son of Nun.'),
  ('1 Kings', 17, 1, 'Elijah the Tishbite, who was one of the settlers of Gilead, said to Ahab, “As the LORD, the God of Israel, lives, before whom I stand, there shall not be dew nor rain these years, but according to my word.”'),
  ('1 Kings', 17, 2, 'Then the LORD’s word came to him, saying,'),
  ('1 Kings', 17, 3, '“Go away from here, turn eastward, and hide yourself by the brook Cherith, that is before the Jordan.'),
  ('1 Kings', 17, 4, 'You shall drink from the brook. I have commanded the ravens to feed you there.”'),
  ('1 Kings', 17, 5, 'So he went and did according to the LORD’s word, for he went and lived by the brook Cherith that is before the Jordan.'),
  ('1 Kings', 17, 6, 'The ravens brought him bread and meat in the morning, and bread and meat in the evening; and he drank from the brook.'),
  ('1 Kings', 17, 7, 'After a while, the brook dried up, because there was no rain in the land.'),
  ('1 Kings', 17, 8, 'The LORD’s word came to him, saying,'),
  ('1 Kings', 17, 9, '“Arise, go to Zarephath, which belongs to Sidon, and stay there. Behold, I have commanded a widow there to sustain you.”'),
  ('1 Kings', 17, 10, 'So he arose and went to Zarephath; and when he came to the gate of the city, behold, a widow was there gathering sticks. He called to her and said, “Please get me a little water in a jar, that I may drink.”'),
  ('1 Kings', 17, 11, 'As she was going to get it, he called to her and said, “Please bring me a morsel of bread in your hand.”'),
  ('1 Kings', 17, 12, 'She said, “As the LORD your God lives, I don’t have anything baked, but only a handful of meal in a jar and a little oil in a jar. Behold, I am gathering two sticks, that I may go in and bake it for me and my son, that we may eat it, and die.”'),
  ('1 Kings', 17, 13, 'Elijah said to her, “Don’t be afraid. Go and do as you have said; but make me a little cake from it first, and bring it out to me, and afterward make some for you and for your son.'),
  ('1 Kings', 17, 14, 'For the LORD, the God of Israel, says, ‘The jar of meal will not run out, and the jar of oil will not fail, until the day that the LORD sends rain on the earth.’”'),
  ('1 Kings', 17, 15, 'She went and did according to the saying of Elijah; and she, he, and her household ate many days.'),
  ('1 Kings', 17, 16, 'The jar of meal didn’t run out and the jar of oil didn’t fail, according to the LORD’s word, which he spoke by Elijah.'),
  ('1 Kings', 17, 17, 'After these things, the son of the woman, the mistress of the house, became sick; and his sickness was so severe that there was no breath left in him.'),
  ('1 Kings', 17, 18, 'She said to Elijah, “What have I to do with you, you man of God? You have come to me to bring my sin to memory, and to kill my son!”'),
  ('1 Kings', 17, 19, 'He said to her, “Give me your son.” He took him out of her bosom, and carried him up into the room where he stayed, and laid him on his own bed.'),
  ('1 Kings', 17, 20, 'He cried to the LORD and said, “LORD my God, have you also brought evil on the widow with whom I am staying, by killing her son?”'),
  ('1 Kings', 17, 21, 'He stretched himself on the child three times, and cried to the LORD and said, “LORD my God, please let this child’s soul come into him again.”'),
  ('1 Kings', 17, 22, 'The LORD listened to the voice of Elijah; and the soul of the child came into him again, and he revived.'),
  ('1 Kings', 17, 23, 'Elijah took the child and brought him down out of the room into the house, and delivered him to his mother; and Elijah said, “Behold, your son lives.”'),
  ('1 Kings', 17, 24, 'The woman said to Elijah, “Now I know that you are a man of God, and that the LORD’s word in your mouth is truth.”'),
  ('1 Kings', 18, 1, 'After many days, the LORD’s word came to Elijah, in the third year, saying, “Go, show yourself to Ahab; and I will send rain on the earth.”'),
  ('1 Kings', 18, 2, 'Elijah went to show himself to Ahab. The famine was severe in Samaria.'),
  ('1 Kings', 18, 3, 'Ahab called Obadiah, who was over the household. (Now Obadiah feared the LORD greatly;'),
  ('1 Kings', 18, 4, 'for when Jezebel cut off the LORD’s prophets, Obadiah took one hundred prophets, and hid them fifty to a cave, and fed them with bread and water.)'),
  ('1 Kings', 18, 5, 'Ahab said to Obadiah, “Go through the land, to all the springs of water, and to all the brooks. Perhaps we may find grass and save the horses and mules alive, that we not lose all the animals.”'),
  ('1 Kings', 18, 6, 'So they divided the land between them to pass throughout it. Ahab went one way by himself, and Obadiah went another way by himself.'),
  ('1 Kings', 18, 7, 'As Obadiah was on the way, behold, Elijah met him. He recognized him, and fell on his face, and said, “Is it you, my lord Elijah?”'),
  ('1 Kings', 18, 8, 'He answered him, “It is I. Go, tell your lord, ‘Behold, Elijah is here!’”'),
  ('1 Kings', 18, 9, 'He said, “How have I sinned, that you would deliver your servant into the hand of Ahab, to kill me?'),
  ('1 Kings', 18, 10, 'As the LORD your God lives, there is no nation or kingdom where my lord has not sent to seek you. When they said, ‘He is not here,’ he took an oath of the kingdom and nation that they didn’t find you.'),
  ('1 Kings', 18, 11, 'Now you say, ‘Go, tell your lord, “Behold, Elijah is here.”’'),
  ('1 Kings', 18, 12, 'It will happen, as soon as I leave you, that the LORD’s Spirit will carry you I don’t know where; and so when I come and tell Ahab, and he can’t find you, he will kill me. But I, your servant, have feared the LORD from my youth.'),
  ('1 Kings', 18, 13, 'Wasn’t it told my lord what I did when Jezebel killed the LORD’s prophets, how I hid one hundred men of the LORD’s prophets with fifty to a cave, and fed them with bread and water?'),
  ('1 Kings', 18, 14, 'Now you say, ‘Go, tell your lord, “Behold, Elijah is here”.’ He will kill me.”'),
  ('1 Kings', 18, 15, 'Elijah said, “As the LORD of Armies lives, before whom I stand, I will surely show myself to him today.”'),
  ('1 Kings', 18, 16, 'So Obadiah went to meet Ahab, and told him; and Ahab went to meet Elijah.'),
  ('1 Kings', 18, 17, 'When Ahab saw Elijah, Ahab said to him, “Is that you, you troubler of Israel?”'),
  ('1 Kings', 18, 18, 'He answered, “I have not troubled Israel, but you and your father’s house, in that you have forsaken the LORD’s commandments and you have followed the Baals.'),
  ('1 Kings', 18, 19, 'Now therefore send, and gather to me all Israel to Mount Carmel, and four hundred fifty of the prophets of Baal, and four hundred of the prophets of the Asherah, who eat at Jezebel’s table.”'),
  ('1 Kings', 18, 20, 'So Ahab sent to all the children of Israel, and gathered the prophets together to Mount Carmel.'),
  ('1 Kings', 18, 21, 'Elijah came near to all the people, and said, “How long will you waver between the two sides? If the LORD is God, follow him; but if Baal, then follow him.” The people didn’t say a word.'),
  ('1 Kings', 18, 22, 'Then Elijah said to the people, “I, even I only, am left as a prophet of the LORD; but Baal’s prophets are four hundred fifty men.'),
  ('1 Kings', 18, 23, 'Let them therefore give us two bulls; and let them choose one bull for themselves, and cut it in pieces, and lay it on the wood, and put no fire under; and I will dress the other bull, and lay it on the wood, and put no fire under it.'),
  ('1 Kings', 18, 24, 'You call on the name of your god, and I will call on the LORD’s name. The God who answers by fire, let him be God.” All the people answered, “What you say is good.”'),
  ('1 Kings', 18, 25, 'Elijah said to the prophets of Baal, “Choose one bull for yourselves, and dress it first, for you are many; and call on the name of your god, but put no fire under it.”'),
  ('1 Kings', 18, 26, 'They took the bull which was given them, and they dressed it, and called on the name of Baal from morning even until noon, saying, “Baal, hear us!” But there was no voice, and nobody answered. They leaped about the altar which was made.'),
  ('1 Kings', 18, 27, 'At noon, Elijah mocked them, and said, “Cry aloud, for he is a god. Either he is deep in thought, or he has gone somewhere, or he is on a journey, or perhaps he sleeps and must be awakened.”'),
  ('1 Kings', 18, 28, 'They cried aloud, and cut themselves in their way with knives and lances until the blood gushed out on them.'),
  ('1 Kings', 18, 29, 'When midday was past, they prophesied until the time of the evening offering; but there was no voice, no answer, and nobody paid attention.'),
  ('1 Kings', 18, 30, 'Elijah said to all the people, “Come near to me!”; and all the people came near to him. He repaired the LORD’s altar that had been thrown down.'),
  ('1 Kings', 18, 31, 'Elijah took twelve stones, according to the number of the tribes of the sons of Jacob, to whom the LORD’s word came, saying, “Israel shall be your name.”'),
  ('1 Kings', 18, 32, 'With the stones he built an altar in the LORD’s name. He made a trench around the altar large enough to contain two seahs of seed.'),
  ('1 Kings', 18, 33, 'He put the wood in order, and cut the bull in pieces and laid it on the wood. He said, “Fill four jars with water, and pour it on the burnt offering and on the wood.”'),
  ('1 Kings', 18, 34, 'He said, “Do it a second time;” and they did it the second time. He said, “Do it a third time;” and they did it the third time.'),
  ('1 Kings', 18, 35, 'The water ran around the altar; and he also filled the trench with water.'),
  ('1 Kings', 18, 36, 'At the time of the evening offering, Elijah the prophet came near and said, “LORD, the God of Abraham, of Isaac, and of Israel, let it be known today that you are God in Israel and that I am your servant, and that I have done all these things at your word.'),
  ('1 Kings', 18, 37, 'Hear me, LORD, hear me, that this people may know that you, LORD, are God, and that you have turned their heart back again.”'),
  ('1 Kings', 18, 38, 'Then the LORD’s fire fell and consumed the burnt offering, the wood, the stones, and the dust; and it licked up the water that was in the trench.'),
  ('1 Kings', 18, 39, 'When all the people saw it, they fell on their faces. They said, “The LORD, he is God! The LORD, he is God!”'),
  ('1 Kings', 18, 40, 'Elijah said to them, “Seize the prophets of Baal! Don’t let one of them escape!” They seized them; and Elijah brought them down to the brook Kishon, and killed them there.'),
  ('1 Kings', 18, 41, 'Elijah said to Ahab, “Get up, eat and drink; for there is the sound of abundance of rain.”'),
  ('1 Kings', 18, 42, 'So Ahab went up to eat and to drink. Elijah went up to the top of Carmel; and he bowed himself down on the earth, and put his face between his knees.'),
  ('1 Kings', 18, 43, 'He said to his servant, “Go up now and look toward the sea.” He went up and looked, then said, “There is nothing.” He said, “Go again” seven times.'),
  ('1 Kings', 18, 44, 'On the seventh time, he said, “Behold, a small cloud, like a man’s hand, is rising out of the sea.” He said, “Go up, tell Ahab, ‘Get ready and go down, so that the rain doesn’t stop you.’”'),
  ('1 Kings', 18, 45, 'In a little while, the sky grew black with clouds and wind, and there was a great rain. Ahab rode, and went to Jezreel.'),
  ('1 Kings', 18, 46, 'The LORD’s hand was on Elijah; and he tucked his cloak into his belt and ran before Ahab to the entrance of Jezreel.'),
  ('1 Kings', 19, 1, 'Ahab told Jezebel all that Elijah had done, and how he had killed all the prophets with the sword.'),
  ('1 Kings', 19, 2, 'Then Jezebel sent a messenger to Elijah, saying, “So let the gods do to me, and more also, if I don’t make your life as the life of one of them by tomorrow about this time!”'),
  ('1 Kings', 19, 3, 'When he saw that, he arose and ran for his life, and came to Beersheba, which belongs to Judah, and left his servant there.'),
  ('1 Kings', 19, 4, 'But he himself went a day’s journey into the wilderness, and came and sat down under a juniper tree. Then he requested for himself that he might die, and said, “It is enough. Now, O LORD, take away my life; for I am not better than my fathers.”'),
  ('1 Kings', 19, 5, 'He lay down and slept under a juniper tree; and behold, an angel touched him, and said to him, “Arise and eat!”'),
  ('1 Kings', 19, 6, 'He looked, and behold, there was at his head a cake baked on the coals, and a jar of water. He ate and drank, and lay down again.'),
  ('1 Kings', 19, 7, 'The LORD’s angel came again the second time, and touched him, and said, “Arise and eat, because the journey is too great for you.”'),
  ('1 Kings', 19, 8, 'He arose, and ate and drank, and went in the strength of that food forty days and forty nights to Horeb, God’s Mountain.'),
  ('1 Kings', 19, 9, 'He came to a cave there, and camped there; and behold, the LORD’s word came to him, and he said to him, “What are you doing here, Elijah?”'),
  ('1 Kings', 19, 10, 'He said, “I have been very jealous for the LORD, the God of Armies; for the children of Israel have forsaken your covenant, thrown down your altars, and killed your prophets with the sword. I, even I only, am left; and they seek my life, to take it away.”'),
  ('1 Kings', 19, 11, 'He said, “Go out and stand on the mountain before the LORD.” Behold, the LORD passed by, and a great and strong wind tore the mountains and broke in pieces the rocks before the LORD; but the LORD was not in the wind. After the wind there was an earthquake; but the LORD was not in the earthquake.'),
  ('1 Kings', 19, 12, 'After the earthquake a fire passed; but the LORD was not in the fire. After the fire, there was a still small voice.');
INSERT INTO bible_verses (book_name, chapter, verse, text) VALUES
  ('1 Kings', 19, 13, 'When Elijah heard it, he wrapped his face in his mantle, went out, and stood in the entrance of the cave. Behold, a voice came to him, and said, “What are you doing here, Elijah?”'),
  ('1 Kings', 19, 14, 'He said, “I have been very jealous for the LORD, the God of Armies; for the children of Israel have forsaken your covenant, thrown down your altars, and killed your prophets with the sword. I, even I only, am left; and they seek my life, to take it away.”'),
  ('1 Kings', 19, 15, 'The LORD said to him, “Go, return on your way to the wilderness of Damascus. When you arrive, anoint Hazael to be king over Syria.'),
  ('1 Kings', 19, 16, 'Anoint Jehu the son of Nimshi to be king over Israel; and anoint Elisha the son of Shaphat of Abel Meholah to be prophet in your place.'),
  ('1 Kings', 19, 17, 'He who escapes from the sword of Hazael, Jehu will kill; and he who escapes from the sword of Jehu, Elisha will kill.'),
  ('1 Kings', 19, 18, 'Yet I reserved seven thousand in Israel, all the knees of which have not bowed to Baal, and every mouth that has not kissed him.”'),
  ('1 Kings', 19, 19, 'So he departed from there and found Elisha the son of Shaphat, who was plowing with twelve yoke of oxen before him, and he with the twelfth. Elijah went over to him and put his mantle on him.'),
  ('1 Kings', 19, 20, 'Elisha left the oxen and ran after Elijah, and said, “Let me please kiss my father and my mother, and then I will follow you.” He said to him, “Go back again; for what have I done to you?”'),
  ('1 Kings', 19, 21, 'He returned from following him, and took the yoke of oxen, killed them, and boiled their meat with the oxen’s equipment, and gave to the people; and they ate. Then he arose, and went after Elijah, and served him.'),
  ('1 Kings', 20, 1, 'Ben Hadad the king of Syria gathered all his army together; and there were thirty-two kings with him, with horses and chariots. He went up and besieged Samaria, and fought against it.'),
  ('1 Kings', 20, 2, 'He sent messengers into the city to Ahab king of Israel and said to him, “Ben Hadad says,'),
  ('1 Kings', 20, 3, '‘Your silver and your gold are mine. Your wives also and your children, even the best, are mine.’”'),
  ('1 Kings', 20, 4, 'The king of Israel answered, “It is according to your saying, my lord, O king. I am yours, and all that I have.”'),
  ('1 Kings', 20, 5, 'The messengers came again and said, “Ben Hadad says, ‘I sent indeed to you, saying, “You shall deliver me your silver, your gold, your wives, and your children;'),
  ('1 Kings', 20, 6, 'but I will send my servants to you tomorrow about this time, and they will search your house and the houses of your servants. Whatever is pleasant in your eyes, they will put it in their hand, and take it away.”’”'),
  ('1 Kings', 20, 7, 'Then the king of Israel called all the elders of the land, and said, “Please notice how this man seeks mischief; for he sent to me for my wives, and for my children, and for my silver, and for my gold; and I didn’t deny him.”'),
  ('1 Kings', 20, 8, 'All the elders and all the people said to him, “Don’t listen, and don’t consent.”'),
  ('1 Kings', 20, 9, 'Therefore he said to the messengers of Ben Hadad, “Tell my lord the king, ‘All that you sent for to your servant at the first I will do, but this thing I cannot do.’” The messengers departed and brought him back the message.'),
  ('1 Kings', 20, 10, 'Ben Hadad sent to him, and said, “The gods do so to me, and more also, if the dust of Samaria will be enough for handfuls for all the people who follow me.”'),
  ('1 Kings', 20, 11, 'The king of Israel answered, “Tell him, ‘Don’t let him who puts on his armor brag like he who takes it off.’”'),
  ('1 Kings', 20, 12, 'When Ben Hadad heard this message as he was drinking, he and the kings in the pavilions, he said to his servants, “Prepare to attack!” So they prepared to attack the city.'),
  ('1 Kings', 20, 13, 'Behold, a prophet came near to Ahab king of Israel, and said, “The LORD says, ‘Have you seen all this great multitude? Behold, I will deliver it into your hand today. Then you will know that I am the LORD.’”'),
  ('1 Kings', 20, 14, 'Ahab said, “By whom?” He said, “The LORD says, ‘By the young men of the princes of the provinces.’” Then he said, “Who shall begin the battle?” He answered, “You.”'),
  ('1 Kings', 20, 15, 'Then he mustered the young men of the princes of the provinces, and they were two hundred and thirty-two. After them, he mustered all the people, even all the children of Israel, being seven thousand.'),
  ('1 Kings', 20, 16, 'They went out at noon. But Ben Hadad was drinking himself drunk in the pavilions, he and the kings, the thirty-two kings who helped him.'),
  ('1 Kings', 20, 17, 'The young men of the princes of the provinces went out first; and Ben Hadad sent out, and they told him, saying, “Men are coming out from Samaria.”'),
  ('1 Kings', 20, 18, 'He said, “If they have come out for peace, take them alive; or if they have come out for war, take them alive.”'),
  ('1 Kings', 20, 19, 'So these went out of the city, the young men of the princes of the provinces, and the army which followed them.'),
  ('1 Kings', 20, 20, 'They each killed his man. The Syrians fled, and Israel pursued them. Ben Hadad the king of Syria escaped on a horse with horsemen.'),
  ('1 Kings', 20, 21, 'The king of Israel went out and struck the horses and chariots, and killed the Syrians with a great slaughter.'),
  ('1 Kings', 20, 22, 'The prophet came near to the king of Israel and said to him, “Go, strengthen yourself, and plan what you must do, for at the return of the year, the king of Syria will come up against you.”'),
  ('1 Kings', 20, 23, 'The servants of the king of Syria said to him, “Their god is a god of the hills; therefore they were stronger than we. But let’s fight against them in the plain, and surely we will be stronger than they.'),
  ('1 Kings', 20, 24, 'Do this thing: take the kings away, every man out of his place, and put captains in their place.'),
  ('1 Kings', 20, 25, 'Muster an army like the army that you have lost, horse for horse and chariot for chariot. We will fight against them in the plain, and surely we will be stronger than they are.” He listened to their voice and did so.'),
  ('1 Kings', 20, 26, 'At the return of the year, Ben Hadad mustered the Syrians and went up to Aphek to fight against Israel.'),
  ('1 Kings', 20, 27, 'The children of Israel were mustered and given provisions, and went against them. The children of Israel encamped before them like two little flocks of young goats, but the Syrians filled the country.'),
  ('1 Kings', 20, 28, 'A man of God came near and spoke to the king of Israel, and said, “The LORD says, ‘Because the Syrians have said, “The LORD is a god of the hills, but he is not a god of the valleys,” therefore I will deliver all this great multitude into your hand, and you shall know that I am the LORD.’”'),
  ('1 Kings', 20, 29, 'They encamped opposite each other for seven days. Then on the seventh day the battle was joined; and the children of Israel killed one hundred thousand footmen of the Syrians in one day.'),
  ('1 Kings', 20, 30, 'But the rest fled to Aphek, into the city; and the wall fell on twenty-seven thousand men who were left. Ben Hadad fled and came into the city, into an inner room.'),
  ('1 Kings', 20, 31, 'His servants said to him, “See now, we have heard that the kings of the house of Israel are merciful kings. Please let us put sackcloth on our bodies and ropes on our heads, and go out to the king of Israel. Maybe he will save your life.”'),
  ('1 Kings', 20, 32, 'So they put sackcloth on their bodies and ropes on their heads, and came to the king of Israel, and said, “Your servant Ben Hadad says, ‘Please let me live.’” He said, “Is he still alive? He is my brother.”'),
  ('1 Kings', 20, 33, 'Now the men observed diligently and hurried to take this phrase; and they said, “Your brother Ben Hadad.” Then he said, “Go, bring him.” Then Ben Hadad came out to him; and he caused him to come up into the chariot.'),
  ('1 Kings', 20, 34, 'Ben Hadad said to him, “The cities which my father took from your father I will restore. You shall make streets for yourself in Damascus, as my father made in Samaria.” “I”, said Ahab, “will let you go with this covenant.” So he made a covenant with him and let him go.'),
  ('1 Kings', 20, 35, 'A certain man of the sons of the prophets said to his fellow by the LORD’s word, “Please strike me!” The man refused to strike him.'),
  ('1 Kings', 20, 36, 'Then he said to him, “Because you have not obeyed the LORD’s voice, behold, as soon as you have departed from me, a lion will kill you.” As soon as he had departed from him, a lion found him and killed him.'),
  ('1 Kings', 20, 37, 'Then he found another man, and said, “Please strike me.” The man struck him and wounded him.'),
  ('1 Kings', 20, 38, 'So the prophet departed and waited for the king by the way, and disguised himself with his headband over his eyes.'),
  ('1 Kings', 20, 39, 'As the king passed by, he cried to the king, and he said, “Your servant went out into the middle of the battle; and behold, a man came over and brought a man to me, and said, ‘Guard this man! If by any means he is missing, then your life shall be for his life, or else you shall pay a talent of silver.’'),
  ('1 Kings', 20, 40, 'As your servant was busy here and there, he was gone.” The king of Israel said to him, “So shall your judgment be. You yourself have decided it.”'),
  ('1 Kings', 20, 41, 'He hurried, and took the headband away from his eyes; and the king of Israel recognized that he was one of the prophets.'),
  ('1 Kings', 20, 42, 'He said to him, “The LORD says, ‘Because you have let go out of your hand the man whom I had devoted to destruction, therefore your life will take the place of his life, and your people take the place of his people.’”'),
  ('1 Kings', 20, 43, 'The king of Israel went to his house sullen and angry, and came to Samaria.'),
  ('1 Kings', 21, 1, 'After these things, Naboth the Jezreelite had a vineyard which was in Jezreel, next to the palace of Ahab king of Samaria.'),
  ('1 Kings', 21, 2, 'Ahab spoke to Naboth, saying, “Give me your vineyard, that I may have it for a garden of herbs, because it is near my house; and I will give you for it a better vineyard than it. Or, if it seems good to you, I will give you its worth in money.”'),
  ('1 Kings', 21, 3, 'Naboth said to Ahab, “May the LORD forbid me, that I should give the inheritance of my fathers to you!”'),
  ('1 Kings', 21, 4, 'Ahab came into his house sullen and angry because of the word which Naboth the Jezreelite had spoken to him, for he had said, “I will not give you the inheritance of my fathers.” He laid himself down on his bed, and turned away his face, and would eat no bread.'),
  ('1 Kings', 21, 5, 'But Jezebel his wife came to him, and said to him, “Why is your spirit so sad that you eat no bread?”'),
  ('1 Kings', 21, 6, 'He said to her, “Because I spoke to Naboth the Jezreelite, and said to him, ‘Give me your vineyard for money; or else, if it pleases you, I will give you another vineyard for it.’ He answered, ‘I will not give you my vineyard.’”'),
  ('1 Kings', 21, 7, 'Jezebel his wife said to him, “Do you now govern the kingdom of Israel? Arise, and eat bread, and let your heart be merry. I will give you the vineyard of Naboth the Jezreelite.”'),
  ('1 Kings', 21, 8, 'So she wrote letters in Ahab’s name and sealed them with his seal, and sent the letters to the elders and to the nobles who were in his city, who lived with Naboth.'),
  ('1 Kings', 21, 9, 'She wrote in the letters, saying, “Proclaim a fast, and set Naboth on high among the people.'),
  ('1 Kings', 21, 10, 'Set two men, wicked fellows, before him, and let them testify against him, saying, ‘You cursed God and the king!’ Then carry him out, and stone him to death.”'),
  ('1 Kings', 21, 11, 'The men of his city, even the elders and the nobles who lived in his city, did as Jezebel had instructed them in the letters which she had written and sent to them.'),
  ('1 Kings', 21, 12, 'They proclaimed a fast, and set Naboth on high among the people.'),
  ('1 Kings', 21, 13, 'The two men, the wicked fellows, came in and sat before him. The wicked fellows testified against him, even against Naboth, in the presence of the people, saying, “Naboth cursed God and the king!” Then they carried him out of the city and stoned him to death with stones.'),
  ('1 Kings', 21, 14, 'Then they sent to Jezebel, saying, “Naboth has been stoned and is dead.”'),
  ('1 Kings', 21, 15, 'When Jezebel heard that Naboth had been stoned and was dead, Jezebel said to Ahab, “Arise, take possession of the vineyard of Naboth the Jezreelite, which he refused to give you for money; for Naboth is not alive, but dead.”'),
  ('1 Kings', 21, 16, 'When Ahab heard that Naboth was dead, Ahab rose up to go down to the vineyard of Naboth the Jezreelite, to take possession of it.'),
  ('1 Kings', 21, 17, 'The LORD’s word came to Elijah the Tishbite, saying,'),
  ('1 Kings', 21, 18, '“Arise, go down to meet Ahab king of Israel, who dwells in Samaria. Behold, he is in the vineyard of Naboth, where he has gone down to take possession of it.'),
  ('1 Kings', 21, 19, 'You shall speak to him, saying, ‘The LORD says, “Have you killed and also taken possession?”’ You shall speak to him, saying, ‘The LORD says, “In the place where dogs licked the blood of Naboth, dogs will lick your blood, even yours.”’”'),
  ('1 Kings', 21, 20, 'Ahab said to Elijah, “Have you found me, my enemy?” He answered, “I have found you, because you have sold yourself to do that which is evil in the LORD’s sight.'),
  ('1 Kings', 21, 21, 'Behold, I will bring evil on you, and will utterly sweep you away and will cut off from Ahab everyone who urinates against a wall, and him who is shut up and him who is left at large in Israel.'),
  ('1 Kings', 21, 22, 'I will make your house like the house of Jeroboam the son of Nebat, and like the house of Baasha the son of Ahijah, for the provocation with which you have provoked me to anger, and have made Israel to sin.”'),
  ('1 Kings', 21, 23, 'The LORD also spoke of Jezebel, saying, “The dogs will eat Jezebel by the rampart of Jezreel.'),
  ('1 Kings', 21, 24, 'The dogs will eat whoever dies of Ahab in the city; and the birds of the sky will eat whoever dies in the field.”'),
  ('1 Kings', 21, 25, 'But there was no one like Ahab, who sold himself to do that which was evil in the LORD’s sight, whom Jezebel his wife stirred up.'),
  ('1 Kings', 21, 26, 'He did very abominably in following idols, according to all that the Amorites did, whom the LORD cast out before the children of Israel.'),
  ('1 Kings', 21, 27, 'When Ahab heard those words, he tore his clothes, put sackcloth on his body, fasted, lay in sackcloth, and went about despondently.'),
  ('1 Kings', 21, 28, 'The LORD’s word came to Elijah the Tishbite, saying,'),
  ('1 Kings', 21, 29, '“See how Ahab humbles himself before me? Because he humbles himself before me, I will not bring the evil in his days; but I will bring the evil on his house in his son’s day.”'),
  ('1 Kings', 22, 1, 'They continued three years without war between Syria and Israel.'),
  ('1 Kings', 22, 2, 'In the third year, Jehoshaphat the king of Judah came down to the king of Israel.'),
  ('1 Kings', 22, 3, 'The king of Israel said to his servants, “You know that Ramoth Gilead is ours, and we do nothing, and don’t take it out of the hand of the king of Syria?”'),
  ('1 Kings', 22, 4, 'He said to Jehoshaphat, “Will you go with me to battle to Ramoth Gilead?” Jehoshaphat said to the king of Israel, “I am as you are, my people as your people, my horses as your horses.”'),
  ('1 Kings', 22, 5, 'Jehoshaphat said to the king of Israel, “Please inquire first for the LORD’s word.”'),
  ('1 Kings', 22, 6, 'Then the king of Israel gathered the prophets together, about four hundred men, and said to them, “Should I go against Ramoth Gilead to battle, or should I refrain?” They said, “Go up; for the Lord will deliver it into the hand of the king.”'),
  ('1 Kings', 22, 7, 'But Jehoshaphat said, “Isn’t there here a prophet of the LORD, that we may inquire of him?”'),
  ('1 Kings', 22, 8, 'The king of Israel said to Jehoshaphat, “There is yet one man by whom we may inquire of the LORD, Micaiah the son of Imlah; but I hate him, for he does not prophesy good concerning me, but evil.” Jehoshaphat said, “Don’t let the king say so.”'),
  ('1 Kings', 22, 9, 'Then the king of Israel called an officer, and said, “Quickly get Micaiah the son of Imlah.”'),
  ('1 Kings', 22, 10, 'Now the king of Israel and Jehoshaphat the king of Judah were sitting each on his throne, arrayed in their robes, in an open place at the entrance of the gate of Samaria; and all the prophets were prophesying before them.'),
  ('1 Kings', 22, 11, 'Zedekiah the son of Chenaanah made himself horns of iron, and said, “The LORD says, ‘With these you will push the Syrians, until they are consumed.’”'),
  ('1 Kings', 22, 12, 'All the prophets prophesied so, saying, “Go up to Ramoth Gilead and prosper; for the LORD will deliver it into the hand of the king.”'),
  ('1 Kings', 22, 13, 'The messenger who went to call Micaiah spoke to him, saying, “See now, the prophets declare good to the king with one mouth. Please let your word be like the word of one of them, and speak good.”'),
  ('1 Kings', 22, 14, 'Micaiah said, “As the LORD lives, what the LORD says to me, that I will speak.”'),
  ('1 Kings', 22, 15, 'When he had come to the king, the king said to him, “Micaiah, shall we go to Ramoth Gilead to battle, or shall we forbear?” He answered him, “Go up and prosper; and the LORD will deliver it into the hand of the king.”'),
  ('1 Kings', 22, 16, 'The king said to him, “How many times do I have to adjure you that you speak to me nothing but the truth in the LORD’s name?”'),
  ('1 Kings', 22, 17, 'He said, “I saw all Israel scattered on the mountains, as sheep that have no shepherd. The LORD said, ‘These have no master. Let them each return to his house in peace.’”'),
  ('1 Kings', 22, 18, 'The king of Israel said to Jehoshaphat, “Didn’t I tell you that he would not prophesy good concerning me, but evil?”'),
  ('1 Kings', 22, 19, 'Micaiah said, “Therefore hear the LORD’s word. I saw the LORD sitting on his throne, and all the army of heaven standing by him on his right hand and on his left.');
INSERT INTO bible_verses (book_name, chapter, verse, text) VALUES
  ('1 Kings', 22, 20, 'The LORD said, ‘Who will entice Ahab, that he may go up and fall at Ramoth Gilead?’ One said one thing, and another said another.'),
  ('1 Kings', 22, 21, 'A spirit came out and stood before the LORD, and said, ‘I will entice him.’'),
  ('1 Kings', 22, 22, 'The LORD said to him, ‘How?’ He said, ‘I will go out and will be a lying spirit in the mouth of all his prophets.’ He said, ‘You will entice him, and will also prevail. Go out and do so.’'),
  ('1 Kings', 22, 23, 'Now therefore, behold, the LORD has put a lying spirit in the mouth of all these your prophets; and the LORD has spoken evil concerning you.”'),
  ('1 Kings', 22, 24, 'Then Zedekiah the son of Chenaanah came near and struck Micaiah on the cheek, and said, “Which way did the LORD’s Spirit go from me to speak to you?”'),
  ('1 Kings', 22, 25, 'Micaiah said, “Behold, you will see on that day when you go into an inner room to hide yourself.”'),
  ('1 Kings', 22, 26, 'The king of Israel said, “Take Micaiah, and carry him back to Amon the governor of the city and to Joash the king’s son.'),
  ('1 Kings', 22, 27, 'Say, ‘The king says, “Put this fellow in the prison, and feed him with bread of affliction and with water of affliction, until I come in peace.”’”'),
  ('1 Kings', 22, 28, 'Micaiah said, “If you return at all in peace, the LORD has not spoken by me.” He said, “Listen, all you people!”'),
  ('1 Kings', 22, 29, 'So the king of Israel and Jehoshaphat the king of Judah went up to Ramoth Gilead.'),
  ('1 Kings', 22, 30, 'The king of Israel said to Jehoshaphat, “I will disguise myself and go into the battle, but you put on your robes.” The king of Israel disguised himself and went into the battle.'),
  ('1 Kings', 22, 31, 'Now the king of Syria had commanded the thirty-two captains of his chariots, saying, “Don’t fight with small nor great, except only with the king of Israel.”'),
  ('1 Kings', 22, 32, 'When the captains of the chariots saw Jehoshaphat, they said, “Surely that is the king of Israel!” and they came over to fight against him. Jehoshaphat cried out.'),
  ('1 Kings', 22, 33, 'When the captains of the chariots saw that it was not the king of Israel, they turned back from pursuing him.'),
  ('1 Kings', 22, 34, 'A certain man drew his bow at random, and struck the king of Israel between the joints of the armor. Therefore he said to the driver of his chariot, “Turn around, and carry me out of the battle, for I am severely wounded.”'),
  ('1 Kings', 22, 35, 'The battle increased that day. The king was propped up in his chariot facing the Syrians, and died at evening. The blood ran out of the wound into the bottom of the chariot.'),
  ('1 Kings', 22, 36, 'A cry went throughout the army about the going down of the sun, saying, “Every man to his city, and every man to his country!”'),
  ('1 Kings', 22, 37, 'So the king died, and was brought to Samaria; and they buried the king in Samaria.'),
  ('1 Kings', 22, 38, 'They washed the chariot by the pool of Samaria; and the dogs licked up his blood where the prostitutes washed themselves, according to the LORD’s word which he spoke.'),
  ('1 Kings', 22, 39, 'Now the rest of the acts of Ahab, and all that he did, and the ivory house which he built, and all the cities that he built, aren’t they written in the book of the chronicles of the kings of Israel?'),
  ('1 Kings', 22, 40, 'So Ahab slept with his fathers; and Ahaziah his son reigned in his place.'),
  ('1 Kings', 22, 41, 'Jehoshaphat the son of Asa began to reign over Judah in the fourth year of Ahab king of Israel.'),
  ('1 Kings', 22, 42, 'Jehoshaphat was thirty-five years old when he began to reign; and he reigned twenty-five years in Jerusalem. His mother’s name was Azubah the daughter of Shilhi.'),
  ('1 Kings', 22, 43, 'He walked in all the way of Asa his father. He didn’t turn away from it, doing that which was right in the LORD’s eyes. However, the high places were not taken away. The people still sacrificed and burned incense on the high places.'),
  ('1 Kings', 22, 44, 'Jehoshaphat made peace with the king of Israel.'),
  ('1 Kings', 22, 45, 'Now the rest of the acts of Jehoshaphat, and his might that he showed, and how he fought, aren’t they written in the book of the chronicles of the kings of Judah?'),
  ('1 Kings', 22, 46, 'The remnant of the sodomites, that remained in the days of his father Asa, he put away out of the land.'),
  ('1 Kings', 22, 47, 'There was no king in Edom. A deputy ruled.'),
  ('1 Kings', 22, 48, 'Jehoshaphat made ships of Tarshish to go to Ophir for gold, but they didn’t go, for the ships wrecked at Ezion Geber.'),
  ('1 Kings', 22, 49, 'Then Ahaziah the son of Ahab said to Jehoshaphat, “Let my servants go with your servants in the ships.” But Jehoshaphat would not.'),
  ('1 Kings', 22, 50, 'Jehoshaphat slept with his fathers, and was buried with his fathers in his father David’s city. Jehoram his son reigned in his place.'),
  ('1 Kings', 22, 51, 'Ahaziah the son of Ahab began to reign over Israel in Samaria in the seventeenth year of Jehoshaphat king of Judah, and he reigned two years over Israel.'),
  ('1 Kings', 22, 52, 'He did that which was evil in the LORD’s sight, and walked in the way of his father, and in the way of his mother, and in the way of Jeroboam the son of Nebat, in which he made Israel to sin.'),
  ('1 Kings', 22, 53, 'He served Baal and worshiped him, and provoked the LORD, the God of Israel, to anger in all the ways that his father had done so.'),
  ('2 Kings', 1, 1, 'Moab rebelled against Israel after the death of Ahab.'),
  ('2 Kings', 1, 2, 'Ahaziah fell down through the lattice in his upper room that was in Samaria, and was sick. So he sent messengers, and said to them, “Go, inquire of Baal Zebub, the god of Ekron, whether I will recover of this sickness.”'),
  ('2 Kings', 1, 3, 'But the LORD’s angel said to Elijah the Tishbite, “Arise, go up to meet the messengers of the king of Samaria, and tell them, ‘Is it because there is no God in Israel that you go to inquire of Baal Zebub, the god of Ekron?'),
  ('2 Kings', 1, 4, 'Now therefore the LORD says, “You will not come down from the bed where you have gone up, but you will surely die.”’” Then Elijah departed.'),
  ('2 Kings', 1, 5, 'The messengers returned to him, and he said to them, “Why is it that you have returned?”'),
  ('2 Kings', 1, 6, 'They said to him, “A man came up to meet us, and said to us, ‘Go, return to the king who sent you, and tell him, “The LORD says, ‘Is it because there is no God in Israel that you send to inquire of Baal Zebub, the god of Ekron? Therefore you will not come down from the bed where you have gone up, but you will surely die.’”’”'),
  ('2 Kings', 1, 7, 'He said to them, “What kind of man was he who came up to meet you and told you these words?”'),
  ('2 Kings', 1, 8, 'They answered him, “He was a hairy man, and wearing a leather belt around his waist.” He said, “It’s Elijah the Tishbite.”'),
  ('2 Kings', 1, 9, 'Then the king sent a captain of fifty with his fifty to him. He went up to him; and behold, he was sitting on the top of the hill. He said to him, “Man of God, the king has said, ‘Come down!’”'),
  ('2 Kings', 1, 10, 'Elijah answered to the captain of fifty, “If I am a man of God, then let fire come down from the sky and consume you and your fifty!” Then fire came down from the sky, and consumed him and his fifty.'),
  ('2 Kings', 1, 11, 'Again he sent to him another captain of fifty with his fifty. He answered him, “Man of God, the king has said, ‘Come down quickly!’”'),
  ('2 Kings', 1, 12, 'Elijah answered them, “If I am a man of God, then let fire come down from the sky and consume you and your fifty!” Then God’s fire came down from the sky, and consumed him and his fifty.'),
  ('2 Kings', 1, 13, 'Again he sent the captain of a third fifty with his fifty. The third captain of fifty went up, and came and fell on his knees before Elijah, and begged him, and said to him, “Man of God, please let my life and the life of these fifty of your servants be precious in your sight.'),
  ('2 Kings', 1, 14, 'Behold, fire came down from the sky and consumed the last two captains of fifty with their fifties. But now let my life be precious in your sight.”'),
  ('2 Kings', 1, 15, 'The LORD’s angel said to Elijah, “Go down with him. Don’t be afraid of him.” Then he arose and went down with him to the king.'),
  ('2 Kings', 1, 16, 'He said to him, “The LORD says, ‘Because you have sent messengers to inquire of Baal Zebub, the god of Ekron, is it because there is no God in Israel to inquire of his word? Therefore you will not come down from the bed where you have gone up, but you will surely die.’”'),
  ('2 Kings', 1, 17, 'So he died according to the LORD’s word which Elijah had spoken. Jehoram began to reign in his place in the second year of Jehoram the son of Jehoshaphat king of Judah, because he had no son.'),
  ('2 Kings', 1, 18, 'Now the rest of the acts of Ahaziah which he did, aren’t they written in the book of the chronicles of the kings of Israel?'),
  ('2 Kings', 2, 1, 'When the LORD was about to take Elijah up by a whirlwind into heaven, Elijah went with Elisha from Gilgal.'),
  ('2 Kings', 2, 2, 'Elijah said to Elisha, “Please wait here, for the LORD has sent me as far as Bethel.” Elisha said, “As the LORD lives, and as your soul lives, I will not leave you.” So they went down to Bethel.'),
  ('2 Kings', 2, 3, 'The sons of the prophets who were at Bethel came out to Elisha, and said to him, “Do you know that the LORD will take away your master from over you today?” He said, “Yes, I know it. Hold your peace.”'),
  ('2 Kings', 2, 4, 'Elijah said to him, “Elisha, please wait here, for the LORD has sent me to Jericho.” He said, “As the LORD lives, and as your soul lives, I will not leave you.” So they came to Jericho.'),
  ('2 Kings', 2, 5, 'The sons of the prophets who were at Jericho came near to Elisha, and said to him, “Do you know that the LORD will take away your master from over you today?” He answered, “Yes, I know it. Hold your peace.”'),
  ('2 Kings', 2, 6, 'Elijah said to him, “Please wait here, for the LORD has sent me to the Jordan.” He said, “As the LORD lives, and as your soul lives, I will not leave you.” Then they both went on.'),
  ('2 Kings', 2, 7, 'Fifty men of the sons of the prophets went and stood opposite them at a distance; and they both stood by the Jordan.'),
  ('2 Kings', 2, 8, 'Elijah took his mantle, and rolled it up, and struck the waters; and they were divided here and there, so that they both went over on dry ground.'),
  ('2 Kings', 2, 9, 'When they had gone over, Elijah said to Elisha, “Ask what I shall do for you, before I am taken from you.” Elisha said, “Please let a double portion of your spirit be on me.”'),
  ('2 Kings', 2, 10, 'He said, “You have asked a hard thing. If you see me when I am taken from you, it will be so for you; but if not, it will not be so.”'),
  ('2 Kings', 2, 11, 'As they continued on and talked, behold, a chariot of fire and horses of fire separated them; and Elijah went up by a whirlwind into heaven.'),
  ('2 Kings', 2, 12, 'Elisha saw it, and he cried, “My father, my father, the chariots of Israel and its horsemen!” He saw him no more. Then he took hold of his own clothes and tore them in two pieces.'),
  ('2 Kings', 2, 13, 'He also took up Elijah’s mantle that fell from him, and went back and stood by the bank of the Jordan.'),
  ('2 Kings', 2, 14, 'He took Elijah’s mantle that fell from him, and struck the waters, and said, “Where is the LORD, the God of Elijah?” When he also had struck the waters, they were divided apart, and Elisha went over.'),
  ('2 Kings', 2, 15, 'When the sons of the prophets who were at Jericho facing him saw him, they said, “The spirit of Elijah rests on Elisha.” They came to meet him, and bowed themselves to the ground before him.'),
  ('2 Kings', 2, 16, 'They said to him, “See now, there are with your servants fifty strong men. Please let them go and seek your master. Perhaps the LORD’s Spirit has taken him up, and put him on some mountain or into some valley.” He said, “Don’t send them.”'),
  ('2 Kings', 2, 17, 'When they urged him until he was ashamed, he said, “Send them.” Therefore they sent fifty men; and they searched for three days, but didn’t find him.'),
  ('2 Kings', 2, 18, 'They came back to him while he stayed at Jericho; and he said to them, “Didn’t I tell you, ‘Don’t go’?”'),
  ('2 Kings', 2, 19, 'The men of the city said to Elisha, “Behold, please, the situation of this city is pleasant, as my lord sees; but the water is bad, and the land is barren.”'),
  ('2 Kings', 2, 20, 'He said, “Bring me a new jar, and put salt in it.” Then they brought it to him.'),
  ('2 Kings', 2, 21, 'He went out to the spring of the waters, and threw salt into it, and said, “The LORD says, ‘I have healed these waters. There shall not be from there any more death or barren wasteland.’”'),
  ('2 Kings', 2, 22, 'So the waters were healed to this day, according to Elisha’s word which he spoke.'),
  ('2 Kings', 2, 23, 'He went up from there to Bethel. As he was going up by the way, some youths came out of the city and mocked him, and said to him, “Go up, you baldy! Go up, you baldy!”'),
  ('2 Kings', 2, 24, 'He looked behind him and saw them, and cursed them in the LORD’s name. Then two female bears came out of the woods and mauled forty-two of those youths.'),
  ('2 Kings', 2, 25, 'He went from there to Mount Carmel, and from there he returned to Samaria.'),
  ('2 Kings', 3, 1, 'Now Jehoram the son of Ahab began to reign over Israel in Samaria in the eighteenth year of Jehoshaphat king of Judah, and reigned twelve years.'),
  ('2 Kings', 3, 2, 'He did that which was evil in the LORD’s sight, but not like his father and like his mother, for he put away the pillar of Baal that his father had made.'),
  ('2 Kings', 3, 3, 'Nevertheless he held to the sins of Jeroboam the son of Nebat, with which he made Israel to sin. He didn’t depart from them.'),
  ('2 Kings', 3, 4, 'Now Mesha king of Moab was a sheep breeder; and he supplied the king of Israel with one hundred thousand lambs and the wool of one hundred thousand rams.'),
  ('2 Kings', 3, 5, 'But when Ahab was dead, the king of Moab rebelled against the king of Israel.'),
  ('2 Kings', 3, 6, 'King Jehoram went out of Samaria at that time, and mustered all Israel.'),
  ('2 Kings', 3, 7, 'He went and sent to Jehoshaphat the king of Judah, saying, “The king of Moab has rebelled against me. Will you go with me against Moab to battle?” He said, “I will go up. I am as you are, my people as your people, my horses as your horses.”'),
  ('2 Kings', 3, 8, 'Then he said, “Which way shall we go up?” Jehoram answered, “The way of the wilderness of Edom.”'),
  ('2 Kings', 3, 9, 'So the king of Israel went with the king of Judah and the king of Edom, and they marched for seven days along a circuitous route. There was no water for the army or for the animals that followed them.'),
  ('2 Kings', 3, 10, 'The king of Israel said, “Alas! For the LORD has called these three kings together to deliver them into the hand of Moab.”'),
  ('2 Kings', 3, 11, 'But Jehoshaphat said, “Isn’t there a prophet of the LORD here, that we may inquire of the LORD by him?” One of the king of Israel’s servants answered, “Elisha the son of Shaphat, who poured water on the hands of Elijah, is here.”'),
  ('2 Kings', 3, 12, 'Jehoshaphat said, “The LORD’s word is with him.” So the king of Israel and Jehoshaphat and the king of Edom went down to him.'),
  ('2 Kings', 3, 13, 'Elisha said to the king of Israel, “What have I to do with you? Go to the prophets of your father, and to the prophets of your mother.” The king of Israel said to him, “No, for the LORD has called these three kings together to deliver them into the hand of Moab.”'),
  ('2 Kings', 3, 14, 'Elisha said, “As the LORD of Armies lives, before whom I stand, surely, were it not that I respect the presence of Jehoshaphat the king of Judah, I would not look toward you, nor see you.'),
  ('2 Kings', 3, 15, 'But now bring me a musician.” When the musician played, the LORD’s hand came on him.'),
  ('2 Kings', 3, 16, 'He said, “The LORD says, ‘Make this valley full of trenches.’'),
  ('2 Kings', 3, 17, 'For the LORD says, ‘You will not see wind, neither will you see rain, yet that valley will be filled with water, and you will drink, both you and your livestock and your other animals.'),
  ('2 Kings', 3, 18, 'This is an easy thing in the LORD’s sight. He will also deliver the Moabites into your hand.'),
  ('2 Kings', 3, 19, 'You shall strike every fortified city and every choice city, and shall fell every good tree, and stop all springs of water, and mar every good piece of land with stones.’”'),
  ('2 Kings', 3, 20, 'In the morning, about the time of offering the sacrifice, behold, water came by the way of Edom, and the country was filled with water.'),
  ('2 Kings', 3, 21, 'Now when all the Moabites heard that the kings had come up to fight against them, they gathered themselves together, all who were able to put on armor, young and old, and stood on the border.'),
  ('2 Kings', 3, 22, 'They rose up early in the morning, and the sun shone on the water, and the Moabites saw the water opposite them as red as blood.'),
  ('2 Kings', 3, 23, 'They said, “This is blood. The kings are surely destroyed, and they have struck each other. Now therefore, Moab, to the plunder!”');
INSERT INTO bible_verses (book_name, chapter, verse, text) VALUES
  ('2 Kings', 3, 24, 'When they came to the camp of Israel, the Israelites rose up and struck the Moabites, so that they fled before them; and they went forward into the land attacking the Moabites.'),
  ('2 Kings', 3, 25, 'They beat down the cities; and on every good piece of land each man cast his stone, and filled it. They also stopped all the springs of water and cut down all the good trees, until in Kir Hareseth all they left was its stones; however the men armed with slings went around it and attacked it.'),
  ('2 Kings', 3, 26, 'When the king of Moab saw that the battle was too severe for him, he took with him seven hundred men who drew a sword, to break through to the king of Edom; but they could not.'),
  ('2 Kings', 3, 27, 'Then he took his oldest son who would have reigned in his place, and offered him for a burnt offering on the wall. There was great wrath against Israel; and they departed from him, and returned to their own land.'),
  ('2 Kings', 4, 1, 'Now a certain woman of the wives of the sons of the prophets cried out to Elisha, saying, “Your servant my husband is dead. You know that your servant feared the LORD. Now the creditor has come to take for himself my two children to be slaves.”'),
  ('2 Kings', 4, 2, 'Elisha said to her, “What should I do for you? Tell me, what do you have in the house?” She said, “Your servant has nothing in the house, except a pot of oil.”'),
  ('2 Kings', 4, 3, 'Then he said, “Go, borrow empty containers from all your neighbors. Don’t borrow just a few containers.'),
  ('2 Kings', 4, 4, 'Go in and shut the door on you and on your sons, and pour oil into all those containers; and set aside those which are full.”'),
  ('2 Kings', 4, 5, 'So she went from him, and shut the door on herself and on her sons. They brought the containers to her, and she poured oil.'),
  ('2 Kings', 4, 6, 'When the containers were full, she said to her son, “Bring me another container.” He said to her, “There isn’t another container.” Then the oil stopped flowing.'),
  ('2 Kings', 4, 7, 'Then she came and told the man of God. He said, “Go, sell the oil, and pay your debt; and you and your sons live on the rest.”'),
  ('2 Kings', 4, 8, 'One day Elisha went to Shunem, where there was a prominent woman; and she persuaded him to eat bread. So it was, that as often as he passed by, he turned in there to eat bread.'),
  ('2 Kings', 4, 9, 'She said to her husband, “See now, I perceive that this is a holy man of God who passes by us continually.'),
  ('2 Kings', 4, 10, 'Please, let’s make a little room on the roof. Let’s set a bed, a table, a chair, and a lamp stand for him there. When he comes to us, he can stay there.”'),
  ('2 Kings', 4, 11, 'One day he came there, and he went to the room and lay there.'),
  ('2 Kings', 4, 12, 'He said to Gehazi his servant, “Call this Shunammite.” When he had called her, she stood before him.'),
  ('2 Kings', 4, 13, 'He said to him, “Say now to her, ‘Behold, you have cared for us with all this care. What is to be done for you? Would you like to be spoken for to the king, or to the captain of the army?’” She answered, “I dwell among my own people.”'),
  ('2 Kings', 4, 14, 'He said, “What then is to be done for her?” Gehazi answered, “Most certainly she has no son, and her husband is old.”'),
  ('2 Kings', 4, 15, 'He said, “Call her.” When he had called her, she stood in the door.'),
  ('2 Kings', 4, 16, 'He said, “At this season next year, you will embrace a son.” She said, “No, my lord, you man of God, do not lie to your servant.”'),
  ('2 Kings', 4, 17, 'The woman conceived, and bore a son at that season when the time came around, as Elisha had said to her.'),
  ('2 Kings', 4, 18, 'When the child was grown, one day he went out to his father to the reapers.'),
  ('2 Kings', 4, 19, 'He said to his father, “My head! My head!” He said to his servant, “Carry him to his mother.”'),
  ('2 Kings', 4, 20, 'When he had taken him and brought him to his mother, he sat on her knees until noon, and then died.'),
  ('2 Kings', 4, 21, 'She went up and laid him on the man of God’s bed, and shut the door on him, and went out.'),
  ('2 Kings', 4, 22, 'She called to her husband and said, “Please send me one of the servants, and one of the donkeys, that I may run to the man of God and come again.”'),
  ('2 Kings', 4, 23, 'He said, “Why would you want to go to him today? It is not a new moon or a Sabbath.” She said, “It’s all right.”'),
  ('2 Kings', 4, 24, 'Then she saddled a donkey, and said to her servant, “Drive, and go forward! Don’t slow down for me, unless I ask you to.”'),
  ('2 Kings', 4, 25, 'So she went, and came to the man of God to Mount Carmel. When the man of God saw her afar off, he said to Gehazi his servant, “Behold, there is the Shunammite.'),
  ('2 Kings', 4, 26, 'Please run now to meet her, and ask her, ‘Is it well with you? Is it well with your husband? Is it well with your child?’” She answered, “It is well.”'),
  ('2 Kings', 4, 27, 'When she came to the man of God to the hill, she caught hold of his feet. Gehazi came near to thrust her away; but the man of God said, “Leave her alone, for her soul is troubled within her; and the LORD has hidden it from me, and has not told me.”'),
  ('2 Kings', 4, 28, 'Then she said, “Did I ask you for a son, my lord? Didn’t I say, ‘Do not deceive me’?”'),
  ('2 Kings', 4, 29, 'Then he said to Gehazi, “Tuck your cloak into your belt, take my staff in your hand, and go your way. If you meet any man, don’t greet him; and if anyone greets you, don’t answer him again. Then lay my staff on the child’s face.”'),
  ('2 Kings', 4, 30, 'The child’s mother said, “As the LORD lives, and as your soul lives, I will not leave you.” So he arose, and followed her.'),
  ('2 Kings', 4, 31, 'Gehazi went ahead of them, and laid the staff on the child’s face; but there was no voice and no hearing. Therefore he returned to meet him, and told him, “The child has not awakened.”'),
  ('2 Kings', 4, 32, 'When Elisha had come into the house, behold, the child was dead, and lying on his bed.'),
  ('2 Kings', 4, 33, 'He went in therefore, and shut the door on them both, and prayed to the LORD.'),
  ('2 Kings', 4, 34, 'He went up and lay on the child, and put his mouth on his mouth, and his eyes on his eyes, and his hands on his hands. He stretched himself on him; and the child’s flesh grew warm.'),
  ('2 Kings', 4, 35, 'Then he returned, and walked in the house once back and forth, then went up and stretched himself out on him. Then the child sneezed seven times, and the child opened his eyes.'),
  ('2 Kings', 4, 36, 'He called Gehazi, and said, “Call this Shunammite!” So he called her. When she had come in to him, he said, “Take up your son.”'),
  ('2 Kings', 4, 37, 'Then she went in, fell at his feet, and bowed herself to the ground; then she picked up her son, and went out.'),
  ('2 Kings', 4, 38, 'Elisha came again to Gilgal. There was a famine in the land; and the sons of the prophets were sitting before him; and he said to his servant, “Get the large pot, and boil stew for the sons of the prophets.”'),
  ('2 Kings', 4, 39, 'One went out into the field to gather herbs, and found a wild vine, and gathered a lap full of wild gourds from it, and came and cut them up into the pot of stew; for they didn’t recognize them.'),
  ('2 Kings', 4, 40, 'So they poured out for the men to eat. As they were eating some of the stew, they cried out and said, “Man of God, there is death in the pot!” And they could not eat it.'),
  ('2 Kings', 4, 41, 'But he said, “Then bring meal.” He threw it into the pot; and he said, “Serve it to the people, that they may eat.” And there was nothing harmful in the pot.'),
  ('2 Kings', 4, 42, 'A man from Baal Shalishah came, and brought the man of God some bread of the first fruits: twenty loaves of barley and fresh ears of grain in his sack. Elisha said, “Give to the people, that they may eat.”'),
  ('2 Kings', 4, 43, 'His servant said, “What, should I set this before a hundred men?” But he said, “Give it to the people, that they may eat; for the LORD says, ‘They will eat, and will have some left over.’”'),
  ('2 Kings', 4, 44, 'So he set it before them and they ate and had some left over, according to the LORD’s word.'),
  ('2 Kings', 5, 1, 'Now Naaman, captain of the army of the king of Syria, was a great man with his master, and honorable, because by him the LORD had given victory to Syria; he was also a mighty man of valor, but he was a leper.'),
  ('2 Kings', 5, 2, 'The Syrians had gone out in bands, and had brought away captive out of the land of Israel a little girl, and she waited on Naaman’s wife.'),
  ('2 Kings', 5, 3, 'She said to her mistress, “I wish that my lord were with the prophet who is in Samaria! Then he would heal him of his leprosy.”'),
  ('2 Kings', 5, 4, 'Someone went in and told his lord, saying, “The girl who is from the land of Israel said this.”'),
  ('2 Kings', 5, 5, 'The king of Syria said, “Go now, and I will send a letter to the king of Israel.” He departed, and took with him ten talents of silver, six thousand pieces of gold, and ten changes of clothing.'),
  ('2 Kings', 5, 6, 'He brought the letter to the king of Israel, saying, “Now when this letter has come to you, behold, I have sent Naaman my servant to you, that you may heal him of his leprosy.”'),
  ('2 Kings', 5, 7, 'When the king of Israel had read the letter, he tore his clothes and said, “Am I God, to kill and to make alive, that this man sends to me to heal a man of his leprosy? But please consider and see how he seeks a quarrel against me.”'),
  ('2 Kings', 5, 8, 'It was so, when Elisha the man of God heard that the king of Israel had torn his clothes, that he sent to the king, saying, “Why have you torn your clothes? Let him come now to me, and he shall know that there is a prophet in Israel.”'),
  ('2 Kings', 5, 9, 'So Naaman came with his horses and with his chariots, and stood at the door of the house of Elisha.'),
  ('2 Kings', 5, 10, 'Elisha sent a messenger to him, saying, “Go and wash in the Jordan seven times, and your flesh shall come again to you, and you shall be clean.”'),
  ('2 Kings', 5, 11, 'But Naaman was angry, and went away and said, “Behold, I thought, ‘He will surely come out to me, and stand, and call on the name of the LORD his God, and wave his hand over the place, and heal the leper.’'),
  ('2 Kings', 5, 12, 'Aren’t Abanah and Pharpar, the rivers of Damascus, better than all the waters of Israel? Couldn’t I wash in them and be clean?” So he turned and went away in a rage.'),
  ('2 Kings', 5, 13, 'His servants came near and spoke to him, and said, “My father, if the prophet had asked you do some great thing, wouldn’t you have done it? How much rather then, when he says to you, ‘Wash, and be clean’?”'),
  ('2 Kings', 5, 14, 'Then went he down and dipped himself seven times in the Jordan, according to the saying of the man of God; and his flesh was restored like the flesh of a little child, and he was clean.'),
  ('2 Kings', 5, 15, 'He returned to the man of God, he and all his company, and came, and stood before him; and he said, “See now, I know that there is no God in all the earth, but in Israel. Now therefore, please take a gift from your servant.”'),
  ('2 Kings', 5, 16, 'But he said, “As the LORD lives, before whom I stand, I will receive none.” He urged him to take it; but he refused.'),
  ('2 Kings', 5, 17, 'Naaman said, “If not, then, please let two mules’ load of earth be given to your servant; for your servant will from now on offer neither burnt offering nor sacrifice to other gods, but to the LORD.'),
  ('2 Kings', 5, 18, 'In this thing may the LORD pardon your servant: when my master goes into the house of Rimmon to worship there, and he leans on my hand, and I bow myself in the house of Rimmon. When I bow myself in the house of Rimmon, may the LORD pardon your servant in this thing.”'),
  ('2 Kings', 5, 19, 'He said to him, “Go in peace.” So he departed from him a little way.'),
  ('2 Kings', 5, 20, 'But Gehazi the servant of Elisha the man of God, said, “Behold, my master has spared this Naaman the Syrian, in not receiving at his hands that which he brought. As the LORD lives, I will run after him, and take something from him.”'),
  ('2 Kings', 5, 21, 'So Gehazi followed after Naaman. When Naaman saw one running after him, he came down from the chariot to meet him, and said, “Is all well?”'),
  ('2 Kings', 5, 22, 'He said, “All is well. My master has sent me, saying, ‘Behold, even now two young men of the sons of the prophets have come to me from the hill country of Ephraim. Please give them a talent of silver and two changes of clothing.’”'),
  ('2 Kings', 5, 23, 'Naaman said, “Be pleased to take two talents.” He urged him, and bound two talents of silver in two bags, with two changes of clothing, and laid them on two of his servants; and they carried them before him.'),
  ('2 Kings', 5, 24, 'When he came to the hill, he took them from their hand, and stored them in the house. Then he let the men go, and they departed.'),
  ('2 Kings', 5, 25, 'But he went in, and stood before his master. Elisha said to him, “Where did you come from, Gehazi?” He said, “Your servant went nowhere.”'),
  ('2 Kings', 5, 26, 'He said to him, “Didn’t my heart go with you when the man turned from his chariot to meet you? Is it a time to receive money, and to receive garments, and olive groves and vineyards, and sheep and cattle, and male servants and female servants?'),
  ('2 Kings', 5, 27, 'Therefore the leprosy of Naaman will cling to you and to your offspring forever.” He went out from his presence a leper, as white as snow.'),
  ('2 Kings', 6, 1, 'The sons of the prophets said to Elisha, “See now, the place where we live and meet with you is too small for us.'),
  ('2 Kings', 6, 2, 'Please let us go to the Jordan, and each man take a beam from there, and let’s make us a place there, where we may live.” He answered, “Go!”'),
  ('2 Kings', 6, 3, 'One said, “Please be pleased to go with your servants.” He answered, “I will go.”'),
  ('2 Kings', 6, 4, 'So he went with them. When they came to the Jordan, they cut down wood.'),
  ('2 Kings', 6, 5, 'But as one was cutting down a tree, the ax head fell into the water. Then he cried out and said, “Alas, my master! For it was borrowed.”'),
  ('2 Kings', 6, 6, 'The man of God asked, “Where did it fall?” He showed him the place. He cut down a stick, threw it in there, and made the iron float.'),
  ('2 Kings', 6, 7, 'He said, “Take it.” So he put out his hand and took it.'),
  ('2 Kings', 6, 8, 'Now the king of Syria was at war against Israel; and he took counsel with his servants, saying, “My camp will be in such and such a place.”'),
  ('2 Kings', 6, 9, 'The man of God sent to the king of Israel, saying, “Beware that you not pass this place, for the Syrians are coming down there.”'),
  ('2 Kings', 6, 10, 'The king of Israel sent to the place which the man of God told him and warned him of; and he saved himself there, not once or twice.'),
  ('2 Kings', 6, 11, 'The king of Syria’s heart was very troubled about this. He called his servants, and said to them, “Won’t you show me which of us is for the king of Israel?”'),
  ('2 Kings', 6, 12, 'One of his servants said, “No, my lord, O king; but Elisha, the prophet who is in Israel, tells the king of Israel the words that you speak in your bedroom.”'),
  ('2 Kings', 6, 13, 'He said, “Go and see where he is, that I may send and get him.” He was told, “Behold, he is in Dothan.”'),
  ('2 Kings', 6, 14, 'Therefore he sent horses, chariots, and a great army there. They came by night and surrounded the city.'),
  ('2 Kings', 6, 15, 'When the servant of the man of God had risen early and gone out, behold, an army with horses and chariots was around the city. His servant said to him, “Alas, my master! What shall we do?”'),
  ('2 Kings', 6, 16, 'He answered, “Don’t be afraid, for those who are with us are more than those who are with them.”'),
  ('2 Kings', 6, 17, 'Elisha prayed, and said, “LORD, please open his eyes, that he may see.” the LORD opened the young man’s eyes, and he saw; and behold, the mountain was full of horses and chariots of fire around Elisha.'),
  ('2 Kings', 6, 18, 'When they came down to him, Elisha prayed to the LORD, and said, “Please strike this people with blindness.” He struck them with blindness according to Elisha’s word.'),
  ('2 Kings', 6, 19, 'Elisha said to them, “This is not the way, neither is this the city. Follow me, and I will bring you to the man whom you seek.” He led them to Samaria.'),
  ('2 Kings', 6, 20, 'When they had come into Samaria, Elisha said, “LORD, open these men’s eyes, that they may see.” The LORD opened their eyes, and they saw; and behold, they were in the middle of Samaria.'),
  ('2 Kings', 6, 21, 'The king of Israel said to Elisha, when he saw them, “My father, shall I strike them? Shall I strike them?”'),
  ('2 Kings', 6, 22, 'He answered, “You shall not strike them. Would you strike those whom you have taken captive with your sword and with your bow? Set bread and water before them, that they may eat and drink, then go to their master.”'),
  ('2 Kings', 6, 23, 'He prepared a great feast for them. After they ate and drank, he sent them away and they went to their master. So the bands of Syria stopped raiding the land of Israel.'),
  ('2 Kings', 6, 24, 'After this, Benhadad king of Syria gathered all his army, and went up and besieged Samaria.'),
  ('2 Kings', 6, 25, 'There was a great famine in Samaria. Behold, they besieged it until a donkey’s head was sold for eighty pieces of silver, and the fourth part of a kab of dove’s dung for five pieces of silver.');
INSERT INTO bible_verses (book_name, chapter, verse, text) VALUES
  ('2 Kings', 6, 26, 'As the king of Israel was passing by on the wall, a woman cried to him, saying, “Help, my lord, O king!”'),
  ('2 Kings', 6, 27, 'He said, “If the LORD doesn’t help you, where could I get help for you? From the threshing floor, or from the wine press?”'),
  ('2 Kings', 6, 28, 'Then the king asked her, “What is your problem?” She answered, “This woman said to me, ‘Give your son, that we may eat him today, and we will eat my son tomorrow.’'),
  ('2 Kings', 6, 29, 'So we boiled my son and ate him; and I said to her on the next day, ‘Give up your son, that we may eat him;’ and she has hidden her son.”'),
  ('2 Kings', 6, 30, 'When the king heard the words of the woman, he tore his clothes. Now he was passing by on the wall, and the people looked, and behold, he had sackcloth underneath on his body.'),
  ('2 Kings', 6, 31, 'Then he said, “God do so to me, and more also, if the head of Elisha the son of Shaphat stays on him today.”'),
  ('2 Kings', 6, 32, 'But Elisha was sitting in his house, and the elders were sitting with him. Then the king sent a man from before him; but before the messenger came to him, he said to the elders, “Do you see how this son of a murderer has sent to take away my head? Behold, when the messenger comes, shut the door, and hold the door shut against him. Isn’t the sound of his master’s feet behind him?”'),
  ('2 Kings', 6, 33, 'While he was still talking with them, behold, the messenger came down to him. Then he said, “Behold, this evil is from the LORD. Why should I wait for the LORD any longer?”'),
  ('2 Kings', 7, 1, 'Elisha said, “Hear the LORD’s word. The LORD says, ‘Tomorrow about this time a seah of fine flour will be sold for a shekel, and two seahs of barley for a shekel, in the gate of Samaria.’”'),
  ('2 Kings', 7, 2, 'Then the captain on whose hand the king leaned answered the man of God, and said, “Behold, if the LORD made windows in heaven, could this thing be?” He said, “Behold, you will see it with your eyes, but will not eat of it.”'),
  ('2 Kings', 7, 3, 'Now there were four leprous men at the entrance of the gate. They said to one another, “Why do we sit here until we die?'),
  ('2 Kings', 7, 4, 'If we say, ‘We will enter into the city,’ then the famine is in the city, and we will die there. If we sit still here, we also die. Now therefore come, and let’s surrender to the army of the Syrians. If they save us alive, we will live; and if they kill us, we will only die.”'),
  ('2 Kings', 7, 5, 'They rose up in the twilight to go to the camp of the Syrians. When they had come to the outermost part of the camp of the Syrians, behold, no man was there.'),
  ('2 Kings', 7, 6, 'For the Lord had made the army of the Syrians to hear the sound of chariots and the sound of horses, even the noise of a great army; and they said to one another, “Behold, the king of Israel has hired against us the kings of the Hittites and the kings of the Egyptians to attack us.”'),
  ('2 Kings', 7, 7, 'Therefore they arose and fled in the twilight, and left their tents, their horses, and their donkeys, even the camp as it was, and fled for their life.'),
  ('2 Kings', 7, 8, 'When these lepers came to the outermost part of the camp, they went into one tent, and ate and drank, then carried away silver, gold, and clothing and went and hid it. Then they came back, and entered into another tent and carried things from there also, and went and hid them.'),
  ('2 Kings', 7, 9, 'Then they said to one another, “We aren’t doing right. Today is a day of good news, and we keep silent. If we wait until the morning light, punishment will overtake us. Now therefore come, let’s go and tell the king’s household.”'),
  ('2 Kings', 7, 10, 'So they came and called to the city gatekeepers; and they told them, “We came to the camp of the Syrians, and, behold, there was no man there, not even a man’s voice, but the horses tied, and the donkeys tied, and the tents as they were.”'),
  ('2 Kings', 7, 11, 'Then the gatekeepers called out and told it to the king’s household within.'),
  ('2 Kings', 7, 12, 'The king arose in the night, and said to his servants, “I will now show you what the Syrians have done to us. They know that we are hungry. Therefore they have gone out of the camp to hide themselves in the field, saying, ‘When they come out of the city, we shall take them alive, and get into the city.’”'),
  ('2 Kings', 7, 13, 'One of his servants answered, “Please let some people take five of the horses that remain, which are left in the city. Behold, they are like all the multitude of Israel who are left in it. Behold, they are like all the multitude of Israel who are consumed. Let’s send and see.”'),
  ('2 Kings', 7, 14, 'Therefore they took two chariots with horses; and the king sent them out to the Syrian army, saying, “Go and see.”'),
  ('2 Kings', 7, 15, 'They went after them to the Jordan; and behold, all the path was full of garments and equipment which the Syrians had cast away in their haste. The messengers returned and told the king.'),
  ('2 Kings', 7, 16, 'The people went out and plundered the camp of the Syrians. So a seah of fine flour was sold for a shekel, and two measures of barley for a shekel, according to the LORD’s word.'),
  ('2 Kings', 7, 17, 'The king had appointed the captain on whose hand he leaned to be in charge of the gate; and the people trampled over him in the gate, and he died as the man of God had said, who spoke when the king came down to him.'),
  ('2 Kings', 7, 18, 'It happened as the man of God had spoken to the king, saying, “Two seahs of barley for a shekel, and a seah of fine flour for a shekel, shall be tomorrow about this time in the gate of Samaria;”'),
  ('2 Kings', 7, 19, 'and that captain answered the man of God, and said, “Now, behold, if the LORD made windows in heaven, might such a thing be?” and he said, “Behold, you will see it with your eyes, but will not eat of it.”'),
  ('2 Kings', 7, 20, 'It happened like that to him, for the people trampled over him in the gate, and he died.'),
  ('2 Kings', 8, 1, 'Now Elisha had spoken to the woman whose son he had restored to life, saying, “Arise, and go, you and your household, and stay for a while wherever you can; for the LORD has called for a famine. It will also come on the land for seven years.”'),
  ('2 Kings', 8, 2, 'The woman arose, and did according to the man of God’s word. She went with her household, and lived in the land of the Philistines for seven years.'),
  ('2 Kings', 8, 3, 'At the end of seven years, the woman returned from the land of the Philistines. Then she went out to beg the king for her house and for her land.'),
  ('2 Kings', 8, 4, 'Now the king was talking with Gehazi the servant of the man of God, saying, “Please tell me all the great things that Elisha has done.”'),
  ('2 Kings', 8, 5, 'As he was telling the king how he had restored to life him who was dead, behold, the woman whose son he had restored to life begged the king for her house and for her land. Gehazi said, “My lord, O king, this is the woman, and this is her son, whom Elisha restored to life.”'),
  ('2 Kings', 8, 6, 'When the king asked the woman, she told him. So the king appointed to her a certain officer, saying, “Restore all that was hers, and all the fruits of the field since the day that she left the land, even until now.”'),
  ('2 Kings', 8, 7, 'Elisha came to Damascus; and Benhadad the king of Syria was sick. He was told, “The man of God has come here.”'),
  ('2 Kings', 8, 8, 'The king said to Hazael, “Take a present in your hand, and go meet the man of God, and inquire of the LORD by him, saying, ‘Will I recover from this sickness?’”'),
  ('2 Kings', 8, 9, 'So Hazael went to meet him and took a present with him, even of every good thing of Damascus, forty camels’ burden, and came and stood before him and said, “Your son Benhadad king of Syria has sent me to you, saying, ‘Will I recover from this sickness?’”'),
  ('2 Kings', 8, 10, 'Elisha said to him, “Go, tell him, ‘You will surely recover;’ however the LORD has shown me that he will surely die.”'),
  ('2 Kings', 8, 11, 'He settled his gaze steadfastly on him, until he was ashamed. Then the man of God wept.'),
  ('2 Kings', 8, 12, 'Hazael said, “Why do you weep, my lord?” He answered, “Because I know the evil that you will do to the children of Israel. You will set their strongholds on fire, and you will kill their young men with the sword, and will dash their little ones in pieces, and rip up their pregnant women.”'),
  ('2 Kings', 8, 13, 'Hazael said, “But what is your servant, who is but a dog, that he could do this great thing?” Elisha answered, “The LORD has shown me that you will be king over Syria.”'),
  ('2 Kings', 8, 14, 'Then he departed from Elisha, and came to his master, who said to him, “What did Elisha say to you?” He answered, “He told me that you would surely recover.”'),
  ('2 Kings', 8, 15, 'On the next day, he took a thick cloth, dipped it in water, and spread it on the king’s face, so that he died. Then Hazael reigned in his place.'),
  ('2 Kings', 8, 16, 'In the fifth year of Joram the son of Ahab king of Israel, Jehoshaphat being king of Judah then, Jehoram the son of Jehoshaphat king of Judah began to reign.'),
  ('2 Kings', 8, 17, 'He was thirty-two years old when he began to reign. He reigned eight years in Jerusalem.'),
  ('2 Kings', 8, 18, 'He walked in the way of the kings of Israel, as did Ahab’s house, for he married Ahab’s daughter. He did that which was evil in the LORD’s sight.'),
  ('2 Kings', 8, 19, 'However, the LORD would not destroy Judah, for David his servant’s sake, as he promised him to give to him a lamp for his children always.'),
  ('2 Kings', 8, 20, 'In his days Edom revolted from under the hand of Judah, and made a king over themselves.'),
  ('2 Kings', 8, 21, 'Then Joram crossed over to Zair, and all his chariots with him; and he rose up by night and struck the Edomites who surrounded him with the captains of the chariots; and the people fled to their tents.'),
  ('2 Kings', 8, 22, 'So Edom revolted from under the hand of Judah to this day. Then Libnah revolted at the same time.'),
  ('2 Kings', 8, 23, 'The rest of the acts of Joram, and all that he did, aren’t they written in the book of the chronicles of the kings of Judah?'),
  ('2 Kings', 8, 24, 'Joram slept with his fathers, and was buried with his fathers in David’s city; and Ahaziah his son reigned in his place.'),
  ('2 Kings', 8, 25, 'In the twelfth year of Joram the son of Ahab king of Israel, Ahaziah the son of Jehoram king of Judah began to reign.'),
  ('2 Kings', 8, 26, 'Ahaziah was twenty-two years old when he began to reign; and he reigned one year in Jerusalem. His mother’s name was Athaliah the daughter of Omri king of Israel.'),
  ('2 Kings', 8, 27, 'He walked in the way of Ahab’s house and did that which was evil in the LORD’s sight, as did Ahab’s house, for he was the son-in-law of Ahab’s house.'),
  ('2 Kings', 8, 28, 'He went with Joram the son of Ahab to war against Hazael king of Syria at Ramoth Gilead, and the Syrians wounded Joram.'),
  ('2 Kings', 8, 29, 'King Joram returned to be healed in Jezreel from the wounds which the Syrians had given him at Ramah, when he fought against Hazael king of Syria. Ahaziah the son of Jehoram, king of Judah, went down to see Joram the son of Ahab in Jezreel, because he was sick.'),
  ('2 Kings', 9, 1, 'Elisha the prophet called one of the sons of the prophets, and said to him, “Put your belt on your waist, take this vial of oil in your hand, and go to Ramoth Gilead.'),
  ('2 Kings', 9, 2, 'When you come there, find Jehu the son of Jehoshaphat the son of Nimshi, and go in and make him rise up from among his brothers, and take him to an inner room.'),
  ('2 Kings', 9, 3, 'Then take the vial of oil, and pour it on his head, and say, ‘The LORD says, “I have anointed you king over Israel.”’ Then open the door, flee, and don’t wait.”'),
  ('2 Kings', 9, 4, 'So the young man, the young prophet, went to Ramoth Gilead.'),
  ('2 Kings', 9, 5, 'When he came, behold, the captains of the army were sitting. Then he said, “I have a message for you, captain.” Jehu said, “To which one of us?” He said, “To you, O captain.”'),
  ('2 Kings', 9, 6, 'He arose, and went into the house. Then he poured the oil on his head, and said to him, “The LORD, the God of Israel, says, ‘I have anointed you king over the people of the LORD, even over Israel.'),
  ('2 Kings', 9, 7, 'You must strike your master Ahab’s house, that I may avenge the blood of my servants the prophets, and the blood of all the servants of the LORD, at the hand of Jezebel.'),
  ('2 Kings', 9, 8, 'For the whole house of Ahab will perish. I will cut off from Ahab everyone who urinates against a wall, both him who is shut up and him who is left at large in Israel.'),
  ('2 Kings', 9, 9, 'I will make Ahab’s house like the house of Jeroboam the son of Nebat, and like the house of Baasha the son of Ahijah.'),
  ('2 Kings', 9, 10, 'The dogs will eat Jezebel on the plot of ground of Jezreel, and there shall be no one to bury her.’” Then he opened the door and fled.'),
  ('2 Kings', 9, 11, 'When Jehu came out to the servants of his lord and one said to him, “Is all well? Why did this madman come to you?” He said to them, “You know the man and how he talks.”'),
  ('2 Kings', 9, 12, 'They said, “That is a lie. Tell us now.” He said, “He said to me, ‘The LORD says, I have anointed you king over Israel.’”'),
  ('2 Kings', 9, 13, 'Then they hurried, and each man took his cloak, and put it under him on the top of the stairs, and blew the trumpet, saying, “Jehu is king.”'),
  ('2 Kings', 9, 14, 'So Jehu the son of Jehoshaphat the son of Nimshi conspired against Joram. (Now Joram was defending Ramoth Gilead, he and all Israel, because of Hazael king of Syria;'),
  ('2 Kings', 9, 15, 'but King Joram had returned to be healed in Jezreel of the wounds which the Syrians had given him when he fought with Hazael king of Syria.) Jehu said, “If this is your thinking, then let no one escape and go out of the city to go to tell it in Jezreel.”'),
  ('2 Kings', 9, 16, 'So Jehu rode in a chariot and went to Jezreel, for Joram lay there. Ahaziah king of Judah had come down to see Joram.'),
  ('2 Kings', 9, 17, 'Now the watchman was standing on the tower in Jezreel, and he spied the company of Jehu as he came, and said, “I see a company.” Joram said, “Take a horseman, and send to meet them, and let him say, ‘Is it peace?’”'),
  ('2 Kings', 9, 18, 'So one went on horseback to meet him, and said, “the king says, ‘Is it peace?’” Jehu said, “What do you have to do with peace? Fall in behind me!” The watchman said, “The messenger came to them, but he isn’t coming back.”'),
  ('2 Kings', 9, 19, 'Then he sent out a second on horseback, who came to them and said, “The king says, ‘Is it peace?’” Jehu answered, “What do you have to do with peace? Fall in behind me!”'),
  ('2 Kings', 9, 20, 'The watchman said, “He came to them, and isn’t coming back. The driving is like the driving of Jehu the son of Nimshi, for he drives furiously.”'),
  ('2 Kings', 9, 21, 'Joram said, “Get ready!” They got his chariot ready. Then Joram king of Israel and Ahaziah king of Judah went out, each in his chariot; and they went out to meet Jehu, and found him on Naboth the Jezreelite’s land.'),
  ('2 Kings', 9, 22, 'When Joram saw Jehu, he said, “Is it peace, Jehu?” He answered, “What peace, so long as the prostitution of your mother Jezebel and her witchcraft abound?”'),
  ('2 Kings', 9, 23, 'Joram turned his hands and fled, and said to Ahaziah, “This is treason, Ahaziah!”'),
  ('2 Kings', 9, 24, 'Jehu drew his bow with his full strength, and struck Joram between his arms; and the arrow went out at his heart, and he sunk down in his chariot.'),
  ('2 Kings', 9, 25, 'Then Jehu said to Bidkar his captain, “Pick him up, and throw him in the plot of the field of Naboth the Jezreelite; for remember how, when you and I rode together after Ahab his father, the LORD laid this burden on him:'),
  ('2 Kings', 9, 26, '‘Surely I have seen yesterday the blood of Naboth, and the blood of his sons,’ says the LORD; ‘and I will repay you in this plot of ground,’ says the LORD. Now therefore take and cast him onto the plot of ground, according to the LORD’s word.”'),
  ('2 Kings', 9, 27, 'But when Ahaziah the king of Judah saw this, he fled by the way of the garden house. Jehu followed after him, and said, “Strike him also in the chariot!” They struck him at the ascent of Gur, which is by Ibleam. He fled to Megiddo, and died there.'),
  ('2 Kings', 9, 28, 'His servants carried him in a chariot to Jerusalem, and buried him in his tomb with his fathers in David’s city.'),
  ('2 Kings', 9, 29, 'In the eleventh year of Joram the son of Ahab, Ahaziah began to reign over Judah.'),
  ('2 Kings', 9, 30, 'When Jehu had come to Jezreel, Jezebel heard of it; and she painted her eyes, and adorned her head, and looked out at the window.'),
  ('2 Kings', 9, 31, 'As Jehu entered in at the gate, she said, “Do you come in peace, Zimri, you murderer of your master?”'),
  ('2 Kings', 9, 32, 'He lifted up his face to the window, and said, “Who is on my side? Who?” Two or three eunuchs looked out at him.'),
  ('2 Kings', 9, 33, 'He said, “Throw her down!” So they threw her down; and some of her blood was sprinkled on the wall, and on the horses. Then he trampled her under foot.'),
  ('2 Kings', 9, 34, 'When he had come in, he ate and drank. Then he said, “See now to this cursed woman, and bury her; for she is a king’s daughter.”'),
  ('2 Kings', 9, 35, 'They went to bury her, but they found no more of her than the skull, the feet, and the palms of her hands.'),
  ('2 Kings', 9, 36, 'Therefore they came back, and told him. He said, “This is the LORD’s word, which he spoke by his servant Elijah the Tishbite, saying, ‘The dogs will eat the flesh of Jezebel on the plot of Jezreel,'),
  ('2 Kings', 9, 37, 'and the body of Jezebel will be as dung on the surface of the field on Jezreel’s land, so that they won’t say, “This is Jezebel.”’”'),
  ('2 Kings', 10, 1, 'Now Ahab had seventy sons in Samaria. Jehu wrote letters and sent them to Samaria, to the rulers of Jezreel, even the elders, and to those who brought up Ahab’s sons, saying,'),
  ('2 Kings', 10, 2, '“Now as soon as this letter comes to you, since your master’s sons are with you, and you have chariots and horses, a fortified city also, and armor,'),
  ('2 Kings', 10, 3, 'select the best and fittest of your master’s sons, set him on his father’s throne, and fight for your master’s house.”'),
  ('2 Kings', 10, 4, 'But they were exceedingly afraid, and said, “Behold, the two kings didn’t stand before him! How then shall we stand?”'),
  ('2 Kings', 10, 5, 'He who was over the household, and he who was over the city, the elders also, and those who raised the children, sent to Jehu, saying, “We are your servants, and will do all that you ask us. We will not make any man king. You do that which is good in your eyes.”'),
  ('2 Kings', 10, 6, 'Then he wrote a letter the second time to them, saying, “If you are on my side, and if you will listen to my voice, take the heads of the men who are your master’s sons, and come to me to Jezreel by tomorrow this time.” Now the king’s sons, being seventy persons, were with the great men of the city, who brought them up.');
INSERT INTO bible_verses (book_name, chapter, verse, text) VALUES
  ('2 Kings', 10, 7, 'When the letter came to them, they took the king’s sons and killed them, even seventy people, and put their heads in baskets, and sent them to him to Jezreel.'),
  ('2 Kings', 10, 8, 'A messenger came and told him, “They have brought the heads of the king’s sons.” He said, “Lay them in two heaps at the entrance of the gate until the morning.”'),
  ('2 Kings', 10, 9, 'In the morning, he went out and stood, and said to all the people, “You are righteous. Behold, I conspired against my master and killed him, but who killed all these?'),
  ('2 Kings', 10, 10, 'Know now that nothing will fall to the earth of the LORD’s word, which the LORD spoke concerning Ahab’s house. For the LORD has done that which he spoke by his servant Elijah.”'),
  ('2 Kings', 10, 11, 'So Jehu struck all that remained of Ahab’s house in Jezreel, with all his great men, his familiar friends, and his priests, until he left him no one remaining.'),
  ('2 Kings', 10, 12, 'He arose and departed, and went to Samaria. As he was at the shearing house of the shepherds on the way,'),
  ('2 Kings', 10, 13, 'Jehu met with the brothers of Ahaziah king of Judah, and said, “Who are you?” They answered, “We are the brothers of Ahaziah. We are going down to greet the children of the king and the children of the queen.”'),
  ('2 Kings', 10, 14, 'He said, “Take them alive!” They took them alive, and killed them at the pit of the shearing house, even forty-two men. He didn’t leave any of them.'),
  ('2 Kings', 10, 15, 'When he had departed from there, he met Jehonadab the son of Rechab coming to meet him. He greeted him, and said to him, “Is your heart right, as my heart is with your heart?” Jehonadab answered, “It is.” “If it is, give me your hand.” He gave him his hand; and he took him up to him into the chariot.'),
  ('2 Kings', 10, 16, 'He said, “Come with me, and see my zeal for the LORD.” So they made him ride in his chariot.'),
  ('2 Kings', 10, 17, 'When he came to Samaria, he struck all who remained to Ahab in Samaria, until he had destroyed them, according to the LORD’s word which he spoke to Elijah.'),
  ('2 Kings', 10, 18, 'Jehu gathered all the people together, and said to them, “Ahab served Baal a little, but Jehu will serve him much.'),
  ('2 Kings', 10, 19, 'Now therefore call to me all the prophets of Baal, all of his worshipers, and all of his priests. Let no one be absent, for I have a great sacrifice to Baal. Whoever is absent, he shall not live.” But Jehu did deceptively, intending to destroy the worshipers of Baal.'),
  ('2 Kings', 10, 20, 'Jehu said, “Sanctify a solemn assembly for Baal!” So they proclaimed it.'),
  ('2 Kings', 10, 21, 'Jehu sent through all Israel; and all the worshipers of Baal came, so that there was not a man left that didn’t come. They came into the house of Baal; and the house of Baal was filled from one end to another.'),
  ('2 Kings', 10, 22, 'He said to him who kept the wardrobe, “Bring out robes for all the worshipers of Baal!” So he brought robes out to them.'),
  ('2 Kings', 10, 23, 'Jehu went with Jehonadab the son of Rechab into the house of Baal. Then he said to the worshipers of Baal, “Search, and see that none of the servants of the LORD are here with you, but only the worshipers of Baal.”'),
  ('2 Kings', 10, 24, 'So they went in to offer sacrifices and burnt offerings. Now Jehu had appointed for himself eighty men outside, and said, “If any of the men whom I bring into your hands escape, he who lets him go, his life shall be for the life of him.”'),
  ('2 Kings', 10, 25, 'As soon as he had finished offering the burnt offering, Jehu said to the guard and to the captains, “Go in and kill them! Let no one escape.” So they struck them with the edge of the sword. The guard and the captains threw the bodies out, and went to the inner shrine of the house of Baal.'),
  ('2 Kings', 10, 26, 'They brought out the pillars that were in the house of Baal and burned them.'),
  ('2 Kings', 10, 27, 'They broke down the pillar of Baal, and broke down the house of Baal, and made it a latrine, to this day.'),
  ('2 Kings', 10, 28, 'Thus Jehu destroyed Baal out of Israel.'),
  ('2 Kings', 10, 29, 'However, Jehu didn’t depart from the sins of Jeroboam the son of Nebat, with which he made Israel to sin—the golden calves that were in Bethel and that were in Dan.'),
  ('2 Kings', 10, 30, 'The LORD said to Jehu, “Because you have done well in executing that which is right in my eyes, and have done to Ahab’s house according to all that was in my heart, your descendants shall sit on the throne of Israel to the fourth generation.”'),
  ('2 Kings', 10, 31, 'But Jehu took no heed to walk in the law of the LORD, the God of Israel, with all his heart. He didn’t depart from the sins of Jeroboam, with which he made Israel to sin.'),
  ('2 Kings', 10, 32, 'In those days the LORD began to cut away parts of Israel; and Hazael struck them in all the borders of Israel'),
  ('2 Kings', 10, 33, 'from the Jordan eastward, all the land of Gilead, the Gadites, and the Reubenites, and the Manassites, from Aroer, which is by the valley of the Arnon, even Gilead and Bashan.'),
  ('2 Kings', 10, 34, 'Now the rest of the acts of Jehu, and all that he did, and all his might, aren’t they written in the book of the chronicles of the kings of Israel?'),
  ('2 Kings', 10, 35, 'Jehu slept with his fathers; and they buried him in Samaria. Jehoahaz his son reigned in his place.'),
  ('2 Kings', 10, 36, 'The time that Jehu reigned over Israel in Samaria was twenty-eight years.'),
  ('2 Kings', 11, 1, 'Now when Athaliah the mother of Ahaziah saw that her son was dead, she arose and destroyed all the royal offspring.'),
  ('2 Kings', 11, 2, 'But Jehosheba, the daughter of King Joram, sister of Ahaziah, took Joash the son of Ahaziah, and stole him away from among the king’s sons who were slain, even him and his nurse, and put them in the bedroom; and they hid him from Athaliah, so that he was not slain.'),
  ('2 Kings', 11, 3, 'He was with her hidden in the LORD’s house six years while Athaliah reigned over the land.'),
  ('2 Kings', 11, 4, 'In the seventh year Jehoiada sent and fetched the captains over hundreds of the Carites and of the guard, and brought them to him into the LORD’s house; and he made a covenant with them, and made a covenant with them in the LORD’s house, and showed them the king’s son.'),
  ('2 Kings', 11, 5, 'He commanded them, saying, “This is what you must do: a third of you, who come in on the Sabbath, shall be keepers of the watch of the king’s house;'),
  ('2 Kings', 11, 6, 'a third of you shall be at the gate Sur; and a third of you at the gate behind the guard. So you shall keep the watch of the house, and be a barrier.'),
  ('2 Kings', 11, 7, 'The two companies of you, even all who go out on the Sabbath, shall keep the watch of the LORD’s house around the king.'),
  ('2 Kings', 11, 8, 'You shall surround the king, every man with his weapons in his hand; and he who comes within the ranks, let him be slain. Be with the king when he goes out, and when he comes in.”'),
  ('2 Kings', 11, 9, 'The captains over hundreds did according to all that Jehoiada the priest commanded; and they each took his men, those who were to come in on the Sabbath with those who were to go out on the Sabbath, and came to Jehoiada the priest.'),
  ('2 Kings', 11, 10, 'The priest delivered to the captains over hundreds the spears and shields that had been King David’s, which were in the LORD’s house.'),
  ('2 Kings', 11, 11, 'The guard stood, every man with his weapons in his hand, from the right side of the house to the left side of the house, along by the altar and the house, around the king.'),
  ('2 Kings', 11, 12, 'Then he brought out the king’s son, and put the crown on him, and gave him the covenant; and they made him king and anointed him; and they clapped their hands, and said, “Long live the king!”'),
  ('2 Kings', 11, 13, 'When Athaliah heard the noise of the guard and of the people, she came to the people into the LORD’s house;'),
  ('2 Kings', 11, 14, 'and she looked, and behold, the king stood by the pillar, as the tradition was, with the captains and the trumpets by the king; and all the people of the land rejoiced, and blew trumpets. Then Athaliah tore her clothes and cried, “Treason! Treason!”'),
  ('2 Kings', 11, 15, 'Jehoiada the priest commanded the captains of hundreds who were set over the army, and said to them, “Bring her out between the ranks. Kill anyone who follows her with the sword.” For the priest said, “Don’t let her be slain in the LORD’s house.”'),
  ('2 Kings', 11, 16, 'So they seized her; and she went by the way of the horses’ entry to the king’s house, and she was slain there.'),
  ('2 Kings', 11, 17, 'Jehoiada made a covenant between the LORD and the king and the people, that they should be the LORD’s people; also between the king and the people.'),
  ('2 Kings', 11, 18, 'All the people of the land went to the house of Baal, and broke it down. They broke his altars and his images in pieces thoroughly, and killed Mattan the priest of Baal before the altars. The priest appointed officers over the LORD’s house.'),
  ('2 Kings', 11, 19, 'He took the captains over hundreds, and the Carites, and the guard, and all the people of the land; and they brought down the king from the LORD’s house, and came by the way of the gate of the guard to the king’s house. He sat on the throne of the kings.'),
  ('2 Kings', 11, 20, 'So all the people of the land rejoiced, and the city was quiet. They had slain Athaliah with the sword at the king’s house.'),
  ('2 Kings', 11, 21, 'Jehoash was seven years old when he began to reign.'),
  ('2 Kings', 12, 1, 'Jehoash began to reign in the seventh year of Jehu, and he reigned forty years in Jerusalem. His mother’s name was Zibiah of Beersheba.'),
  ('2 Kings', 12, 2, 'Jehoash did that which was right in the LORD’s eyes all his days in which Jehoiada the priest instructed him.'),
  ('2 Kings', 12, 3, 'However, the high places were not taken away. The people still sacrificed and burned incense in the high places.'),
  ('2 Kings', 12, 4, 'Jehoash said to the priests, “All the money of the holy things that is brought into the LORD’s house, in current money, the money of the people for whom each man is evaluated, and all the money that it comes into any man’s heart to bring into the LORD’s house,'),
  ('2 Kings', 12, 5, 'let the priests take it to them, each man from his donor; and they shall repair the damage to the house, wherever any damage is found.”'),
  ('2 Kings', 12, 6, 'But it was so, that in the twenty-third year of King Jehoash the priests had not repaired the damage to the house.'),
  ('2 Kings', 12, 7, 'Then King Jehoash called for Jehoiada the priest, and for the other priests, and said to them, “Why aren’t you repairing the damage to the house? Now therefore take no more money from your treasurers, but deliver it for repair of the damage to the house.”'),
  ('2 Kings', 12, 8, 'The priests consented that they should take no more money from the people, and not repair the damage to the house.'),
  ('2 Kings', 12, 9, 'But Jehoiada the priest took a chest and bored a hole in its lid, and set it beside the altar, on the right side as one comes into the LORD’s house; and the priests who kept the threshold put all the money that was brought into the LORD’s house into it.'),
  ('2 Kings', 12, 10, 'When they saw that there was much money in the chest, the king’s scribe and the high priest came up, and they put it in bags and counted the money that was found in the LORD’s house.'),
  ('2 Kings', 12, 11, 'They gave the money that was weighed out into the hands of those who did the work, who had the oversight of the LORD’s house; and they paid it out to the carpenters and the builders who worked on the LORD’s house,'),
  ('2 Kings', 12, 12, 'and to the masons and the stone cutters, and for buying timber and cut stone to repair the damage to the LORD’s house, and for all that was laid out for the house to repair it.'),
  ('2 Kings', 12, 13, 'But there were not made for the LORD’s house cups of silver, snuffers, basins, trumpets, any vessels of gold or vessels of silver, of the money that was brought into the LORD’s house;'),
  ('2 Kings', 12, 14, 'for they gave that to those who did the work, and repaired the LORD’s house with it.'),
  ('2 Kings', 12, 15, 'Moreover they didn’t demand an accounting from the men into whose hand they delivered the money to give to those who did the work; for they dealt faithfully.'),
  ('2 Kings', 12, 16, 'The money for the trespass offerings and the money for the sin offerings was not brought into the LORD’s house. It was the priests’.'),
  ('2 Kings', 12, 17, 'Then Hazael king of Syria went up and fought against Gath, and took it; and Hazael set his face to go up to Jerusalem.'),
  ('2 Kings', 12, 18, 'Jehoash king of Judah took all the holy things that Jehoshaphat and Jehoram and Ahaziah, his fathers, kings of Judah, had dedicated, and his own holy things, and all the gold that was found in the treasures of the LORD’s house, and of the king’s house, and sent it to Hazael king of Syria; and he went away from Jerusalem.'),
  ('2 Kings', 12, 19, 'Now the rest of the acts of Joash, and all that he did, aren’t they written in the book of the chronicles of the kings of Judah?'),
  ('2 Kings', 12, 20, 'His servants arose and made a conspiracy, and struck Joash at the house of Millo, on the way that goes down to Silla.'),
  ('2 Kings', 12, 21, 'For Jozacar the son of Shimeath, and Jehozabad the son of Shomer, his servants, struck him, and he died; and they buried him with his fathers in David’s city; and Amaziah his son reigned in his place.'),
  ('2 Kings', 13, 1, 'In the twenty-third year of Joash the son of Ahaziah, king of Judah, Jehoahaz the son of Jehu began to reign over Israel in Samaria for seventeen years.'),
  ('2 Kings', 13, 2, 'He did that which was evil in the LORD’s sight, and followed the sins of Jeroboam the son of Nebat, with which he made Israel to sin. He didn’t depart from it.'),
  ('2 Kings', 13, 3, 'The LORD’s anger burned against Israel, and he delivered them into the hand of Hazael king of Syria, and into the hand of Benhadad the son of Hazael, continually.'),
  ('2 Kings', 13, 4, 'Jehoahaz begged the LORD, and the LORD listened to him; for he saw the oppression of Israel, how the king of Syria oppressed them.'),
  ('2 Kings', 13, 5, '(The LORD gave Israel a savior, so that they went out from under the hand of the Syrians; and the children of Israel lived in their tents as before.'),
  ('2 Kings', 13, 6, 'Nevertheless they didn’t depart from the sins of the house of Jeroboam, with which he made Israel to sin, but walked in them; and the Asherah also remained in Samaria.)'),
  ('2 Kings', 13, 7, 'For he didn’t leave to Jehoahaz of the people any more than fifty horsemen, and ten chariots, and ten thousand footmen; for the king of Syria destroyed them and made them like the dust in threshing.'),
  ('2 Kings', 13, 8, 'Now the rest of the acts of Jehoahaz, and all that he did, and his might, aren’t they written in the book of the chronicles of the kings of Israel?'),
  ('2 Kings', 13, 9, 'Jehoahaz slept with his fathers; and they buried him in Samaria; and Joash his son reigned in his place.'),
  ('2 Kings', 13, 10, 'In the thirty-seventh year of Joash king of Judah, Jehoash the son of Jehoahaz began to reign over Israel in Samaria for sixteen years.'),
  ('2 Kings', 13, 11, 'He did that which was evil in the LORD’s sight. He didn’t depart from all the sins of Jeroboam the son of Nebat, with which he made Israel to sin; but he walked in them.'),
  ('2 Kings', 13, 12, 'Now the rest of the acts of Joash, and all that he did, and his might with which he fought against Amaziah king of Judah, aren’t they written in the book of the chronicles of the kings of Israel?'),
  ('2 Kings', 13, 13, 'Joash slept with his fathers; and Jeroboam sat on his throne. Joash was buried in Samaria with the kings of Israel.'),
  ('2 Kings', 13, 14, 'Now Elisha became sick with the illness of which he died; and Joash the king of Israel came down to him, and wept over him, and said, “My father, my father, the chariots of Israel and its horsemen!”'),
  ('2 Kings', 13, 15, 'Elisha said to him, “Take bow and arrows;” and he took bow and arrows for himself.'),
  ('2 Kings', 13, 16, 'He said to the king of Israel, “Put your hand on the bow;” and he put his hand on it. Elisha laid his hands on the king’s hands.'),
  ('2 Kings', 13, 17, 'He said, “Open the window eastward;” and he opened it. Then Elisha said, “Shoot!” and he shot. He said, “The LORD’s arrow of victory, even the arrow of victory over Syria; for you will strike the Syrians in Aphek until you have consumed them.”'),
  ('2 Kings', 13, 18, 'He said, “Take the arrows;” and he took them. He said to the king of Israel, “Strike the ground;” and he struck three times, and stopped.'),
  ('2 Kings', 13, 19, 'The man of God was angry with him, and said, “You should have struck five or six times. Then you would have struck Syria until you had consumed it, but now you will strike Syria just three times.”'),
  ('2 Kings', 13, 20, 'Elisha died, and they buried him. Now the bands of the Moabites invaded the land at the coming in of the year.'),
  ('2 Kings', 13, 21, 'As they were burying a man, behold, they saw a band of raiders; and they threw the man into Elisha’s tomb. As soon as the man touched Elisha’s bones, he revived, and stood up on his feet.'),
  ('2 Kings', 13, 22, 'Hazael king of Syria oppressed Israel all the days of Jehoahaz.'),
  ('2 Kings', 13, 23, 'But the LORD was gracious to them, and had compassion on them, and favored them because of his covenant with Abraham, Isaac, and Jacob, and would not destroy them and he didn’t cast them from his presence as yet.'),
  ('2 Kings', 13, 24, 'Hazael king of Syria died; and Benhadad his son reigned in his place.'),
  ('2 Kings', 13, 25, 'Jehoash the son of Jehoahaz took again out of the hand of Benhadad the son of Hazael the cities which he had taken out of the hand of Jehoahaz his father by war. Joash struck him three times, and recovered the cities of Israel.'),
  ('2 Kings', 14, 1, 'In the second year of Joash, son of Joahaz, king of Israel, Amaziah the son of Joash king of Judah began to reign.'),
  ('2 Kings', 14, 2, 'He was twenty-five years old when he began to reign; and he reigned twenty-nine years in Jerusalem. His mother’s name was Jehoaddin of Jerusalem.'),
  ('2 Kings', 14, 3, 'He did that which was right in the LORD’s eyes, yet not like David his father. He did according to all that Joash his father had done.');
INSERT INTO bible_verses (book_name, chapter, verse, text) VALUES
  ('2 Kings', 14, 4, 'However the high places were not taken away. The people still sacrificed and burned incense in the high places.'),
  ('2 Kings', 14, 5, 'As soon as the kingdom was established in his hand, he killed his servants who had slain the king his father,'),
  ('2 Kings', 14, 6, 'but the children of the murderers he didn’t put to death, according to that which is written in the book of the law of Moses, as the LORD commanded, saying, “The fathers shall not be put to death for the children, nor the children be put to death for the fathers; but every man shall die for his own sin.”'),
  ('2 Kings', 14, 7, 'He killed ten thousand Edomites in the Valley of Salt, and took Sela by war, and called its name Joktheel, to this day.'),
  ('2 Kings', 14, 8, 'Then Amaziah sent messengers to Jehoash, the son of Jehoahaz son of Jehu, king of Israel, saying, “Come, let’s look one another in the face.”'),
  ('2 Kings', 14, 9, 'Jehoash the king of Israel sent to Amaziah king of Judah, saying, “The thistle that was in Lebanon sent to the cedar that was in Lebanon, saying, ‘Give your daughter to my son as wife.’ Then a wild animal that was in Lebanon passed by, and trampled down the thistle.'),
  ('2 Kings', 14, 10, 'You have indeed struck Edom, and your heart has lifted you up. Enjoy the glory of it, and stay at home; for why should you meddle to your harm, that you fall, even you, and Judah with you?”'),
  ('2 Kings', 14, 11, 'But Amaziah would not listen. So Jehoash king of Israel went up; and he and Amaziah king of Judah looked one another in the face at Beth Shemesh, which belongs to Judah.'),
  ('2 Kings', 14, 12, 'Judah was defeated by Israel; and each man fled to his tent.'),
  ('2 Kings', 14, 13, 'Jehoash king of Israel took Amaziah king of Judah, the son of Jehoash the son of Ahaziah, at Beth Shemesh and came to Jerusalem, then broke down the wall of Jerusalem from the gate of Ephraim to the corner gate, four hundred cubits.'),
  ('2 Kings', 14, 14, 'He took all the gold and silver and all the vessels that were found in the LORD’s house and in the treasures of the king’s house, the hostages also, and returned to Samaria.'),
  ('2 Kings', 14, 15, 'Now the rest of the acts of Jehoash which he did, and his might, and how he fought with Amaziah king of Judah, aren’t they written in the book of the chronicles of the kings of Israel?'),
  ('2 Kings', 14, 16, 'Jehoash slept with his fathers, and was buried in Samaria with the kings of Israel; and Jeroboam his son reigned in his place.'),
  ('2 Kings', 14, 17, 'Amaziah the son of Joash king of Judah lived after the death of Jehoash son of Jehoahaz, king of Israel, fifteen years.'),
  ('2 Kings', 14, 18, 'Now the rest of the acts of Amaziah, aren’t they written in the book of the chronicles of the kings of Judah?'),
  ('2 Kings', 14, 19, 'They made a conspiracy against him in Jerusalem, and he fled to Lachish; but they sent after him to Lachish and killed him there.'),
  ('2 Kings', 14, 20, 'They brought him on horses, and he was buried at Jerusalem with his fathers in David’s city.'),
  ('2 Kings', 14, 21, 'All the people of Judah took Azariah, who was sixteen years old, and made him king in the place of his father Amaziah.'),
  ('2 Kings', 14, 22, 'He built Elath and restored it to Judah. After that the king slept with his fathers.'),
  ('2 Kings', 14, 23, 'In the fifteenth year of Amaziah the son of Joash king of Judah, Jeroboam the son of Joash king of Israel began to reign in Samaria for forty-one years.'),
  ('2 Kings', 14, 24, 'He did that which was evil in the LORD’s sight. He didn’t depart from all the sins of Jeroboam the son of Nebat, with which he made Israel to sin.'),
  ('2 Kings', 14, 25, 'He restored the border of Israel from the entrance of Hamath to the sea of the Arabah, according to the LORD, the God of Israel’s word, which he spoke by his servant Jonah the son of Amittai, the prophet, who was from Gath Hepher.'),
  ('2 Kings', 14, 26, 'For the LORD saw the affliction of Israel, that it was very bitter for all, slave and free; and there was no helper for Israel.'),
  ('2 Kings', 14, 27, 'The LORD didn’t say that he would blot out the name of Israel from under the sky; but he saved them by the hand of Jeroboam the son of Joash.'),
  ('2 Kings', 14, 28, 'Now the rest of the acts of Jeroboam, and all that he did, and his might, how he fought, and how he recovered Damascus, and Hamath, which had belonged to Judah, for Israel, aren’t they written in the book of the chronicles of the kings of Israel?'),
  ('2 Kings', 14, 29, 'Jeroboam slept with his fathers, even with the kings of Israel; and Zechariah his son reigned in his place.'),
  ('2 Kings', 15, 1, 'In the twenty-seventh year of Jeroboam king of Israel, Azariah son of Amaziah king of Judah began to reign.'),
  ('2 Kings', 15, 2, 'He was sixteen years old when he began to reign, and he reigned fifty-two years in Jerusalem. His mother’s name was Jecoliah of Jerusalem.'),
  ('2 Kings', 15, 3, 'He did that which was right in the LORD’s eyes, according to all that his father Amaziah had done.'),
  ('2 Kings', 15, 4, 'However, the high places were not taken away. The people still sacrificed and burned incense in the high places.'),
  ('2 Kings', 15, 5, 'The LORD struck the king, so that he was a leper to the day of his death, and lived in a separate house. Jotham, the king’s son, was over the household, judging the people of the land.'),
  ('2 Kings', 15, 6, 'Now the rest of the acts of Azariah, and all that he did, aren’t they written in the book of the chronicles of the kings of Judah?'),
  ('2 Kings', 15, 7, 'Azariah slept with his fathers; and they buried him with his fathers in David’s city; and Jotham his son reigned in his place.'),
  ('2 Kings', 15, 8, 'In the thirty-eighth year of Azariah king of Judah, Zechariah the son of Jeroboam reigned over Israel in Samaria six months.'),
  ('2 Kings', 15, 9, 'He did that which was evil in the LORD’s sight, as his fathers had done. He didn’t depart from the sins of Jeroboam the son of Nebat, with which he made Israel to sin.'),
  ('2 Kings', 15, 10, 'Shallum the son of Jabesh conspired against him, and struck him before the people and killed him, and reigned in his place.'),
  ('2 Kings', 15, 11, 'Now the rest of the acts of Zechariah, behold, they are written in the book of the chronicles of the kings of Israel.'),
  ('2 Kings', 15, 12, 'This was the LORD’s word which he spoke to Jehu, saying, “Your sons to the fourth generation shall sit on the throne of Israel.” So it came to pass.'),
  ('2 Kings', 15, 13, 'Shallum the son of Jabesh began to reign in the thirty-ninth year of Uzziah king of Judah, and he reigned for a month in Samaria.'),
  ('2 Kings', 15, 14, 'Menahem the son of Gadi went up from Tirzah, came to Samaria, struck Shallum the son of Jabesh in Samaria, killed him, and reigned in his place.'),
  ('2 Kings', 15, 15, 'Now the rest of the acts of Shallum, and his conspiracy which he made, behold, they are written in the book of the chronicles of the kings of Israel.'),
  ('2 Kings', 15, 16, 'Then Menahem attacked Tiphsah and all who were in it and its border areas, from Tirzah. He attacked it because they didn’t open their gates to him, and he ripped up all their women who were with child.'),
  ('2 Kings', 15, 17, 'In the thirty ninth year of Azariah king of Judah, Menahem the son of Gadi began to reign over Israel for ten years in Samaria.'),
  ('2 Kings', 15, 18, 'He did that which was evil in the LORD’s sight. He didn’t depart all his days from the sins of Jeroboam the son of Nebat, with which he made Israel to sin.'),
  ('2 Kings', 15, 19, 'Pul the king of Assyria came against the land, and Menahem gave Pul one thousand talents of silver, that his hand might be with him to confirm the kingdom in his hand.'),
  ('2 Kings', 15, 20, 'Menahem exacted the money from Israel, even from all the mighty men of wealth, from each man fifty shekels of silver, to give to the king of Assyria. So the king of Assyria turned back, and didn’t stay there in the land.'),
  ('2 Kings', 15, 21, 'Now the rest of the acts of Menahem, and all that he did, aren’t they written in the book of the chronicles of the kings of Israel?'),
  ('2 Kings', 15, 22, 'Menahem slept with his fathers, and Pekahiah his son reigned in his place.'),
  ('2 Kings', 15, 23, 'In the fiftieth year of Azariah king of Judah, Pekahiah the son of Menahem began to reign over Israel in Samaria for two years.'),
  ('2 Kings', 15, 24, 'He did that which was evil in the LORD’s sight. He didn’t depart from the sins of Jeroboam the son of Nebat, with which he made Israel to sin.'),
  ('2 Kings', 15, 25, 'Pekah the son of Remaliah, his captain, conspired against him and attacked him in Samaria, in the fortress of the king’s house, with Argob and Arieh; and with him were fifty men of the Gileadites. He killed him, and reigned in his place.'),
  ('2 Kings', 15, 26, 'Now the rest of the acts of Pekahiah, and all that he did, behold, they are written in the book of the chronicles of the kings of Israel.'),
  ('2 Kings', 15, 27, 'In the fifty-second year of Azariah king of Judah, Pekah the son of Remaliah began to reign over Israel in Samaria for twenty years.'),
  ('2 Kings', 15, 28, 'He did that which was evil in the LORD’s sight. He didn’t depart from the sins of Jeroboam the son of Nebat, with which he made Israel to sin.'),
  ('2 Kings', 15, 29, 'In the days of Pekah king of Israel, Tiglath Pileser king of Assyria came and took Ijon, Abel Beth Maacah, Janoah, Kedesh, Hazor, Gilead, and Galilee, all the land of Naphtali; and he carried them captive to Assyria.'),
  ('2 Kings', 15, 30, 'Hoshea the son of Elah made a conspiracy against Pekah the son of Remaliah, attacked him, killed him, and reigned in his place, in the twentieth year of Jotham the son of Uzziah.'),
  ('2 Kings', 15, 31, 'Now the rest of the acts of Pekah, and all that he did, behold, they are written in the book of the chronicles of the kings of Israel.'),
  ('2 Kings', 15, 32, 'In the second year of Pekah the son of Remaliah king of Israel, Jotham the son of Uzziah king of Judah began to reign.'),
  ('2 Kings', 15, 33, 'He was twenty-five years old when he began to reign, and he reigned sixteen years in Jerusalem. His mother’s name was Jerusha the daughter of Zadok.'),
  ('2 Kings', 15, 34, 'He did that which was right in the LORD’s eyes. He did according to all that his father Uzziah had done.'),
  ('2 Kings', 15, 35, 'However the high places were not taken away. The people still sacrificed and burned incense in the high places. He built the upper gate of the LORD’s house.'),
  ('2 Kings', 15, 36, 'Now the rest of the acts of Jotham, and all that he did, aren’t they written in the book of the chronicles of the kings of Judah?'),
  ('2 Kings', 15, 37, 'In those days, the LORD began to send Rezin the king of Syria and Pekah the son of Remaliah against Judah.'),
  ('2 Kings', 15, 38, 'Jotham slept with his fathers, and was buried with his fathers in his father David’s city; and Ahaz his son reigned in his place.'),
  ('2 Kings', 16, 1, 'In the seventeenth year of Pekah the son of Remaliah, Ahaz the son of Jotham king of Judah began to reign.'),
  ('2 Kings', 16, 2, 'Ahaz was twenty years old when he began to reign, and he reigned sixteen years in Jerusalem. He didn’t do that which was right in the LORD his God’s eyes, like David his father.'),
  ('2 Kings', 16, 3, 'But he walked in the way of the kings of Israel, and even made his son to pass through the fire, according to the abominations of the nations whom the LORD cast out from before the children of Israel.'),
  ('2 Kings', 16, 4, 'He sacrificed and burned incense in the high places, on the hills, and under every green tree.'),
  ('2 Kings', 16, 5, 'Then Rezin king of Syria and Pekah son of Remaliah king of Israel came up to Jerusalem to wage war. They besieged Ahaz, but could not overcome him.'),
  ('2 Kings', 16, 6, 'At that time Rezin king of Syria recovered Elath to Syria, and drove the Jews from Elath; and the Syrians came to Elath, and lived there to this day.'),
  ('2 Kings', 16, 7, 'So Ahaz sent messengers to Tiglath Pileser king of Assyria, saying, “I am your servant and your son. Come up and save me out of the hand of the king of Syria and out of the hand of the king of Israel, who rise up against me.”'),
  ('2 Kings', 16, 8, 'Ahaz took the silver and gold that was found in the LORD’s house, and in the treasures of the king’s house, and sent it for a present to the king of Assyria.'),
  ('2 Kings', 16, 9, 'The king of Assyria listened to him; and the king of Assyria went up against Damascus and took it, and carried its people captive to Kir, and killed Rezin.'),
  ('2 Kings', 16, 10, 'King Ahaz went to Damascus to meet Tiglath Pileser king of Assyria, and saw the altar that was at Damascus; and King Ahaz sent to Urijah the priest a drawing of the altar and plans to build it.'),
  ('2 Kings', 16, 11, 'Urijah the priest built an altar. According to all that King Ahaz had sent from Damascus, so Urijah the priest made it for the coming of King Ahaz from Damascus.'),
  ('2 Kings', 16, 12, 'When the king had come from Damascus, the king saw the altar; and the king came near to the altar, and offered on it.'),
  ('2 Kings', 16, 13, 'He burned his burnt offering and his meal offering, poured his drink offering, and sprinkled the blood of his peace offerings on the altar.'),
  ('2 Kings', 16, 14, 'The bronze altar, which was before the LORD, he brought from the front of the house, from between his altar and the LORD’s house, and put it on the north side of his altar.'),
  ('2 Kings', 16, 15, 'King Ahaz commanded Urijah the priest, saying, “On the great altar burn the morning burnt offering, the evening meal offering, the king’s burnt offering and his meal offering, with the burnt offering of all the people of the land, their meal offering, and their drink offerings; and sprinkle on it all the blood of the burnt offering, and all the blood of the sacrifice; but the bronze altar will be for me to inquire by.”'),
  ('2 Kings', 16, 16, 'Urijah the priest did so, according to all that King Ahaz commanded.'),
  ('2 Kings', 16, 17, 'King Ahaz cut off the panels of the bases, and removed the basin from off them, and took down the sea from off the bronze oxen that were under it, and put it on a pavement of stone.'),
  ('2 Kings', 16, 18, 'He removed the covered way for the Sabbath that they had built in the house, and the king’s outer entrance to the LORD’s house, because of the king of Assyria.'),
  ('2 Kings', 16, 19, 'Now the rest of the acts of Ahaz which he did, aren’t they written in the book of the chronicles of the kings of Judah?'),
  ('2 Kings', 16, 20, 'Ahaz slept with his fathers, and was buried with his fathers in David’s city; and Hezekiah his son reigned in his place.'),
  ('2 Kings', 17, 1, 'In the twelfth year of Ahaz king of Judah, Hoshea the son of Elah began to reign in Samaria over Israel for nine years.'),
  ('2 Kings', 17, 2, 'He did that which was evil in the LORD’s sight, yet not as the kings of Israel who were before him.'),
  ('2 Kings', 17, 3, 'Shalmaneser king of Assyria came up against him; and Hoshea became his servant, and brought him tribute.'),
  ('2 Kings', 17, 4, 'The king of Assyria discovered a conspiracy in Hoshea; for he had sent messengers to So king of Egypt, and offered no tribute to the king of Assyria, as he had done year by year. Therefore the king of Assyria seized him, and bound him in prison.'),
  ('2 Kings', 17, 5, 'Then the king of Assyria came up throughout all the land, went up to Samaria, and besieged it three years.'),
  ('2 Kings', 17, 6, 'In the ninth year of Hoshea the king of Assyria took Samaria and carried Israel away to Assyria, and placed them in Halah, and on the Habor, the river of Gozan, and in the cities of the Medes.'),
  ('2 Kings', 17, 7, 'It was so because the children of Israel had sinned against the LORD their God, who brought them up out of the land of Egypt from under the hand of Pharaoh king of Egypt, and had feared other gods,'),
  ('2 Kings', 17, 8, 'and walked in the statutes of the nations whom the LORD cast out from before the children of Israel, and of the kings of Israel, which they made.'),
  ('2 Kings', 17, 9, 'The children of Israel secretly did things that were not right against the LORD their God; and they built high places for themselves in all their cities, from the tower of the watchmen to the fortified city;'),
  ('2 Kings', 17, 10, 'and they set up for themselves pillars and Asherah poles on every high hill and under every green tree;'),
  ('2 Kings', 17, 11, 'and there they burned incense in all the high places, as the nations whom the LORD carried away before them did; and they did wicked things to provoke the LORD to anger;'),
  ('2 Kings', 17, 12, 'and they served idols, of which the LORD had said to them, “You shall not do this thing.”'),
  ('2 Kings', 17, 13, 'Yet the LORD testified to Israel and to Judah, by every prophet and every seer, saying, “Turn from your evil ways, and keep my commandments and my statutes, according to all the law which I commanded your fathers, and which I sent to you by my servants the prophets.”'),
  ('2 Kings', 17, 14, 'Notwithstanding, they would not listen, but hardened their neck like the neck of their fathers who didn’t believe in the LORD their God.'),
  ('2 Kings', 17, 15, 'They rejected his statutes and his covenant that he made with their fathers, and his testimonies which he testified to them; and they followed vanity, and became vain, and followed the nations that were around them, concerning whom the LORD had commanded them that they should not do like them.'),
  ('2 Kings', 17, 16, 'They abandoned all the commandments of the LORD their God, and made molten images for themselves, even two calves, and made an Asherah, and worshiped all the army of the sky, and served Baal.');
